class StateWriter:
    """Commit one hash-chained event and advance its two projections."""

    def __init__(
        self,
        root: str | Path,
        *,
        permit_authority: PermitAuthority | None = None,
        clock: Callable[[], str] = _now_utc,
        engineering_fixture: bool = False,
        study_close_guard_capability: StudyCloseGuardCapability | None = None,
        study_close_delivery_observation: StudyCloseDeliveryObservation | None = None,
        foundation_root: str | Path | None = None,
        validation_registry: EvidenceValidatorRegistry | None = None,
    ) -> None:
        self.root = Path(root)
        self.foundation_root = Path(foundation_root) if foundation_root else self.root
        if engineering_fixture and any(
            (candidate / ".git").exists()
            for candidate in (self.root.resolve(), *self.root.resolve().parents)
        ):
            raise TransitionError(
                "engineering_fixture state must be isolated outside a Git worktree"
            )
        if study_close_guard_capability is not None and (
            study_close_guard_capability
            is not StudyCloseGuardCapability.ISOLATED_ENGINEERING_FIXTURE
            or engineering_fixture
            or any(
                (candidate / ".git").exists()
                for candidate in (self.root.resolve(), *self.root.resolve().parents)
            )
        ):
            raise TransitionError(
                "Study-close guard capability must be an isolated non-Git fixture"
            )
        if study_close_delivery_observation is not None and (
            not isinstance(
                study_close_delivery_observation,
                StudyCloseDeliveryObservation,
            )
            or engineering_fixture
            or study_close_guard_capability is not None
        ):
            raise TransitionError(
                "Study-close delivery observation requires a real guarded writer"
            )
        self.control = ControlStore(self.root / "state" / "control.json")
        self.journal = DurableJournal(self.root / LEGACY_JOURNAL_RELATIVE_PATH)
        self._journal_write_capability = _issue_journal_write_capability()
        self.index_path = self.root / "local" / "index.sqlite"
        self.lock_path = self.root / "local" / "state.writer.lock"
        self.evidence = EvidenceStore(self.root / "local" / "evidence")
        self.permit_authority = permit_authority
        self.clock = clock
        self.engineering_fixture = engineering_fixture
        self.study_close_guard_capability = study_close_guard_capability
        self.study_close_delivery_observation = (
            study_close_delivery_observation
        )
        self.validation_registry = (
            validation_registry
            if validation_registry is not None
            else EvidenceValidatorRegistry(
                (
                    EngineeringFixtureValidator(),
                    EngineeringRetryFixtureValidator(),
                )
                if engineering_fixture
                else ()
            )
        )

    @staticmethod
    def _body(control: Mapping[str, Any]) -> dict[str, Any]:
        return {
            key: value
            for key, value in _copy(control).items()
            if key not in {"revision", "heads", "control_hash"}
        }

    @staticmethod
    def _assemble(event: Mapping[str, Any]) -> dict[str, Any]:
        sequence = _require_authority_integer(
            "Journal sequence",
            event.get("sequence"),
            error_type=JournalIntegrityError,
        )
        record_count = _require_authority_integer(
            "Journal index record count",
            event.get("index_record_count"),
            error_type=JournalIntegrityError,
        )
        control = _copy(event["control"])
        control["revision"] = sequence
        control["heads"] = {
            "journal": {
                "sequence": sequence,
                "event_id": event["event_id"],
            },
            "index": {
                "required_sequence": sequence,
                "required_record_count": record_count,
                "required_projection_digest": event[
                    "index_projection_digest"
                ],
            },
        }
        return control

    @staticmethod
    def _event_records(event: Mapping[str, Any]) -> tuple[IndexRecord, ...]:
        sequence = _require_authority_integer(
            "Journal sequence",
            event.get("sequence"),
            error_type=JournalIntegrityError,
        )
        offset = _require_authority_integer(
            "Journal offset",
            event.get("journal_offset"),
            minimum=0,
            error_type=JournalIntegrityError,
        )
        authority = {
            "authority_sequence": sequence,
            "authority_event_id": event["event_id"],
            "authority_offset": offset,
        }
        event_record = IndexRecord(
            kind="journal-event",
            record_id=event["event_id"],
            subject=event["subject"],
            status=event["event_kind"],
            fingerprint=event["event_id"],
            payload={
                "operation_id": event["operation_id"],
                "occurred_at_utc": event["occurred_at_utc"],
            },
            event_stream="control",
            event_sequence=sequence,
            **authority,
        )
        return (event_record,) + tuple(
            IndexRecord.from_mapping({**item, **authority})
            for item in event["index_records"]
        )

    @staticmethod
    def _index_mapping(record: IndexRecord) -> dict[str, Any]:
        return {
            "kind": record.kind,
            "record_id": record.record_id,
            "subject": record.subject,
            "status": record.status,
            "fingerprint": record.fingerprint,
            "payload": dict(record.payload),
            "event_stream": record.event_stream,
            "event_sequence": record.event_sequence,
        }

    @staticmethod
    def _index_record_authority_key(record: IndexRecord) -> tuple[int, int, str]:
        if (
            type(record.authority_sequence) is not int
            or record.authority_sequence < 1
            or type(record.authority_event_id) is not str
            or not record.authority_event_id
            or type(record.authority_offset) is not int
            or record.authority_offset < 0
        ):
            raise IndexIntegrityError("operating projection record lacks Journal authority")
        return (
            record.authority_offset,
            record.authority_sequence,
            record.authority_event_id,
        )

    def _validate_index_record_projection(
        self,
        record: IndexRecord,
        event: Mapping[str, Any],
    ) -> None:
        """Validate one row against its already authenticated Journal event."""

        projected = self._index_mapping(record)
        if record.kind == "journal-event":
            expected = self._index_mapping(self._event_records(event)[0])
            if projected != expected:
                raise IndexIntegrityError("journal-event projection differs from authority")
            return
        matches = [item for item in event["index_records"] if item == projected]
        if len(matches) != 1:
            raise IndexIntegrityError("projection record is not a unique Journal member")

    def _validate_index_record_authority(self, record: IndexRecord) -> None:
        offset, sequence, event_id = self._index_record_authority_key(record)
        event = self.journal.read_event_at(
            offset=offset,
            expected_sequence=sequence,
            expected_event_id=event_id,
        )
        self._validate_index_record_projection(record, event)

    def _authoritative_index_validator(
        self,
    ) -> Callable[[IndexRecord], None]:
        """Build one session-local Journal authority validator."""

        @lru_cache(maxsize=_AUTHORITATIVE_EVENT_CACHE_SIZE)
        def read_authoritative_event(
            offset: int,
            sequence: int,
            event_id: str,
        ) -> Mapping[str, Any]:
            return self.journal.read_event_at(
                offset=offset,
                expected_sequence=sequence,
                expected_event_id=event_id,
            )

        def validate(record: IndexRecord) -> None:
            authority_key = self._index_record_authority_key(record)
            event = read_authoritative_event(*authority_key)
            self._validate_index_record_projection(record, event)

        return validate

    def _open_authoritative_index(self) -> LocalIndexView:
        """Open one authenticated, existing, current-schema read snapshot."""

        try:
            return LocalIndex.open_read_only(
                self.index_path,
                authority_validator=self._authoritative_index_validator(),
            )
        except (IndexIntegrityError, LocalIndexError) as exc:
            raise RecoveryRequired(str(exc)) from exc

    def _open_mutable_authoritative_index(self) -> LocalIndex:
        """Open the authenticated projection for the atomic commit path only."""

        return LocalIndex(
            self.index_path,
            authority_validator=self._authoritative_index_validator(),
        )

    def _open_mutable_recovery_index(self) -> LocalIndex:
        """Open a projection that explicit Journal recovery may rebuild."""

        return LocalIndex(self.index_path)

    def _require_runtime_source(
        self,
        index: LocalIndex,
        source_id: str,
        *,
        freshness_required: bool = True,
        error_type: type[Exception] = TransitionError,
    ) -> IndexRecord:
        """Return typed source authority, optionally requiring live freshness."""

        from axiom_rift.research.source_authority import (
            AUTHORITY_TRANSITION_EVIDENCE,
            SourceAuthorityAuditManifest,
            SourceAuthorityInvalidation,
            SourceAuthorityLatch,
        )
        from axiom_rift.research.sources import (
            SourceContract,
            SourceEligibilityState,
            SourceEligibilityReceipt,
            SourceTransitionEvidence,
            SourceType,
        )

        _require_ascii("source_id", source_id)
        stream = f"source:{source_id}"

        def require_edge(
            record: IndexRecord | None,
            *,
            sequence: int,
            state: str,
            evidence: SourceTransitionEvidence | None,
        ) -> SourceEligibilityReceipt | None:
            if type(sequence) is not int or sequence < 1:
                raise ValueError("source transition sequence is invalid")
            if (
                record is None
                or record.kind != "source-state"
                or record.subject != f"Source:{source_id}"
                or record.fingerprint != source_id
                or record.status != state
                or record.event_stream != stream
                or type(record.event_sequence) is not int
                or record.event_sequence != sequence
                or type(record.payload.get("ordinal")) is not int
                or record.payload.get("ordinal") != sequence
            ):
                raise ValueError("source transition edge is structurally invalid")
            payload = record.payload
            expected_record_id = canonical_digest(
                domain="source-state",
                payload={
                    "source_id": source_id,
                    "state": state,
                    "ordinal": sequence,
                    "evidence_receipt_id": payload.get("evidence_receipt_id"),
                },
            )
            if record.record_id != expected_record_id:
                raise ValueError("source-state identity is not canonical")
            suspension_reason = payload.get("suspension_reason")
            if (state == "suspended") != (
                isinstance(suspension_reason, str) and bool(suspension_reason)
            ):
                raise ValueError("source suspension reason does not match state")
            if evidence is None:
                if (
                    payload.get("receipt") is not None
                    or payload.get("evidence_receipt_id") is not None
                    or payload.get("transition_evidence") is not None
                ):
                    raise ValueError("source registration edge contains transition evidence")
                return None
            receipt_payload = payload.get("receipt")
            if not isinstance(receipt_payload, dict):
                raise ValueError("source transition receipt is absent")
            receipt = SourceEligibilityReceipt(
                source_contract_id=receipt_payload["source_contract_id"],
                evidence=SourceTransitionEvidence(receipt_payload["evidence"]),
                producer_completion_id=receipt_payload["producer_completion_id"],
                observed_at_utc=receipt_payload["observed_at_utc"],
                artifact_hashes=tuple(receipt_payload["artifact_hashes"]),
                facts=receipt_payload["facts"],
            )
            if (
                receipt.source_contract_id != source_id
                or receipt.identity != payload.get("evidence_receipt_id")
                or receipt.evidence is not evidence
                or payload.get("transition_evidence") != evidence.value
                or receipt_payload != receipt.to_identity_payload()
            ):
                raise ValueError("source transition receipt provenance is invalid")
            for artifact_hash in receipt.artifact_hashes:
                self.evidence.verify(artifact_hash)
            return receipt

        try:
            authority_stream = f"source-authority:{source_id}"
            authority_head = index.event_head(authority_stream)
            if authority_head is not None:
                authority_sequence = _require_authority_integer(
                    "source authority head sequence",
                    authority_head.sequence,
                    error_type=ValueError,
                )
                correction = index.get(
                    authority_head.record_kind, authority_head.record_id
                )
                if (
                    correction is None
                    or correction.kind != "source-authority-invalidation"
                    or correction.status != "confirmed_and_suspended"
                    or correction.subject != f"Source:{source_id}"
                    or correction.event_stream != authority_stream
                    or type(correction.event_sequence) is not int
                    or correction.event_sequence != authority_sequence
                    or set(correction.payload)
                    != {
                        "audit_manifest",
                        "eligible_source_state_record_id",
                        "invalidated_state",
                        "invalidation",
                        "latch",
                        "preserved_receipt_id",
                        "prior_active_source_state_record_id",
                        "replacement_state_record_id",
                        "scientific_trial_delta",
                    }
                ):
                    raise ValueError("source authority correction is malformed")
                invalidation = SourceAuthorityInvalidation.from_identity_payload(
                    correction.payload["invalidation"]
                )
                manifest = SourceAuthorityAuditManifest.from_mapping(
                    correction.payload["audit_manifest"]
                )
                latch = SourceAuthorityLatch.from_mapping(correction.payload["latch"])
                expected_latch = SourceAuthorityLatch.bind(
                    invalidation=invalidation,
                    manifest=manifest,
                )
                replacement_id = correction.payload["replacement_state_record_id"]
                replacement = (
                    None
                    if not isinstance(replacement_id, str)
                    else index.get("source-state", replacement_id)
                )
                source_head = index.event_head(stream)
                invalidated = index.get(
                    "source-state", invalidation.source_state_record_id
                )
                prior_active_id = correction.payload[
                    "prior_active_source_state_record_id"
                ]
                prior_active = (
                    None
                    if not isinstance(prior_active_id, str)
                    else index.get("source-state", prior_active_id)
                )
                if source_head is not None:
                    _require_authority_integer(
                        "source head sequence",
                        source_head.sequence,
                        error_type=ValueError,
                    )
                for sequence_name, source_record in (
                    ("invalidated source event sequence", invalidated),
                    ("prior active source event sequence", prior_active),
                    ("replacement source event sequence", replacement),
                ):
                    if source_record is not None:
                        _require_authority_integer(
                            sequence_name,
                            source_record.event_sequence,
                            error_type=ValueError,
                        )
                invalidated_receipt_payload = (
                    None
                    if invalidated is None
                    else invalidated.payload.get("receipt")
                )
                invalidated_receipt = (
                    None
                    if not isinstance(invalidated_receipt_payload, dict)
                    else require_edge(
                        invalidated,
                        sequence=invalidated.event_sequence or 0,
                        state=correction.payload["invalidated_state"],
                        evidence=SourceTransitionEvidence(
                            invalidated_receipt_payload["evidence"]
                        ),
                    )
                )
                invalidated_state = correction.payload["invalidated_state"]
                allowed_invalidated_states = {
                    SourceEligibilityState.CONTEXT_ONLY.value,
                    SourceEligibilityState.HISTORICAL_AUDITED.value,
                    SourceEligibilityState.RUNTIME_ELIGIBLE.value,
                }
                context_only_invalidation = (
                    invalidated_state == SourceEligibilityState.CONTEXT_ONLY.value
                )
                expected_invalidated_id = (
                    None
                    if invalidated is None
                    or invalidated.event_sequence is None
                    else canonical_digest(
                        domain="source-state",
                        payload={
                            "source_id": source_id,
                            "state": invalidated_state,
                            "ordinal": invalidated.event_sequence,
                            "evidence_receipt_id": invalidated.payload.get(
                                "evidence_receipt_id"
                            ),
                        },
                    )
                )
                invalidated_receipt_is_legal = (
                    invalidated_receipt is None
                    and invalidated_receipt_payload is None
                    and correction.payload["preserved_receipt_id"] is None
                    if context_only_invalidation
                    else invalidated_receipt is not None
                    and correction.payload["preserved_receipt_id"]
                    == invalidated_receipt.identity
                    and (
                        (
                            invalidated_state
                            == SourceEligibilityState.HISTORICAL_AUDITED.value
                            and invalidated_receipt.evidence
                            is SourceTransitionEvidence.HISTORICAL_AUDIT
                        )
                        or (
                            invalidated_state
                            == SourceEligibilityState.RUNTIME_ELIGIBLE.value
                            and invalidated_receipt.evidence
                            in {
                                SourceTransitionEvidence.RUNTIME_AVAILABILITY_PROOF,
                                SourceTransitionEvidence.SAME_SEMANTICS_RECERTIFICATION,
                            }
                        )
                    )
                )
                expected_replacement_id = (
                    None
                    if replacement is None
                    else canonical_digest(
                        domain="source-state",
                        payload={
                            "source_id": source_id,
                            "state": "suspended",
                            "ordinal": replacement.event_sequence,
                            "evidence_receipt_id": replacement.payload.get(
                                "evidence_receipt_id"
                            ),
                        },
                    )
                )
                ordinary_suspended = (
                    prior_active is not None
                    and invalidated is not None
                    and prior_active.record_id != invalidated.record_id
                )
                ordinary_suspension_is_legal = True
                if ordinary_suspended:
                    try:
                        ordinary_receipt = require_edge(
                            prior_active,
                            sequence=prior_active.event_sequence or 0,
                            state=SourceEligibilityState.SUSPENDED.value,
                            evidence=SourceTransitionEvidence.DRIFT,
                        )
                    except (KeyError, TypeError, ValueError):
                        ordinary_suspension_is_legal = False
                    else:
                        ordinary_suspension_is_legal = (
                            ordinary_receipt is not None
                            and invalidated.event_sequence is not None
                            and prior_active.event_sequence
                            == invalidated.event_sequence + 1
                            and prior_active.subject == f"Source:{source_id}"
                            and prior_active.fingerprint == source_id
                            and prior_active.payload.get("source_authority_latch")
                            is None
                            and all(
                                prior_active.payload.get(field)
                                == invalidated.payload.get(field)
                                for field in (
                                    "availability_identity",
                                    "clock_identity",
                                    "contract",
                                    "contract_hash",
                                    "field_identity",
                                    "mapping_identity",
                                    "schema_identity",
                                )
                            )
                        )
                if (
                    authority_sequence != 1
                    or invalidation.identity != correction.record_id
                    or correction.fingerprint
                    != invalidation.identity.removeprefix(
                        "source-authority-invalidation:"
                    )
                    or invalidation.source_contract_id != source_id
                    or invalidated_state not in allowed_invalidated_states
                    or correction.payload["eligible_source_state_record_id"]
                    != invalidation.source_state_record_id
                    or latch != expected_latch
                    or correction.payload["preserved_receipt_id"]
                    != (
                        None
                        if replacement is None
                        else replacement.payload.get("evidence_receipt_id")
                    )
                    or correction.payload["scientific_trial_delta"] != 0
                    or source_head is None
                    or replacement is None
                    or replacement.record_id != replacement_id
                    or replacement.record_id != expected_replacement_id
                    or replacement.event_stream != stream
                    or replacement.event_sequence != source_head.sequence
                    or replacement.record_id != source_head.record_id
                    or replacement.status != "suspended"
                    or replacement.subject != f"Source:{source_id}"
                    or replacement.fingerprint != source_id
                    or replacement.payload.get("ordinal")
                    != replacement.event_sequence
                    or replacement.payload.get("transition_evidence")
                    != AUTHORITY_TRANSITION_EVIDENCE
                    or replacement.payload.get("source_authority_latch")
                    != latch.to_identity_payload()
                    or replacement.payload.get(
                        "eligible_source_state_record_id"
                    )
                    != invalidation.source_state_record_id
                    or replacement.payload.get(
                        "prior_active_source_state_record_id"
                    )
                    != prior_active_id
                    or invalidated is None
                    or invalidated.status != invalidated_state
                    or invalidated.record_id != expected_invalidated_id
                    or not invalidated_receipt_is_legal
                    or invalidated.event_stream != stream
                    or prior_active is None
                    or prior_active.event_stream != stream
                    or prior_active.event_sequence != replacement.event_sequence - 1
                    or not ordinary_suspension_is_legal
                    or invalidated.record_id
                    != latch.invalidated_source_state_record_id
                    or invalidated.payload.get("evidence_receipt_id")
                    != correction.payload["preserved_receipt_id"]
                    or replacement.payload.get("receipt")
                    != invalidated.payload.get("receipt")
                    or replacement.payload.get("suspension_reason")
                    != (
                        f"{invalidation.reason_code.value}: "
                        f"{invalidation.observed_defect}"
                    )
                    or any(
                        replacement.payload.get(field)
                        != invalidated.payload.get(field)
                        for field in (
                            "availability_identity",
                            "clock_identity",
                            "contract",
                            "contract_hash",
                            "field_identity",
                            "mapping_identity",
                            "schema_identity",
                        )
                    )
                ):
                    raise ValueError("source authority correction provenance is invalid")
                durable_manifest = SourceAuthorityAuditManifest.from_bytes(
                    self.evidence.read_verified(latch.audit_manifest_hash)
                )
                if durable_manifest != manifest:
                    raise ValueError("source authority audit manifest projection drifted")
                durable_report = self.evidence.read_verified(
                    manifest.report_artifact_hash
                )
                manifest.require_report(durable_report)
                raise error_type(
                    f"source {source_id!r} is permanently audit-invalidated; "
                    "a new SourceContract identity is required"
                )
            head = index.event_head(stream)
            record = None if head is None else index.get(head.record_kind, head.record_id)
            if head is None or record is None or record.status != "runtime_eligible":
                raise ValueError("current source projection is not runtime eligible")
            head_sequence = _require_authority_integer(
                "runtime source head sequence",
                head.sequence,
                error_type=ValueError,
            )
            receipt_payload = record.payload.get("receipt")
            if not isinstance(receipt_payload, dict):
                raise ValueError("runtime source receipt is absent")
            current_evidence = SourceTransitionEvidence(receipt_payload["evidence"])
            if current_evidence not in {
                SourceTransitionEvidence.RUNTIME_AVAILABILITY_PROOF,
                SourceTransitionEvidence.SAME_SEMANTICS_RECERTIFICATION,
            }:
                raise ValueError("current source receipt is not runtime evidence")
            receipt = require_edge(
                record,
                sequence=head_sequence,
                state="runtime_eligible",
                evidence=current_evidence,
            )
            assert receipt is not None
            payload = record.payload
            contract_payload = payload.get("contract")
            if not isinstance(contract_payload, dict):
                raise ValueError("source contract projection is absent")
            contract = SourceContract(
                display_name="journal-projection",
                canonical_instrument=contract_payload["canonical_instrument"],
                runtime_identifier=contract_payload["runtime_identifier"],
                source_type=SourceType(contract_payload["source_type"]),
                instrument_semantics=contract_payload["instrument_semantics"],
                mapping_semantics=contract_payload["mapping_semantics"],
                schema_semantics=contract_payload["schema_semantics"],
                field_semantics=contract_payload["field_semantics"],
                clock_semantics=contract_payload["clock_semantics"],
                availability_semantics=contract_payload["availability_semantics"],
            )
            if (
                contract.identity != source_id
                or contract_payload != contract.to_identity_payload()
                or payload.get("contract_hash") != source_id.removeprefix("source:")
                or payload.get("mapping_identity") != contract.mapping_identity
                or payload.get("schema_identity") != contract.schema_identity
                or payload.get("field_identity") != contract.field_identity
                or payload.get("clock_identity") != contract.clock_identity
                or payload.get("availability_identity") != contract.availability_identity
            ):
                raise ValueError("source contract identity projection is invalid")
            observed_at = datetime.fromisoformat(
                receipt.observed_at_utc.replace("Z", "+00:00")
            ).astimezone(timezone.utc)
            now = datetime.fromisoformat(
                self.clock().replace("Z", "+00:00")
            ).astimezone(timezone.utc)
            availability = contract.availability()
            ttl_seconds = availability.get(
                "eligibility_receipt_ttl_seconds",
                availability["causal_ttl_seconds"],
            )
            if freshness_required and (
                isinstance(ttl_seconds, bool)
                or not isinstance(ttl_seconds, int)
                or ttl_seconds <= 0
            ):
                raise ValueError("runtime source eligibility TTL is invalid")
            age_seconds = (now - observed_at).total_seconds()
            if freshness_required and (
                age_seconds < 0 or age_seconds > ttl_seconds
            ):
                raise ValueError("runtime source eligibility receipt is stale")
            if (
                receipt.evidence is SourceTransitionEvidence.RUNTIME_AVAILABILITY_PROOF
                and head_sequence != 3
            ) or (
                receipt.evidence
                is SourceTransitionEvidence.SAME_SEMANTICS_RECERTIFICATION
                and (head_sequence < 5 or head_sequence % 2 == 0)
            ):
                raise ValueError("runtime source receipt appears at an invalid transition")
            require_edge(
                index.event_record(stream, 1),
                sequence=1,
                state="context_only",
                evidence=None,
            )
            require_edge(
                index.event_record(stream, 2),
                sequence=2,
                state="historical_audited",
                evidence=SourceTransitionEvidence.HISTORICAL_AUDIT,
            )
            if receipt.evidence is SourceTransitionEvidence.SAME_SEMANTICS_RECERTIFICATION:
                initial_runtime = index.event_record(stream, 3)
                initial_receipt = require_edge(
                    initial_runtime,
                    sequence=3,
                    state="runtime_eligible",
                    evidence=SourceTransitionEvidence.RUNTIME_AVAILABILITY_PROOF,
                )
                assert initial_receipt is not None
                require_edge(
                    index.event_record(stream, head_sequence - 1),
                    sequence=head_sequence - 1,
                    state="suspended",
                    evidence=SourceTransitionEvidence.DRIFT,
                )
            return record
        except Exception as exc:
            if isinstance(exc, error_type):
                raise
            raise error_type(
                f"source {source_id!r} lacks current runtime provenance"
            ) from exc

    def _require_source_authority_for_actions(
        self,
        index: LocalIndex,
        source_id: str,
        *,
        actions: Sequence[str],
        error_type: type[Exception] = TransitionError,
    ) -> IndexRecord:
        """Apply one source-freshness policy consistently at all action gates."""

        normalized = tuple(actions)
        allowed = {"performance_batch", "runtime_source_use"}
        if (
            not normalized
            or len(set(normalized)) != len(normalized)
            or any(type(action) is not str or action not in allowed for action in normalized)
        ):
            raise error_type("source authority action policy is invalid")
        return self._require_runtime_source(
            index,
            source_id,
            freshness_required="runtime_source_use" in normalized,
            error_type=error_type,
        )

    def _require_stable_locked(
        self,
        index: LocalIndex | LocalIndexView,
        *,
        allow_empty: bool = False,
    ) -> dict[str, Any] | None:
        control = self.control.read()
        journal_head, journal_event = self.journal.tail()
        index_head = index.event_head("control")
        if control is None:
            if (
                allow_empty
                and type(journal_head.sequence) is int
                and journal_head.sequence == 0
                and index_head is None
            ):
                return None
            raise RecoveryRequired("control is absent or trails durable state")
        if (
            control["authority"].get("manifest_digest")
            != self._authority_manifest_digest(control["authority"])
        ):
            raise RecoveryRequired("authority or Foundation input content drifted")
        state_head = control["heads"]["journal"]
        index_state_head = control["heads"]["index"]
        revision = _require_authority_integer(
            "control revision",
            control.get("revision"),
            error_type=ControlStateError,
        )
        state_sequence = _require_authority_integer(
            "control journal sequence",
            state_head.get("sequence"),
            error_type=ControlStateError,
        )
        required_index_sequence = _require_authority_integer(
            "control index sequence",
            index_state_head.get("required_sequence"),
            error_type=ControlStateError,
        )
        required_record_count = _require_authority_integer(
            "control index record count",
            index_state_head.get("required_record_count"),
            error_type=ControlStateError,
        )
        if required_index_sequence != state_sequence:
            raise ControlStateError("control index and journal sequences diverge")
        if revision != state_sequence:
            raise ControlStateError("control revision and journal head diverge")
        if (
            type(journal_head.sequence) is not int
            or journal_head.sequence != state_sequence
            or journal_head.event_id != state_head["event_id"]
        ):
            raise RecoveryRequired("control and journal require recovery")
        assert journal_event is not None
        if control != seal_control(self._assemble(journal_event)):
            raise RecoveryRequired("control content differs from journal authority")
        if (
            index_head is None
            or type(index_head.sequence) is not int
            or index_head.sequence != journal_head.sequence
            or index_head.fingerprint != journal_head.event_id
        ):
            raise RecoveryRequired("local index requires recovery")
        if index.record_count() != required_record_count:
            raise RecoveryRequired("local index contains an unauthoritative record count")
        projection_digest, projection_valid = index.projection_guard()
        if (
            not projection_valid
            or projection_digest
            != control["heads"]["index"]["required_projection_digest"]
        ):
            raise RecoveryRequired("local index projection digest requires recovery")
        return control

    def read_control(self) -> dict[str, Any] | None:
        return self.control.read()

    @contextmanager
    def open_stable_index(
        self,
    ) -> Iterator[tuple[dict[str, Any], LocalIndexView]]:
        """Yield one Journal-authenticated, query-only management snapshot.

        Reusable management workflows must not open the repository projection
        directly or pair an independently read control file with index rows.
        The read-only running-Job authority already owns the fail-closed stable
        boundary, including writer-lock coordination and full control, Journal,
        authority-manifest, projection-head, record-count, and digest checks.
        """

        authority = RunningJobAuthority(
            self.root,
            foundation_root=self.foundation_root,
        )
        try:
            with authority.open_stable_index() as snapshot:
                yield snapshot
        except RunningJobAuthorityError as exc:
            raise RecoveryRequired(str(exc)) from exc

    def require_stable_head(self) -> dict[str, Any]:
        """Return a read-only stable-head report without attempting recovery.

        Forest inspection commands use this bounded gate instead of calling
        ``recover()`` on every read.  Any control, Journal, index, projection,
        or authority-head mismatch fails closed through ``RecoveryRequired``;
        repair remains an explicit operator action.
        """

        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                current = self._require_stable_locked(index)
                assert current is not None
                projection_digest, projection_valid = index.projection_guard()
                if not projection_valid:
                    raise RecoveryRequired("local index projection requires recovery")
                return {
                    "control": _copy(current),
                    "control_revision": current["revision"],
                    "index_record_count": index.record_count(),
                    "journal_event_id": current["heads"]["journal"]["event_id"],
                    "projection_digest": projection_digest,
                }

    def require_exact_trailing_event_recovery_boundary(
        self,
        *,
        expected_sequence: int,
        expected_event_id: str,
        expected_operation_id: str,
        expected_previous_event_id: str,
    ) -> dict[str, Any]:
        """Admit recovery only from the exact projection before one event.

        This intentionally performs a full Journal-derived projection audit.
        It is an exceptional recovery boundary, never a routine stable read.
        """

        with WriterLock(self.lock_path):
            return self._require_exact_trailing_event_recovery_locked(
                expected_sequence=expected_sequence,
                expected_event_id=expected_event_id,
                expected_operation_id=expected_operation_id,
                expected_previous_event_id=expected_previous_event_id,
            )

    def _require_exact_trailing_event_recovery_locked(
        self,
        *,
        expected_sequence: int,
        expected_event_id: str,
        expected_operation_id: str,
        expected_previous_event_id: str,
    ) -> dict[str, Any]:
        if (
            type(expected_sequence) is not int
            or expected_sequence < 2
            or type(expected_event_id) is not str
            or not expected_event_id
            or type(expected_operation_id) is not str
            or not expected_operation_id
            or type(expected_previous_event_id) is not str
            or not expected_previous_event_id
        ):
            raise RecoveryRequired(
                "exact trailing-event recovery identity is malformed"
            )
        events = self.journal.read_all()
        if len(events) < 2:
            raise RecoveryRequired(
                "exact trailing-event recovery lacks a predecessor"
            )
        trailing = events[-1]
        previous = events[-2]
        if (
            trailing.get("sequence") != expected_sequence
            or trailing.get("event_id") != expected_event_id
            or trailing.get("operation_id") != expected_operation_id
            or trailing.get("previous_event_id") != expected_previous_event_id
            or previous.get("sequence") != expected_sequence - 1
            or previous.get("event_id") != expected_previous_event_id
        ):
            raise RecoveryRequired(
                "Journal tail is not the exact admitted recovery event"
            )
        current = self.control.read()
        if current is None:
            raise RecoveryRequired(
                "exact trailing-event recovery requires predecessor control"
            )
        predecessor_control = seal_control(self._assemble(previous))
        trailing_control = seal_control(self._assemble(trailing))
        if current == predecessor_control:
            control_position = "predecessor"
        elif current == trailing_control:
            control_position = "trailing_event"
        else:
            raise RecoveryRequired(
                "control is outside the exact trailing-event recovery pair"
            )
        expected_records: list[IndexRecord] = []
        for event in events[:-1]:
            expected_records.extend(self._event_records(event))
        with self._open_authoritative_index() as index:
            head = index.event_head("control")
            projection_digest, projection_valid = index.projection_guard()
            if (
                head is None
                or head.sequence != previous["sequence"]
                or head.fingerprint != previous["event_id"]
                or index.record_count() != previous["index_record_count"]
                or not projection_valid
                or projection_digest != previous["index_projection_digest"]
                or not index.full_maintenance_exactly_matches(expected_records)
            ):
                raise RecoveryRequired(
                    "local index is not the exact predecessor projection"
                )
        return {
            "control_position": control_position,
            "expected_event_id": expected_event_id,
            "expected_previous_event_id": expected_previous_event_id,
            "expected_sequence": expected_sequence,
            "full_projection_record_count": len(expected_records),
            "schema": "exact_trailing_event_recovery_boundary.v1",
        }

    @staticmethod
    def _effective_running_job_implementation(
        index: LocalIndex,
        *,
        job_id: str,
        declared_implementation_identity: str,
    ) -> tuple[str, str | None]:
        """Project the latest typed in-place implementation Repair."""
        try:
            return effective_repair_head_implementation(
                index,
                job_id=job_id,
                declared_implementation_identity=(
                    declared_implementation_identity
                ),
            )
        except RunningJobAuthorityIntegrityError as exc:
            raise RecoveryRequired(str(exc)) from exc

    def resume_repaired_job_execution(
        self,
        execution: RunningJobExecution,
        *,
        expected_callable_identity: str,
        operation_id: str,
        expected_evidence_subject: Mapping[str, str] | None = None,
        required_input_hashes: Sequence[str] = (),
    ) -> TransitionResult:
        """Durably re-enter the exact Job engine after a successful Repair."""

        if not isinstance(execution, RunningJobExecution):
            raise PermitError("Repair resume requires a running Job execution context")
        _require_ascii("expected callable identity", expected_callable_identity)
        expected_subject: dict[str, str] | None = None
        if expected_evidence_subject is not None:
            if (
                not isinstance(expected_evidence_subject, Mapping)
                or set(expected_evidence_subject) != {"kind", "id"}
            ):
                raise TransitionError("expected evidence subject is invalid")
            expected_subject = {
                "kind": _require_ascii(
                    "expected evidence subject kind",
                    expected_evidence_subject["kind"],
                ),
                "id": _require_ascii(
                    "expected evidence subject id",
                    expected_evidence_subject["id"],
                ),
            }
        required = tuple(required_input_hashes)
        for item in required:
            _require_digest("required Job input", item)
        if len(set(required)) != len(required):
            raise TransitionError("required Job inputs contain duplicates")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            job = science.get("active_job")
            if (
                not isinstance(job, dict)
                or job.get("status") != "running"
                or science.get("active_repair") is not None
                or job.get("id") != execution.job_id
                or job.get("hash") != execution.job_hash
                or job.get("start_record_id") != execution.start_record_id
            ):
                raise PermitError("repaired Job execution context is stale")
            close_id = job.get("required_repair_resume_record_id")
            direction = body.get("next_action")
            if (
                not isinstance(close_id, str)
                or not isinstance(direction, Mapping)
                or direction
                != {
                    "job_id": execution.job_id,
                    "kind": "resume_job",
                    "repair_close_record_id": close_id,
                }
            ):
                raise TransitionError("no exact repaired Job execution is pending")
            declaration = index.get("job-declared", execution.job_id)
            start = index.get("job-started", execution.start_record_id)
            spec = None if declaration is None else declaration.payload.get("spec")
            if (
                declaration is None
                or declaration.fingerprint != execution.job_hash
                or start is None
                or start.status != "running"
                or start.subject != f"Job:{execution.job_id}"
                or start.fingerprint != execution.job_hash
                or start.payload.get("job_permit_id") != execution.job_permit_id
                or not isinstance(spec, dict)
                or spec.get("callable_identity") != expected_callable_identity
                or (
                    expected_subject is not None
                    and spec.get("evidence_subject") != expected_subject
                )
                or not set(required).issubset(spec.get("input_hashes", []))
            ):
                raise PermitError("repaired Job differs from engine re-entry")
            close = index.get("repair-close", close_id)
            repair_head = index.event_head(f"job-repair:{execution.job_id}")
            effective_implementation, effective_close_id = (
                self._effective_running_job_implementation(
                    index,
                    job_id=execution.job_id,
                    declared_implementation_identity=spec[
                        "implementation_identity"
                    ],
                )
            )
            try:
                repaired_manifest = self._require_job_implementation_evidence(
                    {
                        **dict(spec),
                        "implementation_identity": effective_implementation,
                    },
                    _index=index,
                )
                from axiom_rift.research.implementation_closure import (
                    ImplementationClosureError,
                    require_current_job_source_closure,
                    require_job_implementation_closure,
                )

                subject = spec.get("evidence_subject")
                component_hashes: tuple[str, ...] = ()
                if (
                    isinstance(subject, Mapping)
                    and subject.get("kind") == "Executable"
                ):
                    trial = index.get("trial", str(subject.get("id")))
                    executable = (
                        None if trial is None else trial.payload.get("executable")
                    )
                    if not isinstance(executable, Mapping):
                        raise ImplementationClosureError(
                            "repaired Job lost its exact Executable closure"
                        )
                    component_hashes = require_job_implementation_closure(
                        executable_manifest=executable,
                        job_artifact_hashes=repaired_manifest["artifact_hashes"],
                        artifact_reader=self.evidence.read_verified,
                    )
                subject_kind = (
                    None
                    if not isinstance(subject, Mapping)
                    else subject.get("kind")
                )
                if _job_requires_current_source_authority(
                    engineering_fixture=self.engineering_fixture,
                    evidence_subject_kind=subject_kind,
                ):
                    require_current_job_source_closure(
                        callable_identity=str(spec["callable_identity"]),
                        job_artifact_hashes=repaired_manifest[
                            "artifact_hashes"
                        ],
                        artifact_reader=self.evidence.read_verified,
                        source_root=self.foundation_root / "src",
                        verified_non_source_artifact_hashes=component_hashes,
                    )
            except (ImplementationClosureError, TransitionError) as exc:
                raise RecoveryRequired(
                    "repaired Job current implementation authority drifted"
                ) from exc
            attempt_id = (
                None if close is None else close.payload.get("attempt_record_id")
            )
            attempt = (
                None
                if not isinstance(attempt_id, str)
                else index.get("repair-attempt", attempt_id)
            )
            repair_id = None if close is None else close.payload.get("repair_id")
            if (
                close is None
                or close.kind != "repair-close"
                or close.status != "repaired"
                or close.subject != f"Job:{execution.job_id}"
                or close.record_id != close_id
                or repair_head is None
                or repair_head.record_id != close_id
                or effective_close_id != close_id
                or close.payload.get("job_id") != execution.job_id
                or close.payload.get("effective_implementation_identity")
                != effective_implementation
                or close.payload.get("resume_action") != spec.get("resume_action")
                or not isinstance(repair_id, str)
                or attempt is None
                or attempt.status != "repaired"
                or attempt.subject != f"Repair:{repair_id}"
                or attempt.payload.get("repair_id") != repair_id
                or attempt.payload.get("job_id") != execution.job_id
            ):
                raise RecoveryRequired("repaired Job re-entry provenance is invalid")
            resume_payload = {
                "callable_identity": expected_callable_identity,
                "effective_implementation_identity": effective_implementation,
                "engine_entry_record_id": job.get("engine_entry_record_id"),
                "execution": execution.payload(),
                "repair_attempt_record_id": attempt_id,
                "repair_close_record_id": close_id,
                "repair_id": repair_id,
                "runtime_entry_record_id": job.get("runtime_entry_record_id"),
            }
            record_id = canonical_digest(
                domain="job-repaired-execution-resume",
                payload=resume_payload,
            )
            stream = f"job-resume:{execution.job_id}"
            head = index.event_head(stream)
            record = _record(
                kind="job-resumed",
                record_id=record_id,
                subject=f"Job:{execution.job_id}",
                status="validated",
                fingerprint=execution.job_hash,
                payload=resume_payload,
                event_stream=stream,
                event_sequence=1 if head is None else head.sequence + 1,
            )
            job.pop("required_repair_resume_record_id")
            job["last_repair_resume_record_id"] = record_id
            body["next_action"] = {
                "kind": "resume_job",
                "job_id": execution.job_id,
            }
            return body, [record], {
                "job_id": execution.job_id,
                "repair_close_record_id": close_id,
                "resume_record_id": record_id,
            }

        return self._commit(
            event_kind="job_repaired_execution_resumed",
            operation_id=operation_id,
            subject=f"Job:{execution.job_id}",
            payload={
                "execution": execution.payload(),
                "expected_callable_identity": expected_callable_identity,
                "expected_evidence_subject": expected_subject,
                "required_input_hashes": list(required),
            },
            prepare=prepare,
        )

    def verify_running_job_execution(
        self,
        execution: RunningJobExecution,
        *,
        expected_callable_identity: str,
        expected_evidence_subject: Mapping[str, str] | None = None,
        required_input_hashes: Sequence[str] = (),
    ) -> dict[str, Any]:
        """Reconstruct a non-runtime engine capability from Journal authority."""

        if not isinstance(execution, RunningJobExecution):
            raise PermitError("engine entry requires a running Job execution context")
        _require_ascii("expected callable identity", expected_callable_identity)
        expected_subject: dict[str, str] | None = None
        if expected_evidence_subject is not None:
            if (
                not isinstance(expected_evidence_subject, Mapping)
                or set(expected_evidence_subject) != {"kind", "id"}
            ):
                raise TransitionError("expected evidence subject is invalid")
            expected_subject = {
                "kind": _require_ascii(
                    "expected evidence subject kind",
                    expected_evidence_subject["kind"],
                ),
                "id": _require_ascii(
                    "expected evidence subject id",
                    expected_evidence_subject["id"],
                ),
            }
        required = tuple(required_input_hashes)
        for item in required:
            _require_digest("required Job input", item)
        if len(set(required)) != len(required):
            raise TransitionError("required Job inputs contain duplicates")

        control = self.read_control()
        active_job = (
            None
            if control is None
            else control.get("scientific", {}).get("active_job")
        )
        pending_repair_close = (
            None
            if not isinstance(active_job, dict)
            else active_job.get("required_repair_resume_record_id")
        )
        if isinstance(pending_repair_close, str):
            self.resume_repaired_job_execution(
                execution,
                expected_callable_identity=expected_callable_identity,
                expected_evidence_subject=expected_subject,
                required_input_hashes=required,
                operation_id=(
                    "resume-repaired-job-execution-" + pending_repair_close
                ),
            )
        authority = RunningJobAuthority(
            self.root,
            foundation_root=self.foundation_root,
        )
        try:
            return authority.verify_running_job_execution(
                execution,
                expected_callable_identity=expected_callable_identity,
                expected_evidence_subject=expected_subject,
                required_input_hashes=required,
            )
        except RunningJobAuthorityIntegrityError as exc:
            raise RecoveryRequired(str(exc)) from exc

    def verify_reproducible_cache_producer(
        self,
        producer: RunningJobExecution,
        *,
        cache_output_name: str,
        cache_hash: str,
        expected_callable_identity: str,
        expected_evidence_subject: Mapping[str, str],
        expected_output_classes: Mapping[str, str],
        expected_study_id: str,
        manifest_output_name: str,
        manifest_hash: str,
    ) -> None:
        """Require cache bytes to come from a completed validated Job."""
        authority = RunningJobAuthority(
            self.root,
            foundation_root=self.foundation_root,
        )
        try:
            authority.verify_reproducible_cache_producer(
                producer,
                cache_output_name=cache_output_name,
                cache_hash=cache_hash,
                expected_callable_identity=expected_callable_identity,
                expected_evidence_subject=expected_evidence_subject,
                expected_output_classes=expected_output_classes,
                expected_study_id=expected_study_id,
                manifest_output_name=manifest_output_name,
                manifest_hash=manifest_hash,
            )
        except RunningJobAuthorityIntegrityError as exc:
            raise RecoveryRequired(str(exc)) from exc
        except (RunningJobAuthorityError, ValueError) as exc:
            raise TransitionError(str(exc)) from exc

    def _commit(
        self,
        *,
        event_kind: str,
        operation_id: str,
        subject: str,
        payload: Mapping[str, Any],
        prepare: Prepare,
        evidence_blobs: Sequence[bytes] = (),
        authority_replacements: Sequence[Mapping[str, Any]] = (),
        authority_derivation_check: Callable[[], None] | None = None,
        journal_storage_migration: bool = False,
        crash_after: str | None = None,
        allow_empty: bool = False,
        read_only_when_unchanged: bool = False,
    ) -> TransitionResult:
        _require_ascii("event_kind", event_kind)
        _require_ascii("operation_id", operation_id)
        _require_ascii("subject", subject)
        if bool(authority_replacements) != (event_kind == "authority_migrated"):
            raise TransitionError(
                "authority replacements and the typed migration event are inseparable"
            )
        if authority_derivation_check is not None and event_kind != "authority_migrated":
            raise TransitionError(
                "authority derivation checks require the typed migration event"
            )
        if journal_storage_migration != (event_kind == "journal_storage_migrated"):
            raise TransitionError(
                "Journal storage materialization and its typed event are inseparable"
            )
        evidence = [self.evidence.finalize(blob).manifest() for blob in evidence_blobs]
        committed_payload = {**dict(payload), "evidence": evidence}
        operation_fingerprint = _digest(
            {"event_kind": event_kind, "payload": committed_payload},
            domain="operation",
        )
        if crash_after == "after_evidence":
            raise InjectedCrash("after_evidence")
        with WriterLock(self.lock_path):
            with self._open_mutable_authoritative_index() as index:
                current = self._require_stable_locked(index, allow_empty=allow_empty)
                existing = index.get("operation", operation_id)
                if existing is not None:
                    if existing.fingerprint != operation_fingerprint:
                        raise TransitionError("idempotency key reused with different input")
                    if (
                        existing.authority_sequence is None
                        or existing.authority_event_id is None
                    ):
                        raise IndexIntegrityError(
                            "idempotent operation lacks Journal authority"
                        )
                    return TransitionResult(
                        event_id=existing.authority_event_id,
                        revision=existing.authority_sequence,
                        reused=True,
                        result=existing.payload.get("result", {}),
                    )
                if current is not None:
                    science = current["scientific"]
                    pending_direction = current["next_action"].get("kind")
                    required_direction_events = {
                        "complete_engineering_failure": {"job_completed"},
                        "complete_runtime_source_ineligibility": {
                            "job_completed"
                        },
                        "diagnose_study": {"study_diagnosis_recorded"},
                        "dispose_revealed_holdout_engineering_gap": {
                            "holdout_engineering_gap_disposed"
                        },
                        "judge_external_dependency_evidence": {
                            "external_dependency_evidence_judged"
                        },
                        "judge_job_evidence": {
                            "job_evidence_judged",
                            "negative_memory_recorded",
                        },
                        "record_holdout_evaluation": {
                            "holdout_evaluated",
                            "negative_memory_recorded",
                        },
                        "record_axis_reopen_authority": {
                            "axis_reopen_authority_recorded"
                        },
                        "record_research_intake": {
                            "research_intake_recorded"
                        },
                        "record_source_eligibility": {
                            "source_eligibility_recorded"
                        },
                        "review_architecture": {
                            "architecture_review_recorded"
                        },
                        "resolve_candidate_engineering_gap": {
                            "candidate_disposed",
                            "job_declared",
                        },
                    }.get(pending_direction)
                    if (
                        required_direction_events is not None
                        and event_kind not in required_direction_events
                        and not _engineering_fixture_seed_exemption(
                            engineering_fixture=(
                                self.engineering_fixture
                                or self.study_close_guard_capability
                                is StudyCloseGuardCapability.ISOLATED_ENGINEERING_FIXTURE
                            ),
                            event_kind=event_kind,
                            subject=subject,
                            payload=committed_payload,
                        )
                    ):
                        direction_label = {
                            "complete_engineering_failure": (
                                "unrecovered engineering Job completion"
                            ),
                            "complete_runtime_source_ineligibility": (
                                "runtime source-ineligibility completion"
                            ),
                            "record_research_intake": "research intake",
                            "diagnose_study": "Study diagnosis",
                            "dispose_revealed_holdout_engineering_gap": (
                                "revealed holdout engineering-gap disposition"
                            ),
                            "judge_external_dependency_evidence": (
                                "external dependency judgement"
                            ),
                            "judge_job_evidence": "Job evidence judgement",
                            "record_holdout_evaluation": (
                                "revealed holdout disposition"
                            ),
                            "record_axis_reopen_authority": (
                                "audit-deferred axis reopen authority"
                            ),
                            "record_source_eligibility": (
                                "source eligibility transition"
                            ),
                            "review_architecture": "architecture review",
                            "resolve_candidate_engineering_gap": (
                                "candidate engineering-gap resolution"
                            ),
                        }[pending_direction]
                        raise TransitionError(
                            f"transition cannot bypass pending {direction_label}"
                        )
                    active_job = science.get("active_job")
                    active_repair = science.get("active_repair")
                    if isinstance(active_job, dict):
                        allowed_by_status = {
                            "declared": {
                                "permit_issued",
                                "permit_revoked",
                                "job_started",
                            },
                            "running": {
                                "engineering_failure_disposition_recorded",
                                "job_repaired_execution_resumed",
                                "permit_issued",
                                "permit_revoked",
                                "runtime_engine_entered",
                                "source_eligibility_recorded",
                                "holdout_revealed",
                                "job_completed",
                                "repair_opened",
                            },
                            "interrupted_repair": {
                                "repair_attempt_failed",
                                "repair_closed",
                                "repair_concluded_unrecovered",
                            },
                        }
                        if event_kind not in allowed_by_status.get(
                            active_job.get("status"), set()
                        ):
                            raise TransitionError(
                                "active Job must resume or complete before another transition"
                            )
                    if active_repair is not None and event_kind not in {
                        "repair_attempt_failed",
                        "repair_closed",
                        "repair_concluded_unrecovered",
                    }:
                        raise TransitionError(
                            "active Repair must close before another transition"
                        )
                    pending_terminal = current["next_action"]
                    frozen_release_withdrawal = (
                        pending_terminal.get("kind") == "close_mission"
                        and pending_terminal.get("outcome")
                        == "completed_pre_live_handoff"
                        and event_kind == "release_disposed"
                        and isinstance(science.get("active_release"), dict)
                        and science["active_release"].get("id")
                        == pending_terminal.get("basis_record_id")
                        and science["active_release"].get("status") == "frozen"
                    )
                    if (
                        pending_terminal.get("kind") == "close_mission"
                        and event_kind
                        not in {"mission_closed", "terminal_basis_withdrawn"}
                        and not frozen_release_withdrawal
                    ):
                        raise TransitionError(
                            "pending Mission terminal must close or be withdrawn exactly"
                        )
                    if science.get("active_holdout_evaluation") is not None and event_kind not in {
                        "engineering_failure_disposition_recorded",
                        "holdout_evaluated",
                        "holdout_engineering_gap_disposed",
                        "job_repaired_execution_resumed",
                        "negative_memory_recorded",
                        "job_completed",
                        "permit_issued",
                        "permit_revoked",
                        "repair_opened",
                        "repair_attempt_failed",
                        "repair_closed",
                        "repair_concluded_unrecovered",
                    }:
                        raise TransitionError(
                            "revealed holdout must receive a typed disposition before other work"
                        )
                    if (
                        current["next_action"].get("kind")
                        == "await_new_future_holdout_data"
                        and event_kind not in {"holdout_sealed", "external_blocker_recorded"}
                    ):
                        raise TransitionError(
                            "failed holdout requires genuinely later sealed data"
                        )
                    if (
                        current["next_action"].get("kind")
                        == "register_future_development_material"
                        and event_kind
                        not in {
                            "future_development_registered",
                            "external_blocker_recorded",
                        }
                    ):
                        raise TransitionError(
                            "successor holdout requires its typed future-development registration"
                        )
                next_body, records, result = prepare(current, index)
                if not isinstance(next_body, dict):
                    raise TransitionError("transition control body must be a mapping")
                if current is not None:
                    current_authority = current["authority"]
                    next_authority = next_body.get("authority")
                    if event_kind == "authority_migrated":
                        expected_authority = _copy(current_authority)
                        if isinstance(next_authority, dict):
                            expected_authority["manifest_digest"] = next_authority.get(
                                "manifest_digest"
                            )
                        if (
                            not isinstance(next_authority, dict)
                            or next_authority != expected_authority
                            or next_authority.get("manifest_digest")
                            == current_authority.get("manifest_digest")
                        ):
                            raise TransitionError(
                                "authority migration may change only the manifest digest"
                            )
                    elif next_authority != current_authority:
                        raise TransitionError(
                            "only a typed authority migration may change authority"
                        )
                preview = _copy(next_body)
                if current is None:
                    preview["revision"] = 1
                    preview["heads"] = {
                        "journal": {"sequence": 1, "event_id": "0" * 64},
                        "index": {
                            "required_sequence": 1,
                            "required_record_count": 1,
                            "required_projection_digest": "0" * 64,
                        },
                    }
                else:
                    preview["revision"] = current["revision"]
                    preview["heads"] = _copy(current["heads"])
                try:
                    seal_control(preview)
                except ControlStateError as exc:
                    raise TransitionError(
                        "transition produced an invalid control body"
                    ) from exc
                physical_authority = (
                    next_body.get("authority")
                    if current is None
                    else current.get("authority")
                )
                if not isinstance(physical_authority, Mapping):
                    raise TransitionError(
                        "transition authority manifest is unavailable"
                    )

                def require_preappend_authority() -> None:
                    expected_manifest = physical_authority.get(
                        "manifest_digest"
                    )
                    if (
                        type(expected_manifest) is not str
                        or expected_manifest
                        != self._authority_manifest_digest(
                            physical_authority
                        )
                    ):
                        raise RecoveryRequired(
                            "authority or Foundation input changed during transition preparation"
                        )
                    if authority_derivation_check is not None:
                        authority_derivation_check()

                if read_only_when_unchanged and not records:
                    if current is None or next_body != self._body(current):
                        raise TransitionError(
                            "read-only observation attempted to change control state"
                        )
                    require_preappend_authority()
                    head = self.journal.tail()[0]
                    return TransitionResult(
                        event_id=head.event_id or "",
                        revision=head.sequence,
                        reused=True,
                        result=dict(result),
                    )
                operation_record = _record(
                    kind="operation",
                    record_id=operation_id,
                    subject=subject,
                    status="success",
                    fingerprint=operation_fingerprint,
                    payload={
                        "event_kind": event_kind,
                        "result": dict(result),
                    },
                )
                all_records = [operation_record, *records]
                for record in all_records:
                    if index.get(record.kind, record.record_id) is not None:
                        raise RecordCollisionError(
                            "a new journal event cannot re-project an existing record key"
                        )
                current_head = (
                    JournalHead(0, None)
                    if current is None
                    else JournalHead(
                        current["heads"]["journal"]["sequence"],
                        current["heads"]["journal"]["event_id"],
                    )
                )
                projected_digest = index.projected_digest(all_records)
                event_occurred_at_utc = self.clock()
                _parse_utc("event occurred_at_utc", event_occurred_at_utc)
                require_preappend_authority()
                event = self.journal._append_authorized(
                    capability=self._journal_write_capability,
                    expected_head=current_head,
                    event_kind=event_kind,
                    operation_id=operation_id,
                    subject=subject,
                    occurred_at_utc=event_occurred_at_utc,
                    payload=committed_payload,
                    control=next_body,
                    index_records=[self._index_mapping(item) for item in all_records],
                    index_record_count=index.record_count() + 1 + len(all_records),
                    index_projection_digest=projected_digest,
                )
                if authority_derivation_check is not None:
                    authority_derivation_check()
                if crash_after == "after_journal":
                    raise InjectedCrash("after_journal")
                if journal_storage_migration:
                    def after_journal_storage_stage(label: str) -> None:
                        if crash_after == label:
                            raise InjectedCrash(label)

                    self.journal.materialize_legacy_migration(
                        event,
                        after_stage=after_journal_storage_stage,
                    )
                    if crash_after == "after_journal_storage":
                        raise InjectedCrash("after_journal_storage")
                if authority_replacements:
                    self._apply_authority_replacements(
                        authority=next_body["authority"],
                        replacements=authority_replacements,
                        expected_manifest_digest=next_body["authority"][
                            "manifest_digest"
                        ],
                    )
                if crash_after == "after_authority_files":
                    raise InjectedCrash("after_authority_files")
                replacement = self._assemble(event)
                self.control.compare_and_swap(
                    expected_revision=-1 if current is None else current["revision"],
                    expected_event_id=(
                        None
                        if current is None
                        else current["heads"]["journal"]["event_id"]
                    ),
                    replacement=replacement,
                )
                if crash_after == "after_cursor":
                    raise InjectedCrash("after_cursor")
                index.put_many(self._event_records(event))
                if crash_after == "after_index":
                    raise InjectedCrash("after_index")
                return TransitionResult(
                    event_id=event["event_id"],
                    revision=event["sequence"],
                    reused=False,
                    result=dict(result),
                )

    def recover(self) -> dict[str, Any]:
        """Explicitly reconcile control and index projections from authority."""

        with WriterLock(self.lock_path):
            return self._recover_locked()

    def recover_exact_trailing_event(
        self,
        *,
        expected_sequence: int,
        expected_event_id: str,
        expected_operation_id: str,
        expected_previous_event_id: str,
    ) -> dict[str, Any]:
        """Atomically prove and recover one exact trailing Journal event."""

        with WriterLock(self.lock_path):
            boundary = self._require_exact_trailing_event_recovery_locked(
                expected_sequence=expected_sequence,
                expected_event_id=expected_event_id,
                expected_operation_id=expected_operation_id,
                expected_previous_event_id=expected_previous_event_id,
            )
            report = self._recover_locked(
                expected_tail=(
                    expected_sequence,
                    expected_event_id,
                    expected_operation_id,
                    expected_previous_event_id,
                )
            )
        return {"recovery_boundary": boundary, **report}

    def _recover_locked(
        self,
        *,
        expected_tail: tuple[int, str, str, str] | None = None,
    ) -> dict[str, Any]:
        journal_storage_repaired = self.journal.recover_storage()
        events = self.journal.read_all()
        if expected_tail is not None:
            sequence, event_id, operation_id, previous_event_id = expected_tail
            if (
                not events
                or events[-1].get("sequence") != sequence
                or events[-1].get("event_id") != event_id
                or events[-1].get("operation_id") != operation_id
                or events[-1].get("previous_event_id") != previous_event_id
            ):
                raise RecoveryRequired(
                    "Journal tail changed after exact recovery admission"
                )
        control = self.control.read()
        if control is not None:
            sequence = control["heads"]["journal"]["sequence"]
            event_id = control["heads"]["journal"]["event_id"]
            if sequence > len(events):
                raise JournalIntegrityError("control claims a future journal head")
            if sequence and events[sequence - 1]["event_id"] != event_id:
                raise JournalIntegrityError("control claims a foreign journal head")
        if not events:
            if control is not None:
                raise JournalIntegrityError("control exists without journal authority")
            return {
                "journal_sequence": 0,
                "journal_storage_repaired": journal_storage_repaired,
                "control_repaired": False,
                "index_rebuilt": False,
                "study_kpi_projection_changed": False,
            }
        last = events[-1]
        desired = self._assemble(last)
        try:
            sealed_desired = seal_control(desired)
        except ControlStateError as exc:
            raise JournalIntegrityError(
                "latest Journal control body is invalid"
            ) from exc
        applied_sequence = (
            0 if control is None else control["heads"]["journal"]["sequence"]
        )
        with self._open_mutable_recovery_index() as index:
            projection_corrupt = False
            try:
                head = index.event_head("control")
                index.check_integrity()
            except IndexIntegrityError:
                head = None
                projection_corrupt = True
            if head is not None:
                if head.sequence > len(events):
                    raise JournalIntegrityError("index claims a future journal head")
                if events[head.sequence - 1]["event_id"] != head.fingerprint:
                    raise JournalIntegrityError("index claims a foreign journal head")
            self._apply_pending_authority_migrations(
                events=events,
                applied_sequence=applied_sequence,
                final_authority=desired["authority"],
            )
            if (
                self._authority_manifest_digest(desired["authority"])
                != desired["authority"]["manifest_digest"]
            ):
                raise RecoveryRequired(
                    "journal authority manifest is not materialized"
                )
            control_repaired = control is None or control != sealed_desired
            if control_repaired:
                self.control.replace(desired)
            records: list[IndexRecord] = []
            for event in events:
                records.extend(self._event_records(event))
            needs_rebuild = (
                projection_corrupt
                or head is None
                or head.sequence != last["sequence"]
                or head.fingerprint != last["event_id"]
                or index.record_count() != last["index_record_count"]
            )
            if not projection_corrupt and not index.exactly_matches(records):
                needs_rebuild = True
            if needs_rebuild:
                index.rebuild(records)
            index.check_integrity()
            if not index.exactly_matches(records):
                raise JournalIntegrityError(
                    "local index record set differs from Journal authority"
                )
            if index.record_count() != last["index_record_count"]:
                raise JournalIntegrityError(
                    "rebuilt index count differs from journal authority"
                )
            projection_digest, projection_valid = index.projection_guard()
            if (
                not projection_valid
                or projection_digest != last["index_projection_digest"]
            ):
                raise JournalIntegrityError(
                    "rebuilt index digest differs from journal authority"
                )
        report = {
            "journal_sequence": last["sequence"],
            "journal_storage_repaired": journal_storage_repaired,
            "control_repaired": control_repaired,
            "index_rebuilt": needs_rebuild,
        }
        # Recovery restores authority (Journal, control, and the reconstructible
        # SQLite projection).  The Markdown KPI ledger is lag-tolerant
        # navigation and is materialized only by explicit maintenance; making
        # every recovery render complete KPI history would reintroduce the
        # same history-linear bottleneck removed from routine Study close.
        report["study_kpi_projection_changed"] = False
        return report

    def initialize_ready(
        self,
        *,
        operation_id: str = "foundation-ready-boundary",
        crash_after: str | None = None,
    ) -> TransitionResult:
        body = ready_control_body()
        body["authority"]["manifest_digest"] = self._authority_manifest_digest(
            body["authority"]
        )
        if self.engineering_fixture:
            body["engineering"]["commissioning_fixture"] = True
        closeout_fingerprint = _digest(body["initiative"], domain="initiative-close")

        def prepare(
            current: dict[str, Any] | None, _index: LocalIndex
        ) -> tuple[dict[str, Any], list[IndexRecord], Mapping[str, Any]]:
            if current is not None:
                raise TransitionError("control is already initialized")
            record = _record(
                kind="initiative-close",
                record_id="INI-0001:completed_ready_boundary",
                subject="Initiative:INI-0001",
                status="completed_ready_boundary",
                fingerprint=closeout_fingerprint,
                payload={
                    "scientific_claim": "none",
                    "trial_delta": 0,
                    "holdout_delta": 0,
                    "next_action": "await_root_goal",
                },
            )
            return body, [record], {"outcome": "completed_ready_boundary"}

        return self._commit(
            event_kind="foundation_ready",
            operation_id=operation_id,
            subject="Initiative:INI-0001",
            payload={"scientific_claim": "none"},
            prepare=prepare,
            crash_after=crash_after,
            allow_empty=True,
        )

    @staticmethod
    def _authority_relative_paths(authority: Mapping[str, Any]) -> tuple[str, ...]:
        relative_paths = tuple(
            [authority["operating_direction"]]
            + list(authority["contracts"])
            + list(authority["foundation_inputs"])
        )
        if len(set(relative_paths)) != len(relative_paths):
            raise RecoveryRequired("authority manifest paths are not unique")
        return relative_paths

    @staticmethod
    def _authority_digest_from_hashes(hashes: Mapping[str, str]) -> str:
        return _digest(dict(sorted(hashes.items())), domain="authority-manifest")

    def _authority_path_hashes(
        self, authority: Mapping[str, Any]
    ) -> dict[str, str]:
        hashes: dict[str, str] = {}
        for relative in self._authority_relative_paths(authority):
            try:
                hashes[relative] = hash_foundation_file(
                    self.foundation_root,
                    relative,
                )
            except FoundationAuthorityFileError as exc:
                raise RecoveryRequired(str(exc)) from exc
        return hashes

    def _authority_manifest_digest(self, authority: Mapping[str, Any]) -> str:
        return self._authority_digest_from_hashes(
            self._authority_path_hashes(authority)
        )

    def _replace_authority_file(
        self,
        relative: str,
        content: bytes,
        *,
        expected_current_sha256: str,
    ) -> None:
        try:
            replace_foundation_file(
                self.foundation_root,
                relative,
                content,
                expected_current_sha256=expected_current_sha256,
            )
        except FoundationAuthorityFileError as exc:
            raise RecoveryRequired(str(exc)) from exc

    def _apply_authority_replacements(
        self,
        *,
        authority: Mapping[str, Any],
        replacements: Sequence[Mapping[str, Any]],
        expected_manifest_digest: str,
    ) -> None:
        rows = self._validated_authority_replacement_rows(
            authority=authority,
            replacements=replacements,
        )
        targets = {
            row["path"]: {
                "allowed_current_hashes": {row["old_sha256"]},
                "artifact_sha256": row["artifact_sha256"],
                "new_sha256": row["new_sha256"],
            }
            for row in rows
        }
        self._materialize_authority_targets(
            authority=authority,
            targets=targets,
            expected_manifest_digest=expected_manifest_digest,
        )

    def _validated_authority_replacement_rows(
        self,
        *,
        authority: Mapping[str, Any],
        replacements: Sequence[Mapping[str, Any]],
    ) -> tuple[dict[str, str], ...]:
        bound_paths = set(self._authority_relative_paths(authority))
        observed_paths: set[str] = set()
        rows: list[dict[str, str]] = []
        if not replacements:
            raise JournalIntegrityError("authority migration has no replacements")
        for replacement in replacements:
            if set(replacement) != {
                "artifact_sha256",
                "new_sha256",
                "old_sha256",
                "path",
            }:
                raise JournalIntegrityError(
                    "authority replacement schema is invalid"
                )
            relative = _require_ascii("authority replacement path", replacement["path"])
            if relative not in bound_paths or relative in observed_paths:
                raise JournalIntegrityError(
                    "authority replacement path is unbound or duplicated"
                )
            observed_paths.add(relative)
            old_hash = _require_digest(
                "authority old hash", replacement["old_sha256"]
            )
            new_hash = _require_digest(
                "authority new hash", replacement["new_sha256"]
            )
            artifact_hash = _require_digest(
                "authority artifact hash", replacement["artifact_sha256"]
            )
            if artifact_hash != new_hash or old_hash == new_hash:
                raise JournalIntegrityError(
                    "authority replacement identities are invalid"
                )
            rows.append(
                {
                    "artifact_sha256": artifact_hash,
                    "new_sha256": new_hash,
                    "old_sha256": old_hash,
                    "path": relative,
                }
            )
        return tuple(rows)

    def _materialize_authority_targets(
        self,
        *,
        authority: Mapping[str, Any],
        targets: Mapping[str, Mapping[str, Any]],
        expected_manifest_digest: str,
    ) -> None:
        current_hashes = self._authority_path_hashes(authority)
        to_write: list[tuple[str, bytes, str, str]] = []
        for relative in sorted(targets):
            target = targets[relative]
            if relative not in current_hashes or set(target) != {
                "allowed_current_hashes",
                "artifact_sha256",
                "new_sha256",
            }:
                raise JournalIntegrityError("authority target schema is invalid")
            allowed_current_hashes = target["allowed_current_hashes"]
            artifact_hash = _require_digest(
                "authority target artifact hash", target["artifact_sha256"]
            )
            new_hash = _require_digest(
                "authority target new hash", target["new_sha256"]
            )
            if (
                not isinstance(allowed_current_hashes, set)
                or not allowed_current_hashes
                or any(
                    type(value) is not str
                    or len(value) != 64
                    or any(character not in "0123456789abcdef" for character in value)
                    for value in allowed_current_hashes
                )
                or artifact_hash != new_hash
            ):
                raise JournalIntegrityError("authority target identities are invalid")
            current_hash = current_hashes[relative]
            if current_hash != new_hash:
                if current_hash not in allowed_current_hashes:
                    raise RecoveryRequired(
                        f"authority replacement source drifted: {relative}"
                    )
                content = self.evidence.read_verified(artifact_hash)
                to_write.append(
                    (relative, content, current_hash, new_hash)
                )
            current_hashes[relative] = new_hash
        if (
            self._authority_digest_from_hashes(current_hashes)
            != expected_manifest_digest
        ):
            raise RecoveryRequired(
                "authority replacement set does not produce the bound manifest"
            )
        for relative, content, current_hash, new_hash in to_write:
            self._replace_authority_file(
                relative,
                content,
                expected_current_sha256=current_hash,
            )
            try:
                materialized_hash = hash_foundation_file(
                    self.foundation_root,
                    relative,
                )
            except FoundationAuthorityFileError as exc:
                raise RecoveryRequired(str(exc)) from exc
            if materialized_hash != new_hash:
                raise RecoveryRequired(
                    f"authority replacement verification failed: {relative}"
                )
        if self._authority_manifest_digest(authority) != expected_manifest_digest:
            raise RecoveryRequired("authority migration manifest does not materialize")

    def _verify_foundation_data_derivation_event(
        self,
        *,
        event: Mapping[str, Any],
        binding: Mapping[str, Any],
    ) -> None:
        if set(binding) != {
            "data_document_sha256",
            "data_exposure_document_sha256",
            "material_identity",
            "proof_hash",
            "proof_id",
            "schema",
        } or binding.get("schema") != (
            "foundation_data_authority_derivation_binding.v1"
        ):
            raise JournalIntegrityError(
                "Foundation data derivation binding is malformed"
            )
        try:
            data_hash = _require_digest(
                "Foundation data document hash",
                binding.get("data_document_sha256"),
            )
            exposure_hash = _require_digest(
                "Foundation data exposure document hash",
                binding.get("data_exposure_document_sha256"),
            )
            proof_hash = _require_digest(
                "Foundation data derivation proof hash",
                binding.get("proof_hash"),
            )
            _require_digest(
                "Foundation material identity",
                binding.get("material_identity"),
            )
        except TransitionError as exc:
            raise JournalIntegrityError(
                "Foundation data derivation binding digests are malformed"
            ) from exc
        proof_id = binding.get("proof_id")
        if (
            type(proof_id) is not str
            or not proof_id.startswith("foundation-data-derivation:")
            or len(proof_id) != 91
        ):
            raise JournalIntegrityError(
                "Foundation data derivation proof identity is malformed"
            )
        evidence = event.get("payload", {}).get("evidence")
        if not isinstance(evidence, list):
            raise JournalIntegrityError(
                "Foundation data derivation evidence is absent"
            )
        evidenced_hashes = {
            item.get("sha256")
            for item in evidence
            if isinstance(item, Mapping)
        }
        if not {data_hash, exposure_hash, proof_hash}.issubset(evidenced_hashes):
            raise JournalIntegrityError(
                "Foundation data derivation evidence is incomplete"
            )
        try:
            data_document = self.evidence.read_verified(data_hash)
            data_exposure_document = self.evidence.read_verified(exposure_hash)
            proof_bytes = self.evidence.read_verified(proof_hash)
        except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
            raise RecoveryRequired(
                "Foundation data derivation evidence is unavailable or corrupt"
            ) from exc
        try:
            proof = FoundationDataDerivationProof.from_bytes(proof_bytes)
        except FoundationDataAuthorityError as exc:
            raise JournalIntegrityError(
                "Foundation data derivation proof is malformed"
            ) from exc
        if (
            proof.data_document_sha256 != data_hash
            or proof.data_exposure_document_sha256 != exposure_hash
            or foundation_data_derivation_binding(proof) != dict(binding)
        ):
            raise JournalIntegrityError(
                "Foundation data derivation event binding differs"
            )
        try:
            verify_foundation_data_derivation_proof(
                self.root,
                proof=proof,
                data_document=data_document,
                data_exposure_document=data_exposure_document,
            )
        except FoundationDataAuthorityError as exc:
            raise RecoveryRequired(str(exc)) from exc

    def _apply_pending_authority_migrations(
        self,
        *,
        events: Sequence[Mapping[str, Any]],
        applied_sequence: int,
        final_authority: Mapping[str, Any],
    ) -> None:
        targets: dict[str, dict[str, Any]] = {}
        latest_foundation_derivation: tuple[
            Mapping[str, Any], Mapping[str, Any]
        ] | None = None
        typed_foundation_boundary_seen = False
        for authoritative_event in events:
            if authoritative_event.get("event_kind") != "authority_migrated":
                continue
            authoritative_payload = authoritative_event.get("payload")
            if not isinstance(authoritative_payload, Mapping):
                raise JournalIntegrityError(
                    "authority migration payload is malformed"
                )
            authoritative_rows = authoritative_payload.get("replacements")
            if not isinstance(authoritative_rows, list) or any(
                not isinstance(row, Mapping) for row in authoritative_rows
            ):
                raise JournalIntegrityError(
                    "authority migration replacement rows are malformed"
                )
            row_paths = [row.get("path") for row in authoritative_rows]
            protected_paths = set(row_paths).intersection(
                PROTECTED_FOUNDATION_DATA_PATHS
            )
            binding = authoritative_payload.get("foundation_data_derivation")
            if binding is not None:
                if (
                    len(row_paths) != len(PROTECTED_FOUNDATION_DATA_PATHS)
                    or set(row_paths) != set(PROTECTED_FOUNDATION_DATA_PATHS)
                    or not isinstance(binding, Mapping)
                ):
                    raise JournalIntegrityError(
                        "typed Foundation data migration path set is invalid"
                    )
                latest_foundation_derivation = (
                    authoritative_event,
                    binding,
                )
                typed_foundation_boundary_seen = True
            elif "foundation_data_derivation" in authoritative_payload:
                raise JournalIntegrityError(
                    "Foundation data derivation binding is null"
                )
            elif protected_paths:
                # Historical migrations predate the prospective typed boundary.
                if typed_foundation_boundary_seen:
                    raise JournalIntegrityError(
                        "untyped Foundation data migration follows typed activation"
                    )
                latest_foundation_derivation = None
        for event in events[applied_sequence:]:
            if event.get("event_kind") != "authority_migrated":
                continue
            payload = event.get("payload")
            control = event.get("control")
            if not isinstance(payload, dict) or not isinstance(control, dict):
                raise JournalIntegrityError("authority migration event is malformed")
            replacements = payload.get("replacements")
            authority = control.get("authority")
            if not isinstance(replacements, list) or not isinstance(authority, dict):
                raise JournalIntegrityError("authority migration payload is malformed")
            sequence = event.get("sequence")
            if type(sequence) is not int or sequence <= 1 or sequence > len(events):
                raise JournalIntegrityError("authority migration sequence is invalid")
            previous_control = events[sequence - 2].get("control")
            previous_authority = (
                None
                if not isinstance(previous_control, dict)
                else previous_control.get("authority")
            )
            if not isinstance(previous_authority, dict):
                raise JournalIntegrityError(
                    "authority migration predecessor is malformed"
                )
            expected_authority = _copy(previous_authority)
            expected_authority["manifest_digest"] = authority.get("manifest_digest")
            if (
                authority != expected_authority
                or payload.get("schema") != "authority_manifest_migration.v1"
                or payload.get("old_manifest_digest")
                != previous_authority.get("manifest_digest")
                or payload.get("new_manifest_digest")
                != authority.get("manifest_digest")
            ):
                raise JournalIntegrityError("authority migration chain is invalid")
            rows = self._validated_authority_replacement_rows(
                authority=authority,
                replacements=replacements,
            )
            for row in rows:
                relative = row["path"]
                existing = targets.get(relative)
                if existing is None:
                    targets[relative] = {
                        "allowed_current_hashes": {
                            row["old_sha256"],
                            row["new_sha256"],
                        },
                        "artifact_sha256": row["artifact_sha256"],
                        "new_sha256": row["new_sha256"],
                    }
                    continue
                if existing["new_sha256"] != row["old_sha256"]:
                    raise JournalIntegrityError(
                        "authority replacement hash chain is discontinuous"
                    )
                existing["allowed_current_hashes"].add(row["new_sha256"])
                existing["artifact_sha256"] = row["artifact_sha256"]
                existing["new_sha256"] = row["new_sha256"]
        if latest_foundation_derivation is not None:
            event, binding = latest_foundation_derivation
            self._verify_foundation_data_derivation_event(
                event=event,
                binding=binding,
            )
        if targets:
            self._materialize_authority_targets(
                authority=final_authority,
                targets=targets,
                expected_manifest_digest=final_authority["manifest_digest"],
            )

    @staticmethod
    def _active_mission_stable_boundary(current: Mapping[str, Any]) -> bool:
        """Recognize the exact no-Initiative Mission scheduling boundary."""

        science = current["scientific"]
        mission_id = science.get("active_mission")
        authorizations = current.get("authorizations")
        raw_action = current.get("next_action")
        try:
            resume_action = ExternalResumeAction.from_next_action(raw_action)
        except (ExternalDependencyContractError, TypeError):
            resume_action = None
        stable_action = (
            resume_action is not None
            and resume_action.kind == "choose_next_initiative_or_terminal"
            and resume_action.mission_id == mission_id
            and resume_action.to_next_action() == raw_action
        )
        return (
            type(mission_id) is str
            and stable_action
            and science.get("active_initiative") is None
            and all(
                science.get(name) is None
                for name in (
                    "active_study",
                    "active_batch",
                    "active_job",
                    "active_repair",
                    "active_executable",
                    "active_lineage",
                    "active_release",
                    "active_holdout_evaluation",
                )
            )
            and isinstance(authorizations, dict)
            and set(authorizations) == {f"Mission:{mission_id}"}
            and science.get("claim") == "none"
            and science.get("holdout_reveals") == 0
            and science.get("required_future_holdout_id") is None
        )

    @staticmethod
    def _authority_migration_boundary(
        current: Mapping[str, Any], *, allow_active_stable_boundary: bool
    ) -> str | None:
        science = current["scientific"]
        inactive_names = (
            "active_study",
            "active_batch",
            "active_job",
            "active_repair",
            "active_executable",
            "active_lineage",
            "active_release",
            "active_holdout_evaluation",
        )
        disposed_root = (
            current["next_action"].get("kind") == "await_root_goal"
            and science.get("active_mission") is None
            and science.get("active_initiative") is None
            and all(science.get(name) is None for name in inactive_names)
            and current.get("authorizations") == {}
            and science.get("claim") == "none"
        )
        if disposed_root:
            return "disposed_root"
        active_authorizations = current.get("authorizations")
        mission_id = science.get("active_mission")
        initiative_id = science.get("active_initiative")
        active_stable = (
            allow_active_stable_boundary
            and (
                (
                    current["next_action"].get("kind") == "portfolio_decision"
                    and type(mission_id) is str
                    and type(initiative_id) is str
                    and all(science.get(name) is None for name in inactive_names)
                    and isinstance(active_authorizations, dict)
                    and set(active_authorizations)
                    == {f"Mission:{mission_id}", f"Initiative:{initiative_id}"}
                    and science.get("claim") == "none"
                )
                or StateWriter._active_mission_stable_boundary(current)
            )
        )
        return "active_stable" if active_stable else None

    def migrate_journal_storage(
        self,
        *,
        reason: str,
        operation_id: str,
        allow_active_stable_boundary: bool = False,
        crash_after: str | None = None,
    ) -> TransitionResult:
        """Seal exact legacy Journal bytes and activate segmented storage."""

        _require_ascii("Journal storage migration reason", reason)
        _require_ascii("operation_id", operation_id)
        if type(allow_active_stable_boundary) is not bool:
            raise TransitionError("active stable Journal migration flag must be bool")
        self._require_study_close_delivery_guard()

        if self.journal.manifest_path.is_file() and not self.journal.path.exists():
            with WriterLock(self.lock_path):
                with self._open_authoritative_index() as index:
                    self._require_stable_locked(index)
                    existing = index.get("operation", operation_id)
                    if (
                        existing is None
                        or existing.status != "success"
                        or existing.payload.get("event_kind")
                        != "journal_storage_migrated"
                        or existing.authority_sequence is None
                        or existing.authority_event_id is None
                    ):
                        raise TransitionError(
                            "segmented Journal lacks the requested migration operation"
                        )
                    return TransitionResult(
                        event_id=existing.authority_event_id,
                        revision=existing.authority_sequence,
                        reused=True,
                        result=existing.payload.get("result", {}),
                    )
        if not self.journal.path.is_file():
            raise TransitionError("legacy Journal is unavailable for migration")
        if self.journal.manifest_path.exists():
            raise TransitionError("legacy and segmented Journal layouts overlap")
        if self.journal.segment_directory.is_dir() and any(
            path.is_file() and not path.name.startswith(".")
            for path in self.journal.segment_directory.iterdir()
        ):
            raise TransitionError("Journal segment residue precedes migration")

        legacy_content = self.journal.path.read_bytes()
        legacy_events = self.journal.read_all()
        if not legacy_events:
            raise TransitionError("Journal storage migration requires authority")
        pre_migration = {
            "byte_length": len(legacy_content),
            "sha256": sha256(legacy_content).hexdigest(),
            "first_sequence": legacy_events[0]["sequence"],
            "last_sequence": legacy_events[-1]["sequence"],
            "first_event_id": legacy_events[0]["event_id"],
            "last_event_id": legacy_events[-1]["event_id"],
        }
        boundary_name = (
            "active_stable"
            if allow_active_stable_boundary
            else "disposed_root"
        )
        migration_payload = {
            "schema": JOURNAL_STORAGE_MIGRATION_SCHEMA,
            "boundary": boundary_name,
            "reason": reason,
            "legacy_path": LEGACY_JOURNAL_RELATIVE_PATH,
            "manifest_path": JOURNAL_MANIFEST_RELATIVE_PATH,
            "sealed_segment_id": "000001",
            "sealed_segment_path": "records/journal/journal-000001.jsonl",
            "seal_path": "records/journal/journal-000001.seal.json",
            "active_segment_id": "000002",
            "active_segment_path": "records/journal/journal-000002.jsonl",
            "pre_migration": pre_migration,
            "trial_delta": 0,
            "holdout_delta": 0,
            "candidate_delta": 0,
            "claim_delta": 0,
            "recovery_action": "StateWriter.recover",
        }
        migration_id = canonical_digest(
            domain="journal-storage-migration", payload=migration_payload
        )

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("Journal storage migration requires control")
            boundary = self._authority_migration_boundary(
                current,
                allow_active_stable_boundary=allow_active_stable_boundary,
            )
            if boundary != boundary_name:
                raise TransitionError(
                    "Journal storage migration requires a disposed root or "
                    "authorized active Portfolio boundary"
                )
            if self.journal.manifest_path.exists():
                raise RecoveryRequired("Journal storage changed before migration")
            observed = self.journal.path.read_bytes()
            observed_events = self.journal.read_all()
            if (
                len(observed) != pre_migration["byte_length"]
                or sha256(observed).hexdigest() != pre_migration["sha256"]
                or not observed_events
                or observed_events[0]["event_id"]
                != pre_migration["first_event_id"]
                or observed_events[-1]["sequence"]
                != pre_migration["last_sequence"]
                or observed_events[-1]["event_id"]
                != pre_migration["last_event_id"]
                or current["heads"]["journal"]["event_id"]
                != pre_migration["last_event_id"]
            ):
                raise RecoveryRequired("legacy Journal changed before migration")
            body = self._body(current)
            record = _record(
                kind="journal-storage-migration",
                record_id=migration_id,
                subject="Journal:authority",
                status="activated",
                fingerprint=migration_id,
                payload=migration_payload,
            )
            return body, [record], {
                "migration_id": migration_id,
                "manifest_path": JOURNAL_MANIFEST_RELATIVE_PATH,
                "active_segment_path": migration_payload[
                    "active_segment_path"
                ],
            }

        return self._commit(
            event_kind="journal_storage_migrated",
            operation_id=operation_id,
            subject="Journal:authority",
            payload=migration_payload,
            prepare=prepare,
            journal_storage_migration=True,
            crash_after=crash_after,
        )

    def migrate_authority(
        self,
        *,
        replacements: Mapping[str, bytes],
        reason: str,
        operation_id: str,
        allow_active_stable_boundary: bool = False,
        crash_after: str | None = None,
    ) -> TransitionResult:
        """Activate exact staged authority bytes without rewriting prior state."""

        return self._migrate_authority(
            replacements=replacements,
            reason=reason,
            operation_id=operation_id,
            allow_active_stable_boundary=allow_active_stable_boundary,
            foundation_data_boundary=False,
            crash_after=crash_after,
        )

    def migrate_foundation_data_authority(
        self,
        *,
        replacements: Mapping[str, bytes],
        reason: str,
        operation_id: str,
        allow_active_stable_boundary: bool = False,
        crash_after: str | None = None,
    ) -> TransitionResult:
        """Migrate both Foundation data documents under an exact derivation proof."""

        return self._migrate_authority(
            replacements=replacements,
            reason=reason,
            operation_id=operation_id,
            allow_active_stable_boundary=allow_active_stable_boundary,
            foundation_data_boundary=True,
            crash_after=crash_after,
        )

    def _migrate_authority(
        self,
        *,
        replacements: Mapping[str, bytes],
        reason: str,
        operation_id: str,
        allow_active_stable_boundary: bool,
        foundation_data_boundary: bool,
        crash_after: str | None,
    ) -> TransitionResult:
        """Shared authority migration engine with a protected data capability."""

        self.require_study_close_delivery_guard()
        _require_ascii("authority migration reason", reason)
        _require_ascii("operation_id", operation_id)
        if type(allow_active_stable_boundary) is not bool:
            raise TransitionError("active stable authority boundary flag must be bool")
        if not isinstance(replacements, Mapping) or not replacements:
            raise TransitionError("authority migration requires replacement bytes")
        if any(type(relative) is not str for relative in replacements):
            raise TransitionError("authority replacement paths must be strings")
        requested_paths = tuple(sorted(replacements))
        protected_paths = set(requested_paths).intersection(
            PROTECTED_FOUNDATION_DATA_PATHS
        )
        if foundation_data_boundary:
            if set(requested_paths) != set(PROTECTED_FOUNDATION_DATA_PATHS):
                raise TransitionError(
                    "typed Foundation data migration requires exactly both data documents"
                )
        elif protected_paths:
            raise TransitionError(
                "Foundation data documents require the typed derivation boundary"
            )
        for content in replacements.values():
            if type(content) is not bytes:
                raise TransitionError("authority replacement content must be bytes")
        foundation_data_document = (
            replacements[FOUNDATION_DATA_PATH]
            if foundation_data_boundary
            else None
        )
        foundation_data_exposure_document = (
            replacements[FOUNDATION_DATA_EXPOSURE_PATH]
            if foundation_data_boundary
            else None
        )
        foundation_proof: FoundationDataDerivationProof | None = None
        foundation_binding: dict[str, str] | None = None
        if foundation_data_boundary:
            assert foundation_data_document is not None
            assert foundation_data_exposure_document is not None
            try:
                foundation_proof = build_foundation_data_derivation_proof(
                    self.root,
                    data_document=foundation_data_document,
                    data_exposure_document=foundation_data_exposure_document,
                )
            except FoundationDataAuthorityError as exc:
                raise TransitionError(str(exc)) from exc
            foundation_binding = foundation_data_derivation_binding(
                foundation_proof
            )

        def authority_evidence_blobs() -> tuple[bytes, ...]:
            values = [replacements[relative] for relative in requested_paths]
            if foundation_proof is not None:
                values.append(foundation_proof.to_bytes())
            unique: list[bytes] = []
            observed_hashes: set[str] = set()
            for value in values:
                digest = sha256(value).hexdigest()
                if digest not in observed_hashes:
                    observed_hashes.add(digest)
                    unique.append(value)
            return tuple(unique)

        def require_foundation_derivation() -> None:
            if foundation_proof is None:
                return
            assert foundation_data_document is not None
            assert foundation_data_exposure_document is not None
            try:
                verify_foundation_data_derivation_proof(
                    self.root,
                    proof=foundation_proof,
                    data_document=foundation_data_document,
                    data_exposure_document=foundation_data_exposure_document,
                )
            except FoundationDataAuthorityError as exc:
                raise RecoveryRequired(str(exc)) from exc
        authority: dict[str, Any] | None = None
        old_hashes: dict[str, str] | None = None
        current_contents: dict[str, bytes] | None = None
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                stable = self._require_stable_locked(index)
                if stable is None:
                    raise TransitionError(
                        "authority migration requires initialized control"
                    )
                existing = index.get("operation", operation_id)
                if existing is None:
                    authority = _copy(stable["authority"])
                    bound_paths = set(self._authority_relative_paths(authority))
                    if any(path not in bound_paths for path in requested_paths):
                        raise TransitionError(
                            "authority migration names an unbound path"
                        )
                    old_hashes = self._authority_path_hashes(authority)
                    if (
                        self._authority_digest_from_hashes(old_hashes)
                        != authority.get("manifest_digest")
                    ):
                        raise RecoveryRequired(
                            "authority drift precedes the migration"
                        )
                    current_contents = {
                        relative: (self.foundation_root / relative).read_bytes()
                        for relative in requested_paths
                    }
                    if foundation_proof is not None:
                        try:
                            validate_foundation_data_identity_transition(
                                predecessor_data_document=current_contents[
                                    FOUNDATION_DATA_PATH
                                ],
                                predecessor_data_exposure_document=current_contents[
                                    FOUNDATION_DATA_EXPOSURE_PATH
                                ],
                                successor_proof=foundation_proof,
                            )
                        except FoundationDataAuthorityError as exc:
                            raise TransitionError(str(exc)) from exc
        if existing is not None:
            if (
                existing.status != "success"
                or existing.payload.get("event_kind") != "authority_migrated"
                or existing.authority_sequence is None
                or existing.authority_event_id is None
                or existing.authority_offset is None
            ):
                raise TransitionError("existing authority migration operation is invalid")
            event = self.journal.read_event_at(
                offset=existing.authority_offset,
                expected_sequence=existing.authority_sequence,
                expected_event_id=existing.authority_event_id,
            )
            event_payload = event.get("payload")
            if (
                event.get("operation_id") != operation_id
                or event.get("event_kind") != "authority_migrated"
                or not isinstance(event_payload, dict)
            ):
                raise TransitionError("existing authority migration payload is absent")
            rows = event_payload.get("replacements")
            observed = (
                {}
                if not isinstance(rows, list)
                else {row.get("path"): row.get("new_sha256") for row in rows}
            )
            requested = {
                relative: sha256(replacements[relative]).hexdigest()
                for relative in requested_paths
            }
            requested_boundary = (
                "active_stable"
                if allow_active_stable_boundary
                else "disposed_root"
            )
            if (
                event_payload.get("reason") != reason
                or event_payload.get("boundary") != requested_boundary
                or observed != requested
                or event_payload.get("foundation_data_derivation")
                != foundation_binding
            ):
                raise TransitionError("idempotency key reused with different input")
            base_payload = {
                key: value for key, value in event_payload.items() if key != "evidence"
            }

            def unreachable(_current, _index):
                raise TransitionError("existing migration unexpectedly prepared again")

            return self._commit(
                event_kind="authority_migrated",
                operation_id=operation_id,
                subject="Authority:active",
                payload=base_payload,
                prepare=unreachable,
                evidence_blobs=authority_evidence_blobs(),
                authority_replacements=tuple(rows),
                authority_derivation_check=(
                    require_foundation_derivation
                    if foundation_proof is not None
                    else None
                ),
                crash_after=crash_after,
            )
        assert authority is not None
        assert old_hashes is not None
        assert current_contents is not None
        old_manifest_digest = self._authority_digest_from_hashes(old_hashes)
        replacement_rows: list[dict[str, str]] = []
        new_hashes = dict(old_hashes)
        for relative in requested_paths:
            content = replacements[relative]
            _require_authority_document_bytes(
                relative=relative,
                current=current_contents[relative],
                replacement=content,
            )
            artifact = self.evidence.finalize(content)
            if artifact.sha256 == old_hashes[relative]:
                raise TransitionError("authority replacement does not change content")
            new_hashes[relative] = artifact.sha256
            replacement_rows.append(
                {
                    "artifact_sha256": artifact.sha256,
                    "new_sha256": artifact.sha256,
                    "old_sha256": old_hashes[relative],
                    "path": relative,
                }
            )
        new_manifest_digest = self._authority_digest_from_hashes(new_hashes)
        migration_payload = {
            "boundary": (
                "active_stable"
                if allow_active_stable_boundary
                else "disposed_root"
            ),
            "holdout_delta": 0,
            "new_manifest_digest": new_manifest_digest,
            "old_manifest_digest": old_manifest_digest,
            "reason": reason,
            "replacements": replacement_rows,
            "schema": "authority_manifest_migration.v1",
            "scientific_claim": "none",
            "trial_delta": 0,
        }
        if foundation_binding is not None:
            migration_payload["foundation_data_derivation"] = foundation_binding
        migration_id = canonical_digest(
            domain="authority-manifest-migration", payload=migration_payload
        )

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("authority migration requires control")
            if (
                current["authority"].get("manifest_digest")
                != old_manifest_digest
                or self._authority_path_hashes(current["authority"]) != old_hashes
            ):
                raise RecoveryRequired("authority changed before migration commit")
            boundary = self._authority_migration_boundary(
                current,
                allow_active_stable_boundary=allow_active_stable_boundary,
            )
            if boundary is None:
                raise TransitionError(
                    "authority migration requires a disposed root or authorized "
                    "active Portfolio boundary"
                )
            if boundary != migration_payload["boundary"]:
                raise TransitionError("authority migration boundary differs")
            body = self._body(current)
            body["authority"]["manifest_digest"] = new_manifest_digest
            record = _record(
                kind="authority-migration",
                record_id=migration_id,
                subject="Authority:active",
                status="activated",
                fingerprint=migration_id,
                payload=migration_payload,
            )
            return body, [record], {
                "migration_id": migration_id,
                "new_manifest_digest": new_manifest_digest,
            }

        return self._commit(
            event_kind="authority_migrated",
            operation_id=operation_id,
            subject="Authority:active",
            payload=migration_payload,
            prepare=prepare,
            evidence_blobs=authority_evidence_blobs(),
            authority_replacements=tuple(replacement_rows),
            authority_derivation_check=(
                require_foundation_derivation
                if foundation_proof is not None
                else None
            ),
            crash_after=crash_after,
        )

    def activate_project_goal_continuation(
        self,
        *,
        predecessor_mission_id: str,
        predecessor_mission_close_record_id: str,
        operation_id: str,
    ) -> TransitionResult:
        """Adopt one legacy negative terminal as the successor boundary."""

        _require_ascii("predecessor Mission id", predecessor_mission_id)
        _require_digest(
            "predecessor Mission close record",
            predecessor_mission_close_record_id,
        )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("Project Goal activation requires control")
            science = current["scientific"]
            if (
                current["next_action"] != {"kind": "await_root_goal"}
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_mission",
                        "active_initiative",
                        "active_study",
                        "active_batch",
                        "active_job",
                        "active_repair",
                        "active_executable",
                        "active_lineage",
                        "active_release",
                        "active_holdout_evaluation",
                    )
                )
                or current["authorizations"] != {}
            ):
                raise TransitionError(
                    "Project Goal activation requires the bare root boundary"
                )
            if index.event_head("project-goal:OPERATING_DIRECTION.md") is not None:
                raise TransitionError("Project Goal continuation is already activated")
            close_record = index.get(
                "mission-close", predecessor_mission_close_record_id
            )
            mission_open = index.get("mission-open", predecessor_mission_id)
            mission_closes = index.records_by_kind("mission-close")
            latest_close = (
                None
                if not mission_closes
                else max(
                    mission_closes,
                    key=lambda record: (
                        -1
                        if record.authority_sequence is None
                        else record.authority_sequence,
                        -1
                        if record.authority_offset is None
                        else record.authority_offset,
                    ),
                )
            )
            basis_id = (
                None
                if close_record is None
                else close_record.payload.get("basis_record_id")
            )
            basis = (
                None
                if not isinstance(basis_id, str)
                else index.get("exhaustion-audit", basis_id)
            )
            if (
                close_record is None
                or close_record.subject != f"Mission:{predecessor_mission_id}"
                or close_record.status != "closed_no_candidate"
                or mission_open is None
                or mission_open.subject != f"Mission:{predecessor_mission_id}"
                or mission_open.status != "open"
                or basis is None
                or basis.status != "accepted"
                or basis.subject != f"Mission:{predecessor_mission_id}"
                or latest_close is None
                or latest_close.record_id != predecessor_mission_close_record_id
            ):
                raise TransitionError(
                    "legacy predecessor is not an accepted negative terminal"
                )
            body = self._body(current)
            body["next_action"] = {
                "kind": "await_root_goal",
                "predecessor_basis_record_id": basis_id,
                "predecessor_mission_close_record_id": (
                    predecessor_mission_close_record_id
                ),
                "predecessor_mission_id": predecessor_mission_id,
                "predecessor_outcome": "closed_no_candidate",
            }
            adoption_payload = {
                "adopted_mission_close_record_id": (
                    predecessor_mission_close_record_id
                ),
                "basis_record_id": basis_id,
                "mission_id": predecessor_mission_id,
                "no_retroactive_authorization": True,
                "project_goal_authority": current["authority"][
                    "operating_direction"
                ],
                "schema": "project_goal_continuation_adoption.v1",
            }
            adoption_id = canonical_digest(
                domain="project-goal-continuation-adoption",
                payload=adoption_payload,
            )
            record = _record(
                kind="project-goal-adoption",
                record_id=adoption_id,
                subject="ProjectGoal:OPERATING_DIRECTION.md",
                status="active",
                fingerprint=adoption_id,
                payload=adoption_payload,
                event_stream="project-goal:OPERATING_DIRECTION.md",
                event_sequence=1,
            )
            return body, [record], {
                "adoption_id": adoption_id,
                "next_mission_ordinal": 2,
            }

        return self._commit(
            event_kind="project_goal_continuation_activated",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "predecessor_mission_close_record_id": (
                    predecessor_mission_close_record_id
                ),
                "predecessor_mission_id": predecessor_mission_id,
            },
            prepare=prepare,
        )

    @staticmethod
    def _authorization(
        *, kind: SubjectKind, subject_id: str, semantic_hash: str, epoch: int = 1
    ) -> SubjectRef:
        authorization_hash = _digest(
            {
                "kind": kind.value,
                "subject_id": subject_id,
                "semantic_hash": semantic_hash,
                "epoch": epoch,
            },
            domain="subject-authorization",
        )
        return SubjectRef(
            kind=kind,
            subject_id=subject_id,
            authorization_epoch=epoch,
            authorization_hash=authorization_hash,
        )

    @staticmethod
    def _bind_authorization(body: dict[str, Any], subject: SubjectRef) -> None:
        body["authorizations"][subject.key] = subject.payload()

    @staticmethod
    def _drop_authorization(
        body: dict[str, Any], kind: SubjectKind, subject_id: str
    ) -> None:
        body["authorizations"].pop(f"{kind.value}:{subject_id}", None)

    @staticmethod
    def _current_subject(
        control: Mapping[str, Any], kind: SubjectKind, subject_id: str
    ) -> SubjectRef:
        value = control["authorizations"].get(f"{kind.value}:{subject_id}")
        if not isinstance(value, dict):
            raise PermitError("permit subject is not active")
        return SubjectRef(
            kind=kind,
            subject_id=subject_id,
            authorization_epoch=value["authorization_epoch"],
            authorization_hash=value["authorization_hash"],
        )

    @staticmethod
    def _permit_status(index: LocalIndex, permit_id: str) -> PermitStatus:
        head = index.event_head(f"permit:{permit_id}")
        if head is None:
            raise PermitError("permit was not issued by this journal")
        latest = index.get(head.record_kind, head.record_id)
        if latest is None or latest.fingerprint != permit_id:
            raise PermitError("permit status projection is invalid")
        if latest.kind == "permit-revoked":
            return PermitStatus.REVOKED
        if latest.kind == "permit-consumed":
            return PermitStatus.CONSUMED
        if latest.kind != "permit-issued":
            raise PermitError("permit status projection has an unknown record kind")
        return PermitStatus.ISSUED

    def open_mission(
        self,
        *,
        mission_id: str,
        goal: Mapping[str, Any],
        successor_basis: Mapping[str, Any] | None = None,
        operation_id: str,
    ) -> TransitionResult:
        _require_ascii("mission_id", mission_id)
        goal_manifest = _require_manifest(
            "goal",
            goal,
            required={"objective", "scope", "terminal_contract"},
        )
        goal_hash = _digest(goal_manifest, domain="mission-goal")
        supplied_successor = (
            None
            if successor_basis is None
            else _require_successor_basis(successor_basis)
        )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("Foundation is not initialized")
            body = self._body(current)
            science = body["scientific"]
            if science["active_mission"] is not None:
                raise TransitionError("a root Mission is already active")
            if index.get("mission-open", mission_id) is not None:
                raise TransitionError("Mission identity is already durable")
            boundary = body["next_action"]
            if boundary["kind"] != "await_root_goal":
                raise TransitionError("control is not at the root-goal boundary")
            if science.get("active_release") is not None:
                raise TransitionError("ready boundary contains an active Release")
            if science.get("active_holdout_evaluation") is not None:
                raise TransitionError("ready boundary contains an active holdout")
            predecessor_keys = {
                "kind",
                "predecessor_basis_record_id",
                "predecessor_mission_close_record_id",
                "predecessor_mission_id",
                "predecessor_outcome",
            }
            predecessor: dict[str, Any] | None = None
            if set(boundary) == {"kind"}:
                if supplied_successor is not None:
                    raise TransitionError(
                        "the first Mission cannot declare a successor basis"
                    )
                if index.count_by_kind("mission-close"):
                    raise TransitionError(
                        "a bare boundary with Mission history requires typed adoption"
                    )
                mission_ordinal = 1
                science["holdout_reveals"] = 0
                science["required_future_holdout_id"] = None
            elif set(boundary) == predecessor_keys:
                if boundary["predecessor_outcome"] != "closed_no_candidate":
                    raise TransitionError(
                        "only a negative Mission terminal admits a successor"
                    )
                if (
                    supplied_successor is None
                    or supplied_successor["predecessor_mission_close_record_id"]
                    != boundary["predecessor_mission_close_record_id"]
                ):
                    raise TransitionError(
                        "successor basis does not bind the exact predecessor"
                    )
                close_record = index.get(
                    "mission-close",
                    boundary["predecessor_mission_close_record_id"],
                )
                if (
                    close_record is None
                    or close_record.subject
                    != f"Mission:{boundary['predecessor_mission_id']}"
                    or close_record.status != boundary["predecessor_outcome"]
                    or close_record.payload.get("basis_record_id")
                    != boundary["predecessor_basis_record_id"]
                ):
                    raise TransitionError(
                        "successor predecessor is absent or stale"
                    )
                predecessor_open = index.get(
                    "mission-open", boundary["predecessor_mission_id"]
                )
                if predecessor_open is None:
                    raise TransitionError("predecessor Mission open record is absent")
                prior_ordinal = predecessor_open.payload.get("mission_ordinal", 1)
                if type(prior_ordinal) is not int or prior_ordinal < 1:
                    raise TransitionError("predecessor Mission ordinal is invalid")
                mission_ordinal = prior_ordinal + 1
                predecessor = {
                    "continuation_reason": supplied_successor[
                        "continuation_reason"
                    ],
                    "predecessor_basis_record_id": boundary[
                        "predecessor_basis_record_id"
                    ],
                    "predecessor_mission_close_record_id": boundary[
                        "predecessor_mission_close_record_id"
                    ],
                    "predecessor_mission_id": boundary[
                        "predecessor_mission_id"
                    ],
                    "predecessor_outcome": boundary["predecessor_outcome"],
                }
            else:
                raise TransitionError("root-goal predecessor boundary is malformed")
            science["active_mission"] = mission_id
            body["next_action"] = (
                {"kind": "open_initiative", "mission_id": mission_id}
                if self.engineering_fixture
                else {"kind": "record_research_intake", "mission_id": mission_id}
            )
            authorization = self._authorization(
                kind=SubjectKind.MISSION,
                subject_id=mission_id,
                semantic_hash=goal_hash,
            )
            self._bind_authorization(body, authorization)
            project_stream = "project-goal:OPERATING_DIRECTION.md"
            project_head = index.event_head(project_stream)
            project_sequence = 1 if project_head is None else project_head.sequence + 1
            record = _record(
                kind="mission-open",
                record_id=mission_id,
                subject=f"Mission:{mission_id}",
                status="open",
                fingerprint=goal_hash,
                payload={
                    "goal_hash": goal_hash,
                    "goal": goal_manifest,
                    "mission_ordinal": mission_ordinal,
                    "project_goal_authority": body["authority"][
                        "operating_direction"
                    ],
                    "successor_basis": predecessor,
                },
                event_stream=project_stream,
                event_sequence=project_sequence,
            )
            return body, [record], {
                "mission_id": mission_id,
                "mission_ordinal": mission_ordinal,
                "project_goal_complete": False,
            }

        return self._commit(
            event_kind="mission_opened",
            operation_id=operation_id,
            subject=f"Mission:{mission_id}",
            payload={
                "mission_id": mission_id,
                "goal_hash": goal_hash,
                "goal": goal_manifest,
                "successor_basis": supplied_successor,
            },
            prepare=prepare,
        )

    @staticmethod
    def _derive_research_history_summary(index: LocalIndex) -> dict[str, Any]:
        studies = index.records_by_kind("study-open")
        closes = index.records_by_kind("study-close")
        trials = index.records_by_kind("trial")
        layer_counts: dict[str, int] = {}
        architecture_counts: dict[str, int] = {}
        component_domain_trial_counts: dict[str, int] = {}
        classified_studies = 0
        for study in studies:
            layer = study.payload.get("primary_research_layer")
            architecture = study.payload.get("system_architecture_family")
            if isinstance(layer, str) and isinstance(architecture, str):
                classified_studies += 1
                layer_counts[layer] = layer_counts.get(layer, 0) + 1
                architecture_counts[architecture] = (
                    architecture_counts.get(architecture, 0) + 1
                )
        for trial in trials:
            executable = trial.payload.get("executable")
            manifests = (
                None
                if not isinstance(executable, dict)
                else executable.get("component_manifests")
            )
            if not isinstance(manifests, list):
                continue
            seen_domains: set[str] = set()
            for manifest in manifests:
                protocol = (
                    None
                    if not isinstance(manifest, dict)
                    else manifest.get("protocol")
                )
                if isinstance(protocol, str) and protocol:
                    seen_domains.add(protocol.split(".", 1)[0])
            for domain in seen_domains:
                component_domain_trial_counts[domain] = (
                    component_domain_trial_counts.get(domain, 0) + 1
                )
        outcome_counts: dict[str, int] = {}
        for close in closes:
            outcome_counts[close.status] = outcome_counts.get(close.status, 0) + 1
        evidence_state_counts: dict[str, int] = {}
        for diagnosis in index.records_by_kind("study-diagnosis"):
            evidence_state_counts[diagnosis.status] = (
                evidence_state_counts.get(diagnosis.status, 0) + 1
            )
        mission_outcomes: dict[str, int] = {}
        for close in index.records_by_kind("mission-close"):
            mission_outcomes[close.status] = mission_outcomes.get(close.status, 0) + 1
        return {
            "candidate_record_count": index.count_by_kind("candidate"),
            "architecture_review_count": index.count_by_kind(
                "architecture-review"
            ),
            "classified_study_count": classified_studies,
            "component_domain_trial_counts": dict(
                sorted(component_domain_trial_counts.items())
            ),
            "legacy_unclassified_study_count": len(studies) - classified_studies,
            "evidence_state_counts": dict(sorted(evidence_state_counts.items())),
            "mission_outcome_counts": dict(sorted(mission_outcomes.items())),
            "negative_memory_count": index.count_by_kind("negative-memory"),
            "research_layer_study_counts": dict(sorted(layer_counts.items())),
            "study_count": len(studies),
            "study_kpi_count": index.count_by_kind("study-kpi"),
            "study_outcome_counts": dict(sorted(outcome_counts.items())),
            "system_architecture_study_counts": dict(
                sorted(architecture_counts.items())
            ),
            "trial_count": len(trials),
        }

    def record_research_intake(
        self,
        *,
        intake: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.research.governance import MissionResearchIntake

        self._require_study_close_delivery_guard()
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures do not create research intake")
        if not isinstance(intake, MissionResearchIntake):
            raise TransitionError("intake must be a MissionResearchIntake")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            if (
                science["active_mission"] != intake.mission_id
                or science["active_initiative"] is not None
                or any(
                    science[name] is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_job",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "research intake requires one Mission and no subordinate work"
                )
            if current["next_action"] != {
                "kind": "record_research_intake",
                "mission_id": intake.mission_id,
            }:
                raise TransitionError("research intake is not the exact next action")
            journal_head = current.get("heads", {}).get("journal", {})
            if (
                intake.history_head_sequence != current.get("revision")
                or intake.history_head_sequence != journal_head.get("sequence")
                or intake.history_head_event_id != journal_head.get("event_id")
            ):
                raise TransitionError("research intake history head is stale")
            if index.event_head(f"research-intake:{intake.mission_id}") is not None:
                raise TransitionError("Mission research intake already exists")
            history_summary = self._derive_research_history_summary(index)
            mission = index.get("mission-open", intake.mission_id)
            if mission is None:
                raise TransitionError("research intake Mission is unavailable")
            mission_ordinal = mission.payload.get("mission_ordinal")
            if (
                type(mission_ordinal) is not int
                or mission_ordinal < 1
                or (mission_ordinal > 1 and history_summary["study_count"] < 1)
            ):
                raise TransitionError("successor intake lacks predecessor research history")
            payload = {
                **intake.to_identity_payload(),
                "history_summary": history_summary,
                "holdout_reveals": science["holdout_reveals"],
                "mission_ordinal": mission_ordinal,
            }
            body = self._body(current)
            body["next_action"] = {
                "kind": "open_initiative",
                "mission_id": intake.mission_id,
                "research_intake_id": intake.identity,
            }
            record = _record(
                kind="research-intake",
                record_id=intake.identity,
                subject=f"Mission:{intake.mission_id}",
                status="accepted",
                fingerprint=intake.identity.removeprefix("research-intake:"),
                payload=payload,
                event_stream=f"research-intake:{intake.mission_id}",
                event_sequence=1,
            )
            return body, [record], {
                "research_intake_id": intake.identity,
                "history_summary": history_summary,
            }

        return self._commit(
            event_kind="research_intake_recorded",
            operation_id=operation_id,
            subject=f"Mission:{intake.mission_id}",
            payload={"research_intake_id": intake.identity},
            prepare=prepare,
        )

    def activate_research_protocol(
        self,
        *,
        activation: Any,
        operation_id: str,
        allow_active_stable_boundary: bool = False,
        allow_active_unexecuted_study_boundary: bool = False,
    ) -> TransitionResult:
        """Activate or rebind the prospective protocol to current authority."""

        from axiom_rift.research.protocol import (
            ResearchProtocol,
            ResearchProtocolActivation,
        )
        from axiom_rift.research.validation_v2 import (
            SCIENTIFIC_ADJUDICATION_VALIDATOR_V2_ID,
        )

        if not isinstance(activation, ResearchProtocolActivation):
            raise TransitionError("research protocol activation must be typed")
        if type(allow_active_stable_boundary) is not bool:
            raise TransitionError(
                "active stable research protocol boundary flag must be bool"
            )
        if type(allow_active_unexecuted_study_boundary) is not bool:
            raise TransitionError(
                "active unexecuted Study protocol boundary flag must be bool"
            )
        if (
            activation.protocol
            is not ResearchProtocol.SCIENTIFIC_ADJUDICATION_V2
            or activation.validator_id
            != SCIENTIFIC_ADJUDICATION_VALIDATOR_V2_ID
        ):
            raise TransitionError(
                "research protocol activation does not name the supported v2 validator"
            )
        self.evidence.verify(activation.audit_artifact_hash)
        try:
            self.validation_registry.require_registered(
                validator_id=activation.validator_id,
                domain="scientific",
            )
        except EvidenceValidationError as exc:
            raise TransitionError(
                "research protocol validator is unavailable or drifted"
            ) from exc
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("research protocol activation requires control")
            science = current["scientific"]
            if (
                current.get("authority", {}).get("manifest_digest")
                != activation.authority_manifest_digest
            ):
                raise TransitionError(
                    "research protocol activation is bound to another authority"
                )
            portfolio_boundary = (
                isinstance(science.get("active_mission"), str)
                and isinstance(science.get("active_initiative"), str)
                and current.get("next_action", {}).get("kind")
                == "portfolio_decision"
                and all(
                    science.get(name) is None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            )
            mission_boundary = (
                allow_active_stable_boundary
                and self._active_mission_stable_boundary(current)
            )
            active_batch = science.get("active_batch")
            active_study = science.get("active_study")
            active_batch_record = (
                None
                if not isinstance(active_batch, dict)
                else index.get(
                    "batch-open",
                    str(active_batch.get("id", "")),
                )
            )
            active_study_record = (
                None
                if not isinstance(active_study, str)
                else index.get("study-open", active_study)
            )
            registration_only_surface = False
            if (
                allow_active_unexecuted_study_boundary
                and active_batch_record is not None
                and active_study_record is not None
                and active_batch_record.status == "open"
                and active_batch_record.subject == f"Study:{active_study}"
                and index.event_head(
                    f"batch-budget:{active_batch_record.record_id}"
                )
                is None
                and not index.records_by_payload_text(
                    "job-declared",
                    "batch_id",
                    active_batch_record.record_id,
                )
            ):
                trial_head = index.event_head(
                    f"batch-trials:{active_batch_record.record_id}"
                )
                if trial_head is None:
                    registration_only_surface = True
                elif active_study_record.payload.get("replay_obligation_ids"):
                    from axiom_rift.operations.replay_study_admission import (
                        ReplayStudyAdmissionError,
                        inspect_replay_study_registration,
                    )

                    try:
                        inspect_replay_study_registration(
                            index,
                            study_record=active_study_record,
                            batch_record=active_batch_record,
                        ).require_usable()
                    except ReplayStudyAdmissionError as exc:
                        raise RecoveryRequired(str(exc)) from exc
                    registration_only_surface = True
            active_unexecuted_study_boundary = (
                allow_active_unexecuted_study_boundary
                and isinstance(science.get("active_mission"), str)
                and isinstance(science.get("active_initiative"), str)
                and isinstance(active_study, str)
                and isinstance(active_batch, dict)
                and current.get("next_action")
                == {
                    "kind": "declare_job",
                    "batch_id": active_batch.get("id"),
                }
                and all(
                    science.get(name) is None
                    for name in (
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                    )
                )
                and registration_only_surface
            )
            if not (
                portfolio_boundary
                or mission_boundary
                or active_unexecuted_study_boundary
            ):
                raise TransitionError(
                    "research protocol activation requires the stable Portfolio "
                    "boundary, its explicit stable Mission boundary, or an "
                    "explicit unexecuted Study boundary"
                )
            if (
                not isinstance(science.get("active_mission"), str)
                or (
                    not active_unexecuted_study_boundary
                    and any(
                        science.get(name) is not None
                        for name in (
                            "active_batch",
                            "active_executable",
                            "active_holdout_evaluation",
                            "active_job",
                            "active_lineage",
                            "active_release",
                            "active_repair",
                            "active_study",
                        )
                    )
                )
            ):
                raise TransitionError(
                    "research protocol activation has active scientific execution"
                )
            stream = "research-protocol:scientific"
            prior_head = index.event_head(stream)
            prior = (
                None
                if prior_head is None
                else index.get(prior_head.record_kind, prior_head.record_id)
            )
            prior_activation = None
            if prior is not None:
                try:
                    prior_activation = ResearchProtocolActivation(
                        protocol=ResearchProtocol(prior.payload.get("protocol")),
                        validator_id=prior.payload.get("validator_id"),
                        authority_manifest_digest=prior.payload.get(
                            "authority_manifest_digest"
                        ),
                        audit_artifact_hash=prior.payload.get(
                            "audit_artifact_hash"
                        ),
                    )
                except (TypeError, ValueError):
                    prior_activation = None
            if prior_head is not None and (
                prior is None
                or prior.kind != "research-protocol-activation"
                or prior.status != "active"
                or prior.event_sequence != prior_head.sequence
                or prior.subject != "ProjectGoal:OPERATING_DIRECTION.md"
                or prior_activation is None
                or prior.record_id != prior_activation.identity
                or prior.fingerprint
                != prior_activation.identity.removeprefix("research-protocol:")
                or prior.payload.get("schema")
                != "research_protocol_activation.v1"
                or prior.payload.get("ordinal") != prior_head.sequence
                or prior.payload.get("scientific_trial_delta") != 0
            ):
                raise RecoveryRequired(
                    "prospective scientific protocol projection is invalid"
                )
            if (
                prior is not None
                and prior.payload.get("authority_manifest_digest")
                == activation.authority_manifest_digest
                and prior.payload.get("validator_id") == activation.validator_id
            ):
                raise TransitionError(
                    "prospective scientific protocol is already bound to this "
                    "authority and validator"
                )
            ordinal = 1 if prior_head is None else prior_head.sequence + 1
            record = _record(
                kind="research-protocol-activation",
                record_id=activation.identity,
                subject="ProjectGoal:OPERATING_DIRECTION.md",
                status="active",
                fingerprint=activation.identity.removeprefix(
                    "research-protocol:"
                ),
                payload={
                    **activation.to_identity_payload(),
                    "ordinal": ordinal,
                    "scientific_trial_delta": 0,
                    "supersedes_activation_record_id": (
                        None if prior is None else prior.record_id
                    ),
                },
                event_stream=stream,
                event_sequence=ordinal,
            )
            return self._body(current), [record], {
                "activation_record_id": activation.identity,
                "ordinal": ordinal,
                "protocol": activation.protocol.value,
                "trial_delta": 0,
                "validator_id": activation.validator_id,
            }

        return self._commit(
            event_kind="research_protocol_activated",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload=activation.to_identity_payload(),
            prepare=prepare,
        )

    def open_initiative(
        self,
        *,
        initiative_id: str,
        objective: Mapping[str, Any],
        operation_id: str,
    ) -> TransitionResult:
        _require_ascii("initiative_id", initiative_id)
        objective_manifest = _require_manifest(
            "objective",
            objective,
            required={"objective", "bounds", "done_conditions"},
        )
        objective_hash = _digest(objective_manifest, domain="initiative-objective")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science["active_mission"] is None or science["active_initiative"] is not None:
                raise TransitionError("Initiative open requires one active Mission and no Initiative")
            portfolio_head = index.event_head(
                f"portfolio:{science['active_mission']}"
            )
            replay_constraints = self._replay_scheduler_constraints(
                index,
                mission_id=science["active_mission"],
            )
            incoming_replay = {
                name: current["next_action"].get(name)
                for name in (
                    "pending_replay_obligation_ids",
                    "required_replay_priority",
                )
                if current["next_action"].get(name) is not None
            }
            if incoming_replay != (replay_constraints or {}):
                raise TransitionError(
                    "Initiative admission replay scheduler authority is stale"
                )
            research_intake_id: str | None = None
            if not self.engineering_fixture:
                next_action = current["next_action"]
                if portfolio_head is None:
                    research_intake_id = next_action.get("research_intake_id")
                    intake = (
                        None
                        if not isinstance(research_intake_id, str)
                        else index.get("research-intake", research_intake_id)
                    )
                    if (
                        next_action.get("kind") != "open_initiative"
                        or next_action.get("mission_id") != science["active_mission"]
                        or intake is None
                        or intake.subject != f"Mission:{science['active_mission']}"
                        or intake.status != "accepted"
                    ):
                        raise TransitionError(
                            "first Initiative requires the exact accepted research intake"
                        )
                elif next_action.get("kind") not in {
                    "choose_next_initiative_or_terminal",
                    "open_initiative",
                } or next_action.get("mission_id") != science["active_mission"]:
                    raise TransitionError(
                        "successor Initiative is not the exact Mission boundary"
                    )
            science["active_initiative"] = initiative_id
            if portfolio_head is None:
                body["next_action"] = {
                    "kind": "build_portfolio",
                    "initiative_id": initiative_id,
                }
                if research_intake_id is not None:
                    body["next_action"]["research_intake_id"] = research_intake_id
            else:
                snapshot = index.get(
                    portfolio_head.record_kind, portfolio_head.record_id
                )
                if snapshot is None or snapshot.kind != "portfolio-snapshot":
                    raise TransitionError("Mission Portfolio head is unavailable")
                body["next_action"] = {
                    "kind": "portfolio_decision",
                    "portfolio_snapshot_id": snapshot.record_id,
                }
                if replay_constraints is not None:
                    body["next_action"].update(replay_constraints)
            authorization = self._authorization(
                kind=SubjectKind.INITIATIVE,
                subject_id=initiative_id,
                semantic_hash=objective_hash,
            )
            self._bind_authorization(body, authorization)
            record = _record(
                kind="initiative-open",
                record_id=initiative_id,
                subject=f"Initiative:{initiative_id}",
                status="open",
                fingerprint=objective_hash,
                payload={
                    "objective_hash": objective_hash,
                    "objective": objective_manifest,
                    "research_intake_id": research_intake_id,
                },
            )
            return body, [record], {"initiative_id": initiative_id}

        return self._commit(
            event_kind="initiative_opened",
            operation_id=operation_id,
            subject=f"Initiative:{initiative_id}",
            payload={
                "initiative_id": initiative_id,
                "objective_hash": objective_hash,
                "objective": objective_manifest,
            },
            prepare=prepare,
        )

    def close_initiative(
        self,
        *,
        outcome: str,
        operation_id: str,
    ) -> TransitionResult:
        _require_ascii("outcome", outcome)
        allowed = set(_INITIATIVE_OUTCOMES)
        if self.engineering_fixture:
            allowed.add(_ENGINEERING_FIXTURE_OUTCOME)
        if outcome not in allowed:
            raise TransitionError("Initiative outcome is not typed")

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            initiative_id = science["active_initiative"]
            if initiative_id is None:
                raise TransitionError("no active Initiative")
            if any(
                science[key] is not None
                for key in ("active_study", "active_batch", "active_job", "active_repair")
            ):
                raise TransitionError("Initiative close has undisposed active work")
            if (
                not self.engineering_fixture
                and body["next_action"].get("kind")
                in {"diagnose_study", "review_architecture"}
            ):
                raise TransitionError(
                    "Initiative close cannot bypass research diagnosis or review"
                )
            replay_heads = self._historical_replay_obligation_heads(
                _index,
                mission_id=science["active_mission"],
            )
            if any(head.status == "in_progress" for _, head in replay_heads):
                raise TransitionError(
                    "Initiative close cannot strand an in-progress historical replay"
                )
            science["active_initiative"] = None
            self._drop_authorization(body, SubjectKind.INITIATIVE, initiative_id)
            body["next_action"] = {
                "kind": "choose_next_initiative_or_terminal",
                "mission_id": science["active_mission"],
            }
            replay_constraints = self._replay_scheduler_constraints(
                _index,
                mission_id=science["active_mission"],
            )
            if replay_constraints is not None:
                body["next_action"].update(replay_constraints)
            fingerprint = _digest(
                {"initiative_id": initiative_id, "outcome": outcome},
                domain="initiative-close",
            )
            record = _record(
                kind="initiative-close",
                record_id=fingerprint,
                subject=f"Initiative:{initiative_id}",
                status=outcome,
                fingerprint=fingerprint,
                payload={"outcome": outcome},
            )
            return body, [record], {"initiative_id": initiative_id, "outcome": outcome}

        return self._commit(
            event_kind="initiative_closed",
            operation_id=operation_id,
            subject="Initiative:active",
            payload={"outcome": outcome},
            prepare=prepare,
        )

    @staticmethod
    def _portfolio_decision_withdrawal(
        index: LocalIndex,
        decision_id: str,
    ) -> IndexRecord | None:
        stream = f"portfolio-decision-status:{decision_id}"
        head = index.event_head(stream)
        if head is None:
            return None
        record = index.get(head.record_kind, head.record_id)
        if (
            record is None
            or record.kind != "portfolio-decision-withdrawal"
            or record.status != "withdrawn_pre_execution"
            or record.event_stream != stream
            or record.event_sequence != 1
            or head.sequence != 1
            or record.payload.get("decision_id") != decision_id
        ):
            raise RecoveryRequired(
                "Portfolio Decision withdrawal status projection is invalid"
            )
        return record

    @staticmethod
    def _active_portfolio_decision(
        index: LocalIndex,
        decision_id: str,
    ) -> IndexRecord | None:
        decision = index.get("portfolio-decision", decision_id)
        withdrawal = StateWriter._portfolio_decision_withdrawal(index, decision_id)
        if withdrawal is None:
            return decision
        if (
            decision is None
            or withdrawal.subject != decision.subject
            or withdrawal.fingerprint != decision.fingerprint
        ):
            raise RecoveryRequired(
                "withdrawn Portfolio Decision lost its accepted provenance"
            )
        return None

    @staticmethod
    def _historical_replay_obligation_heads(
        index: LocalIndex,
        *,
        mission_id: str,
    ) -> tuple[tuple[Any, IndexRecord], ...]:
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            obligation_heads,
        )

        try:
            return obligation_heads(index, mission_id=mission_id)
        except ReplayProjectionError as exc:
            raise RecoveryRequired(str(exc)) from exc

    @classmethod
    def _replay_scheduler_constraints(
        cls,
        index: LocalIndex,
        *,
        mission_id: str,
    ) -> dict[str, Any] | None:
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            scheduler_constraints,
        )

        try:
            return scheduler_constraints(index, mission_id=mission_id)
        except ReplayProjectionError as exc:
            raise RecoveryRequired(str(exc)) from exc

    @staticmethod
    def _with_replay_scheduler_constraints(
        action: Mapping[str, Any],
        constraints: Mapping[str, Any] | None,
    ) -> dict[str, Any]:
        from axiom_rift.operations.replay_projection import (
            with_scheduler_constraints,
        )

        return with_scheduler_constraints(action, constraints)

    @staticmethod
    def _effective_axis_resolution(
        index: LocalIndex,
        axis: Mapping[str, Any],
        *,
        prospective_source_ids: Sequence[str] = (),
    ) -> Any:
        from axiom_rift.operations.effective_axis_projection import (
            EffectiveAxisProjectionError,
            effective_axis_resolution,
        )

        try:
            return effective_axis_resolution(
                index,
                axis,
                prospective_source_ids=prospective_source_ids,
            )
        except EffectiveAxisProjectionError as exc:
            raise RecoveryRequired(str(exc)) from exc

    @staticmethod
    def _source_authority_subject_ids(
        executable: Mapping[str, Any],
        *,
        error_type: type[Exception],
    ) -> tuple[str, ...]:
        """Derive source-authority subjects without widening performance use."""

        from axiom_rift.operations.effective_axis_projection import (
            EffectiveAxisProjectionError,
            source_authority_subject_ids,
        )

        try:
            return source_authority_subject_ids(executable)
        except EffectiveAxisProjectionError as exc:
            raise error_type(str(exc)) from exc

    @staticmethod
    def _effective_axis_resolutions(
        index: LocalIndex | LocalIndexView,
        axes: Sequence[Mapping[str, Any]],
        *,
        prospective_source_ids_by_axis: Mapping[
            str, Sequence[str]
        ] | None = None,
    ) -> tuple[Any, ...]:
        from axiom_rift.operations.effective_axis_projection import (
            EffectiveAxisProjectionError,
            effective_axis_resolutions,
        )

        try:
            return effective_axis_resolutions(
                index,
                axes,
                prospective_source_ids_by_axis=(
                    prospective_source_ids_by_axis
                ),
            )
        except EffectiveAxisProjectionError as exc:
            raise RecoveryRequired(str(exc)) from exc

    @staticmethod
    def _mission_effective_axis_blockers(
        index: LocalIndex,
        *,
        mission_id: str,
    ) -> tuple[Any, ...]:
        from axiom_rift.operations.effective_axis_projection import (
            EffectiveAxisProjectionError,
            mission_effective_axis_blockers,
        )

        try:
            return mission_effective_axis_blockers(
                index,
                mission_id=mission_id,
            )
        except EffectiveAxisProjectionError as exc:
            raise RecoveryRequired(str(exc)) from exc

    @staticmethod
    def _axis_architecture_anchor(
        index: LocalIndex | LocalIndexView,
        axis: Mapping[str, Any],
    ) -> dict[str, Any] | None:
        typed_identity = axis.get("architecture_chassis_identity")
        typed_payload = axis.get("architecture_chassis")
        if isinstance(typed_identity, str):
            if not isinstance(typed_payload, dict):
                raise RecoveryRequired("typed Portfolio axis chassis is malformed")
            return {
                "architecture_chassis": dict(typed_payload),
                "architecture_chassis_identity": typed_identity,
                "baseline_executable": None,
                "baseline_executable_id": None,
            }
        axis_identity = axis.get("axis_identity")
        if not isinstance(axis_identity, str):
            raise RecoveryRequired("legacy Portfolio axis identity is malformed")
        anchors: dict[tuple[str, str], dict[str, Any]] = {}
        for record in index.records_by_payload_text(
            "portfolio-decision",
            "target_axis_identity",
            axis_identity,
        ):
            if StateWriter._active_portfolio_decision(index, record.record_id) is None:
                continue
            payload = record.payload
            architecture_identity = payload.get("architecture_chassis_identity")
            baseline_id = payload.get("baseline_executable_id")
            if (
                payload.get("target_axis_identity") != axis_identity
                or not isinstance(architecture_identity, str)
                or not isinstance(baseline_id, str)
            ):
                continue
            anchor = {
                "architecture_chassis": payload.get("architecture_chassis"),
                "architecture_chassis_identity": architecture_identity,
                "baseline_executable": payload.get("baseline_executable"),
                "baseline_executable_id": baseline_id,
            }
            anchors[(architecture_identity, baseline_id)] = anchor
        if len(anchors) > 1:
            raise RecoveryRequired(
                "legacy Portfolio axis has conflicting prospective chassis anchors"
            )
        return None if not anchors else next(iter(anchors.values()))

    @staticmethod
    def _axis_architecture_authority_identity(
        index: LocalIndex | LocalIndexView,
        axis: Mapping[str, Any],
    ) -> str:
        """Return the exact typed or legacy-anchored chassis authority."""

        anchor = StateWriter._axis_architecture_anchor(index, axis)
        identity = (
            None
            if anchor is None
            else anchor.get("architecture_chassis_identity")
        )
        if isinstance(identity, str):
            return identity
        legacy = axis.get("system_architecture_family")
        if not isinstance(legacy, str):
            raise RecoveryRequired(
                "Portfolio axis architecture authority is unavailable"
            )
        return legacy

    def _require_registered_chassis_baseline(
        self,
        *,
        index: LocalIndex,
        controlled_chassis: Any,
        decision: IndexRecord,
    ) -> None:
        baseline = controlled_chassis.baseline_executable
        baseline_payload = baseline.to_identity_payload()
        provenance = decision.payload.get("baseline_provenance")
        if (
            decision.payload.get("baseline_executable_id") != baseline.identity
            or decision.payload.get("baseline_executable") != baseline_payload
            or not isinstance(provenance, dict)
        ):
            raise TransitionError(
                "controlled chassis baseline differs from its accepted Decision"
            )
        target_axis_identity = decision.payload.get("target_axis_identity")
        if not isinstance(target_axis_identity, str):
            raise TransitionError(
                "controlled chassis baseline lacks its target axis identity"
            )
        replacement_equivalence = decision.payload.get(
            "replacement_architecture_equivalence"
        )
        replacement_provenance = (
            provenance.get("kind") == "accepted_replay_replacement"
        )
        prior = (
            None
            if replacement_provenance
            else self._prior_scientific_baseline(
                index,
                baseline,
                portfolio_axis_identity=target_axis_identity,
            )
        )
        if replacement_provenance:
            preflight_id = (
                replacement_equivalence.get(
                    "accepted_replacement_preflight_id"
                )
                if isinstance(replacement_equivalence, Mapping)
                else None
            )
            replacement_ids = (
                replacement_equivalence.get("replacement_executable_ids")
                if isinstance(replacement_equivalence, Mapping)
                else None
            )
            if (
                provenance
                != {
                    "kind": "accepted_replay_replacement",
                    "record_id": preflight_id,
                }
                or not isinstance(replacement_ids, list)
                or not replacement_ids
                or any(
                    not isinstance(executable_id, str)
                    or not executable_id.startswith("executable:")
                    for executable_id in replacement_ids
                )
                or len(replacement_ids) != len(set(replacement_ids))
                or replacement_equivalence.get(
                    "replacement_baseline_executable_id"
                )
                != baseline.identity
                or replacement_equivalence.get("target_axis_identity")
                != target_axis_identity
                or index.get("trial", baseline.identity) is not None
            ):
                raise TransitionError(
                    "controlled chassis replacement baseline authority is invalid"
                )
        elif provenance.get("kind") == "trial":
            if prior is None or provenance.get("record_id") != prior.record_id:
                raise TransitionError(
                    "controlled chassis baseline lost its prior scientific trial"
                )
        elif provenance.get("kind") == "controlled_chassis_anchor_reuse":
            anchor_id = provenance.get("record_id")
            anchor = (
                None
                if not isinstance(anchor_id, str)
                else self._active_portfolio_decision(index, anchor_id)
            )
            if (
                prior is not None
                or anchor is None
                or anchor.payload.get("baseline_executable_id") != baseline.identity
                or anchor.payload.get("baseline_executable") != baseline_payload
                or not isinstance(anchor.payload.get("baseline_provenance"), dict)
                or anchor.payload["baseline_provenance"].get("kind")
                not in {
                    "first_controlled_chassis_bootstrap",
                    "first_axis_controlled_chassis_bootstrap",
                }
            ):
                raise TransitionError(
                    "controlled chassis bootstrap anchor reuse is invalid"
                )
        else:
            relevant_trials = list(
                index.records_by_payload_text(
                    "trial",
                    "trial_data_contract",
                    baseline.data_contract,
                )
            )
            axis_controlled_history = [
                record
                for record in index.records_by_payload_text(
                    "study-open",
                    "portfolio_axis_identity",
                    target_axis_identity,
                )
                if isinstance(record.payload.get("controlled_chassis"), dict)
            ]
            has_any_controlled_history = (
                index.has_controlled_chassis_study()
            )
            expected_bootstrap = (
                {
                    "data_contract": baseline.data_contract,
                    "kind": "first_axis_controlled_chassis_bootstrap",
                    "portfolio_axis_identity": target_axis_identity,
                }
                if relevant_trials
                and has_any_controlled_history
                and not axis_controlled_history
                else {
                    "data_contract": baseline.data_contract,
                    "kind": (
                        "first_controlled_chassis_bootstrap"
                        if relevant_trials
                        else "first_data_contract_bootstrap"
                    ),
                }
            )
            if (
                provenance != expected_bootstrap
                or prior is not None
                or (
                    relevant_trials
                    and axis_controlled_history
                    and provenance.get("kind")
                    != "controlled_chassis_anchor_reuse"
                )
            ):
                raise TransitionError(
                    "controlled chassis baseline bootstrap is no longer valid"
                )
        for component, component_id in zip(
            baseline.components, baseline.component_identities, strict=True
        ):
            expected = self._component_manifest_record(
                component_id=component_id,
                manifest=component.to_identity_payload(),
            )
            existing = index.get("component-manifest", component_id)
            if existing is None:
                raise TransitionError(
                    "controlled chassis baseline component is not registered"
                )
            self._require_component_manifest_projection(index, expected)

    @staticmethod
    def _prior_scientific_baseline(
        index: LocalIndex,
        baseline: Any,
        portfolio_axis_identity: str | None = None,
    ) -> IndexRecord | None:
        if portfolio_axis_identity is not None:
            _require_ascii("Portfolio axis identity", portfolio_axis_identity)
        baseline_payload = baseline.to_identity_payload()
        exact = index.get("trial", baseline.identity)
        exact_executable = (
            None if exact is None else exact.payload.get("executable")
        )
        if not (
            isinstance(exact_executable, dict)
            and exact_executable.get("data_contract") == baseline.data_contract
        ):
            relevant = bool(
                index.records_by_payload_text(
                    "trial",
                    "trial_data_contract",
                    baseline.data_contract,
                )
            )
            if not relevant:
                return None
        if exact is None:
            data_contract_history = tuple(
                index.records_by_payload_text(
                    "study-open",
                    "study_open_baseline_data_contract",
                    baseline.data_contract,
                )
            )
            controlled_history = tuple(
                record
                for record in data_contract_history
                if portfolio_axis_identity is None
                or record.payload.get("portfolio_axis_identity")
                == portfolio_axis_identity
            )
            candidate_axis_identities = tuple(
                sorted(
                    {
                        value
                        for value in (
                            record.payload.get("portfolio_axis_identity")
                            for record in controlled_history
                        )
                        if isinstance(value, str)
                    }
                )
            )
            decision_candidates = (
                index.records_by_payload_text(
                    "portfolio-decision",
                    "target_axis_identity",
                    portfolio_axis_identity,
                )
                if portfolio_axis_identity is not None
                else index.records_by_payload_text_values(
                    "portfolio-decision",
                    "target_axis_identity",
                    candidate_axis_identities,
                )
            )
            accepted_bootstrap_anchors = [
                record
                for record in decision_candidates
                if StateWriter._active_portfolio_decision(index, record.record_id)
                is not None
                and record.payload.get("baseline_executable_id") == baseline.identity
                and record.payload.get("baseline_executable") == baseline_payload
                and isinstance(record.payload.get("baseline_provenance"), dict)
                and record.payload["baseline_provenance"].get("kind")
                in {
                    "first_controlled_chassis_bootstrap",
                    "first_axis_controlled_chassis_bootstrap",
                }
                and (
                    portfolio_axis_identity is None
                    or record.payload.get("target_axis_identity")
                    == portfolio_axis_identity
                )
            ]
            if not controlled_history or accepted_bootstrap_anchors:
                return None
        study_id = None if exact is None else exact.payload.get("study_id")
        study = (
            None
            if not isinstance(study_id, str)
            else index.get("study-open", study_id)
        )
        if (
            exact is None
            or exact.status != "evaluated"
            or exact.fingerprint != baseline.identity.removeprefix("executable:")
            or exact.payload.get("scientific_eligible") is not True
            or exact.payload.get("engineering_fixture") is not False
            or exact.payload.get("executable") != baseline_payload
            or study is None
            or exact.payload.get("mission_id") != study.payload.get("mission_id")
        ):
            raise TransitionError(
                "Portfolio Decision baseline must reuse a prior scientific Executable"
            )
        return exact

    def _require_component_parity_payload(
        self,
        *,
        index: LocalIndex,
        equivalence: Mapping[str, Any],
        mission_id: str,
        portfolio_decision_id: str | None,
    ) -> None:
        completion_id = equivalence.get("completion_record_id")
        parity_manifest_hash = equivalence.get("parity_manifest_hash")
        try:
            _require_digest("component parity completion", completion_id)
            _require_digest("component parity manifest", parity_manifest_hash)
        except (TypeError, ValueError) as exc:
            raise TransitionError("component parity authority is malformed") from exc
        completion = index.get("job-completed", completion_id)
        if completion is None or completion.status != "success":
            raise TransitionError(
                "component parity requires a successful registered-validator Job completion"
            )
        job_id = completion.payload.get("job_id")
        declaration = (
            None
            if not isinstance(job_id, str)
            else index.get("job-declared", job_id)
        )
        binding = (
            None
            if declaration is None
            else declaration.payload.get("spec", {}).get("component_parity_binding")
        )
        parity = completion.payload.get("component_parity")
        expected = {
            "canonical_component_id": equivalence.get("canonical_component_id"),
            "canonical_component_manifest": equivalence.get(
                "canonical_component_manifest"
            ),
            "dimensions": equivalence.get("dimensions"),
            "equivalent_component_id": equivalence.get("equivalent_component_id"),
            "equivalent_component_manifest": equivalence.get(
                "equivalent_component_manifest"
            ),
        }
        if (
            declaration is None
            or declaration.fingerprint != completion.fingerprint
            or declaration.payload.get("mission_id") != mission_id
            or not isinstance(binding, dict)
            or (
                portfolio_decision_id is not None
                and binding.get("portfolio_decision_id") != portfolio_decision_id
            )
            or any(binding.get(name) != value for name, value in expected.items())
            or not isinstance(parity, dict)
            or parity.get("equivalent") is not True
            or parity.get("result_manifest_hash") != parity_manifest_hash
            or any(parity.get(name) != value for name, value in expected.items())
        ):
            raise TransitionError(
                "component parity completion differs from its typed endpoints"
            )
        trace = parity.get("validation_trace")
        measurement_hashes = parity.get("measurement_artifact_hashes")
        if (
            not isinstance(trace, dict)
            or trace.get("validator_id") != binding.get("validator_id")
            or type(trace.get("declared_artifact_count")) is not int
            or trace.get("declared_artifact_count", 0) <= 0
            or trace.get("declared_artifact_count")
            != trace.get("opened_artifact_count")
            or not isinstance(measurement_hashes, list)
            or not measurement_hashes
        ):
            raise TransitionError(
                "component parity lacks a complete registered-validator trace"
            )
        decisions = index.records_by_subject_status(
            subject=f"Job:{job_id}", status="accept_component_parity"
        )
        if not any(
            record.payload.get("completion_record_id") == completion_id
            for record in decisions
        ):
            raise TransitionError("component parity Job has not been accepted by Writer")
        for artifact_hash in [parity_manifest_hash, *measurement_hashes]:
            try:
                self.evidence.verify(artifact_hash)
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise TransitionError(
                    "component parity evidence bytes are unavailable"
                ) from exc

    def _require_component_parity_evidence(
        self,
        *,
        index: LocalIndex,
        controlled_chassis: Any,
        mission_id: str,
        portfolio_decision_id: str,
    ) -> None:
        """Verify every equivalence through Writer-accepted validator completions."""

        from axiom_rift.research.chassis import ControlledStudyChassis

        if not isinstance(controlled_chassis, ControlledStudyChassis):
            raise TransitionError("controlled component chassis is not typed")
        for equivalence in controlled_chassis.equivalences:
            self._require_component_parity_payload(
                index=index,
                equivalence=equivalence.to_identity_payload(),
                mission_id=mission_id,
                portfolio_decision_id=portfolio_decision_id,
            )

    @staticmethod
    def _component_parity_member_records(
        *,
        equivalence: Mapping[str, Any],
        mission_id: str,
        portfolio_decision_id: str,
    ) -> list[IndexRecord]:
        from axiom_rift.research.chassis import (
            ChassisIdentityError,
            architecture_component_semantic_surface_identity,
            component_semantic_surface_identity,
        )

        canonical_id = equivalence.get("canonical_component_id")
        equivalent_id = equivalence.get("equivalent_component_id")
        if not isinstance(canonical_id, str) or not isinstance(equivalent_id, str):
            raise TransitionError("component parity endpoints are malformed")
        edge_id = canonical_digest(
            domain="component-parity-edge",
            payload={
                "component_ids": sorted((canonical_id, equivalent_id)),
                "schema": "component_parity_edge.v1",
            },
        )
        records: list[IndexRecord] = []
        for endpoint, peer, prefix in (
            (canonical_id, equivalent_id, "canonical"),
            (equivalent_id, canonical_id, "equivalent"),
        ):
            manifest = equivalence.get(f"{prefix}_component_manifest")
            if not isinstance(manifest, Mapping):
                raise TransitionError("component parity endpoint manifest is malformed")
            try:
                surface = architecture_component_semantic_surface_identity(manifest)
            except ChassisIdentityError as exc:
                if "outside the prediction-to-position" not in str(exc):
                    raise TransitionError(str(exc)) from exc
                surface = component_semantic_surface_identity(manifest)
            record_id = canonical_digest(
                domain="component-parity-member",
                payload={
                    "completion_record_id": equivalence.get(
                        "completion_record_id"
                    ),
                    "edge_id": edge_id,
                    "endpoint_id": endpoint,
                    "schema": "component_parity_member.v1",
                },
            )
            records.append(
                _record(
                    kind="component-parity-member",
                    record_id=record_id,
                    subject=f"Component:{endpoint}",
                    status="equivalent",
                    fingerprint=surface,
                    payload={
                        "edge_id": edge_id,
                        "endpoint_id": endpoint,
                        "equivalence": dict(equivalence),
                        "mission_id": mission_id,
                        "peer_component_id": peer,
                        "portfolio_decision_id": portfolio_decision_id,
                        "schema": "component_parity_member_projection.v1",
                    },
                )
            )
        return records

    def _verified_component_parity_edges(
        self,
        index: LocalIndex,
        *,
        surface_seeds: tuple[str, ...] = (),
        component_seeds: tuple[str, ...] = (),
    ) -> tuple[dict[str, Any], ...]:
        """Re-verify every durable Writer-accepted parity edge from exact bytes."""

        if not surface_seeds and not component_seeds:
            return ()
        edges: dict[tuple[str, str], dict[str, Any]] = {}
        members_by_id: dict[str, IndexRecord] = {}
        pending_surfaces = list(dict.fromkeys(surface_seeds))
        pending_components = list(dict.fromkeys(component_seeds))
        seen_surfaces: set[str] = set()
        seen_components: set[str] = set()
        while pending_surfaces or pending_components:
            if pending_surfaces:
                surface = pending_surfaces.pop()
                if surface in seen_surfaces:
                    continue
                seen_surfaces.add(surface)
                candidates = index.records_by_fingerprint(surface)
            else:
                component_id = pending_components.pop()
                if component_id in seen_components:
                    continue
                seen_components.add(component_id)
                candidates = index.records_by_subject_status(
                    subject=f"Component:{component_id}",
                    status="equivalent",
                )
            for candidate in candidates:
                if candidate.kind != "component-parity-member":
                    continue
                members_by_id[candidate.record_id] = candidate
                equivalence = candidate.payload.get("equivalence")
                if not isinstance(equivalence, dict):
                    raise RecoveryRequired(
                        "accepted component parity member is malformed"
                    )
                for name in (
                    "canonical_component_id",
                    "equivalent_component_id",
                ):
                    value = equivalence.get(name)
                    if isinstance(value, str) and value not in seen_components:
                        pending_components.append(value)
        members = tuple(members_by_id.values())
        for member in members:
            equivalence = member.payload.get("equivalence")
            mission_id = member.payload.get("mission_id")
            portfolio_decision_id = member.payload.get("portfolio_decision_id")
            if (
                member.status != "equivalent"
                or member.payload.get("schema")
                != "component_parity_member_projection.v1"
                or not isinstance(equivalence, dict)
                or not isinstance(mission_id, str)
                or not isinstance(portfolio_decision_id, str)
            ):
                raise RecoveryRequired("accepted component parity member is malformed")
            self._require_component_parity_payload(
                index=index,
                equivalence=equivalence,
                mission_id=mission_id,
                portfolio_decision_id=portfolio_decision_id,
            )
            endpoints = (
                equivalence["canonical_component_id"],
                equivalence["equivalent_component_id"],
            )
            if any(not isinstance(value, str) for value in endpoints):
                raise RecoveryRequired("accepted component parity endpoints are malformed")
            key = tuple(sorted(endpoints))
            prior = edges.get(key)
            if prior is not None and (
                prior["canonical_component_manifest"]
                != equivalence["canonical_component_manifest"]
                or prior["equivalent_component_manifest"]
                != equivalence["equivalent_component_manifest"]
            ):
                prior_by_id = {
                    prior["canonical_component_id"]: prior[
                        "canonical_component_manifest"
                    ],
                    prior["equivalent_component_id"]: prior[
                        "equivalent_component_manifest"
                    ],
                }
                current_by_id = {
                    equivalence["canonical_component_id"]: equivalence[
                        "canonical_component_manifest"
                    ],
                    equivalence["equivalent_component_id"]: equivalence[
                        "equivalent_component_manifest"
                    ],
                }
                if prior_by_id != current_by_id:
                    raise RecoveryRequired(
                        "accepted component parity endpoints conflict"
                    )
            edges[key] = equivalence
        return tuple(edges[key] for key in sorted(edges))

    @staticmethod
    def _architecture_parity_surface_replacements(
        equivalences: tuple[Mapping[str, Any], ...],
    ) -> dict[str, str]:
        from axiom_rift.research.chassis import (
            ChassisIdentityError,
            architecture_component_semantic_surface_identity,
        )

        parents: dict[str, str] = {}
        manifests: dict[str, Mapping[str, Any]] = {}

        def find(component_id: str) -> str:
            parent = parents.setdefault(component_id, component_id)
            if parent != component_id:
                parents[component_id] = find(parent)
            return parents[component_id]

        def union(left_id: str, right_id: str) -> None:
            left_root = find(left_id)
            right_root = find(right_id)
            if left_root == right_root:
                return
            low, high = sorted((left_root, right_root))
            parents[high] = low

        for equivalence in equivalences:
            endpoint_values = []
            for prefix in ("canonical", "equivalent"):
                component_id = equivalence.get(f"{prefix}_component_id")
                manifest = equivalence.get(f"{prefix}_component_manifest")
                if not isinstance(component_id, str) or not isinstance(manifest, Mapping):
                    raise RecoveryRequired("accepted parity endpoint is malformed")
                expected_id = "component:" + canonical_digest(
                    domain="component", payload=dict(manifest)
                )
                if component_id != expected_id:
                    raise RecoveryRequired(
                        "accepted parity endpoint differs from its manifest"
                    )
                prior = manifests.get(component_id)
                if prior is not None and dict(prior) != dict(manifest):
                    raise RecoveryRequired("accepted parity manifest collision")
                manifests[component_id] = manifest
                endpoint_values.append(component_id)
            union(endpoint_values[0], endpoint_values[1])

        surface_owners: dict[str, str] = {}
        for component_id, manifest in manifests.items():
            try:
                surface = architecture_component_semantic_surface_identity(
                    manifest
                )
            except ChassisIdentityError as exc:
                if "outside the prediction-to-position" in str(exc):
                    continue
                raise RecoveryRequired(str(exc)) from exc
            owner = surface_owners.get(surface)
            if owner is None:
                surface_owners[surface] = component_id
            else:
                union(owner, component_id)

        classes: dict[str, list[str]] = {}
        for component_id in parents:
            classes.setdefault(find(component_id), []).append(component_id)
        replacements: dict[str, str] = {}
        for members in classes.values():
            normalized_members = sorted(members)
            class_surface = "architecture-equivalence-class:" + canonical_digest(
                domain="architecture-equivalence-class",
                payload={
                    "component_ids": normalized_members,
                    "schema": "architecture_equivalence_class.v1",
                },
            )
            for component_id in normalized_members:
                try:
                    surface = architecture_component_semantic_surface_identity(
                        manifests[component_id]
                    )
                except ChassisIdentityError as exc:
                    if "outside the prediction-to-position" in str(exc):
                        continue
                    raise RecoveryRequired(str(exc)) from exc
                prior = replacements.get(surface)
                if prior is not None and prior != class_surface:
                    raise RecoveryRequired(
                        "accepted parity architecture classes conflict"
                    )
                replacements[surface] = class_surface
        return replacements

    def _resolved_architecture_family(
        self,
        *,
        index: LocalIndex,
        architecture_payload: Mapping[str, Any],
        extra_equivalences: tuple[Mapping[str, Any], ...] = (),
    ) -> str:
        from axiom_rift.research.chassis import (
            ChassisIdentityError,
            architecture_family_identity,
        )

        roles = architecture_payload.get("roles")
        if not isinstance(roles, Mapping):
            raise TransitionError("architecture chassis roles are malformed")
        surface_seeds = tuple(
            sorted(
                {
                    surface
                    for role in roles.values()
                    if isinstance(role, Mapping)
                    for surface in role.get("component_semantic_surfaces", [])
                    if isinstance(surface, str)
                }
            )
        )
        cache = getattr(index, "_axiom_verified_parity_cache", None)
        if cache is None:
            cache = {}
            try:
                setattr(index, "_axiom_verified_parity_cache", cache)
            except AttributeError:
                # Authenticated read-only views are slot-backed.  They remain
                # valid callers; only the optional per-transaction cache is
                # unavailable on that boundary.
                pass
        verified = cache.get(surface_seeds)
        if verified is None:
            verified = self._verified_component_parity_edges(
                index,
                surface_seeds=surface_seeds,
            )
            cache[surface_seeds] = verified
        equivalences = (
            *verified,
            *extra_equivalences,
        )
        replacements = self._architecture_parity_surface_replacements(
            tuple(equivalences)
        )
        try:
            return architecture_family_identity(
                architecture_payload,
                surface_replacements=replacements,
            )
        except ChassisIdentityError as exc:
            raise TransitionError(str(exc)) from exc

    def _study_resolved_architecture_family(
        self,
        *,
        index: LocalIndex,
        study: IndexRecord,
        extra_equivalences: tuple[Mapping[str, Any], ...] = (),
    ) -> str:
        controlled = study.payload.get("controlled_chassis")
        architecture = (
            None if not isinstance(controlled, dict) else controlled.get("architecture")
        )
        if isinstance(architecture, dict):
            return self._resolved_architecture_family(
                index=index,
                architecture_payload=architecture,
                extra_equivalences=extra_equivalences,
            )
        legacy = study.payload.get("system_architecture_family")
        if not isinstance(legacy, str):
            raise TransitionError("Study lacks a system architecture family")
        return legacy

    def _review_resolved_architecture_family(
        self,
        *,
        index: LocalIndex,
        review: IndexRecord,
        extra_equivalences: tuple[Mapping[str, Any], ...] = (),
    ) -> str:
        families: set[str] = set()
        for diagnosis_id in review.payload.get("covered_diagnosis_ids", []):
            if not isinstance(diagnosis_id, str):
                raise RecoveryRequired("architecture review diagnosis binding is malformed")
            diagnosis = index.get("study-diagnosis", diagnosis_id)
            study_id = None if diagnosis is None else diagnosis.payload.get("study_id")
            study = (
                None
                if not isinstance(study_id, str)
                else index.get("study-open", study_id)
            )
            if study is None:
                raise RecoveryRequired(
                    "architecture review lost a covered Study diagnosis"
                )
            controlled = study.payload.get("controlled_chassis")
            architecture = (
                None
                if not isinstance(controlled, dict)
                else controlled.get("architecture")
            )
            if isinstance(architecture, dict):
                families.add(
                    self._resolved_architecture_family(
                        index=index,
                        architecture_payload=architecture,
                        extra_equivalences=extra_equivalences,
                    )
                )
            else:
                legacy = study.payload.get("system_architecture_family")
                if not isinstance(legacy, str):
                    raise RecoveryRequired(
                        "architecture review Study family is unavailable"
                    )
                families.add(legacy)
        if len(families) > 1:
            raise RecoveryRequired(
                "architecture review covered Studies no longer share one family"
            )
        if families:
            return next(iter(families))
        stored = review.payload.get("system_architecture_family")
        if not isinstance(stored, str):
            raise RecoveryRequired("architecture review family is unavailable")
        return stored

    def _axis_resolved_architecture_family(
        self,
        *,
        index: LocalIndex,
        axis: Mapping[str, Any],
        extra_equivalences: tuple[Mapping[str, Any], ...] = (),
    ) -> str:
        """Resolve one current or newly proposed axis without history-wide lookup."""

        architecture = axis.get("architecture_chassis")
        if isinstance(architecture, Mapping):
            return self._resolved_architecture_family(
                index=index,
                architecture_payload=architecture,
                extra_equivalences=extra_equivalences,
            )
        anchor = self._axis_architecture_anchor(index, axis)
        if anchor is not None:
            anchored_architecture = anchor.get("architecture_chassis")
            if isinstance(anchored_architecture, Mapping):
                return self._resolved_architecture_family(
                    index=index,
                    architecture_payload=anchored_architecture,
                    extra_equivalences=extra_equivalences,
                )
            anchored_identity = anchor.get("architecture_chassis_identity")
            if isinstance(anchored_identity, str):
                return anchored_identity
        legacy = axis.get("system_architecture_family")
        if not isinstance(legacy, str):
            raise TransitionError("Portfolio axis architecture family is unavailable")
        return legacy

    def _pending_architecture_review_trigger(
        self,
        *,
        index: LocalIndex,
        mission_id: str,
        portfolio_snapshot_id: str,
        architecture_family: str,
        extra_equivalences: tuple[Mapping[str, Any], ...] = (),
    ) -> IndexRecord | None:
        snapshot = index.get("portfolio-snapshot", portfolio_snapshot_id)
        standard = (
            None if snapshot is None else snapshot.payload.get("exhaustion_standard")
        )
        if not isinstance(standard, dict):
            return None
        minimum_studies = standard.get("architecture_review_minimum_studies")
        minimum_axes = standard.get("architecture_review_minimum_axes")
        if type(minimum_studies) is not int or type(minimum_axes) is not int:
            raise RecoveryRequired("architecture review threshold is malformed")
        reviewed_ids: set[str] = set()
        for review in index.records_by_payload_text(
            "architecture-review",
            "mission_id",
            mission_id,
        ):
            reviewed_ids.update(
                value
                for value in review.payload.get("covered_diagnosis_ids", [])
                if isinstance(value, str)
            )
        diagnoses: list[IndexRecord] = []
        for diagnosis in index.records_by_payload_text(
            "study-diagnosis",
            "mission_id",
            mission_id,
        ):
            if (
                diagnosis.record_id in reviewed_ids
                or diagnosis.payload.get("evidence_state")
                in {"engineering_gap", "supported_requires_confirmation"}
            ):
                continue
            study_id = diagnosis.payload.get("study_id")
            study = (
                None
                if not isinstance(study_id, str)
                else index.get("study-open", study_id)
            )
            if study is None:
                raise RecoveryRequired(
                    "architecture review diagnosis lost its Study"
                )
            if (
                self._study_resolved_architecture_family(
                    index=index,
                    study=study,
                    extra_equivalences=extra_equivalences,
                )
                == architecture_family
            ):
                diagnoses.append(diagnosis)
        axis_ids = {
            diagnosis.payload.get("portfolio_axis_id") for diagnosis in diagnoses
        }
        if (
            len(diagnoses) < minimum_studies
            or len(axis_ids) < minimum_axes
            or None in axis_ids
        ):
            return None
        trigger_payload = {
            "diagnosis_ids": sorted(
                diagnosis.record_id for diagnosis in diagnoses
            ),
            "mission_id": mission_id,
            "portfolio_axis_ids": sorted(axis_ids),
            "portfolio_snapshot_id": portfolio_snapshot_id,
            "primary_research_layers": sorted(
                {
                    diagnosis.payload["primary_research_layer"]
                    for diagnosis in diagnoses
                }
            ),
            "schema": "architecture_review_trigger.v1",
            "system_architecture_family": architecture_family,
            "threshold": {
                "minimum_distinct_axes": minimum_axes,
                "minimum_studies": minimum_studies,
            },
        }
        trigger_id = canonical_digest(
            domain="architecture-review-trigger",
            payload=trigger_payload,
        )
        return _record(
            kind="architecture-review-trigger",
            record_id=trigger_id,
            subject=f"Mission:{mission_id}",
            status="required",
            fingerprint=trigger_id,
            payload=trigger_payload,
        )

    @staticmethod
    def study_input_hash(
        *,
        question: Mapping[str, Any],
        material_identity: str,
        semantic_proposal: Mapping[str, Any],
        semantic_question_equivalence: Any | None = None,
        semantic_question_lineage: Any | None = None,
        controlled_chassis: Any | None = None,
        portfolio_axis_id: str | None = None,
        portfolio_axis_identity: str | None = None,
        portfolio_decision_id: str | None = None,
    ) -> str:
        question_manifest = _require_manifest(
            "question",
            question,
            required={
                "causal_question",
                "changed_variables",
                "controlled_variables",
                "done_conditions",
                "evidence_modes",
            },
        )
        question_manifest["evidence_modes"] = list(
            _require_study_evidence_modes(question_manifest)
        )
        question_hash = _digest(question_manifest, domain="study-question")
        _require_ascii("material_identity", material_identity)
        from axiom_rift.research.chassis import ControlledStudyChassis

        if controlled_chassis is not None and not isinstance(
            controlled_chassis, ControlledStudyChassis
        ):
            raise TransitionError("controlled_chassis must be a ControlledStudyChassis")
        from axiom_rift.research.semantic_question import (
            SemanticQuestionEquivalenceProposal,
            SemanticQuestionLineageProposal,
        )

        if semantic_question_equivalence is not None and not isinstance(
            semantic_question_equivalence,
            SemanticQuestionEquivalenceProposal,
        ):
            raise TransitionError(
                "semantic_question_equivalence must be a typed proposal"
            )
        if semantic_question_lineage is not None and not isinstance(
            semantic_question_lineage,
            SemanticQuestionLineageProposal,
        ):
            raise TransitionError(
                "semantic_question_lineage must be a typed proposal"
            )
        if (
            semantic_question_equivalence is not None
            and semantic_question_lineage is None
        ):
            raise TransitionError(
                "semantic question equivalence requires exact Study lineage"
            )
        expected_equivalence_id = (
            None
            if semantic_question_equivalence is None
            else semantic_question_equivalence.identity
        )
        if (
            semantic_question_lineage is not None
            and semantic_question_lineage.equivalence_proposal_id
            != expected_equivalence_id
        ):
            raise TransitionError(
                "semantic question lineage and equivalence proposals diverge"
            )
        input_payload: dict[str, Any] = {
                "controlled_chassis": (
                    None
                    if controlled_chassis is None
                    else controlled_chassis.to_identity_payload()
                ),
                "question_hash": question_hash,
                "material_identity": material_identity,
                "portfolio_axis_id": portfolio_axis_id,
                "portfolio_axis_identity": portfolio_axis_identity,
                "portfolio_decision_id": portfolio_decision_id,
                "semantic_proposal": dict(semantic_proposal),
        }
        if semantic_question_equivalence is not None:
            input_payload["semantic_question_equivalence"] = (
                semantic_question_equivalence.to_identity_payload()
            )
        if semantic_question_lineage is not None:
            input_payload["semantic_question_lineage"] = (
                semantic_question_lineage.to_identity_payload()
            )
        return _digest(
            input_payload,
            domain="study-input",
        )

    @staticmethod
    def _current_accepted_replay_replacement_preflight(
        index: LocalIndex,
        *,
        mission_id: str,
        obligation_ids: tuple[str, ...],
    ) -> IndexRecord | None:
        """Resolve one exact replacement trigger at a pending Study boundary."""

        if not obligation_ids:
            return None
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            obligation_heads,
            require_current_replacement_preflight_basis,
        )

        heads = {
            obligation.identity: head
            for obligation, head in obligation_heads(
                index,
                mission_id=mission_id,
            )
        }
        triggers: list[IndexRecord] = []
        for obligation_id in obligation_ids:
            head = heads.get(obligation_id)
            if head is None:
                raise TransitionError(
                    "replay implementation admission lacks its obligation"
                )
            resume = head
            if (
                head.kind != "historical-replay-obligation-resume"
                and head.status == "in_progress"
                and isinstance(head.event_stream, str)
                and type(head.event_sequence) is int
                and head.event_sequence >= 2
            ):
                resume = index.event_record(
                    head.event_stream,
                    head.event_sequence - 1,
                )
            evidence = (
                resume.payload.get("resume_evidence")
                if resume.kind == "historical-replay-obligation-resume"
                else None
            )
            trigger_id = (
                evidence.get("trigger_record_id")
                if isinstance(evidence, Mapping)
                else None
            )
            if not isinstance(trigger_id, str) or not trigger_id.startswith(
                "job-implementation-preflight:"
            ):
                continue
            trigger = index.get("job-implementation-preflight", trigger_id)
            stream_head = (
                None
                if trigger is None
                or not isinstance(trigger.event_stream, str)
                else index.event_head(trigger.event_stream)
            )
            replacement_for = (
                None
                if trigger is None
                else trigger.payload.get("replacement_for_preflight_id")
            )
            trigger_fingerprint = (
                None
                if trigger is None
                else _digest(
                    trigger.payload,
                    domain="replay-job-implementation-preflight",
                )
            )
            if (
                trigger is None
                or trigger.fingerprint != trigger_fingerprint
                or trigger.record_id
                != "job-implementation-preflight:" + trigger_fingerprint
                or trigger.status != "accepted"
                or trigger.payload.get("schema")
                != "replay_job_implementation_preflight.v1"
                or trigger.payload.get("outcome") != "accepted"
                or trigger.payload.get("mission_id") != mission_id
                or trigger.payload.get("replay_obligation_ids")
                != list(obligation_ids)
                or trigger.payload.get("batch_id") is not None
                or trigger.payload.get("study_id") is not None
                or not isinstance(replacement_for, str)
                or trigger.event_stream
                != (
                    "replay-job-implementation-preflight-replacement:"
                    + replacement_for
                )
                or stream_head is None
                or stream_head.record_id != trigger.record_id
                or not isinstance(
                    trigger.payload.get("source_closure_authority"),
                    Mapping,
                )
                or trigger.payload.get("failure_fingerprint") is not None
                or trigger.payload.get("reason_code") is not None
                or trigger.payload.get("remediation_kind") is not None
            ):
                raise RecoveryRequired(
                    "replay replacement implementation trigger is malformed"
                )
            triggers.append(trigger)
        if not triggers:
            return None
        if (
            len(triggers) != len(obligation_ids)
            or len({trigger.record_id for trigger in triggers}) != 1
        ):
            raise TransitionError(
                "replay obligations mix replacement implementation authority"
            )
        return triggers[0]

    @staticmethod
    def _study_replay_implementation_admission(
        index: LocalIndex,
        *,
        study_id: str,
        authority_manifest_digest: str,
        _include_repair_successors: bool = True,
    ) -> IndexRecord | None:
        study = index.get("study-open", study_id)
        initial_admission_id = (
            None
            if study is None
            else study.payload.get("replay_implementation_admission_id")
        )
        recertification_stream = (
            f"replay-implementation-admission-study:{study_id}"
        )
        recertification_head = index.event_head(recertification_stream)
        if initial_admission_id is not None and recertification_head is not None:
            raise RecoveryRequired(
                "Study mixes initial and recertified replay admissions"
            )
        base_admission_id = (
            recertification_head.record_id
            if initial_admission_id is None
            and recertification_head is not None
            else initial_admission_id
        )
        if base_admission_id is None:
            return None
        base_admission = (
            index.get("replay-implementation-admission", base_admission_id)
            if isinstance(base_admission_id, str)
            else None
        )
        if base_admission is None:
            raise RecoveryRequired(
                "Study replay implementation admission is unavailable"
            )
        from axiom_rift.operations.replay_implementation_repair_admission import (
            ReplayImplementationRepairAdmissionIntegrityError,
            current_replay_implementation_repair_admission,
            repair_admission_stream,
        )

        repair_recertification_stream = repair_admission_stream(study_id)
        repair_recertification_head = index.event_head(
            repair_recertification_stream
        )
        admission = base_admission
        if (
            _include_repair_successors
            and repair_recertification_head is not None
        ):
            validated_base = StateWriter._study_replay_implementation_admission(
                index,
                study_id=study_id,
                authority_manifest_digest=authority_manifest_digest,
                _include_repair_successors=False,
            )
            if validated_base is None:
                raise RecoveryRequired(
                    "post-Repair admission lacks an authenticated predecessor"
                )
            try:
                admission = current_replay_implementation_repair_admission(
                    index,
                    study_id=study_id,
                    base_admission=validated_base,
                )
            except ReplayImplementationRepairAdmissionIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
        from axiom_rift.operations.research_protocol_projection import (
            ResearchProtocolProjectionError,
            require_current_research_protocol_activation,
        )

        try:
            protocol_activation = require_current_research_protocol_activation(
                index,
                authority_manifest_digest=authority_manifest_digest,
            )
        except ResearchProtocolProjectionError as exc:
            raise RecoveryRequired(str(exc)) from exc
        payload = admission.payload
        recertification_preflight_id = payload.get(
            "recertification_preflight_id"
        )
        recertification_preflight = (
            None
            if not isinstance(recertification_preflight_id, str)
            else index.get(
                "job-implementation-preflight",
                recertification_preflight_id,
            )
        )
        accepted_id = payload.get("accepted_replacement_preflight_id")
        accepted = (
            index.get("job-implementation-preflight", accepted_id)
            if isinstance(accepted_id, str)
            else None
        )
        accepted_head = (
            None
            if accepted is None
            or not isinstance(accepted.event_stream, str)
            else index.event_head(accepted.event_stream)
        )
        fingerprint = _digest(
            payload,
            domain="replay-implementation-admission",
        )
        request = payload.get("request")
        surface = payload.get("scientific_surface")
        source_authority = payload.get("source_closure_authority")
        from axiom_rift.operations.replay_job_implementation_preflight import (
            PREFLIGHT_SCHEMA,
            ReplayJobImplementationPreflightError,
            replay_job_scientific_surface_hash,
            require_active_replay_job_replacement_binding,
        )
        from axiom_rift.research.implementation_closure import (
            JOB_IMPLEMENTATION_SOURCE_AUTHORITY_SCHEMA,
        )

        request_keys = {
            "callable_identity",
            "executable_manifests",
            "implementation_identity",
            "mission_id",
            "protocol_id",
            "replacement_for_preflight_id",
            "replay_obligation_ids",
            "schema",
            "scientific_bindings",
        }
        source_keys = {
            "callable_module_path",
            "dependency_count",
            "path_inventory_hash",
            "schema",
            "source_closure_hash",
        }
        manifests = (
            request.get("executable_manifests")
            if isinstance(request, Mapping)
            else None
        )
        bindings = (
            request.get("scientific_bindings")
            if isinstance(request, Mapping)
            else None
        )
        try:
            surface_hash = (
                replay_job_scientific_surface_hash(surface)
                if isinstance(surface, Mapping)
                else None
            )
            executable_ids = (
                []
                if not isinstance(manifests, list)
                else [
                    "executable:"
                    + canonical_digest(
                        domain="executable",
                        payload=manifest,
                    )
                    for manifest in manifests
                ]
            )
            if (
                accepted is not None
                and payload.get("schema")
                != "replay_implementation_admission.v3"
            ):
                require_active_replay_job_replacement_binding(
                    accepted_payload=accepted.payload,
                    active_payload={
                        "callable_identity": request.get(
                            "callable_identity"
                        ),
                        "executable_ids": executable_ids,
                        "executable_manifests": manifests,
                        "implementation_identity": request.get(
                            "implementation_identity"
                        ),
                        "mission_id": request.get("mission_id"),
                        "protocol_id": request.get("protocol_id"),
                        "replacement_for_preflight_id": None,
                        "replay_obligation_ids": request.get(
                            "replay_obligation_ids"
                        ),
                        "schema": PREFLIGHT_SCHEMA,
                        "scientific_surface": surface,
                        "scientific_surface_hash": surface_hash,
                    },
                )
        except (
            AttributeError,
            ReplayJobImplementationPreflightError,
            TypeError,
            ValueError,
        ):
            surface_hash = None
            executable_ids = []
        accepted_invalid = accepted_id is not None and (
            not isinstance(accepted_id, str)
            or accepted is None
            or accepted.status != "accepted"
            or accepted.payload.get("outcome") != "accepted"
            or accepted.payload.get("remediation_kind") is not None
            or accepted_head is None
            or accepted_head.record_id != accepted.record_id
        )
        from axiom_rift.operations.replay_implementation_repair_admission import (
            REPAIR_RECERTIFICATION_ADMISSION_SCHEMA,
        )

        admission_schema = payload.get("schema")
        legacy_recertified = (
            admission_schema == "replay_implementation_admission.v2"
        )
        repair_recertified = (
            admission_schema == REPAIR_RECERTIFICATION_ADMISSION_SCHEMA
        )
        recertified = legacy_recertified or repair_recertified
        admission_boundary_invalid = bool(
            study is None
            or type(study.authority_sequence) is not int
            or type(protocol_activation.authority_sequence) is not int
            or type(admission.authority_sequence) is not int
            or (
                legacy_recertified
                and not (
                    study.authority_sequence
                    < protocol_activation.authority_sequence
                    < admission.authority_sequence
                )
            )
            or (
                not recertified
                and (
                    protocol_activation.authority_sequence
                    >= study.authority_sequence
                    or admission.authority_sequence
                    != study.authority_sequence
                    or admission.authority_event_id
                    != study.authority_event_id
                )
            )
            or (
                repair_recertified
                and not (
                    protocol_activation.authority_sequence
                    < admission.authority_sequence
                    and study.authority_sequence
                    < admission.authority_sequence
                )
            )
        )
        expected_payload_keys = {
            "accepted_replacement_preflight_id",
            "authority_manifest_digest",
            "batch_id",
            "request",
            "research_protocol_activation_id",
            "schema",
            "scientific_surface",
            "scientific_surface_hash",
            "source_closure_authority",
            "study_id",
        }
        if recertified:
            expected_payload_keys.update(
                {
                    "recertification_preflight_id",
                    "registered_prefix_executable_ids",
                }
            )
        if repair_recertified:
            expected_payload_keys.update(
                {
                    "predecessor_admission_id",
                    "repair_close_record_ids",
                    "repair_executable_id",
                    "repair_job_id",
                    "trigger_repair_close_record_id",
                }
            )
        recertification_invalid = False
        if recertified:
            batch_id = payload.get("batch_id")
            batch = (
                None
                if not isinstance(batch_id, str)
                else index.get("batch-open", batch_id)
            )
            preflight_head = (
                None
                if recertification_preflight is None
                or not isinstance(
                    recertification_preflight.event_stream,
                    str,
                )
                else index.event_head(
                    recertification_preflight.event_stream
                )
            )
            prefix = payload.get("registered_prefix_executable_ids")
            try:
                from axiom_rift.operations.replay_study_admission import (
                    ReplayStudyAdmissionError,
                    inspect_replay_study_registration,
                )

                registration = (
                    inspect_replay_study_registration(
                        index,
                        study_record=study,
                        batch_record=batch,
                    ).require_usable()
                    if study is not None and batch is not None
                    else None
                )
            except ReplayStudyAdmissionError:
                registration = None
            registered_trials = (
                ()
                if registration is None or batch is None
                else tuple(
                    index.event_record(
                        f"batch-trials:{batch.record_id}",
                        ordinal,
                    )
                    for ordinal in range(
                        1,
                        registration.registered_count + 1,
                    )
                )
            )
            prefix_count = len(prefix) if isinstance(prefix, list) else -1
            active_recertification_head = (
                repair_recertification_head
                if repair_recertified
                else recertification_head
            )
            active_recertification_stream = (
                repair_recertification_stream
                if repair_recertified
                else recertification_stream
            )
            active_recertification_sequence = (
                None
                if active_recertification_head is None
                else active_recertification_head.sequence
            )
            recertification_invalid = (
                active_recertification_head is None
                or (
                    legacy_recertified
                    and active_recertification_head.sequence != 1
                )
                or active_recertification_head.record_id != admission.record_id
                or admission.event_stream != active_recertification_stream
                or admission.event_sequence != active_recertification_sequence
                or recertification_preflight is None
                or recertification_preflight.status != "accepted"
                or recertification_preflight.payload.get("outcome")
                != "accepted"
                or recertification_preflight.payload.get("batch_id")
                != batch_id
                or recertification_preflight.payload.get("study_id")
                != study_id
                or recertification_preflight.payload.get("executable_ids")
                != executable_ids
                or recertification_preflight.payload.get(
                    "scientific_surface_hash"
                )
                != payload.get("scientific_surface_hash")
                or recertification_preflight.payload.get(
                    "source_closure_authority"
                )
                != source_authority
                or recertification_preflight.payload.get("request_identity")
                != (
                    None
                    if not isinstance(request, Mapping)
                    else (
                        "replay-job-implementation-preflight-request:"
                        + canonical_digest(
                            domain=(
                                "replay-job-implementation-preflight-request"
                            ),
                            payload=request,
                        )
                    )
                )
                or preflight_head is None
                or preflight_head.record_id
                != recertification_preflight.record_id
                or type(admission.authority_sequence) is not int
                or admission.authority_sequence
                != recertification_preflight.authority_sequence
                or admission.authority_event_id
                != recertification_preflight.authority_event_id
                or not isinstance(prefix, list)
                or any(type(item) is not str for item in prefix)
                or registration is None
                or prefix_count < 0
                or prefix_count > registration.registered_count
                or tuple(prefix)
                != registration.expected_executable_ids[: len(prefix)]
                or registration.registered_executable_ids[: len(prefix)]
                != tuple(prefix)
                or (
                    repair_recertified
                    and (
                        tuple(prefix) != registration.expected_executable_ids
                        or recertification_preflight.payload.get(
                            "repair_close_record_id"
                        )
                        != payload.get("trigger_repair_close_record_id")
                    )
                )
                or any(trial is None for trial in registered_trials)
                or any(
                    trial.authority_sequence >= admission.authority_sequence
                    for trial in registered_trials[:prefix_count]
                    if trial is not None
                )
                or any(
                    trial.authority_sequence <= admission.authority_sequence
                    for trial in registered_trials[prefix_count:]
                    if trial is not None
                )
            )
        if (
            study is None
            or study.status != "open"
            or study.subject != f"Study:{study_id}"
            or admission.status != "active"
            or admission.subject != f"Study:{study_id}"
            or set(payload) != expected_payload_keys
            or admission_schema
            not in {
                "replay_implementation_admission.v1",
                "replay_implementation_admission.v2",
                REPAIR_RECERTIFICATION_ADMISSION_SCHEMA,
            }
            or payload.get("study_id") != study_id
            or payload.get("authority_manifest_digest")
            != authority_manifest_digest
            or payload.get("research_protocol_activation_id")
            != protocol_activation.record_id
            or not isinstance(request, Mapping)
            or set(request) != request_keys
            or request.get("schema")
            != "replay_job_implementation_preflight_request.v1"
            or request.get("replacement_for_preflight_id") is not None
            or study.payload.get("mission_id") != request.get("mission_id")
            or study.payload.get("replay_obligation_ids")
            != request.get("replay_obligation_ids")
            or type(payload.get("batch_id")) is not str
            or not payload["batch_id"].startswith("batch:")
            or len(payload["batch_id"].removeprefix("batch:")) != 64
            or any(
                character not in "0123456789abcdef"
                for character in payload["batch_id"].removeprefix("batch:")
            )
            or not isinstance(manifests, list)
            or not manifests
            or not isinstance(bindings, list)
            or len(bindings) != len(manifests)
            or len(executable_ids) != len(manifests)
            or not isinstance(surface, Mapping)
            or surface_hash != payload.get("scientific_surface_hash")
            or surface.get("callable_identity")
            != request.get("callable_identity")
            or surface.get("mission_id") != request.get("mission_id")
            or surface.get("protocol_id") != request.get("protocol_id")
            or surface.get("replay_obligation_ids")
            != request.get("replay_obligation_ids")
            or not isinstance(source_authority, Mapping)
            or set(source_authority) != source_keys
            or source_authority.get("schema")
            != JOB_IMPLEMENTATION_SOURCE_AUTHORITY_SCHEMA
            or accepted_invalid
            or admission_boundary_invalid
            or recertification_invalid
            or admission.fingerprint != fingerprint
            or admission.record_id
            != f"replay-implementation-admission:{fingerprint}"
        ):
            raise RecoveryRequired(
                "Study replay implementation admission is malformed"
            )
        return admission

    def _require_replay_registration_source_authority(
        self,
        index: LocalIndex,
        *,
        admission: IndexRecord,
        executable: Any,
    ) -> None:
        """Recheck current bytes before a replay trial can enter multiplicity."""

        request = admission.payload.get("request")
        manifests = (
            None
            if not isinstance(request, Mapping)
            else request.get("executable_manifests")
        )
        bindings = (
            None
            if not isinstance(request, Mapping)
            else request.get("scientific_bindings")
        )
        executable_manifest = executable.to_identity_payload()
        try:
            member_index = (
                manifests.index(executable_manifest)
                if isinstance(manifests, list)
                else -1
            )
        except ValueError:
            member_index = -1
        if (
            member_index < 0
            or not isinstance(bindings, list)
            or member_index >= len(bindings)
            or not isinstance(bindings[member_index], Mapping)
        ):
            raise TransitionError(
                "Executable differs from the replay implementation admission"
            )
        spec = {
            "callable_identity": request["callable_identity"],
            "evidence_subject": {
                "kind": "Executable",
                "id": executable.identity,
            },
            "implementation_identity": request["implementation_identity"],
            "scientific_binding": bindings[member_index],
        }
        implementation = self._require_job_implementation_evidence(
            spec,
            _index=index,
        )
        try:
            from axiom_rift.research.implementation_closure import (
                ImplementationClosureError,
                require_current_job_source_closure,
                require_job_implementation_closure,
            )

            component_hashes = require_job_implementation_closure(
                executable_manifest=executable_manifest,
                job_artifact_hashes=implementation["artifact_hashes"],
                artifact_reader=self.evidence.read_verified,
            )
            source_authority = require_current_job_source_closure(
                callable_identity=request["callable_identity"],
                job_artifact_hashes=implementation["artifact_hashes"],
                artifact_reader=self.evidence.read_verified,
                source_root=(self.foundation_root / "src").absolute(),
                verified_non_source_artifact_hashes=component_hashes,
            )
        except ImplementationClosureError as exc:
            raise TransitionError(
                "replay implementation source drifted before trial "
                f"registration: {exc}"
            ) from exc
        if source_authority != admission.payload.get(
            "source_closure_authority"
        ):
            raise TransitionError(
                "replay implementation source authority changed after Study admission"
            )

    def _replay_scientific_protocol_failure(
        self,
        current: Mapping[str, Any],
        index: LocalIndex,
        *,
        request: Any,
    ) -> str | None:
        """Return a durable partial-Study incompatibility, not a validator guess."""

        protocol_head = index.event_head("research-protocol:scientific")
        if protocol_head is None:
            return "active scientific protocol is absent"
        protocol = index.get(
            protocol_head.record_kind,
            protocol_head.record_id,
        )
        if (
            protocol is None
            or protocol.kind != "research-protocol-activation"
            or protocol.status != "active"
            or protocol.event_sequence != protocol_head.sequence
            or protocol.event_stream != "research-protocol:scientific"
        ):
            raise RecoveryRequired(
                "active scientific protocol projection is invalid"
            )
        if (
            protocol.payload.get("protocol")
            != "scientific_adjudication_v2"
            or protocol.payload.get("authority_manifest_digest")
            != current.get("authority", {}).get("manifest_digest")
        ):
            return "active scientific protocol is not current"
        validator_ids = {
            binding.get("validator_id")
            for binding in request.scientific_binding_values()
            if isinstance(binding, Mapping)
        }
        if validator_ids != {protocol.payload.get("validator_id")}:
            return "replay family validator differs from the active protocol"
        return None

    def open_study(
        self,
        *,
        study_id: str,
        question: Mapping[str, Any],
        material_identity: str,
        material_display_name: str,
        semantic_proposal: Mapping[str, Any],
        semantic_question_equivalence: Any | None = None,
        semantic_question_lineage: Any | None = None,
        controlled_chassis: Any | None = None,
        permit: Permit,
        operation_id: str,
        portfolio_axis_id: str | None = None,
        portfolio_axis_identity: str | None = None,
        portfolio_decision_id: str | None = None,
        replay_implementation_request: Any | None = None,
        replay_batch_spec: Any | None = None,
    ) -> TransitionResult:
        self._require_study_close_delivery_guard()
        try:
            validate_study_id(study_id)
        except ValueError as exc:
            raise TransitionError("study_id is invalid") from exc
        question_manifest = _require_manifest(
            "question",
            question,
            required={
                "causal_question",
                "changed_variables",
                "controlled_variables",
                "done_conditions",
                "evidence_modes",
            },
        )
        question_manifest["evidence_modes"] = list(
            _require_study_evidence_modes(question_manifest)
        )
        question_hash = _digest(question_manifest, domain="study-question")
        _require_ascii("material_identity", material_identity)
        _require_ascii("material_display_name", material_display_name)
        semantic_proposal_manifest = _copy(semantic_proposal)
        from axiom_rift.research.semantic_question import (
            SemanticQuestionCore,
            SemanticQuestionEquivalenceProposal,
            SemanticQuestionError,
            SemanticQuestionLineageProposal,
        )

        try:
            semantic_question_core = SemanticQuestionCore.from_question_manifest(
                question_manifest
            )
        except SemanticQuestionError as exc:
            raise TransitionError(str(exc)) from exc
        if semantic_question_equivalence is not None and not isinstance(
            semantic_question_equivalence,
            SemanticQuestionEquivalenceProposal,
        ):
            raise TransitionError(
                "semantic_question_equivalence must be a typed proposal"
            )
        if semantic_question_lineage is not None and not isinstance(
            semantic_question_lineage,
            SemanticQuestionLineageProposal,
        ):
            raise TransitionError(
                "semantic_question_lineage must be a typed proposal"
            )
        from axiom_rift.research.trials import (
            MaterialReference,
            StudyTrialContext,
            TrialAccountant,
        )
        from axiom_rift.research.chassis import ControlledStudyChassis

        if controlled_chassis is not None and not isinstance(
            controlled_chassis, ControlledStudyChassis
        ):
            raise TransitionError("controlled_chassis must be a ControlledStudyChassis")
        if not self.engineering_fixture and controlled_chassis is None:
            raise TransitionError(
                "scientific Study requires a typed controlled component chassis"
            )

        trial_accountant = TrialAccountant.from_foundation(self.foundation_root)
        material_reference = MaterialReference(
            identity=material_identity,
            display_name=material_display_name,
        )
        study_hash = self.study_input_hash(
            question=question_manifest,
            material_identity=material_identity,
            semantic_proposal=semantic_proposal_manifest,
            semantic_question_equivalence=semantic_question_equivalence,
            semantic_question_lineage=semantic_question_lineage,
            controlled_chassis=controlled_chassis,
            portfolio_axis_id=portfolio_axis_id,
            portfolio_axis_identity=portfolio_axis_identity,
            portfolio_decision_id=portfolio_decision_id,
        )

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science["active_initiative"] is None or science["active_study"] is not None:
                raise TransitionError("Study open requires an Initiative and no active Study")
            initiative_id = science["active_initiative"]
            portfolio_snapshot_id: str | None = None
            mechanism_family: str | None = None
            primary_research_layer: str | None = None
            system_architecture_family: str | None = None
            changed_domains: list[str] | None = None
            controlled_domains: list[str] | None = None
            portfolio_action: str | None = None
            commitment_batches: int | None = None
            replay_obligation_ids: tuple[str, ...] = ()
            replacement_preflight: IndexRecord | None = None
            if not self.engineering_fixture:
                if (
                    portfolio_axis_id is None
                    or portfolio_axis_identity is None
                    or portfolio_decision_id is None
                ):
                    raise TransitionError(
                        "scientific Study requires exact Portfolio axis and Decision identities"
                    )
                _require_ascii("portfolio_axis_id", portfolio_axis_id)
                next_action = current["next_action"]
                portfolio_snapshot_id = next_action.get("portfolio_snapshot_id")
                if (
                    next_action.get("kind") != "execute_portfolio_decision"
                    or next_action.get("target_id") != portfolio_axis_id
                    or next_action.get("target_axis_identity")
                    != portfolio_axis_identity
                    or next_action.get("decision_id") != portfolio_decision_id
                    or not isinstance(portfolio_snapshot_id, str)
                ):
                    raise TransitionError(
                        "Study must execute the current Portfolio Decision target"
                    )
                snapshot = _index.get("portfolio-snapshot", portfolio_snapshot_id)
                if snapshot is None:
                    raise TransitionError("Study Portfolio snapshot is unavailable")
                decision = self._active_portfolio_decision(
                    _index, portfolio_decision_id
                )
                if (
                    decision is None
                    or decision.payload.get("portfolio_snapshot_id")
                    != portfolio_snapshot_id
                ):
                    raise TransitionError("Study Portfolio Decision is unavailable or stale")
                from axiom_rift.operations.replay_projection import (
                    ReplayProjectionError,
                    ReplayTransitionError,
                    require_study_pending,
                )

                try:
                    replay_obligation_ids = require_study_pending(
                        _index,
                        mission_id=science["active_mission"],
                        decision_payload=decision.payload,
                        next_action=next_action,
                    )
                except ReplayProjectionError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                except ReplayTransitionError as exc:
                    raise TransitionError(str(exc)) from exc
                replacement_preflight = (
                    self._current_accepted_replay_replacement_preflight(
                        _index,
                        mission_id=science["active_mission"],
                        obligation_ids=replay_obligation_ids,
                    )
                )
                options = {
                    option["option_id"]: option
                    for option in decision.payload.get("options", [])
                }
                chosen = options.get(decision.payload.get("chosen_option_id"))
                work_actions = {
                    "complementary_sleeve",
                    "contrast",
                    "deepen",
                    "recombine",
                    "rotate",
                    "synthesize",
                }
                if (
                    not isinstance(chosen, dict)
                    or chosen.get("action") not in work_actions
                    or chosen.get("target_id") != portfolio_axis_id
                ):
                    raise TransitionError(
                        "Portfolio Decision does not authorize a scientific Study"
                    )
                axis = next(
                    (
                        value
                        for value in snapshot.payload["axes"]
                        if value["axis_id"] == portfolio_axis_id
                    ),
                    None,
                )
                if (
                    axis is None
                    or axis["status"] == "pruned"
                    or axis.get("axis_identity") != portfolio_axis_identity
                ):
                    raise TransitionError("Study Portfolio axis is absent or pruned")
                decision_baseline = decision.payload.get("baseline_executable")
                if not isinstance(decision_baseline, Mapping):
                    raise RecoveryRequired(
                        "accepted Portfolio Decision baseline is malformed"
                    )
                source_authority_subject_ids = (
                    self._source_authority_subject_ids(
                        decision_baseline,
                        error_type=RecoveryRequired,
                    )
                )
                recorded_source_authority_subject_ids = decision.payload.get(
                    "source_authority_subject_ids"
                )
                if (
                    recorded_source_authority_subject_ids is not None
                    and recorded_source_authority_subject_ids
                    != list(source_authority_subject_ids)
                ):
                    raise RecoveryRequired(
                        "accepted Portfolio Decision source authority is malformed"
                    )
                effective_axis = self._effective_axis_resolution(
                    _index,
                    axis,
                    prospective_source_ids=source_authority_subject_ids,
                )
                if not effective_axis.selectable:
                    raise TransitionError(
                        "Study Portfolio axis is effectively blocked by current source authority"
                    )
                mechanism_family = axis["mechanism_family"]
                primary_research_layer = axis["primary_research_layer"]
                system_architecture_family = axis["system_architecture_family"]
                changed_domains = list(axis["changed_domains"])
                controlled_domains = list(axis["controlled_domains"])
                portfolio_action = chosen["action"]
                commitment_batches = decision.payload["commitment_batches"]
                if (
                    type(commitment_batches) is not int
                    or commitment_batches <= 0
                ):
                    raise TransitionError(
                        "Portfolio Decision must commit a positive finite Batch bound"
                    )
                assert controlled_chassis is not None
                if [domain.value for domain in controlled_chassis.changed_domains] != sorted(
                    changed_domains
                ):
                    raise TransitionError(
                        "Study changed component domains differ from its Portfolio axis"
                    )
                if [domain.value for domain in controlled_chassis.controlled_domains] != sorted(
                    controlled_domains
                ):
                    raise TransitionError(
                        "Study controlled component domains differ from its Portfolio axis"
                    )
                typed_axis_chassis = axis.get("architecture_chassis_identity")
                typed_axis_payload = axis.get("architecture_chassis")
                accepted_architecture = next_action.get(
                    "architecture_chassis_identity"
                )
                accepted_resolved_family = next_action.get(
                    "resolved_architecture_family"
                )
                accepted_baseline = next_action.get("baseline_executable_id")
                resolved_controlled_family = self._resolved_architecture_family(
                    index=_index,
                    architecture_payload=controlled_chassis.architecture.to_identity_payload(),
                )
                resolved_axis_family = (
                    None
                    if not isinstance(typed_axis_chassis, str)
                    else self._resolved_architecture_family(
                        index=_index,
                        architecture_payload=typed_axis_payload,
                    )
                    if isinstance(typed_axis_payload, dict)
                    else None
                )
                axis_family_mismatch = (
                    isinstance(typed_axis_chassis, str)
                    and resolved_axis_family != resolved_controlled_family
                )
                recorded_replacement_equivalence = decision.payload.get(
                    "replacement_architecture_equivalence"
                )
                action_replacement_equivalence = next_action.get(
                    "replacement_architecture_equivalence"
                )
                if axis_family_mismatch:
                    from axiom_rift.operations.replay_job_implementation_preflight import (
                        ReplayJobImplementationPreflightError,
                        ReplayJobImplementationPreflightRequest,
                        require_replacement_replay_study_semantics,
                    )
                    from axiom_rift.research.portfolio import BatchSpec
                    from axiom_rift.research.semantic_question import (
                        SemanticQuestionLineageProposal,
                        SemanticQuestionRelation,
                    )

                    if not isinstance(
                        replay_implementation_request,
                        ReplayJobImplementationPreflightRequest,
                    ):
                        raise TransitionError(
                            "Study replacement chassis lacks its exact implementation request"
                        )
                    if not isinstance(replay_batch_spec, BatchSpec):
                        raise TransitionError(
                            "Study replacement chassis lacks its exact Batch spec"
                        )
                    if (
                        not isinstance(
                            semantic_question_lineage,
                            SemanticQuestionLineageProposal,
                        )
                        or semantic_question_lineage.relation
                        is not SemanticQuestionRelation.ENGINEERING_REENTRY
                        or semantic_question_lineage.successor_study_id
                        != study_id
                        or semantic_question_lineage.predecessor_core_id
                        != semantic_question_lineage.successor_core_id
                        or semantic_question_lineage.successor_core_id
                        != semantic_question_core.identity
                    ):
                        raise TransitionError(
                            "Study replacement chassis lacks engineering reentry lineage"
                        )
                    prospective_replacement_study = {
                        "changed_domains": changed_domains,
                        "controlled_chassis": (
                            controlled_chassis.to_identity_payload()
                        ),
                        "controlled_domains": controlled_domains,
                        "material_identity": material_identity,
                        "mechanism_family": mechanism_family,
                        "mission_id": science["active_mission"],
                        "portfolio_action": portfolio_action,
                        "primary_research_layer": primary_research_layer,
                        "question": question_manifest,
                        "replay_obligation_ids": list(
                            replay_obligation_ids
                        ),
                        "semantic_proposal": semantic_proposal_manifest,
                        "semantic_question_core_id": (
                            semantic_question_core.identity
                        ),
                    }
                    try:
                        equivalence_hash = (
                            require_replacement_replay_study_semantics(
                                accepted_payload=(
                                    {}
                                    if replacement_preflight is None
                                    else replacement_preflight.payload
                                ),
                                study_payload=prospective_replacement_study,
                            )
                        )
                    except ReplayJobImplementationPreflightError as exc:
                        raise TransitionError(
                            "Study replacement chassis lacks exact accepted "
                            "scientific equivalence"
                        ) from exc
                    assert replacement_preflight is not None
                    prospective_study_binding_hash = _digest(
                        prospective_replacement_study,
                        domain="replay-replacement-study-binding",
                    )
                    expected_replacement_equivalence = {
                        "accepted_replacement_preflight_id": (
                            replacement_preflight.record_id
                        ),
                        "accepted_axis_architecture_family": (
                            resolved_axis_family
                        ),
                        "replacement_architecture_family": (
                            resolved_controlled_family
                        ),
                        "replacement_baseline_executable_id": (
                            controlled_chassis.baseline_executable.identity
                        ),
                        "replay_obligation_ids": list(
                            replay_obligation_ids
                        ),
                        "replacement_executable_ids": list(
                            replay_implementation_request.executable_ids
                        ),
                        "replacement_batch_id": replay_batch_spec.identity,
                        "replacement_request_identity": (
                            replay_implementation_request.identity
                        ),
                        "replacement_lineage_id": (
                            semantic_question_lineage.identity
                        ),
                        "schema": (
                            "replay_replacement_architecture_equivalence.v1"
                        ),
                        "scientific_equivalence_hash": equivalence_hash,
                        "prospective_study_binding_hash": (
                            prospective_study_binding_hash
                        ),
                        "target_axis_identity": axis["axis_identity"],
                    }
                    engineering_diagnosis_id = (
                        recorded_replacement_equivalence.get(
                            "engineering_gap_diagnosis_id"
                        )
                        if isinstance(
                            recorded_replacement_equivalence,
                            Mapping,
                        )
                        else None
                    )
                    decision_diagnosis_id = decision.payload.get(
                        "study_diagnosis_id"
                    )
                    decision_diagnosis = (
                        _index.get(
                            "study-diagnosis",
                            decision_diagnosis_id,
                        )
                        if isinstance(decision_diagnosis_id, str)
                        else None
                    )
                    if (
                        decision_diagnosis is not None
                        and decision_diagnosis.payload.get("evidence_state")
                        == "engineering_gap"
                        and engineering_diagnosis_id
                        != decision_diagnosis_id
                    ):
                        raise RecoveryRequired(
                            "Study engineering reentry binding is absent"
                        )
                    if isinstance(engineering_diagnosis_id, str):
                        engineering_diagnosis = _index.get(
                            "study-diagnosis",
                            engineering_diagnosis_id,
                        )
                        replaced_preflight_id = (
                            replacement_preflight.payload.get(
                                "replacement_for_preflight_id"
                            )
                        )
                        diagnosis_basis = (
                            set()
                            if engineering_diagnosis is None
                            else {
                                (
                                    item.get("kind"),
                                    item.get("record_id"),
                                )
                                for item in engineering_diagnosis.payload.get(
                                    "evidence_basis",
                                    [],
                                )
                                if isinstance(item, Mapping)
                            }
                        )
                        if (
                            engineering_diagnosis is None
                            or engineering_diagnosis.payload.get(
                                "evidence_state"
                            )
                            != "engineering_gap"
                            or decision.payload.get("study_diagnosis_id")
                            != engineering_diagnosis_id
                            or semantic_question_lineage
                            .predecessor_study_id
                            != engineering_diagnosis.payload.get("study_id")
                            or {
                                "study-diagnosis:"
                                + engineering_diagnosis_id,
                                "job-implementation-preflight:"
                                + replaced_preflight_id,
                            }.difference(
                                semantic_question_lineage.basis_record_ids
                            )
                            or (
                                "job-implementation-preflight",
                                replaced_preflight_id,
                            )
                            not in diagnosis_basis
                        ):
                            raise RecoveryRequired(
                                "Study engineering reentry diagnosis is malformed"
                            )
                        expected_replacement_equivalence[
                            "engineering_gap_diagnosis_id"
                        ] = engineering_diagnosis_id
                    if (
                        recorded_replacement_equivalence
                        != expected_replacement_equivalence
                        or action_replacement_equivalence
                        != expected_replacement_equivalence
                    ):
                        raise TransitionError(
                            "Study replacement chassis differs from its "
                            "accepted Decision equivalence"
                        )
                elif (
                    recorded_replacement_equivalence is not None
                    or action_replacement_equivalence is not None
                ):
                    raise RecoveryRequired(
                        "Study carries unnecessary replacement architecture authority"
                    )
                if (
                    not isinstance(accepted_architecture, str)
                    or not isinstance(accepted_resolved_family, str)
                    or not isinstance(accepted_baseline, str)
                    or accepted_architecture
                    != decision.payload.get("architecture_chassis_identity")
                    or decision.payload.get("architecture_chassis")
                    != controlled_chassis.architecture.to_identity_payload()
                    or accepted_baseline
                    != decision.payload.get("baseline_executable_id")
                    or accepted_architecture
                    != controlled_chassis.architecture.identity
                    or accepted_baseline
                    != controlled_chassis.baseline_executable.identity
                    or accepted_resolved_family != resolved_controlled_family
                ):
                    raise TransitionError(
                        "Study chassis differs from its accepted Portfolio Decision anchor"
                    )
                self._require_registered_chassis_baseline(
                    index=_index,
                    controlled_chassis=controlled_chassis,
                    decision=decision,
                )
                self._require_component_parity_evidence(
                    index=_index,
                    controlled_chassis=controlled_chassis,
                    mission_id=science["active_mission"],
                    portfolio_decision_id=portfolio_decision_id,
                )
                required_study_scope = {
                    "study",
                    f"decision:{portfolio_decision_id}",
                    f"axis:{portfolio_axis_identity}",
                    f"baseline:{accepted_baseline}",
                    f"chassis:{accepted_architecture}",
                    f"snapshot:{portfolio_snapshot_id}",
                }
                if not required_study_scope.issubset(permit.scope):
                    raise TransitionError(
                        "StudyPermit does not bind the accepted Portfolio Decision"
                    )
                system_architecture_family = resolved_controlled_family
            admission_record: IndexRecord | None = None
            if replay_obligation_ids:
                from axiom_rift.operations.research_protocol_projection import (
                    ResearchProtocolProjectionError,
                    require_current_research_protocol_activation,
                )
                from axiom_rift.operations.replay_job_implementation_preflight import (
                    PREFLIGHT_SCHEMA,
                    ReplayJobImplementationPreflightError,
                    ReplayJobImplementationPreflightRequest,
                    derive_replay_job_scientific_surface,
                    evaluate_replay_job_implementation_preflight,
                    replay_job_scientific_surface_hash,
                    require_active_replay_job_replacement_binding,
                )
                from axiom_rift.research.portfolio import BatchSpec

                if (
                    not isinstance(
                        replay_implementation_request,
                        ReplayJobImplementationPreflightRequest,
                    )
                    or not isinstance(replay_batch_spec, BatchSpec)
                    or replay_implementation_request.mission_id
                    != science["active_mission"]
                    or replay_implementation_request.replay_obligation_ids
                    != replay_obligation_ids
                    or replay_implementation_request.replacement_for_preflight_id
                    is not None
                ):
                    raise TransitionError(
                        "replay Study lacks typed implementation admission"
                    )
                authority_manifest_digest = current.get("authority", {}).get(
                    "manifest_digest"
                )
                try:
                    protocol_activation = (
                        require_current_research_protocol_activation(
                            _index,
                            authority_manifest_digest=authority_manifest_digest,
                        )
                    )
                except ResearchProtocolProjectionError as exc:
                    raise TransitionError(
                        "replay Study requires the current prospective protocol "
                        "before implementation admission"
                    ) from exc
                current_preflight = (
                    evaluate_replay_job_implementation_preflight(
                        replay_implementation_request,
                        index=_index,
                        artifact_reader=self.evidence.read_verified,
                        source_root=(self.foundation_root / "src").absolute(),
                    )
                )
                if not current_preflight.accepted:
                    raise TransitionError(
                        "replay Study implementation is not current: "
                        f"{current_preflight.reason_code}: "
                        f"{current_preflight.failure_detail}"
                    )
                study_surface_payload = {
                    "changed_domains": changed_domains,
                    "controlled_chassis": (
                        None
                        if controlled_chassis is None
                        else controlled_chassis.to_identity_payload()
                    ),
                    "controlled_domains": controlled_domains,
                    "material_identity": material_identity,
                    "mechanism_family": mechanism_family,
                    "mission_id": science["active_mission"],
                    "portfolio_action": portfolio_action,
                    "primary_research_layer": primary_research_layer,
                    "question": question_manifest,
                    "replay_obligation_ids": list(replay_obligation_ids),
                    "semantic_proposal": semantic_proposal_manifest,
                    "semantic_question_core_id": semantic_question_core.identity,
                }
                try:
                    scientific_surface = derive_replay_job_scientific_surface(
                        replay_implementation_request,
                        study_payload=study_surface_payload,
                        batch_payload={
                            "spec": replay_batch_spec.to_identity_payload()
                        },
                        artifact_reader=self.evidence.read_verified,
                    )
                    scientific_surface_hash = (
                        replay_job_scientific_surface_hash(
                            scientific_surface
                        )
                    )
                    active_payload = {
                            "callable_identity": (
                                replay_implementation_request.callable_identity
                            ),
                            "executable_ids": list(
                                replay_implementation_request.executable_ids
                            ),
                            "executable_manifests": [
                                executable.to_identity_payload()
                                for executable in (
                                    replay_implementation_request.executables
                                )
                            ],
                            "implementation_identity": (
                                replay_implementation_request
                                .implementation_identity
                            ),
                            "mission_id": (
                                replay_implementation_request.mission_id
                            ),
                            "protocol_id": (
                                replay_implementation_request.protocol_id
                            ),
                            "replacement_for_preflight_id": None,
                            "replay_obligation_ids": list(
                                replay_implementation_request
                                .replay_obligation_ids
                            ),
                            "schema": PREFLIGHT_SCHEMA,
                            "scientific_surface": scientific_surface,
                            "scientific_surface_hash": (
                                scientific_surface_hash
                            ),
                        }
                    if replacement_preflight is not None:
                        require_active_replay_job_replacement_binding(
                            accepted_payload=replacement_preflight.payload,
                            active_payload=active_payload,
                        )
                except ReplayJobImplementationPreflightError as exc:
                    raise TransitionError(str(exc)) from exc
                request_payload = (
                    replay_implementation_request.to_identity_payload()
                )
                admission_payload = {
                    "accepted_replacement_preflight_id": (
                        None
                        if replacement_preflight is None
                        else replacement_preflight.record_id
                    ),
                    "authority_manifest_digest": authority_manifest_digest,
                    "batch_id": replay_batch_spec.identity,
                    "request": request_payload,
                    "research_protocol_activation_id": (
                        protocol_activation.record_id
                    ),
                    "schema": "replay_implementation_admission.v1",
                    "scientific_surface": scientific_surface,
                    "scientific_surface_hash": scientific_surface_hash,
                    "source_closure_authority": dict(
                        current_preflight.source_closure_authority or {}
                    ),
                    "study_id": study_id,
                }
                admission_fingerprint = _digest(
                    admission_payload,
                    domain="replay-implementation-admission",
                )
                admission_record = _record(
                    kind="replay-implementation-admission",
                    record_id=(
                        "replay-implementation-admission:"
                        + admission_fingerprint
                    ),
                    subject=f"Study:{study_id}",
                    status="active",
                    fingerprint=admission_fingerprint,
                    payload=admission_payload,
                )
            elif (
                replay_implementation_request is not None
                or replay_batch_spec is not None
            ):
                raise TransitionError(
                    "replay implementation admission lacks a replacement trigger"
                )
            if material_identity == trial_accountant.observed_material_identity:
                trial_context = trial_accountant.open_study(
                    material=material_reference,
                    semantic_proposal=semantic_proposal_manifest,
                )
            else:
                development_material = _index.get(
                    "development-material", material_identity
                )
                if (
                    development_material is None
                    or development_material.status != "accepted"
                    or development_material.subject
                    != f"Mission:{science['active_mission']}"
                    or development_material.payload.get("mission_id")
                    != science["active_mission"]
                    or development_material.payload.get("material_identity")
                    != material_identity
                    or (
                        science["holdout_reveals"] > 0
                        and development_material.payload.get("holdout_id")
                        != science.get("required_future_holdout_id")
                    )
                ):
                    raise TransitionError(
                        "Study material is not registered for the active Mission"
                    )
                trial_context = StudyTrialContext(
                    material_identity=material_identity,
                    prior_global_multiplicity=0,
                    semantic_warnings=trial_accountant.lookup_semantic_warnings(
                        semantic_proposal_manifest
                    ),
                    warning_scheduler_weight="none",
                )
            trial_head = _index.event_head(
                f"material-trial:{trial_context.material_identity}"
            )
            prior_global_multiplicity = (
                trial_context.prior_global_multiplicity
                + (0 if trial_head is None else trial_head.sequence)
            )
            prior_material_trial_count = 0 if trial_head is None else trial_head.sequence
            self._validate_permit_locked(
                control=current,
                index=_index,
                permit=permit,
                expected_kind=PermitKind.STUDY,
                action="open_study",
                subject_kind=SubjectKind.INITIATIVE,
                subject_id=initiative_id,
                expected_input_hash=study_hash,
            )
            science["active_study"] = study_id
            body["next_action"] = {"kind": "freeze_batch", "study_id": study_id}
            authorization = self._authorization(
                kind=SubjectKind.STUDY,
                subject_id=study_id,
                semantic_hash=study_hash,
            )
            self._bind_authorization(body, authorization)
            consumption = self._permit_consumption_record(permit, operation_id)
            record = _record(
                kind="study-open",
                record_id=study_id,
                subject=f"Study:{study_id}",
                status="open",
                fingerprint=study_hash,
                payload={
                    "question_hash": question_hash,
                    "question": question_manifest,
                    "material_identity": trial_context.material_identity,
                    "mechanism_family": mechanism_family,
                    "mission_id": science["active_mission"],
                    "primary_research_layer": primary_research_layer,
                    "system_architecture_family": system_architecture_family,
                    "portfolio_architecture_family": axis[
                        "system_architecture_family"
                    ] if not self.engineering_fixture else None,
                    "controlled_chassis": (
                        None
                        if controlled_chassis is None
                        else controlled_chassis.to_identity_payload()
                    ),
                    "controlled_chassis_identity": (
                        None
                        if controlled_chassis is None
                        else controlled_chassis.controlled_chassis_identity
                    ),
                    "changed_domains": changed_domains,
                    "controlled_domains": controlled_domains,
                    "portfolio_action": portfolio_action,
                    "portfolio_axis_id": portfolio_axis_id,
                    "portfolio_axis_identity": portfolio_axis_identity,
                    "portfolio_decision_id": portfolio_decision_id,
                    "portfolio_snapshot_id": portfolio_snapshot_id,
                    "commitment_batches": commitment_batches,
                    "semantic_proposal": semantic_proposal_manifest,
                    "semantic_question_core_id": semantic_question_core.identity,
                    "semantic_question_equivalence": (
                        None
                        if semantic_question_equivalence is None
                        else semantic_question_equivalence.to_identity_payload()
                    ),
                    "semantic_question_equivalence_id": (
                        None
                        if semantic_question_equivalence is None
                        else semantic_question_equivalence.identity
                    ),
                    "semantic_question_lineage": (
                        None
                        if semantic_question_lineage is None
                        else semantic_question_lineage.to_identity_payload()
                    ),
                    "semantic_question_lineage_id": (
                        None
                        if semantic_question_lineage is None
                        else semantic_question_lineage.identity
                    ),
                    "prior_global_multiplicity": prior_global_multiplicity,
                    "prior_material_trial_count": prior_material_trial_count,
                    "semantic_warning_ids": [
                        warning.warning_id for warning in trial_context.semantic_warnings
                    ],
                    "warning_scheduler_weight": trial_context.warning_scheduler_weight,
                    **(
                        {"replay_obligation_ids": list(replay_obligation_ids)}
                        if replay_obligation_ids
                        else {}
                    ),
                    **(
                        {
                            "replay_implementation_admission_id": (
                                admission_record.record_id
                            )
                        }
                        if admission_record is not None
                        else {}
                    ),
                },
            )
            semantic_records: list[IndexRecord] = []
            from axiom_rift.operations.semantic_question_registry import (
                SemanticQuestionRegistryError,
                SemanticQuestionRegistryIntegrityError,
                require_repeated_core_lineage,
                require_semantic_question_projection,
                require_semantic_question_registry_activation,
                semantic_question_prospective_equivalence_record,
                semantic_question_prospective_lineage_record,
                semantic_question_records_for_study,
            )

            try:
                registry_active = (
                    require_semantic_question_registry_activation(_index)
                    is not None
                )
                if registry_active:
                    require_repeated_core_lineage(
                        _index,
                        successor_study_id=study_id,
                        successor_core_id=semantic_question_core.identity,
                        proposal=semantic_question_lineage,
                    )
                    for projected in semantic_question_records_for_study(record):
                        pending = require_semantic_question_projection(
                            _index, projected
                        )
                        if pending is not None:
                            semantic_records.append(pending)
                    equivalence_record = None
                    if semantic_question_equivalence is not None:
                        equivalence_record = (
                            semantic_question_prospective_equivalence_record(
                                _index,
                                record,
                                semantic_question_equivalence,
                            )
                        )
                        pending = require_semantic_question_projection(
                            _index, equivalence_record
                        )
                        if pending is not None:
                            semantic_records.append(pending)
                    if semantic_question_lineage is not None:
                        lineage_record = (
                            semantic_question_prospective_lineage_record(
                                _index,
                                record,
                                semantic_question_lineage,
                                equivalence_record=equivalence_record,
                            )
                        )
                        pending = require_semantic_question_projection(
                            _index, lineage_record
                        )
                        if pending is not None:
                            semantic_records.append(pending)
            except SemanticQuestionRegistryIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except SemanticQuestionRegistryError as exc:
                raise TransitionError(str(exc)) from exc
            return body, [
                consumption,
                *(
                    (admission_record,)
                    if admission_record is not None
                    else ()
                ),
                record,
                *semantic_records,
            ], {
                "study_id": study_id,
                "study_hash": study_hash,
                "semantic_question_core_id": semantic_question_core.identity,
                "semantic_question_lineage_id": (
                    None
                    if semantic_question_lineage is None
                    else semantic_question_lineage.identity
                ),
                "controlled_chassis_identity": (
                    None
                    if controlled_chassis is None
                    else controlled_chassis.controlled_chassis_identity
                ),
                "replay_implementation_admission_id": (
                    None
                    if admission_record is None
                    else admission_record.record_id
                ),
                "prior_global_multiplicity": prior_global_multiplicity,
                "semantic_warning_count": len(trial_context.semantic_warnings),
            }

        return self._commit(
            event_kind="study_opened",
            operation_id=operation_id,
            subject=f"Study:{study_id}",
            payload={
                "study_id": study_id,
                "question_hash": question_hash,
                "question": question_manifest,
                "material_identity": material_identity,
                "portfolio_axis_identity": portfolio_axis_identity,
                "portfolio_decision_id": portfolio_decision_id,
                "study_hash": study_hash,
                "permit_id": permit.permit_id,
                "semantic_question_core_id": semantic_question_core.identity,
                "semantic_question_equivalence_id": (
                    None
                    if semantic_question_equivalence is None
                    else semantic_question_equivalence.identity
                ),
                "semantic_question_lineage_id": (
                    None
                    if semantic_question_lineage is None
                    else semantic_question_lineage.identity
                ),
            },
            prepare=prepare,
        )

    def study_chassis_combination_identity(
        self,
        *,
        left_study_id: str,
        right_study_id: str,
        shared_domains: tuple[Any, ...],
    ) -> str:
        """Prove cross-Study chassis compatibility from stored Writer authority."""

        validate_study_id(left_study_id)
        validate_study_id(right_study_id)
        from axiom_rift.research.chassis import (
            ChassisIdentityError,
            combine_control_payloads,
        )
        from axiom_rift.research.governance import ResearchLayer

        if type(shared_domains) is not tuple or not shared_domains or any(
            not isinstance(domain, ResearchLayer) for domain in shared_domains
        ):
            raise TransitionError("shared chassis domains are not typed")
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                self._require_stable_locked(index)
                studies = [
                    index.get("study-open", study_id)
                    for study_id in (left_study_id, right_study_id)
                ]
                if any(study is None for study in studies):
                    raise TransitionError(
                        "cross-Study chassis proof requires registered Studies"
                    )
                payloads: list[Mapping[str, Any]] = []
                for study in studies:
                    assert study is not None
                    payload = study.payload.get("controlled_chassis")
                    mission_id = study.payload.get("mission_id")
                    decision_id = study.payload.get("portfolio_decision_id")
                    if (
                        not isinstance(payload, dict)
                        or not isinstance(mission_id, str)
                        or not isinstance(decision_id, str)
                    ):
                        raise TransitionError(
                            "Study lacks a Writer-bound controlled chassis"
                        )
                    equivalences = payload.get("equivalences")
                    if not isinstance(equivalences, list):
                        raise TransitionError(
                            "Study component equivalences are malformed"
                        )
                    for equivalence in equivalences:
                        if not isinstance(equivalence, dict):
                            raise TransitionError(
                                "Study component equivalence is malformed"
                            )
                        self._require_component_parity_payload(
                            index=index,
                            equivalence=equivalence,
                            mission_id=mission_id,
                            portfolio_decision_id=decision_id,
                        )
                    payloads.append(payload)
                surface_seeds: set[str] = set()
                component_seeds: set[str] = set()
                for payload in payloads:
                    architecture = payload.get("architecture")
                    roles = (
                        None
                        if not isinstance(architecture, dict)
                        else architecture.get("roles")
                    )
                    if not isinstance(roles, dict):
                        raise TransitionError(
                            "Study architecture roles are malformed"
                        )
                    for role in roles.values():
                        surfaces = (
                            None
                            if not isinstance(role, dict)
                            else role.get("component_semantic_surfaces")
                        )
                        if not isinstance(surfaces, list):
                            raise TransitionError(
                                "Study architecture surfaces are malformed"
                            )
                        surface_seeds.update(
                            value for value in surfaces if isinstance(value, str)
                        )
                    components = payload.get("controlled_component_identities")
                    if not isinstance(components, dict):
                        raise TransitionError(
                            "Study controlled component identities are malformed"
                        )
                    for domain in shared_domains:
                        values = components.get(domain.value)
                        if not isinstance(values, list):
                            raise TransitionError(
                                "Study shared controlled domain is malformed"
                            )
                        component_seeds.update(
                            value for value in values if isinstance(value, str)
                        )
                try:
                    return combine_control_payloads(
                        payloads[0],
                        payloads[1],
                        shared_domains=shared_domains,
                        verified_equivalences=self._verified_component_parity_edges(
                            index,
                            surface_seeds=tuple(sorted(surface_seeds)),
                            component_seeds=tuple(sorted(component_seeds)),
                        ),
                    )
                except ChassisIdentityError as exc:
                    raise TransitionError(str(exc)) from exc

    def record_source_eligibility(
        self,
        *,
        eligibility: Any,
        receipt: Any | None,
        operation_id: str,
    ) -> TransitionResult:
        """Commit one typed source-contract eligibility edge to the journal."""

        from axiom_rift.research.source_authority import SourceAuthorityLatch
        from axiom_rift.research.sources import (
            RuntimeSourceDriftObservation,
            SourceContractError,
            SourceEligibility,
            SourceEligibilityReceipt,
            SourceEligibilityState,
            SourceTransitionEvidence,
            require_source_state_transition,
        )

        if not isinstance(eligibility, SourceEligibility):
            raise TransitionError("eligibility must be a SourceEligibility")
        source_id = eligibility.contract.source_contract_id
        contract_hash = source_id.removeprefix("source:")
        _require_digest("source contract hash", contract_hash)
        if eligibility.state is SourceEligibilityState.CONTEXT_ONLY:
            if receipt is not None or eligibility.evidence_receipt_id is not None:
                raise TransitionError("context_only registration has no evidence receipt")
            transition_evidence = None
        else:
            if not isinstance(receipt, SourceEligibilityReceipt):
                raise TransitionError("source transition requires a typed evidence receipt")
            if receipt.source_contract_id != source_id:
                raise TransitionError("source receipt is bound to another contract")
            if eligibility.evidence_receipt_id != receipt.identity:
                raise TransitionError("source eligibility does not bind the supplied receipt")
            transition_evidence = receipt.evidence
            for artifact_hash in receipt.artifact_hashes:
                self.evidence.verify(artifact_hash)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            if body["scientific"]["active_mission"] is None:
                raise TransitionError("source eligibility requires an active Mission")
            pending = body.get("next_action")
            routed_source_job = (
                isinstance(pending, Mapping)
                and pending.get("kind") == "record_source_eligibility"
            )
            active_job = body["scientific"].get("active_job")
            runtime_drift_context: dict[str, Any] | None = None
            if (
                receipt is not None
                and receipt.evidence is SourceTransitionEvidence.DRIFT
                and eligibility.state is SourceEligibilityState.SUSPENDED
                and isinstance(active_job, Mapping)
                and active_job.get("status") == "running"
            ):
                runtime_drift_declaration = index.get(
                    "job-declared", active_job.get("id", "")
                )
                runtime_drift_start = index.get(
                    "job-started", active_job.get("start_record_id", "")
                )
                runtime_spec = (
                    None
                    if runtime_drift_declaration is None
                    else runtime_drift_declaration.payload.get("spec")
                )
                runtime_start = (
                    None
                    if runtime_drift_start is None
                    else runtime_drift_start.payload.get("runtime")
                )
                candidate_id = (
                    None
                    if not isinstance(runtime_start, Mapping)
                    else runtime_start.get("candidate_id")
                )
                executable_id = (
                    None
                    if not isinstance(runtime_start, Mapping)
                    else runtime_start.get("executable_id")
                )
                candidate_head = (
                    None
                    if not isinstance(executable_id, str)
                    else index.event_head(f"candidate:{executable_id}")
                )
                candidate = (
                    None
                    if candidate_head is None
                    else index.get(candidate_head.record_kind, candidate_head.record_id)
                )
                runtime_entry_id = active_job.get("runtime_entry_record_id")
                runtime_entry = (
                    None
                    if not isinstance(runtime_entry_id, str)
                    else index.get("runtime-engine-entry", runtime_entry_id)
                )
                allowed_producers = {
                    runtime_drift_start.record_id
                } if runtime_drift_start is not None else set()
                if runtime_entry is not None:
                    allowed_producers.add(runtime_entry.record_id)
                if (
                    runtime_drift_declaration is None
                    or runtime_drift_start is None
                    or not isinstance(runtime_spec, Mapping)
                    or not isinstance(runtime_spec.get("runtime_binding"), Mapping)
                    or not isinstance(runtime_start, Mapping)
                    or runtime_drift_declaration.payload.get("mission_id")
                    != body["scientific"].get("active_mission")
                    or runtime_spec.get("evidence_subject")
                    != {"kind": "Executable", "id": executable_id}
                    or executable_id != body["scientific"].get("active_executable")
                    or candidate is None
                    or candidate.record_id != candidate_id
                    or candidate_head is None
                    or candidate_head.record_id != candidate_id
                    or source_id
                    not in candidate.payload.get("executable", {}).get(
                        "source_contracts", []
                    )
                    or pending
                    != {"kind": "resume_job", "job_id": active_job.get("id")}
                    or receipt.producer_completion_id not in allowed_producers
                    or (
                        runtime_entry_id is not None
                        and (
                            runtime_entry is None
                            or runtime_entry.status != "validated"
                            or runtime_entry.subject
                            != f"Job:{active_job.get('id')}"
                            or runtime_entry.fingerprint != active_job.get("hash")
                            or runtime_entry.payload.get("job_start_record_id")
                            != runtime_drift_start.record_id
                            or runtime_entry.payload.get("candidate_id")
                            != candidate_id
                        )
                    )
                ):
                    raise TransitionError(
                        "runtime source drift is not bound to the exact active runtime Job"
                    )
                observations: list[tuple[str, RuntimeSourceDriftObservation]] = []
                for artifact_hash in receipt.artifact_hashes:
                    content = self.evidence.read_verified(artifact_hash)
                    try:
                        value = parse_canonical(content)
                    except (TypeError, ValueError):
                        continue
                    if (
                        isinstance(value, Mapping)
                        and value.get("schema")
                        == "runtime_source_drift_observation.v1"
                    ):
                        try:
                            observation = RuntimeSourceDriftObservation.from_bytes(
                                content
                            )
                        except (SourceContractError, TypeError, ValueError) as exc:
                            raise TransitionError(
                                "runtime source drift observation is malformed"
                            ) from exc
                        observations.append((artifact_hash, observation))
                if len(observations) != 1:
                    raise TransitionError(
                        "runtime source drift requires one exact typed observation"
                    )
                observation_hash, observation = observations[0]
                if (
                    observation.candidate_id != candidate_id
                    or observation.executable_id != executable_id
                    or observation.job_id != active_job.get("id")
                    or observation.job_hash != active_job.get("hash")
                    or observation.job_start_record_id
                    != runtime_drift_start.record_id
                    or observation.observed_at_utc != receipt.observed_at_utc
                    or observation.producer_record_id
                    != receipt.producer_completion_id
                    or observation.source_contract_id != source_id
                    or observation.fact_values() != receipt.fact_values()
                ):
                    raise TransitionError(
                        "runtime source drift observation differs from its active Job"
                    )
                runtime_drift_context = {
                    "artifact_hash": observation_hash,
                    "candidate_id": candidate_id,
                    "executable_id": executable_id,
                    "observation": observation,
                    "runtime_start": runtime_start,
                }
            elif isinstance(active_job, Mapping) and active_job.get("status") == "running":
                raise TransitionError(
                    "a running Job source transition must be its exact runtime drift"
                )
            if routed_source_job:
                resume_next_action = pending.get("resume_next_action")
                if (
                    receipt is None
                    or set(pending)
                    != {
                        "completion_record_id",
                        "job_id",
                        "kind",
                        "resume_next_action",
                        "source_contract_id",
                    }
                    or pending.get("source_contract_id") != source_id
                    or pending.get("completion_record_id")
                    != receipt.producer_completion_id
                    or not isinstance(resume_next_action, Mapping)
                    or not isinstance(resume_next_action.get("kind"), str)
                ):
                    raise TransitionError(
                        "source eligibility does not consume its exact routed Job"
                    )
            elif (
                receipt is not None
                and not self.engineering_fixture
                and runtime_drift_context is None
            ):
                raise TransitionError(
                    "source Job evidence must consume its exact completion route"
                )
            if (
                receipt is not None
                and not self.engineering_fixture
                and runtime_drift_context is None
            ):
                producer = index.get(
                    "job-completed", receipt.producer_completion_id
                )
                source_evidence = (
                    None if producer is None else producer.payload.get("source")
                )
                declaration = (
                    None
                    if producer is None
                    else index.get("job-declared", producer.payload.get("job_id", ""))
                )
                if (
                    producer is None
                    or producer.status != "success"
                    or (
                        routed_source_job
                        and producer.payload.get("job_id")
                        != pending.get("job_id")
                    )
                    or declaration is None
                    or declaration.payload.get("mission_id")
                    != body["scientific"]["active_mission"]
                    or not isinstance(source_evidence, dict)
                    or source_evidence.get("source_contract_id") != source_id
                    or source_evidence.get("transition_evidence")
                    != receipt.evidence.value
                    or source_evidence.get("observed_at_utc") != receipt.observed_at_utc
                    or source_evidence.get("facts") != receipt.fact_values()
                    or tuple(source_evidence.get("artifact_hashes", ()))
                    != receipt.artifact_hashes
                ):
                    raise TransitionError(
                        "source receipt is not derived from its successful source Job"
                    )
            source_head = index.event_head(f"source:{source_id}")
            latest = (
                None
                if source_head is None
                else index.get(source_head.record_kind, source_head.record_id)
            )
            if latest is not None and latest.kind != "source-state":
                raise TransitionError("source-state projection is invalid")
            latch_payload = (
                None if latest is None else latest.payload.get("source_authority_latch")
            )
            authority_head = index.event_head(f"source-authority:{source_id}")
            if authority_head is not None or latch_payload is not None:
                if latch_payload is None:
                    raise RecoveryRequired(
                        "source authority correction lacks its permanent latch"
                    )
                try:
                    latch = SourceAuthorityLatch.from_mapping(latch_payload)
                except (TypeError, ValueError) as exc:
                    raise RecoveryRequired(
                        "source authority latch projection is malformed"
                    ) from exc
                if (
                    latest is None
                    or latest.status != SourceEligibilityState.SUSPENDED.value
                    or latch.source_contract_id != source_id
                    or latch.to_identity_payload() != latch_payload
                    or authority_head is None
                    or authority_head.record_id != latch.invalidation_id
                ):
                    raise RecoveryRequired(
                        "source authority latch projection is inconsistent"
                    )
                raise TransitionError(
                    "audit-invalidated SourceContract cannot be recertified; "
                    "register a new SourceContract identity"
                )
            previous = (
                None if latest is None else SourceEligibilityState(latest.status)
            )
            if runtime_drift_context is not None:
                observation = runtime_drift_context["observation"]
                runtime_start = runtime_drift_context["runtime_start"]
                if (
                    latest is None
                    or previous is not SourceEligibilityState.RUNTIME_ELIGIBLE
                    or latest.record_id
                    != observation.prior_source_state_record_id
                    or latest.payload.get("evidence_receipt_id")
                    != observation.prior_source_receipt_id
                    or observation.prior_source_receipt_id
                    not in runtime_start.get("source_receipt_ids", [])
                ):
                    raise TransitionError(
                        "runtime source drift does not bind the exact source state used at Job start"
                    )
            require_source_state_transition(
                previous=previous,
                target=eligibility.state,
                evidence=transition_evidence,
            )
            if previous is not None and eligibility.evidence_receipt_id is None:
                raise TransitionError("a source transition requires an evidence receipt")
            ordinal = 1 if latest is None else latest.payload["ordinal"] + 1
            state_key = canonical_digest(
                domain="source-state",
                payload={
                    "source_id": source_id,
                    "state": eligibility.state.value,
                    "ordinal": ordinal,
                    "evidence_receipt_id": eligibility.evidence_receipt_id,
                },
            )
            source_payload = {
                "contract_hash": contract_hash,
                "contract": eligibility.contract.to_identity_payload(),
                "mapping_identity": eligibility.contract.mapping_identity,
                "schema_identity": eligibility.contract.schema_identity,
                "field_identity": eligibility.contract.field_identity,
                "clock_identity": eligibility.contract.clock_identity,
                "availability_identity": eligibility.contract.availability_identity,
                "ordinal": ordinal,
                "evidence_receipt_id": eligibility.evidence_receipt_id,
                "suspension_reason": eligibility.suspension_reason,
                "transition_evidence": (
                    None if transition_evidence is None else transition_evidence.value
                ),
                "receipt": None if receipt is None else receipt.to_identity_payload(),
                "scientific_trial_delta": 0,
                "alpha_failure": False,
            }
            if runtime_drift_context is not None:
                source_payload["runtime_source_drift_observation_id"] = (
                    runtime_drift_context["observation"].identity
                )
            record = _record(
                kind="source-state",
                record_id=state_key,
                subject=f"Source:{source_id}",
                status=eligibility.state.value,
                fingerprint=source_id,
                payload=source_payload,
                event_stream=f"source:{source_id}",
                event_sequence=ordinal,
            )
            records = [record]
            if routed_source_job:
                body["next_action"] = _copy(pending["resume_next_action"])
            elif runtime_drift_context is not None:
                observation = runtime_drift_context["observation"]
                observation_record = _record(
                    kind="runtime-source-drift-observation",
                    record_id=observation.identity,
                    subject=f"Job:{active_job['id']}",
                    status="fail_closed",
                    fingerprint=active_job["hash"],
                    payload={
                        **observation.to_identity_payload(),
                        "artifact_hash": runtime_drift_context["artifact_hash"],
                    },
                )
                records.append(observation_record)
                body["next_action"] = {
                    "job_id": active_job["id"],
                    "kind": "complete_runtime_source_ineligibility",
                    "observation_id": observation.identity,
                    "source_contract_id": source_id,
                    "source_state_record_id": state_key,
                }
            return body, records, {
                "runtime_source_drift_observation_id": (
                    None
                    if runtime_drift_context is None
                    else runtime_drift_context["observation"].identity
                ),
                "source_id": source_id,
                "state": eligibility.state.value,
                "ordinal": ordinal,
            }

        return self._commit(
            event_kind="source_eligibility_recorded",
            operation_id=operation_id,
            subject=f"Source:{source_id}",
            payload={
                "source_id": source_id,
                "state": eligibility.state.value,
                "transition_evidence": (
                    None if transition_evidence is None else transition_evidence.value
                ),
                "receipt_id": None if receipt is None else receipt.identity,
            },
            prepare=prepare,
        )

    def suspend_source_authority_from_audit(
        self,
        *,
        invalidation: Any,
        operation_id: str,
        crash_after: str | None = None,
    ) -> TransitionResult:
        """Fail closed one exact legacy source head without rewriting history."""

        from axiom_rift.research.source_authority import (
            AUTHORITY_TRANSITION_EVIDENCE,
            SourceAuthorityAuditManifest,
            SourceAuthorityInvalidation,
            SourceAuthorityLatch,
        )
        from axiom_rift.research.sources import (
            SourceContract,
            SourceEligibilityReceipt,
            SourceEligibilityState,
            SourceTransitionEvidence,
            SourceType,
        )

        if not isinstance(invalidation, SourceAuthorityInvalidation):
            raise TransitionError(
                "source authority suspension requires a typed invalidation"
            )
        try:
            manifest = SourceAuthorityAuditManifest.from_bytes(
                self.evidence.read_verified(invalidation.audit_artifact_hash)
            )
            invalidation.require_manifest(manifest)
            report_bytes = self.evidence.read_verified(
                manifest.report_artifact_hash
            )
            manifest.require_report(report_bytes)
            latch = SourceAuthorityLatch.bind(
                invalidation=invalidation,
                manifest=manifest,
            )
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "source authority suspension lacks its exact canonical audit manifest"
            ) from exc
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("source authority suspension requires control")
            science = current["scientific"]
            if (
                not isinstance(science.get("active_mission"), str)
                or not isinstance(science.get("active_initiative"), str)
                or current.get("next_action", {}).get("kind")
                != "portfolio_decision"
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "source authority suspension requires the stable Portfolio boundary"
                )
            try:
                durable_manifest = SourceAuthorityAuditManifest.from_bytes(
                    self.evidence.read_verified(invalidation.audit_artifact_hash)
                )
                durable_report_bytes = self.evidence.read_verified(
                    durable_manifest.report_artifact_hash
                )
                durable_manifest.require_report(durable_report_bytes)
            except (OSError, RuntimeError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "source authority audit evidence changed before commit"
                ) from exc
            if durable_manifest != manifest or durable_report_bytes != report_bytes:
                raise RecoveryRequired(
                    "source authority audit manifest changed before commit"
                )

            source_id = invalidation.source_contract_id
            if index.event_head(f"source-authority:{source_id}") is not None:
                raise TransitionError(
                    "source is permanently audit-invalidated; "
                    "a new SourceContract identity is required"
                )
            stream = f"source:{source_id}"
            head = index.event_head(stream)
            latest = (
                None
                if head is None
                else index.get(head.record_kind, head.record_id)
            )
            eligible = index.get(
                "source-state",
                invalidation.source_state_record_id,
            )
            expected_latest_id = (
                None
                if latest is None or latest.event_sequence is None
                else canonical_digest(
                    domain="source-state",
                    payload={
                        "source_id": source_id,
                        "state": latest.status,
                        "ordinal": latest.event_sequence,
                        "evidence_receipt_id": latest.payload.get(
                            "evidence_receipt_id"
                        ),
                    },
                )
            )
            expected_eligible_id = (
                None
                if eligible is None or eligible.event_sequence is None
                else canonical_digest(
                    domain="source-state",
                    payload={
                        "source_id": source_id,
                        "state": eligible.status,
                        "ordinal": eligible.event_sequence,
                        "evidence_receipt_id": eligible.payload.get(
                            "evidence_receipt_id"
                        ),
                    },
                )
            )
            if (
                head is None
                or latest is None
                or latest.kind != "source-state"
                or latest.record_id != expected_latest_id
                or latest.subject != f"Source:{source_id}"
                or latest.fingerprint != source_id
                or latest.event_sequence != head.sequence
                or latest.payload.get("ordinal") != head.sequence
                or eligible is None
                or eligible.kind != "source-state"
                or eligible.record_id != invalidation.source_state_record_id
                or eligible.record_id != expected_eligible_id
                or eligible.status
                not in {
                    SourceEligibilityState.CONTEXT_ONLY.value,
                    SourceEligibilityState.HISTORICAL_AUDITED.value,
                    SourceEligibilityState.RUNTIME_ELIGIBLE.value,
                }
                or eligible.subject != f"Source:{source_id}"
                or eligible.fingerprint != source_id
                or eligible.event_stream != stream
                or eligible.payload.get("ordinal") != eligible.event_sequence
            ):
                raise TransitionError(
                    "source authority invalidation does not bind its eligible head"
                )
            ordinary_suspended = latest.record_id != eligible.record_id
            prior_stream_record = (
                None
                if eligible.event_sequence is None
                else index.event_record(stream, eligible.event_sequence)
            )
            if ordinary_suspended and (
                eligible.status != SourceEligibilityState.RUNTIME_ELIGIBLE.value
                or latest.status != SourceEligibilityState.SUSPENDED.value
                or eligible.event_sequence is None
                or latest.event_sequence != eligible.event_sequence + 1
                or prior_stream_record is None
                or prior_stream_record.record_id != eligible.record_id
                or latest.payload.get("transition_evidence")
                != SourceTransitionEvidence.DRIFT.value
                or latest.payload.get("source_authority_latch") is not None
            ):
                raise TransitionError(
                    "source authority invalidation is not the active eligible head "
                    "or its exact ordinary suspension"
                )
            contract_payload = eligible.payload.get("contract")
            if not isinstance(contract_payload, dict):
                raise RecoveryRequired("source authority contract projection is absent")
            try:
                contract = SourceContract(
                    display_name="audit-invalidated-journal-projection",
                    canonical_instrument=contract_payload["canonical_instrument"],
                    runtime_identifier=contract_payload["runtime_identifier"],
                    source_type=SourceType(contract_payload["source_type"]),
                    instrument_semantics=contract_payload["instrument_semantics"],
                    mapping_semantics=contract_payload["mapping_semantics"],
                    schema_semantics=contract_payload["schema_semantics"],
                    field_semantics=contract_payload["field_semantics"],
                    clock_semantics=contract_payload["clock_semantics"],
                    availability_semantics=contract_payload[
                        "availability_semantics"
                    ],
                )
            except (KeyError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "source authority contract projection is malformed"
                ) from exc
            if (
                contract.identity != source_id
                or contract.to_identity_payload() != contract_payload
                or eligible.payload.get("contract_hash")
                != source_id.removeprefix("source:")
                or eligible.payload.get("mapping_identity")
                != contract.mapping_identity
                or eligible.payload.get("schema_identity")
                != contract.schema_identity
                or eligible.payload.get("field_identity") != contract.field_identity
                or eligible.payload.get("clock_identity") != contract.clock_identity
                or eligible.payload.get("availability_identity")
                != contract.availability_identity
            ):
                raise RecoveryRequired(
                    "source authority contract projection differs from its identity"
                )

            invalidated_state = eligible.status
            preserved_receipt_id = eligible.payload.get("evidence_receipt_id")
            preserved_receipt = eligible.payload.get("receipt")
            if (
                invalidated_state == SourceEligibilityState.CONTEXT_ONLY.value
                and (preserved_receipt_id is not None or preserved_receipt is not None)
            ) or (
                invalidated_state != SourceEligibilityState.CONTEXT_ONLY.value
                and (
                    not isinstance(preserved_receipt_id, str)
                    or not isinstance(preserved_receipt, dict)
                )
            ):
                raise RecoveryRequired(
                    "source authority invalidation cannot preserve the legal receipt"
                )
            receipt: SourceEligibilityReceipt | None = None
            if isinstance(preserved_receipt, dict):
                try:
                    receipt = SourceEligibilityReceipt(
                        source_contract_id=preserved_receipt["source_contract_id"],
                        evidence=SourceTransitionEvidence(
                            preserved_receipt["evidence"]
                        ),
                        producer_completion_id=preserved_receipt[
                            "producer_completion_id"
                        ],
                        observed_at_utc=preserved_receipt["observed_at_utc"],
                        artifact_hashes=tuple(preserved_receipt["artifact_hashes"]),
                        facts=preserved_receipt["facts"],
                    )
                except (KeyError, TypeError, ValueError) as exc:
                    raise RecoveryRequired(
                        "source authority invalidation receipt is malformed"
                    ) from exc
            legal_receipt = (
                receipt is None
                and invalidated_state == SourceEligibilityState.CONTEXT_ONLY.value
            ) or (
                receipt is not None
                and receipt.identity == preserved_receipt_id
                and receipt.source_contract_id == source_id
                and receipt.to_identity_payload() == preserved_receipt
                and eligible.payload.get("transition_evidence")
                == receipt.evidence.value
                and (
                    (
                        invalidated_state
                        == SourceEligibilityState.HISTORICAL_AUDITED.value
                        and receipt.evidence
                        is SourceTransitionEvidence.HISTORICAL_AUDIT
                    )
                    or (
                        invalidated_state
                        == SourceEligibilityState.RUNTIME_ELIGIBLE.value
                        and receipt.evidence
                        in {
                            SourceTransitionEvidence.RUNTIME_AVAILABILITY_PROOF,
                            SourceTransitionEvidence.SAME_SEMANTICS_RECERTIFICATION,
                        }
                    )
                )
            )
            if not legal_receipt:
                raise RecoveryRequired(
                    "source authority invalidation receipt differs from its state"
                )
            ordinary_suspension_receipt: SourceEligibilityReceipt | None = None
            if ordinary_suspended:
                latest_receipt_payload = latest.payload.get("receipt")
                try:
                    ordinary_suspension_receipt = SourceEligibilityReceipt(
                        source_contract_id=latest_receipt_payload[
                            "source_contract_id"
                        ],
                        evidence=SourceTransitionEvidence(
                            latest_receipt_payload["evidence"]
                        ),
                        producer_completion_id=latest_receipt_payload[
                            "producer_completion_id"
                        ],
                        observed_at_utc=latest_receipt_payload["observed_at_utc"],
                        artifact_hashes=tuple(
                            latest_receipt_payload["artifact_hashes"]
                        ),
                        facts=latest_receipt_payload["facts"],
                    )
                except (KeyError, TypeError, ValueError) as exc:
                    raise RecoveryRequired(
                        "ordinary source suspension receipt is malformed"
                    ) from exc
                if (
                    ordinary_suspension_receipt.evidence
                    is not SourceTransitionEvidence.DRIFT
                    or ordinary_suspension_receipt.source_contract_id != source_id
                    or ordinary_suspension_receipt.identity
                    != latest.payload.get("evidence_receipt_id")
                    or ordinary_suspension_receipt.to_identity_payload()
                    != latest_receipt_payload
                    or not isinstance(latest.payload.get("suspension_reason"), str)
                    or any(
                        latest.payload.get(field) != eligible.payload.get(field)
                        for field in (
                            "availability_identity",
                            "clock_identity",
                            "contract",
                            "contract_hash",
                            "field_identity",
                            "mapping_identity",
                            "schema_identity",
                        )
                    )
                ):
                    raise RecoveryRequired(
                        "ordinary source suspension does not preserve eligible provenance"
                    )
            if receipt is not None:
                for artifact_hash in receipt.artifact_hashes:
                    self.evidence.verify(artifact_hash)
            if ordinary_suspension_receipt is not None:
                for artifact_hash in ordinary_suspension_receipt.artifact_hashes:
                    self.evidence.verify(artifact_hash)
            suspension_reason = (
                f"{invalidation.reason_code.value}: "
                f"{invalidation.observed_defect}"
            )
            ordinal = head.sequence + 1
            state_id = canonical_digest(
                domain="source-state",
                payload={
                    "source_id": source_id,
                    "state": SourceEligibilityState.SUSPENDED.value,
                    "ordinal": ordinal,
                    "evidence_receipt_id": preserved_receipt_id,
                },
            )
            correction_stream = f"source-authority:{source_id}"
            correction_head = index.event_head(correction_stream)
            if correction_head is not None:
                raise RecoveryRequired(
                    "source authority contract already has an audit correction"
                )
            correction = _record(
                kind="source-authority-invalidation",
                record_id=invalidation.identity,
                subject=f"Source:{source_id}",
                status="confirmed_and_suspended",
                fingerprint=invalidation.identity.removeprefix(
                    "source-authority-invalidation:"
                ),
                payload={
                    "audit_manifest": manifest.to_identity_payload(),
                    "eligible_source_state_record_id": eligible.record_id,
                    "invalidation": invalidation.to_identity_payload(),
                    "latch": latch.to_identity_payload(),
                    "invalidated_state": invalidated_state,
                    "preserved_receipt_id": preserved_receipt_id,
                    "prior_active_source_state_record_id": latest.record_id,
                    "replacement_state_record_id": state_id,
                    "scientific_trial_delta": 0,
                },
                event_stream=correction_stream,
                event_sequence=1,
            )
            state = _record(
                kind="source-state",
                record_id=state_id,
                subject=f"Source:{source_id}",
                status=SourceEligibilityState.SUSPENDED.value,
                fingerprint=source_id,
                payload={
                    "contract_hash": source_id.removeprefix("source:"),
                    "contract": contract.to_identity_payload(),
                    "mapping_identity": contract.mapping_identity,
                    "schema_identity": contract.schema_identity,
                    "field_identity": contract.field_identity,
                    "clock_identity": contract.clock_identity,
                    "availability_identity": contract.availability_identity,
                    "ordinal": ordinal,
                    "evidence_receipt_id": preserved_receipt_id,
                    "suspension_reason": suspension_reason,
                    "transition_evidence": AUTHORITY_TRANSITION_EVIDENCE,
                    "receipt": (
                        None
                        if preserved_receipt is None
                        else _copy(preserved_receipt)
                    ),
                    "eligible_source_state_record_id": eligible.record_id,
                    "prior_active_source_state_record_id": latest.record_id,
                    "source_authority_latch": latch.to_identity_payload(),
                    "scientific_trial_delta": 0,
                    "alpha_failure": False,
                },
                event_stream=stream,
                event_sequence=ordinal,
            )
            return self._body(current), [correction, state], {
                "invalidation_record_id": invalidation.identity,
                "invalidated_state": invalidated_state,
                "prior_active_source_state_record_id": latest.record_id,
                "source_id": source_id,
                "source_state_record_id": state_id,
                "state": SourceEligibilityState.SUSPENDED.value,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="source_authority_suspended_from_audit",
            operation_id=operation_id,
            subject=f"Source:{invalidation.source_contract_id}",
            payload=invalidation.to_identity_payload(),
            prepare=prepare,
            crash_after=crash_after,
        )

    def record_source_replacement_lineage(
        self,
        *,
        lineage: Any,
        operation_id: str,
    ) -> TransitionResult:
        """Retire one invalidated old axis into a distinct eligible source axis."""

        from axiom_rift.operations.effective_axis_projection import (
            EffectiveAxisProjectionError,
            validate_source_replacement_lineage,
        )
        from axiom_rift.research.effective_axis import EffectiveAxisStatus
        from axiom_rift.research.source_authority import SourceReplacementLineage

        self._require_study_close_delivery_guard()
        if not isinstance(lineage, SourceReplacementLineage):
            raise TransitionError(
                "source replacement lineage must be a typed additive record"
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            mission_id = science.get("active_mission")
            if mission_id != lineage.mission_id or any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "source replacement requires a stable active Mission boundary"
                )
            active_initiative = science.get("active_initiative")
            next_action = current.get("next_action")
            stable_portfolio_boundary = (
                isinstance(active_initiative, str)
                and isinstance(next_action, dict)
                and next_action.get("kind") == "portfolio_decision"
            )
            if not (
                stable_portfolio_boundary
                or self._active_mission_stable_boundary(current)
            ):
                raise TransitionError(
                    "source replacement cannot bypass pending research direction"
                )
            portfolio_head = index.event_head(f"portfolio:{mission_id}")
            snapshot = (
                None
                if portfolio_head is None
                else index.get(portfolio_head.record_kind, portfolio_head.record_id)
            )
            raw_axes = None if snapshot is None else snapshot.payload.get("axes")
            if (
                snapshot is None
                or snapshot.record_id != lineage.portfolio_snapshot_id
                or snapshot.subject != f"Mission:{mission_id}"
                or not isinstance(raw_axes, list)
            ):
                raise TransitionError(
                    "source replacement is not bound to the current Portfolio"
                )
            axes = {
                axis.get("axis_id"): axis
                for axis in raw_axes
                if isinstance(axis, dict) and isinstance(axis.get("axis_id"), str)
            }
            original_axis = axes.get(lineage.original_axis_id)
            replacement_axis = axes.get(lineage.replacement_axis_id)
            if (
                len(axes) != len(raw_axes)
                or original_axis is None
                or replacement_axis is None
            ):
                raise TransitionError(
                    "source replacement Portfolio axes are unavailable"
                )
            try:
                binding = validate_source_replacement_lineage(
                    index,
                    lineage,
                    require_current_replacement_source=True,
                )
            except EffectiveAxisProjectionError as exc:
                raise TransitionError(str(exc)) from exc
            original_resolution, replacement_resolution = (
                self._effective_axis_resolutions(
                    index,
                    (original_axis, replacement_axis),
                )
            )
            exact_invalidation = any(
                item.source_contract_id
                == lineage.invalidated_source_contract_id
                and item.invalidation_record_id == lineage.invalidation_id
                for item in original_resolution.invalidations
            )
            if (
                original_resolution.effective_status
                is not EffectiveAxisStatus.BLOCKED_BY_INVALIDATED_SOURCE
                or not exact_invalidation
                or not replacement_resolution.selectable
                or binding.record_id != lineage.identity
            ):
                raise TransitionError(
                    "source replacement does not retire one exact blocked axis "
                    "into a selectable replacement axis"
                )
            stream = (
                f"source-replacement:{mission_id}:"
                f"{lineage.original_axis_identity}:"
                f"{lineage.invalidated_source_contract_id}"
            )
            if index.event_head(stream) is not None:
                raise TransitionError(
                    "source replacement lineage is already recorded"
                )
            payload = {
                "candidate_delta": 0,
                "claim_delta": "none",
                "holdout_delta": 0,
                "lineage": lineage.to_identity_payload(),
                "scientific_credit": 0,
                "terminal_scientific_credit": 0,
                "trial_delta": 0,
            }
            record = _record(
                kind="source-replacement-lineage",
                record_id=lineage.identity,
                subject=f"Axis:{lineage.original_axis_identity}",
                status="retired_original_axis",
                fingerprint=lineage.identity.removeprefix(
                    "source-replacement-lineage:"
                ),
                payload=payload,
                event_stream=stream,
                event_sequence=1,
            )
            return self._body(current), [record], {
                "candidate_delta": 0,
                "claim_delta": "none",
                "holdout_delta": 0,
                "original_axis_id": lineage.original_axis_id,
                "replacement_axis_id": lineage.replacement_axis_id,
                "source_replacement_lineage_id": lineage.identity,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="source_replacement_lineage_recorded",
            operation_id=operation_id,
            subject=f"Axis:{lineage.original_axis_identity}",
            payload={"lineage": lineage.to_identity_payload()},
            prepare=prepare,
        )

    def open_batch(
        self,
        *,
        batch_spec: Any,
        permit: Permit,
        source_permits: tuple[Permit, ...] = (),
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.research.portfolio import BatchSpec

        self._require_study_close_delivery_guard()
        if not isinstance(batch_spec, BatchSpec):
            raise TransitionError("batch_spec must be a frozen BatchSpec")
        batch_id = batch_spec.identity
        batch_hash = batch_spec.identity.removeprefix("batch:")
        _require_digest("batch_hash", batch_hash)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            study_id = science["active_study"]
            if study_id is None or science["active_batch"] is not None:
                raise TransitionError("Batch open requires one active Study and no Batch")
            if batch_spec.study_id != study_id:
                raise TransitionError("BatchSpec is bound to another Study")
            study_record = index.get("study-open", study_id)
            if (
                study_record is None
                or study_record.status != "open"
                or study_record.fingerprint != batch_spec.study_hash
            ):
                raise TransitionError("BatchSpec is not bound to the active Study identity")
            replay_admission = self._study_replay_implementation_admission(
                index,
                study_id=study_id,
                authority_manifest_digest=current.get("authority", {}).get(
                    "manifest_digest"
                ),
            )
            if (
                replay_admission is not None
                and replay_admission.payload.get("batch_id") != batch_id
            ):
                raise TransitionError(
                    "Batch differs from the replay implementation admission"
                )
            batch_head = index.event_head(f"study-batches:{study_id}")
            prior_batch_count = 0 if batch_head is None else batch_head.sequence
            commitment_batches = study_record.payload.get("commitment_batches")
            if not self.engineering_fixture and (
                type(commitment_batches) is not int
                or commitment_batches <= 0
            ):
                raise TransitionError(
                    "scientific Study requires a positive finite Batch bound"
                )
            if not self.engineering_fixture:
                assert type(commitment_batches) is int
                if prior_batch_count >= commitment_batches:
                    raise TransitionError(
                        "scientific Study Batch commitment is exhausted"
                    )
                if prior_batch_count == 0:
                    if body.get("next_action") != {
                        "kind": "freeze_batch",
                        "study_id": study_id,
                    }:
                        raise TransitionError(
                            "first Batch is not the exact frozen Study action"
                        )
                else:
                    continuation_head = index.event_head(
                        f"study-continuation:{study_id}"
                    )
                    continuation = (
                        None
                        if continuation_head is None
                        else index.get(
                            continuation_head.record_kind,
                            continuation_head.record_id,
                        )
                    )
                    expected_action = {
                        "batch_id": batch_id,
                        "continuation_decision_id": (
                            None
                            if continuation is None
                            else continuation.record_id
                        ),
                        "kind": "freeze_batch",
                        "study_id": study_id,
                    }
                    if (
                        continuation_head is None
                        or continuation_head.sequence != prior_batch_count
                        or continuation is None
                        or continuation.kind
                        != "study-continuation-decision"
                        or continuation.status != "continue"
                        or continuation.payload.get("study_id") != study_id
                        or continuation.payload.get("prior_batch_id")
                        != batch_head.record_id
                        or continuation.payload.get("next_batch_id")
                        != batch_id
                        or body.get("next_action") != expected_action
                    ):
                        raise TransitionError(
                            "later Batch lacks its exact continuation decision"
                        )
            self._validate_permit_locked(
                control=current,
                index=index,
                permit=permit,
                expected_kind=PermitKind.BATCH,
                action="open_batch",
                subject_kind=SubjectKind.STUDY,
                subject_id=study_id,
                expected_input_hash=batch_hash,
            )
            used_source_permits: set[str] = set()
            for source_id in batch_spec.source_contract_ids:
                matches = [
                    candidate
                    for candidate in source_permits
                    if f"source:{source_id}" in candidate.scope
                ]
                if len(matches) != 1:
                    raise PermitError(
                        "each external source requires one exact SourcePermit"
                    )
                source_permit = matches[0]
                self._validate_permit_locked(
                    control=current,
                    index=index,
                    permit=source_permit,
                    expected_kind=PermitKind.SOURCE,
                    action="performance_batch",
                    subject_kind=SubjectKind.STUDY,
                    subject_id=study_id,
                    expected_input_hash=batch_hash,
                    required_scope=(f"source:{source_id}",),
                )
                self._require_source_authority_for_actions(
                    index,
                    source_id,
                    actions=("performance_batch",),
                    error_type=PermitError,
                )
                used_source_permits.add(source_permit.permit_id)
            if used_source_permits != {item.permit_id for item in source_permits}:
                raise PermitError("Batch received an unrelated SourcePermit")
            science["active_batch"] = {"id": batch_id, "hash": batch_hash, "status": "open"}
            body["next_action"] = {"kind": "declare_job", "batch_id": batch_id}
            consumption = self._permit_consumption_record(permit, operation_id)
            source_consumptions = [
                self._permit_consumption_record(item, operation_id)
                for item in source_permits
            ]
            record = _record(
                kind="batch-open",
                record_id=batch_id,
                subject=f"Study:{study_id}",
                status="open",
                fingerprint=batch_hash,
                payload={
                    "batch_hash": batch_hash,
                    "display_id": batch_spec.batch_id,
                    "display_name": batch_spec.display_name,
                    "spec": batch_spec.to_identity_payload(),
                    "source_permit_ids": sorted(used_source_permits),
                },
                event_stream=f"study-batches:{study_id}",
                event_sequence=prior_batch_count + 1,
            )
            return body, [consumption, *source_consumptions, record], {"batch_id": batch_id}

        return self._commit(
            event_kind="batch_opened",
            operation_id=operation_id,
            subject=f"Batch:{batch_id}",
            payload={
                "batch_id": batch_id,
                "batch_hash": batch_hash,
                "source_permit_ids": sorted(item.permit_id for item in source_permits),
            },
            prepare=prepare,
        )

    def _batch_budget_reservation_repair_plan_locked(
        self,
        current: Mapping[str, Any],
        index: LocalIndex | LocalIndexView,
        *,
        corrected_job_budgets: Mapping[str, Mapping[str, int]],
        policy_id: str,
        reason: str,
    ) -> dict[str, object]:
        body = self._body(dict(current))
        science = body["scientific"]
        batch = science.get("active_batch")
        if (
            not isinstance(batch, dict)
            or science.get("active_job") is not None
            or science.get("active_repair") is not None
            or body.get("next_action")
            != {"kind": "declare_job", "batch_id": batch.get("id")}
        ):
            raise TransitionError(
                "Batch budget repair requires a stable between-Job boundary"
            )
        batch_id = batch.get("id")
        if type(batch_id) is not str:
            raise TransitionError("Batch budget repair lacks its active Batch")
        batch_record = index.get("batch-open", batch_id)
        budget_head = index.event_head(f"batch-budget:{batch_id}")
        if (
            batch_record is None
            or budget_head is None
            or budget_head.record_kind != "batch-budget-reservation"
        ):
            raise TransitionError(
                "Batch budget repair requires unrepaired reservations"
            )
        budget_record = index.get(
            budget_head.record_kind,
            budget_head.record_id,
        )
        if budget_record is None:
            raise TransitionError("Batch budget reservation head is absent")
        job_inventory = _batch_job_decision_inventory(
            index,
            batch_id=batch_id,
        )
        declarations = job_inventory.declarations
        if not declarations:
            raise TransitionError("Batch budget repair has no completed Jobs")
        decisions = {
            record.subject.removeprefix("Job:")
            for record in job_inventory.decisions
            if record.status in {"continue_batch", "stop_batch"}
        }
        job_ids = {record.record_id for record in declarations}
        if not job_ids.issubset(decisions):
            raise TransitionError(
                "Batch budget repair cannot rebase unfinished Job reservations"
            )
        declared_job_budgets: dict[str, dict[str, int]] = {}
        implementation_identities: dict[str, str] = {}
        declaration_specs: dict[str, Mapping[str, Any]] = {}
        for declaration in declarations:
            spec = declaration.payload.get("spec")
            budget = None if not isinstance(spec, Mapping) else spec.get("budget")
            implementation = (
                None
                if not isinstance(spec, Mapping)
                else spec.get("implementation_identity")
            )
            if not isinstance(budget, Mapping) or type(implementation) is not str:
                raise TransitionError(
                    "Batch budget repair Job declaration is malformed"
                )
            declared_job_budgets[declaration.record_id] = {
                "compute_seconds": budget.get("compute_seconds"),
                "wall_seconds": budget.get("wall_seconds"),
            }
            implementation_identities[declaration.record_id] = implementation
            assert isinstance(spec, Mapping)
            declaration_specs[declaration.record_id] = spec
        frozen_spec = batch_record.payload.get("spec")
        if not isinstance(frozen_spec, Mapping):
            raise TransitionError("Batch budget repair lacks the frozen ceiling")
        if not self.engineering_fixture:
            acceptance = frozen_spec.get("acceptance_profile")
            concurrent = (
                None
                if not isinstance(acceptance, Mapping)
                else acceptance.get("concurrent_family")
            )
            family_ids = (
                None
                if not isinstance(concurrent, Mapping)
                else concurrent.get("executable_ids")
            )
            subjects = {
                spec.get("evidence_subject", {}).get("id")
                for spec in declaration_specs.values()
                if isinstance(spec.get("evidence_subject"), Mapping)
            }
            callable_identities = {
                spec.get("callable_identity")
                for spec in declaration_specs.values()
            }
            if (
                policy_id != FIXED_HOLD_REPLAY_BUDGET_POLICY_ID
                or reason != FIXED_HOLD_REPLAY_BUDGET_REPAIR_REASON
                or not isinstance(acceptance, Mapping)
                or acceptance.get("candidate_authority") != "none"
                or not isinstance(acceptance.get("exact_original_criteria"), list)
                or not acceptance.get("exact_original_criteria")
                or type(acceptance.get("replay_obligation_id")) is not str
                or not isinstance(concurrent, Mapping)
                or concurrent.get("evaluation_mode") != "vectorized"
                or concurrent.get("family_size") != frozen_spec.get("max_trials")
                or not isinstance(family_ids, list)
                or len(family_ids) != frozen_spec.get("max_trials")
                or not subjects
                or not subjects.issubset(set(family_ids))
                or len(callable_identities) != 1
                or len(set(implementation_identities.values())) != 1
                or frozen_spec.get("stop_rule")
                != "stop only after the exact registered family"
            ):
                raise TransitionError(
                    "Batch budget repair is outside the registered replay policy"
                )
            cache_producer_count = 0
            registered_budgets: dict[str, dict[str, int]] = {}
            try:
                for job_id, spec in declaration_specs.items():
                    output_classes = spec.get("output_classes")
                    if not isinstance(output_classes, Mapping):
                        raise ValueError(
                            "Batch budget repair output classes are invalid"
                        )
                    cache_producer_count += tuple(output_classes.values()).count(
                        "reproducible_cache"
                    )
                    registered_budgets[job_id] = (
                        registered_batch_budget_for_output_classes(
                            policy_id=policy_id,
                            output_classes=output_classes,
                        )
                    )
            except ValueError as exc:
                raise TransitionError(str(exc)) from exc
            normalized_corrected = {
                job_id: dict(budget)
                for job_id, budget in corrected_job_budgets.items()
            }
            if (
                cache_producer_count != 1
                or normalized_corrected != registered_budgets
            ):
                raise TransitionError(
                    "Batch budget repair differs from the registered policy"
                )
        try:
            manifest = batch_budget_reservation_repair_manifest(
                batch_id=batch_id,
                frozen_budget_ceiling={
                    "compute_seconds": frozen_spec.get("max_compute_seconds"),
                    "wall_seconds": frozen_spec.get("max_wall_seconds"),
                },
                declared_job_budgets=declared_job_budgets,
                corrected_job_budgets=corrected_job_budgets,
                job_implementation_identities=implementation_identities,
                policy_id=policy_id,
                reason=reason,
            )
        except ValueError as exc:
            raise TransitionError(str(exc)) from exc
        prior = manifest["prior_reserved_totals"]
        if (
            not isinstance(prior, Mapping)
            or budget_record.payload.get("compute_seconds")
            != prior.get("compute_seconds")
            or budget_record.payload.get("wall_seconds")
            != prior.get("wall_seconds")
        ):
            raise TransitionError(
                "Batch budget repair differs from the reservation head"
            )
        return manifest

    def plan_batch_budget_reservation_repair(
        self,
        *,
        corrected_job_budgets: Mapping[str, Mapping[str, int]],
        policy_id: str,
        reason: str,
    ) -> dict[str, object]:
        """Build a read-only, reduction-only Batch reservation repair."""

        _require_ascii("Batch budget repair policy", policy_id)
        _require_ascii("Batch budget repair reason", reason)
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                current = self._require_stable_locked(index)
                if not isinstance(current, Mapping):
                    raise TransitionError("Batch budget repair requires control")
                return self._batch_budget_reservation_repair_plan_locked(
                    current,
                    index,
                    corrected_job_budgets=corrected_job_budgets,
                    policy_id=policy_id,
                    reason=reason,
                )

    def repair_batch_budget_reservations(
        self,
        *,
        corrected_job_budgets: Mapping[str, Mapping[str, int]],
        policy_id: str,
        reason: str,
        proof_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Release proven over-reservations without changing frozen science."""

        _require_ascii("Batch budget repair policy", policy_id)
        _require_ascii("Batch budget repair reason", reason)
        _require_digest("Batch budget repair proof", proof_hash)
        try:
            proof = parse_canonical(self.evidence.read_verified(proof_hash))
        except ValueError as exc:
            raise TransitionError("Batch budget repair proof is invalid") from exc
        if not isinstance(proof, Mapping):
            raise TransitionError("Batch budget repair proof is not an object")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("Batch budget repair requires control")
            expected = self._batch_budget_reservation_repair_plan_locked(
                current,
                index,
                corrected_job_budgets=corrected_job_budgets,
                policy_id=policy_id,
                reason=reason,
            )
            if dict(proof) != expected:
                raise TransitionError(
                    "Batch budget repair proof differs from durable state"
                )
            batch_id = str(expected["batch_id"])
            budget_head = index.event_head(f"batch-budget:{batch_id}")
            if budget_head is None:
                raise TransitionError("Batch budget repair head disappeared")
            totals = expected["corrected_reserved_totals"]
            assert isinstance(totals, Mapping)
            record = _record(
                kind="batch-budget-repair",
                record_id=canonical_digest(
                    domain="batch-budget-repair",
                    payload={
                        "batch_id": batch_id,
                        "policy_id": policy_id,
                        "proof_hash": proof_hash,
                    },
                ),
                subject=f"Batch:{batch_id}",
                status="repaired",
                fingerprint=proof_hash,
                payload={
                    "compute_seconds": totals["compute_seconds"],
                    "proof_hash": proof_hash,
                    "repair": expected,
                    "wall_seconds": totals["wall_seconds"],
                },
                event_stream=f"batch-budget:{batch_id}",
                event_sequence=budget_head.sequence + 1,
            )
            return self._body(current), [record], {
                "batch_id": batch_id,
                "completed_job_count": expected["completed_job_count"],
                "corrected_reserved_totals": dict(totals),
                "proof_hash": proof_hash,
                "scientific_trial_delta": 0,
            }

        return self._commit(
            event_kind="batch_budget_repaired",
            operation_id=operation_id,
            subject="Batch:active",
            payload={
                "corrected_job_budgets": {
                    job_id: dict(budget)
                    for job_id, budget in sorted(corrected_job_budgets.items())
                },
                "policy_id": policy_id,
                "proof_hash": proof_hash,
                "reason": reason,
            },
            prepare=prepare,
        )

    @staticmethod
    def _batch_continuation_bindings(
        index: LocalIndex,
        batch_id: str,
    ) -> dict[str, Any]:
        """Re-derive the closed Batch member, completion, and evidence set."""

        batch = index.get("batch-open", batch_id)
        spec = None if batch is None else batch.payload.get("spec")
        if batch is None or not isinstance(spec, Mapping):
            raise TransitionError("Study continuation lost its frozen Batch")
        trial_head = index.event_head(f"batch-trials:{batch_id}")
        trial_records: list[IndexRecord] = []
        if trial_head is not None:
            for sequence in range(1, trial_head.sequence + 1):
                trial = index.event_record(
                    f"batch-trials:{batch_id}", sequence
                )
                if (
                    trial is None
                    or trial.kind != "trial"
                    or trial.subject != f"Batch:{batch_id}"
                    or trial.event_sequence != sequence
                ):
                    raise TransitionError(
                        "Study continuation Batch member projection is invalid"
                    )
                trial_records.append(trial)
        registered_members = tuple(
            sorted(record.record_id for record in trial_records)
        )
        if len(set(registered_members)) != len(registered_members):
            raise TransitionError(
                "Study continuation Batch member set is not unique"
            )
        acceptance = spec.get("acceptance_profile")
        concurrent = (
            None
            if not isinstance(acceptance, Mapping)
            else acceptance.get("concurrent_family")
        )
        frozen_members = (
            None
            if not isinstance(concurrent, Mapping)
            else concurrent.get("executable_ids")
        )
        if frozen_members is not None and (
            not isinstance(frozen_members, list)
            or any(type(member) is not str for member in frozen_members)
            or len(set(frozen_members)) != len(frozen_members)
            or set(frozen_members) != set(registered_members)
        ):
            raise TransitionError(
                "Study continuation differs from the frozen concurrent family"
            )

        from axiom_rift.operations.scientific_history import (
            ScientificHistoryProjectionError,
            project_batch_job_evidence,
        )

        try:
            job_evidence = project_batch_job_evidence(
                index,
                batch_id=batch_id,
            )
        except ScientificHistoryProjectionError as exc:
            raise TransitionError(str(exc)) from exc
        declarations = job_evidence.declarations
        member_job_ids = tuple(record.record_id for record in declarations)
        declaration_members: set[str] = set()
        completion_ids: list[str] = []
        durable_evidence_hashes: set[str] = set()
        decision_statuses: list[str] = []
        for declaration, completion, evidence_decision in zip(
            declarations,
            job_evidence.completions,
            job_evidence.decisions,
            strict=True,
        ):
            declaration_spec = declaration.payload.get("spec")
            evidence_subject = (
                None
                if not isinstance(declaration_spec, Mapping)
                else declaration_spec.get("evidence_subject")
            )
            if (
                not isinstance(evidence_subject, Mapping)
                or evidence_subject.get("kind") != "Executable"
                or type(evidence_subject.get("id")) is not str
            ):
                raise TransitionError(
                    "Study continuation Job is not bound to a Batch member"
                )
            declaration_members.add(evidence_subject["id"])
            decision_statuses.append(evidence_decision.status)
            completion_id = completion.record_id
            if (
                completion.subject != f"Job:{declaration.record_id}"
                or completion.payload.get("job_id") != declaration.record_id
                or completion.fingerprint != declaration.fingerprint
            ):
                raise TransitionError(
                    "Study continuation Job completion binding is invalid"
                )
            completion_ids.append(completion_id)
            outputs = completion.payload.get("outputs")
            output_classes = completion.payload.get("output_classes")
            if not isinstance(outputs, Mapping) or not isinstance(
                output_classes, Mapping
            ):
                raise TransitionError(
                    "Study continuation completion outputs are malformed"
                )
            for output_name, output_hash in outputs.items():
                if output_classes.get(output_name) != "durable_evidence":
                    continue
                _require_digest(
                    "Study continuation durable evidence", output_hash
                )
                durable_evidence_hashes.add(output_hash)
        if (
            len(declarations) != len(registered_members)
            or len(declaration_members) != len(declarations)
            or declaration_members != set(registered_members)
        ):
            raise TransitionError(
                "Study continuation requires exactly one completed Job per Batch member"
            )
        return {
            "completion_record_ids": tuple(sorted(completion_ids)),
            "evidence_hashes": tuple(sorted(durable_evidence_hashes)),
            "member_executable_ids": registered_members,
            "member_job_ids": member_job_ids,
            "stop_rule_state": (
                "unresolved"
                if not decision_statuses
                else (
                    "reached"
                    if "stop_batch" in decision_statuses
                    else "not_reached"
                )
            ),
        }

    def dispose_batch(
        self, *, outcome: str, operation_id: str
    ) -> TransitionResult:
        _require_ascii("outcome", outcome)
        allowed = set(_BATCH_OUTCOMES)
        if self.engineering_fixture:
            allowed.add(_ENGINEERING_FIXTURE_OUTCOME)
        if outcome not in allowed:
            raise TransitionError("Batch outcome is not typed")

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            batch = science["active_batch"]
            if not isinstance(batch, dict):
                raise TransitionError("no active Batch")
            if not self.engineering_fixture:
                next_action = body.get("next_action")
                exact_dispose = {
                    "kind": "dispose_batch",
                    "batch_id": batch["id"],
                }
                exact_unstarted = {
                    "kind": "declare_job",
                    "batch_id": batch["id"],
                }
                if next_action == exact_unstarted:
                    self._batch_unavailable_reason(
                        _index,
                        batch["id"],
                        outcome,
                    )
                elif (
                    isinstance(next_action, Mapping)
                    and next_action.get("kind") == "dispose_batch"
                    and next_action.get("batch_id") == batch["id"]
                    and set(next_action).issubset(
                        {"basis_record_id", "batch_id", "kind"}
                    )
                ):
                    disposition_basis = self._require_stop_batch_outcome(
                        _index,
                        batch["id"],
                        outcome,
                    )
                    basis_record_id = next_action.get("basis_record_id")
                    if (
                        basis_record_id is not None
                        and basis_record_id != disposition_basis
                    ):
                        raise TransitionError(
                            "Batch disposition differs from its exact preflight basis"
                        )
                else:
                    raise TransitionError(
                        "Batch disposition is not the exact next action"
                    )
            if science["active_job"] is not None or science["active_repair"] is not None:
                raise TransitionError("cannot dispose Batch with active Job or Repair")
            science["active_batch"] = None
            basis_record_id = (
                body.get("next_action", {}).get("basis_record_id")
                if isinstance(body.get("next_action"), Mapping)
                else None
            )
            close_payload = {"outcome": outcome}
            if isinstance(basis_record_id, str):
                close_payload["basis_record_id"] = basis_record_id
            fingerprint = _digest(
                {
                    "batch_id": batch["id"],
                    **close_payload,
                },
                domain="batch-close",
            )
            record = _record(
                kind="batch-close",
                record_id=fingerprint,
                subject=f"Batch:{batch['id']}",
                status=outcome,
                fingerprint=fingerprint,
                payload=close_payload,
            )
            study_id = science["active_study"]
            study = (
                None
                if not isinstance(study_id, str)
                else _index.get("study-open", study_id)
            )
            batch_head = (
                None
                if not isinstance(study_id, str)
                else _index.event_head(f"study-batches:{study_id}")
            )
            if not self.engineering_fixture:
                commitment = (
                    None
                    if study is None
                    else study.payload.get("commitment_batches")
                )
                if (
                    study is None
                    or batch_head is None
                    or batch_head.record_id != batch["id"]
                    or type(commitment) is not int
                    or commitment <= 0
                    or batch_head.sequence > commitment
                ):
                    raise TransitionError(
                        "Batch disposition lost its finite Study commitment"
                    )
                body["next_action"] = (
                    {
                        "batch_close_record_id": fingerprint,
                        "kind": "review_study_continuation",
                        "prior_batch_id": batch["id"],
                        "study_id": study_id,
                    }
                    if batch_head.sequence < commitment
                    else {"kind": "judge_study", "study_id": study_id}
                )
            else:
                body["next_action"] = {
                    "kind": "judge_study",
                    "study_id": study_id,
                }
            return body, [record], {"batch_id": batch["id"], "outcome": outcome}

        return self._commit(
            event_kind="batch_disposed",
            operation_id=operation_id,
            subject="Batch:active",
            payload={"outcome": outcome},
            prepare=prepare,
        )

    def review_study_continuation(
        self,
        *,
        decision: Any,
        operation_id: str,
    ) -> TransitionResult:
        """Close an intermediate boundary or pre-bind one exact next Batch."""

        from axiom_rift.research.study_continuation import (
            StudyContinuationDecision,
            StudyContinuationOutcome,
        )

        self._require_study_close_delivery_guard()
        if not isinstance(decision, StudyContinuationDecision):
            raise TransitionError(
                "decision must be a StudyContinuationDecision"
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            study_id = science.get("active_study")
            if (
                study_id != decision.study_id
                or science.get("active_batch") is not None
                or science.get("active_job") is not None
                or science.get("active_repair") is not None
            ):
                raise TransitionError(
                    "Study continuation requires its stable active Study"
                )
            expected_pending = {
                "batch_close_record_id": decision.prior_batch_close_record_id,
                "kind": "review_study_continuation",
                "prior_batch_id": decision.prior_batch_id,
                "study_id": study_id,
            }
            if body.get("next_action") != expected_pending:
                raise TransitionError(
                    "Study continuation is not the exact pending review"
                )
            study = index.get("study-open", study_id)
            batch = index.get("batch-open", decision.prior_batch_id)
            close = index.get(
                "batch-close", decision.prior_batch_close_record_id
            )
            batch_head = index.event_head(f"study-batches:{study_id}")
            commitment = (
                None
                if study is None
                else study.payload.get("commitment_batches")
            )
            if (
                study is None
                or study.fingerprint != decision.study_hash
                or study.payload.get("question_hash") != decision.question_hash
                or study.payload.get("controlled_chassis_identity")
                != decision.controlled_chassis_identity
                or study.payload.get("portfolio_snapshot_id")
                != decision.portfolio_snapshot_id
                or study.payload.get("portfolio_axis_id")
                != decision.portfolio_axis_id
                or study.payload.get("portfolio_axis_identity")
                != decision.portfolio_axis_identity
                or study.payload.get("portfolio_decision_id")
                != decision.portfolio_decision_id
                or batch is None
                or batch.fingerprint
                != decision.prior_batch_id.removeprefix("batch:")
                or batch.payload.get("spec", {}).get("study_hash")
                != decision.study_hash
                or batch.payload.get("spec", {}).get("stop_rule")
                != decision.stop_rule
                or close is None
                or close.subject != f"Batch:{decision.prior_batch_id}"
                or batch_head is None
                or batch_head.record_id != decision.prior_batch_id
                or type(commitment) is not int
                or commitment <= 1
                or batch_head.sequence >= commitment
            ):
                raise TransitionError(
                    "Study continuation lost its immutable Study or Batch binding"
                )
            portfolio_head = index.event_head(
                f"portfolio:{science['active_mission']}"
            )
            snapshot = index.get(
                "portfolio-snapshot", decision.portfolio_snapshot_id
            )
            if (
                portfolio_head is None
                or portfolio_head.record_id != decision.portfolio_snapshot_id
                or snapshot is None
                or snapshot.subject != f"Mission:{science['active_mission']}"
            ):
                raise TransitionError(
                    "Study continuation Portfolio snapshot is stale"
                )
            axes = tuple(
                axis
                for axis in snapshot.payload.get("axes", ())
                if isinstance(axis, Mapping)
            )
            active_axis = next(
                (
                    axis
                    for axis in axes
                    if axis.get("axis_id") == decision.portfolio_axis_id
                ),
                None,
            )
            axis_resolutions = self._effective_axis_resolutions(
                index,
                axes,
            )
            other_axis_ids = tuple(
                sorted(
                    axis["axis_id"]
                    for axis, resolution in zip(
                        axes,
                        axis_resolutions,
                        strict=True,
                    )
                    if axis.get("axis_id") != decision.portfolio_axis_id
                    and type(axis.get("axis_id")) is str
                    and resolution.decision_option_eligible
                )
            )
            if (
                active_axis is None
                or active_axis.get("axis_identity")
                != decision.portfolio_axis_identity
                or other_axis_ids != decision.other_axis_ids
            ):
                raise TransitionError(
                    "Study continuation differs from the current Portfolio forest"
                )
            bindings = self._batch_continuation_bindings(
                index, decision.prior_batch_id
            )
            if any(
                getattr(decision, name) != bindings[name]
                for name in (
                    "completion_record_ids",
                    "evidence_hashes",
                    "member_executable_ids",
                    "member_job_ids",
                )
            ):
                raise TransitionError(
                    "Study continuation differs from exact Batch evidence"
                )
            if decision.stop_rule_state.value != bindings["stop_rule_state"]:
                raise TransitionError(
                    "Study continuation stop-rule state differs from exact Job judgements"
                )
            for evidence_hash in decision.evidence_hashes:
                try:
                    self.evidence.verify(evidence_hash)
                except (FileNotFoundError, RuntimeError, ValueError) as exc:
                    raise TransitionError(
                        "Study continuation durable evidence is unavailable"
                    ) from exc
            review_basis = {
                (basis.kind, basis.record_id)
                for assessment in decision.quant_team_review.assessments
                for basis in assessment.basis_records
            }
            required_basis = {
                ("portfolio-snapshot", decision.portfolio_snapshot_id),
                (
                    "batch-close",
                    decision.prior_batch_close_record_id,
                ),
                *(
                    ("job-completed", completion_id)
                    for completion_id in decision.completion_record_ids
                ),
            }
            if (
                any(
                    index.get(kind, record_id) is None
                    for kind, record_id in review_basis
                )
                or not required_basis.issubset(review_basis)
            ):
                raise TransitionError(
                    "Study continuation review omits exact durable bases"
                )
            continuation_head = index.event_head(
                f"study-continuation:{study_id}"
            )
            if (
                (continuation_head is None and batch_head.sequence != 1)
                or (
                    continuation_head is not None
                    and continuation_head.sequence != batch_head.sequence - 1
                )
            ):
                raise TransitionError(
                    "Study continuation decision sequence is invalid"
                )
            if decision.outcome is StudyContinuationOutcome.CONTINUE:
                assert decision.next_batch_id is not None
                body["next_action"] = {
                    "batch_id": decision.next_batch_id,
                    "continuation_decision_id": decision.identity,
                    "kind": "freeze_batch",
                    "study_id": study_id,
                }
            else:
                body["next_action"] = {
                    "kind": "judge_study",
                    "study_id": study_id,
                }
            record = _record(
                kind="study-continuation-decision",
                record_id=decision.identity,
                subject=f"Study:{study_id}",
                status=decision.outcome.value,
                fingerprint=decision.identity.removeprefix(
                    "study-continuation-decision:"
                ),
                payload=decision.to_identity_payload(),
                event_stream=f"study-continuation:{study_id}",
                event_sequence=batch_head.sequence,
            )
            return body, [record], {
                "continuation_decision_id": decision.identity,
                "next_batch_id": decision.next_batch_id,
                "outcome": decision.outcome.value,
            }

        return self._commit(
            event_kind="study_continuation_reviewed",
            operation_id=operation_id,
            subject=f"Study:{decision.study_id}",
            payload={
                "decision_id": decision.identity,
                "outcome": decision.outcome.value,
            },
            prepare=prepare,
        )

    @staticmethod
    def _contains_study_kpi_metric(
        value: Mapping[str, Any],
        name: str,
    ) -> bool:
        return any(
            key == name
            or (
                isinstance(item, Mapping)
                and StateWriter._contains_study_kpi_metric(item, name)
            )
            for key, item in value.items()
        )

    @staticmethod
    def _collect_study_kpi_metric(
        measurements: Sequence[Mapping[str, Any]],
        name: str,
    ) -> int | None:
        observed: list[int | None] = []

        def visit(value: Mapping[str, Any]) -> None:
            for key, item in value.items():
                if key == name:
                    if item is not None and (
                        isinstance(item, bool) or not isinstance(item, int)
                    ):
                        raise TransitionError(
                            f"Study KPI metric {name} is not an integer or null"
                        )
                    observed.append(item)
                elif isinstance(item, Mapping):
                    visit(item)

        for measurement in measurements:
            metrics = measurement.get("metrics")
            if isinstance(metrics, Mapping):
                visit(metrics)
        values = set(observed)
        if not values:
            return None
        if len(values) != 1:
            raise TransitionError(f"Study KPI metric {name} is ambiguous")
        return values.pop()

    def _study_kpi_from_completion(
        self,
        *,
        index: LocalIndex,
        study_id: str,
        completion_record_id: str,
        require_stop_decision: bool = True,
    ) -> dict[str, Any]:
        _require_digest("Study KPI completion record", completion_record_id)
        completion = index.get("job-completed", completion_record_id)
        if completion is None:
            raise TransitionError("Study KPI completion record is unavailable")
        job_id = completion.payload.get("job_id")
        if type(job_id) is not str:
            raise TransitionError("Study KPI completion has no Job identity")
        declaration = index.get("job-declared", job_id)
        if (
            declaration is None
            or declaration.payload.get("study_id") != study_id
        ):
            raise TransitionError("Study KPI completion belongs to another Study")
        batch_head = index.event_head(f"study-batches:{study_id}")
        if (
            batch_head is None
            or declaration.payload.get("batch_id") != batch_head.record_id
        ):
            raise TransitionError(
                "Study KPI completion does not belong to the final Study Batch"
            )
        decisions = tuple(
            record
            for record in index.records_by_fingerprint(completion.fingerprint)
            if record.kind == "job-evidence-decision"
            and record.payload.get("completion_record_id") == completion_record_id
        )
        if require_stop_decision and (
            len(decisions) != 1
            or decisions[0].subject != f"Job:{job_id}"
            or decisions[0].status != "stop_batch"
        ):
            raise TransitionError(
                "Study KPI completion is not the disposition-driving stop_batch evidence"
            )
        scientific = completion.payload.get("scientific")
        if (
            not isinstance(scientific, Mapping)
            or scientific.get("scientific_eligible") is not True
        ):
            engineering = completion.payload.get("engineering_disposition")
            failure = completion.payload.get("failure")
            if isinstance(engineering, Mapping):
                if (
                    completion.status != "failed"
                    or not isinstance(failure, Mapping)
                    or failure.get("failure_kind") != "engineering"
                    or engineering.get("schema")
                    != "engineering_failure_disposition.v1"
                    or engineering.get("job_id") != job_id
                ):
                    raise TransitionError(
                        "Study KPI engineering completion is malformed"
                    )
                spec = declaration.payload.get("spec")
                subject = (
                    None
                    if not isinstance(spec, Mapping)
                    else spec.get("evidence_subject")
                )
                executable_id = (
                    subject.get("id")
                    if isinstance(subject, Mapping)
                    and subject.get("kind") == "Executable"
                    and type(subject.get("id")) is str
                    else None
                )
                return {
                    "completion_record_id": completion_record_id,
                    "executable_id": executable_id,
                    "metrics": {
                        name: None for name in _STUDY_KPI_METRICS
                    },
                    "source": "typed_engineering_failure_completion",
                    "unavailable_reason": "engineering_failure",
                }
            nonperformance = tuple(
                (domain, evidence)
                for domain, evidence in (
                    ("source", completion.payload.get("source")),
                    ("external", completion.payload.get("external")),
                )
                if isinstance(evidence, Mapping)
            )
            if len(nonperformance) != 1:
                raise TransitionError(
                    "Study KPI completion is not validator-derived evidence"
                )
            domain, evidence = nonperformance[0]
            if (
                type(evidence.get("validator_id")) is not str
                or not isinstance(evidence.get("validation_trace"), Mapping)
                or type(evidence.get("result_manifest_hash")) is not str
            ):
                raise TransitionError(
                    "Study KPI non-performance completion lacks validator provenance"
                )
            _require_digest(
                "Study KPI non-performance result",
                evidence["result_manifest_hash"],
            )
            spec = declaration.payload.get("spec")
            subject = None if not isinstance(spec, Mapping) else spec.get(
                "evidence_subject"
            )
            executable_id = (
                subject.get("id")
                if isinstance(subject, Mapping)
                and subject.get("kind") == "Executable"
                and type(subject.get("id")) is str
                else None
            )
            return {
                "completion_record_id": completion_record_id,
                "executable_id": executable_id,
                "metrics": {name: None for name in _STUDY_KPI_METRICS},
                "source": f"validator_derived_{domain}_completion",
                "unavailable_reason": "non_performance_study",
            }
        executable_id = scientific.get("executable_id")
        if type(executable_id) is not str:
            raise TransitionError("Study KPI completion has no Executable identity")
        measurement_hashes = scientific.get("measurement_artifact_hashes")
        if (
            not isinstance(measurement_hashes, list)
            or not measurement_hashes
            or len(set(measurement_hashes)) != len(measurement_hashes)
        ):
            raise TransitionError("Study KPI completion has invalid measurements")
        measurements: list[Mapping[str, Any]] = []
        for measurement_hash in measurement_hashes:
            _require_digest("Study KPI measurement artifact", measurement_hash)
            try:
                measurement = parse_canonical(
                    self.evidence.read_verified(measurement_hash)
                )
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise TransitionError(
                    "Study KPI measurement artifact is unavailable or invalid"
                ) from exc
            if not isinstance(measurement, Mapping):
                raise TransitionError(
                    "Study KPI measurement belongs to another Job or Executable"
                )
            metric_payload = measurement.get("metrics")
            has_kpi = isinstance(metric_payload, Mapping) and any(
                self._contains_study_kpi_metric(metric_payload, name)
                for name in _STUDY_KPI_METRICS
            )
            binding_mismatch = any(
                field in measurement and measurement.get(field) != expected
                for field, expected in (
                    ("executable_id", executable_id),
                    ("job_id", job_id),
                    ("job_hash", declaration.fingerprint),
                )
            )
            binding_absent_for_kpi = has_kpi and any(
                measurement.get(field) != expected
                for field, expected in (
                    ("executable_id", executable_id),
                    ("job_id", job_id),
                    ("job_hash", declaration.fingerprint),
                )
            )
            if binding_mismatch or binding_absent_for_kpi:
                raise TransitionError(
                    "Study KPI measurement belongs to another Job or Executable"
                )
            measurements.append(measurement)
        metrics = {
            name: self._collect_study_kpi_metric(measurements, name)
            for name in _STUDY_KPI_METRICS
        }
        return {
            "completion_record_id": completion_record_id,
            "executable_id": executable_id,
            "metrics": metrics,
            "source": "scientific_job_completion",
            "unavailable_reason": None,
        }

    @staticmethod
    def _study_kpi_display_id(
        index: LocalIndex,
        executable_id: str | None,
        reserved_display_owners: Mapping[str, str] | None = None,
    ) -> str | None:
        if executable_id is None:
            return None
        _require_ascii("Study KPI Executable identity", executable_id)
        reserved = dict(reserved_display_owners or {})
        if any(
            type(display) is not str
            or not display
            or not display.isascii()
            or type(identity) is not str
            or not identity
            or not identity.isascii()
            for display, identity in reserved.items()
        ):
            raise TransitionError("Reserved Study KPI display binding is invalid")

        def stored_display_owners(display_id: str) -> set[str]:
            owners: set[str] = set()
            for record in index.records_by_payload_text(
                "study-kpi",
                "study_kpi_executable_display_id",
                display_id,
            ):
                prior_identity = record.payload.get("executable_id")
                prior_display = record.payload.get("executable_display_id")
                if (
                    type(prior_identity) is not str
                    or prior_display != display_id
                ):
                    raise TransitionError(
                        "Existing Study KPI display binding is invalid"
                    )
                owners.add(prior_identity)
            if len(owners) > 1:
                raise TransitionError(
                    "Existing Study KPI display id is not unique"
                )
            return owners

        existing_for_identity: set[str] = set()
        for record in index.records_by_payload_text(
            "study-kpi",
            "study_kpi_executable_id",
            executable_id,
        ):
            prior_identity = record.payload.get("executable_id")
            prior_display = record.payload.get("executable_display_id")
            if prior_identity != executable_id or type(prior_display) is not str:
                raise TransitionError(
                    "Existing Study KPI display binding is invalid"
                )
            existing_for_identity.add(prior_display)
        existing_for_identity.update(
            display
            for display, identity in reserved.items()
            if identity == executable_id
        )
        if len(existing_for_identity) > 1:
            raise TransitionError("Executable has inconsistent Study KPI display ids")
        if existing_for_identity:
            display = next(iter(existing_for_identity))
            stored_owners = stored_display_owners(display)
            reserved_owner = reserved.get(display)
            if (
                (stored_owners and stored_owners != {executable_id})
                or (
                    reserved_owner is not None
                    and reserved_owner != executable_id
                )
            ):
                raise TransitionError(
                    "Existing Study KPI display id is not unique"
                )
            return display
        digest = executable_id.removeprefix("executable:")
        for length in range(12, 65, 4):
            display = f"EXE-{digest[:length]}"
            owners = stored_display_owners(display)
            reserved_owner = reserved.get(display)
            if not owners and reserved_owner is None:
                return display
            if len(owners | ({reserved_owner} if reserved_owner else set())) > 1:
                raise TransitionError(
                    "Existing Study KPI display id is not unique"
                )
        raise TransitionError("Executable has no unique Study KPI display id")

    @staticmethod
    def _batch_stop_completion_ids(
        index: LocalIndex,
        batch_id: str,
        inventory: _BatchJobDecisionInventory | None = None,
    ) -> tuple[str, ...]:
        resolved_inventory = (
            inventory
            if inventory is not None
            else _batch_job_decision_inventory(index, batch_id=batch_id)
        )
        if resolved_inventory.batch_id != batch_id:
            raise TransitionError("Batch evidence inventory belongs to another Batch")
        completion_ids: set[str] = set()
        for decision in resolved_inventory.decisions:
            if decision.status != "stop_batch":
                continue
            completion_id = decision.payload.get("completion_record_id")
            if type(completion_id) is not str:
                raise TransitionError(
                    "Batch stop decision lacks its completion identity"
                )
            completion_ids.add(completion_id)
        return tuple(sorted(completion_ids))

    @staticmethod
    def _batch_rejected_replay_preflights(
        index: LocalIndex,
        batch_id: str,
    ) -> tuple[IndexRecord, ...]:
        """Return exact Writer-derived pre-Job implementation rejections."""

        candidates = tuple(
            record
            for record in index.records_by_subject_status(
                f"Batch:{batch_id}",
                "rejected",
            )
            if record.kind == "job-implementation-preflight"
        )
        if len(candidates) > 1:
            raise TransitionError(
                "Batch has ambiguous replay implementation preflight rejection"
            )
        if not candidates:
            return ()
        record = candidates[0]
        payload = record.payload
        batch = index.get("batch-open", batch_id)
        study_id = payload.get("study_id")
        study = (
            None
            if not isinstance(study_id, str)
            else index.get("study-open", study_id)
        )
        family_ids = (
            None
            if batch is None
            else _concurrent_family_executable_ids(batch)
        )
        stream_head = (
            None
            if not isinstance(record.event_stream, str)
            else index.event_head(record.event_stream)
        )
        from axiom_rift.operations.replay_job_implementation_preflight import (
            REPLACEMENT_REQUIRED,
            ReplayJobImplementationPreflightError,
            replay_job_scientific_surface_hash,
        )

        try:
            surface = payload.get("scientific_surface")
            surface_hash = (
                replay_job_scientific_surface_hash(surface)
                if isinstance(surface, Mapping)
                else None
            )
        except ReplayJobImplementationPreflightError as exc:
            raise TransitionError(
                "Batch replay implementation rejection surface is malformed"
            ) from exc
        fingerprint = _digest(
            payload,
            domain="replay-job-implementation-preflight",
        )
        failure_fingerprint = payload.get("failure_fingerprint")
        validation_plans = payload.get("validation_plan_hashes")
        executable_ids = payload.get("executable_ids")
        if (
            payload.get("schema")
            != "replay_job_implementation_preflight.v1"
            or payload.get("batch_id") != batch_id
            or payload.get("outcome") != "rejected"
            or payload.get("remediation_kind") != REPLACEMENT_REQUIRED
            or payload.get("replacement_for_preflight_id") is not None
            or payload.get("source_closure_authority") is not None
            or payload.get("reason_code")
            not in {
                "historical_replay_lineage_invalid",
                "implementation_manifest_invalid",
                "source_closure_invalid",
            }
            or type(payload.get("failure_detail")) is not str
            or not payload["failure_detail"]
            or not payload["failure_detail"].isascii()
            or type(failure_fingerprint) is not str
            or len(failure_fingerprint) != 64
            or any(
                character not in "0123456789abcdef"
                for character in failure_fingerprint
            )
            or payload.get("artifact_hashes") != []
            or payload.get("component_implementation_hashes") != []
            or study is None
            or study.payload.get("mission_id") != payload.get("mission_id")
            or study.payload.get("replay_obligation_ids")
            != payload.get("replay_obligation_ids")
            or not isinstance(family_ids, tuple)
            or not isinstance(executable_ids, list)
            or sorted(executable_ids) != sorted(family_ids)
            or not isinstance(validation_plans, list)
            or len(validation_plans) != len(executable_ids)
            or validation_plans != sorted(set(validation_plans))
            or surface_hash != payload.get("scientific_surface_hash")
            or record.fingerprint != fingerprint
            or record.record_id
            != f"job-implementation-preflight:{fingerprint}"
            or record.event_stream
            != f"replay-job-implementation-preflight-batch:{batch_id}"
            or record.event_sequence != 1
            or stream_head is None
            or stream_head.record_id != record.record_id
        ):
            raise TransitionError(
                "Batch replay implementation rejection is malformed"
            )
        return (record,)

    @classmethod
    def _require_stop_batch_outcome(
        cls,
        index: LocalIndex,
        batch_id: str,
        outcome: str,
        inventory: _BatchJobDecisionInventory | None = None,
    ) -> str:
        """Bind a final stop decision to the matching operational Batch outcome."""

        resolved_inventory = (
            inventory
            if inventory is not None
            else _batch_job_decision_inventory(index, batch_id=batch_id)
        )
        rejected_preflights = cls._batch_rejected_replay_preflights(
            index,
            batch_id,
        )
        completion_ids = cls._batch_stop_completion_ids(
            index,
            batch_id,
            resolved_inventory,
        )
        if rejected_preflights:
            if completion_ids or resolved_inventory.decisions:
                raise TransitionError(
                    "pre-Job implementation rejection conflicts with Batch Job evidence"
                )
            if outcome != "not_evaluable":
                raise TransitionError(
                    "pre-Job implementation rejection requires not_evaluable Batch outcome"
                )
            return rejected_preflights[0].record_id
        if len(completion_ids) != 1:
            raise TransitionError(
                "Batch disposition requires exactly one final stop_batch completion"
            )
        completion_id = completion_ids[0]
        completion = index.get("job-completed", completion_id)
        if completion is None:
            raise TransitionError("Batch stop completion is unavailable")
        engineering = completion.payload.get("engineering_disposition")
        failure = completion.payload.get("failure")
        typed_engineering = (
            completion.status == "failed"
            and isinstance(engineering, Mapping)
            and engineering.get("schema")
            == "engineering_failure_disposition.v1"
            and isinstance(failure, Mapping)
            and failure.get("failure_kind") == "engineering"
        )
        if typed_engineering and outcome != "engineering_failure":
            raise TransitionError(
                "Typed unrecovered engineering completion requires the "
                "engineering_failure Batch outcome"
            )
        if not typed_engineering and outcome == "engineering_failure":
            raise TransitionError(
                "Engineering-failure Batch outcome requires its typed unrecovered "
                "completion"
            )
        return completion_id

    @staticmethod
    def _batch_unavailable_reason(
        index: LocalIndex,
        batch_id: str,
        outcome: str,
        inventory: _BatchJobDecisionInventory | None = None,
        *,
        allow_legacy_started_failure: bool = False,
    ) -> str:
        if type(allow_legacy_started_failure) is not bool:
            raise TransitionError(
                "legacy started-Batch failure compatibility flag must be bool"
            )
        if inventory is not None and inventory.batch_id != batch_id:
            raise TransitionError("Batch evidence inventory belongs to another Batch")
        rejected_preflights = StateWriter._batch_rejected_replay_preflights(
            index,
            batch_id,
        )
        budget_head = index.event_head(f"batch-budget:{batch_id}")
        trial_head = index.event_head(f"batch-trials:{batch_id}")
        started = budget_head is not None or trial_head is not None
        if rejected_preflights:
            resolved_inventory = (
                inventory
                if inventory is not None
                else _batch_job_decision_inventory(index, batch_id=batch_id)
            )
            if (
                outcome != "not_evaluable"
                or resolved_inventory.decisions
                or StateWriter._batch_stop_completion_ids(
                    index,
                    batch_id,
                    resolved_inventory,
                )
            ):
                raise TransitionError(
                    "Batch implementation rejection has conflicting disposition evidence"
                )
            return (
                f"{'started' if started else 'unstarted'}_batch_"
                "implementation_authority_invalid_"
                "without_final_validator_completion"
            )
        if not started:
            if outcome not in {"not_evaluable", "stopped_early"}:
                raise TransitionError(
                    "Unstarted Batch requires a typed unavailable disposition"
                )
        elif outcome == "budget_exhausted":
            batch_record = index.get("batch-open", batch_id)
            budget_record = index.get(
                budget_head.record_kind,
                budget_head.record_id,
            ) if budget_head is not None else None
            spec = None if batch_record is None else batch_record.payload.get("spec")
            budget = None if budget_record is None else budget_record.payload
            trial_count = 0 if trial_head is None else trial_head.sequence
            if (
                not isinstance(spec, Mapping)
                or (
                    (
                        not isinstance(budget, Mapping)
                        or (
                            budget.get("compute_seconds")
                            != spec.get("max_compute_seconds")
                            and budget.get("wall_seconds")
                            != spec.get("max_wall_seconds")
                        )
                    )
                    and trial_count != spec.get("max_trials")
                )
            ):
                raise TransitionError("Batch budget is not exhausted")
        elif outcome in {
            "engineering_failure",
            "not_evaluable",
            "stopped_early",
        }:
            if not allow_legacy_started_failure:
                raise TransitionError(
                    "Started Batch without final validator evidence requires a "
                    "disposition-driving stop_batch completion; continue_batch "
                    "keeps Repair or bounded work open"
                )
            if outcome == "stopped_early":
                return (
                    "started_batch_stopped_early_"
                    "without_final_validator_completion"
                )
            resolved_inventory = (
                inventory
                if inventory is not None
                else _batch_job_decision_inventory(index, batch_id=batch_id)
            )
            decisions = [
                decision
                for decision in resolved_inventory.decisions
                if decision.status == "continue_batch"
            ]
            latest = (
                None
                if not decisions
                else max(
                    decisions,
                    key=lambda item: (
                        -1
                        if item.authority_sequence is None
                        else item.authority_sequence
                    ),
                )
            )
            completion_id = (
                None
                if latest is None
                else latest.payload.get("completion_record_id")
            )
            completion = (
                None
                if not isinstance(completion_id, str)
                else index.get("job-completed", completion_id)
            )
            failure = None if completion is None else completion.payload.get("failure")
            expected_status = "failed" if outcome == "engineering_failure" else "not_evaluable"
            expected_failure = "engineering" if outcome == "engineering_failure" else "not_evaluable"
            if (
                completion is None
                or completion.status != expected_status
                or not isinstance(failure, Mapping)
                or failure.get("failure_kind") != expected_failure
                or isinstance(completion.payload.get("scientific"), Mapping)
                or isinstance(completion.payload.get("source"), Mapping)
                or isinstance(completion.payload.get("external"), Mapping)
            ):
                raise TransitionError(
                    f"Batch {outcome} lacks its final non-scientific failure basis"
                )
        else:
            raise TransitionError(
                "Started Batch without a final stop completion requires a typed "
                "unavailable disposition"
            )
        return (
            f"{'started' if started else 'unstarted'}_batch_{outcome}_"
            "without_final_validator_completion"
        )

    @staticmethod
    def _legacy_started_batch_failure_allowed(
        *,
        index: LocalIndex,
        kpi_record: IndexRecord,
    ) -> bool:
        """Limit read compatibility to KPI sources predating typed Batch exit."""

        activation = index.get(
            "operation",
            _TYPED_STARTED_BATCH_EXIT_ACTIVATION_OPERATION_ID,
        )
        if activation is None:
            # Before the additive activation exists, old immutable KPI rows
            # must remain readable so the migration itself can recover safely.
            return True
        activation_sequence = activation.authority_sequence
        if (
            activation.kind != "operation"
            or activation.status != "success"
            or activation.payload.get("event_kind") != "authority_migrated"
            or type(activation_sequence) is not int
        ):
            raise TransitionError(
                "typed started-Batch exit activation boundary is invalid"
            )
        payload = kpi_record.payload
        provenance = payload.get("provenance")
        if provenance == "historical_backfill":
            source_sequence = payload.get("historical_study_close_revision")
        else:
            source_sequence = kpi_record.authority_sequence
            if type(source_sequence) is not int:
                event_id = kpi_record.authority_event_id
                event = (
                    None
                    if type(event_id) is not str
                    else index.get("journal-event", event_id)
                )
                source_sequence = (
                    None if event is None else event.authority_sequence
                )
        if type(source_sequence) is not int:
            raise TransitionError(
                "legacy started-Batch KPI lacks its authority sequence"
            )
        return source_sequence < activation_sequence

    @staticmethod
    def _require_scientific_study_outcome(
        *,
        completion: IndexRecord,
        outcome: str,
    ) -> None:
        scientific = completion.payload.get("scientific")
        if (
            not isinstance(scientific, Mapping)
            or scientific.get("scientific_eligible") is not True
        ):
            raise TransitionError(
                "Study outcome basis is not an eligible scientific completion"
            )
        verdict = scientific.get("verdict")
        adjudication = scientific.get("adjudication")
        if adjudication is None:
            evidence_class = {
                "passed": "positive",
                "failed": "negative",
                "not_evaluable": "unavailable",
            }.get(verdict)
        else:
            state = (
                adjudication.get("state")
                if isinstance(adjudication, Mapping)
                else None
            )
            expected_verdict = {
                "confirmed": "passed",
                "contradicted": "failed",
                "frontier": "passed",
                "not_evaluable": "not_evaluable",
                "partial_positive": "not_evaluable",
                "unresolved": "not_evaluable",
            }.get(state)
            evidence_class = {
                "confirmed": "positive",
                "frontier": "positive",
                "partial_positive": "positive",
                "contradicted": "negative",
                "not_evaluable": "unavailable",
                "unresolved": "unavailable",
            }.get(state)
            if expected_verdict != verdict:
                evidence_class = None
        allowed_outcomes = {
            "positive": {"preserved", "supported"},
            "negative": {"not_supported", "pruned"},
            "unavailable": {"evidence_gap", "not_evaluable"},
        }
        if evidence_class is None:
            raise TransitionError(
                "Study outcome basis has malformed scientific adjudication"
            )
        if outcome not in allowed_outcomes[evidence_class]:
            raise TransitionError(
                "Study outcome conflicts with its disposition-driving scientific "
                "adjudication"
            )

    def _study_kpi_payload(
        self,
        *,
        index: LocalIndex,
        study_id: str,
        outcome: str,
        completion_record_id: str | None,
        closed_at_utc: str,
    ) -> dict[str, Any] | None:
        if self.engineering_fixture:
            return None
        if completion_record_id is None:
            batch_head = index.event_head(f"study-batches:{study_id}")
            if batch_head is None:
                raise TransitionError(
                    "Real Study close requires a disposed Batch"
                )
            batch_id = batch_head.record_id
            job_inventory = _batch_job_decision_inventory(
                index,
                batch_id=batch_id,
            )
            if self._batch_stop_completion_ids(
                index,
                batch_id,
                job_inventory,
            ):
                raise TransitionError(
                    "Study with a final stop decision requires its validator completion"
                )
            close_records = tuple(
                record
                for status in _BATCH_OUTCOMES
                for record in index.records_by_subject_status(
                    f"Batch:{batch_id}", status
                )
                if record.kind == "batch-close"
            )
            close_status = None if len(close_records) != 1 else close_records[0].status
            if (
                close_status is None
                or outcome not in {"evidence_gap", "not_evaluable"}
            ):
                raise TransitionError(
                    "Study KPI unavailable state is not writer-derived"
                )
            unavailable_reason = self._batch_unavailable_reason(
                index,
                batch_id,
                close_status,
                job_inventory,
            )
            source = {
                "completion_record_id": None,
                "executable_id": None,
                "executable_display_id": None,
                "metrics": {name: None for name in _STUDY_KPI_METRICS},
                "source": "writer_derived_unavailable",
                "unavailable_reason": unavailable_reason,
            }
        else:
            source = self._study_kpi_from_completion(
                index=index,
                study_id=study_id,
                completion_record_id=completion_record_id,
            )
            if source["source"] == "scientific_job_completion":
                completion = index.get("job-completed", completion_record_id)
                if completion is None:
                    raise TransitionError(
                        "Study outcome scientific completion is unavailable"
                    )
                self._require_scientific_study_outcome(
                    completion=completion,
                    outcome=outcome,
                )
            elif (
                source["source"] == "typed_engineering_failure_completion"
                and outcome not in {"evidence_gap", "not_evaluable"}
            ):
                raise TransitionError(
                    "Engineering Study outcome cannot become a scientific outcome"
                )
            if (
                source["source"]
                in {
                    "validator_derived_source_completion",
                    "validator_derived_external_completion",
                }
                and outcome
                not in {"preserved", "pruned", "evidence_gap", "not_evaluable"}
            ):
                raise TransitionError(
                    "Non-performance Study KPI completion is incompatible with the outcome"
                )
            source["executable_display_id"] = self._study_kpi_display_id(
                index,
                source["executable_id"],
            )
        head = index.event_head("study-kpi")
        sequence = 1 if head is None else head.sequence + 1
        payload = {
            **source,
            "historical_study_close_event_id": None,
            "historical_study_close_record_id": None,
            "historical_study_close_revision": None,
            "outcome": outcome,
            "provenance": "prospective_close",
            "sequence": sequence,
            "study_id": study_id,
        }
        try:
            StudyKpiProjectionRow(
                sequence=sequence,
                closed_at_utc=closed_at_utc,
                study_id=study_id,
                executable_id=payload["executable_id"],
                executable_display_id=payload["executable_display_id"],
                net_profit_micropoints=payload["metrics"][
                    "net_profit_micropoints"
                ],
                median_fold_profit_factor_milli=payload["metrics"][
                    "median_fold_profit_factor_milli"
                ],
                trade_count=payload["metrics"]["trade_count"],
                monthly_realized_exit_drawdown_share_of_gross_profit_ppm=payload[
                    "metrics"
                ]["monthly_realized_exit_drawdown_share_of_gross_profit_ppm"],
                outcome=outcome,
            )
        except (KeyError, TypeError, ValueError) as exc:
            raise TransitionError("Study KPI row is not renderable") from exc
        return payload

    @staticmethod
    def _study_batch_close_record(
        index: LocalIndex,
        batch_id: str,
    ) -> IndexRecord:
        close_records = tuple(
            record
            for status in _BATCH_OUTCOMES
            for record in index.records_by_subject_status(
                f"Batch:{batch_id}",
                status,
            )
            if record.kind == "batch-close"
        )
        if len(close_records) != 1:
            raise TransitionError("Historical Study Batch close is ambiguous")
        return close_records[0]

    def _historical_engineering_unavailable_source(
        self,
        *,
        index: LocalIndex,
        study_id: str,
        batch_id: str,
        completion_record_id: str,
    ) -> dict[str, Any]:
        completion = index.get("job-completed", completion_record_id)
        job_id = None if completion is None else completion.payload.get("job_id")
        declaration = (
            None
            if not isinstance(job_id, str)
            else index.get("job-declared", job_id)
        )
        decisions = (
            ()
            if completion is None
            else tuple(
                record
                for record in index.records_by_fingerprint(completion.fingerprint)
                if record.kind == "job-evidence-decision"
                and record.payload.get("completion_record_id")
                == completion_record_id
            )
        )
        failure = None if completion is None else completion.payload.get("failure")
        spec = None if declaration is None else declaration.payload.get("spec")
        evidence_subject = (
            None if not isinstance(spec, Mapping) else spec.get("evidence_subject")
        )
        executable_id = (
            evidence_subject.get("id")
            if isinstance(evidence_subject, Mapping)
            and evidence_subject.get("kind") == "Executable"
            and type(evidence_subject.get("id")) is str
            else None
        )
        batch_close = self._study_batch_close_record(index, batch_id)
        if (
            completion is None
            or completion.status != "failed"
            or not isinstance(job_id, str)
            or declaration is None
            or declaration.payload.get("study_id") != study_id
            or declaration.payload.get("batch_id") != batch_id
            or len(decisions) != 1
            or decisions[0].subject != f"Job:{job_id}"
            or decisions[0].status != "stop_batch"
            or not isinstance(failure, Mapping)
            or failure.get("failure_kind") != "engineering"
            or executable_id is None
            or isinstance(completion.payload.get("scientific"), Mapping)
            or isinstance(completion.payload.get("source"), Mapping)
            or isinstance(completion.payload.get("external"), Mapping)
            or batch_close.status != "engineering_failure"
        ):
            raise TransitionError(
                "Historical Study KPI lacks an exact engineering-failure basis"
            )
        return {
            "completion_record_id": completion_record_id,
            "executable_id": executable_id,
            "executable_display_id": None,
            "metrics": {name: None for name in _STUDY_KPI_METRICS},
            "source": "historical_writer_verified_unavailable",
            "unavailable_reason": (
                "historical_final_non_scientific_engineering_failure"
            ),
        }

    def _historical_study_kpi_payload(
        self,
        *,
        index: LocalIndex,
        close_record: IndexRecord,
        sequence: int,
        reserved_display_owners: Mapping[str, str],
    ) -> dict[str, Any]:
        study_id = close_record.subject.removeprefix("Study:")
        close_event = index.get(
            "journal-event",
            close_record.authority_event_id or "",
        )
        study_open = index.get("study-open", study_id)
        batch_head = index.event_head(f"study-batches:{study_id}")
        if (
            close_record.kind != "study-close"
            or close_record.subject != f"Study:{study_id}"
            or close_record.status not in _STUDY_OUTCOMES
            or close_record.authority_sequence is None
            or close_event is None
            or close_event.status != "study_closed"
            or close_event.authority_sequence != close_record.authority_sequence
            or close_event.authority_event_id != close_record.authority_event_id
            or study_open is None
            or batch_head is None
        ):
            raise TransitionError("Historical Study close provenance is invalid")
        batch_id = batch_head.record_id
        job_inventory = _batch_job_decision_inventory(
            index,
            batch_id=batch_id,
        )
        completion_ids = self._batch_stop_completion_ids(
            index,
            batch_id,
            job_inventory,
        )
        if len(completion_ids) > 1:
            raise TransitionError("Historical Study has multiple final completions")
        if completion_ids:
            completion_record_id = completion_ids[0]
            try:
                source = self._study_kpi_from_completion(
                    index=index,
                    study_id=study_id,
                    completion_record_id=completion_record_id,
                )
            except TransitionError:
                source = self._historical_engineering_unavailable_source(
                    index=index,
                    study_id=study_id,
                    batch_id=batch_id,
                    completion_record_id=completion_record_id,
                )
        else:
            batch_close = self._study_batch_close_record(index, batch_id)
            unavailable_reason = self._batch_unavailable_reason(
                index,
                batch_id,
                batch_close.status,
                job_inventory,
                allow_legacy_started_failure=True,
            )
            source = {
                "completion_record_id": None,
                "executable_id": None,
                "executable_display_id": None,
                "metrics": {name: None for name in _STUDY_KPI_METRICS},
                "source": "writer_derived_unavailable",
                "unavailable_reason": unavailable_reason,
            }
        if (
            source["source"]
            in {
                "validator_derived_source_completion",
                "validator_derived_external_completion",
            }
            and close_record.status
            not in {"preserved", "pruned", "evidence_gap", "not_evaluable"}
        ):
            raise TransitionError(
                "Historical non-performance completion is incompatible with its outcome"
            )
        if (
            source["source"]
            in {
                "writer_derived_unavailable",
                "historical_writer_verified_unavailable",
            }
            and close_record.status
            not in {"evidence_gap", "not_evaluable", "pruned"}
        ):
            raise TransitionError(
                "Historical unavailable KPI is incompatible with its outcome"
            )
        source["executable_display_id"] = self._study_kpi_display_id(
            index,
            source["executable_id"],
            reserved_display_owners,
        )
        payload = {
            **source,
            "historical_study_close_event_id": close_record.authority_event_id,
            "historical_study_close_record_id": close_record.record_id,
            "historical_study_close_revision": close_record.authority_sequence,
            "outcome": close_record.status,
            "provenance": "historical_backfill",
            "sequence": sequence,
            "study_id": study_id,
        }
        try:
            StudyKpiProjectionRow(
                sequence=sequence,
                closed_at_utc=close_event.payload["occurred_at_utc"],
                study_id=study_id,
                executable_id=payload["executable_id"],
                executable_display_id=payload["executable_display_id"],
                net_profit_micropoints=payload["metrics"][
                    "net_profit_micropoints"
                ],
                median_fold_profit_factor_milli=payload["metrics"][
                    "median_fold_profit_factor_milli"
                ],
                trade_count=payload["metrics"]["trade_count"],
                monthly_realized_exit_drawdown_share_of_gross_profit_ppm=payload[
                    "metrics"
                ]["monthly_realized_exit_drawdown_share_of_gross_profit_ppm"],
                outcome=close_record.status,
            )
        except (KeyError, TypeError, ValueError) as exc:
            raise TransitionError(
                "Historical Study KPI row is not renderable"
            ) from exc
        return payload

    def backfill_historical_study_kpis(
        self,
        *,
        operation_id: str = _STUDY_KPI_BACKFILL_OPERATION_ID,
    ) -> TransitionResult:
        """Project pre-activation Study closes into one evidence-bound ledger."""

        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot backfill real Study KPIs")
        _require_ascii("operation_id", operation_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if (
                science["active_mission"] is not None
                or any(
                    science[name] is not None
                    for name in (
                        "active_initiative",
                        "active_study",
                        "active_batch",
                        "active_job",
                        "active_repair",
                        "active_lineage",
                        "active_executable",
                        "active_release",
                        "active_holdout_evaluation",
                    )
                )
                or body.get("next_action", {}).get("kind") != "await_root_goal"
            ):
                raise TransitionError(
                    "Historical Study KPI backfill requires the Mission-admission boundary"
                )
            activation = index.get(
                "operation",
                _STUDY_KPI_ACTIVATION_OPERATION_ID,
            )
            activation_event = (
                None
                if activation is None or activation.authority_event_id is None
                else index.get("journal-event", activation.authority_event_id)
            )
            if (
                activation is None
                or activation.authority_sequence is None
                or activation_event is None
                or activation_event.status != "authority_migrated"
                or activation.payload.get("event_kind") != "authority_migrated"
            ):
                raise TransitionError("Study KPI activation authority is unavailable")
            if index.count_by_kind("study-kpi"):
                raise TransitionError("Historical Study KPI backfill is already populated")
            all_closes = tuple(index.records_by_kind("study-close"))
            historical_closes = tuple(
                sorted(
                    (
                        record
                        for record in all_closes
                        if record.authority_sequence is not None
                        and record.authority_sequence
                        < activation.authority_sequence
                    ),
                    key=lambda record: record.authority_sequence or 0,
                )
            )
            historical_open_ids = {
                record.record_id
                for record in index.records_by_kind("study-open")
                if record.authority_sequence is not None
                and record.authority_sequence < activation.authority_sequence
            }
            historical_close_ids = {
                record.subject.removeprefix("Study:")
                for record in historical_closes
            }
            if (
                not historical_closes
                or len(historical_close_ids) != len(historical_closes)
                or historical_open_ids != historical_close_ids
                or index.event_head("study-kpi") is not None
            ):
                raise TransitionError("Historical Study close set is incomplete")
            if any(
                record.authority_sequence is not None
                and record.authority_sequence >= activation.authority_sequence
                for record in all_closes
            ):
                raise TransitionError(
                    "A prospective Study close is missing its mandatory KPI record"
                )
            reserved_display_owners: dict[str, str] = {}
            row_records: list[IndexRecord] = []
            row_fingerprints: list[str] = []
            for sequence, close_record in enumerate(historical_closes, start=1):
                payload = self._historical_study_kpi_payload(
                    index=index,
                    close_record=close_record,
                    sequence=sequence,
                    reserved_display_owners=reserved_display_owners,
                )
                display_id = payload["executable_display_id"]
                executable_id = payload["executable_id"]
                if display_id is not None and executable_id is not None:
                    reserved_display_owners[display_id] = executable_id
                fingerprint = _digest(payload, domain="study-kpi")
                row_fingerprints.append(fingerprint)
                row_records.append(
                    _record(
                        kind="study-kpi",
                        record_id=payload["study_id"],
                        subject=f"Study:{payload['study_id']}",
                        status=payload["outcome"],
                        fingerprint=fingerprint,
                        payload=payload,
                        event_stream="study-kpi",
                        event_sequence=sequence,
                    )
                )
            manifest_payload = {
                "activation_event_id": activation.authority_event_id,
                "activation_operation_id": _STUDY_KPI_ACTIVATION_OPERATION_ID,
                "activation_revision": activation.authority_sequence,
                "cutoff_revision": activation.authority_sequence - 1,
                "holdout_delta": 0,
                "row_fingerprints": row_fingerprints,
                "row_count": len(row_records),
                "schema": "study_kpi_historical_backfill.v1",
                "scientific_claim": "none",
                "sequence_end": len(row_records),
                "sequence_start": 1,
                "source_study_close_record_ids": [
                    record.record_id for record in historical_closes
                ],
                "trial_delta": 0,
            }
            backfill_record_id = _digest(
                manifest_payload,
                domain="study-kpi-backfill",
            )
            backfill_record = _record(
                kind="study-kpi-backfill",
                record_id=backfill_record_id,
                subject="StudyKpi:historical",
                status="complete",
                fingerprint=backfill_record_id,
                payload=manifest_payload,
            )
            return body, [backfill_record, *row_records], {
                "backfill_record_id": backfill_record_id,
                "row_count": len(row_records),
                "sequence_end": len(row_records),
                "sequence_start": 1,
            }

        transition = self._commit(
            event_kind="study_kpi_backfilled",
            operation_id=operation_id,
            subject="StudyKpi:historical",
            payload={
                "activation_operation_id": _STUDY_KPI_ACTIVATION_OPERATION_ID,
            },
            prepare=prepare,
        )
        self.rebuild_study_kpi_projection()
        return transition

    def rebuild_study_kpi_projection(self) -> bool:
        """Explicitly materialize the lag-tolerant Markdown navigation view.

        This intentionally performs a complete authority scan.  Routine Study
        close never calls it; the immutable ``study-kpi`` Journal record is the
        close-time authority and Git delivery validates only the bounded suffix.
        """

        rows: list[StudyKpiProjectionRow] = []
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                self._require_stable_locked(index)
                historical_backfills_by_event: dict[str, list[IndexRecord]] = {}
                for backfill in index.records_by_subject_status(
                    "StudyKpi:historical",
                    "complete",
                ):
                    if (
                        backfill.kind == "study-kpi-backfill"
                        and isinstance(backfill.authority_event_id, str)
                    ):
                        historical_backfills_by_event.setdefault(
                            backfill.authority_event_id,
                            [],
                        ).append(backfill)
                for record in index.records_by_kind("study-kpi"):
                    payload = record.payload
                    expected_fields = {
                        "completion_record_id",
                        "executable_id",
                        "executable_display_id",
                        "historical_study_close_event_id",
                        "historical_study_close_record_id",
                        "historical_study_close_revision",
                        "metrics",
                        "outcome",
                        "provenance",
                        "sequence",
                        "source",
                        "study_id",
                        "unavailable_reason",
                    }
                    metrics = payload.get("metrics")
                    sequence = payload.get("sequence")
                    study_id = payload.get("study_id")
                    outcome = payload.get("outcome")
                    provenance = payload.get("provenance")
                    if (
                        set(payload) != expected_fields
                        or not isinstance(metrics, Mapping)
                        or set(metrics) != set(_STUDY_KPI_METRICS)
                        or type(sequence) is not int
                        or record.record_id != study_id
                        or record.subject != f"Study:{study_id}"
                        or record.status != outcome
                        or record.event_stream != "study-kpi"
                        or record.event_sequence != sequence
                        or record.authority_event_id is None
                    ):
                        raise TransitionError("Study KPI record projection is invalid")
                    source = payload.get("source")
                    completion_record_id = payload.get("completion_record_id")
                    executable_id = payload.get("executable_id")
                    executable_display_id = payload.get("executable_display_id")
                    unavailable_reason = payload.get("unavailable_reason")
                    historical_close_event_id = payload.get(
                        "historical_study_close_event_id"
                    )
                    historical_close_record_id = payload.get(
                        "historical_study_close_record_id"
                    )
                    historical_close_revision = payload.get(
                        "historical_study_close_revision"
                    )
                    if source == "scientific_job_completion":
                        if (
                            type(completion_record_id) is not str
                            or type(executable_id) is not str
                            or type(executable_display_id) is not str
                            or unavailable_reason is not None
                        ):
                            raise TransitionError("Study KPI evidence source is invalid")
                    elif source in {
                        "validator_derived_source_completion",
                        "validator_derived_external_completion",
                    }:
                        if (
                            type(completion_record_id) is not str
                            or (
                                executable_id is not None
                                and type(executable_id) is not str
                            )
                            or (
                                executable_id is None
                                and executable_display_id is not None
                            )
                            or (
                                executable_id is not None
                                and type(executable_display_id) is not str
                            )
                            or unavailable_reason != "non_performance_study"
                            or any(value is not None for value in metrics.values())
                        ):
                            raise TransitionError(
                                "Study KPI non-performance source is invalid"
                            )
                    elif source == "writer_derived_unavailable":
                        allowed_reasons = {
                            "unstarted_batch_not_evaluable_without_final_validator_completion": "not_evaluable",
                            "unstarted_batch_stopped_early_without_final_validator_completion": "stopped_early",
                            "unstarted_batch_implementation_authority_invalid_without_final_validator_completion": "not_evaluable",
                            "started_batch_budget_exhausted_without_final_validator_completion": "budget_exhausted",
                            "started_batch_stopped_early_without_final_validator_completion": "stopped_early",
                            "started_batch_not_evaluable_without_final_validator_completion": "not_evaluable",
                            "started_batch_engineering_failure_without_final_validator_completion": "engineering_failure",
                            "started_batch_implementation_authority_invalid_without_final_validator_completion": "not_evaluable",
                        }
                        batch_head = index.event_head(
                            f"study-batches:{study_id}"
                        )
                        reason_status = allowed_reasons.get(unavailable_reason)
                        job_inventory = (
                            None
                            if batch_head is None or reason_status is None
                            else _batch_job_decision_inventory(
                                index,
                                batch_id=batch_head.record_id,
                            )
                        )
                        close_records = (
                            ()
                            if batch_head is None or reason_status is None
                            else tuple(
                                item
                                for item in index.records_by_subject_status(
                                    f"Batch:{batch_head.record_id}",
                                    reason_status,
                                )
                                if item.kind == "batch-close"
                            )
                        )
                        derived_reason = (
                            None
                            if batch_head is None or reason_status is None
                            else self._batch_unavailable_reason(
                                index,
                                batch_head.record_id,
                                reason_status,
                                job_inventory,
                                allow_legacy_started_failure=(
                                    self._legacy_started_batch_failure_allowed(
                                        index=index,
                                        kpi_record=record,
                                    )
                                ),
                            )
                        )
                        if (
                            completion_record_id is not None
                            or executable_id is not None
                            or executable_display_id is not None
                            or any(value is not None for value in metrics.values())
                            or reason_status is None
                            or outcome
                            not in {"evidence_gap", "not_evaluable", "pruned"}
                            or batch_head is None
                            or derived_reason != unavailable_reason
                            or self._batch_stop_completion_ids(
                                index,
                                batch_head.record_id,
                                job_inventory,
                            )
                            or len(close_records) != 1
                        ):
                            raise TransitionError(
                                "Study KPI Writer-derived unavailable source is invalid"
                            )
                    elif source == "historical_writer_verified_unavailable":
                        batch_head = index.event_head(
                            f"study-batches:{study_id}"
                        )
                        derived_source = (
                            None
                            if batch_head is None
                            or type(completion_record_id) is not str
                            else self._historical_engineering_unavailable_source(
                                index=index,
                                study_id=study_id,
                                batch_id=batch_head.record_id,
                                completion_record_id=completion_record_id,
                            )
                        )
                        if (
                            provenance != "historical_backfill"
                            or type(executable_id) is not str
                            or type(executable_display_id) is not str
                            or any(value is not None for value in metrics.values())
                            or unavailable_reason
                            != "historical_final_non_scientific_engineering_failure"
                            or derived_source is None
                            or derived_source["executable_id"] != executable_id
                            or derived_source["unavailable_reason"]
                            != unavailable_reason
                        ):
                            raise TransitionError(
                                "Historical Study KPI unavailable source is invalid"
                            )
                    else:
                        raise TransitionError("Study KPI source is not typed")
                    authority_event = index.get(
                        "journal-event",
                        record.authority_event_id,
                    )
                    if provenance == "prospective_close":
                        if (
                            historical_close_event_id is not None
                            or historical_close_record_id is not None
                            or historical_close_revision is not None
                            or authority_event is None
                            or authority_event.status != "study_closed"
                        ):
                            raise TransitionError(
                                "Prospective Study KPI close provenance is invalid"
                            )
                        event = authority_event
                    elif provenance == "historical_backfill":
                        event = (
                            None
                            if type(historical_close_event_id) is not str
                            else index.get(
                                "journal-event",
                                historical_close_event_id,
                            )
                        )
                        source_close = (
                            None
                            if type(historical_close_record_id) is not str
                            else index.get(
                                "study-close",
                                historical_close_record_id,
                            )
                        )
                        backfill_records = tuple(
                            historical_backfills_by_event.get(
                                record.authority_event_id,
                                (),
                            )
                        )
                        if (
                            authority_event is None
                            or authority_event.status != "study_kpi_backfilled"
                            or type(historical_close_revision) is not int
                            or event is None
                            or event.status != "study_closed"
                            or event.authority_sequence
                            != historical_close_revision
                            or source_close is None
                            or source_close.authority_event_id
                            != historical_close_event_id
                            or source_close.authority_sequence
                            != historical_close_revision
                            or source_close.subject != f"Study:{study_id}"
                            or source_close.status != outcome
                            or len(backfill_records) != 1
                            or record.fingerprint
                            not in backfill_records[0].payload.get(
                                "row_fingerprints",
                                [],
                            )
                        ):
                            raise TransitionError(
                                "Historical Study KPI close provenance is invalid"
                            )
                    else:
                        raise TransitionError("Study KPI provenance is not typed")
                    if event is None:
                        raise TransitionError(
                            "Study KPI record is not bound to a Study close event"
                        )
                    try:
                        rows.append(
                            StudyKpiProjectionRow(
                                sequence=sequence,
                                closed_at_utc=event.payload["occurred_at_utc"],
                                study_id=study_id,
                                executable_id=executable_id,
                                executable_display_id=executable_display_id,
                                net_profit_micropoints=metrics[
                                    "net_profit_micropoints"
                                ],
                                median_fold_profit_factor_milli=metrics[
                                    "median_fold_profit_factor_milli"
                                ],
                                trade_count=metrics["trade_count"],
                                monthly_realized_exit_drawdown_share_of_gross_profit_ppm=metrics[
                                    "monthly_realized_exit_drawdown_share_of_gross_profit_ppm"
                                ],
                                outcome=outcome,
                            )
                        )
                    except (KeyError, TypeError, ValueError) as exc:
                        raise TransitionError(
                            "Study KPI record cannot be rendered"
                        ) from exc
                try:
                    return materialize_study_kpi(
                        self.root / LEDGER_RELATIVE_PATH,
                        rows,
                    )
                except (OSError, ValueError) as exc:
                    raise TransitionError(
                        "Study KPI projection materialization failed"
                    ) from exc

    def close_study(
        self,
        *,
        outcome: str,
        operation_id: str,
        kpi_completion_record_id: str | None = None,
    ) -> TransitionResult:
        _require_ascii("outcome", outcome)
        allowed = set(_STUDY_OUTCOMES)
        if self.engineering_fixture:
            allowed.add(_ENGINEERING_FIXTURE_OUTCOME)
        if outcome not in allowed:
            raise TransitionError("Study outcome is not typed")
        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            study_id = science["active_study"]
            if study_id is None or science["active_batch"] is not None:
                raise TransitionError("Study close requires no undisposed Batch")
            if science["active_job"] is not None or science["active_repair"] is not None:
                raise TransitionError("Study close requires no active Job or Repair")
            study_record = _index.get("study-open", study_id)
            if study_record is None:
                raise TransitionError("Study declaration is unavailable")
            batch_head = _index.event_head(f"study-batches:{study_id}")
            if (
                batch_head is None
                or body.get("next_action")
                != {"kind": "judge_study", "study_id": study_id}
            ):
                raise TransitionError("Study close is not the exact next action")
            from axiom_rift.operations.replay_projection import (
                ReplayProjectionError,
                ReplayTransitionError,
                require_study_terminal_authority,
            )

            try:
                require_study_terminal_authority(
                    _index,
                    mission_id=study_record.payload.get("mission_id"),
                    study=study_record,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            kpi_payload = self._study_kpi_payload(
                index=_index,
                study_id=study_id,
                outcome=outcome,
                completion_record_id=kpi_completion_record_id,
                closed_at_utc="1970-01-01T00:00:00Z",
            )
            science["active_study"] = None
            self._drop_authorization(body, SubjectKind.STUDY, study_id)
            fingerprint_payload = {"study_id": study_id, "outcome": outcome}
            if kpi_payload is not None:
                fingerprint_payload["study_kpi"] = kpi_payload
            fingerprint = _digest(fingerprint_payload, domain="study-close")
            body["next_action"] = (
                {
                    "kind": "portfolio_decision",
                    "portfolio_snapshot_id": study_record.payload.get(
                        "portfolio_snapshot_id"
                    ),
                }
                if self.engineering_fixture
                else {
                    "kind": "diagnose_study",
                    "study_id": study_id,
                    "study_close_record_id": fingerprint,
                    "portfolio_snapshot_id": study_record.payload.get(
                        "portfolio_snapshot_id"
                    ),
                }
            )
            record = _record(
                kind="study-close",
                record_id=fingerprint,
                subject=f"Study:{study_id}",
                status=outcome,
                fingerprint=fingerprint,
                payload={
                    "outcome": outcome,
                    "portfolio_axis_id": study_record.payload.get(
                        "portfolio_axis_id"
                    ),
                    "portfolio_axis_identity": study_record.payload.get(
                        "portfolio_axis_identity"
                    ),
                    "portfolio_snapshot_id": study_record.payload.get(
                        "portfolio_snapshot_id"
                    ),
                    "primary_research_layer": study_record.payload.get(
                        "primary_research_layer"
                    ),
                    "system_architecture_family": study_record.payload.get(
                        "system_architecture_family"
                    ),
                    "study_kpi_record_id": (
                        None if kpi_payload is None else study_id
                    ),
                },
            )
            records = [record]
            from axiom_rift.operations.semantic_question_registry import (
                SemanticQuestionRegistryError,
                SemanticQuestionRegistryIntegrityError,
                require_semantic_question_registry_activation,
                semantic_question_lineage_resolution_records,
            )

            try:
                if (
                    require_semantic_question_registry_activation(_index)
                    is not None
                ):
                    records.extend(
                        semantic_question_lineage_resolution_records(
                            _index, record
                        )
                    )
            except SemanticQuestionRegistryIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except SemanticQuestionRegistryError as exc:
                raise TransitionError(str(exc)) from exc
            if kpi_payload is not None:
                kpi_fingerprint = _digest(kpi_payload, domain="study-kpi")
                records.append(
                    _record(
                        kind="study-kpi",
                        record_id=study_id,
                        subject=f"Study:{study_id}",
                        status=outcome,
                        fingerprint=kpi_fingerprint,
                        payload=kpi_payload,
                        event_stream="study-kpi",
                        event_sequence=kpi_payload["sequence"],
                    )
                )
            return body, records, {
                "study_id": study_id,
                "outcome": outcome,
                "study_kpi_record_id": None if kpi_payload is None else study_id,
                "study_kpi_sequence": (
                    None if kpi_payload is None else kpi_payload["sequence"]
                ),
            }

        transition = self._commit(
            event_kind="study_closed",
            operation_id=operation_id,
            subject="Study:active",
            payload={
                "kpi_completion_record_id": kpi_completion_record_id,
                "outcome": outcome,
            },
            prepare=prepare,
        )
        return transition

    @staticmethod
    def _study_diagnosis_evidence_basis(
        index: LocalIndex,
        *,
        study_id: str,
        close_record: IndexRecord,
    ) -> list[dict[str, str]]:
        from axiom_rift.operations.scientific_history import (
            ScientificHistoryProjectionError,
            project_study_job_evidence,
        )

        references: set[tuple[str, str]] = {
            ("study-close", close_record.record_id)
        }
        kpi_record_id = close_record.payload.get("study_kpi_record_id")
        if isinstance(kpi_record_id, str):
            kpi = index.get("study-kpi", kpi_record_id)
            if kpi is None:
                raise TransitionError("Study diagnosis KPI basis is unavailable")
            references.add(("study-kpi", kpi.record_id))
            completion_id = kpi.payload.get("completion_record_id")
            if isinstance(completion_id, str):
                if index.get("job-completed", completion_id) is None:
                    raise TransitionError(
                        "Study diagnosis completion basis is unavailable"
                    )
                references.add(("job-completed", completion_id))
        batch_head = index.event_head(f"study-batches:{study_id}")
        if batch_head is None:
            raise TransitionError("Study diagnosis requires a final Batch")
        references.add((batch_head.record_kind, batch_head.record_id))
        batch_closes = tuple(
            record
            for status in _BATCH_OUTCOMES
            for record in index.records_by_subject_status(
                f"Batch:{batch_head.record_id}", status
            )
            if record.kind == "batch-close"
        )
        if len(batch_closes) != 1:
            raise TransitionError("Study diagnosis final Batch close is ambiguous")
        references.add(("batch-close", batch_closes[0].record_id))
        rejected_preflights = StateWriter._batch_rejected_replay_preflights(
            index,
            batch_head.record_id,
        )
        if rejected_preflights:
            if (
                batch_closes[0].status != "not_evaluable"
                or batch_closes[0].payload.get("basis_record_id")
                != rejected_preflights[0].record_id
            ):
                raise TransitionError(
                    "Study diagnosis implementation rejection has another Batch outcome"
                )
            references.add(
                (
                    "job-implementation-preflight",
                    rejected_preflights[0].record_id,
                )
            )
        try:
            job_evidence = project_study_job_evidence(
                index,
                study_id=study_id,
            )
        except ScientificHistoryProjectionError as exc:
            raise TransitionError(str(exc)) from exc
        references.update(
            ("job-completed", completion.record_id)
            for completion in job_evidence.completions
        )
        references.update(
            ("negative-memory", memory.record_id)
            for memory in job_evidence.negative_memories
        )
        return [
            {"kind": kind, "record_id": record_id}
            for kind, record_id in sorted(references)
        ]

    def record_study_diagnosis(
        self,
        *,
        diagnosis: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.research.governance import (
            EvidenceState,
            ResearchLayer,
            StudyDiagnosis,
            diagnosis_branch,
        )

        self._require_study_close_delivery_guard()
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures do not create Study diagnosis")
        if not isinstance(diagnosis, StudyDiagnosis):
            raise TransitionError("diagnosis must be a StudyDiagnosis")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("Study diagnosis requires an active Mission")
            science = current["scientific"]
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError("Study diagnosis cannot bypass active work")
            next_action = current["next_action"]
            if next_action != {
                "kind": "diagnose_study",
                "study_id": diagnosis.study_id,
                "study_close_record_id": diagnosis.study_close_record_id,
                "portfolio_snapshot_id": next_action.get("portfolio_snapshot_id"),
            }:
                raise TransitionError("Study diagnosis is not the exact next action")
            close_record = index.get(
                "study-close", diagnosis.study_close_record_id
            )
            study = index.get("study-open", diagnosis.study_id)
            if (
                close_record is None
                or close_record.subject != f"Study:{diagnosis.study_id}"
                or study is None
                or study.payload.get("mission_id") != science["active_mission"]
                or close_record.payload.get("portfolio_axis_identity")
                != study.payload.get("portfolio_axis_identity")
            ):
                raise TransitionError("Study diagnosis subject is unavailable or stale")
            outcome = close_record.status
            supported_states = {EvidenceState.SUPPORTED_REQUIRES_CONFIRMATION}
            unavailable_states = {
                EvidenceState.ENGINEERING_GAP,
                EvidenceState.NOT_IDENTIFIABLE,
            }
            negative_states = set(EvidenceState) - supported_states - {
                EvidenceState.ENGINEERING_GAP,
                EvidenceState.NOT_IDENTIFIABLE,
            }
            allowed_states = (
                supported_states
                if outcome in {"supported", "preserved"}
                else unavailable_states
                if outcome in {"evidence_gap", "not_evaluable"}
                else negative_states
                if outcome == "not_supported"
                else negative_states | {EvidenceState.NOT_IDENTIFIABLE}
                if outcome == "pruned"
                else set()
            )
            if diagnosis.evidence_state not in allowed_states:
                raise TransitionError(
                    "Study diagnosis evidence state conflicts with its typed outcome"
                )
            kpi = index.get("study-kpi", diagnosis.study_id)
            unavailable_reason = (
                None if kpi is None else kpi.payload.get("unavailable_reason")
            )
            engineering_basis = (
                unavailable_reason
                in {
                    "engineering_failure",
                    "started_batch_implementation_authority_invalid_"
                    "without_final_validator_completion",
                    "unstarted_batch_implementation_authority_invalid_"
                    "without_final_validator_completion",
                }
            )
            if (
                diagnosis.evidence_state == EvidenceState.ENGINEERING_GAP
            ) != engineering_basis:
                raise TransitionError(
                    "engineering diagnosis must match the writer-derived Batch basis"
                )
            try:
                primary_layer = ResearchLayer(
                    study.payload["primary_research_layer"]
                )
            except (KeyError, TypeError, ValueError) as exc:
                raise TransitionError(
                    "Study diagnosis lacks a typed primary research layer"
                ) from exc
            architecture = self._study_resolved_architecture_family(
                index=index,
                study=study,
            )
            allowed_actions, allowed_layers = diagnosis_branch(
                diagnosis.evidence_state,
                primary_layer=primary_layer,
            )
            evidence_basis = self._study_diagnosis_evidence_basis(
                index,
                study_id=diagnosis.study_id,
                close_record=close_record,
            )
            payload = {
                **diagnosis.to_identity_payload(),
                "allowed_actions": list(allowed_actions),
                "allowed_research_layers": list(allowed_layers),
                "evidence_basis": evidence_basis,
                "mission_id": science["active_mission"],
                "portfolio_axis_id": study.payload.get("portfolio_axis_id"),
                "portfolio_axis_identity": study.payload.get(
                    "portfolio_axis_identity"
                ),
                "portfolio_snapshot_id": study.payload.get(
                    "portfolio_snapshot_id"
                ),
                "primary_research_layer": primary_layer.value,
                "study_outcome": outcome,
                "system_architecture_family": architecture,
            }
            prior_diagnoses: list[IndexRecord] = []
            for record in index.records_by_payload_text(
                "study-diagnosis",
                "mission_id",
                science["active_mission"],
            ):
                if (
                    record.payload.get("evidence_state")
                    in {
                        EvidenceState.ENGINEERING_GAP.value,
                        EvidenceState.SUPPORTED_REQUIRES_CONFIRMATION.value,
                    }
                ):
                    continue
                prior_study_id = record.payload.get("study_id")
                prior_study = (
                    None
                    if not isinstance(prior_study_id, str)
                    else index.get("study-open", prior_study_id)
                )
                if (
                    prior_study is not None
                    and self._study_resolved_architecture_family(
                        index=index,
                        study=prior_study,
                    )
                    == architecture
                ):
                    prior_diagnoses.append(record)
            reviewed_ids: set[str] = set()
            for review in index.records_by_payload_text(
                "architecture-review",
                "mission_id",
                science["active_mission"],
            ):
                reviewed_ids.update(
                    value
                    for value in review.payload.get(
                        "covered_diagnosis_ids", []
                    )
                    if isinstance(value, str)
                )
            unreviewed = [
                record for record in prior_diagnoses if record.record_id not in reviewed_ids
            ]
            current_is_reviewable = diagnosis.evidence_state not in {
                EvidenceState.ENGINEERING_GAP,
                EvidenceState.SUPPORTED_REQUIRES_CONFIRMATION,
            }
            review_records = [*unreviewed]
            diagnosis_sequence_head = index.event_head(
                f"study-diagnosis:{science['active_mission']}"
            )
            diagnosis_sequence = (
                1
                if diagnosis_sequence_head is None
                else diagnosis_sequence_head.sequence + 1
            )
            diagnosis_record = _record(
                kind="study-diagnosis",
                record_id=diagnosis.identity,
                subject=f"Study:{diagnosis.study_id}",
                status=diagnosis.evidence_state.value,
                fingerprint=diagnosis.identity.removeprefix("diagnosis:"),
                payload=payload,
                event_stream=f"study-diagnosis:{science['active_mission']}",
                event_sequence=diagnosis_sequence,
            )
            if current_is_reviewable:
                review_records.append(diagnosis_record)
            snapshot_id = study.payload.get("portfolio_snapshot_id")
            snapshot = (
                None
                if not isinstance(snapshot_id, str)
                else index.get("portfolio-snapshot", snapshot_id)
            )
            standard = (
                None if snapshot is None else snapshot.payload.get("exhaustion_standard")
            )
            trigger_record: IndexRecord | None = None
            if isinstance(standard, dict) and current_is_reviewable:
                minimum_studies = standard.get(
                    "architecture_review_minimum_studies"
                )
                minimum_axes = standard.get("architecture_review_minimum_axes")
                axis_ids = {
                    record.payload.get("portfolio_axis_id")
                    for record in review_records
                }
                if (
                    type(minimum_studies) is int
                    and type(minimum_axes) is int
                    and len(review_records) >= minimum_studies
                    and len(axis_ids) >= minimum_axes
                    and None not in axis_ids
                ):
                    trigger_payload = {
                        "diagnosis_ids": sorted(
                            record.record_id for record in review_records
                        ),
                        "mission_id": science["active_mission"],
                        "portfolio_axis_ids": sorted(axis_ids),
                        "portfolio_snapshot_id": snapshot_id,
                        "primary_research_layers": sorted(
                            {
                                record.payload["primary_research_layer"]
                                for record in review_records
                            }
                        ),
                        "schema": "architecture_review_trigger.v1",
                        "system_architecture_family": architecture,
                        "threshold": {
                            "minimum_distinct_axes": minimum_axes,
                            "minimum_studies": minimum_studies,
                        },
                    }
                    trigger_id = canonical_digest(
                        domain="architecture-review-trigger",
                        payload=trigger_payload,
                    )
                    trigger_record = _record(
                        kind="architecture-review-trigger",
                        record_id=trigger_id,
                        subject=f"Mission:{science['active_mission']}",
                        status="required",
                        fingerprint=trigger_id,
                        payload=trigger_payload,
                    )
            body = self._body(current)
            if trigger_record is None:
                body["next_action"] = {
                    "kind": "portfolio_decision",
                    "portfolio_snapshot_id": snapshot_id,
                    "study_diagnosis_id": diagnosis.identity,
                }
                records = [diagnosis_record]
            else:
                body["next_action"] = {
                    "kind": "review_architecture",
                    "trigger_record_id": trigger_record.record_id,
                }
                records = [diagnosis_record, trigger_record]
            from axiom_rift.operations.replay_projection import (
                ReplayProjectionError,
                ReplayTransitionError,
                require_diagnosed_replay,
            )

            try:
                replay_obligation_ids = require_diagnosed_replay(
                    index,
                    mission_id=science["active_mission"],
                    study=study,
                    diagnosis_id=diagnosis.identity,
                    diagnosis_record=diagnosis_record,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            if replay_obligation_ids:
                body["next_action"] = {
                    "kind": "resolve_historical_replay_obligations",
                    "replay_obligation_ids": list(replay_obligation_ids),
                    "resume_next_action": body["next_action"],
                    "study_diagnosis_id": diagnosis.identity,
                    "study_id": diagnosis.study_id,
                }
            return body, records, {
                "architecture_review_trigger_id": (
                    None if trigger_record is None else trigger_record.record_id
                ),
                "study_diagnosis_id": diagnosis.identity,
            }

        return self._commit(
            event_kind="study_diagnosis_recorded",
            operation_id=operation_id,
            subject=f"Study:{diagnosis.study_id}",
            payload={"study_diagnosis_id": diagnosis.identity},
            prepare=prepare,
        )

    def record_architecture_review(
        self,
        *,
        review: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.research.governance import (
            ArchitectureReview,
            ArchitectureReviewConclusion,
        )
        from axiom_rift.operations.architecture_review_direction import (
            ArchitectureReviewDirectionError,
            constraint_from_direction,
            require_existing_axis_binding,
            require_review_binding,
        )

        self._require_study_close_delivery_guard()
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures do not create architecture review")
        if not isinstance(review, ArchitectureReview):
            raise TransitionError("review must be an ArchitectureReview")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("architecture review requires an active Mission")
            science = current["scientific"]
            if science["active_mission"] != review.mission_id:
                raise TransitionError("architecture review belongs to another Mission")
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError("architecture review cannot bypass active work")
            next_action = current["next_action"]
            trigger_id = next_action.get("trigger_record_id")
            trigger = (
                None
                if not isinstance(trigger_id, str)
                else index.get("architecture-review-trigger", trigger_id)
            )
            if (
                next_action.get("kind") != "review_architecture"
                or trigger_id != review.trigger_record_id
                or trigger is None
                or trigger.status != "required"
                or trigger.payload.get("mission_id") != review.mission_id
                or trigger.payload.get("system_architecture_family")
                != review.system_architecture_family
            ):
                raise TransitionError("architecture review trigger is absent or stale")
            payload = {
                **review.to_identity_payload(),
                "covered_diagnosis_ids": trigger.payload["diagnosis_ids"],
                "portfolio_axis_ids": trigger.payload["portfolio_axis_ids"],
                "portfolio_snapshot_id": trigger.payload["portfolio_snapshot_id"],
                "primary_research_layers": trigger.payload[
                    "primary_research_layers"
                ],
            }
            continuation = None
            if (
                review.conclusion
                is ArchitectureReviewConclusion.BOUNDED_SAME_ARCHITECTURE
            ):
                assert review.continuation_direction is not None
                continuation = constraint_from_direction(
                    architecture_review_id=review.identity,
                    direction=review.continuation_direction,
                )
                try:
                    require_review_binding(
                        continuation,
                        review_record_id=review.identity,
                        review_payload=payload,
                        trigger_payload=trigger.payload,
                    )
                except ArchitectureReviewDirectionError as exc:
                    raise TransitionError(str(exc)) from exc
                snapshot = index.get(
                    "portfolio-snapshot",
                    trigger.payload["portfolio_snapshot_id"],
                )
                if snapshot is None:
                    raise RecoveryRequired(
                        "architecture review lost its Portfolio snapshot"
                    )
                axis_values = tuple(snapshot.payload.get("axes", []))
                axes_by_id = {
                    axis["axis_id"]: axis
                    for axis in axis_values
                    if isinstance(axis, Mapping)
                    and isinstance(axis.get("axis_id"), str)
                }
                resolutions = self._effective_axis_resolutions(index, axis_values)
                selectable_axis_ids = frozenset(
                    axis["axis_id"]
                    for axis, resolution in zip(
                        axis_values,
                        resolutions,
                        strict=True,
                    )
                    if resolution.decision_option_eligible
                )
                resolved_families = {
                    axis_id: self._axis_resolved_architecture_family(
                        index=index,
                        axis=axis,
                    )
                    for axis_id, axis in axes_by_id.items()
                }
                try:
                    require_existing_axis_binding(
                        continuation,
                        axes_by_id=axes_by_id,
                        selectable_axis_ids=selectable_axis_ids,
                        resolved_architecture_families=resolved_families,
                    )
                except ArchitectureReviewDirectionError as exc:
                    raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = {
                "kind": "portfolio_decision",
                "architecture_review_id": review.identity,
                "constraint_source_id": review.identity,
                "portfolio_snapshot_id": trigger.payload["portfolio_snapshot_id"],
            }
            if continuation is not None:
                body["next_action"].update(continuation.to_action_fields())
            elif (
                review.conclusion
                == ArchitectureReviewConclusion.ROTATE_ARCHITECTURE
            ):
                body["next_action"]["excluded_architecture_family"] = (
                    review.system_architecture_family
                )
            else:
                body["next_action"]["excluded_research_layers"] = trigger.payload[
                    "primary_research_layers"
                ]
            record = _record(
                kind="architecture-review",
                record_id=review.identity,
                subject=f"Mission:{review.mission_id}",
                status=review.conclusion.value,
                fingerprint=review.identity.removeprefix("architecture-review:"),
                payload=payload,
            )
            return body, [record], {"architecture_review_id": review.identity}

        return self._commit(
            event_kind="architecture_review_recorded",
            operation_id=operation_id,
            subject=f"Mission:{review.mission_id}",
            payload={"architecture_review_id": review.identity},
            prepare=prepare,
        )

    @staticmethod
    def _normalize_job_spec(spec: Mapping[str, Any]) -> dict[str, Any]:
        return normalize_job_spec(spec)

    @staticmethod
    def _validate_job_spec(spec: Mapping[str, Any]) -> None:
        try:
            validate_job_spec(
                spec,
                evidence_modes_validator=_require_study_evidence_modes,
            )
        except JobContractError as exc:
            raise TransitionError(str(exc)) from exc

    def _require_job_implementation_evidence(
        self,
        spec: Mapping[str, Any],
        *,
        _index: LocalIndex | LocalIndexView | None = None,
    ) -> Mapping[str, Any]:
        def require(
            index: LocalIndex | LocalIndexView,
        ) -> Mapping[str, Any]:
            try:
                historical_sources = (
                    authenticated_historical_implementation_sources(
                        spec,
                        index=index,
                        artifact_reader=self.evidence.read_verified,
                    )
                )
                return require_job_implementation_evidence(
                    spec,
                    artifact_reader=self.evidence.read_verified,
                    historical_source_authorities=historical_sources,
                )
            except (
                HistoricalReplayImplementationAuthorityError,
                JobImplementationAuthorityError,
            ) as exc:
                raise TransitionError(str(exc)) from exc

        if _index is not None:
            return require(_index)
        with self.open_stable_index() as (_control, index):
            return require(index)

    def _require_reusable_success_outputs(
        self, *, completion: IndexRecord, spec: Mapping[str, Any]
    ) -> None:
        try:
            require_reusable_success_outputs(
                completion_payload=completion.payload,
                spec=spec,
                repository_root=self.root,
                durable_verifier=self.evidence.verify,
            )
        except JobCacheAuthorityError as exc:
            raise RecoveryRequired(str(exc)) from exc

    def _preflight_scientific_binding(self, spec: Mapping[str, Any]) -> None:
        binding = spec.get("scientific_binding")
        if not isinstance(binding, Mapping):
            return
        try:
            self.validation_registry.preflight_binding(
                validator_id=binding["validator_id"],
                domain="scientific",
                binding=binding,
            )
        except EvidenceValidationError as exc:
            raise TransitionError(
                f"scientific validation preflight failed: {exc}"
            ) from exc

    def _authority_requires_scientific_adjudication_v2(
        self,
        current: Mapping[str, Any],
    ) -> bool:
        authority = current.get("authority")
        if not isinstance(authority, Mapping):
            raise RecoveryRequired("scientific protocol authority is unavailable")
        contracts = authority.get("contracts")
        if not isinstance(contracts, list):
            raise RecoveryRequired("scientific protocol contract manifest is invalid")
        root = self.foundation_root.resolve()
        for relative in contracts:
            _require_ascii("authority contract path", relative)
            path = (root / relative).resolve()
            if root != path and root not in path.parents:
                raise RecoveryRequired("scientific protocol contract escapes Foundation")
            if not path.is_file():
                raise RecoveryRequired("scientific protocol contract is unavailable")
            if any(
                line.strip() == b"scientific_adjudication_v2:"
                for line in path.read_bytes().splitlines()
            ):
                return True
        return False

    def record_replay_job_implementation_preflight(
        self,
        *,
        request: Any,
        operation_id: str,
        repair_close_record_id: str | None = None,
    ) -> TransitionResult:
        """Check one replay family before it spends trial or Job budget.

        The Writer derives scope from the current Mission and Batch, invokes
        the byte inspector inside the stable-index lock, and writes the result
        itself.  Callers cannot submit an ``accepted`` result.  Rejection is
        operational evidence only and routes the Batch to an unavailable
        disposition without manufacturing a failed Job.  An exact successful
        running-Job implementation Repair may use the same evaluator to append
        a successor family admission after that Job is completed and judged;
        the completed prefix and predecessor admission are re-derived here.
        """

        from axiom_rift.operations.replay_job_implementation_preflight import (
            PREFLIGHT_SCHEMA,
            ReplayJobImplementationPreflightError,
            ReplayJobImplementationPreflightRequest,
            derive_replay_job_scientific_surface,
            evaluate_replay_job_implementation_preflight,
            replay_job_scientific_surface_hash,
            require_active_replay_job_replacement_binding,
            require_durable_replay_job_implementation_preflight,
            require_replacement_replay_job_scientific_surface,
        )
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            obligation_heads,
            require_current_replacement_preflight_basis,
        )
        from axiom_rift.research.replay_obligation import ReplayObligationStatus

        self._require_study_close_delivery_guard()
        if not isinstance(request, ReplayJobImplementationPreflightRequest):
            raise TransitionError(
                "replay Job implementation preflight request is not typed"
            )
        if repair_close_record_id is not None:
            _require_digest(
                "replay implementation Repair close",
                repair_close_record_id,
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "replay Job implementation preflight requires control"
                )
            science = current["scientific"]
            mission_id = science.get("active_mission")
            if mission_id != request.mission_id:
                raise TransitionError(
                    "replay implementation preflight belongs to another Mission"
                )
            if science.get("active_job") is not None or science.get(
                "active_repair"
            ) is not None:
                raise TransitionError(
                    "replay implementation preflight cannot bypass active work"
                )
            heads = {
                obligation.identity: (obligation, head)
                for obligation, head in obligation_heads(
                    index,
                    mission_id=mission_id,
                )
            }
            selected = tuple(
                heads.get(obligation_id)
                for obligation_id in request.replay_obligation_ids
            )
            if any(item is None for item in selected):
                raise TransitionError(
                    "replay implementation preflight lacks its exact obligation"
                )
            active_batch = science.get("active_batch")
            active_study_id = science.get("active_study")
            batch_id: str | None = None
            study_id: str | None = None
            surface_batch: IndexRecord | None = None
            surface_study: IndexRecord | None = None
            current_admission: IndexRecord | None = None
            required_replacement_preflight: IndexRecord | None = None
            registration_inspection: Any | None = None
            repair_boundary: Any | None = None
            protocol_failure: str | None = None
            protocol_activation: IndexRecord | None = None
            replacement = request.replacement_for_preflight_id
            replaced_record = (
                None
                if replacement is None
                else index.get("job-implementation-preflight", replacement)
            )
            if isinstance(active_batch, Mapping):
                if replacement is not None:
                    raise TransitionError(
                        "active replay preflight cannot replace another preflight"
                    )
                batch_id = active_batch.get("id")
                study_id = active_study_id
                batch = (
                    None
                    if not isinstance(batch_id, str)
                    else index.get("batch-open", batch_id)
                )
                study = (
                    None
                    if not isinstance(study_id, str)
                    else index.get("study-open", study_id)
                )
                surface_batch = batch
                surface_study = study
                resolved_family_ids = (
                    None
                    if batch is None
                    else _concurrent_family_executable_ids(batch)
                )
                family_ids = (
                    None
                    if resolved_family_ids is None
                    else list(resolved_family_ids)
                )
                action = current.get("next_action")
                if study is not None and batch is not None:
                    from axiom_rift.operations.replay_study_admission import (
                        ReplayStudyAdmissionError,
                        inspect_replay_study_registration,
                    )

                    try:
                        registration_inspection = (
                            inspect_replay_study_registration(
                                index,
                                study_record=study,
                                batch_record=batch,
                            ).require_usable()
                        )
                    except ReplayStudyAdmissionError as exc:
                        raise RecoveryRequired(str(exc)) from exc
                budget_head = (
                    None
                    if not isinstance(batch_id, str)
                    else index.event_head(f"batch-budget:{batch_id}")
                )
                declarations = (
                    ()
                    if not isinstance(batch_id, str)
                    else tuple(
                        index.records_by_payload_text(
                            "job-declared",
                            "batch_id",
                            batch_id,
                        )
                    )
                )
                existing_preflight_head = (
                    None
                    if not isinstance(batch_id, str)
                    else index.event_head(
                        "replay-job-implementation-preflight-batch:"
                        + batch_id
                    )
                )
                current_admission = (
                    None
                    if not isinstance(study_id, str)
                    else self._study_replay_implementation_admission(
                        index,
                        study_id=study_id,
                        authority_manifest_digest=current.get(
                            "authority", {}
                        ).get("manifest_digest"),
                    )
                )
                if (
                    batch is None
                    or study is None
                    or study.payload.get("mission_id") != mission_id
                    or study.payload.get("replay_obligation_ids")
                    != list(request.replay_obligation_ids)
                    or not isinstance(family_ids, list)
                    or len(family_ids) != len(request.executable_ids)
                    or set(family_ids) != set(request.executable_ids)
                    or not isinstance(action, Mapping)
                    or action.get("kind") != "declare_job"
                    or action.get("batch_id") != batch_id
                    or registration_inspection is None
                    or registration_inspection.expected_executable_ids
                    != request.executable_ids
                    or (
                        repair_close_record_id is None
                        and (
                            current_admission is not None
                            or budget_head is not None
                            or declarations
                            or existing_preflight_head is not None
                        )
                    )
                    or (
                        repair_close_record_id is not None
                        and current_admission is None
                    )
                ):
                    raise TransitionError(
                        "replay implementation preflight differs from the active family"
                    )
                if repair_close_record_id is not None:
                    assert current_admission is not None
                    assert study is not None
                    assert batch is not None
                    from axiom_rift.operations import (
                        replay_implementation_repair_admission
                        as repair_module,
                    )

                    boundary_inspector = (
                        repair_module.inspect_replay_implementation_repair_boundary
                    )
                    boundary_error = (
                        repair_module.ReplayImplementationRepairAdmissionError
                    )

                    try:
                        repair_boundary = boundary_inspector(
                            index,
                            predecessor_admission=current_admission,
                            study_record=study,
                            batch_record=batch,
                            request=request.to_identity_payload(),
                            registration_inspection=registration_inspection,
                            trigger_repair_close_record_id=(
                                repair_close_record_id
                            ),
                        )
                    except boundary_error as exc:
                        raise TransitionError(str(exc)) from exc
                if any(
                    item is None
                    or item[1].status
                    not in {
                        ReplayObligationStatus.PENDING.value,
                        ReplayObligationStatus.IN_PROGRESS.value,
                    }
                    for item in selected
                ):
                    raise TransitionError(
                        "active replay preflight obligation is not schedulable"
                    )
                protocol_failure = self._replay_scientific_protocol_failure(
                    current,
                    index,
                    request=request,
                )
                if protocol_failure is not None:
                    raise TransitionError(
                        "replay implementation preflight requires an exact "
                        "prospective protocol rebind before recertification: "
                        + protocol_failure
                    )
                from axiom_rift.operations.research_protocol_projection import (
                    ResearchProtocolProjectionError,
                    require_current_research_protocol_activation,
                )

                try:
                    protocol_activation = (
                        require_current_research_protocol_activation(
                            index,
                            authority_manifest_digest=current.get(
                                "authority", {}
                            ).get("manifest_digest"),
                        )
                    )
                except ResearchProtocolProjectionError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                if repair_boundary is not None:
                    assert current_admission is not None
                    accepted_id = current_admission.payload.get(
                        "accepted_replacement_preflight_id"
                    )
                    required_replacement_preflight = (
                        None
                        if accepted_id is None
                        else index.get(
                            "job-implementation-preflight",
                            str(accepted_id),
                        )
                    )
                    if accepted_id is not None and (
                        required_replacement_preflight is None
                    ):
                        raise RecoveryRequired(
                            "post-Repair replay admission lost its "
                            "replacement authority"
                        )
                else:
                    if (
                        type(study.authority_sequence) is not int
                        or type(protocol_activation.authority_sequence) is not int
                        or study.authority_sequence
                        >= protocol_activation.authority_sequence
                    ):
                        raise RecoveryRequired(
                            "missing replay admission is not inside the legacy "
                            "pre-activation recertification boundary"
                        )
                    replacement_triggers: list[IndexRecord] = []
                    for _obligation, head_record in selected:
                        prior = (
                            None
                            if not isinstance(head_record.event_stream, str)
                            or type(head_record.event_sequence) is not int
                            or head_record.event_sequence < 2
                            else index.event_record(
                                head_record.event_stream,
                                head_record.event_sequence - 1,
                            )
                        )
                        resume_evidence = (
                            None
                            if prior is None
                            or prior.kind
                            != "historical-replay-obligation-resume"
                            else prior.payload.get("resume_evidence")
                        )
                        trigger_id = (
                            None
                            if not isinstance(resume_evidence, Mapping)
                            else resume_evidence.get("trigger_record_id")
                        )
                        trigger = (
                            None
                            if not isinstance(trigger_id, str)
                            else index.get(
                                "job-implementation-preflight",
                                trigger_id,
                            )
                        )
                        if trigger is not None and trigger.payload.get(
                            "replacement_for_preflight_id"
                        ) is not None:
                            replacement_triggers.append(trigger)
                    if replacement_triggers:
                        trigger_ids = {
                            record.record_id for record in replacement_triggers
                        }
                        if (
                            len(replacement_triggers) != len(selected)
                            or len(trigger_ids) != 1
                        ):
                            raise TransitionError(
                                "active replay family mixes replacement authorities"
                            )
                        required_replacement_preflight = replacement_triggers[0]
            else:
                replaced_batch_id = (
                    None
                    if replaced_record is None
                    else replaced_record.payload.get("batch_id")
                )
                replaced_study_id = (
                    None
                    if replaced_record is None
                    else replaced_record.payload.get("study_id")
                )
                surface_batch = (
                    None
                    if not isinstance(replaced_batch_id, str)
                    else index.get("batch-open", replaced_batch_id)
                )
                surface_study = (
                    None
                    if not isinstance(replaced_study_id, str)
                    else index.get("study-open", replaced_study_id)
                )
                if (
                    science.get("active_study") is not None
                    or science.get("active_executable") is not None
                    or replaced_record is None
                    or replaced_record.status != "rejected"
                    or replaced_record.payload.get("schema") != PREFLIGHT_SCHEMA
                    or replaced_record.payload.get("mission_id") != mission_id
                    or replaced_record.payload.get("replay_obligation_ids")
                    != list(request.replay_obligation_ids)
                    or surface_batch is None
                    or surface_study is None
                    or any(
                        item is None
                        or item[1].status
                        != ReplayObligationStatus.DEFERRED.value
                        for item in selected
                    )
                    or index.event_head(
                        "replay-job-implementation-preflight-replacement:"
                        + str(replacement)
                    )
                    is not None
                ):
                    raise TransitionError(
                        "replacement replay preflight lacks its current deferral"
                    )
                for selected_item in selected:
                    assert selected_item is not None
                    obligation, deferral_head = selected_item
                    try:
                        current_rejection = (
                            require_current_replacement_preflight_basis(
                                index,
                                obligation=obligation,
                                deferral_head=deferral_head,
                                rejected_preflight_id=replacement,
                            )
                        )
                    except ReplayProjectionError as exc:
                        raise RecoveryRequired(str(exc)) from exc
                    except ReplayTransitionError as exc:
                        raise TransitionError(str(exc)) from exc
                    if current_rejection.record_id != replaced_record.record_id:
                        raise TransitionError(
                            "replacement replay preflight names another rejection"
                        )
            if surface_batch is None or surface_study is None:
                raise TransitionError(
                    "replay implementation preflight lacks its scientific surface"
                )
            try:
                for binding in request.scientific_binding_values():
                    self._preflight_scientific_binding(
                        {"scientific_binding": binding}
                    )
                scientific_surface = derive_replay_job_scientific_surface(
                    request,
                    study_payload=surface_study.payload,
                    batch_payload=surface_batch.payload,
                    artifact_reader=self.evidence.read_verified,
                    registered_batch_executable_ids=(
                        None
                        if replaced_record is None
                        else tuple(
                            replaced_record.payload.get(
                                "executable_ids",
                                (),
                            )
                        )
                    ),
                )
                scientific_surface_hash = (
                    replay_job_scientific_surface_hash(scientific_surface)
                )
            except ReplayJobImplementationPreflightError as exc:
                raise TransitionError(str(exc)) from exc
            if repair_boundary is not None and (
                current_admission is None
                or current_admission.payload.get("scientific_surface")
                != scientific_surface
                or current_admission.payload.get("scientific_surface_hash")
                != scientific_surface_hash
            ):
                raise TransitionError(
                    "post-Repair recertification changed the admitted "
                    "scientific surface"
                )
            scientific_candidate = {
                "callable_identity": request.callable_identity,
                "executable_ids": list(request.executable_ids),
                "executable_manifests": [
                    executable.to_identity_payload()
                    for executable in request.executables
                ],
                "implementation_identity": request.implementation_identity,
                "mission_id": request.mission_id,
                "protocol_id": request.protocol_id,
                "replacement_for_preflight_id": replacement,
                "replay_obligation_ids": list(
                    request.replay_obligation_ids
                ),
                "schema": PREFLIGHT_SCHEMA,
                "scientific_surface": scientific_surface,
                "scientific_surface_hash": scientific_surface_hash,
            }
            if replaced_record is not None:
                try:
                    require_replacement_replay_job_scientific_surface(
                        prior_preflight_id=replaced_record.record_id,
                        prior_payload=replaced_record.payload,
                        replacement_payload=scientific_candidate,
                    )
                except ReplayJobImplementationPreflightError as exc:
                    raise TransitionError(str(exc)) from exc
            if required_replacement_preflight is not None:
                trigger_head = (
                    None
                    if not isinstance(
                        required_replacement_preflight.event_stream,
                        str,
                    )
                    else index.event_head(
                        required_replacement_preflight.event_stream
                    )
                )
                if repair_boundary is None:
                    try:
                        require_active_replay_job_replacement_binding(
                            accepted_payload=(
                                required_replacement_preflight.payload
                            ),
                            active_payload=scientific_candidate,
                        )
                    except ReplayJobImplementationPreflightError as exc:
                        raise TransitionError(str(exc)) from exc
                if (
                    required_replacement_preflight.status != "accepted"
                    or trigger_head is None
                    or trigger_head.record_id
                    != required_replacement_preflight.record_id
                ):
                    raise TransitionError(
                        "active replay family lacks its current accepted replacement"
                    )
            result = evaluate_replay_job_implementation_preflight(
                request,
                index=index,
                artifact_reader=self.evidence.read_verified,
                source_root=(self.foundation_root / "src").absolute(),
            )
            try:
                require_durable_replay_job_implementation_preflight(result)
            except ReplayJobImplementationPreflightError as exc:
                raise TransitionError(
                    "replay implementation needs same-identity source repair "
                    "before any durable rejection or scientific transition: "
                    f"{result.reason_code}: {result.failure_detail}"
                ) from exc
            if repair_boundary is not None and not result.accepted:
                raise TransitionError(
                    "post-Repair family recertification failed its independent "
                    f"implementation preflight: {result.reason_code}: "
                    f"{result.failure_detail}"
                )
            payload = {
                **result.to_record_payload(),
                "batch_id": batch_id,
                "scientific_surface": scientific_surface,
                "scientific_surface_hash": scientific_surface_hash,
                "study_id": study_id,
                **(
                    {}
                    if repair_boundary is None
                    else {
                        "repair_close_record_id": (
                            repair_boundary.trigger_repair_close_record_id
                        )
                    }
                ),
            }
            fingerprint = _digest(
                payload,
                domain="replay-job-implementation-preflight",
            )
            preflight_id = f"job-implementation-preflight:{fingerprint}"
            if repair_boundary is not None:
                stream = repair_module.repair_preflight_stream(
                    repair_boundary.trigger_repair_close_record_id
                )
            else:
                stream = (
                    f"replay-job-implementation-preflight-replacement:{replacement}"
                    if replacement is not None
                    else f"replay-job-implementation-preflight-batch:{batch_id}"
                )
            head = index.event_head(stream)
            if repair_boundary is not None and head is not None:
                raise RecoveryRequired(
                    "post-Repair implementation preflight stream is not atomic"
                )
            record = _record(
                kind="job-implementation-preflight",
                record_id=preflight_id,
                subject=(
                    f"Batch:{batch_id}"
                    if isinstance(batch_id, str)
                    else f"Mission:{mission_id}"
                ),
                status=result.status,
                fingerprint=fingerprint,
                payload=payload,
                event_stream=stream,
                event_sequence=1 if head is None else head.sequence + 1,
            )
            admission_record: IndexRecord | None = None
            if result.accepted and registration_inspection is not None:
                if (
                    not isinstance(batch_id, str)
                    or not isinstance(study_id, str)
                    or protocol_activation is None
                ):
                    raise RecoveryRequired(
                        "legacy replay recertification lost its Study, Batch, or protocol"
                    )
                admission_payload = {
                    "accepted_replacement_preflight_id": (
                        None
                        if required_replacement_preflight is None
                        else required_replacement_preflight.record_id
                    ),
                    "authority_manifest_digest": current.get(
                        "authority", {}
                    ).get("manifest_digest"),
                    "batch_id": batch_id,
                    "recertification_preflight_id": preflight_id,
                    "registered_prefix_executable_ids": list(
                        registration_inspection.registered_executable_ids
                    ),
                    "research_protocol_activation_id": (
                        protocol_activation.record_id
                    ),
                    "request": request.to_identity_payload(),
                    "schema": "replay_implementation_admission.v2",
                    "scientific_surface": scientific_surface,
                    "scientific_surface_hash": scientific_surface_hash,
                    "source_closure_authority": dict(
                        result.source_closure_authority or {}
                    ),
                    "study_id": study_id,
                }
                admission_stream = (
                    "replay-implementation-admission-study:" + study_id
                )
                admission_sequence = 1
                if repair_boundary is not None:
                    repair_schema = (
                        repair_module.REPAIR_RECERTIFICATION_ADMISSION_SCHEMA
                    )
                    admission_payload.update(
                        {
                            "predecessor_admission_id": (
                                repair_boundary.predecessor_admission_id
                            ),
                            "repair_close_record_ids": list(
                                repair_boundary.repair_close_record_ids
                            ),
                            "repair_executable_id": (
                                repair_boundary.repair_executable_id
                            ),
                            "repair_job_id": repair_boundary.repair_job_id,
                            "schema": repair_schema,
                            "trigger_repair_close_record_id": (
                                repair_boundary.trigger_repair_close_record_id
                            ),
                        }
                    )
                    admission_stream = (
                        repair_module.repair_admission_stream(study_id)
                    )
                    admission_sequence = (
                        repair_boundary.admission_event_sequence
                    )
                admission_fingerprint = _digest(
                    admission_payload,
                    domain="replay-implementation-admission",
                )
                admission_record = _record(
                    kind="replay-implementation-admission",
                    record_id=(
                        "replay-implementation-admission:"
                        + admission_fingerprint
                    ),
                    subject=f"Study:{study_id}",
                    status="active",
                    fingerprint=admission_fingerprint,
                    payload=admission_payload,
                    event_stream=admission_stream,
                    event_sequence=admission_sequence,
                )
            body = self._body(current)
            if (
                repair_boundary is None
                and not result.accepted
                and isinstance(batch_id, str)
            ):
                body["next_action"] = {
                    "basis_record_id": preflight_id,
                    "kind": "dispose_batch",
                    "batch_id": batch_id,
                }
            return body, [
                record,
                *([] if admission_record is None else [admission_record]),
            ], {
                "admission_id": (
                    None
                    if admission_record is None
                    else admission_record.record_id
                ),
                "preflight_id": preflight_id,
                "reason_code": result.reason_code,
                "status": result.status,
            }

        return self._commit(
            event_kind=(
                "replay_implementation_repair_recertified"
                if repair_close_record_id is not None
                else "replay_job_implementation_preflight_recorded"
            ),
            operation_id=operation_id,
            subject=f"Mission:{request.mission_id}",
            payload={
                "request_identity": request.identity,
                **(
                    {}
                    if repair_close_record_id is None
                    else {"repair_close_record_id": repair_close_record_id}
                ),
            },
            prepare=prepare,
        )

    def declare_job(
        self, *, spec: Mapping[str, Any], operation_id: str
    ) -> TransitionResult:
        self._require_study_close_delivery_guard()
        spec = self._normalize_job_spec(spec)
        self._validate_job_spec(spec)
        external_binding = spec.get("external_dependency_binding")
        if isinstance(external_binding, dict):
            try:
                self.evidence.verify(external_binding["validation_plan_hash"])
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise TransitionError(
                    "external validation plan evidence is absent or corrupt"
                ) from exc
        self._preflight_scientific_binding(spec)
        work_basis = {
            "callable_identity": spec["callable_identity"],
            "component_parity_binding": spec.get("component_parity_binding"),
            "evidence_subject": spec["evidence_subject"],
            "external_dependency_binding": spec.get(
                "external_dependency_binding"
            ),
            "input_hashes": spec["input_hashes"],
            "holdout_binding": spec.get("holdout_binding"),
            "runtime_binding": spec.get("runtime_binding"),
            "scientific_binding": spec.get("scientific_binding"),
            "source_binding": spec.get("source_binding"),
        }

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            return_next_action = _copy(body["next_action"])
            if science["active_mission"] is None:
                raise TransitionError("Job requires an active Mission")
            if science["active_job"] is not None:
                raise TransitionError("another parent Job is active")
            active_batch = science.get("active_batch")
            if isinstance(active_batch, dict):
                batch_record = _index.get("batch-open", active_batch["id"])
                if batch_record is None:
                    raise RecoveryRequired(
                        "active Batch declaration is unavailable at Job declaration"
                    )
                _require_concurrent_family_registration(
                    _index,
                    batch_record=batch_record,
                    evidence_subject=spec["evidence_subject"],
                )
            external_binding = spec.get("external_dependency_binding")
            external_plan: ExternalRecoveryPlan | None = None
            external_plan_records: list[IndexRecord] = []
            if isinstance(external_binding, dict):
                try:
                    external_plan = external_plan_from_binding(external_binding)
                except ExternalDependencyContractError as exc:
                    raise TransitionError(str(exc)) from exc
            scientific_binding = spec.get("scientific_binding")
            protocol_head = _index.event_head("research-protocol:scientific")
            if (
                isinstance(scientific_binding, dict)
                and protocol_head is None
                and self._authority_requires_scientific_adjudication_v2(current)
            ):
                raise TransitionError(
                    "authority requires an active v2 scientific protocol"
                )
            if isinstance(scientific_binding, dict) and protocol_head is not None:
                protocol = _index.get(
                    protocol_head.record_kind, protocol_head.record_id
                )
                if (
                    protocol is None
                    or protocol.kind != "research-protocol-activation"
                    or protocol.status != "active"
                    or protocol.event_sequence != protocol_head.sequence
                    or protocol.payload.get("protocol")
                    != "scientific_adjudication_v2"
                    or protocol.payload.get("authority_manifest_digest")
                    != current.get("authority", {}).get("manifest_digest")
                ):
                    raise RecoveryRequired(
                        "active scientific protocol projection is invalid"
                    )
                if (
                    scientific_binding.get("validator_id")
                    != protocol.payload.get("validator_id")
                ):
                    raise TransitionError(
                        "prospective scientific Job must use the active v2 protocol"
                    )
            try:
                external_plan_records.extend(
                    require_job_admission(
                        engineering_fixture=self.engineering_fixture,
                        current=current,
                        science=science,
                        spec=spec,
                        external_binding=external_binding,
                        external_plan=external_plan,
                        index=_index,
                        record_builder=_record,
                        active_decision_loader=self._active_portfolio_decision,
                    )
                )
            except JobAdmissionAuthorityError as exc:
                raise TransitionError(str(exc)) from exc
            mission_id = science["active_mission"]
            scientific_lineage_material_identity: str | None = None
            lineage_study_id: str | None = None
            lineage_study: IndexRecord | None = None
            if (
                isinstance(scientific_binding, dict)
                and not self.engineering_fixture
            ):
                lineage_study_id = science["active_study"]
                if not isinstance(lineage_study_id, str):
                    evidence_subject = spec["evidence_subject"]
                    trial = (
                        _index.get("trial", evidence_subject["id"])
                        if evidence_subject["kind"] == "Executable"
                        else None
                    )
                    lineage_study_id = (
                        None if trial is None else trial.payload.get("study_id")
                    )
                lineage_study = (
                    None
                    if not isinstance(lineage_study_id, str)
                    else _index.get("study-open", lineage_study_id)
                )
                declared_modes = set(scientific_binding["evidence_modes"])
                if (
                    lineage_study is None
                    or lineage_study.payload.get("mission_id") != mission_id
                    or not declared_modes.issubset(
                        _require_study_evidence_modes(
                            lineage_study.payload.get("question", {})
                        )
                    )
                ):
                    raise TransitionError(
                        "scientific Job evidence modes exceed its Study preregistration"
                    )
                scientific_lineage_material_identity = _require_digest(
                    "scientific Job lineage material",
                    lineage_study.payload.get("material_identity"),
                )
            implementation_manifest = self._require_job_implementation_evidence(
                spec,
                _index=_index,
            )
            replay_admission = (
                None
                if not isinstance(lineage_study_id, str)
                else self._study_replay_implementation_admission(
                    _index,
                    study_id=lineage_study_id,
                    authority_manifest_digest=current.get(
                        "authority", {}
                    ).get("manifest_digest"),
                )
            )
            if (
                lineage_study is not None
                and lineage_study.payload.get("replay_obligation_ids")
                and replay_admission is None
            ):
                raise RecoveryRequired(
                    "replay Job declaration requires a current implementation admission"
                )
            if replay_admission is not None:
                admitted_request = replay_admission.payload.get("request")
                manifests = (
                    None
                    if not isinstance(admitted_request, Mapping)
                    else admitted_request.get("executable_manifests")
                )
                bindings = (
                    None
                    if not isinstance(admitted_request, Mapping)
                    else admitted_request.get("scientific_bindings")
                )
                subject_id = spec["evidence_subject"]["id"]
                subject_trial = _index.get("trial", subject_id)
                subject_manifest = (
                    None
                    if subject_trial is None
                    else subject_trial.payload.get("executable")
                )
                try:
                    member_index = (
                        manifests.index(subject_manifest)
                        if isinstance(manifests, list)
                        else -1
                    )
                except ValueError:
                    member_index = -1
                admitted_binding = (
                    bindings[member_index]
                    if isinstance(bindings, list)
                    and 0 <= member_index < len(bindings)
                    else None
                )
                if (
                    not isinstance(admitted_request, Mapping)
                    or member_index < 0
                    or spec["callable_identity"]
                    != admitted_request.get("callable_identity")
                    or spec["implementation_identity"]
                    != admitted_request.get("implementation_identity")
                    or scientific_binding != admitted_binding
                    or implementation_manifest.get("protocol")
                    != admitted_request.get("protocol_id")
                ):
                    raise TransitionError(
                        "Job differs from the replay implementation admission"
                    )
            component_implementation_hashes: tuple[str, ...] = ()
            source_closure_authority: dict[str, Any] | None = None
            external_observed_development_binding_payload: (
                dict[str, Any] | None
            ) = None
            if _job_requires_current_source_authority(
                engineering_fixture=self.engineering_fixture,
                evidence_subject_kind=spec["evidence_subject"]["kind"],
            ):
                from axiom_rift.research.implementation_closure import (
                    ImplementationClosureError,
                    require_current_job_source_closure,
                    require_job_implementation_closure,
                )

                executable_manifest: dict[str, Any] | None = None
                try:
                    if spec["evidence_subject"]["kind"] == "Executable":
                        subject_trial = _index.get(
                            "trial", spec["evidence_subject"]["id"]
                        )
                        executable_manifest = (
                            None
                            if subject_trial is None
                            else subject_trial.payload.get("executable")
                        )
                        if not isinstance(executable_manifest, dict):
                            raise TransitionError(
                                "Executable Job subject lacks its exact trial manifest"
                            )
                        component_implementation_hashes = (
                            require_job_implementation_closure(
                                executable_manifest=executable_manifest,
                                job_artifact_hashes=implementation_manifest[
                                    "artifact_hashes"
                                ],
                                artifact_reader=self.evidence.read_verified,
                            )
                        )
                    source_closure_hashes = (
                        _job_implementation_source_closure_hashes(
                            implementation_manifest=implementation_manifest,
                            artifact_reader=self.evidence.read_verified,
                        )
                    )
                    if source_closure_hashes:
                        source_closure_authority = (
                            require_current_job_source_closure(
                                callable_identity=spec["callable_identity"],
                                job_artifact_hashes=implementation_manifest[
                                    "artifact_hashes"
                                ],
                                artifact_reader=self.evidence.read_verified,
                                source_root=self.foundation_root / "src",
                                verified_non_source_artifact_hashes=(
                                    component_implementation_hashes
                                ),
                            )
                        )
                        if executable_manifest is not None:
                            closure_payload = parse_canonical(
                                self.evidence.read_verified(
                                    source_closure_hashes[0]
                                )
                            )
                            if not isinstance(closure_payload, Mapping):
                                raise ImplementationClosureError(
                                    "Job source closure payload is malformed"
                                )
                            external_binding_value = (
                                external_observed_development_job_binding(
                                    executable_id=spec["evidence_subject"][
                                        "id"
                                    ],
                                    executable_manifest=executable_manifest,
                                    job_spec=spec,
                                    source_closure_dependencies=(
                                        closure_payload["dependencies"]
                                    ),
                                )
                            )
                            if external_binding_value is not None:
                                verify_external_observed_development_job_prefixes(
                                    repository_root=self.foundation_root,
                                    binding=external_binding_value,
                                )
                                external_observed_development_binding_payload = (
                                    external_binding_value.to_payload()
                                )
                    else:
                        raise TransitionError(
                            "prospective production Job requires one exact "
                            "current source closure; historical implementation "
                            "exemptions are read-only evidence, not execution authority"
                        )
                except (
                    ExternalObservedDevelopmentJobBindingError,
                    ImplementationClosureError,
                ) as exc:
                    raise TransitionError(str(exc)) from exc
            candidate_execution_context: dict[str, Any] | None = None
            active_executable = science.get("active_executable")
            if (
                isinstance(active_executable, str)
                and spec["evidence_subject"]
                == {"kind": "Executable", "id": active_executable}
            ):
                candidate_head = _index.event_head(
                    f"candidate:{active_executable}"
                )
                candidate = (
                    None
                    if candidate_head is None
                    else _index.get(
                        candidate_head.record_kind,
                        candidate_head.record_id,
                    )
                )
                expected_candidate = (
                    ("engineering-executable-fixture", "bound_fixture")
                    if self.engineering_fixture
                    else ("candidate", "frozen")
                )
                if candidate is None or (
                    candidate.kind,
                    candidate.status,
                ) != expected_candidate:
                    raise TransitionError(
                        "candidate Job lacks its current frozen activation"
                    )
                executable_payload = candidate.payload.get("executable")
                candidate_source_bindings = candidate.payload.get(
                    "source_bindings"
                )
                candidate_source_ids = (
                    None
                    if not isinstance(executable_payload, Mapping)
                    else executable_payload.get("source_contracts")
                )
                if (
                    not isinstance(candidate_source_ids, list)
                    or any(type(source_id) is not str for source_id in candidate_source_ids)
                    or candidate_source_ids != sorted(set(candidate_source_ids))
                    or not isinstance(candidate_source_bindings, list)
                    or any(
                        not isinstance(binding, Mapping)
                        or binding.get("source_contract_id") not in candidate_source_ids
                        for binding in candidate_source_bindings
                    )
                    or sorted(
                        binding["source_contract_id"]
                        for binding in candidate_source_bindings
                    )
                    != candidate_source_ids
                ):
                    raise RecoveryRequired(
                        "candidate source bindings are malformed"
                    )
                candidate_source_job = spec.get("source_binding")
                if isinstance(candidate_source_job, Mapping):
                    target_source_id = candidate_source_job.get(
                        "source_contract_id"
                    )
                    if target_source_id not in candidate_source_ids:
                        raise TransitionError(
                            "candidate source Job must target one of its frozen SourceContracts"
                        )
                    if _index.event_head(
                        f"source-authority:{target_source_id}"
                    ) is not None:
                        raise TransitionError(
                            "audit-invalidated candidate source requires a new SourceContract identity"
                        )
                    source_state_record_ids: list[str] = []
                    for source_id in candidate_source_ids:
                        source_head = _index.event_head(f"source:{source_id}")
                        source_state = (
                            None
                            if source_head is None
                            else _index.get(
                                source_head.record_kind,
                                source_head.record_id,
                            )
                        )
                        if (
                            source_state is None
                            or source_state.kind != "source-state"
                            or source_state.subject != f"Source:{source_id}"
                            or source_state.event_sequence
                            != source_head.sequence
                        ):
                            raise RecoveryRequired(
                                "candidate source Job lacks its exact current source state"
                            )
                        source_state_record_ids.append(
                            source_state.record_id
                        )
                    candidate_execution_context = {
                        "candidate_activation_id": candidate.record_id,
                        "executable_id": active_executable,
                        "schema": "candidate_source_job_execution_context.v1",
                        "source_state_record_ids": sorted(
                            source_state_record_ids
                        ),
                        "target_source_contract_id": target_source_id,
                    }
                else:
                    try:
                        source_snapshot = current_runtime_source_snapshot(
                            index=_index,
                            source_contract_ids=tuple(candidate_source_ids),
                            require_runtime_source=self._require_runtime_source,
                        )
                        candidate_execution_context = (
                            candidate_job_execution_context(
                                index=_index,
                                candidate=candidate,
                                current=source_snapshot,
                                runtime_binding=(
                                    spec.get("runtime_binding")
                                    if isinstance(
                                        spec.get("runtime_binding"), Mapping
                                    )
                                    else None
                                ),
                            )
                        )
                    except RuntimeSuccessAuthorityError as exc:
                        raise TransitionError(str(exc)) from exc
            try:
                observed_binding_value = scientific_observed_development_job_binding(
                    foundation_root=self.foundation_root,
                    input_hashes=spec["input_hashes"],
                    lineage_material_identity=(
                        scientific_lineage_material_identity
                    ),
                )
            except ObservedDevelopmentBindingError as exc:
                raise TransitionError(str(exc)) from exc
            observed_development_binding = (
                None
                if observed_binding_value is None
                else observed_binding_value.to_payload()
            )
            implementation_source_authority = (
                None
                if source_closure_authority is None
                else {
                    "authority": source_closure_authority,
                    "schema": "job_implementation_source_binding.v1",
                }
            )
            identity_plan = build_job_identity_plan(
                spec=spec,
                work_basis=work_basis,
                mission_id=mission_id,
                candidate_execution_context=candidate_execution_context,
                observed_development_binding=observed_development_binding,
                implementation_source_authority=implementation_source_authority,
                external_observed_development_binding=(
                    external_observed_development_binding_payload
                ),
            )
            bound_work_basis = dict(identity_plan.bound_work_basis)
            job_hash = identity_plan.job_hash
            job_id = identity_plan.job_id
            work_fingerprint = identity_plan.work_fingerprint
            success_fingerprint = identity_plan.success_fingerprint
            cached_success = _index.get("job-success-cache", success_fingerprint)
            if cached_success is not None:
                completion_id = cached_success.payload.get("completion_record_id")
                completion = (
                    None
                    if not isinstance(completion_id, str)
                    else _index.get("job-completed", completion_id)
                )
                if completion is None:
                    raise RecoveryRequired("successful Job cache is inconsistent")
                try:
                    require_cached_success_binding(
                        cached_payload=cached_success.payload,
                        completion_status=completion.status,
                        completion_payload=completion.payload,
                        spec=spec,
                        mission_id=mission_id,
                        candidate_execution_context=candidate_execution_context,
                        observed_development_binding=observed_development_binding,
                        implementation_source_authority=(
                            implementation_source_authority
                        ),
                        external_observed_development_binding=(
                            external_observed_development_binding_payload
                        ),
                    )
                except JobCacheAuthorityError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                if observed_binding_value is not None:
                    try:
                        verify_observed_development_prefix_artifact(
                            foundation_root=self.foundation_root,
                            binding=observed_binding_value,
                        )
                    except ObservedDevelopmentBindingError as exc:
                        raise RecoveryRequired(
                            "observed development cache source bytes are unavailable "
                            "or inconsistent"
                        ) from exc
                self._require_reusable_success_outputs(
                    completion=completion, spec=spec
                )
                return body, [], {
                    "disposition": "reuse_success",
                    "completion_record_id": completion.record_id,
                    "job_id": completion.payload["job_id"],
                }
            try:
                retry_admission = prepare_job_retry_admission(
                    index=_index,
                    mission_id=mission_id,
                    initiative_id=science.get("active_initiative"),
                    study_id=science.get("active_study"),
                    batch_id=(
                        active_batch.get("id")
                        if isinstance(active_batch, Mapping)
                        else None
                    ),
                    spec=spec,
                    candidate_execution_context=candidate_execution_context,
                    implementation_manifest=implementation_manifest,
                    current_job_id=job_id,
                    current_job_hash=job_hash,
                    work_fingerprint=work_fingerprint,
                    read_evidence=self.evidence.read_verified,
                    verify_evidence=self.evidence.verify,
                    evidence_path=self.evidence.verified_path,
                    validation_registry=self.validation_registry,
                    engineering_fixture=self.engineering_fixture,
                )
            except JobRetryAdmissionSpecificationError as exc:
                raise TransitionError(str(exc)) from exc
            except JobRetryAdmissionIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except JobRetryAdmissionRejected as exc:
                raise IdenticalFailedRetryError(str(exc)) from exc
            retry_family = retry_admission.family
            retry_basis_records = list(retry_admission.basis_records)
            attempt_head = _index.event_head(
                f"job-attempt:{work_fingerprint}"
            )
            evidence_subject = spec["evidence_subject"]
            active_by_kind = {
                "Mission": science["active_mission"],
                "Initiative": science["active_initiative"],
                "Study": science["active_study"],
                "Executable": science["active_executable"],
            }
            if evidence_subject["kind"] == "Executable":
                subject_exists = (
                    _index.get("trial", evidence_subject["id"]) is not None
                    or _index.get("engineering-evaluation-fixture", evidence_subject["id"])
                    is not None
                    or active_by_kind["Executable"] == evidence_subject["id"]
                )
            elif evidence_subject["kind"] == "Release":
                subject_exists = (
                    _index.get("release-declared", evidence_subject["id"]) is not None
                )
            else:
                subject_exists = active_by_kind[evidence_subject["kind"]] == evidence_subject["id"]
            if not subject_exists:
                raise TransitionError("Job evidence subject is not active or registered")
            reservation_records: list[IndexRecord] = []
            batch = science["active_batch"]
            if isinstance(batch, dict):
                batch_record = _index.get("batch-open", batch["id"])
                if batch_record is None:
                    raise TransitionError("active Batch declaration is unavailable")
                budget_head = _index.event_head(f"batch-budget:{batch['id']}")
                previous_budget = (
                    {"compute_seconds": 0, "wall_seconds": 0}
                    if budget_head is None
                    else _index.get(budget_head.record_kind, budget_head.record_id).payload
                )
                next_compute = previous_budget["compute_seconds"] + spec["budget"]["compute_seconds"]
                next_wall = previous_budget["wall_seconds"] + spec["budget"]["wall_seconds"]
                frozen_spec = batch_record.payload["spec"]
                if (
                    next_compute > frozen_spec["max_compute_seconds"]
                    or next_wall > frozen_spec["max_wall_seconds"]
                ):
                    raise TransitionError("Job exceeds the frozen Batch compute or wall budget")
                reservation_id = canonical_digest(
                    domain="batch-budget-reservation",
                    payload={"batch_id": batch["id"], "job_id": job_id},
                )
                reservation_records.append(
                    _record(
                        kind="batch-budget-reservation",
                        record_id=reservation_id,
                        subject=f"Batch:{batch['id']}",
                        status="reserved",
                        fingerprint=job_hash,
                        payload={
                            "compute_seconds": next_compute,
                            "wall_seconds": next_wall,
                            "job_id": job_id,
                        },
                        event_stream=f"batch-budget:{batch['id']}",
                        event_sequence=1 if budget_head is None else budget_head.sequence + 1,
                    )
                )
            try:
                retry_family_record = build_retry_family_declaration_record(
                    admission=retry_admission,
                    job_id=job_id,
                    job_hash=job_hash,
                    work_fingerprint=work_fingerprint,
                )
            except JobRetryAdmissionSpecificationError as exc:
                raise TransitionError(str(exc)) from exc
            science["active_job"] = {
                "id": job_id,
                "hash": job_hash,
                "return_next_action": return_next_action,
                "status": "declared",
                "resume_action": spec["resume_action"],
            }
            body["next_action"] = {"kind": "issue_job_permit", "job_id": job_id}
            authorization = self._authorization(
                kind=SubjectKind.JOB, subject_id=job_id, semantic_hash=job_hash
            )
            self._bind_authorization(body, authorization)
            record = _record(
                kind="job-declared",
                record_id=job_id,
                subject=f"Job:{job_id}",
                status="declared",
                fingerprint=job_hash,
                payload={
                    "spec": dict(spec),
                    "mission_id": science["active_mission"],
                    "initiative_id": science["active_initiative"],
                    "study_id": science["active_study"],
                    "batch_id": None if not isinstance(batch, dict) else batch["id"],
                    "candidate_execution_context": (
                        candidate_execution_context
                    ),
                    **(
                        {
                            "observed_development_binding": (
                                observed_development_binding
                            )
                        }
                        if observed_development_binding is not None
                        else {}
                    ),
                    **(
                        {
                            "external_observed_development_binding": (
                                external_observed_development_binding_payload
                            )
                        }
                        if external_observed_development_binding_payload
                        is not None
                        else {}
                    ),
                    "return_next_action": return_next_action,
                    "retry_family": retry_family.payload(),
                    "retry_family_fingerprint": retry_family.fingerprint,
                    "retry_basis_record_ids": sorted(
                        record.record_id for record in retry_basis_records
                    ),
                    "success_fingerprint": success_fingerprint,
                    "work_fingerprint": work_fingerprint,
                    **(
                        {
                            "component_implementation_hashes": list(
                                component_implementation_hashes
                            )
                        }
                        if component_implementation_hashes
                        else {}
                    ),
                    **(
                        {
                            "source_closure_authority": (
                                source_closure_authority
                            )
                        }
                        if source_closure_authority is not None
                        else {}
                    ),
                },
                event_stream=f"job-attempt:{work_fingerprint}",
                event_sequence=(
                    1 if attempt_head is None else attempt_head.sequence + 1
                ),
            )
            return body, [
                *external_plan_records,
                *retry_basis_records,
                *reservation_records,
                record,
                retry_family_record,
            ], {
                "job_id": job_id,
                "job_hash": job_hash,
            }

        return self._commit(
            event_kind="job_declared",
            operation_id=operation_id,
            subject=(
                f"{spec['evidence_subject']['kind']}:{spec['evidence_subject']['id']}"
            ),
            payload={"job_spec_hash": _digest(dict(spec), domain="job-spec")},
            prepare=prepare,
            read_only_when_unchanged=True,
        )

    def issue_permit(
        self,
        *,
        kind: PermitKind,
        subject_kind: SubjectKind,
        subject_id: str,
        input_hash: str,
        actions: tuple[str, ...],
        scope: tuple[str, ...],
        expires_at_utc: str,
        one_shot: bool,
        operation_id: str,
    ) -> Permit:
        if self.permit_authority is None:
            raise PermitError("permit authority is unavailable")
        _require_digest("input_hash", input_hash)
        if not isinstance(kind, PermitKind) or not isinstance(subject_kind, SubjectKind):
            raise PermitError("permit kind and subject kind must be typed")
        allowed_subjects, allowed_actions = _PERMIT_RULES[kind]
        if subject_kind not in allowed_subjects:
            raise PermitError(f"{kind.value} permit cannot bind {subject_kind.value}")
        if not actions or not set(actions).issubset(allowed_actions):
            raise PermitError(f"{kind.value} permit contains a forbidden action")
        if kind in {
            PermitKind.SOURCE,
            PermitKind.STUDY,
            PermitKind.BATCH,
            PermitKind.JOB,
            PermitKind.REPAIR,
            PermitKind.HOLDOUT,
            PermitKind.RELEASE,
        } and not one_shot:
            raise PermitError(f"{kind.value} permits must be one-shot")
        if kind is PermitKind.RUNTIME and one_shot:
            raise PermitError("RuntimePermit uses reusable running-Job lease semantics")

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            subject = self._current_subject(current, subject_kind, subject_id)
            if kind is PermitKind.STUDY and not self.engineering_fixture:
                next_action = current.get("next_action", {})
                decision_id = next_action.get("decision_id")
                snapshot_id = next_action.get("portfolio_snapshot_id")
                axis_identity = next_action.get("target_axis_identity")
                architecture_identity = next_action.get(
                    "architecture_chassis_identity"
                )
                baseline_id = next_action.get("baseline_executable_id")
                decision = (
                    None
                    if not isinstance(decision_id, str)
                    else self._active_portfolio_decision(_index, decision_id)
                )
                snapshot = (
                    None
                    if not isinstance(snapshot_id, str)
                    else _index.get("portfolio-snapshot", snapshot_id)
                )
                required_scope = {
                    "study",
                    f"decision:{decision_id}",
                    f"axis:{axis_identity}",
                    f"baseline:{baseline_id}",
                    f"chassis:{architecture_identity}",
                    f"snapshot:{snapshot_id}",
                }
                if (
                    next_action.get("kind") != "execute_portfolio_decision"
                    or not isinstance(architecture_identity, str)
                    or not isinstance(baseline_id, str)
                    or decision is None
                    or snapshot is None
                    or decision.payload.get("portfolio_snapshot_id") != snapshot_id
                    or not required_scope.issubset(scope)
                ):
                    raise PermitError(
                        "StudyPermit requires an accepted current Portfolio Decision"
                    )
            if kind in {PermitKind.RUNTIME, PermitKind.HOLDOUT}:
                if subject_kind is not SubjectKind.EXECUTABLE:
                    raise PermitError("runtime and holdout permits must bind an Executable")
                candidate_head = _index.event_head(f"candidate:{subject_id}")
                candidate = (
                    None
                    if candidate_head is None
                    else _index.get(candidate_head.record_kind, candidate_head.record_id)
                )
                expected = (
                    ("engineering-executable-fixture", "bound_fixture")
                    if self.engineering_fixture
                    else ("candidate", "frozen")
                )
                candidate_bound = (
                    candidate is not None
                    and (candidate.kind, candidate.status) == expected
                )
                if not candidate_bound:
                    raise PermitError("runtime or holdout permit requires a frozen candidate")
                if kind is PermitKind.HOLDOUT:
                    holdout_id = f"holdout:{input_hash}"
                    seal = _index.get("holdout-seal", holdout_id)
                    required_holdout_scope = {
                        holdout_id,
                        f"candidate:{candidate.record_id}",
                        f"executable:{subject_id}",
                    }
                    if (
                        seal is None
                        or seal.status != "sealed_unrevealed"
                        or not required_holdout_scope.issubset(scope)
                        or current["scientific"].get("active_holdout_evaluation")
                        is not None
                        or (
                            current["scientific"].get("required_future_holdout_id")
                            is not None
                            and current["scientific"]["required_future_holdout_id"]
                            != holdout_id
                        )
                        or _index.event_head(f"holdout-reveal:{holdout_id}") is not None
                    ):
                        raise PermitError(
                            "HoldoutPermit requires one current unrevealed semantic seal"
                        )
            if kind is PermitKind.SOURCE:
                source_scopes = [item[7:] for item in scope if item.startswith("source:")]
                if not source_scopes:
                    raise PermitError("SourcePermit must name at least one source scope")
                for source_id in source_scopes:
                    self._require_source_authority_for_actions(
                        _index,
                        source_id,
                        actions=actions,
                        error_type=PermitError,
                    )
            if kind is PermitKind.RUNTIME:
                from axiom_rift.runtime.guards import EvidenceDepth

                depth_scopes = [item for item in scope if item.startswith("depth:")]
                allowed_depth_scopes = {
                    f"depth:{EvidenceDepth.EXECUTION_PROOF.value}",
                    f"depth:{EvidenceDepth.MATERIALIZATION.value}",
                }
                if len(depth_scopes) != 1 or depth_scopes[0] not in allowed_depth_scopes:
                    raise PermitError(
                        "RuntimePermit requires one execution_proof or materialization depth"
                    )
                required_depth_by_action = {
                    "run_execution_proof": f"depth:{EvidenceDepth.EXECUTION_PROOF.value}",
                    "materialize": f"depth:{EvidenceDepth.MATERIALIZATION.value}",
                }
                if any(
                    action in required_depth_by_action
                    and required_depth_by_action[action] != depth_scopes[0]
                    for action in actions
                ):
                    raise PermitError("RuntimePermit action and evidence depth conflict")
            if kind is PermitKind.RELEASE:
                declaration = _index.get("release-declared", subject_id)
                if (
                    declaration is None
                    or declaration.status != "declared"
                    or declaration.fingerprint != input_hash
                ):
                    raise PermitError("ReleasePermit requires the exact Release declaration")
            permit = self.permit_authority.issue(
                kind=kind,
                subject=subject,
                input_hash=input_hash,
                actions=actions,
                scope=scope,
                issued_at_utc=self.clock(),
                expires_at_utc=expires_at_utc,
                one_shot=one_shot,
                audit_revision=current["revision"],
            )
            record = _record(
                kind="permit-issued",
                record_id=permit.permit_id,
                subject=f"Permit:{permit.permit_id}",
                status="issued",
                fingerprint=permit.permit_id,
                payload=permit.payload(),
                event_stream=f"permit:{permit.permit_id}",
                event_sequence=1,
            )
            return self._body(current), [record], {"permit": permit.payload()}

        result = self._commit(
            event_kind="permit_issued",
            operation_id=operation_id,
            subject=f"{subject_kind.value}:{subject_id}",
            payload={
                "kind": kind.value,
                "subject_kind": subject_kind.value,
                "subject_id": subject_id,
                "input_hash": input_hash,
                "actions": list(actions),
                "scope": list(scope),
                "expires_at_utc": expires_at_utc,
                "one_shot": one_shot,
            },
            prepare=prepare,
        )
        return Permit.from_mapping(result.result["permit"])

    def revoke_permit(
        self,
        *,
        permit_id: str,
        reason: str,
        operation_id: str,
    ) -> TransitionResult:
        _require_digest("permit_id", permit_id)
        _require_ascii("reason", reason)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            if self._permit_status(index, permit_id) is not PermitStatus.ISSUED:
                raise PermitError("only an issued permit can be revoked")
            issued = index.get("permit-issued", permit_id)
            if issued is None:
                raise PermitError("permit issue record is absent")
            record_id = canonical_digest(
                domain="permit-revocation",
                payload={"permit_id": permit_id, "reason": reason},
            )
            record = _record(
                kind="permit-revoked",
                record_id=record_id,
                subject=f"Permit:{permit_id}",
                status="revoked",
                fingerprint=permit_id,
                payload={"reason": reason, "issued_kind": issued.payload["kind"]},
                event_stream=f"permit:{permit_id}",
                event_sequence=2,
            )
            return self._body(current), [record], {"permit_id": permit_id}

        return self._commit(
            event_kind="permit_revoked",
            operation_id=operation_id,
            subject=f"Permit:{permit_id}",
            payload={"permit_id": permit_id, "reason": reason},
            prepare=prepare,
        )

    def freeze_candidate(
        self,
        *,
        executable: Any,
        evidence_refs: tuple[str, ...],
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.core.identity import ExecutableSpec

        self._require_study_close_delivery_guard()
        if not isinstance(executable, ExecutableSpec):
            raise TransitionError("candidate requires a frozen ExecutableSpec")
        executable_id = executable.identity
        executable_hash = executable_id.removeprefix("executable:")
        _require_digest("executable_hash", executable_hash)
        if len(set(evidence_refs)) != len(evidence_refs):
            raise TransitionError("candidate evidence references must be unique")
        for reference in evidence_refs:
            _require_ascii("candidate evidence reference", reference)
        evidence_refs = tuple(sorted(evidence_refs))
        candidate_basis_hash = canonical_digest(
            domain="candidate",
            payload={
                "executable_id": executable_id,
                "evidence_refs": list(evidence_refs),
            },
        )

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science["active_mission"] is None:
                raise TransitionError("candidate freeze requires an active Mission")
            if body["next_action"].get("kind") in {
                "record_research_intake",
                "diagnose_study",
                "review_architecture",
            }:
                raise TransitionError(
                    "candidate freeze cannot bypass research direction"
                )
            candidate_id = "candidate:" + canonical_digest(
                domain="mission-candidate",
                payload={
                    "evidence_refs": list(evidence_refs),
                    "executable_id": executable_id,
                    "mission_id": science["active_mission"],
                },
            )
            if science["active_executable"] is not None:
                raise TransitionError("another Executable is active")
            if any(
                science[name] is not None
                for name in ("active_study", "active_batch", "active_job", "active_repair")
            ):
                raise TransitionError("candidate freeze requires disposed scientific work")
            if (
                science["holdout_reveals"] > 0
                and science.get("required_future_holdout_id") is None
            ):
                raise TransitionError(
                    "post-holdout candidate work requires genuinely later sealed data"
                )
            post_holdout_receipt = None
            if science["holdout_reveals"] > 0:
                trial = _index.get("trial", executable_id)
                material_identity = (
                    None if trial is None else trial.payload.get("material_identity")
                )
                development_material = (
                    None
                    if not isinstance(material_identity, str)
                    else _index.get("development-material", material_identity)
                )
                receipt_id = (
                    None
                    if development_material is None
                    else development_material.payload.get(
                        "post_holdout_development_id"
                    )
                )
                post_holdout_receipt = (
                    None
                    if not isinstance(receipt_id, str)
                    else _index.get("post-holdout-development", receipt_id)
                )
                receipt_payload = (
                    {}
                    if post_holdout_receipt is None
                    else post_holdout_receipt.payload
                )
                if (
                    trial is None
                    or trial.payload.get("mission_id") != science["active_mission"]
                    or trial.payload.get("executable")
                    != executable.to_identity_payload()
                    or post_holdout_receipt is None
                    or post_holdout_receipt.status != "accepted"
                    or post_holdout_receipt.subject
                    != f"Material:{material_identity}"
                    or receipt_payload.get("holdout_id")
                    != science["required_future_holdout_id"]
                    or receipt_payload.get("mission_id")
                    != science["active_mission"]
                    or executable.data_contract != f"data:{material_identity}"
                    or executable.split_contract
                    != f"split:{receipt_payload.get('split_identity')}"
                    or development_material is None
                    or development_material.status != "accepted"
                    or development_material.subject
                    != f"Mission:{science['active_mission']}"
                    or development_material.payload.get(
                        "post_holdout_development_id"
                    )
                    != receipt_id
                    or development_material.payload.get("material_receipt_hash")
                    != receipt_payload.get("material_receipt_hash")
                    or post_holdout_receipt.authority_sequence is None
                    or trial.authority_sequence is None
                    or trial.authority_sequence
                    <= post_holdout_receipt.authority_sequence
                ):
                    raise TransitionError(
                        "post-holdout candidate work requires its durable future-development receipt"
                    )
            source_bindings: list[dict[str, Any]] = []
            for source_id in executable.source_contracts:
                source_state = self._require_runtime_source(_index, source_id)
                source_bindings.append(
                    {
                        "source_contract_id": source_id,
                        "eligibility_receipt_id": source_state.payload[
                            "evidence_receipt_id"
                        ],
                        "mapping_identity": source_state.payload["mapping_identity"],
                        "source_state_record_id": source_state.record_id,
                    }
                )
            if not self.engineering_fixture:
                if not evidence_refs:
                    raise TransitionError("candidate freeze requires bound evidence")
                scientific_depths: set[str] = set()
                confirmation_eligible = False
                for reference in evidence_refs:
                    evidence = _index.get("job-completed", reference)
                    if evidence is None or evidence.status != "success":
                        raise TransitionError(
                            "candidate evidence must name a successful Job completion"
                        )
                    if (
                        post_holdout_receipt is not None
                        and (
                            evidence.authority_sequence is None
                            or evidence.authority_sequence
                            <= post_holdout_receipt.authority_sequence
                        )
                    ):
                        raise TransitionError(
                            "post-holdout candidate evidence must postdate future-development authority"
                        )
                    declaration = _index.get(
                        "job-declared", evidence.payload.get("job_id", "")
                    )
                    if declaration is None:
                        raise TransitionError("candidate evidence Job declaration is absent")
                    scientific = evidence.payload.get("scientific")
                    effective_scope = (
                        None
                        if not isinstance(scientific, dict)
                        else _effective_completion_scope(_index, evidence)
                    )
                    if (
                        not isinstance(scientific, dict)
                        or effective_scope is None
                        or effective_scope.scientific_eligible is not True
                        or scientific.get("executable_id") != executable_id
                        or scientific.get("evidence_depth")
                        not in {"discovery", "confirmation"}
                    ):
                        raise TransitionError(
                            "candidate evidence is not validator-derived scientific evidence"
                        )
                    scientific_depths.add(scientific["evidence_depth"])
                    if scientific["evidence_depth"] == "confirmation":
                        confirmation_eligible = (
                            confirmation_eligible
                            or effective_scope.candidate_eligible is True
                        )
                    declared_subject = declaration.payload["spec"]["evidence_subject"]
                    if declared_subject != {
                        "kind": "Executable",
                        "id": executable_id,
                    } or declaration.payload["mission_id"] != science["active_mission"]:
                        raise TransitionError(
                            "candidate evidence is not bound to this Executable and Mission"
                        )
                if scientific_depths != {"discovery", "confirmation"}:
                    raise TransitionError(
                        "candidate freeze requires discovery and confirmation evidence"
                    )
                if not confirmation_eligible:
                    raise TransitionError(
                        "confirmation validator did not authorize candidate promotion"
                    )
            science["active_executable"] = executable_id
            body["next_action"] = {
                "kind": "plan_candidate_bound_evidence",
                "executable_id": executable_id,
            }
            candidate_head = _index.event_head(f"candidate:{executable_id}")
            candidate_sequence = (
                1 if candidate_head is None else candidate_head.sequence + 1
            )
            activation_hash = _digest(
                {
                    "candidate_id": candidate_id,
                    "candidate_sequence": candidate_sequence,
                    "executable_hash": executable_hash,
                    "mission_id": science["active_mission"],
                },
                domain="candidate-authorization",
            )
            authorization = self._authorization(
                kind=SubjectKind.EXECUTABLE,
                subject_id=executable_id,
                semantic_hash=activation_hash,
                epoch=candidate_sequence,
            )
            self._bind_authorization(body, authorization)
            status = "bound_fixture" if self.engineering_fixture else "frozen"
            record = _record(
                kind=(
                    "engineering-executable-fixture"
                    if self.engineering_fixture
                    else "candidate"
                ),
                record_id=candidate_id,
                subject=f"Executable:{executable_id}",
                status=status,
                fingerprint=executable_hash,
                payload={
                    "evidence_refs": list(evidence_refs),
                    "executable": executable.to_identity_payload(),
                    "mission_id": science["active_mission"],
                    "source_bindings": source_bindings,
                    "scientific_eligible": not self.engineering_fixture,
                    "scheduler_eligible": False,
                },
                event_stream=f"candidate:{executable_id}",
                event_sequence=candidate_sequence,
            )
            return body, [record], {
                "candidate_id": candidate_id,
                "executable_id": executable_id,
                "fixture": self.engineering_fixture,
            }

        return self._commit(
            event_kind="candidate_frozen",
            operation_id=operation_id,
            subject=f"Executable:{executable_id}",
            payload={
                "candidate_basis_hash": candidate_basis_hash,
                "executable_id": executable_id,
                "executable_hash": executable_hash,
                "evidence_refs": list(evidence_refs),
                "engineering_fixture": self.engineering_fixture,
            },
            prepare=prepare,
        )

    def dispose_candidate(
        self,
        *,
        disposition: str,
        reason: str,
        operation_id: str,
    ) -> TransitionResult:
        _require_ascii("disposition", disposition)
        _require_ascii("reason", reason)
        if disposition not in {
            "rejected",
            "returned_to_library",
            "superseded",
            "invalidated",
        }:
            raise TransitionError("candidate disposition is not typed")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            executable_id = science["active_executable"]
            if executable_id is None:
                raise TransitionError("no active candidate Executable")
            if science["active_job"] is not None or science["active_repair"] is not None:
                raise TransitionError("candidate disposition cannot bypass active work")
            pending_gap = body.get("next_action")
            engineering_gap = (
                pending_gap
                if isinstance(pending_gap, Mapping)
                and pending_gap.get("kind")
                == "resolve_candidate_engineering_gap"
                else None
            )
            if engineering_gap is not None:
                if (
                    engineering_gap.get("executable_id") != executable_id
                    or not isinstance(
                        engineering_gap.get("completion_record_id"), str
                    )
                    or index.get(
                        "job-completed",
                        engineering_gap["completion_record_id"],
                    )
                    is None
                ):
                    raise RecoveryRequired(
                        "candidate engineering-gap resolution lost its completion"
                    )
                if engineering_gap.get("successor_scope") is not None and (
                    disposition != "invalidated"
                    or reason
                    != "engineering_requires_scientific_change"
                ):
                    raise TransitionError(
                        "scientific-change engineering gap must invalidate the frozen candidate"
                    )
            candidate_head = index.event_head(f"candidate:{executable_id}")
            candidate = (
                None
                if candidate_head is None
                else index.get(candidate_head.record_kind, candidate_head.record_id)
            )
            if candidate is None:
                raise TransitionError("candidate binding is unavailable")
            if science.get("active_release") is not None:
                raise TransitionError("an active Release must be disposed before its candidate")
            passed_holdout = index.get("candidate-holdout", candidate.record_id)
            if passed_holdout is not None and (
                passed_holdout.status != "passed"
                or passed_holdout.payload.get("mission_id")
                != science["active_mission"]
                or passed_holdout.payload.get("executable_id") != executable_id
            ):
                raise TransitionError("candidate holdout projection is inconsistent")
            science["active_executable"] = None
            self._drop_authorization(body, SubjectKind.EXECUTABLE, executable_id)
            if passed_holdout is not None:
                science["required_future_holdout_id"] = None
                body["next_action"] = {
                    "kind": "await_new_future_holdout_data",
                    "predecessor_holdout_id": passed_holdout.payload["holdout_id"],
                }
            elif science["active_initiative"] is None:
                body["next_action"] = {
                    "kind": "open_initiative",
                    "mission_id": science["active_mission"],
                }
            else:
                portfolio_head = index.event_head(
                    f"portfolio:{science['active_mission']}"
                )
                snapshot = (
                    None
                    if portfolio_head is None
                    else index.get(portfolio_head.record_kind, portfolio_head.record_id)
                )
                if snapshot is None or snapshot.kind != "portfolio-snapshot":
                    raise TransitionError(
                        "candidate disposition in an Initiative requires a current Portfolio snapshot"
                    )
                body["next_action"] = {
                    "kind": "portfolio_decision",
                    "portfolio_snapshot_id": snapshot.record_id,
                }
            disposition_identity = {
                "candidate_id": candidate.record_id,
                "disposition": disposition,
                "reason": reason,
            }
            disposition_payload = {
                "candidate_id": candidate.record_id,
                "executable_id": executable_id,
                "mission_id": science["active_mission"],
                "reason": reason,
            }
            if engineering_gap is not None:
                disposition_identity[
                    "engineering_gap_completion_record_id"
                ] = engineering_gap["completion_record_id"]
                disposition_payload["engineering_gap"] = dict(
                    engineering_gap
                )
            record_id = canonical_digest(
                domain="candidate-disposition",
                payload=disposition_identity,
            )
            record = _record(
                kind="candidate-disposition",
                record_id=record_id,
                subject=f"Executable:{executable_id}",
                status=disposition,
                fingerprint=candidate.fingerprint,
                payload=disposition_payload,
                event_stream=f"candidate:{executable_id}",
                event_sequence=candidate_head.sequence + 1,
            )
            return body, [record], {"executable_id": executable_id}

        return self._commit(
            event_kind="candidate_disposed",
            operation_id=operation_id,
            subject="Executable:active",
            payload={"disposition": disposition, "reason": reason},
            prepare=prepare,
        )

    def _derive_release_basis_locked(
        self,
        *,
        index: LocalIndex,
        control: Mapping[str, Any],
        executable_id: str,
        candidate_id: str,
        completion_record_ids: tuple[str, ...],
        allow_engineering_fixture: bool = False,
    ) -> dict[str, Any]:
        """Derive Release claims only from current runtime Job completions."""

        from axiom_rift.runtime.guards import (
            EvidenceDepth,
            REQUIRED_CASES,
            REQUIRED_PARITY,
            REQUIRED_RELEASE_ARTIFACT_ROLES,
        )
        from axiom_rift.operations.runtime_source_readiness import (
            RuntimeSourceReadinessError,
            current_readiness_payload,
            validate_completion_receipt_reuse,
        )
        from axiom_rift.runtime.source_lifecycle_coverage import (
            SourceLifecycleCoverageError,
            derive_source_lifecycle_coverage,
            require_source_lifecycle_coverage_ids,
        )

        science = control["scientific"]
        mission_id = science["active_mission"]
        if mission_id is None or science["active_executable"] != executable_id:
            raise TransitionError("Release basis is not in the active Mission")
        if science["active_job"] is not None or science["active_repair"] is not None:
            raise TransitionError("Release transition cannot bypass active work")
        candidate_head = index.event_head(f"candidate:{executable_id}")
        candidate = (
            None
            if candidate_head is None
            else index.get(candidate_head.record_kind, candidate_head.record_id)
        )
        expected_candidate = (
            ("engineering-executable-fixture", "bound_fixture")
            if allow_engineering_fixture and self.engineering_fixture
            else ("candidate", "frozen")
        )
        if (
            candidate is None
            or (candidate.kind, candidate.status) != expected_candidate
            or candidate.record_id != candidate_id
        ):
            raise TransitionError("Release basis lacks the current frozen candidate")
        executable_manifest = candidate.payload.get("executable")
        if not isinstance(executable_manifest, Mapping):
            raise TransitionError(
                "Release candidate lacks its frozen Executable manifest"
            )
        try:
            required_source_lifecycle_rows = (
                derive_source_lifecycle_coverage(executable_manifest)
            )
        except SourceLifecycleCoverageError as exc:
            raise TransitionError(str(exc)) from exc
        required_source_lifecycle_ids = {
            row["coverage_id"] for row in required_source_lifecycle_rows
        }
        current_subject = self._current_subject(
            control, SubjectKind.EXECUTABLE, executable_id
        )
        candidate_source_bindings = candidate.payload.get("source_bindings")
        if not isinstance(candidate_source_bindings, list):
            raise TransitionError("Release candidate source bindings are malformed")
        source_bindings_by_id: dict[str, Mapping[str, Any]] = {}
        for source_binding in candidate_source_bindings:
            if (
                not isinstance(source_binding, Mapping)
                or set(source_binding)
                != {
                    "eligibility_receipt_id",
                    "mapping_identity",
                    "source_contract_id",
                    "source_state_record_id",
                }
                or type(source_binding.get("source_contract_id")) is not str
                or type(source_binding.get("mapping_identity")) is not str
                or type(source_binding.get("eligibility_receipt_id")) is not str
                or type(source_binding.get("source_state_record_id")) is not str
                or source_binding["source_contract_id"] in source_bindings_by_id
            ):
                raise TransitionError("Release candidate source bindings are malformed")
            source_bindings_by_id[source_binding["source_contract_id"]] = source_binding
        candidate_source_ids = candidate.payload.get("executable", {}).get(
            "source_contracts"
        )
        if (
            not isinstance(candidate_source_ids, list)
            or candidate_source_ids != sorted(source_bindings_by_id)
        ):
            raise TransitionError("Release candidate source inventory is malformed")
        current_source_states: dict[str, IndexRecord] = {}
        current_readiness_rows: list[dict[str, Any]] = []
        for source_id in candidate_source_ids:
            frozen_binding = source_bindings_by_id[source_id]
            frozen_state = index.get(
                "source-state", frozen_binding["source_state_record_id"]
            )
            frozen_sequence = (
                None if frozen_state is None else frozen_state.event_sequence
            )
            expected_frozen_state_id = (
                None
                if type(frozen_sequence) is not int
                else canonical_digest(
                    domain="source-state",
                    payload={
                        "source_id": source_id,
                        "state": "runtime_eligible",
                        "ordinal": frozen_sequence,
                        "evidence_receipt_id": frozen_binding[
                            "eligibility_receipt_id"
                        ],
                    },
                )
            )
            if (
                frozen_state is None
                or frozen_state.kind != "source-state"
                or frozen_state.status != "runtime_eligible"
                or frozen_state.subject != f"Source:{source_id}"
                or frozen_state.fingerprint != source_id
                or frozen_state.event_stream != f"source:{source_id}"
                or frozen_state.record_id != expected_frozen_state_id
                or frozen_state.payload.get("ordinal") != frozen_sequence
                or frozen_state.payload.get("evidence_receipt_id")
                != frozen_binding["eligibility_receipt_id"]
                or frozen_state.payload.get("mapping_identity")
                != frozen_binding["mapping_identity"]
                or type(frozen_state.authority_sequence) is not int
                or type(candidate.authority_sequence) is not int
                or frozen_state.authority_sequence
                >= candidate.authority_sequence
            ):
                raise TransitionError(
                    "Release candidate source binding lacks its exact frozen state"
                )
            state = self._require_runtime_source(index, source_id)
            if (
                state.payload.get("mapping_identity")
                != frozen_binding["mapping_identity"]
            ):
                raise TransitionError(
                    "Release current source mapping differs from its frozen candidate"
                )
            current_source_states[source_id] = state
            try:
                current_readiness_rows.append(
                    current_readiness_payload(
                        source_contract_id=source_id,
                        current_state=state,
                    )
                )
            except RuntimeSourceReadinessError as exc:
                raise TransitionError(str(exc)) from exc
        current_readiness_rows.sort(key=lambda item: item["source_contract_id"])
        current_source_receipts = [
            item["receipt_id"] for item in current_readiness_rows
        ]

        def authority_event_time(record: IndexRecord) -> str:
            offset, sequence, event_id = self._index_record_authority_key(record)
            event = self.journal.read_event_at(
                offset=offset,
                expected_sequence=sequence,
                expected_event_id=event_id,
            )
            occurred_at_utc = event.get("occurred_at_utc")
            if type(occurred_at_utc) is not str:
                raise RecoveryRequired(
                    "Release evidence authority timestamp is unavailable"
                )
            return occurred_at_utc

        parity: set[str] = set()
        cases: set[str] = set()
        artifact_hashes: set[str] = set()
        artifact_roles: dict[str, str] = {}
        artifact_role_completion_ids: dict[str, str] = {}
        artifact_role_hashes: set[str] = set()
        job_ids: list[str] = []
        runtime_permit_ids: list[str] = []
        depth_records: list[dict[str, str]] = []
        completion_readiness_rows: list[dict[str, Any]] = []
        completion_source_receipts: dict[str, list[str]] = {}
        source_lifecycle_coverage_ids: set[str] = set()
        for completion_id in completion_record_ids:
            completion = index.get("job-completed", completion_id)
            if completion is None or completion.status != "success":
                raise TransitionError("Release references an unsuccessful or absent Job")
            runtime = completion.payload.get("runtime")
            if not isinstance(runtime, dict):
                raise TransitionError("Release references a non-runtime Job")
            job_id = completion.payload.get("job_id")
            declaration = (
                None if not isinstance(job_id, str) else index.get("job-declared", job_id)
            )
            start_id = completion.payload.get("start_record_id")
            started = (
                None
                if not isinstance(start_id, str)
                else index.get("job-started", start_id)
            )
            if declaration is None or started is None:
                raise TransitionError("Release Job provenance chain is incomplete")
            spec = declaration.payload.get("spec")
            binding = None if not isinstance(spec, dict) else spec.get("runtime_binding")
            if (
                not isinstance(binding, dict)
                or declaration.payload.get("mission_id") != mission_id
                or spec.get("evidence_subject")
                != {"kind": "Executable", "id": executable_id}
            ):
                raise TransitionError("Release Job belongs to another scientific subject")
            started_runtime = started.payload.get("runtime")
            if not isinstance(started_runtime, dict):
                raise TransitionError("Release Job did not start through RuntimePermit")
            for name in (
                "action",
                "candidate_id",
                "evidence_depth",
                "executable_id",
                "mission_id",
                "runtime_permit_id",
                "source_receipt_ids",
                "source_snapshot_rows",
                "source_state_record_ids",
            ):
                if runtime.get(name) != started_runtime.get(name):
                    raise TransitionError(
                        "Release Job runtime provenance changed at completion"
                    )
            entry_id = runtime.get("runtime_entry_record_id")
            engine_entry = (
                None
                if not isinstance(entry_id, str)
                else index.get("runtime-engine-entry", entry_id)
            )
            runtime_source_receipts = runtime.get("source_receipt_ids")
            runtime_source_state_ids = runtime.get("source_state_record_ids")
            runtime_source_snapshot_rows = runtime.get("source_snapshot_rows")
            source_snapshot_by_id: dict[str, Mapping[str, Any]] = {}
            if isinstance(runtime_source_snapshot_rows, list):
                for source_snapshot in runtime_source_snapshot_rows:
                    if (
                        not isinstance(source_snapshot, Mapping)
                        or set(source_snapshot)
                        != {
                            "mapping_identity",
                            "source_contract_id",
                            "source_receipt_id",
                            "source_state_record_id",
                        }
                        or type(source_snapshot.get("source_contract_id"))
                        is not str
                        or source_snapshot["source_contract_id"]
                        in source_snapshot_by_id
                    ):
                        raise TransitionError(
                            "Release Job source snapshot rows are malformed"
                        )
                    source_snapshot_by_id[
                        source_snapshot["source_contract_id"]
                    ] = source_snapshot
            if (
                engine_entry is None
                or engine_entry.payload.get("job_id") != job_id
                or engine_entry.payload.get("candidate_id") != candidate_id
                or engine_entry.payload.get("runtime_permit_id")
                != runtime.get("runtime_permit_id")
                or not isinstance(runtime_source_receipts, list)
                or any(type(item) is not str for item in runtime_source_receipts)
                or len(set(runtime_source_receipts)) != len(runtime_source_receipts)
                or not isinstance(runtime_source_state_ids, list)
                or any(type(item) is not str for item in runtime_source_state_ids)
                or runtime_source_state_ids
                != sorted(set(runtime_source_state_ids))
                or not isinstance(runtime_source_snapshot_rows, list)
                or list(source_snapshot_by_id) != candidate_source_ids
                or sorted(
                    row["source_receipt_id"]
                    for row in source_snapshot_by_id.values()
                )
                != runtime_source_receipts
                or sorted(
                    row["source_state_record_id"]
                    for row in source_snapshot_by_id.values()
                )
                != runtime_source_state_ids
                or engine_entry.payload.get("source_receipt_ids")
                != runtime_source_receipts
                or engine_entry.payload.get("source_state_record_ids")
                != runtime_source_state_ids
                or engine_entry.payload.get("source_snapshot_rows")
                != runtime_source_snapshot_rows
            ):
                raise TransitionError("Release Job lacks durable engine-entry provenance")
            if (
                runtime["mission_id"] != mission_id
                or runtime["candidate_id"] != candidate_id
                or runtime["executable_id"] != executable_id
                or runtime["action"] != binding["action"]
                or runtime["evidence_depth"] != binding["evidence_depth"]
            ):
                raise TransitionError("Release Job is stale or bound to another activation")
            completion_source_rows: list[dict[str, Any]] = []
            consumed_receipts: set[str] = set()
            for source_id in candidate_source_ids:
                source_binding = source_bindings_by_id[source_id]
                try:
                    source_row = validate_completion_receipt_reuse(
                        index=index,
                        source_contract_id=source_id,
                        candidate_mapping_identity=source_binding[
                            "mapping_identity"
                        ],
                        completion_receipt_ids=runtime_source_receipts,
                        completion_source_snapshot=(
                            source_snapshot_by_id[source_id]
                        ),
                        current_state=current_source_states[source_id],
                        engine_entry_authority_sequence=(
                            engine_entry.authority_sequence
                        ),
                        completion_authority_sequence=(
                            completion.authority_sequence
                        ),
                        engine_entry_occurred_at_utc=authority_event_time(
                            engine_entry
                        ),
                        completion_occurred_at_utc=authority_event_time(
                            completion
                        ),
                        verify_artifact=self.evidence.verify,
                    )
                except RuntimeSourceReadinessError as exc:
                    raise TransitionError(
                        f"Release invalidates completion {completion_id}: {exc}"
                    ) from exc
                receipt_id = source_row["completion_receipt_id"]
                if receipt_id in consumed_receipts:
                    raise TransitionError(
                        "Release completion reuses one receipt for multiple sources"
                    )
                consumed_receipts.add(receipt_id)
                completion_source_rows.append(source_row)
            if consumed_receipts != set(runtime_source_receipts):
                raise TransitionError(
                    "Release completion source receipts do not match its keyed source inventory"
                )
            completion_source_receipts[completion_id] = sorted(
                runtime_source_receipts
            )
            completion_readiness_rows.append(
                {
                    "completion_record_id": completion_id,
                    "sources": completion_source_rows,
                }
            )
            permit_id = runtime["runtime_permit_id"]
            issued = index.get("permit-issued", permit_id)
            if (
                issued is None
                or issued.payload.get("kind") != PermitKind.RUNTIME.value
                or issued.payload.get("input_hash") != declaration.fingerprint
                or issued.payload.get("subject") != current_subject.payload()
                or runtime["action"] not in issued.payload.get("actions", [])
            ):
                raise TransitionError("Release Job RuntimePermit provenance is invalid")
            required_scope = {
                f"candidate:{candidate_id}",
                f"depth:{runtime['evidence_depth']}",
                f"executable:{executable_id}",
                f"job:{job_id}",
            }
            if not required_scope.issubset(issued.payload.get("scope", [])):
                raise TransitionError("Release Job RuntimePermit scope is incomplete")
            if not allow_engineering_fixture and runtime.get("release_eligible") is not True:
                raise TransitionError("Release Job validator did not authorize Release evidence")
            output_classes = completion.payload.get("output_classes")
            outputs = completion.payload.get("outputs")
            if not isinstance(output_classes, dict) or not isinstance(outputs, dict):
                raise TransitionError("Release Job output manifest is invalid")
            durable = {
                output_hash
                for output_name, output_hash in outputs.items()
                if output_classes.get(output_name) == "durable_evidence"
            }
            if not durable:
                raise TransitionError("Release Job has no durable evidence artifact")
            for artifact_hash in durable:
                self.evidence.verify(artifact_hash)
            runtime_roles = runtime.get("artifact_roles")
            if not isinstance(runtime_roles, dict) or not runtime_roles:
                raise TransitionError("Release Job lacks validated artifact roles")
            for role, artifact_hash in runtime_roles.items():
                if role in artifact_roles:
                    if artifact_roles[role] != artifact_hash:
                        raise TransitionError(
                            "Release artifact role has conflicting evidence"
                        )
                    raise TransitionError(
                        "Release artifact role producer is ambiguous"
                    )
                if role not in artifact_roles and artifact_hash in artifact_role_hashes:
                    raise TransitionError("one artifact cannot satisfy multiple Release roles")
                if artifact_hash not in durable:
                    raise TransitionError("Release role is not a durable Job output")
                artifact_roles[role] = artifact_hash
                artifact_role_completion_ids[role] = completion_id
                artifact_role_hashes.add(artifact_hash)
            depth = runtime["evidence_depth"]
            observed_parity = set(runtime.get("parity_surfaces", []))
            observed_cases = set(runtime.get("materialization_cases", []))
            try:
                planned_source_lifecycle_ids = (
                    require_source_lifecycle_coverage_ids(
                        binding.get(
                            "planned_source_lifecycle_coverage_ids"
                        ),
                        allowed_rows=required_source_lifecycle_rows,
                        planned_materialization_cases=binding.get(
                            "planned_materialization_cases", ()
                        ),
                    )
                )
            except SourceLifecycleCoverageError as exc:
                raise TransitionError(
                    f"Release invalidates completion {completion_id}: {exc}"
                ) from exc
            if runtime.get("source_lifecycle_coverage_ids") != list(
                planned_source_lifecycle_ids
            ):
                raise TransitionError(
                    "Release Job source lifecycle coverage differs from its "
                    "preregistered and validated plan"
                )
            if depth == EvidenceDepth.EXECUTION_PROOF.value:
                if (
                    observed_cases
                    or not observed_parity
                    or planned_source_lifecycle_ids
                ):
                    raise TransitionError("execution proof Release evidence is malformed")
                parity.update(observed_parity)
            elif depth == EvidenceDepth.MATERIALIZATION.value:
                if observed_parity or not observed_cases:
                    raise TransitionError("materialization Release evidence is malformed")
                cases.update(observed_cases)
                source_lifecycle_coverage_ids.update(
                    planned_source_lifecycle_ids
                )
            else:
                raise TransitionError("Release Job has an ineligible evidence depth")
            artifact_hashes.update(durable)
            job_ids.append(job_id)
            runtime_permit_ids.append(permit_id)
            depth_records.append({"completion_id": completion_id, "depth": depth})
        missing_parity = REQUIRED_PARITY - parity
        missing_cases = REQUIRED_CASES - cases
        missing_roles = REQUIRED_RELEASE_ARTIFACT_ROLES - set(artifact_roles)
        missing_source_lifecycle = (
            required_source_lifecycle_ids
            - source_lifecycle_coverage_ids
        )
        if (
            missing_parity
            or missing_cases
            or missing_roles
            or missing_source_lifecycle
        ):
            raise TransitionError(
                f"Release evidence coverage is incomplete: "
                f"parity={sorted(missing_parity)!r}, cases={sorted(missing_cases)!r}, "
                f"roles={sorted(missing_roles)!r}, "
                f"source_lifecycle={sorted(missing_source_lifecycle)!r}"
            )
        handoff_hash = artifact_roles["local_handoff_manifest"]
        handoff_completion_id = artifact_role_completion_ids[
            "local_handoff_manifest"
        ]
        handoff_source_receipts = completion_source_receipts[
            handoff_completion_id
        ]
        try:
            handoff = parse_canonical(self.evidence.read_verified(handoff_hash))
        except ValueError as exc:
            raise TransitionError("local handoff manifest is not canonical") from exc
        expected_handoff = {
            "artifact_roles": {
                role: artifact_hash
                for role, artifact_hash in sorted(artifact_roles.items())
                if role != "local_handoff_manifest"
            },
            "authority_manifest_digest": control["authority"]["manifest_digest"],
            "candidate_id": candidate_id,
            "executable_id": executable_id,
            "mission_id": mission_id,
            "schema": "axiom_local_handoff.v1",
            "source_receipt_ids": handoff_source_receipts,
        }
        if handoff != expected_handoff:
            raise TransitionError("local handoff manifest differs from the Release basis")
        return {
            "artifact_hashes": sorted(artifact_hashes),
            "artifact_roles": dict(sorted(artifact_roles.items())),
            "completion_record_ids": list(completion_record_ids),
            "depth_records": depth_records,
            "job_ids": job_ids,
            "materialization_cases": sorted(cases),
            "parity_surfaces": sorted(parity),
            "runtime_permit_ids": runtime_permit_ids,
            "source_readiness": {
                "completion_uses": completion_readiness_rows,
                "current": current_readiness_rows,
                "schema": "release_source_readiness.v1",
            },
            "source_lifecycle_coverage": {
                "required_rows": [
                    dict(row) for row in required_source_lifecycle_rows
                ],
                "satisfied_coverage_ids": sorted(
                    source_lifecycle_coverage_ids
                ),
                "schema": "release_source_lifecycle_coverage.v1",
            },
            "source_receipt_ids": current_source_receipts,
        }

    def validate_release_basis_fixture(
        self,
        *,
        executable_id: str,
        candidate_id: str,
        completion_record_ids: tuple[str, ...],
    ) -> Mapping[str, Any]:
        """Exercise the production Release derivation without creating Release authority."""

        if not self.engineering_fixture:
            raise TransitionError("fixture Release validation requires engineering mode")
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                control = self._require_stable_locked(index)
                assert control is not None
                return self._derive_release_basis_locked(
                    index=index,
                    control=control,
                    executable_id=executable_id,
                    candidate_id=candidate_id,
                    completion_record_ids=completion_record_ids,
                    allow_engineering_fixture=True,
                )

    def declare_release(
        self,
        *,
        release_id: str,
        executable_id: str,
        candidate_id: str,
        evidence: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.runtime.guards import ReleaseEvidence

        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot declare a Release")
        _require_ascii("release_id", release_id)
        _require_ascii("executable_id", executable_id)
        _require_ascii("candidate_id", candidate_id)
        if not isinstance(evidence, ReleaseEvidence):
            raise TransitionError("Release declaration requires ReleaseEvidence")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science.get("active_release") is not None:
                raise TransitionError("another Release is already active")
            derived = self._derive_release_basis_locked(
                index=index,
                control=current,
                executable_id=executable_id,
                candidate_id=candidate_id,
                completion_record_ids=evidence.completion_record_ids,
            )
            release_payload = {
                "release_id": release_id,
                "candidate_id": candidate_id,
                "executable_id": executable_id,
                "mission_id": science["active_mission"],
                **derived,
            }
            release_hash = _digest(release_payload, domain="release")
            authorization = self._authorization(
                kind=SubjectKind.RELEASE,
                subject_id=release_id,
                semantic_hash=release_hash,
            )
            self._bind_authorization(body, authorization)
            science["active_release"] = {
                "id": release_id,
                "status": "declared",
                "candidate_id": candidate_id,
                "executable_id": executable_id,
            }
            body["next_action"] = {
                "kind": "issue_release_permit",
                "release_id": release_id,
            }
            record = _record(
                kind="release-declared",
                record_id=release_id,
                subject=f"Executable:{executable_id}",
                status="declared",
                fingerprint=release_hash,
                payload=release_payload,
                event_stream=f"release:{release_id}",
                event_sequence=1,
            )
            return body, [record], {
                "release_id": release_id,
                "release_hash": release_hash,
            }

        return self._commit(
            event_kind="release_declared",
            operation_id=operation_id,
            subject=f"Release:{release_id}",
            payload={
                "release_id": release_id,
                "candidate_id": candidate_id,
                "executable_id": executable_id,
                "completion_record_ids": list(evidence.completion_record_ids),
            },
            prepare=prepare,
        )

    def freeze_release(
        self,
        *,
        release_id: str,
        permit: Permit,
        operation_id: str,
    ) -> TransitionResult:
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot freeze a Release")
        _require_ascii("release_id", release_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            active_release = science.get("active_release")
            if (
                not isinstance(active_release, dict)
                or active_release.get("id") != release_id
                or active_release.get("status") != "declared"
            ):
                raise TransitionError("Release is not the single active declaration")
            declared = index.get("release-declared", release_id)
            if declared is None or declared.status != "declared":
                raise TransitionError("Release declaration is absent")
            self._validate_permit_locked(
                control=current,
                index=index,
                permit=permit,
                expected_kind=PermitKind.RELEASE,
                action="freeze_release",
                subject_kind=SubjectKind.RELEASE,
                subject_id=release_id,
                expected_input_hash=declared.fingerprint,
                required_scope=(f"release:{release_id}",),
            )
            executable_id = declared.payload["executable_id"]
            derived = self._derive_release_basis_locked(
                index=index,
                control=current,
                executable_id=executable_id,
                candidate_id=declared.payload["candidate_id"],
                completion_record_ids=tuple(
                    declared.payload["completion_record_ids"]
                ),
            )
            for name, value in derived.items():
                if declared.payload.get(name) != value:
                    raise TransitionError("Release declaration differs from current evidence")
            if _digest(dict(declared.payload), domain="release") != declared.fingerprint:
                raise TransitionError("Release declaration identity is invalid")
            record = _record(
                kind="release",
                record_id=release_id,
                subject=f"Executable:{executable_id}",
                status="frozen",
                fingerprint=declared.fingerprint,
                payload=dict(declared.payload),
                event_stream=f"release:{release_id}",
                event_sequence=2,
            )
            consumption = self._permit_consumption_record(permit, operation_id)
            self._drop_authorization(body, SubjectKind.RELEASE, release_id)
            active_release["status"] = "frozen"
            body["next_action"] = {
                "kind": "close_mission",
                "outcome": "completed_pre_live_handoff",
                "basis_record_id": release_id,
            }
            return body, [consumption, record], {"release_id": release_id}

        return self._commit(
            event_kind="release_frozen",
            operation_id=operation_id,
            subject=f"Release:{release_id}",
            payload={"release_id": release_id, "permit_id": permit.permit_id},
            prepare=prepare,
        )

    def abandon_release(
        self,
        *,
        release_id: str,
        disposition: str,
        reason: str,
        operation_id: str,
    ) -> TransitionResult:
        """Dispose the one active Release without changing its Executable identity."""

        if disposition not in {"abandoned", "invalidated"}:
            raise TransitionError("Release disposition is not typed")
        _require_ascii("release_id", release_id)
        _require_ascii("reason", reason)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            active = science.get("active_release")
            if not isinstance(active, dict) or active.get("id") != release_id:
                raise TransitionError("Release is not active")
            head = index.event_head(f"release:{release_id}")
            latest = None if head is None else index.get(head.record_kind, head.record_id)
            if latest is None or latest.status not in {"declared", "frozen"}:
                raise TransitionError("active Release projection is invalid")
            if latest.status == "frozen" and disposition != "invalidated":
                raise TransitionError("a frozen Release may only be invalidated")
            record_id = canonical_digest(
                domain="release-disposition",
                payload={
                    "release_id": release_id,
                    "prior_status": latest.status,
                    "disposition": disposition,
                    "reason": reason,
                },
            )
            record = _record(
                kind="release-disposition",
                record_id=record_id,
                subject=f"Release:{release_id}",
                status=disposition,
                fingerprint=latest.fingerprint,
                payload={"prior_status": latest.status, "reason": reason},
                event_stream=f"release:{release_id}",
                event_sequence=head.sequence + 1,
            )
            self._drop_authorization(body, SubjectKind.RELEASE, release_id)
            science["active_release"] = None
            body["next_action"] = {
                "kind": "plan_candidate_bound_evidence",
                "executable_id": science["active_executable"],
            }
            return body, [record], {"release_id": release_id, "disposition": disposition}

        return self._commit(
            event_kind="release_disposed",
            operation_id=operation_id,
            subject=f"Release:{release_id}",
            payload={"disposition": disposition, "reason": reason},
            prepare=prepare,
        )

    @staticmethod
    def _component_manifest_record(
        *,
        component_id: str,
        manifest: Mapping[str, Any],
    ) -> IndexRecord:
        from axiom_rift.research.chassis import (
            component_semantic_surface_identity,
        )

        expected_id = "component:" + canonical_digest(
            domain="component", payload=dict(manifest)
        )
        if component_id != expected_id:
            raise TransitionError("component identity differs from its exact manifest")
        protocol = manifest.get("protocol")
        if not isinstance(protocol, str) or not protocol or not protocol.isascii():
            raise TransitionError("component protocol is invalid")
        domain = protocol.split(".", 1)[0]
        surface_identity = component_semantic_surface_identity(manifest)
        return _record(
            kind="component-manifest",
            record_id=component_id,
            subject=f"Component:{component_id}",
            status="registered",
            fingerprint=surface_identity,
            payload={
                "component_id": component_id,
                "manifest": dict(manifest),
                "protocol_domain": domain,
                "schema": "component_manifest_projection.v1",
                "semantic_surface_identity": surface_identity,
            },
        )

    @staticmethod
    def _require_component_manifest_projection(
        index: LocalIndex,
        record: IndexRecord,
    ) -> IndexRecord | None:
        existing = index.get(record.kind, record.record_id)
        if existing is None:
            return record
        if (
            existing.subject != record.subject
            or existing.status != record.status
            or existing.fingerprint != record.fingerprint
            or dict(existing.payload) != dict(record.payload)
        ):
            raise RecordCollisionError("component manifest projection collision")
        return None

    @staticmethod
    def _component_protocol_neutral_surface(
        manifest: Mapping[str, Any],
    ) -> str:
        try:
            return component_manifest_surfaces(manifest).protocol_neutral
        except ComponentManifestError as exc:
            raise TransitionError(str(exc)) from exc

    def _project_executable_components(
        self,
        index: LocalIndex,
        executable: Any,
    ) -> list[IndexRecord]:
        """Project exact components and reject only genuinely new surface aliases."""

        from axiom_rift.core.identity import ExecutableSpec

        if not isinstance(executable, ExecutableSpec):
            raise TransitionError("component projection requires an ExecutableSpec")
        records: list[IndexRecord] = []
        seen_surfaces: set[str] = set()
        seen_protocol_neutral_surfaces: set[str] = set()
        for component, component_id in zip(
            executable.components,
            executable.component_identities,
            strict=True,
        ):
            candidate = self._component_manifest_record(
                component_id=component_id,
                manifest=component.to_identity_payload(),
            )
            if candidate.fingerprint in seen_surfaces:
                raise TransitionError(
                    "one Executable cannot contain duplicate protocol-neutral component surfaces"
                )
            seen_surfaces.add(candidate.fingerprint)
            protocol_neutral_surface = self._component_protocol_neutral_surface(
                component.to_identity_payload()
            )
            if protocol_neutral_surface in seen_protocol_neutral_surfaces:
                raise TransitionError(
                    "one Executable cannot relabel the same component semantics across protocol domains"
                )
            seen_protocol_neutral_surfaces.add(protocol_neutral_surface)
            exact = index.get("component-manifest", component_id)
            if exact is not None:
                self._require_component_manifest_projection(index, candidate)
                continue
            variants = tuple(
                record
                for record in index.records_by_fingerprint(candidate.fingerprint)
                if record.kind == "component-manifest"
            )
            if variants:
                raise TransitionError(
                    "new component protocol/name drift duplicates an existing semantic surface"
                )
            cross_domain_variants = index.component_manifests_by_surface(
                COMPONENT_SURFACE_PROTOCOL_NEUTRAL,
                protocol_neutral_surface,
            )
            if cross_domain_variants:
                raise TransitionError(
                    "new component protocol/domain drift duplicates existing semantics"
                )
            records.append(candidate)
        return records

    def backfill_component_manifests(
        self,
        *,
        operation_id: str,
    ) -> TransitionResult:
        """Project exact legacy trial components without changing scientific credit."""

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "component manifest backfill requires a stable scientific boundary"
                )
            projected: dict[str, IndexRecord] = {}
            for trial in index.records_by_kind("trial"):
                executable = trial.payload.get("executable")
                if not isinstance(executable, dict):
                    raise TransitionError("legacy trial executable manifest is absent")
                component_ids = executable.get("component_identities")
                manifests = executable.get("component_manifests")
                if (
                    not isinstance(component_ids, list)
                    or not isinstance(manifests, list)
                    or len(component_ids) != len(manifests)
                ):
                    raise TransitionError("legacy trial component manifests are malformed")
                for component_id, manifest in zip(component_ids, manifests, strict=True):
                    if not isinstance(component_id, str) or not isinstance(manifest, dict):
                        raise TransitionError(
                            "legacy trial component identity binding is malformed"
                        )
                    record = self._component_manifest_record(
                        component_id=component_id,
                        manifest=manifest,
                    )
                    prior = projected.get(component_id)
                    if prior is not None and dict(prior.payload) != dict(record.payload):
                        raise RecordCollisionError(
                            "legacy component identity has conflicting manifests"
                        )
                    projected[component_id] = record
            records: list[IndexRecord] = []
            for component_id in sorted(projected):
                record = self._require_component_manifest_projection(
                    index, projected[component_id]
                )
                if record is not None:
                    records.append(record)
            return self._body(current), records, {
                "claim": science["claim"],
                "component_manifest_count": len(projected),
                "holdout_delta": 0,
                "projected_record_count": len(records),
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="component_manifests_backfilled",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "claim_delta": "none",
                "holdout_delta": 0,
                "trial_delta": 0,
            },
            prepare=prepare,
        )

    @staticmethod
    def _executable_surface_record(
        *,
        surface_identity: str,
        executable_ids: tuple[str, ...],
    ) -> IndexRecord:
        if (
            not surface_identity.startswith("executable-surface:")
            or len(surface_identity) != 83
        ):
            raise TransitionError("Executable semantic surface identity is invalid")
        normalized_ids = tuple(sorted(set(executable_ids)))
        if len(normalized_ids) != len(executable_ids) or not normalized_ids:
            raise TransitionError("Executable semantic surface members are invalid")
        for executable_id in normalized_ids:
            if (
                not executable_id.startswith("executable:")
                or len(executable_id) != 75
            ):
                raise TransitionError("Executable semantic surface member is invalid")
        return _record(
            kind="executable-surface",
            record_id=surface_identity,
            subject=f"ExecutableSurface:{surface_identity}",
            status="registered",
            fingerprint=surface_identity,
            payload={
                "exact_executable_ids": list(normalized_ids),
                "schema": "executable_semantic_surface_projection.v1",
                "surface_identity": surface_identity,
            },
        )

    @staticmethod
    def _require_executable_surface_projection(
        index: LocalIndex,
        record: IndexRecord,
    ) -> IndexRecord | None:
        existing = index.get(record.kind, record.record_id)
        if existing is None:
            return record
        if (
            existing.subject != record.subject
            or existing.status != record.status
            or existing.fingerprint != record.fingerprint
            or dict(existing.payload) != dict(record.payload)
        ):
            raise RecordCollisionError("Executable semantic surface projection collision")
        return None

    def backfill_semantic_question_registry(
        self,
        *,
        operation_id: str,
    ) -> TransitionResult:
        """Bind every historical Study to one exact question core, without credit."""

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "Semantic question backfill requires a stable scientific boundary"
                )
            from axiom_rift.operations.semantic_question_registry import (
                SemanticQuestionRegistryError,
                SemanticQuestionRegistryIntegrityError,
                backfill_semantic_question_records,
                require_semantic_question_projection,
                semantic_question_registry_activation_record,
            )

            try:
                study_opens = index.records_by_kind("study-open")
                projections = backfill_semantic_question_records(study_opens)
                core_count = sum(
                    record.kind == "semantic-question-core"
                    for record in projections
                )
                binding_count = sum(
                    record.kind == "semantic-question-study"
                    for record in projections
                )
                if binding_count != len(study_opens):
                    raise SemanticQuestionRegistryIntegrityError(
                        "semantic question backfill lost a Study binding"
                    )
                activation = semantic_question_registry_activation_record(
                    operation_id=operation_id,
                    study_count=binding_count,
                    core_count=core_count,
                )
                records: list[IndexRecord] = []
                for projection in (*projections, activation):
                    pending = require_semantic_question_projection(
                        index, projection
                    )
                    if pending is not None:
                        records.append(pending)
            except SemanticQuestionRegistryIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except SemanticQuestionRegistryError as exc:
                raise TransitionError(str(exc)) from exc
            return self._body(current), records, {
                "claim": science["claim"],
                "core_count": core_count,
                "holdout_delta": 0,
                "projected_record_count": len(records),
                "study_binding_count": binding_count,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="semantic_question_registry_backfilled",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "claim_delta": "none",
                "holdout_delta": 0,
                "trial_delta": 0,
            },
            prepare=prepare,
        )

    def record_semantic_question_corrections(
        self,
        *,
        equivalence_proposals: Sequence[Any],
        lineage_proposals: Sequence[Any],
        review_artifact_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Add expert-reviewed historical lineage without rewriting verdicts."""

        self._require_study_close_delivery_guard()
        _require_digest(
            "semantic question review artifact",
            review_artifact_hash,
        )
        if not self.engineering_fixture:
            self.evidence.verify(review_artifact_hash)
        from axiom_rift.research.semantic_question import (
            SemanticQuestionEquivalenceProposal,
            SemanticQuestionLineageProposal,
        )

        if (
            not isinstance(equivalence_proposals, (list, tuple))
            or any(
                not isinstance(item, SemanticQuestionEquivalenceProposal)
                for item in equivalence_proposals
            )
            or not isinstance(lineage_proposals, (list, tuple))
            or not lineage_proposals
            or any(
                not isinstance(item, SemanticQuestionLineageProposal)
                for item in lineage_proposals
            )
        ):
            raise TransitionError(
                "semantic question corrections require typed proposal sequences"
            )
        if len({item.identity for item in equivalence_proposals}) != len(
            equivalence_proposals
        ) or len({item.identity for item in lineage_proposals}) != len(
            lineage_proposals
        ):
            raise TransitionError(
                "semantic question correction proposals must be unique"
            )
        if len({item.successor_study_id for item in lineage_proposals}) != len(
            lineage_proposals
        ):
            raise TransitionError(
                "one correction event may record only one incoming edge per Study"
            )
        equivalence_ids = tuple(
            sorted(item.identity for item in equivalence_proposals)
        )
        lineage_ids = tuple(sorted(item.identity for item in lineage_proposals))

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "Semantic question correction requires a stable scientific boundary"
                )
            from axiom_rift.operations.semantic_question_registry import (
                SemanticQuestionRegistryError,
                SemanticQuestionRegistryIntegrityError,
                require_semantic_question_projection,
                require_semantic_question_registry_activation,
                semantic_question_equivalence_record,
                semantic_question_lineage_record,
            )

            try:
                if require_semantic_question_registry_activation(index) is None:
                    raise SemanticQuestionRegistryError(
                        "semantic question registry is not active"
                    )
                if not self.engineering_fixture:
                    protocol_head = index.event_head(
                        "research-protocol:scientific"
                    )
                    protocol = (
                        None
                        if protocol_head is None
                        else index.get(
                            protocol_head.record_kind,
                            protocol_head.record_id,
                        )
                    )
                    if (
                        protocol is None
                        or protocol.kind != "research-protocol-activation"
                        or protocol.status != "active"
                        or protocol.event_sequence != protocol_head.sequence
                        or protocol.payload.get("authority_manifest_digest")
                        != current["authority"]["manifest_digest"]
                    ):
                        raise RecoveryRequired(
                            "semantic question review lacks the active protocol"
                        )
                    if (
                        protocol.payload.get("audit_artifact_hash")
                        != review_artifact_hash
                    ):
                        raise SemanticQuestionRegistryError(
                            "semantic question review artifact differs from the active protocol"
                        )
                records: list[IndexRecord] = []
                accepted_equivalences: dict[str, IndexRecord] = {}
                for proposal in equivalence_proposals:
                    projected = semantic_question_equivalence_record(
                        index, proposal
                    )
                    pending = require_semantic_question_projection(
                        index, projected
                    )
                    accepted_equivalences[proposal.identity] = (
                        projected
                        if pending is not None
                        else index.get(projected.kind, projected.record_id)
                    )  # type: ignore[assignment]
                    if accepted_equivalences[proposal.identity] is None:
                        raise SemanticQuestionRegistryIntegrityError(
                            "accepted semantic question equivalence disappeared"
                        )
                    if pending is not None:
                        records.append(pending)
                for proposal in lineage_proposals:
                    accepted = None
                    equivalence_id = proposal.equivalence_proposal_id
                    if equivalence_id is not None:
                        accepted = accepted_equivalences.get(equivalence_id)
                        if accepted is None:
                            matches = tuple(
                                record
                                for record in index.records_by_fingerprint(
                                    equivalence_id
                                )
                                if record.kind
                                == "semantic-question-equivalence"
                            )
                            if len(matches) != 1:
                                raise SemanticQuestionRegistryError(
                                    "lineage equivalence is unavailable or ambiguous"
                                )
                            accepted = matches[0]
                    projected = semantic_question_lineage_record(
                        index,
                        proposal,
                        equivalence_record=accepted,
                    )
                    pending = require_semantic_question_projection(
                        index, projected
                    )
                    if pending is not None:
                        records.append(pending)
            except SemanticQuestionRegistryIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except SemanticQuestionRegistryError as exc:
                raise TransitionError(str(exc)) from exc
            return self._body(current), records, {
                "claim": science["claim"],
                "equivalence_count": len(equivalence_proposals),
                "holdout_delta": 0,
                "lineage_count": len(lineage_proposals),
                "projected_record_count": len(records),
                "review_artifact_hash": review_artifact_hash,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="semantic_question_corrections_recorded",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "claim_delta": "none",
                "equivalence_proposal_ids": list(equivalence_ids),
                "holdout_delta": 0,
                "lineage_proposal_ids": list(lineage_ids),
                "review_artifact_hash": review_artifact_hash,
                "trial_delta": 0,
            },
            prepare=prepare,
        )

    def backfill_executable_semantic_surfaces(
        self,
        *,
        operation_id: str,
    ) -> TransitionResult:
        """Index legacy trials by protocol-neutral Executable surface, without credit."""

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "Executable semantic surface backfill requires a stable scientific boundary"
                )
            from axiom_rift.research.chassis import (
                ChassisIdentityError,
                executable_semantic_surface_identity,
            )

            grouped: dict[str, set[str]] = {}
            for trial in index.records_by_kind("trial"):
                executable_payload = trial.payload.get("executable")
                if not isinstance(executable_payload, dict):
                    raise TransitionError("legacy trial executable manifest is absent")
                try:
                    surface_identity = executable_semantic_surface_identity(
                        executable_payload
                    )
                except ChassisIdentityError as exc:
                    raise TransitionError(str(exc)) from exc
                grouped.setdefault(surface_identity, set()).add(trial.record_id)
            records: list[IndexRecord] = []
            for surface_identity in sorted(grouped):
                projected = self._executable_surface_record(
                    surface_identity=surface_identity,
                    executable_ids=tuple(sorted(grouped[surface_identity])),
                )
                record = self._require_executable_surface_projection(index, projected)
                if record is not None:
                    records.append(record)
            return self._body(current), records, {
                "claim": science["claim"],
                "exact_executable_count": sum(len(values) for values in grouped.values()),
                "holdout_delta": 0,
                "projected_record_count": len(records),
                "surface_count": len(grouped),
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="executable_semantic_surfaces_backfilled",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "claim_delta": "none",
                "holdout_delta": 0,
                "trial_delta": 0,
            },
            prepare=prepare,
        )

    def register_trial(
        self,
        *,
        executable: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.core.identity import ExecutableSpec

        if not isinstance(executable, ExecutableSpec):
            raise TransitionError("trial registration requires an ExecutableSpec")
        executable_id = executable.identity
        executable_hash = executable_id.removeprefix("executable:")
        _require_digest("executable_hash", executable_hash)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            batch = current["scientific"]["active_batch"]
            if not isinstance(batch, dict):
                raise TransitionError("trial registration requires an active Batch")
            batch_record = index.get("batch-open", batch["id"])
            if batch_record is None:
                raise TransitionError("active Batch declaration is unavailable")
            declared_sources = set(
                batch_record.payload["spec"].get("source_contract_ids", [])
            )
            executable_sources = set(executable.source_contracts)
            if not executable_sources.issubset(declared_sources):
                raise TransitionError(
                    "Executable uses an external source absent from the frozen Batch"
                )
            for source_id in executable_sources:
                self._require_source_authority_for_actions(
                    index,
                    source_id,
                    actions=("performance_batch",),
                )
            record_kind = "engineering-evaluation-fixture" if self.engineering_fixture else "trial"
            study_id = current["scientific"]["active_study"]
            study_record = index.get("study-open", study_id)
            if study_record is None:
                raise TransitionError("active Study declaration is unavailable")
            replay_admission = self._study_replay_implementation_admission(
                index,
                study_id=study_id,
                authority_manifest_digest=current.get("authority", {}).get(
                    "manifest_digest"
                ),
            )
            study_replay_obligation_ids = study_record.payload.get(
                "replay_obligation_ids"
            )
            if study_replay_obligation_ids and replay_admission is None:
                raise RecoveryRequired(
                    "replay trial registration requires a current "
                    "implementation admission"
                )
            if replay_admission is not None:
                request_payload = replay_admission.payload.get("request")
                admitted_manifests = (
                    None
                    if not isinstance(request_payload, Mapping)
                    else request_payload.get("executable_manifests")
                )
                if (
                    not isinstance(admitted_manifests, list)
                    or executable.to_identity_payload()
                    not in admitted_manifests
                ):
                    raise TransitionError(
                        "Executable differs from the replay implementation admission"
                    )
                self._require_replay_registration_source_authority(
                    index,
                    admission=replay_admission,
                    executable=executable,
                )
            material_identity = study_record.payload["material_identity"]
            from axiom_rift.operations.replay_projection import (
                ReplayProjectionError,
                ReplayTransitionError,
                prepare_execution_progress,
            )

            try:
                progressed_replay_obligation_ids, replay_progress_records = (
                    prepare_execution_progress(
                        index,
                        study_record=study_record,
                        batch_record=batch_record,
                        executable_id=executable_id,
                        executable_payload=executable.to_identity_payload(),
                    )
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            component_records: list[IndexRecord] = []
            executable_surface_record: IndexRecord | None = None
            if not self.engineering_fixture:
                from axiom_rift.research.chassis import (
                    ChassisIdentityError,
                    executable_semantic_surface_identity,
                    validate_controlled_executable,
                )

                controlled_chassis = study_record.payload.get("controlled_chassis")
                if not isinstance(controlled_chassis, dict):
                    raise TransitionError(
                        "scientific Study lacks a controlled component chassis"
                    )
                try:
                    is_exact_baseline_control = (
                        controlled_chassis.get("baseline_executable_id")
                        == executable_id
                        and controlled_chassis.get("baseline_executable")
                        == executable.to_identity_payload()
                    )
                    if not is_exact_baseline_control:
                        validate_controlled_executable(
                            controlled_chassis, executable
                        )
                    surface_identity = executable_semantic_surface_identity(executable)
                except ChassisIdentityError as exc:
                    raise TransitionError(str(exc)) from exc
                surface_projection = index.get(
                    "executable-surface", surface_identity
                )
                if surface_projection is not None:
                    exact_ids = surface_projection.payload.get(
                        "exact_executable_ids"
                    )
                    if (
                        surface_projection.status != "registered"
                        or surface_projection.fingerprint != surface_identity
                        or surface_projection.payload.get("schema")
                        != "executable_semantic_surface_projection.v1"
                        or not isinstance(exact_ids, list)
                        or any(not isinstance(value, str) for value in exact_ids)
                    ):
                        raise RecoveryRequired(
                            "Executable semantic surface projection is malformed"
                        )
                    if executable_id not in exact_ids:
                        raise TransitionError(
                            "protocol-neutral Executable duplicate already has scientific history; "
                            "reuse its exact historical identity"
                        )
            existing = index.get(record_kind, executable_id)
            if existing is not None:
                if existing.fingerprint != executable_hash:
                    raise RecordCollisionError("Executable identity collision")
                if (
                    not self.engineering_fixture
                    and index.get("executable-surface", surface_identity) is None
                ):
                    raise RecoveryRequired(
                        "counted Executable lacks its semantic surface projection"
                    )
                return self._body(current), replay_progress_records, {
                    "trial_delta": 0,
                    "cache_hit": True,
                    "replay_obligation_ids": list(
                        progressed_replay_obligation_ids
                    ),
                }
            if not self.engineering_fixture:
                component_records.extend(
                    self._project_executable_components(index, executable)
                )
                executable_surface_record = self._executable_surface_record(
                    surface_identity=surface_identity,
                    executable_ids=(executable_id,),
                )
                projection = self._require_executable_surface_projection(
                    index, executable_surface_record
                )
                if projection is None:
                    raise RecoveryRequired(
                        "new Executable collides with an existing semantic surface"
                    )
                executable_surface_record = projection
            status = "engineering_only" if self.engineering_fixture else "evaluated"
            trial_head = index.event_head(f"batch-trials:{batch['id']}")
            evaluated_count = 0 if trial_head is None else trial_head.sequence
            max_trials = batch_record.payload["spec"]["max_trials"]
            if evaluated_count >= max_trials:
                raise TransitionError("frozen Batch trial budget is exhausted")
            if (
                not self.engineering_fixture
                and executable.data_contract != f"data:{material_identity}"
            ):
                raise TransitionError(
                    "Executable data contract differs from the active Study material"
                )
            record = _record(
                kind=record_kind,
                record_id=executable_id,
                subject=f"Batch:{batch['id']}",
                status=status,
                fingerprint=executable_hash,
                payload={
                    "engineering_fixture": self.engineering_fixture,
                    "executable": executable.to_identity_payload(),
                    "scientific_eligible": not self.engineering_fixture,
                    "scheduler_eligible": False,
                    "trial_delta": 0 if self.engineering_fixture else 1,
                    "material_identity": material_identity,
                    "mission_id": study_record.payload.get("mission_id"),
                    "portfolio_axis_id": study_record.payload.get("portfolio_axis_id"),
                    "portfolio_axis_identity": study_record.payload.get(
                        "portfolio_axis_identity"
                    ),
                    "portfolio_decision_id": study_record.payload.get(
                        "portfolio_decision_id"
                    ),
                    "portfolio_snapshot_id": study_record.payload.get(
                        "portfolio_snapshot_id"
                    ),
                    "study_id": study_id,
                    **(
                        {
                            "replay_obligation_ids": list(
                                progressed_replay_obligation_ids
                            )
                        }
                        if progressed_replay_obligation_ids
                        else {}
                    ),
                },
                event_stream=f"batch-trials:{batch['id']}",
                event_sequence=evaluated_count + 1,
            )
            records = [
                *replay_progress_records,
                *component_records,
                *(
                    []
                    if executable_surface_record is None
                    else [executable_surface_record]
                ),
                record,
            ]
            global_multiplicity: int | None = None
            if not self.engineering_fixture:
                material_head = index.event_head(
                    f"material-trial:{material_identity}"
                )
                material_sequence = 1 if material_head is None else material_head.sequence + 1
                global_multiplicity = (
                    study_record.payload["prior_global_multiplicity"]
                    + material_sequence
                    - study_record.payload["prior_material_trial_count"]
                )
                accounting_id = canonical_digest(
                    domain="material-trial",
                    payload={
                        "material_identity": material_identity,
                        "executable_id": executable_id,
                    },
                )
                records.append(
                    _record(
                        kind="trial-accounting",
                        record_id=accounting_id,
                        subject=f"Material:{material_identity}",
                        status="counted",
                        fingerprint=executable_hash,
                        payload={
                            "executable_id": executable_id,
                            "global_multiplicity": global_multiplicity,
                            "study_id": study_id,
                        },
                        event_stream=f"material-trial:{material_identity}",
                        event_sequence=material_sequence,
                    )
                )
            return self._body(current), records, {
                "trial_delta": 0 if self.engineering_fixture else 1,
                "cache_hit": False,
                "global_multiplicity": global_multiplicity,
            }

        return self._commit(
            event_kind="trial_registered",
            operation_id=operation_id,
            subject=f"Executable:{executable_id}",
            payload={
                "executable_id": executable_id,
                "executable_hash": executable_hash,
            },
            prepare=prepare,
        )

    def record_lineage(
        self,
        *,
        parent_executable_id: str,
        child_executable_id: str,
        relation: str,
        operation_id: str,
    ) -> TransitionResult:
        if parent_executable_id == child_executable_id:
            raise TransitionError("Lineage requires distinct Executables")
        allowed_relations = {
            "mechanism_branch",
            "contrast",
            "recombination",
            "synthesis",
            "semantic_refinement",
        }
        if relation not in allowed_relations:
            raise TransitionError("Lineage relation is not typed")
        for identity in (parent_executable_id, child_executable_id):
            if not identity.startswith("executable:") or len(identity) != 75:
                raise TransitionError("Lineage members must be Executable identities")
        lineage_id = canonical_digest(
            domain="lineage",
            payload={
                "parent": parent_executable_id,
                "child": child_executable_id,
                "relation": relation,
            },
        )

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            if current["scientific"]["active_mission"] is None:
                raise TransitionError("Lineage requires an active Mission")
            for identity in (parent_executable_id, child_executable_id):
                candidate_head = _index.event_head(f"candidate:{identity}")
                if (
                    _index.get("trial", identity) is None
                    and _index.get("engineering-evaluation-fixture", identity) is None
                    and candidate_head is None
                ):
                    raise TransitionError("Lineage member is not a registered Executable")
            record = _record(
                kind="lineage",
                record_id=lineage_id,
                subject=f"Executable:{child_executable_id}",
                status="related",
                fingerprint=lineage_id,
                payload={
                    "parent_executable_id": parent_executable_id,
                    "child_executable_id": child_executable_id,
                    "relation": relation,
                    "evidence_merged": False,
                },
            )
            return self._body(current), [record], {"lineage_id": lineage_id}

        return self._commit(
            event_kind="lineage_recorded",
            operation_id=operation_id,
            subject=f"Executable:{child_executable_id}",
            payload={"lineage_id": lineage_id},
            prepare=prepare,
        )

    def record_portfolio_snapshot(
        self,
        *,
        snapshot: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.research.portfolio import PortfolioSnapshot
        from axiom_rift.operations.architecture_review_direction import (
            ArchitectureReviewDirectionError,
            constraint_from_action,
            eligible_new_mechanism_axes,
            require_review_binding,
        )

        self._require_study_close_delivery_guard()
        if not isinstance(snapshot, PortfolioSnapshot):
            raise TransitionError("snapshot must be a PortfolioSnapshot")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            science = current["scientific"]
            if science["active_mission"] != snapshot.mission_id:
                raise TransitionError("Portfolio snapshot belongs to another Mission")
            if science["active_initiative"] is None:
                raise TransitionError("Portfolio snapshot requires an active Initiative")
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError("Portfolio snapshot cannot bypass active work")
            head = index.event_head(f"portfolio:{snapshot.mission_id}")
            sequence = 1 if head is None else head.sequence + 1
            required_target_axis_ids: list[str] = []
            constraint_source_id: str | None = None
            continuation = None
            replay_scheduler_projection_recovered = False
            replay_constraints = self._replay_scheduler_constraints(
                index,
                mission_id=snapshot.mission_id,
            )
            if head is None:
                standard = snapshot.exhaustion_standard_value()
                if not self.engineering_fixture and not isinstance(standard, dict):
                    raise TransitionError(
                        "scientific Portfolio requires a preregistered exhaustion standard"
                    )
                if isinstance(standard, dict):
                    if not self.engineering_fixture and any(
                        axis.architecture_chassis is None for axis in snapshot.axes
                    ):
                        raise TransitionError(
                            "scientific Portfolio axes require canonical architecture chassis"
                        )
                    families = {axis.mechanism_family for axis in snapshot.axes}
                    research_layers = {
                        axis.primary_research_layer.value for axis in snapshot.axes
                    }
                    architecture_families = {
                        axis.architecture_chassis.identity
                        for axis in snapshot.axes
                        if axis.architecture_chassis is not None
                    }
                    if (
                        len(snapshot.axes) < standard["minimum_axes"]
                        or len(families) < standard["minimum_mechanism_families"]
                        or len(research_layers)
                        < standard["minimum_primary_research_layers"]
                        or len(architecture_families)
                        < standard["minimum_system_architecture_families"]
                    ):
                        raise TransitionError(
                            "initial Portfolio is smaller than its exhaustion standard"
                        )
                intake = (
                    None
                    if not isinstance(snapshot.research_intake_id, str)
                    else index.get("research-intake", snapshot.research_intake_id)
                )
                if (
                    current["next_action"].get("kind") != "build_portfolio"
                    or current["next_action"].get("initiative_id")
                    != science["active_initiative"]
                    or (
                        not self.engineering_fixture
                        and (
                            current["next_action"].get("research_intake_id")
                            != snapshot.research_intake_id
                            or intake is None
                            or intake.subject != f"Mission:{snapshot.mission_id}"
                            or intake.status != "accepted"
                        )
                    )
                ):
                    raise TransitionError(
                        "initial Portfolio snapshot is not the exact Initiative action"
                    )
            else:
                prior = index.get(head.record_kind, head.record_id)
                if prior is None or prior.kind != "portfolio-snapshot":
                    raise TransitionError("current Portfolio snapshot is unavailable")
                next_action = current["next_action"]
                try:
                    continuation = constraint_from_action(next_action)
                except ArchitectureReviewDirectionError as exc:
                    raise TransitionError(str(exc)) from exc
                decision_id = next_action.get("decision_id")
                decision = (
                    None
                    if not isinstance(decision_id, str)
                    else self._active_portfolio_decision(index, decision_id)
                )
                if (
                    next_action.get("kind") != "record_portfolio_snapshot"
                    or decision is None
                    or decision.payload.get("portfolio_snapshot_id") != prior.record_id
                ):
                    raise TransitionError(
                        "Portfolio snapshot mutation requires the current structural Decision"
                    )
                from axiom_rift.operations.replay_projection import (
                    ReplayTransitionError,
                    validate_snapshot_scheduler_projection,
                )

                try:
                    replay_scheduler_projection_recovered = (
                        validate_snapshot_scheduler_projection(
                            next_action=next_action,
                            decision_payload=decision.payload,
                            constraints=replay_constraints,
                        )
                    )
                except ReplayTransitionError as exc:
                    raise TransitionError(str(exc)) from exc
                old_axes = {axis["axis_id"]: axis for axis in prior.payload["axes"]}
                if continuation is not None:
                    review = index.get(
                        "architecture-review",
                        continuation.architecture_review_id,
                    )
                    trigger = index.get(
                        "architecture-review-trigger",
                        continuation.trigger_record_id,
                    )
                    if review is None or trigger is None:
                        raise RecoveryRequired(
                            "bounded architecture continuation authority is unavailable"
                        )
                    try:
                        require_review_binding(
                            continuation,
                            review_record_id=review.record_id,
                            review_payload=review.payload,
                            trigger_payload=trigger.payload,
                        )
                        if self._review_resolved_architecture_family(
                            index=index,
                            review=review,
                        ) != continuation.required_architecture_family:
                            raise ArchitectureReviewDirectionError(
                                "bounded architecture review family is no longer current"
                            )
                    except ArchitectureReviewDirectionError as exc:
                        raise RecoveryRequired(str(exc)) from exc
                new_payload = snapshot.to_identity_payload()
                new_axes = {axis["axis_id"]: axis for axis in new_payload["axes"]}
                if (
                    new_payload.get("exhaustion_standard")
                    != prior.payload.get("exhaustion_standard")
                ):
                    raise TransitionError(
                        "Portfolio exhaustion standard is immutable within a Mission"
                    )
                if (
                    new_payload.get("research_intake_id")
                    != prior.payload.get("research_intake_id")
                ):
                    raise TransitionError(
                        "Portfolio research intake is immutable within a Mission"
                    )
                if not set(old_axes).issubset(new_axes):
                    raise TransitionError("Portfolio axes cannot be silently removed")
                added_axis_ids = set(new_axes) - set(old_axes)
                action = next_action.get("action")
                target_id = next_action.get("target_id")
                protocol_revision = None
                if action == "revise_protocol":
                    from axiom_rift.research.axis_protocol_revision import (
                        AxisProtocolRevisionProposal,
                    )

                    try:
                        protocol_revision = (
                            AxisProtocolRevisionProposal.from_mapping(
                                decision.payload.get("protocol_revision")
                            )
                        )
                    except (TypeError, ValueError) as exc:
                        raise RecoveryRequired(
                            "accepted protocol revision authority is malformed"
                        ) from exc
                    if (
                        decision.payload.get("protocol_revision_id")
                        != protocol_revision.identity
                        or next_action.get("protocol_revision_id")
                        != protocol_revision.identity
                    ):
                        raise RecoveryRequired(
                            "protocol revision identity is not exact"
                        )
                if not self.engineering_fixture and any(
                    new_axes[axis_id].get("architecture_chassis_identity") is None
                    for axis_id in added_axis_ids
                ):
                    raise TransitionError(
                        "new scientific Portfolio axes require canonical architecture chassis"
                    )
                pruned_reopen_axis_ids: list[str] = []
                for axis_id, old_axis in old_axes.items():
                    if (
                        not (
                            protocol_revision is not None
                            and axis_id == target_id
                        )
                        and new_axes[axis_id]["axis_identity"]
                        != old_axis["axis_identity"]
                    ):
                        raise TransitionError(
                            "Portfolio axis meaning is immutable within a Mission"
                        )
                    if old_axis["status"] == "pruned" and new_axes[axis_id]["status"] != "pruned":
                        pruned_reopen_axis_ids.append(axis_id)
                if pruned_reopen_axis_ids:
                    from axiom_rift.research.effective_axis import (
                        AxisReopenAuthority,
                        axis_reopen_evidence,
                    )

                    if (
                        pruned_reopen_axis_ids != [target_id]
                        or action != "preserve"
                        or new_axes[target_id]["status"] != "preserved"
                    ):
                        raise TransitionError(
                            "a pruned Portfolio axis requires its exact preserve authority"
                        )
                    resolution = self._effective_axis_resolution(
                        index, old_axes[target_id]
                    )
                    reopen_evidence = axis_reopen_evidence(resolution)
                    expected_authority = AxisReopenAuthority(
                        mission_id=snapshot.mission_id,
                        portfolio_snapshot_id=prior.record_id,
                        portfolio_decision_id=decision.record_id,
                        axis_id=target_id,
                        axis_identity=old_axes[target_id]["axis_identity"],
                        replay_resolution_record_ids=(
                            reopen_evidence.replay_resolution_record_ids
                        ),
                        evidence_scope_overlay_ids=(
                            reopen_evidence.evidence_scope_overlay_ids
                        ),
                        historical_cost_completion_ids=(
                            reopen_evidence.historical_cost_completion_ids
                        ),
                        historical_cost_latch_ids=(
                            reopen_evidence.historical_cost_latch_ids
                        ),
                        historical_cost_negative_memory_ids=(
                            reopen_evidence.historical_cost_negative_memory_ids
                        ),
                    )
                    authority_id = next_action.get(
                        "axis_reopen_authority_id"
                    )
                    authority = (
                        None
                        if not isinstance(authority_id, str)
                        else index.get("axis-reopen-authority", authority_id)
                    )
                    authority_stream = (
                        f"axis-reopen:{snapshot.mission_id}:"
                        f"{old_axes[target_id]['axis_identity']}"
                    )
                    authority_head = index.event_head(authority_stream)
                    if (
                        authority_id != expected_authority.identity
                        or authority is None
                        or authority.kind != "axis-reopen-authority"
                        or authority.status != "authorized"
                        or authority.subject
                        != f"Axis:{old_axes[target_id]['axis_identity']}"
                        or authority.fingerprint
                        != expected_authority.identity.removeprefix(
                            "axis-reopen-authority:"
                        )
                        or authority.payload.get("authority")
                        != expected_authority.to_identity_payload()
                        or authority.payload.get("effective_axis")
                        != resolution.to_projection_payload()
                        or authority.event_stream != authority_stream
                        or authority_head is None
                        or authority_head.record_id != authority.record_id
                        or authority.event_sequence != authority_head.sequence
                        or prior.authority_sequence is None
                        or decision.authority_sequence is None
                        or authority.authority_sequence is None
                        or decision.authority_sequence <= prior.authority_sequence
                        or authority.authority_sequence
                        <= decision.authority_sequence
                    ):
                        raise TransitionError(
                            "pruned Portfolio axis lacks its exact one-shot reopen authority"
                        )
                elif next_action.get("axis_reopen_authority_id") is not None:
                    raise TransitionError(
                        "axis reopen authority cannot authorize an unrelated snapshot"
                    )
                if action in {"preserve", "prune"}:
                    if set(new_axes) != set(old_axes) or target_id not in old_axes:
                        raise TransitionError(
                            "axis disposition snapshot may change one declared target only"
                        )
                    expected_status = "preserved" if action == "preserve" else "pruned"
                    for axis_id, old_axis in old_axes.items():
                        wanted = expected_status if axis_id == target_id else old_axis["status"]
                        if new_axes[axis_id]["status"] != wanted:
                            raise TransitionError(
                                "Portfolio snapshot differs from its structural Decision"
                            )
                elif action == "revise_protocol":
                    assert protocol_revision is not None
                    old_target = old_axes.get(target_id)
                    new_target = new_axes.get(target_id)
                    old_target_architecture_authority = (
                        None
                        if not isinstance(old_target, Mapping)
                        else self._axis_architecture_authority_identity(
                            index,
                            old_target,
                        )
                    )
                    immutable_fields = set(old_target or {}).difference(
                        {
                            "architecture_chassis",
                            "architecture_chassis_identity",
                            "axis_identity",
                            "system_architecture_family",
                            "why_now",
                        }
                    )
                    if (
                        continuation is not None
                        or set(new_axes) != set(old_axes)
                        or target_id != protocol_revision.axis_id
                        or not isinstance(old_target, Mapping)
                        or not isinstance(new_target, Mapping)
                        or any(
                            new_axes[axis_id] != old_axis
                            for axis_id, old_axis in old_axes.items()
                            if axis_id != target_id
                        )
                        or any(
                            new_target.get(field) != old_target.get(field)
                            for field in immutable_fields
                        )
                        or old_target.get("axis_identity")
                        != protocol_revision.predecessor_axis_identity
                        or new_target.get("axis_identity")
                        != protocol_revision.successor_axis_identity
                        or old_target.get("mechanism_family")
                        != protocol_revision.mechanism_family
                        or new_target.get("mechanism_family")
                        != protocol_revision.mechanism_family
                        or old_target_architecture_authority
                        != protocol_revision.predecessor_architecture_family
                        or new_target.get("architecture_chassis_identity")
                        != protocol_revision.successor_architecture_family
                        or new_target.get("system_architecture_family")
                        != protocol_revision.successor_architecture_family
                        or not isinstance(
                            new_target.get("architecture_chassis"),
                            Mapping,
                        )
                    ):
                        raise TransitionError(
                            "protocol revision must replace one exact axis chassis only"
                        )
                elif action == "new_mechanism":
                    added = set(new_axes) - set(old_axes)
                    old_families = {
                        axis["mechanism_family"] for axis in old_axes.values()
                    }
                    proposed_axis = decision.payload.get("proposed_axis")
                    proposed_axis_identity = decision.payload.get(
                        "proposed_axis_identity"
                    )
                    if (
                        not added
                        or any(
                            new_axes[axis_id]["status"] != old_axis["status"]
                            for axis_id, old_axis in old_axes.items()
                        )
                        or not any(
                            new_axes[axis_id]["mechanism_family"] not in old_families
                            for axis_id in added
                        )
                    ):
                        raise TransitionError(
                            "new_mechanism must add a genuinely distinct untouched axis"
                        )
                    if proposed_axis is not None and (
                        not isinstance(proposed_axis, Mapping)
                        or not isinstance(proposed_axis_identity, str)
                        or added != {proposed_axis.get("axis_id")}
                        or new_axes.get(proposed_axis.get("axis_id"))
                        != dict(proposed_axis)
                        or proposed_axis.get("axis_identity")
                        != proposed_axis_identity
                    ):
                        raise TransitionError(
                            "new mechanism differs from its exact proposed axis"
                        )
                    if continuation is not None:
                        added_axes = {
                            axis_id: new_axes[axis_id] for axis_id in added
                        }
                        resolved_families = {
                            axis_id: self._axis_resolved_architecture_family(
                                index=index,
                                axis=axis,
                            )
                            for axis_id, axis in added_axes.items()
                        }
                        try:
                            required_target_axis_ids = list(
                                eligible_new_mechanism_axes(
                                    continuation,
                                    added_axes=added_axes,
                                    resolved_architecture_families=resolved_families,
                                )
                            )
                        except ArchitectureReviewDirectionError as exc:
                            raise TransitionError(str(exc)) from exc
                        constraint_source_id = continuation.architecture_review_id
                    else:
                        required_layers = set(
                            next_action.get("required_followup_layers", [])
                        )
                        excluded_layers = set(
                            next_action.get("excluded_research_layers", [])
                        )
                        excluded_architecture = next_action.get(
                            "excluded_architecture_family"
                        )
                        constrained = bool(
                            required_layers
                            or excluded_layers
                            or isinstance(excluded_architecture, str)
                        )
                    if continuation is None and constrained:
                        required_target_axis_ids = sorted(
                            axis_id
                            for axis_id in added
                            if (
                                not required_layers
                                or new_axes[axis_id]["primary_research_layer"]
                                in required_layers
                            )
                            and new_axes[axis_id]["primary_research_layer"]
                            not in excluded_layers
                            and (
                                not isinstance(excluded_architecture, str)
                                or (
                                    isinstance(
                                        new_axes[axis_id].get(
                                            "architecture_chassis_identity"
                                        ),
                                        str,
                                    )
                                    and new_axes[axis_id][
                                        "architecture_chassis_identity"
                                    ]
                                    != excluded_architecture
                                )
                            )
                        )
                        if not required_target_axis_ids:
                            raise TransitionError(
                                "new mechanism does not satisfy its diagnosis or architecture constraint"
                            )
                        source = next_action.get("constraint_source_id")
                        if not isinstance(source, str):
                            raise TransitionError(
                                "constrained Portfolio mutation lacks its source"
                            )
                        constraint_source_id = source
                else:
                    raise TransitionError(
                        "Portfolio Decision does not authorize snapshot mutation"
                    )
            body = self._body(current)
            body["next_action"] = {
                "kind": "portfolio_decision",
                "portfolio_snapshot_id": snapshot.identity,
            }
            if continuation is not None:
                body["next_action"].update(
                    continuation.with_materialized_targets(
                        tuple(required_target_axis_ids)
                    ).to_action_fields()
                )
            elif required_target_axis_ids:
                body["next_action"].update(
                    {
                        "constraint_source_id": constraint_source_id,
                        "required_target_axis_ids": required_target_axis_ids,
                    }
                )
            if replay_constraints is not None:
                body["next_action"].update(replay_constraints)
            record = _record(
                kind="portfolio-snapshot",
                record_id=snapshot.identity,
                subject=f"Mission:{snapshot.mission_id}",
                status=(
                    "closed"
                    if all(axis.status == "pruned" for axis in snapshot.axes)
                    else "current"
                ),
                fingerprint=snapshot.identity.removeprefix("portfolio:"),
                payload=snapshot.to_identity_payload(),
                event_stream=f"portfolio:{snapshot.mission_id}",
                event_sequence=sequence,
            )
            result = {"portfolio_snapshot_id": snapshot.identity}
            if replay_scheduler_projection_recovered:
                result["replay_scheduler_projection_recovered"] = True
            return body, [record], result

        return self._commit(
            event_kind="portfolio_snapshot_recorded",
            operation_id=operation_id,
            subject=f"Mission:{snapshot.mission_id}",
            payload={"portfolio_snapshot_id": snapshot.identity},
            prepare=prepare,
        )

    def record_axis_reopen_authority(
        self,
        *,
        operation_id: str,
    ) -> TransitionResult:
        """Authorize exactly one audit-deferred historical prune to be preserved."""

        from axiom_rift.research.effective_axis import (
            AxisReopenAuthority,
            axis_reopen_evidence,
        )

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("axis reopen authority requires control")
            science = current["scientific"]
            mission_id = science.get("active_mission")
            if (
                not isinstance(mission_id, str)
                or science.get("active_initiative") is None
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "axis reopen authority requires a stable Initiative boundary"
                )
            next_action = current.get("next_action")
            if (
                not isinstance(next_action, Mapping)
                or next_action.get("kind")
                != "record_axis_reopen_authority"
            ):
                raise TransitionError(
                    "no exact audit-deferred axis reopen is pending"
                )
            snapshot_id = next_action.get("portfolio_snapshot_id")
            decision_id = next_action.get("decision_id")
            target_id = next_action.get("target_id")
            target_identity = next_action.get("target_axis_identity")
            portfolio_head = index.event_head(f"portfolio:{mission_id}")
            snapshot = (
                None
                if not isinstance(snapshot_id, str)
                else index.get("portfolio-snapshot", snapshot_id)
            )
            decision = (
                None
                if not isinstance(decision_id, str)
                else self._active_portfolio_decision(index, decision_id)
            )
            axes = (
                {}
                if snapshot is None
                else {
                    axis.get("axis_id"): axis
                    for axis in snapshot.payload.get("axes", ())
                    if isinstance(axis, Mapping)
                    and isinstance(axis.get("axis_id"), str)
                }
            )
            axis = axes.get(target_id)
            if (
                portfolio_head is None
                or portfolio_head.record_id != snapshot_id
                or snapshot is None
                or snapshot.subject != f"Mission:{mission_id}"
                or decision is None
                or decision.subject != f"Mission:{mission_id}"
                or decision.payload.get("portfolio_snapshot_id") != snapshot_id
                or decision.payload.get("target_axis_identity")
                != target_identity
                or decision.status != "preserve"
                or next_action.get("action") != "preserve"
                or axis is None
                or axis.get("axis_identity") != target_identity
                or axis.get("status") != "pruned"
            ):
                raise TransitionError(
                    "axis reopen authority lost its exact Decision and snapshot"
                )
            resolution = self._effective_axis_resolution(index, axis)
            reopen_evidence = axis_reopen_evidence(resolution)
            if decision.payload.get("effective_axis") != (
                resolution.to_projection_payload()
            ):
                raise TransitionError(
                    "axis reopen Decision authority is stale"
                )
            expected_action: dict[str, Any] = {
                "action": "preserve",
                "decision_id": decision.record_id,
                "kind": "record_axis_reopen_authority",
                "portfolio_snapshot_id": snapshot.record_id,
                "target_axis_identity": target_identity,
                "target_id": target_id,
            }
            expected_action.update(reopen_evidence.to_action_fields())
            decision_obligations = decision.payload.get(
                "replay_obligation_ids"
            )
            if isinstance(decision_obligations, list) and decision_obligations:
                expected_action["replay_obligation_ids"] = list(
                    decision_obligations
                )
            expected_action = self._with_replay_scheduler_constraints(
                expected_action,
                self._replay_scheduler_constraints(
                    index,
                    mission_id=mission_id,
                ),
            )
            if dict(next_action) != expected_action:
                raise TransitionError(
                    "axis reopen action differs from its exact audit evidence"
                )
            authority = AxisReopenAuthority(
                mission_id=mission_id,
                portfolio_snapshot_id=snapshot.record_id,
                portfolio_decision_id=decision.record_id,
                axis_id=target_id,
                axis_identity=target_identity,
                replay_resolution_record_ids=(
                    reopen_evidence.replay_resolution_record_ids
                ),
                evidence_scope_overlay_ids=(
                    reopen_evidence.evidence_scope_overlay_ids
                ),
                historical_cost_completion_ids=(
                    reopen_evidence.historical_cost_completion_ids
                ),
                historical_cost_latch_ids=(
                    reopen_evidence.historical_cost_latch_ids
                ),
                historical_cost_negative_memory_ids=(
                    reopen_evidence.historical_cost_negative_memory_ids
                ),
            )
            stream = f"axis-reopen:{mission_id}:{target_identity}"
            stream_head = index.event_head(stream)
            record = _record(
                kind="axis-reopen-authority",
                record_id=authority.identity,
                subject=f"Axis:{target_identity}",
                status="authorized",
                fingerprint=authority.identity.removeprefix(
                    "axis-reopen-authority:"
                ),
                payload={
                    "authority": authority.to_identity_payload(),
                    "candidate_delta": 0,
                    "claim_delta": "none",
                    "effective_axis": resolution.to_projection_payload(),
                    "holdout_delta": 0,
                    "scientific_credit": 0,
                    "trial_delta": 0,
                },
                event_stream=stream,
                event_sequence=(
                    1 if stream_head is None else stream_head.sequence + 1
                ),
            )
            body = self._body(current)
            snapshot_action = dict(next_action)
            snapshot_action["kind"] = "record_portfolio_snapshot"
            snapshot_action["axis_reopen_authority_id"] = authority.identity
            for field in reopen_evidence.to_action_fields():
                snapshot_action.pop(field)
            body["next_action"] = snapshot_action
            return body, [record], {
                "axis_id": target_id,
                "axis_reopen_authority_id": authority.identity,
                "candidate_delta": 0,
                "claim_delta": "none",
                "holdout_delta": 0,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="axis_reopen_authority_recorded",
            operation_id=operation_id,
            subject="Portfolio:active",
            payload={"transition": "audit_deferred_prune_reopen"},
            prepare=prepare,
        )

    def record_portfolio_decision(
        self,
        *,
        decision: Any,
        operation_id: str,
        replacement_replay_batch_spec: Any | None = None,
        replacement_replay_implementation_request: Any | None = None,
        replacement_replay_study_payload: Mapping[str, Any] | None = None,
        replacement_semantic_question_lineage: Any | None = None,
    ) -> TransitionResult:
        from axiom_rift.research.portfolio import PortfolioAction, PortfolioDecision
        from axiom_rift.operations.architecture_review_direction import (
            ARCHITECTURE_CONTINUATION_ACTION_FIELDS,
            ArchitectureReviewDirectionError,
            constraint_from_action,
            require_decision_direction,
            require_existing_axis_binding,
            require_review_binding,
            required_quant_team_basis,
        )

        self._require_study_close_delivery_guard()

        if not isinstance(decision, PortfolioDecision):
            raise TransitionError("decision must be a PortfolioDecision")
        decision_hash = decision.identity.removeprefix("decision:")
        _require_digest("decision hash", decision_hash)

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("Portfolio Decision requires an active Mission")
            science = current["scientific"]
            if science["active_initiative"] is None:
                raise TransitionError("Portfolio Decision requires an active Initiative")
            if any(
                science[name] is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError("Portfolio Decision cannot bypass active work")
            portfolio_head = _index.event_head(
                f"portfolio:{science['active_mission']}"
            )
            snapshot = (
                None
                if portfolio_head is None
                else _index.get(portfolio_head.record_kind, portfolio_head.record_id)
            )
            if snapshot is None or snapshot.kind != "portfolio-snapshot":
                raise TransitionError("Portfolio Decision requires a current snapshot")
            review = decision.quant_team_review
            if (
                not self.engineering_fixture
                and review is None
            ):
                raise TransitionError(
                    "real Portfolio Decision requires a plural quant-team review"
                )
            if review is not None:
                review_basis = {
                    (basis.kind, basis.record_id)
                    for assessment in review.assessments
                    for basis in assessment.basis_records
                }
                if any(
                    _index.get(kind, record_id) is None
                    for kind, record_id in review_basis
                ):
                    raise TransitionError(
                        "quant-team review cites unavailable durable evidence"
                    )
                if ("portfolio-snapshot", snapshot.record_id) not in review_basis:
                    raise TransitionError(
                        "quant-team review does not bind the current Portfolio"
                    )
            next_action = current["next_action"]
            try:
                continuation = constraint_from_action(next_action)
            except ArchitectureReviewDirectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            if (
                next_action.get("kind") != "portfolio_decision"
                or (
                    next_action.get("portfolio_snapshot_id") is not None
                    and next_action.get("portfolio_snapshot_id") != snapshot.record_id
                )
            ):
                raise TransitionError("Portfolio Decision is not the exact next action")
            axis_values = tuple(snapshot.payload["axes"])
            axes_by_id = {axis["axis_id"]: axis for axis in axis_values}
            axis_resolutions = self._effective_axis_resolutions(
                _index,
                axis_values,
            )
            effective_axes = {
                axis["axis_id"]: resolution
                for axis, resolution in zip(
                    axis_values,
                    axis_resolutions,
                    strict=True,
                )
            }
            option_eligible_targets = {
                axis_id
                for axis_id, resolution in effective_axes.items()
                if resolution.decision_option_eligible
            }
            if any(
                option.target_id not in option_eligible_targets
                for option in decision.options
            ):
                raise TransitionError(
                    "Portfolio Decision names an undeclared or effectively blocked target axis"
                )
            chosen_effective_axis = effective_axes[decision.chosen.target_id]
            if chosen_effective_axis.requires_reopen and decision.chosen.action not in {
                PortfolioAction.PRESERVE,
                PortfolioAction.PRUNE,
            }:
                raise TransitionError(
                    "deferred Portfolio axis requires an exact preserve/reopen "
                    "Decision before scientific work"
                )
            if (
                not chosen_effective_axis.selectable
                and not chosen_effective_axis.requires_reopen
            ):
                raise TransitionError(
                    "Portfolio Decision chosen axis is effectively blocked"
                )
            required_target_axis_ids = next_action.get("required_target_axis_ids")
            if required_target_axis_ids is not None and (
                not isinstance(required_target_axis_ids, list)
                or not required_target_axis_ids
                or required_target_axis_ids != sorted(set(required_target_axis_ids))
                or any(type(item) is not str for item in required_target_axis_ids)
                or any(
                    item not in option_eligible_targets
                    for item in required_target_axis_ids
                )
            ):
                raise TransitionError(
                    "Portfolio Decision bypasses its admitted constrained axis"
                )
            if (
                continuation is None
                and required_target_axis_ids is not None
                and decision.chosen.target_id not in required_target_axis_ids
            ):
                raise TransitionError(
                    "Portfolio Decision bypasses its admitted constrained axis"
                )
            constraint_source_id = next_action.get("constraint_source_id")
            if constraint_source_id is not None and (
                type(constraint_source_id) is not str
                or not constraint_source_id
                or not constraint_source_id.isascii()
            ):
                raise TransitionError("Portfolio Decision constraint source is invalid")
            if required_target_axis_ids is not None and constraint_source_id is None:
                raise TransitionError(
                    "Portfolio Decision constrained axes lack their exact source"
                )
            work_actions = {
                PortfolioAction.COMPLEMENTARY_SLEEVE,
                PortfolioAction.CONTRAST,
                PortfolioAction.DEEPEN,
                PortfolioAction.RECOMBINE,
                PortfolioAction.ROTATE,
                PortfolioAction.SYNTHESIZE,
            }
            from axiom_rift.operations.replay_projection import (
                ReplayProjectionError,
                ReplayTransitionError,
                is_exact_replay_protocol_revision_selection,
                validate_decision_selection,
                validate_replay_review_basis,
            )

            try:
                replay_constraints = validate_decision_selection(
                    _index,
                    mission_id=science["active_mission"],
                    next_action=next_action,
                    replay_obligation_ids=decision.replay_obligation_ids,
                    action=decision.chosen.action.value,
                    target_axis_id=decision.chosen.target_id,
                    work_actions=frozenset(item.value for item in work_actions),
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            if review is not None:
                try:
                    validate_replay_review_basis(
                        constraints=replay_constraints,
                        selected_obligation_ids=decision.replay_obligation_ids,
                        review_basis=review_basis,
                    )
                except ReplayProjectionError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                except ReplayTransitionError as exc:
                    raise TransitionError(str(exc)) from exc
            scheduler_constraints = None
            if continuation is not None:
                scheduler_constraints = {
                    name: next_action[name]
                    for name in ARCHITECTURE_CONTINUATION_ACTION_FIELDS
                    if name in next_action
                }
            elif (
                required_target_axis_ids is not None
                or constraint_source_id is not None
            ):
                scheduler_constraints = {
                    "constraint_source_id": constraint_source_id,
                    "required_target_axis_ids": required_target_axis_ids,
                }
            if replay_constraints is not None:
                scheduler_constraints = {**(scheduler_constraints or {}), **replay_constraints}
            if (
                decision.recent_positive_lineage_id is not None
                and decision.recent_positive_lineage_id not in option_eligible_targets
                and _index.get("lineage", decision.recent_positive_lineage_id) is None
            ):
                raise TransitionError("recent-positive reference is not durable")
            target_axis = axes_by_id[decision.chosen.target_id]
            protocol_revision = decision.protocol_revision
            if protocol_revision is not None:
                from axiom_rift.operations.replay_projection import (
                    obligation_heads,
                    require_initial_completion_validity_revision_record,
                    require_scientific_change_return_record,
                    require_satisfaction_invalidation_record,
                )
                from axiom_rift.operations.semantic_question_registry import (
                    SemanticQuestionRegistryError,
                    SemanticQuestionRegistryIntegrityError,
                    require_semantic_question_study_binding,
                )
                from axiom_rift.operations.replay_projection import (
                    ReplayObligationStatus,
                )

                lineage = protocol_revision.semantic_question_lineage
                current_axis_architecture_authority = (
                    self._axis_architecture_authority_identity(
                        _index,
                        target_axis,
                    )
                )
                matching_obligations = tuple(
                    (obligation, head)
                    for obligation, head in obligation_heads(
                        _index,
                        mission_id=science["active_mission"],
                    )
                    if obligation.identity
                    == protocol_revision.replay_obligation_id
                )
                if (
                    decision.chosen.action
                    is not PortfolioAction.REVISE_PROTOCOL
                    or protocol_revision.mission_id
                    != science["active_mission"]
                    or protocol_revision.axis_id
                    != decision.chosen.target_id
                    or protocol_revision.predecessor_axis_identity
                    != target_axis.get("axis_identity")
                    or protocol_revision.mechanism_family
                    != target_axis.get("mechanism_family")
                    or protocol_revision.predecessor_architecture_family
                    != current_axis_architecture_authority
                    or lineage.successor_study_id
                    == lineage.predecessor_study_id
                    or _index.get("study-open", lineage.successor_study_id)
                    is not None
                    or len(matching_obligations) != 1
                ):
                    raise TransitionError(
                        "protocol revision authority differs from its current axis"
                    )
                obligation, obligation_head = matching_obligations[0]
                initial_completion_revision = (
                    protocol_revision.authority_kind
                    == "historical-scientific-validity-invalidation"
                )
                if obligation_head.status != ReplayObligationStatus.PENDING.value:
                    raise TransitionError(
                        "protocol revision lacks its current replay authority"
                    )
                if initial_completion_revision:
                    if (
                        obligation_head.kind != "historical-replay-obligation"
                        or obligation_head.record_id != obligation.identity
                    ):
                        raise TransitionError(
                            "initial protocol revision lacks its current replay "
                            "obligation"
                        )
                elif (
                    obligation_head.kind != protocol_revision.authority_kind
                    or obligation_head.record_id
                    != protocol_revision.authority_record_id
                ):
                    raise TransitionError(
                        "protocol revision lacks its current replay authority"
                    )
                try:
                    if (
                        protocol_revision.authority_kind
                        == "historical-replay-satisfaction-invalidation"
                    ):
                        require_satisfaction_invalidation_record(
                            _index,
                            obligation=obligation,
                            record=obligation_head,
                        )
                    elif (
                        protocol_revision.authority_kind
                        == "historical-replay-scientific-change-return"
                    ):
                        require_scientific_change_return_record(
                            _index,
                            obligation=obligation,
                            record=obligation_head,
                        )
                    else:
                        require_initial_completion_validity_revision_record(
                            _index,
                            obligation=obligation,
                            invalidation_record_id=(
                                protocol_revision.authority_record_id
                            ),
                        )
                    require_semantic_question_study_binding(
                        _index,
                        study_id=lineage.predecessor_study_id,
                        core_id=lineage.predecessor_core_id,
                    )
                except (
                    ReplayProjectionError,
                    SemanticQuestionRegistryIntegrityError,
                ) as exc:
                    raise RecoveryRequired(str(exc)) from exc
                except SemanticQuestionRegistryError as exc:
                    raise TransitionError(str(exc)) from exc
                if any(
                    ":" not in reference
                    or _index.get(*reference.split(":", 1)) is None
                    for reference in lineage.basis_record_ids
                ):
                    raise TransitionError(
                        "protocol revision lineage cites unavailable evidence"
                    )
                if (
                    review is not None
                    and (
                        protocol_revision.authority_kind,
                        protocol_revision.authority_record_id,
                    )
                    not in review_basis
                ):
                    raise TransitionError(
                        "quant-team review omits the protocol revision basis"
                    )
            baseline = decision.baseline_executable
            architecture = decision.architecture_chassis
            component_records: list[IndexRecord] = []
            baseline_provenance: dict[str, Any] | None = None
            resolved_architecture_family: str | None = None
            replacement_architecture_equivalence: dict[str, Any] | None = None
            replacement_replay_study: dict[str, Any] | None = None
            replacement_trigger_for_decision: IndexRecord | None = None
            source_authority_subject_ids: tuple[str, ...] = ()
            if baseline is not None:
                source_authority_subject_ids = self._source_authority_subject_ids(
                    baseline.to_identity_payload(),
                    error_type=TransitionError,
                )
            if not self.engineering_fixture and decision.chosen.action in work_actions:
                if baseline is None or architecture is None:
                    raise TransitionError(
                        "scientific Portfolio Decision must bind a baseline Executable chassis"
                    )
                typed_axis_identity = target_axis.get(
                    "architecture_chassis_identity"
                )
                typed_axis_payload = target_axis.get("architecture_chassis")
                prior_anchor = self._axis_architecture_anchor(_index, target_axis)
                resolved_architecture_family = self._resolved_architecture_family(
                    index=_index,
                    architecture_payload=architecture.to_identity_payload(),
                )
                if isinstance(typed_axis_identity, str):
                    if not isinstance(typed_axis_payload, dict):
                        raise RecoveryRequired(
                            "typed Portfolio axis chassis payload is malformed"
                        )
                    typed_axis_family = self._resolved_architecture_family(
                        index=_index,
                        architecture_payload=typed_axis_payload,
                    )
                    if typed_axis_family != resolved_architecture_family:
                        replacement_preflight = (
                            self._current_accepted_replay_replacement_preflight(
                                _index,
                                mission_id=science["active_mission"],
                                obligation_ids=decision.replay_obligation_ids,
                            )
                        )
                        replacement_trigger_for_decision = (
                            replacement_preflight
                        )
                        from axiom_rift.operations.replay_job_implementation_preflight import (
                            PREFLIGHT_SCHEMA,
                            ReplayJobImplementationPreflightError,
                            ReplayJobImplementationPreflightRequest,
                            derive_replay_job_scientific_surface,
                            replay_job_scientific_surface_hash,
                            require_active_replay_job_replacement_binding,
                            require_replacement_replay_baseline_semantics,
                            require_replacement_replay_study_semantics,
                        )
                        from axiom_rift.research.portfolio import BatchSpec
                        from axiom_rift.research.semantic_question import (
                            SemanticQuestionLineageProposal,
                            SemanticQuestionRelation,
                        )

                        try:
                            if not isinstance(
                                replacement_replay_study_payload,
                                Mapping,
                            ):
                                raise ReplayJobImplementationPreflightError(
                                    "replacement replay Study payload is absent"
                                )
                            if not isinstance(
                                replacement_replay_implementation_request,
                                ReplayJobImplementationPreflightRequest,
                            ):
                                raise ReplayJobImplementationPreflightError(
                                    "replacement replay implementation request is absent"
                                )
                            if not isinstance(
                                replacement_replay_batch_spec,
                                BatchSpec,
                            ):
                                raise ReplayJobImplementationPreflightError(
                                    "replacement replay Batch spec is absent"
                                )
                            if (
                                not isinstance(
                                    replacement_semantic_question_lineage,
                                    SemanticQuestionLineageProposal,
                                )
                                or replacement_semantic_question_lineage.relation
                                is not SemanticQuestionRelation.ENGINEERING_REENTRY
                                or replacement_semantic_question_lineage
                                .predecessor_core_id
                                != replacement_semantic_question_lineage
                                .successor_core_id
                                or replacement_semantic_question_lineage
                                .successor_core_id
                                != replacement_replay_study_payload.get(
                                    "semantic_question_core_id"
                                )
                            ):
                                raise ReplayJobImplementationPreflightError(
                                    "replacement replay engineering lineage is absent"
                                )
                            if (
                                replacement_replay_implementation_request
                                .replacement_for_preflight_id
                                is not None
                            ):
                                raise ReplayJobImplementationPreflightError(
                                    "active replacement request cannot replace a preflight"
                                )
                            replacement_replay_study = _copy(
                                replacement_replay_study_payload
                            )
                            active_surface = (
                                derive_replay_job_scientific_surface(
                                    replacement_replay_implementation_request,
                                    study_payload=(
                                        replacement_replay_study
                                    ),
                                    batch_payload={
                                        "spec": (
                                            replacement_replay_batch_spec
                                            .to_identity_payload()
                                        )
                                    },
                                    artifact_reader=(
                                        self.evidence.read_verified
                                    ),
                                )
                            )
                            active_surface_hash = (
                                replay_job_scientific_surface_hash(
                                    active_surface
                                )
                            )
                            require_active_replay_job_replacement_binding(
                                accepted_payload=(
                                    {}
                                    if replacement_preflight is None
                                    else replacement_preflight.payload
                                ),
                                active_payload={
                                    "callable_identity": (
                                        replacement_replay_implementation_request
                                        .callable_identity
                                    ),
                                    "executable_ids": list(
                                        replacement_replay_implementation_request
                                        .executable_ids
                                    ),
                                    "executable_manifests": [
                                        executable.to_identity_payload()
                                        for executable in (
                                            replacement_replay_implementation_request
                                            .executables
                                        )
                                    ],
                                    "implementation_identity": (
                                        replacement_replay_implementation_request
                                        .implementation_identity
                                    ),
                                    "mission_id": (
                                        replacement_replay_implementation_request
                                        .mission_id
                                    ),
                                    "protocol_id": (
                                        replacement_replay_implementation_request
                                        .protocol_id
                                    ),
                                    "replacement_for_preflight_id": None,
                                    "replay_obligation_ids": list(
                                        replacement_replay_implementation_request
                                        .replay_obligation_ids
                                    ),
                                    "schema": PREFLIGHT_SCHEMA,
                                    "scientific_surface": active_surface,
                                    "scientific_surface_hash": (
                                        active_surface_hash
                                    ),
                                },
                            )
                            baseline_equivalence_hash = (
                                require_replacement_replay_baseline_semantics(
                                    accepted_payload=(
                                        {}
                                        if replacement_preflight is None
                                        else replacement_preflight.payload
                                    ),
                                    baseline_executable_manifest=(
                                        baseline.to_identity_payload()
                                    ),
                                )
                            )
                            study_equivalence_hash = (
                                require_replacement_replay_study_semantics(
                                    accepted_payload=(
                                        {}
                                        if replacement_preflight is None
                                        else replacement_preflight.payload
                                    ),
                                    study_payload=replacement_replay_study,
                                )
                            )
                        except ReplayJobImplementationPreflightError as exc:
                            raise TransitionError(
                                "Portfolio Decision baseline differs from its "
                                "typed axis chassis"
                            ) from exc
                        assert replacement_preflight is not None
                        replacement_chassis = (
                            replacement_replay_study.get(
                                "controlled_chassis"
                            )
                            if isinstance(replacement_replay_study, Mapping)
                            else None
                        )
                        replacement_question = (
                            replacement_replay_study.get("question")
                            if isinstance(replacement_replay_study, Mapping)
                            else None
                        )
                        replacement_proposal = (
                            replacement_replay_study.get(
                                "semantic_proposal"
                            )
                            if isinstance(replacement_replay_study, Mapping)
                            else None
                        )
                        if (
                            baseline_equivalence_hash
                            != study_equivalence_hash
                            or not isinstance(replacement_chassis, Mapping)
                            or replacement_chassis.get(
                                "baseline_executable"
                            )
                            != baseline.to_identity_payload()
                            or replacement_chassis.get("architecture")
                            != architecture.to_identity_payload()
                            or replacement_replay_study.get("mission_id")
                            != science["active_mission"]
                            or replacement_replay_study.get(
                                "replay_obligation_ids"
                            )
                            != list(decision.replay_obligation_ids)
                            or replacement_replay_study.get(
                                "portfolio_action"
                            )
                            != decision.chosen.action.value
                            or replacement_replay_study.get(
                                "mechanism_family"
                            )
                            != target_axis.get("mechanism_family")
                            or replacement_replay_study.get(
                                "primary_research_layer"
                            )
                            != target_axis.get("primary_research_layer")
                            or replacement_replay_study.get(
                                "changed_domains"
                            )
                            != target_axis.get("changed_domains")
                            or replacement_replay_study.get(
                                "controlled_domains"
                            )
                            != target_axis.get("controlled_domains")
                            or not isinstance(replacement_question, Mapping)
                            or replacement_question.get("causal_question")
                            != target_axis.get("causal_question")
                            or not isinstance(replacement_proposal, Mapping)
                            or replacement_proposal.get("mechanism")
                            != target_axis.get("mechanism_family")
                        ):
                            raise TransitionError(
                                "Portfolio Decision replacement Study differs "
                                "from its reused axis"
                            )
                        replacement_study_binding_hash = _digest(
                            replacement_replay_study,
                            domain="replay-replacement-study-binding",
                        )
                        replacement_architecture_equivalence = {
                            "accepted_replacement_preflight_id": (
                                replacement_preflight.record_id
                            ),
                            "accepted_axis_architecture_family": (
                                typed_axis_family
                            ),
                            "replacement_architecture_family": (
                                resolved_architecture_family
                            ),
                            "replacement_baseline_executable_id": (
                                baseline.identity
                            ),
                            "replay_obligation_ids": list(
                                decision.replay_obligation_ids
                            ),
                            "replacement_executable_ids": list(
                                replacement_replay_implementation_request
                                .executable_ids
                            ),
                            "replacement_batch_id": (
                                replacement_replay_batch_spec.identity
                            ),
                            "replacement_request_identity": (
                                replacement_replay_implementation_request
                                .identity
                            ),
                            "replacement_lineage_id": (
                                replacement_semantic_question_lineage.identity
                            ),
                            "schema": (
                                "replay_replacement_architecture_equivalence.v1"
                            ),
                            "scientific_equivalence_hash": (
                                study_equivalence_hash
                            ),
                            "prospective_study_binding_hash": (
                                replacement_study_binding_hash
                            ),
                            "target_axis_identity": target_axis[
                                "axis_identity"
                            ],
                        }
                if not isinstance(typed_axis_identity, str) and prior_anchor is not None and (
                    (
                        self._resolved_architecture_family(
                            index=_index,
                            architecture_payload=prior_anchor[
                                "architecture_chassis"
                            ],
                        )
                        if isinstance(
                            prior_anchor.get("architecture_chassis"), dict
                        )
                        else prior_anchor["architecture_chassis_identity"]
                    )
                    != resolved_architecture_family
                ):
                    raise TransitionError(
                        "legacy Portfolio axis cannot change its prospective chassis anchor"
                    )
                if (
                    not isinstance(typed_axis_identity, str)
                    and prior_anchor is not None
                    and replacement_architecture_equivalence is None
                    and (
                        prior_anchor.get("baseline_executable_id")
                        != baseline.identity
                        or prior_anchor.get("baseline_executable")
                        != baseline.to_identity_payload()
                    )
                ):
                    raise TransitionError(
                        "legacy Portfolio axis cannot change its prospective "
                        "baseline anchor"
                    )
                prior_baseline = (
                    None
                    if replacement_architecture_equivalence is not None
                    else self._prior_scientific_baseline(
                        _index,
                        baseline,
                        portfolio_axis_identity=target_axis[
                            "axis_identity"
                        ],
                    )
                )
                bootstrap_anchors = [
                    record
                    for record in _index.records_by_payload_text(
                        "portfolio-decision",
                        "target_axis_identity",
                        target_axis["axis_identity"],
                    )
                    if self._active_portfolio_decision(_index, record.record_id)
                    is not None
                    and record.payload.get("baseline_executable_id") == baseline.identity
                    and record.payload.get("baseline_executable")
                    == baseline.to_identity_payload()
                    and isinstance(record.payload.get("baseline_provenance"), dict)
                    and record.payload["baseline_provenance"].get("kind")
                    in {
                        "first_controlled_chassis_bootstrap",
                        "first_axis_controlled_chassis_bootstrap",
                    }
                    and record.payload.get("target_axis_identity")
                    == target_axis["axis_identity"]
                ]
                if len(bootstrap_anchors) > 1:
                    raise RecoveryRequired(
                        "controlled chassis has conflicting bootstrap anchors"
                    )
                has_data_contract_trials = any(
                    isinstance(record.payload.get("executable"), dict)
                    and record.payload["executable"].get("data_contract")
                    == baseline.data_contract
                    for record in _index.records_by_payload_text(
                        "trial",
                        "trial_data_contract",
                        baseline.data_contract,
                    )
                )
                axis_has_controlled_history = any(
                    isinstance(record.payload.get("controlled_chassis"), dict)
                    and record.payload.get("portfolio_axis_identity")
                    == target_axis["axis_identity"]
                    for record in _index.records_by_payload_text(
                        "study-open",
                        "portfolio_axis_identity",
                        target_axis["axis_identity"],
                    )
                )
                has_any_controlled_history = (
                    _index.has_controlled_chassis_study()
                )
                baseline_provenance = (
                    {
                        "kind": "accepted_replay_replacement",
                        "record_id": replacement_architecture_equivalence[
                            "accepted_replacement_preflight_id"
                        ],
                    }
                    if replacement_architecture_equivalence is not None
                    else
                    {
                        "kind": "trial",
                        "record_id": prior_baseline.record_id,
                    }
                    if prior_baseline is not None
                    else {
                        "kind": "controlled_chassis_anchor_reuse",
                        "record_id": bootstrap_anchors[0].record_id,
                    }
                    if bootstrap_anchors
                    else {
                        "data_contract": baseline.data_contract,
                        **(
                            {
                                "kind": "first_axis_controlled_chassis_bootstrap",
                                "portfolio_axis_identity": target_axis[
                                    "axis_identity"
                                ],
                            }
                            if has_data_contract_trials
                            and has_any_controlled_history
                            and not axis_has_controlled_history
                            else {
                                "kind": (
                                    "first_controlled_chassis_bootstrap"
                                    if has_data_contract_trials
                                    else "first_data_contract_bootstrap"
                                )
                            }
                        ),
                    }
                )
                component_records = self._project_executable_components(
                    _index, baseline
                )
                effective_target = self._effective_axis_resolution(
                    _index,
                    target_axis,
                    prospective_source_ids=source_authority_subject_ids,
                )
                if not effective_target.selectable:
                    raise TransitionError(
                        "Portfolio Decision baseline uses an invalidated source; "
                        "a new SourceContract and axis are required"
                    )
            elif (
                not self.engineering_fixture
                and (baseline is not None or architecture is not None)
            ):
                raise TransitionError(
                    "structural Portfolio Decision cannot pre-register a Study baseline"
                )
            if (
                (
                    replacement_replay_study_payload is not None
                    or replacement_replay_implementation_request is not None
                    or replacement_replay_batch_spec is not None
                    or replacement_semantic_question_lineage is not None
                )
                and replacement_replay_study is None
            ):
                raise TransitionError(
                    "replacement replay Study authority is unnecessary"
                )
            target_architecture_identity = resolved_architecture_family
            if target_architecture_identity is None:
                target_architecture_identity = (
                    self._axis_resolved_architecture_family(
                        index=_index,
                        axis=target_axis,
                    )
                )
            diagnosis_id = next_action.get("study_diagnosis_id")
            diagnosis = (
                None
                if not isinstance(diagnosis_id, str)
                else _index.get("study-diagnosis", diagnosis_id)
            )
            diagnosis_structural_forest_exit = False
            if isinstance(diagnosis_id, str):
                if (
                    diagnosis is None
                    or diagnosis.payload.get("mission_id")
                    != science["active_mission"]
                    or diagnosis.payload.get("portfolio_snapshot_id")
                    != snapshot.record_id
                ):
                    raise TransitionError(
                        "Portfolio Decision Study diagnosis is absent or stale"
                    )
                allowed_actions = set(diagnosis.payload.get("allowed_actions", []))
                allowed_layers = set(
                    diagnosis.payload.get("allowed_research_layers", [])
                )
                source_axis_id = diagnosis.payload.get("portfolio_axis_id")
                source_axis = axes_by_id.get(source_axis_id)
                chosen_action = decision.chosen.action.value
                same_axis_disposition = (
                    decision.chosen.target_id == source_axis_id
                    and chosen_action in {"preserve", "prune"}
                    and chosen_action in allowed_actions
                )
                branch_match = (
                    chosen_action not in {"preserve", "prune"}
                    and chosen_action in allowed_actions
                    and (
                        target_axis["primary_research_layer"] in allowed_layers
                        or chosen_action == "new_mechanism"
                    )
                )
                forest_diversion = (
                    source_axis is not None
                    and decision.chosen.target_id != source_axis_id
                    and chosen_action
                    in {
                        "complementary_sleeve",
                        "contrast",
                        "recombine",
                        "rotate",
                        "synthesize",
                    }
                    and (
                        target_axis["primary_research_layer"]
                        != source_axis["primary_research_layer"]
                        or (
                            isinstance(target_architecture_identity, str)
                            and target_architecture_identity
                            != diagnosis.payload.get("system_architecture_family")
                        )
                    )
                )
                proposed_axis = decision.proposed_axis
                diagnosis_structural_forest_exit = (
                    chosen_action == "new_mechanism"
                    and source_axis is not None
                    and proposed_axis is not None
                    and proposed_axis.axis_id not in axes_by_id
                    and proposed_axis.mechanism_family
                    not in {
                        axis.get("mechanism_family")
                        for axis in axes_by_id.values()
                    }
                    and (
                        proposed_axis.primary_research_layer.value
                        != source_axis.get("primary_research_layer")
                        or proposed_axis.system_architecture_family
                        != diagnosis.payload.get(
                            "system_architecture_family"
                        )
                    )
                )
                diagnosis_basis = {
                    (item.get("kind"), item.get("record_id"))
                    for item in diagnosis.payload.get("evidence_basis", [])
                    if isinstance(item, Mapping)
                }
                replaced_preflight_id = (
                    None
                    if replacement_trigger_for_decision is None
                    else replacement_trigger_for_decision.payload.get(
                        "replacement_for_preflight_id"
                    )
                )
                engineering_reentry = (
                    diagnosis.payload.get("evidence_state")
                    == "engineering_gap"
                    and decision.chosen.target_id == source_axis_id
                    and chosen_action in {item.value for item in work_actions}
                    and target_axis["primary_research_layer"] in allowed_layers
                    and replacement_architecture_equivalence is not None
                    and replacement_semantic_question_lineage is not None
                    and replacement_semantic_question_lineage
                    .predecessor_study_id
                    == diagnosis.payload.get("study_id")
                    and {
                        "study-diagnosis:" + diagnosis_id,
                        "job-implementation-preflight:"
                        + replaced_preflight_id,
                    }.issubset(
                        set(
                            replacement_semantic_question_lineage
                            .basis_record_ids
                        )
                    )
                    and isinstance(replaced_preflight_id, str)
                    and (
                        "job-implementation-preflight",
                        replaced_preflight_id,
                    )
                    in diagnosis_basis
                )
                replay_protocol_revision = (
                    is_exact_replay_protocol_revision_selection(
                        constraints=replay_constraints,
                        selected_obligation_ids=(
                            decision.replay_obligation_ids
                        ),
                        action=chosen_action,
                        protocol_revision_obligation_id=(
                            None
                            if protocol_revision is None
                            else protocol_revision.replay_obligation_id
                        ),
                    )
                )
                if not (
                    same_axis_disposition
                    or branch_match
                    or forest_diversion
                    or diagnosis_structural_forest_exit
                    or engineering_reentry
                    or replay_protocol_revision
                ):
                    raise TransitionError(
                        "Portfolio Decision does not follow or structurally exit its diagnosis"
                    )
                if engineering_reentry:
                    assert replacement_architecture_equivalence is not None
                    replacement_architecture_equivalence[
                        "engineering_gap_diagnosis_id"
                    ] = diagnosis_id
                if (
                    review is not None
                    and ("study-diagnosis", diagnosis_id) not in review_basis
                ):
                    raise TransitionError(
                        "quant-team review omits its Study-diagnosis basis"
                    )
            architecture_review_id = next_action.get("architecture_review_id")
            architecture_review = (
                None
                if not isinstance(architecture_review_id, str)
                else _index.get("architecture-review", architecture_review_id)
            )
            if isinstance(architecture_review_id, str) and (
                architecture_review is None
                or architecture_review.payload.get("mission_id")
                != science["active_mission"]
            ):
                raise TransitionError(
                    "Portfolio Decision architecture review is absent or stale"
                )
            if (
                review is not None
                and isinstance(architecture_review_id, str)
                and ("architecture-review", architecture_review_id)
                not in review_basis
            ):
                raise TransitionError(
                    "quant-team review omits its architecture-review basis"
                )
            excluded_architecture = next_action.get(
                "excluded_architecture_family"
            )
            excluded_layers = set(
                next_action.get("excluded_research_layers", [])
            )
            if architecture_review is not None:
                conclusion = architecture_review.payload.get("conclusion")
                if conclusion == "bounded_same_architecture":
                    if continuation is None:
                        raise TransitionError(
                            "bounded architecture review lost its continuation"
                        )
                    trigger = _index.get(
                        "architecture-review-trigger",
                        continuation.trigger_record_id,
                    )
                    if trigger is None:
                        raise RecoveryRequired(
                            "bounded architecture review trigger is unavailable"
                        )
                    try:
                        require_review_binding(
                            continuation,
                            review_record_id=architecture_review.record_id,
                            review_payload=architecture_review.payload,
                            trigger_payload=trigger.payload,
                        )
                        if self._review_resolved_architecture_family(
                            index=_index,
                            review=architecture_review,
                        ) != continuation.required_architecture_family:
                            raise ArchitectureReviewDirectionError(
                                "bounded architecture review family is no longer current"
                            )
                        required_axis_ids = set(
                            continuation.required_target_axis_ids
                        )
                        required_axis_ids.add(decision.chosen.target_id)
                        resolved_families = {
                            axis_id: self._axis_resolved_architecture_family(
                                index=_index,
                                axis=axes_by_id[axis_id],
                            )
                            for axis_id in required_axis_ids
                            if axis_id in axes_by_id
                        }
                        require_existing_axis_binding(
                            continuation,
                            axes_by_id=axes_by_id,
                            selectable_axis_ids=frozenset(
                                option_eligible_targets
                            ),
                            resolved_architecture_families=resolved_families,
                        )
                        require_decision_direction(
                            continuation,
                            action=decision.chosen.action.value,
                            target_axis_id=decision.chosen.target_id,
                            target_axis_identity=target_axis["axis_identity"],
                            target_architecture_family=target_architecture_identity,
                        )
                    except ArchitectureReviewDirectionError as exc:
                        raise TransitionError(str(exc)) from exc
                    if review is None or not required_quant_team_basis(
                        continuation
                    ).issubset(review_basis):
                        raise TransitionError(
                            "quant-team review omits bounded architecture bases"
                        )
                elif continuation is not None:
                    raise TransitionError(
                        "legacy architecture review carries a bounded continuation"
                    )
                elif conclusion == "rotate_architecture":
                    reviewed_family = self._review_resolved_architecture_family(
                        index=_index,
                        review=architecture_review,
                    )
                    if (
                        excluded_architecture != reviewed_family
                        or excluded_layers
                    ):
                        raise TransitionError(
                            "Portfolio Decision architecture constraint is malformed"
                        )
                elif conclusion == "change_research_layer":
                    if (
                        excluded_layers
                        != set(
                            architecture_review.payload.get(
                                "primary_research_layers", []
                            )
                        )
                        or excluded_architecture is not None
                    ):
                        raise TransitionError(
                            "Portfolio Decision layer constraint is malformed"
                        )
                else:
                    raise TransitionError(
                        "Portfolio Decision architecture conclusion is invalid"
                    )
            if decision.chosen.action != PortfolioAction.NEW_MECHANISM:
                if (
                    isinstance(excluded_architecture, str)
                    and not isinstance(target_architecture_identity, str)
                ):
                    raise TransitionError(
                        "Portfolio Decision cannot prove architecture rotation from a legacy name"
                    )
                if (
                    isinstance(excluded_architecture, str)
                    and target_architecture_identity == excluded_architecture
                ):
                    raise TransitionError(
                        "Portfolio Decision did not rotate the reviewed architecture"
                    )
                if target_axis["primary_research_layer"] in excluded_layers:
                    raise TransitionError(
                        "Portfolio Decision did not change the reviewed research layer"
                    )
            body = self._body(current)
            audit_deferred_prune_reopen = (
                decision.chosen.action is PortfolioAction.PRESERVE
                and chosen_effective_axis.requires_reopen
                and chosen_effective_axis.snapshot_status == "pruned"
            )
            next_kind = (
                "record_axis_reopen_authority"
                if audit_deferred_prune_reopen
                else (
                    "record_portfolio_snapshot"
                    if decision.chosen.action
                    in {
                        PortfolioAction.NEW_MECHANISM,
                        PortfolioAction.REVISE_PROTOCOL,
                        PortfolioAction.PRESERVE,
                        PortfolioAction.PRUNE,
                    }
                    else "execute_portfolio_decision"
                )
            )
            body["next_action"] = {
                "kind": next_kind,
                "decision_id": decision.identity,
                "action": decision.chosen.action.value,
                "target_id": decision.chosen.target_id,
                "target_axis_identity": target_axis["axis_identity"],
                "portfolio_snapshot_id": snapshot.record_id,
            }
            if decision.replay_obligation_ids:
                body["next_action"]["replay_obligation_ids"] = list(
                    decision.replay_obligation_ids
                )
            if protocol_revision is not None:
                body["next_action"]["protocol_revision_id"] = (
                    protocol_revision.identity
                )
            if audit_deferred_prune_reopen:
                from axiom_rift.research.effective_axis import (
                    axis_reopen_evidence,
                )

                body["next_action"].update(
                    axis_reopen_evidence(
                        chosen_effective_axis
                    ).to_action_fields()
                )
            if next_kind == "execute_portfolio_decision" and not self.engineering_fixture:
                assert baseline is not None and architecture is not None
                body["next_action"].update(
                    {
                        "architecture_chassis_identity": architecture.identity,
                        "resolved_architecture_family": resolved_architecture_family,
                        "baseline_executable_id": baseline.identity,
                    }
                )
                if isinstance(diagnosis_id, str):
                    body["next_action"]["study_diagnosis_id"] = diagnosis_id
                if isinstance(architecture_review_id, str):
                    body["next_action"]["architecture_review_id"] = (
                        architecture_review_id
                    )
                if isinstance(scheduler_constraints, Mapping):
                    body["next_action"].update(
                        {
                            name: scheduler_constraints[name]
                            for name in ARCHITECTURE_CONTINUATION_ACTION_FIELDS
                            if name in scheduler_constraints
                        }
                    )
                if replacement_architecture_equivalence is not None:
                    body["next_action"][
                        "replacement_architecture_equivalence"
                    ] = replacement_architecture_equivalence
            if next_kind == "record_portfolio_snapshot" and (
                decision.chosen.action == PortfolioAction.NEW_MECHANISM
            ):
                constraint_source_id = next_action.get("constraint_source_id")
                if continuation is not None:
                    body["next_action"].update(continuation.to_action_fields())
                    constraint_source_id = continuation.architecture_review_id
                elif (
                    isinstance(diagnosis_id, str)
                    and not diagnosis_structural_forest_exit
                ):
                    body["next_action"]["required_followup_layers"] = list(
                        diagnosis.payload["allowed_research_layers"]
                    )
                    constraint_source_id = diagnosis_id
                if isinstance(excluded_architecture, str):
                    body["next_action"]["excluded_architecture_family"] = (
                        excluded_architecture
                    )
                if excluded_layers:
                    body["next_action"]["excluded_research_layers"] = sorted(
                        excluded_layers
                    )
                if (
                    "required_followup_layers" in body["next_action"]
                    or "excluded_architecture_family" in body["next_action"]
                    or "excluded_research_layers" in body["next_action"]
                ):
                    if not isinstance(constraint_source_id, str):
                        raise TransitionError(
                            "constrained new mechanism lacks its exact source"
                        )
                    body["next_action"]["constraint_source_id"] = (
                        constraint_source_id
                    )
            if next_kind in {
                "record_axis_reopen_authority",
                "record_portfolio_snapshot",
            }:
                body["next_action"] = self._with_replay_scheduler_constraints(
                    body["next_action"],
                    replay_constraints,
                )
            record = _record(
                kind="portfolio-decision",
                record_id=decision.identity,
                subject=f"Mission:{science['active_mission']}",
                status=decision.chosen.action.value,
                fingerprint=decision_hash,
                payload={
                    **decision.to_identity_payload(),
                    "architecture_review_id": architecture_review_id,
                    "baseline_provenance": baseline_provenance,
                    "effective_axis": effective_axes[
                        decision.chosen.target_id
                    ].to_projection_payload(),
                    "portfolio_snapshot_id": snapshot.record_id,
                    "scheduler_constraints": scheduler_constraints,
                    "source_authority_subject_ids": list(
                        source_authority_subject_ids
                    ),
                    "study_diagnosis_id": diagnosis_id,
                    "target_axis_identity": target_axis["axis_identity"],
                    "resolved_architecture_family": resolved_architecture_family,
                    "replacement_architecture_equivalence": (
                        replacement_architecture_equivalence
                    ),
                },
            )
            return body, [*component_records, record], {
                "decision_id": decision.identity
            }

        return self._commit(
            event_kind="portfolio_decision_recorded",
            operation_id=operation_id,
            subject="Portfolio:active",
            payload={"decision_id": decision.identity},
            prepare=prepare,
        )

    def withdraw_pending_portfolio_decision(
        self,
        *,
        manifest_artifact_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Withdraw an accepted but unstarted Decision whose basis was invalidated."""

        from axiom_rift.research.decision_withdrawal import (
            PortfolioDecisionWithdrawalManifest,
            PortfolioDecisionWithdrawalReason,
        )
        from axiom_rift.operations.architecture_review_direction import (
            ARCHITECTURE_CONTINUATION_ACTION_FIELDS,
            ArchitectureReviewDirectionError,
            constraint_from_action,
            require_review_binding,
        )

        _require_digest(
            "Portfolio Decision withdrawal manifest",
            manifest_artifact_hash,
        )
        try:
            manifest_bytes = self.evidence.read_verified(manifest_artifact_hash)
            manifest = PortfolioDecisionWithdrawalManifest.from_bytes(manifest_bytes)
            report_bytes = self.evidence.read_verified(manifest.report_artifact_hash)
            manifest.require_report(report_bytes)
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "Portfolio Decision withdrawal lacks its exact canonical manifest"
            ) from exc
        if (
            manifest.reason_code
            is not PortfolioDecisionWithdrawalReason.SOURCE_AUTHORITY_INVALIDATED
        ):
            raise TransitionError("Portfolio Decision withdrawal reason is unsupported")

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("Portfolio Decision withdrawal requires control")
            science = current["scientific"]
            mission_id = science.get("active_mission")
            initiative_id = science.get("active_initiative")
            if type(mission_id) is not str or type(initiative_id) is not str:
                raise TransitionError(
                    "Portfolio Decision withdrawal requires active Mission work"
                )
            if any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                    "active_holdout_evaluation",
                )
            ):
                raise TransitionError(
                    "Portfolio Decision withdrawal cannot bypass started work"
                )
            next_action = current.get("next_action")
            decision = index.get("portfolio-decision", manifest.decision_id)
            if (
                self._portfolio_decision_withdrawal(
                    index,
                    manifest.decision_id,
                )
                is not None
            ):
                raise TransitionError("Portfolio Decision is already withdrawn")
            if (
                not isinstance(next_action, dict)
                or next_action.get("kind") != "execute_portfolio_decision"
                or next_action.get("decision_id") != manifest.decision_id
                or decision is None
                or decision.subject != f"Mission:{mission_id}"
                or decision.payload.get("portfolio_snapshot_id")
                != next_action.get("portfolio_snapshot_id")
            ):
                raise TransitionError(
                    "Portfolio Decision withdrawal is not the exact unstarted action"
                )
            snapshot = index.get(
                "portfolio-snapshot",
                manifest.portfolio_snapshot_id,
            )
            axes = (
                ()
                if snapshot is None
                else tuple(snapshot.payload.get("axes", ()))
            )
            target_axes = tuple(
                axis
                for axis in axes
                if isinstance(axis, dict)
                and axis.get("axis_id") == manifest.target_axis_id
            )
            resolvable_axes = tuple(
                axis
                for axis in axes
                if isinstance(axis, dict)
                and isinstance(axis.get("axis_id"), str)
            )
            axis_resolutions = self._effective_axis_resolutions(
                index,
                resolvable_axes,
            )
            eligible_axis_ids = {
                axis["axis_id"]
                for axis, resolution in zip(
                    resolvable_axes,
                    axis_resolutions,
                    strict=True,
                )
                if resolution.selectable
            }
            chosen_options = tuple(
                option
                for option in decision.payload.get("options", ())
                if isinstance(option, dict)
                and option.get("option_id")
                == decision.payload.get("chosen_option_id")
            )
            baseline = decision.payload.get("baseline_executable")
            if not isinstance(baseline, Mapping):
                raise RecoveryRequired(
                    "Portfolio Decision source authority baseline is malformed"
                )
            bound_sources = self._source_authority_subject_ids(
                baseline,
                error_type=RecoveryRequired,
            )
            recorded_bound_sources = decision.payload.get(
                "source_authority_subject_ids"
            )
            if (
                recorded_bound_sources is not None
                and recorded_bound_sources != list(bound_sources)
            ):
                raise RecoveryRequired(
                    "Portfolio Decision source authority projection is malformed"
                )
            source_head = index.event_head(
                f"source:{manifest.source_contract_id}"
            )
            source_state = (
                None
                if source_head is None
                else index.get(source_head.record_kind, source_head.record_id)
            )
            if (
                snapshot is None
                or snapshot.record_id != decision.payload.get("portfolio_snapshot_id")
                or len(target_axes) != 1
                or len(chosen_options) != 1
                or chosen_options[0].get("target_id") != manifest.target_axis_id
                or target_axes[0].get("axis_identity")
                != manifest.target_axis_identity
                or decision.payload.get("target_axis_identity")
                != manifest.target_axis_identity
                or next_action.get("target_id") != manifest.target_axis_id
                or next_action.get("target_axis_identity")
                != manifest.target_axis_identity
                or decision.payload.get("baseline_executable_id")
                != manifest.baseline_executable_id
                or (
                    next_action.get("baseline_executable_id") is not None
                    and next_action.get("baseline_executable_id")
                    != manifest.baseline_executable_id
                )
                or manifest.source_contract_id not in bound_sources
                or source_head is None
                or source_state is None
                or source_head.record_id != manifest.source_state_record_id
                or source_state.subject
                != f"Source:{manifest.source_contract_id}"
                or source_state.fingerprint != manifest.source_contract_id
            ):
                raise TransitionError(
                    "Portfolio Decision withdrawal manifest does not bind its exact basis"
                )
            try:
                durable_manifest_bytes = self.evidence.read_verified(
                    manifest_artifact_hash
                )
                durable_report_bytes = self.evidence.read_verified(
                    manifest.report_artifact_hash
                )
                durable_manifest = PortfolioDecisionWithdrawalManifest.from_bytes(
                    durable_manifest_bytes
                )
                durable_manifest.require_report(durable_report_bytes)
            except (OSError, RuntimeError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "Portfolio Decision withdrawal evidence changed before commit"
                ) from exc
            if (
                durable_manifest_bytes != manifest_bytes
                or durable_report_bytes != report_bytes
                or durable_manifest != manifest
            ):
                raise RecoveryRequired(
                    "Portfolio Decision withdrawal evidence changed before commit"
                )
            body = self._body(current)
            replacement_action: dict[str, Any] = {
                "kind": "portfolio_decision",
                "portfolio_snapshot_id": decision.payload["portfolio_snapshot_id"],
            }
            constraints = decision.payload.get("scheduler_constraints")
            if constraints is not None:
                allowed_constraint_fields = {
                    "constraint_source_id",
                    "pending_replay_obligation_ids",
                    "required_replay_priority",
                    "required_target_axis_ids",
                } | set(ARCHITECTURE_CONTINUATION_ACTION_FIELDS)
                if (
                    not isinstance(constraints, dict)
                    or not constraints
                    or not set(constraints).issubset(allowed_constraint_fields)
                ):
                    raise RecoveryRequired(
                        "withdrawn Decision scheduler constraints are malformed"
                    )
                required = constraints.get("required_target_axis_ids")
                source = constraints.get("constraint_source_id")
                if required is not None:
                    if (
                        not isinstance(required, list)
                        or not required
                        or required != sorted(set(required))
                        or any(type(item) is not str for item in required)
                        or any(item not in eligible_axis_ids for item in required)
                        or manifest.target_axis_id not in required
                    ):
                        raise RecoveryRequired(
                            "withdrawn Decision target constraints are malformed"
                        )
                    replacement_action["required_target_axis_ids"] = list(required)
                if source is not None:
                    if (
                        type(source) is not str
                        or not source
                        or not source.isascii()
                    ):
                        raise RecoveryRequired(
                            "withdrawn Decision constraint source is malformed"
                        )
                    replacement_action["constraint_source_id"] = source
                if required is not None and source is None:
                    raise RecoveryRequired(
                        "withdrawn Decision constrained axes lack their source"
                    )
                for name in ARCHITECTURE_CONTINUATION_ACTION_FIELDS:
                    if name in constraints:
                        value = constraints[name]
                        replacement_action[name] = (
                            list(value) if isinstance(value, list) else value
                        )
                replay_constraints = self._replay_scheduler_constraints(
                    index,
                    mission_id=mission_id,
                )
                stored_replay = {
                    name: constraints.get(name)
                    for name in (
                        "pending_replay_obligation_ids",
                        "required_replay_priority",
                    )
                    if constraints.get(name) is not None
                }
                if stored_replay != (replay_constraints or {}):
                    raise RecoveryRequired(
                        "withdrawn Decision replay constraints are stale"
                    )
                replacement_action.update(stored_replay)
            diagnosis_id = decision.payload.get("study_diagnosis_id")
            if isinstance(diagnosis_id, str):
                replacement_action["study_diagnosis_id"] = diagnosis_id
            review_id = decision.payload.get("architecture_review_id")
            if isinstance(review_id, str):
                review = index.get("architecture-review", review_id)
                if review is None or review.payload.get("mission_id") != mission_id:
                    raise RecoveryRequired(
                        "withdrawn Decision architecture review is unavailable"
                    )
                replacement_action["architecture_review_id"] = review_id
                conclusion = review.payload.get("conclusion")
                if conclusion == "bounded_same_architecture":
                    try:
                        continuation = constraint_from_action(replacement_action)
                    except ArchitectureReviewDirectionError as exc:
                        raise RecoveryRequired(str(exc)) from exc
                    trigger = (
                        None
                        if continuation is None
                        else index.get(
                            "architecture-review-trigger",
                            continuation.trigger_record_id,
                        )
                    )
                    if continuation is None or trigger is None:
                        raise RecoveryRequired(
                            "withdrawn bounded architecture direction is unavailable"
                        )
                    try:
                        require_review_binding(
                            continuation,
                            review_record_id=review.record_id,
                            review_payload=review.payload,
                            trigger_payload=trigger.payload,
                        )
                    except ArchitectureReviewDirectionError as exc:
                        raise RecoveryRequired(str(exc)) from exc
                elif conclusion == "rotate_architecture":
                    replacement_action["excluded_architecture_family"] = (
                        self._review_resolved_architecture_family(
                            index=index,
                            review=review,
                        )
                    )
                elif conclusion == "change_research_layer":
                    replacement_action["excluded_research_layers"] = sorted(
                        review.payload.get("primary_research_layers", [])
                    )
                else:
                    raise RecoveryRequired(
                        "withdrawn Decision architecture review is malformed"
                    )
            body["next_action"] = replacement_action
            record_id = canonical_digest(
                domain="portfolio-decision-withdrawal",
                payload={
                    "manifest": manifest.to_identity_payload(),
                    "manifest_artifact_hash": manifest_artifact_hash,
                },
            )
            record = _record(
                kind="portfolio-decision-withdrawal",
                record_id=record_id,
                subject=f"Mission:{mission_id}",
                status="withdrawn_pre_execution",
                fingerprint=decision.fingerprint,
                payload={
                    "decision_id": manifest.decision_id,
                    "manifest": manifest.to_identity_payload(),
                    "manifest_artifact_hash": manifest_artifact_hash,
                    "replacement_next_action": replacement_action,
                },
                event_stream=(
                    f"portfolio-decision-status:{manifest.decision_id}"
                ),
                event_sequence=1,
            )
            return body, [record], {
                "decision_id": manifest.decision_id,
                "withdrawal_record_id": record_id,
            }

        return self._commit(
            event_kind="portfolio_decision_withdrawn",
            operation_id=operation_id,
            subject="Portfolio:active",
            payload={
                "manifest": manifest.to_identity_payload(),
                "manifest_artifact_hash": manifest_artifact_hash,
            },
            prepare=prepare,
        )

    def withdraw_unbound_execution_plan_portfolio_decision(
        self,
        *,
        manifest_artifact_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Withdraw one unstarted scientific action misbound to a mutation step."""

        from axiom_rift.research.decision_withdrawal import (
            PortfolioDecisionWithdrawalReason,
            PortfolioExecutionPlanWithdrawalManifest,
        )

        _require_digest(
            "execution-plan Portfolio Decision withdrawal manifest",
            manifest_artifact_hash,
        )
        try:
            manifest_bytes = self.evidence.read_verified(manifest_artifact_hash)
            manifest = PortfolioExecutionPlanWithdrawalManifest.from_bytes(
                manifest_bytes
            )
            report_bytes = self.evidence.read_verified(
                manifest.report_artifact_hash
            )
            proposed_bytes = self.evidence.read_verified(
                manifest.proposed_snapshot_artifact_hash
            )
            proposed = parse_canonical(proposed_bytes)
            manifest.require_report(report_bytes)
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "execution-plan Portfolio Decision withdrawal lacks exact evidence"
            ) from exc
        if (
            manifest.reason_code
            is not PortfolioDecisionWithdrawalReason.UNBOUND_STRUCTURAL_EXECUTION_PLAN
            or not isinstance(proposed, Mapping)
            or canonical_digest(
                domain="portfolio-snapshot",
                payload=dict(proposed),
            )
            != manifest.proposed_snapshot_id.removeprefix("portfolio:")
        ):
            raise TransitionError(
                "execution-plan Portfolio Decision withdrawal proposal is malformed"
            )

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "execution-plan Portfolio Decision withdrawal requires control"
                )
            science = current["scientific"]
            mission_id = science.get("active_mission")
            initiative_id = science.get("active_initiative")
            if type(mission_id) is not str or type(initiative_id) is not str:
                raise TransitionError(
                    "execution-plan Portfolio Decision withdrawal requires active work"
                )
            if any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                    "active_holdout_evaluation",
                )
            ):
                raise TransitionError(
                    "execution-plan Portfolio Decision withdrawal cannot bypass work"
                )
            next_action = current.get("next_action")
            decision = index.get("portfolio-decision", manifest.decision_id)
            decision_operation = index.get(
                "operation",
                manifest.decision_operation_id,
            )
            decision_operation_result = (
                None
                if decision_operation is None
                else decision_operation.payload.get("result")
            )
            snapshot = index.get(
                "portfolio-snapshot",
                manifest.portfolio_snapshot_id,
            )
            diagnosis = index.get(
                "study-diagnosis",
                manifest.study_diagnosis_id,
            )
            if (
                self._portfolio_decision_withdrawal(
                    index,
                    manifest.decision_id,
                )
                is not None
            ):
                raise TransitionError("Portfolio Decision is already withdrawn")
            chosen_options = (
                ()
                if decision is None
                else tuple(
                    option
                    for option in decision.payload.get("options", ())
                    if isinstance(option, Mapping)
                    and option.get("option_id")
                    == decision.payload.get("chosen_option_id")
                )
            )
            old_axes_value = (
                None if snapshot is None else snapshot.payload.get("axes")
            )
            proposed_axes_value = proposed.get("axes")
            if (
                type(old_axes_value) is not list
                or type(proposed_axes_value) is not list
                or any(not isinstance(axis, Mapping) for axis in old_axes_value)
                or any(
                    not isinstance(axis, Mapping)
                    for axis in proposed_axes_value
                )
            ):
                raise TransitionError(
                    "execution-plan withdrawal axes are malformed"
                )
            old_axes = {
                axis.get("axis_id"): dict(axis) for axis in old_axes_value
            }
            proposed_axes = {
                axis.get("axis_id"): dict(axis)
                for axis in proposed_axes_value
            }
            if (
                None in old_axes
                or None in proposed_axes
                or len(old_axes) != len(old_axes_value)
                or len(proposed_axes) != len(proposed_axes_value)
            ):
                raise TransitionError(
                    "execution-plan withdrawal axes are ambiguous"
                )
            added = set(proposed_axes) - set(old_axes)
            chosen = chosen_options[0] if len(chosen_options) == 1 else None
            target_axis = old_axes.get(manifest.target_axis_id)
            proposed_axis = proposed_axes.get(manifest.proposed_axis_id)
            execution_actions = {
                "complementary_sleeve",
                "contrast",
                "deepen",
                "recombine",
                "rotate",
                "synthesize",
            }
            scheduler_constraints = (
                None
                if decision is None
                else decision.payload.get("scheduler_constraints")
            )
            replay_constraints = self._replay_scheduler_constraints(
                index,
                mission_id=mission_id,
            )
            intended_study = index.get(
                "study-open",
                manifest.intended_study_id,
            )
            if (
                not isinstance(next_action, Mapping)
                or next_action.get("kind") != "execute_portfolio_decision"
                or next_action.get("decision_id") != manifest.decision_id
                or next_action.get("portfolio_snapshot_id")
                != manifest.portfolio_snapshot_id
                or next_action.get("target_id") != manifest.target_axis_id
                or next_action.get("target_axis_identity")
                != manifest.target_axis_identity
                or (
                    next_action.get("study_diagnosis_id")
                    != manifest.study_diagnosis_id
                    and not (
                        self.engineering_fixture
                        and next_action.get("study_diagnosis_id") is None
                    )
                )
                or current.get("revision")
                != manifest.decision_authority_revision
                or current.get("heads", {}).get("journal", {}).get("event_id")
                != manifest.decision_authority_event_id
                or decision_operation is None
                or decision_operation.status != "success"
                or decision_operation.payload.get("event_kind")
                != "portfolio_decision_recorded"
                or not isinstance(decision_operation_result, Mapping)
                or decision_operation_result.get("decision_id")
                != manifest.decision_id
                or decision_operation.authority_sequence
                != manifest.decision_authority_revision
                or decision_operation.authority_event_id
                != manifest.decision_authority_event_id
                or decision is None
                or decision.subject != f"Mission:{mission_id}"
                or decision.payload.get("portfolio_snapshot_id")
                != manifest.portfolio_snapshot_id
                or decision.payload.get("study_diagnosis_id")
                != manifest.study_diagnosis_id
                or decision.payload.get("proposed_axis") is not None
                or decision.payload.get("replay_obligation_ids", [])
                or chosen is None
                or chosen.get("action") != manifest.chosen_action
                or manifest.chosen_action not in execution_actions
                or chosen.get("target_id") != manifest.target_axis_id
                or decision.payload.get("target_axis_identity")
                != manifest.target_axis_identity
                or snapshot is None
                or snapshot.record_id != manifest.portfolio_snapshot_id
                or not isinstance(target_axis, Mapping)
                or target_axis.get("axis_identity")
                != manifest.target_axis_identity
                or diagnosis is None
                or diagnosis.subject != f"Study:{diagnosis.payload.get('study_id')}"
                or diagnosis.payload.get("mission_id") != mission_id
                or diagnosis.payload.get("portfolio_snapshot_id")
                != manifest.portfolio_snapshot_id
                or proposed.get("schema") != "portfolio_snapshot.v3"
                or proposed.get("mission_id") != mission_id
                or added != {manifest.proposed_axis_id}
                or set(old_axes) - set(proposed_axes)
                or any(
                    proposed_axes[axis_id] != axis
                    for axis_id, axis in old_axes.items()
                )
                or not isinstance(proposed_axis, Mapping)
                or proposed_axis.get("axis_identity")
                != manifest.proposed_axis_identity
                or proposed_axis.get("mechanism_family")
                in {axis.get("mechanism_family") for axis in old_axes.values()}
                or intended_study is not None
                or scheduler_constraints != replay_constraints
            ):
                raise TransitionError(
                    "execution-plan withdrawal does not bind its exact failure"
                )
            try:
                durable_manifest_bytes = self.evidence.read_verified(
                    manifest_artifact_hash
                )
                durable_report_bytes = self.evidence.read_verified(
                    manifest.report_artifact_hash
                )
                durable_proposed_bytes = self.evidence.read_verified(
                    manifest.proposed_snapshot_artifact_hash
                )
                durable_manifest = (
                    PortfolioExecutionPlanWithdrawalManifest.from_bytes(
                        durable_manifest_bytes
                    )
                )
                durable_manifest.require_report(durable_report_bytes)
            except (OSError, RuntimeError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "execution-plan Portfolio Decision evidence changed"
                ) from exc
            if (
                durable_manifest_bytes != manifest_bytes
                or durable_report_bytes != report_bytes
                or durable_proposed_bytes != proposed_bytes
                or durable_manifest != manifest
            ):
                raise RecoveryRequired(
                    "execution-plan Portfolio Decision evidence changed"
                )
            replacement_action: dict[str, Any] = {
                "kind": "portfolio_decision",
                "portfolio_snapshot_id": manifest.portfolio_snapshot_id,
                "study_diagnosis_id": manifest.study_diagnosis_id,
            }
            if replay_constraints is not None:
                replacement_action.update(replay_constraints)
            body = self._body(current)
            body["next_action"] = replacement_action
            record_id = canonical_digest(
                domain="portfolio-decision-withdrawal",
                payload={
                    "manifest": manifest.to_identity_payload(),
                    "manifest_artifact_hash": manifest_artifact_hash,
                },
            )
            record = _record(
                kind="portfolio-decision-withdrawal",
                record_id=record_id,
                subject=f"Mission:{mission_id}",
                status="withdrawn_pre_execution",
                fingerprint=decision.fingerprint,
                payload={
                    "decision_id": manifest.decision_id,
                    "manifest": manifest.to_identity_payload(),
                    "manifest_artifact_hash": manifest_artifact_hash,
                    "replacement_next_action": replacement_action,
                },
                event_stream=(
                    f"portfolio-decision-status:{manifest.decision_id}"
                ),
                event_sequence=1,
            )
            return body, [record], {
                "decision_id": manifest.decision_id,
                "withdrawal_record_id": record_id,
            }

        return self._commit(
            event_kind="portfolio_decision_withdrawn",
            operation_id=operation_id,
            subject="Portfolio:active",
            payload={
                "manifest_artifact_hash": manifest_artifact_hash,
                "manifest": manifest.to_identity_payload(),
            },
            prepare=prepare,
        )

    def withdraw_structurally_invalid_portfolio_decision(
        self,
        *,
        manifest_artifact_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Withdraw one unstarted structural Decision proved impossible as stated."""

        from axiom_rift.research.decision_withdrawal import (
            PortfolioDecisionWithdrawalReason,
            PortfolioStructuralDecisionWithdrawalManifest,
        )

        _require_digest(
            "structural Portfolio Decision withdrawal manifest",
            manifest_artifact_hash,
        )
        try:
            manifest_bytes = self.evidence.read_verified(manifest_artifact_hash)
            manifest = PortfolioStructuralDecisionWithdrawalManifest.from_bytes(
                manifest_bytes
            )
            report_bytes = self.evidence.read_verified(
                manifest.report_artifact_hash
            )
            proposed_bytes = self.evidence.read_verified(
                manifest.proposed_snapshot_artifact_hash
            )
            proposed = parse_canonical(proposed_bytes)
            manifest.require_report(report_bytes)
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "structural Portfolio Decision withdrawal lacks exact evidence"
            ) from exc
        if (
            manifest.reason_code
            is not PortfolioDecisionWithdrawalReason.NEW_MECHANISM_DUPLICATES_EXISTING_FAMILY
            or not isinstance(proposed, Mapping)
            or canonical_digest(
                domain="portfolio-snapshot",
                payload=dict(proposed),
            )
            != manifest.proposed_snapshot_id.removeprefix("portfolio:")
        ):
            raise TransitionError(
                "structural Portfolio Decision withdrawal proposal is malformed"
            )

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "structural Portfolio Decision withdrawal requires control"
                )
            science = current["scientific"]
            mission_id = science.get("active_mission")
            initiative_id = science.get("active_initiative")
            if type(mission_id) is not str or type(initiative_id) is not str:
                raise TransitionError(
                    "structural Portfolio Decision withdrawal requires active Mission work"
                )
            if any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                    "active_holdout_evaluation",
                )
            ):
                raise TransitionError(
                    "structural Portfolio Decision withdrawal cannot bypass started work"
                )
            next_action = current.get("next_action")
            decision = index.get("portfolio-decision", manifest.decision_id)
            decision_operation = index.get(
                "operation",
                manifest.decision_operation_id,
            )
            decision_operation_result = (
                None
                if decision_operation is None
                else decision_operation.payload.get("result")
            )
            snapshot = index.get(
                "portfolio-snapshot",
                manifest.portfolio_snapshot_id,
            )
            if (
                self._portfolio_decision_withdrawal(
                    index,
                    manifest.decision_id,
                )
                is not None
            ):
                raise TransitionError("Portfolio Decision is already withdrawn")
            chosen_options = (
                ()
                if decision is None
                else tuple(
                    option
                    for option in decision.payload.get("options", ())
                    if isinstance(option, Mapping)
                    and option.get("option_id")
                    == decision.payload.get("chosen_option_id")
                )
            )
            old_axes_value = (
                None if snapshot is None else snapshot.payload.get("axes")
            )
            proposed_axes_value = proposed.get("axes")
            if (
                type(old_axes_value) is not list
                or type(proposed_axes_value) is not list
                or any(not isinstance(axis, Mapping) for axis in old_axes_value)
                or any(
                    not isinstance(axis, Mapping) for axis in proposed_axes_value
                )
            ):
                raise TransitionError(
                    "structural Portfolio Decision withdrawal axes are malformed"
                )
            old_axes = {axis.get("axis_id"): dict(axis) for axis in old_axes_value}
            proposed_axes = {
                axis.get("axis_id"): dict(axis) for axis in proposed_axes_value
            }
            if (
                None in old_axes
                or None in proposed_axes
                or len(old_axes) != len(old_axes_value)
                or len(proposed_axes) != len(proposed_axes_value)
            ):
                raise TransitionError(
                    "structural Portfolio Decision withdrawal axes are ambiguous"
                )
            added = set(proposed_axes) - set(old_axes)
            chosen = chosen_options[0] if len(chosen_options) == 1 else None
            target_axis = old_axes.get(manifest.target_axis_id)
            proposed_axis = proposed_axes.get(manifest.proposed_axis_id)
            conflicting_axis = old_axes.get(manifest.conflicting_axis_id)
            scheduler_constraints = (
                None
                if decision is None
                else decision.payload.get("scheduler_constraints")
            )
            replay_constraints = self._replay_scheduler_constraints(
                index,
                mission_id=mission_id,
            )
            if (
                not isinstance(next_action, Mapping)
                or next_action.get("kind") != "record_portfolio_snapshot"
                or next_action.get("decision_id") != manifest.decision_id
                or next_action.get("action") != "new_mechanism"
                or next_action.get("portfolio_snapshot_id")
                != manifest.portfolio_snapshot_id
                or next_action.get("target_id") != manifest.target_axis_id
                or next_action.get("target_axis_identity")
                != manifest.target_axis_identity
                or current.get("revision")
                != manifest.decision_authority_revision
                or current.get("heads", {}).get("journal", {}).get("event_id")
                != manifest.decision_authority_event_id
                or decision_operation is None
                or decision_operation.status != "success"
                or decision_operation.payload.get("event_kind")
                != "portfolio_decision_recorded"
                or not isinstance(decision_operation_result, Mapping)
                or decision_operation_result.get("decision_id")
                != manifest.decision_id
                or decision_operation.authority_sequence
                != manifest.decision_authority_revision
                or decision_operation.authority_event_id
                != manifest.decision_authority_event_id
                or decision is None
                or decision.subject != f"Mission:{mission_id}"
                or decision.payload.get("portfolio_snapshot_id")
                != manifest.portfolio_snapshot_id
                or snapshot is None
                or snapshot.record_id != manifest.portfolio_snapshot_id
                or chosen is None
                or chosen.get("action") != "new_mechanism"
                or chosen.get("target_id") != manifest.target_axis_id
                or decision.payload.get("target_axis_identity")
                != manifest.target_axis_identity
                or not isinstance(target_axis, Mapping)
                or target_axis.get("axis_identity")
                != manifest.target_axis_identity
                or proposed.get("schema") != "portfolio_snapshot.v3"
                or proposed.get("mission_id") != mission_id
                or added != {manifest.proposed_axis_id}
                or set(old_axes) - set(proposed_axes)
                or any(proposed_axes[axis_id] != axis for axis_id, axis in old_axes.items())
                or not isinstance(proposed_axis, Mapping)
                or proposed_axis.get("axis_identity")
                != manifest.proposed_axis_identity
                or proposed_axis.get("mechanism_family")
                != manifest.duplicate_mechanism_family
                or not isinstance(conflicting_axis, Mapping)
                or conflicting_axis.get("axis_identity")
                != manifest.conflicting_axis_identity
                or conflicting_axis.get("mechanism_family")
                != manifest.duplicate_mechanism_family
                or proposed_axis.get("causal_question")
                != conflicting_axis.get("causal_question")
                or scheduler_constraints != replay_constraints
            ):
                raise TransitionError(
                    "structural Portfolio Decision withdrawal does not bind its exact failure"
                )
            if not self.engineering_fixture:
                from axiom_rift.operations.semantic_question_registry import (
                    SemanticQuestionRegistryError,
                    SemanticQuestionRegistryIntegrityError,
                    require_semantic_question_study_binding,
                )

                lineage = manifest.semantic_question_lineage
                try:
                    require_semantic_question_study_binding(
                        index,
                        study_id=lineage.predecessor_study_id,
                        core_id=lineage.predecessor_core_id,
                    )
                except SemanticQuestionRegistryIntegrityError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                except SemanticQuestionRegistryError as exc:
                    raise TransitionError(str(exc)) from exc
                if (
                    index.get("study-open", lineage.successor_study_id)
                    is not None
                    or any(
                        ":" not in reference
                        or index.get(*reference.split(":", 1)) is None
                        for reference in lineage.basis_record_ids
                    )
                ):
                    raise TransitionError(
                        "structural withdrawal semantic lineage is stale"
                    )
            replacement_action: dict[str, Any] = {
                "kind": "portfolio_decision",
                "portfolio_snapshot_id": manifest.portfolio_snapshot_id,
            }
            if replay_constraints is not None:
                replacement_action.update(replay_constraints)
            try:
                durable_manifest_bytes = self.evidence.read_verified(
                    manifest_artifact_hash
                )
                durable_report_bytes = self.evidence.read_verified(
                    manifest.report_artifact_hash
                )
                durable_proposed_bytes = self.evidence.read_verified(
                    manifest.proposed_snapshot_artifact_hash
                )
                durable_manifest = (
                    PortfolioStructuralDecisionWithdrawalManifest.from_bytes(
                        durable_manifest_bytes
                    )
                )
                durable_manifest.require_report(durable_report_bytes)
            except (OSError, RuntimeError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "structural Portfolio Decision withdrawal evidence changed"
                ) from exc
            if (
                durable_manifest_bytes != manifest_bytes
                or durable_report_bytes != report_bytes
                or durable_proposed_bytes != proposed_bytes
                or durable_manifest != manifest
            ):
                raise RecoveryRequired(
                    "structural Portfolio Decision withdrawal evidence changed"
                )
            body = self._body(current)
            body["next_action"] = replacement_action
            record_id = canonical_digest(
                domain="portfolio-decision-withdrawal",
                payload={
                    "manifest": manifest.to_identity_payload(),
                    "manifest_artifact_hash": manifest_artifact_hash,
                },
            )
            record = _record(
                kind="portfolio-decision-withdrawal",
                record_id=record_id,
                subject=f"Mission:{mission_id}",
                status="withdrawn_pre_execution",
                fingerprint=decision.fingerprint,
                payload={
                    "decision_id": manifest.decision_id,
                    "manifest": manifest.to_identity_payload(),
                    "manifest_artifact_hash": manifest_artifact_hash,
                    "replacement_next_action": replacement_action,
                },
                event_stream=(
                    f"portfolio-decision-status:{manifest.decision_id}"
                ),
                event_sequence=1,
            )
            return body, [record], {
                "decision_id": manifest.decision_id,
                "withdrawal_record_id": record_id,
            }

        return self._commit(
            event_kind="portfolio_decision_withdrawn",
            operation_id=operation_id,
            subject="Portfolio:active",
            payload={
                "manifest_artifact_hash": manifest_artifact_hash,
                "manifest": manifest.to_identity_payload(),
            },
            prepare=prepare,
        )

    def _require_historical_validity_override(
        self,
        index: LocalIndex,
        *,
        override: Any,
        completion_record_id: str,
        executable_id: str,
        declaration: IndexRecord,
    ) -> None:
        """Verify that an additive validity override is an exact dependency fact."""

        from axiom_rift.research.historical_adjudication import (
            HistoricalValidityOverride,
            HistoricalValidityReason,
        )
        from axiom_rift.research.source_authority import (
            AUTHORITY_TRANSITION_EVIDENCE,
            SourceAuthorityAuditManifest,
            SourceAuthorityInvalidation,
            SourceAuthorityLatch,
        )

        if not isinstance(override, HistoricalValidityOverride):
            raise TransitionError("historical validity override is unsupported")

        if (
            override.reason
            is HistoricalValidityReason.DECISION_INPUT_POINT_IN_TIME_UNPROVEN
        ):
            from axiom_rift.operations.completion_validity_projection import (
                CompletionValidityProjectionError,
                current_completion_validity_invalidation,
            )

            if override.subject_id != completion_record_id:
                raise TransitionError(
                    "historical validity override targets another completion"
                )
            try:
                head = current_completion_validity_invalidation(
                    index, completion_record_id
                )
            except CompletionValidityProjectionError as exc:
                raise TransitionError(
                    "historical completion validity head is malformed"
                ) from exc
            if (
                head is None
                or head.invalidation_record_id != override.evidence_record_id
                or head.completion_record_id != completion_record_id
                or head.executable_id != executable_id
                or head.invalidation.job_id != declaration.record_id
                or head.invalidation.study_id
                != declaration.payload.get("study_id")
            ):
                raise TransitionError(
                    "historical validity override does not bind the canonical "
                    "completion correction"
                )
            return

        if override.reason is not HistoricalValidityReason.SOURCE_AUTHORITY_INVALIDATED:
            raise TransitionError("historical validity override is unsupported")

        source_id = override.subject_id
        correction = index.get(
            "source-authority-invalidation", override.evidence_record_id
        )
        if correction is None:
            raise TransitionError(
                "historical validity override evidence is unavailable"
            )
        try:
            invalidation = SourceAuthorityInvalidation.from_identity_payload(
                correction.payload["invalidation"]
            )
            manifest = SourceAuthorityAuditManifest.from_mapping(
                correction.payload["audit_manifest"]
            )
            latch = SourceAuthorityLatch.from_mapping(correction.payload["latch"])
            expected_latch = SourceAuthorityLatch.bind(
                invalidation=invalidation,
                manifest=manifest,
            )
        except (KeyError, TypeError, ValueError) as exc:
            raise TransitionError(
                "historical validity override evidence is malformed"
            ) from exc

        correction_head = index.event_head(f"source-authority:{source_id}")
        if (
            invalidation.identity != override.evidence_record_id
            or invalidation.source_contract_id != source_id
            or correction.subject != f"Source:{source_id}"
            or correction.status != "confirmed_and_suspended"
            or correction.fingerprint
            != override.evidence_record_id.removeprefix(
                "source-authority-invalidation:"
            )
            or correction.event_stream != f"source-authority:{source_id}"
            or correction.event_sequence != 1
            or correction_head is None
            or correction_head.record_kind != correction.kind
            or correction_head.record_id != correction.record_id
            or correction_head.sequence != correction.event_sequence
            or latch != expected_latch
            or latch.source_contract_id != source_id
            or latch.invalidation_id != override.evidence_record_id
            or latch.audit_manifest_hash != invalidation.audit_artifact_hash
        ):
            raise TransitionError(
                "historical validity override does not bind the canonical correction"
            )

        try:
            durable_manifest = SourceAuthorityAuditManifest.from_bytes(
                self.evidence.read_verified(latch.audit_manifest_hash)
            )
            durable_report = self.evidence.read_verified(
                latch.report_artifact_hash
            )
            durable_manifest.require_report(durable_report)
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "historical validity override audit evidence is unavailable"
            ) from exc
        if durable_manifest != manifest:
            raise TransitionError(
                "historical validity override audit manifest has drifted"
            )

        original_state = index.get(
            "source-state", invalidation.source_state_record_id
        )
        replacement_id = correction.payload.get("replacement_state_record_id")
        replacement_state = (
            None
            if not isinstance(replacement_id, str)
            else index.get("source-state", replacement_id)
        )
        prior_active_id = correction.payload.get(
            "prior_active_source_state_record_id"
        )
        prior_active_state = (
            None
            if not isinstance(prior_active_id, str)
            else index.get("source-state", prior_active_id)
        )
        source_head = index.event_head(f"source:{source_id}")
        preserved_receipt_id = correction.payload.get("preserved_receipt_id")
        ordinary_suspended = (
            original_state is not None
            and prior_active_state is not None
            and original_state.record_id != prior_active_state.record_id
        )
        if (
            original_state is None
            or original_state.subject != f"Source:{source_id}"
            or original_state.status != "runtime_eligible"
            or original_state.fingerprint != source_id
            or original_state.event_stream != f"source:{source_id}"
            or replacement_state is None
            or replacement_state.subject != f"Source:{source_id}"
            or replacement_state.status != "suspended"
            or replacement_state.fingerprint != source_id
            or replacement_state.event_stream != f"source:{source_id}"
            or original_state.event_sequence is None
            or prior_active_state is None
            or prior_active_state.event_sequence is None
            or replacement_state.event_sequence
            != prior_active_state.event_sequence + 1
            or source_head is None
            or source_head.record_kind != "source-state"
            or source_head.record_id != replacement_state.record_id
            or source_head.sequence != replacement_state.event_sequence
            or replacement_state.payload.get("transition_evidence")
            != AUTHORITY_TRANSITION_EVIDENCE
            or replacement_state.payload.get("source_authority_latch")
            != latch.to_identity_payload()
            or correction.payload.get("eligible_source_state_record_id")
            != original_state.record_id
            or replacement_state.payload.get("eligible_source_state_record_id")
            != original_state.record_id
            or replacement_state.payload.get(
                "prior_active_source_state_record_id"
            )
            != prior_active_state.record_id
            or replacement_state.payload.get("evidence_receipt_id")
            != preserved_receipt_id
            or original_state.payload.get("evidence_receipt_id")
            != preserved_receipt_id
            or replacement_state.payload.get("receipt")
            != original_state.payload.get("receipt")
            or (
                ordinary_suspended
                and (
                    prior_active_state.status != "suspended"
                    or prior_active_state.event_sequence
                    != original_state.event_sequence + 1
                    or prior_active_state.payload.get("transition_evidence")
                    != "drift"
                    or prior_active_state.payload.get("source_authority_latch")
                    is not None
                    or any(
                        prior_active_state.payload.get(field)
                        != original_state.payload.get(field)
                        for field in (
                            "availability_identity",
                            "clock_identity",
                            "contract",
                            "contract_hash",
                            "field_identity",
                            "mapping_identity",
                            "schema_identity",
                        )
                    )
                )
            )
        ):
            raise TransitionError(
                "historical validity override source suspension is not durable"
            )

        spec = declaration.payload.get("spec")
        trial = index.get("trial", executable_id)
        executable = None if trial is None else trial.payload.get("executable")
        sources = (
            None if not isinstance(executable, dict) else executable.get("source_contracts")
        )
        if (
            not isinstance(spec, dict)
            or spec.get("evidence_subject")
            != {"kind": "Executable", "id": executable_id}
            or trial is None
            or trial.record_id != executable_id
            or trial.status != "evaluated"
            or not isinstance(executable, dict)
            or canonical_digest(domain="executable", payload=executable)
            != executable_id.removeprefix("executable:")
            or not isinstance(sources, list)
            or source_id not in sources
        ):
            raise TransitionError(
                "historical validity override is not bound to the completed trial"
            )

    def record_historical_scientific_validity_invalidations(
        self,
        *,
        invalidations: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Remove authority from exact historical completions additively.

        The completion, Study close, trial, adjudication, and negative-memory
        records remain immutable.  Each new stream head is backed by one exact
        ASCII audit finding row and receives no scientific or lifecycle credit.
        """

        from axiom_rift.operations.completion_validity_projection import (
            CompletionValidityProjectionError,
            completion_validity_invalidation_record,
            completion_validity_stream,
            validate_completion_validity_invalidation_binding,
        )
        from axiom_rift.research.historical_scientific_validity import (
            AUTHORITY_DELTA_ZERO,
            HistoricalScientificValidityInvalidation,
        )

        normalized = tuple(invalidations)
        if (
            not normalized
            or any(
                not isinstance(item, HistoricalScientificValidityInvalidation)
                for item in normalized
            )
            or len({item.completion_record_id for item in normalized})
            != len(normalized)
            or len({item.identity for item in normalized}) != len(normalized)
        ):
            raise TransitionError(
                "historical scientific validity correction requires unique "
                "typed completion invalidations"
            )
        normalized = tuple(
            sorted(normalized, key=lambda item: item.completion_record_id)
        )

        def require_audit_finding(
            invalidation: HistoricalScientificValidityInvalidation,
            document: bytes,
        ) -> None:
            try:
                lines = document.decode("ascii").splitlines()
            except UnicodeDecodeError as exc:
                raise TransitionError(
                    "historical scientific validity audit must be ASCII"
                ) from exc
            heading = f"- {invalidation.audit_finding_id}:"
            starts = [position for position, line in enumerate(lines) if line == heading]
            if len(starts) != 1:
                raise TransitionError(
                    "historical scientific validity audit finding is not unique"
                )
            start = starts[0]
            end = len(lines)
            for position in range(start + 1, len(lines)):
                if lines[position].startswith("- AX-") and lines[position].endswith(":"):
                    end = position
                    break
            finding = lines[start:end]
            required = (
                f"  reason {invalidation.reason.value}",
                (
                    f"  {invalidation.study_id} {invalidation.executable_id} "
                    f"completion {invalidation.completion_record_id}"
                ),
            )
            if any(finding.count(line) != 1 for line in required):
                raise TransitionError(
                    "historical scientific validity audit lacks the exact "
                    "completion finding slice"
                )

        audit_documents: dict[str, bytes] = {}
        for invalidation in normalized:
            try:
                document = self.evidence.read_verified(
                    invalidation.audit_artifact_hash
                )
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise TransitionError(
                    "historical scientific validity audit evidence is unavailable"
                ) from exc
            require_audit_finding(invalidation, document)
            prior_document = audit_documents.setdefault(
                invalidation.audit_artifact_hash, document
            )
            if prior_document != document:
                raise TransitionError(
                    "historical scientific validity audit evidence is inconsistent"
                )
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "historical scientific validity correction requires control"
                )
            science = current["scientific"]
            if (
                not isinstance(science.get("active_mission"), str)
                or not isinstance(science.get("active_initiative"), str)
                or current.get("next_action", {}).get("kind")
                != "portfolio_decision"
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "historical scientific validity correction requires the "
                    "active stable Portfolio boundary"
                )

            records: list[IndexRecord] = []
            inventory: list[dict[str, str]] = []
            for invalidation in normalized:
                try:
                    durable_document = self.evidence.read_verified(
                        invalidation.audit_artifact_hash
                    )
                except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                    raise RecoveryRequired(
                        "historical scientific validity audit evidence changed "
                        "before commit"
                    ) from exc
                if durable_document != audit_documents[invalidation.audit_artifact_hash]:
                    raise RecoveryRequired(
                        "historical scientific validity audit evidence changed "
                        "before commit"
                    )
                require_audit_finding(invalidation, durable_document)
                stream = completion_validity_stream(
                    invalidation.completion_record_id
                )
                if index.event_head(stream) is not None:
                    raise TransitionError(
                        "historical scientific validity completion already has a head"
                    )
                try:
                    validate_completion_validity_invalidation_binding(
                        index, invalidation
                    )
                    record = completion_validity_invalidation_record(
                        invalidation,
                        sequence=1,
                    )
                except (CompletionValidityProjectionError, TypeError, ValueError) as exc:
                    raise TransitionError(
                        "historical scientific validity binding is invalid"
                    ) from exc
                records.append(record)
                inventory.append(
                    {
                        "completion_record_id": invalidation.completion_record_id,
                        "invalidation_record_id": invalidation.identity,
                    }
                )
            return self._body(current), records, {
                "authority_delta": dict(AUTHORITY_DELTA_ZERO),
                "invalidations": inventory,
            }

        return self._commit(
            event_kind="historical_scientific_validity_invalidations_recorded",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "invalidations": [
                    item.to_identity_payload() for item in normalized
                ],
            },
            prepare=prepare,
        )

    def record_historical_cost_semantics_latch(
        self,
        *,
        manifest_artifact_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Activate the one frozen completed-period spread-cost qualification.

        The canonical manifest and its exact ASCII report are content-addressed
        evidence.  The Writer independently rederives the complete bounded
        inventory from the authenticated index before recording a zero-credit,
        sequence-one latch without changing control or scientific state.
        """

        from axiom_rift.operations.historical_cost_semantics_projection import (
            LATCH_EVENT_KIND,
            LATCH_RECORD_KIND,
            LATCH_STREAM,
            HistoricalCostSemanticsProjectionError,
            build_historical_spread_semantics_audit_manifest,
            historical_cost_semantics_activation_records,
            validate_historical_cost_semantics_latch_binding,
        )
        from axiom_rift.research.historical_cost_semantics import (
            AUTHORITY_DELTA_ZERO,
            HistoricalCostSemanticsError,
            HistoricalCostSemanticsLatch,
            HistoricalSpreadSemanticsAuditManifest,
        )

        _require_digest(
            "historical spread semantics audit manifest",
            manifest_artifact_hash,
        )
        try:
            manifest_bytes = self.evidence.read_verified(manifest_artifact_hash)
            manifest = HistoricalSpreadSemanticsAuditManifest.from_bytes(
                manifest_bytes
            )
            if manifest.artifact_hash != manifest_artifact_hash:
                raise HistoricalCostSemanticsError(
                    "canonical manifest hash differs from its evidence identity"
                )
            report_bytes = self.evidence.read_verified(
                manifest.audit_artifact_hash
            )
            manifest.require_report(report_bytes)
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "historical cost semantics latch lacks its exact canonical evidence"
            ) from exc

        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "historical cost semantics latch requires control"
                )
            science = current["scientific"]
            mission_id = science.get("active_mission")
            initiative_id = science.get("active_initiative")
            next_action = current.get("next_action")
            snapshot_id = (
                next_action.get("portfolio_snapshot_id")
                if isinstance(next_action, Mapping)
                else None
            )
            snapshot = (
                index.get("portfolio-snapshot", snapshot_id)
                if type(snapshot_id) is str
                else None
            )
            if (
                type(mission_id) is not str
                or type(initiative_id) is not str
                or not isinstance(next_action, Mapping)
                or next_action.get("kind") != "portfolio_decision"
                or type(snapshot_id) is not str
                or snapshot is None
                or snapshot.subject != f"Mission:{mission_id}"
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "historical cost semantics latch requires the active stable "
                    "Portfolio boundary"
                )
            if index.event_head(LATCH_STREAM) is not None or index.count_by_kind(
                LATCH_RECORD_KIND
            ):
                raise TransitionError(
                    "historical cost semantics latch already has a frozen head"
                )

            try:
                durable_manifest_bytes = self.evidence.read_verified(
                    manifest_artifact_hash
                )
                durable_report_bytes = self.evidence.read_verified(
                    manifest.audit_artifact_hash
                )
                durable_manifest = HistoricalSpreadSemanticsAuditManifest.from_bytes(
                    durable_manifest_bytes
                )
                durable_manifest.require_report(durable_report_bytes)
            except (OSError, RuntimeError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "historical cost semantics evidence changed before commit"
                ) from exc
            if (
                durable_manifest_bytes != manifest_bytes
                or durable_report_bytes != report_bytes
                or durable_manifest != manifest
            ):
                raise RecoveryRequired(
                    "historical cost semantics evidence changed before commit"
                )

            try:
                expected_manifest = (
                    build_historical_spread_semantics_audit_manifest(
                        index,
                        audit_artifact_hash=manifest.audit_artifact_hash,
                    )
                )
                if (
                    expected_manifest != manifest
                    or canonical_bytes(expected_manifest.to_payload())
                    != manifest_bytes
                ):
                    raise HistoricalCostSemanticsProjectionError(
                        "current inventory differs from the canonical audit manifest"
                )
                latch = HistoricalCostSemanticsLatch.from_audit_manifest(manifest)
                audit_slice = validate_historical_cost_semantics_latch_binding(
                    index,
                    latch,
                    manifest,
                )
                records = historical_cost_semantics_activation_records(
                    latch,
                    audit_slice,
                )
            except (
                HistoricalCostSemanticsError,
                HistoricalCostSemanticsProjectionError,
                TypeError,
                ValueError,
            ) as exc:
                raise TransitionError(
                    "historical cost semantics manifest cannot be rederived exactly"
                ) from exc

            return self._body(current), list(records), {
                "audit_manifest_hash": manifest.artifact_hash,
                "authority_delta": dict(AUTHORITY_DELTA_ZERO),
                "latch_record_id": latch.identity,
            }

        return self._commit(
            event_kind=LATCH_EVENT_KIND,
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "audit_manifest_hash": manifest.artifact_hash,
                "audit_manifest_identity": manifest.identity,
                "audit_report_hash": manifest.audit_artifact_hash,
            },
            prepare=prepare,
        )

    def _writer_derived_historical_validity_overrides(
        self,
        index: LocalIndex,
        *,
        completion_record_id: str,
        executable_id: str,
        declaration: IndexRecord,
        prior: IndexRecord | None,
    ) -> tuple[Any, ...]:
        """Derive the monotone validity facts for one legacy completion.

        A request may describe these facts, but it cannot create, omit, or
        withdraw them.  Durable source-authority and completion-validity heads,
        plus any prior additive overlay, are the only inputs to this projection.
        """

        from axiom_rift.research.historical_adjudication import (
            HistoricalValidityOverride,
            HistoricalValidityReason,
        )

        trial = index.get("trial", executable_id)
        executable = None if trial is None else trial.payload.get("executable")
        sources = (
            None
            if not isinstance(executable, dict)
            else executable.get("source_contracts")
        )
        if (
            trial is None
            or trial.record_id != executable_id
            or trial.status != "evaluated"
            or not isinstance(executable, dict)
            or canonical_digest(domain="executable", payload=executable)
            != executable_id.removeprefix("executable:")
            or not isinstance(sources, list)
            or any(type(source_id) is not str for source_id in sources)
            or len(sources) != len(set(sources))
        ):
            raise TransitionError(
                "historical validity projection lacks the exact completed trial"
            )

        overrides_by_subject: dict[str, Any] = {}
        if prior is not None:
            raw_prior = prior.payload.get("validity_overrides")
            if not isinstance(raw_prior, list):
                raise RecoveryRequired(
                    "prior historical validity projection is malformed"
                )
            try:
                prior_overrides = tuple(
                    HistoricalValidityOverride(
                        reason=HistoricalValidityReason(item["reason"]),
                        subject_id=item["subject_id"],
                        evidence_record_id=item["evidence_record_id"],
                    )
                    for item in raw_prior
                    if isinstance(item, dict)
                    and set(item)
                    == {"evidence_record_id", "reason", "subject_id"}
                )
            except (KeyError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "prior historical validity projection is malformed"
                ) from exc
            if len(prior_overrides) != len(raw_prior):
                raise RecoveryRequired(
                    "prior historical validity projection is malformed"
                )
            for override in prior_overrides:
                self._require_historical_validity_override(
                    index,
                    override=override,
                    completion_record_id=completion_record_id,
                    executable_id=executable_id,
                    declaration=declaration,
                )
                previous = overrides_by_subject.setdefault(
                    override.subject_id, override
                )
                if previous != override:
                    raise RecoveryRequired(
                        "prior historical validity projection conflicts"
                    )

        for source_id in sorted(sources):
            correction_head = index.event_head(f"source-authority:{source_id}")
            if correction_head is None:
                continue
            if correction_head.record_kind != "source-authority-invalidation":
                raise RecoveryRequired(
                    "source authority correction head is malformed"
                )
            try:
                override = HistoricalValidityOverride(
                    reason=(
                        HistoricalValidityReason.SOURCE_AUTHORITY_INVALIDATED
                    ),
                    subject_id=source_id,
                    evidence_record_id=correction_head.record_id,
                )
            except (TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "source authority correction identity is malformed"
                ) from exc
            self._require_historical_validity_override(
                index,
                override=override,
                completion_record_id=completion_record_id,
                executable_id=executable_id,
                declaration=declaration,
            )
            previous = overrides_by_subject.setdefault(source_id, override)
            if previous != override:
                raise RecoveryRequired(
                    "historical validity correction cannot be replaced"
                )

        from axiom_rift.operations.completion_validity_projection import (
            CompletionValidityProjectionError,
            current_completion_validity_invalidation,
        )

        try:
            completion_head = current_completion_validity_invalidation(
                index, completion_record_id
            )
        except CompletionValidityProjectionError as exc:
            raise RecoveryRequired(
                "completion validity correction head is malformed"
            ) from exc
        if completion_head is not None:
            try:
                override = HistoricalValidityOverride(
                    reason=(
                        HistoricalValidityReason.DECISION_INPUT_POINT_IN_TIME_UNPROVEN
                    ),
                    subject_id=completion_record_id,
                    evidence_record_id=completion_head.invalidation_record_id,
                )
            except (TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "completion validity correction identity is malformed"
                ) from exc
            self._require_historical_validity_override(
                index,
                override=override,
                completion_record_id=completion_record_id,
                executable_id=executable_id,
                declaration=declaration,
            )
            previous = overrides_by_subject.setdefault(
                completion_record_id, override
            )
            if previous != override:
                raise RecoveryRequired(
                    "historical completion validity correction cannot be replaced"
                )

        return tuple(
            sorted(
                overrides_by_subject.values(),
                key=lambda item: (
                    item.reason.value,
                    item.subject_id,
                    item.evidence_record_id,
                ),
            )
        )

    def plan_historical_replay_correction(
        self,
        *,
        adjudication_record_ids: Sequence[str],
        replay_study_id: str,
    ) -> dict[str, Any]:
        """Build a read-only explicit complete-history correction audit plan."""

        normalized_ids = tuple(sorted(adjudication_record_ids))
        if (
            not normalized_ids
            or len(normalized_ids) != len(set(normalized_ids))
            or any(type(item) is not str for item in normalized_ids)
        ):
            raise TransitionError("replay correction adjudication ids are invalid")
        validate_study_id(replay_study_id)
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                current = self._require_stable_locked(index)
                assert current is not None
                mission_id = current["scientific"].get("active_mission")
                if not isinstance(mission_id, str):
                    raise TransitionError(
                        "replay correction plan requires an active Mission"
                    )
                from axiom_rift.operations.replay_projection import (
                    ReplayProjectionError,
                    ReplayTransitionError,
                    build_explicit_historical_replay_correction_audit_plan,
                )

                try:
                    return build_explicit_historical_replay_correction_audit_plan(
                        index,
                        mission_id=mission_id,
                        adjudication_record_ids=normalized_ids,
                        replay_study_id=replay_study_id,
                    )
                except ReplayProjectionError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                except ReplayTransitionError as exc:
                    raise TransitionError(str(exc)) from exc

    def record_historical_replay_correction(
        self,
        *,
        adjudication_record_ids: Sequence[str],
        satisfactions: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Backfill replay streams and bind already-completed audit-only replay."""

        from axiom_rift.research.replay_obligation import ReplaySatisfaction
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_correction,
        )

        normalized_ids = tuple(sorted(adjudication_record_ids))
        normalized_satisfactions = tuple(
            sorted(satisfactions, key=lambda item: getattr(item, "obligation_id", ""))
        )
        if (
            not normalized_ids
            or len(normalized_ids) != len(set(normalized_ids))
            or any(type(item) is not str for item in normalized_ids)
            or not normalized_satisfactions
            or any(
                not isinstance(item, ReplaySatisfaction)
                for item in normalized_satisfactions
            )
            or len(
                {item.obligation_id for item in normalized_satisfactions}
            )
            != len(normalized_satisfactions)
        ):
            raise TransitionError("historical replay correction request is invalid")
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("historical replay correction requires control")
            science = current["scientific"]
            mission_id = science.get("active_mission")
            if not isinstance(mission_id, str) or any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "historical replay correction requires a stable Mission boundary"
                )
            try:
                records, constraints, result = prepare_correction(
                    index,
                    mission_id=mission_id,
                    adjudication_record_ids=normalized_ids,
                    satisfactions=normalized_satisfactions,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                body["next_action"], constraints
            )
            return body, records, result

        return self._commit(
            event_kind="historical_replay_correction_recorded",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "adjudication_record_ids": list(normalized_ids),
                "satisfactions": [
                    item.to_identity_payload()
                    for item in normalized_satisfactions
                ],
            },
            prepare=prepare,
        )

    def plan_historical_replay_satisfaction_invalidation(
        self,
        *,
        obligation_id: str,
    ) -> dict[str, Any]:
        """Derive a read-only audit artifact for one invalid satisfied head."""

        if (
            type(obligation_id) is not str
            or not obligation_id.startswith("historical-replay-obligation:")
        ):
            raise TransitionError(
                "replay satisfaction invalidation obligation is malformed"
            )
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            build_satisfaction_invalidation_plan,
        )

        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                current = self._require_stable_locked(index)
                assert current is not None
                mission_id = current["scientific"].get("active_mission")
                if not isinstance(mission_id, str):
                    raise TransitionError(
                        "replay satisfaction invalidation requires an active Mission"
                    )
                try:
                    return build_satisfaction_invalidation_plan(
                        index,
                        mission_id=mission_id,
                        obligation_id=obligation_id,
                    )
                except ReplayProjectionError as exc:
                    raise RecoveryRequired(str(exc)) from exc
                except ReplayTransitionError as exc:
                    raise TransitionError(str(exc)) from exc

    def invalidate_historical_replay_satisfaction(
        self,
        *,
        obligation_id: str,
        audit_manifest_hash: str,
        operation_id: str,
        historical_family_authority: HistoricalFamilyAuthority | None = None,
    ) -> TransitionResult:
        """Revoke one reproducibly invalid satisfaction and requeue it."""

        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_satisfaction_invalidation,
            scheduler_constraints,
        )
        from axiom_rift.research.replay_satisfaction_invalidation import (
            replay_satisfaction_invalidation_manifest_from_bytes,
        )
        from axiom_rift.operations.historical_family_authority_admission import (
            HistoricalFamilyAuthorityAdmissionError,
            prepare_historical_family_authority_record,
        )

        if (
            type(obligation_id) is not str
            or not obligation_id.startswith("historical-replay-obligation:")
        ):
            raise TransitionError(
                "replay satisfaction invalidation obligation is malformed"
            )
        _require_digest(
            "replay satisfaction invalidation audit manifest",
            audit_manifest_hash,
        )
        try:
            manifest_bytes = self.evidence.read_verified(audit_manifest_hash)
            manifest = replay_satisfaction_invalidation_manifest_from_bytes(
                manifest_bytes
            )
        except (OSError, RuntimeError, TypeError, ValueError) as exc:
            raise TransitionError(
                "replay satisfaction invalidation lacks its exact canonical manifest"
            ) from exc
        if manifest.obligation_id != obligation_id:
            raise TransitionError(
                "replay satisfaction invalidation artifact targets another obligation"
            )
        family_authority = historical_family_authority
        if family_authority is not None and not isinstance(
            family_authority,
            HistoricalFamilyAuthority,
        ):
            raise TransitionError(
                "historical family correction authority is not typed"
            )

        def require_family_authority(
            index: LocalIndex,
        ) -> IndexRecord | None:
            if family_authority is None:
                return None
            if family_authority.replay_obligation_id != obligation_id:
                raise TransitionError(
                    "historical family authority targets another obligation"
                )
            try:
                return prepare_historical_family_authority_record(
                    repository_root=self.root,
                    index=index,
                    authority=family_authority,
                )
            except HistoricalFamilyAuthorityAdmissionError as exc:
                raise TransitionError(str(exc)) from exc
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "replay satisfaction invalidation requires control"
                )
            science = current["scientific"]
            mission_id = science.get("active_mission")
            next_action = current.get("next_action")
            if (
                not isinstance(mission_id, str)
                or not isinstance(next_action, dict)
                or next_action.get("kind")
                not in {
                    "choose_next_initiative_or_terminal",
                    "portfolio_decision",
                }
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "replay satisfaction invalidation requires a stable scheduler boundary"
                )
            current_constraints = scheduler_constraints(
                index,
                mission_id=mission_id,
            )
            projected_constraints = {
                name: next_action.get(name)
                for name in (
                    "pending_replay_obligation_ids",
                    "required_replay_priority",
                )
                if next_action.get(name) is not None
            }
            if projected_constraints != (current_constraints or {}):
                raise TransitionError(
                    "replay satisfaction invalidation scheduler authority is stale"
                )
            try:
                durable_bytes = self.evidence.read_verified(audit_manifest_hash)
                durable_manifest = (
                    replay_satisfaction_invalidation_manifest_from_bytes(
                        durable_bytes
                    )
                )
            except (OSError, RuntimeError, TypeError, ValueError) as exc:
                raise RecoveryRequired(
                    "replay satisfaction invalidation evidence changed before commit"
                ) from exc
            if durable_bytes != manifest_bytes or durable_manifest != manifest:
                raise RecoveryRequired(
                    "replay satisfaction invalidation manifest changed before commit"
                )
            try:
                records, constraints, result = prepare_satisfaction_invalidation(
                    index,
                    mission_id=mission_id,
                    obligation_id=obligation_id,
                    manifest=durable_manifest,
                    audit_manifest_hash=audit_manifest_hash,
                )
                family_record = require_family_authority(index)
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                next_action,
                constraints,
            )
            if family_record is not None:
                records.append(family_record)
                result = {
                    **result,
                    "historical_family_authority_id": family_record.record_id,
                }
            return body, records, result

        event_payload = {
            "audit_manifest_hash": audit_manifest_hash,
            "obligation_id": obligation_id,
            "satisfaction_record_id": manifest.satisfaction_record_id,
        }
        if family_authority is not None:
            event_payload["historical_family_authority"] = (
                family_authority.to_identity_payload()
            )
        return self._commit(
            event_kind="historical_replay_satisfaction_invalidated",
            operation_id=operation_id,
            subject="Mission:active",
            payload=event_payload,
            prepare=prepare,
        )

    @staticmethod
    def _require_replay_scheduler_boundary(
        current: Mapping[str, Any] | None,
        index: LocalIndex,
        *,
        operation_name: str,
    ) -> tuple[str, Mapping[str, Any]]:
        """Authenticate one idle Mission scheduler boundary without mutation."""

        from axiom_rift.operations.replay_projection import scheduler_constraints

        if current is None:
            raise TransitionError(f"{operation_name} requires control")
        science = current["scientific"]
        mission_id = science.get("active_mission")
        next_action = current.get("next_action")
        if (
            not isinstance(mission_id, str)
            or not isinstance(next_action, Mapping)
            or next_action.get("kind")
            not in {
                "choose_next_initiative_or_terminal",
                "portfolio_decision",
            }
            or any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            )
        ):
            raise TransitionError(
                f"{operation_name} requires a stable scheduler boundary"
            )
        current_constraints = scheduler_constraints(
            index,
            mission_id=mission_id,
        )
        projected_constraints = {
            name: next_action.get(name)
            for name in (
                "pending_replay_obligation_ids",
                "required_replay_priority",
            )
            if next_action.get(name) is not None
        }
        if projected_constraints != (current_constraints or {}):
            raise TransitionError(
                f"{operation_name} scheduler authority is stale"
            )
        return mission_id, next_action

    def register_historical_replay_family_authorities(
        self,
        *,
        historical_family_authorities: Sequence[HistoricalFamilyAuthority],
        operation_id: str,
    ) -> TransitionResult:
        """Register exact pending-member family authority without research credit."""

        from axiom_rift.operations.historical_family_authority_admission import (
            HistoricalFamilyAuthorityAdmissionError,
            prepare_historical_family_authority_record,
        )
        from axiom_rift.operations.replay_projection import obligation_heads

        normalized = tuple(
            sorted(
                historical_family_authorities,
                key=lambda item: getattr(item, "replay_obligation_id", ""),
            )
        )
        obligation_ids = tuple(
            item.replay_obligation_id
            for item in normalized
            if isinstance(item, HistoricalFamilyAuthority)
        )
        if (
            not normalized
            or len(obligation_ids) != len(normalized)
            or len(set(obligation_ids)) != len(obligation_ids)
        ):
            raise TransitionError(
                "historical family authority registration request is invalid"
            )
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            mission_id, _next_action = self._require_replay_scheduler_boundary(
                current,
                index,
                operation_name="historical family authority registration",
            )
            heads = {
                obligation.identity: head
                for obligation, head in obligation_heads(
                    index,
                    mission_id=mission_id,
                )
            }
            if any(
                heads.get(obligation_id) is None
                or heads[obligation_id].status != "pending"
                for obligation_id in obligation_ids
            ):
                raise TransitionError(
                    "historical family authority target is not exactly pending"
                )
            try:
                records = [
                    prepare_historical_family_authority_record(
                        repository_root=self.root,
                        index=index,
                        authority=authority,
                    )
                    for authority in normalized
                ]
            except HistoricalFamilyAuthorityAdmissionError as exc:
                raise TransitionError(str(exc)) from exc
            return self._body(current), records, {
                "candidate_delta": 0,
                "historical_family_authority_ids": [
                    record.record_id for record in records
                ],
                "holdout_reveal_delta": 0,
                "replay_obligation_ids": list(obligation_ids),
                "scientific_claim_delta": 0,
                "scientific_trial_delta": 0,
            }

        return self._commit(
            event_kind="historical_replay_family_authorities_registered",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "historical_family_authorities": [
                    item.to_identity_payload() for item in normalized
                ]
            },
            prepare=prepare,
        )

    def resolve_historical_replay_obligations(
        self,
        *,
        satisfactions: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Resolve exact in-progress replay after its mandatory Study diagnosis."""

        from axiom_rift.research.replay_obligation import ReplaySatisfaction
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_resolution,
        )

        normalized = tuple(
            sorted(satisfactions, key=lambda item: getattr(item, "obligation_id", ""))
        )
        if (
            not normalized
            or any(not isinstance(item, ReplaySatisfaction) for item in normalized)
            or len({item.obligation_id for item in normalized}) != len(normalized)
        ):
            raise TransitionError("replay resolution request is invalid")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("replay resolution requires control")
            mission_id = current["scientific"].get("active_mission")
            next_action = current.get("next_action")
            if not isinstance(mission_id, str) or not isinstance(next_action, dict):
                raise TransitionError("replay resolution requires an active Mission")
            try:
                records, constraints, result = prepare_resolution(
                    index,
                    mission_id=mission_id,
                    next_action=next_action,
                    satisfactions=normalized,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                next_action["resume_next_action"], constraints
            )
            return body, records, result

        return self._commit(
            event_kind="historical_replay_obligations_resolved",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "satisfactions": [item.to_identity_payload() for item in normalized]
            },
            prepare=prepare,
        )

    def recertify_historical_replay_sibling_evidence(
        self,
        *,
        source_satisfaction_ids: Sequence[str],
        historical_family_authorities: Sequence[HistoricalFamilyAuthority],
        operation_id: str,
    ) -> TransitionResult:
        """Credit omitted exact siblings without new trials or caller verdicts."""

        from axiom_rift.operations.historical_family_authority_admission import (
            HistoricalFamilyAuthorityAdmissionError,
            prepare_historical_family_authority_record,
            require_sibling_recertification_family_core,
        )
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_sibling_evidence_recertification,
        )

        normalized_sources = tuple(sorted(set(source_satisfaction_ids)))
        normalized_authorities = tuple(
            sorted(
                historical_family_authorities,
                key=lambda item: getattr(item, "replay_obligation_id", ""),
            )
        )
        obligation_ids = tuple(
            item.replay_obligation_id
            for item in normalized_authorities
            if isinstance(item, HistoricalFamilyAuthority)
        )
        if (
            not normalized_sources
            or len(normalized_sources) != len(source_satisfaction_ids)
            or not normalized_authorities
            or len(obligation_ids) != len(normalized_authorities)
            or len(set(obligation_ids)) != len(obligation_ids)
        ):
            raise TransitionError(
                "historical sibling recertification request is invalid"
            )
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            mission_id, next_action = self._require_replay_scheduler_boundary(
                current,
                index,
                operation_name="historical sibling recertification",
            )
            try:
                (
                    _derived_satisfactions,
                    satisfaction_records,
                    constraints,
                    result,
                ) = prepare_sibling_evidence_recertification(
                    index,
                    mission_id=mission_id,
                    source_satisfaction_ids=normalized_sources,
                    obligation_ids=obligation_ids,
                )
                family_records = [
                    prepare_historical_family_authority_record(
                        repository_root=self.root,
                        index=index,
                        authority=authority,
                    )
                    for authority in normalized_authorities
                ]
                authority_by_obligation = {
                    authority.replay_obligation_id: authority
                    for authority in normalized_authorities
                }
                for satisfaction in _derived_satisfactions:
                    target_authority = authority_by_obligation.get(
                        satisfaction.obligation_id
                    )
                    if target_authority is None:
                        raise HistoricalFamilyAuthorityAdmissionError(
                            "sibling recertification target authority is absent"
                        )
                    require_sibling_recertification_family_core(
                        index,
                        target_authority=target_authority,
                        source_replay_study_id=satisfaction.replay_study_id,
                    )
            except HistoricalFamilyAuthorityAdmissionError as exc:
                raise TransitionError(str(exc)) from exc
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                next_action,
                constraints,
            )
            return body, [*family_records, *satisfaction_records], {
                **result,
                "historical_family_authority_ids": [
                    record.record_id for record in family_records
                ],
            }

        return self._commit(
            event_kind="historical_replay_sibling_evidence_recertified",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "historical_family_authorities": [
                    item.to_identity_payload()
                    for item in normalized_authorities
                ],
                "source_satisfaction_ids": list(normalized_sources),
            },
            prepare=prepare,
        )

    def defer_historical_replay_obligations(
        self,
        *,
        deferrals: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Defer replay only against durable basis and one exact resume condition."""

        from axiom_rift.research.replay_obligation import ReplayDeferral
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_deferral,
        )

        normalized = tuple(
            sorted(deferrals, key=lambda item: getattr(item, "obligation_id", ""))
        )
        if (
            not normalized
            or any(not isinstance(item, ReplayDeferral) for item in normalized)
            or len({item.obligation_id for item in normalized}) != len(normalized)
        ):
            raise TransitionError("replay deferral request is invalid")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("replay deferral requires control")
            mission_id = current["scientific"].get("active_mission")
            if not isinstance(mission_id, str):
                raise TransitionError("replay deferral requires an active Mission")
            try:
                records, constraints, result = prepare_deferral(
                    index,
                    mission_id=mission_id,
                    deferrals=normalized,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            deferred_ids = {item.obligation_id for item in normalized}
            action = current["next_action"]
            if (
                action.get("kind") == "resolve_historical_replay_obligations"
                and set(action.get("replay_obligation_ids", ())) == deferred_ids
                and isinstance(action.get("resume_next_action"), dict)
            ):
                action = action["resume_next_action"]
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                action, constraints
            )
            return body, records, result

        return self._commit(
            event_kind="historical_replay_obligations_deferred",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "deferrals": [item.to_identity_payload() for item in normalized]
            },
            prepare=prepare,
        )

    def return_historical_replay_obligations_for_scientific_change(
        self,
        *,
        obligation_ids: Sequence[str],
        operation_id: str,
    ) -> TransitionResult:
        """Restore an exact stopped family after a typed Study-level change."""

        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_scientific_change_return,
        )

        normalized = tuple(sorted(set(obligation_ids)))
        if (
            not normalized
            or len(normalized) != len(obligation_ids)
            or any(type(item) is not str for item in normalized)
        ):
            raise TransitionError(
                "scientific-change replay return request is invalid"
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError(
                    "scientific-change replay return requires control"
                )
            mission_id = current["scientific"].get("active_mission")
            next_action = current.get("next_action")
            if not isinstance(mission_id, str) or not isinstance(
                next_action, dict
            ):
                raise TransitionError(
                    "scientific-change replay return requires an active Mission"
                )
            try:
                records, constraints, result = prepare_scientific_change_return(
                    index,
                    mission_id=mission_id,
                    next_action=next_action,
                    obligation_ids=normalized,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            resume_next_action = next_action.get("resume_next_action")
            if not isinstance(resume_next_action, dict):
                raise RecoveryRequired(
                    "scientific-change replay return lost its resume action"
                )
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                resume_next_action,
                constraints,
            )
            return body, records, result

        return self._commit(
            event_kind=(
                "historical_replay_obligations_returned_for_scientific_change"
            ),
            operation_id=operation_id,
            subject="Mission:active",
            payload={"replay_obligation_ids": list(normalized)},
            prepare=prepare,
        )

    def dispose_historical_replay_obligations(
        self,
        *,
        satisfactions: Sequence[Any],
        deferrals: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Atomically satisfy completed members and defer unresolved peers."""

        from axiom_rift.research.replay_obligation import (
            ReplayDeferral,
            ReplaySatisfaction,
        )
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_disposition,
        )

        normalized_satisfactions = tuple(
            sorted(
                satisfactions,
                key=lambda item: getattr(item, "obligation_id", ""),
            )
        )
        normalized_deferrals = tuple(
            sorted(
                deferrals,
                key=lambda item: getattr(item, "obligation_id", ""),
            )
        )
        satisfaction_ids = {
            item.obligation_id
            for item in normalized_satisfactions
            if isinstance(item, ReplaySatisfaction)
        }
        deferral_ids = {
            item.obligation_id
            for item in normalized_deferrals
            if isinstance(item, ReplayDeferral)
        }
        if (
            not normalized_satisfactions
            or not normalized_deferrals
            or len(satisfaction_ids) != len(normalized_satisfactions)
            or len(deferral_ids) != len(normalized_deferrals)
            or satisfaction_ids.intersection(deferral_ids)
        ):
            raise TransitionError("mixed replay disposition request is invalid")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("mixed replay disposition requires control")
            mission_id = current["scientific"].get("active_mission")
            next_action = current.get("next_action")
            if not isinstance(mission_id, str) or not isinstance(
                next_action,
                dict,
            ):
                raise TransitionError(
                    "mixed replay disposition requires an active Mission"
                )
            try:
                records, constraints, result = prepare_disposition(
                    index,
                    mission_id=mission_id,
                    next_action=next_action,
                    satisfactions=normalized_satisfactions,
                    deferrals=normalized_deferrals,
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                next_action["resume_next_action"],
                constraints,
            )
            return body, records, result

        return self._commit(
            event_kind="historical_replay_obligations_disposed",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "deferrals": [
                    item.to_identity_payload()
                    for item in normalized_deferrals
                ],
                "satisfactions": [
                    item.to_identity_payload()
                    for item in normalized_satisfactions
                ],
            },
            prepare=prepare,
        )

    def resume_historical_replay_obligations(
        self,
        *,
        resumes: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Requeue exact deferred replay after one stored finite trigger."""

        from axiom_rift.research.replay_obligation import (
            ReplayRepairBasisKind,
            ReplayRepairProvenance,
            ReplayResumeEvidence,
        )
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            prepare_resume,
            scheduler_constraints,
        )

        normalized = tuple(
            sorted(resumes, key=lambda item: getattr(item, "obligation_id", ""))
        )
        if (
            not normalized
            or any(not isinstance(item, ReplayResumeEvidence) for item in normalized)
            or len({item.obligation_id for item in normalized}) != len(normalized)
        ):
            raise TransitionError("replay resume request is invalid")
        self._require_study_close_delivery_guard()

        def repair_provenance(
            index: LocalIndex,
            previous_completion: IndexRecord,
            previous_declaration: IndexRecord,
            declaration: IndexRecord,
            diagnosis: IndexRecord,
        ) -> ReplayRepairProvenance:
            previous_spec = previous_declaration.payload.get("spec")
            spec = declaration.payload.get("spec")
            failure = previous_completion.payload.get("failure")
            if not isinstance(previous_spec, Mapping) or not isinstance(spec, Mapping):
                raise TransitionError(
                    "replay repair Job provenance is malformed"
                )
            previous_manifest = self._require_job_implementation_evidence(
                previous_spec,
                _index=index,
            )
            repaired_manifest = self._require_job_implementation_evidence(
                spec,
                _index=index,
            )
            changed_proof = spec.get("changed_cause_proof_hash")
            if not isinstance(changed_proof, str):
                raise TransitionError(
                    "replay repair changed-cause provenance is absent"
                )
            _require_digest("replay changed-cause proof", changed_proof)
            try:
                changed_manifest = parse_canonical(
                    self.evidence.read_verified(changed_proof)
                )
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise TransitionError(
                    "replay repair changed-cause proof is unavailable"
                ) from exc
            previous_identity = previous_spec.get("implementation_identity")
            repaired_identity = spec.get("implementation_identity")
            new_evidence = (
                None
                if not isinstance(changed_manifest, Mapping)
                else changed_manifest.get("new_evidence_hashes")
            )
            common_invalid = (
                not isinstance(changed_manifest, Mapping)
                or changed_manifest.get("changed_dimension") != "implementation"
                or changed_manifest.get("previous_implementation_identity")
                != previous_identity
                or changed_manifest.get("new_implementation_identity")
                != repaired_identity
                or previous_identity == repaired_identity
                or type(changed_manifest.get("explanation")) is not str
                or not changed_manifest["explanation"]
                or not changed_manifest["explanation"].isascii()
                or not isinstance(new_evidence, list)
                or not new_evidence
                or any(type(item) is not str for item in new_evidence)
                or len(new_evidence) != len(set(new_evidence))
                or repaired_identity not in new_evidence
                or previous_spec.get("changed_cause_proof_hash") == changed_proof
            )
            basis_kind: ReplayRepairBasisKind
            failure_signature: str | None
            invalid_criterion_ids: tuple[str, ...]
            prior_reproduction: set[str]
            if previous_completion.status == "failed":
                reproduction = (
                    None
                    if not isinstance(failure, Mapping)
                    else failure.get("minimum_reproduction_evidence")
                )
                failure_signature = (
                    None
                    if not isinstance(failure, Mapping)
                    else failure.get("failure_signature")
                )
                legacy_changed_cause_fields = {
                    "changed_dimension",
                    "explanation",
                    "new_evidence_hashes",
                    "new_implementation_identity",
                    "prior_failure_signature",
                    "previous_implementation_identity",
                    "schema",
                }
                validated_changed_cause_fields = {
                    *legacy_changed_cause_fields,
                    "result_artifact_hashes",
                    "validation_plan_hash",
                    "validator_id",
                }
                changed_cause_fields = (
                    frozenset(changed_manifest)
                    if isinstance(changed_manifest, Mapping)
                    else frozenset()
                )
                production_retry_family = declaration.payload.get(
                    "retry_family_fingerprint"
                )
                retry_basis_record_ids = declaration.payload.get(
                    "retry_basis_record_ids"
                )
                if (
                    common_invalid
                    or changed_cause_fields
                    not in {
                        frozenset(legacy_changed_cause_fields),
                        frozenset(validated_changed_cause_fields),
                    }
                    or (
                        isinstance(production_retry_family, str)
                        and (
                            changed_cause_fields
                            != validated_changed_cause_fields
                            or not isinstance(retry_basis_record_ids, list)
                            or len(retry_basis_record_ids) != 1
                            or type(retry_basis_record_ids[0]) is not str
                        )
                    )
                    or changed_manifest.get("schema") != "job_changed_cause.v1"
                    or not isinstance(failure_signature, str)
                    or changed_manifest.get("prior_failure_signature")
                    != failure_signature
                    or not isinstance(reproduction, list)
                    or any(type(item) is not str for item in reproduction)
                    or changed_proof in reproduction
                ):
                    raise TransitionError(
                        "replay repair changed-cause proof does not bind the exact failure"
                    )
                if changed_cause_fields == validated_changed_cause_fields:
                    validation_plan_hash = changed_manifest.get(
                        "validation_plan_hash"
                    )
                    validation_results = changed_manifest.get(
                        "result_artifact_hashes"
                    )
                    validator_id = changed_manifest.get("validator_id")
                    if (
                        type(validation_plan_hash) is not str
                        or not isinstance(validation_results, list)
                        or not validation_results
                        or validation_results
                        != sorted(set(validation_results))
                        or any(
                            type(item) is not str
                            for item in validation_results
                        )
                        or validation_plan_hash in validation_results
                        or type(validator_id) is not str
                        or not validator_id.startswith("validator:")
                    ):
                        raise TransitionError(
                            "replay repair engineering validation binding is malformed"
                        )
                    _require_digest(
                        "replay repair engineering validation plan",
                        validation_plan_hash,
                    )
                    _require_digest(
                        "replay repair engineering validator",
                        validator_id.removeprefix("validator:"),
                    )
                    for validation_hash in (
                        validation_plan_hash,
                        *validation_results,
                    ):
                        try:
                            self.evidence.verify(validation_hash)
                        except (
                            FileNotFoundError,
                            OSError,
                            RuntimeError,
                            ValueError,
                        ) as exc:
                            raise TransitionError(
                                "replay repair engineering validation evidence is unavailable"
                            ) from exc
                _require_digest(
                    "replay prior failure signature", failure_signature
                )
                basis_kind = ReplayRepairBasisKind.OPERATIONAL_FAILURE
                invalid_criterion_ids = ()
                prior_reproduction = set(reproduction)
            elif previous_completion.status == "success":
                raw_invalid = (
                    None
                    if not isinstance(changed_manifest, Mapping)
                    else changed_manifest.get("invalid_criterion_ids")
                )
                if (
                    common_invalid
                    or set(changed_manifest) != {
                        "changed_dimension",
                        "explanation",
                        "invalid_criterion_ids",
                        "new_evidence_hashes",
                        "new_implementation_identity",
                        "previous_implementation_identity",
                        "prior_completion_record_id",
                        "schema",
                        "study_diagnosis_id",
                        "validation_plan_hash",
                    }
                    or changed_manifest.get("schema")
                    != "replay_scientific_repair.v1"
                    or changed_manifest.get("prior_completion_record_id")
                    != previous_completion.record_id
                    or changed_manifest.get("study_diagnosis_id")
                    != diagnosis.record_id
                    or not isinstance(raw_invalid, list)
                    or not raw_invalid
                    or any(type(item) is not str for item in raw_invalid)
                    or len(raw_invalid) != len(set(raw_invalid))
                ):
                    raise TransitionError(
                        "replay scientific repair proof does not bind exact invalid evidence"
                    )
                basis_kind = ReplayRepairBasisKind.SCIENTIFIC_INVALIDITY
                failure_signature = None
                invalid_criterion_ids = tuple(sorted(raw_invalid))
                prior_reproduction = set()
            else:
                raise TransitionError(
                    "replay repair basis is neither failed nor scientifically invalid"
                )
            if (
                not isinstance(changed_manifest, Mapping)
                or not isinstance(new_evidence, list)
            ):
                raise TransitionError(
                    "replay repair changed-cause proof is malformed"
                )
            for evidence_hash in new_evidence:
                _require_digest("replay changed-cause evidence", evidence_hash)
                try:
                    self.evidence.verify(evidence_hash)
                except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                    raise TransitionError(
                        "replay repair changed-cause evidence is unavailable"
                    ) from exc
                if evidence_hash in prior_reproduction:
                    raise TransitionError(
                        "replay repair reuses prior failure reproduction evidence"
                    )
            if any(
                artifact_hash not in new_evidence
                for artifact_hash in repaired_manifest["artifact_hashes"]
            ):
                raise TransitionError(
                    "replay repair proof omits implementation artifact bytes"
                )
            protocol = repaired_manifest.get("protocol")
            if previous_manifest.get("protocol") != protocol:
                raise TransitionError(
                    "replay repair changes its implementation protocol"
                )
            scientific_binding = spec.get("scientific_binding")
            if (
                not isinstance(scientific_binding, Mapping)
                or scientific_binding != previous_spec.get("scientific_binding")
            ):
                raise TransitionError(
                    "replay repair changes its scientific binding"
                )
            plan_hash = scientific_binding.get("validation_plan_hash")
            if not isinstance(plan_hash, str):
                raise TransitionError(
                    "replay repair validation plan is absent"
                )
            _require_digest("replay repair validation plan", plan_hash)
            try:
                plan = parse_canonical(self.evidence.read_verified(plan_hash))
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise TransitionError(
                    "replay repair validation plan is unavailable"
                ) from exc
            criteria = None if not isinstance(plan, Mapping) else plan.get("criteria")
            evidence_subject = spec.get("evidence_subject")
            criterion_ids = (
                ()
                if not isinstance(criteria, list)
                else tuple(
                    item.get("criterion_id")
                    for item in criteria
                    if isinstance(item, Mapping)
                )
            )
            if (
                not isinstance(plan, Mapping)
                or plan.get("schema") != "scientific_validation_plan.v2"
                or plan.get("mission_id") != declaration.payload.get("mission_id")
                or not isinstance(evidence_subject, Mapping)
                or plan.get("executable_id") != evidence_subject.get("id")
                or not criterion_ids
                or len(criterion_ids) != len(criteria)
                or any(type(item) is not str for item in criterion_ids)
                or len(criterion_ids) != len(set(criterion_ids))
                or any(item not in criterion_ids for item in invalid_criterion_ids)
                or (
                    basis_kind is ReplayRepairBasisKind.SCIENTIFIC_INVALIDITY
                    and changed_manifest.get("validation_plan_hash") != plan_hash
                )
            ):
                raise TransitionError(
                    "replay repair validation plan is not subject-bound"
                )
            return ReplayRepairProvenance(
                basis_kind=basis_kind,
                prior_completion_record_id=previous_completion.record_id,
                study_diagnosis_id=diagnosis.record_id,
                protocol_id=protocol,
                validation_plan_hash=plan_hash,
                criterion_ids=tuple(criterion_ids),
                previous_implementation_identity=previous_identity,
                repaired_implementation_identity=repaired_identity,
                changed_cause_proof_hash=changed_proof,
                prior_failure_signature=failure_signature,
                invalid_criterion_ids=invalid_criterion_ids,
                new_evidence_hashes=tuple(new_evidence),
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("replay resume requires control")
            science = current["scientific"]
            mission_id = science.get("active_mission")
            next_action = current.get("next_action")
            if (
                not isinstance(mission_id, str)
                or not isinstance(next_action, dict)
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
                or next_action.get("kind")
                in {
                    "close_mission",
                    "diagnose_study",
                    "resolve_historical_replay_obligations",
                    "review_architecture",
                }
            ):
                raise TransitionError(
                    "replay resume requires a stable schedulable Mission boundary"
                )
            current_constraints = scheduler_constraints(
                index, mission_id=mission_id
            )
            projected_constraints = {
                name: next_action.get(name)
                for name in (
                    "pending_replay_obligation_ids",
                    "required_replay_priority",
                )
                if next_action.get(name) is not None
            }
            if projected_constraints != (current_constraints or {}):
                raise TransitionError(
                    "replay resume scheduler authority is absent or stale"
                )
            try:
                records, constraints, result = prepare_resume(
                    index,
                    mission_id=mission_id,
                    resumes=normalized,
                    repair_provenance=(
                        lambda *items: repair_provenance(index, *items)
                    ),
                )
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except ReplayTransitionError as exc:
                raise TransitionError(str(exc)) from exc
            body = self._body(current)
            body["next_action"] = self._with_replay_scheduler_constraints(
                next_action, constraints
            )
            return body, records, result

        return self._commit(
            event_kind="historical_replay_obligations_resumed",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "resumes": [item.to_identity_payload() for item in normalized]
            },
            prepare=prepare,
        )

    def record_historical_scientific_adjudications(
        self,
        *,
        requests: Sequence[Any],
        audit_artifact_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Add claim-scoped interpretations without rewriting legacy evidence."""

        from axiom_rift.research.historical_adjudication import (
            HistoricalAdjudicationRequest,
            HistoricalScientificAdjudication,
            ReplayPriority,
            derive_historical_adjudication,
            profile_manifest,
        )
        from axiom_rift.research.adjudication import AdjudicationProfile
        from axiom_rift.research.replay_obligation import (
            ReplayObligationStatus,
            ReplayPriorityEscalation,
            derive_historical_replay_obligation,
        )
        from axiom_rift.operations.completion_validity_projection import (
            CompletionValidityProjectionError,
            current_completion_validity_invalidation,
        )
        from axiom_rift.operations.replay_projection import (
            ReplayProjectionError,
            ReplayTransitionError,
            build_satisfaction_invalidation_plan,
            constraints_for_pending,
            effective_replay_priority,
            initial_obligation_record,
            replay_priority_escalation_record,
            replay_priority_stream,
        )

        _require_digest("historical audit artifact", audit_artifact_hash)
        self.evidence.verify(audit_artifact_hash)
        normalized = tuple(requests)
        if (
            not normalized
            or any(
                not isinstance(item, HistoricalAdjudicationRequest)
                for item in normalized
            )
            or len({item.completion_record_id for item in normalized})
            != len(normalized)
        ):
            raise TransitionError(
                "historical adjudication requires unique typed completion requests"
            )
        normalized = tuple(
            sorted(normalized, key=lambda item: item.completion_record_id)
        )
        request_manifest = [
            {
                "completion_record_id": item.completion_record_id,
                "disposition": item.disposition.value,
                "profile": profile_manifest(item.profile),
                "reason_codes": list(item.reason_codes),
                "replay_priority": item.replay_priority.value,
                "validity_overrides": [
                    override.manifest() for override in item.validity_overrides
                ],
            }
            for item in normalized
        ]
        self._require_study_close_delivery_guard()

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("historical adjudication requires control")
            science = current["scientific"]
            if (
                not isinstance(science.get("active_mission"), str)
                or not isinstance(science.get("active_initiative"), str)
                or current.get("next_action", {}).get("kind")
                != "portfolio_decision"
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
            ):
                raise TransitionError(
                    "historical adjudication requires the active stable Portfolio boundary"
                )

            memory_by_subject: dict[tuple[str, str], list[str]] = {}
            for memory in index.records_by_kind("negative-memory"):
                study_id = memory.payload.get("study_id")
                executable_id = memory.subject.removeprefix("Executable:")
                if isinstance(study_id, str) and isinstance(executable_id, str):
                    memory_by_subject.setdefault(
                        (study_id, executable_id), []
                    ).append(memory.record_id)

            obligation_heads = self._historical_replay_obligation_heads(
                index,
                mission_id=science["active_mission"],
            )
            obligation_by_completion: dict[str, tuple[Any, IndexRecord]] = {}
            for obligation, obligation_head in obligation_heads:
                previous = obligation_by_completion.setdefault(
                    obligation.original_completion_record_id,
                    (obligation, obligation_head),
                )
                if previous != (obligation, obligation_head):
                    raise RecoveryRequired(
                        "historical completion has duplicate replay obligations"
                    )

            records: list[IndexRecord] = []
            derived: list[HistoricalScientificAdjudication] = []
            new_replay_obligations: list[Any] = []
            reused_replay_obligation_ids: list[str] = []
            priority_escalations: list[ReplayPriorityEscalation] = []
            for request in normalized:
                new_priority_escalation: ReplayPriorityEscalation | None = None
                completion = index.get(
                    "job-completed", request.completion_record_id
                )
                scientific = (
                    None
                    if completion is None
                    else completion.payload.get("scientific")
                )
                declaration = (
                    None
                    if completion is None
                    else index.get(
                        "job-declared", completion.payload.get("job_id", "")
                    )
                )
                if (
                    completion is None
                    or completion.status not in {
                        "failed",
                        "not_evaluable",
                        "success",
                    }
                    or not isinstance(scientific, dict)
                    or declaration is None
                ):
                    raise TransitionError(
                        "historical adjudication completion is unavailable"
                    )
                if "adjudication" in scientific:
                    raise TransitionError(
                        "historical adjudication is restricted to legacy completions "
                        "without rich v2 adjudication"
                    )
                study_id = declaration.payload.get("study_id")
                executable_id = scientific.get("executable_id")
                plan_hash = scientific.get("validation_plan_hash")
                measurement_hashes = scientific.get(
                    "measurement_artifact_hashes"
                )
                verdict = scientific.get("verdict")
                if (
                    not isinstance(study_id, str)
                    or not isinstance(executable_id, str)
                    or not isinstance(plan_hash, str)
                    or not isinstance(measurement_hashes, list)
                    or len(measurement_hashes) != 1
                    or not isinstance(measurement_hashes[0], str)
                    or verdict not in {"passed", "failed", "not_evaluable"}
                ):
                    raise TransitionError(
                        "historical adjudication scientific provenance is malformed"
                    )
                measurement_hash = measurement_hashes[0]
                _require_digest("historical validation plan", plan_hash)
                _require_digest("historical measurement", measurement_hash)
                outputs = completion.payload.get("outputs")
                spec = declaration.payload.get("spec")
                if (
                    not isinstance(outputs, dict)
                    or plan_hash not in outputs.values()
                    or measurement_hash not in outputs.values()
                    or not isinstance(spec, dict)
                    or plan_hash not in spec.get("input_hashes", [])
                ):
                    raise TransitionError(
                        "historical adjudication artifacts are not completion-bound"
                    )
                try:
                    plan = parse_canonical(self.evidence.read_verified(plan_hash))
                    measurement = parse_canonical(
                        self.evidence.read_verified(measurement_hash)
                    )
                except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                    raise TransitionError(
                        "historical adjudication evidence is unavailable"
                    ) from exc
                if not isinstance(plan, dict) or not isinstance(measurement, dict):
                    raise TransitionError(
                        "historical adjudication evidence is not a mapping"
                    )
                if (
                    plan.get("schema") != "scientific_validation_plan.v1"
                    or measurement.get("schema") != "scientific_measurement.v1"
                ):
                    raise TransitionError(
                        "historical adjudication requires exact legacy v1 artifacts"
                    )
                if (
                    plan.get("executable_id") != executable_id
                    or measurement.get("executable_id") != executable_id
                    or plan.get("mission_id")
                    != declaration.payload.get("mission_id")
                    or measurement.get("mission_id")
                    != declaration.payload.get("mission_id")
                ):
                    raise TransitionError(
                        "historical adjudication subject binding is invalid"
                    )
                fixed_profile = AdjudicationProfile()
                if request.profile != fixed_profile:
                    raise TransitionError(
                        "historical adjudication profile differs from the "
                        "Writer-derived fixed legacy audit profile"
                    )
                stream = f"historical-adjudication:{completion.record_id}"
                head = index.event_head(stream)
                prior = (
                    None
                    if head is None
                    else index.get(head.record_kind, head.record_id)
                )
                if head is not None and (
                    prior is None
                    or prior.kind != "historical-scientific-adjudication"
                    or prior.event_stream != stream
                    or prior.event_sequence != head.sequence
                ):
                    raise RecoveryRequired(
                        "historical adjudication stream head is malformed"
                    )
                derived_overrides = (
                    self._writer_derived_historical_validity_overrides(
                        index,
                        completion_record_id=completion.record_id,
                        executable_id=executable_id,
                        declaration=declaration,
                        prior=prior,
                    )
                )
                if request.validity_overrides != derived_overrides:
                    raise TransitionError(
                        "historical validity overrides differ from "
                        "Writer-derived durable invalidity heads"
                    )
                study = index.get("study-open", study_id)
                close_records = tuple(
                    record
                    for outcome in _STUDY_OUTCOMES
                    for record in index.records_by_subject_status(
                        f"Study:{study_id}", outcome
                    )
                    if record.kind == "study-close"
                )
                if study is None or len(close_records) != 1:
                    raise TransitionError(
                        "historical adjudication Study close is unavailable"
                    )
                close = close_records[0]
                try:
                    item = derive_historical_adjudication(
                        audit_artifact_hash=audit_artifact_hash,
                        study_id=study_id,
                        study_close_record_id=close.record_id,
                        completion_record_id=completion.record_id,
                        executable_id=executable_id,
                        validation_plan_hash=plan_hash,
                        measurement_artifact_hash=measurement_hash,
                        original_job_status=completion.status,
                        original_scientific_verdict=verdict,
                        plan=plan,
                        measurement=measurement,
                        request=request,
                        negative_memory_ids=tuple(
                            memory_by_subject.get(
                                (study_id, executable_id), ()
                            )
                        ),
                    )
                except ValueError as exc:
                    raise TransitionError(
                        "historical adjudication derivation failed"
                    ) from exc
                if item.adjudication.legacy_verdict != verdict:
                    raise TransitionError(
                        "historical adjudication does not reproduce the legacy verdict"
                    )
                sequence = 1 if head is None else head.sequence + 1
                prior_record_id = None if head is None else head.record_id
                payload = {
                    **item.to_identity_payload(),
                    "supersedes_record_id": prior_record_id,
                    "trial_delta": 0,
                    "holdout_delta": 0,
                    "candidate_delta": 0,
                    "claim_authority": "additive_qualification_only",
                    "profile_authority": "writer_derived_fixed_legacy_v1",
                    "validity_override_authority": (
                        "writer_derived_durable_invalidity_heads"
                    ),
                }
                new_obligation_record: IndexRecord | None = None
                if item.disposition.value == "replay_required":
                    existing = obligation_by_completion.get(
                        completion.record_id
                    )
                    if existing is not None:
                        obligation, obligation_head = existing
                        cursor = prior
                        found_origin = False
                        seen_adjudications: set[str] = set()
                        while cursor is not None:
                            if cursor.record_id in seen_adjudications:
                                raise RecoveryRequired(
                                    "historical adjudication supersession is cyclic"
                                )
                            seen_adjudications.add(cursor.record_id)
                            if (
                                cursor.record_id
                                == obligation.historical_adjudication_id
                            ):
                                found_origin = True
                                break
                            superseded_id = cursor.payload.get(
                                "supersedes_record_id"
                            )
                            if superseded_id is None:
                                cursor = None
                            elif not isinstance(superseded_id, str):
                                raise RecoveryRequired(
                                    "historical adjudication supersession is malformed"
                                )
                            else:
                                cursor = index.get(
                                    "historical-scientific-adjudication",
                                    superseded_id,
                                )
                        if (
                            not found_origin
                            or obligation.original_executable_id != executable_id
                            or obligation.original_study_id != study_id
                            or obligation.original_study_close_record_id
                            != close.record_id
                            or obligation.governing_mission_id
                            != science["active_mission"]
                        ):
                            raise RecoveryRequired(
                                "historical replay obligation is outside the "
                                "adjudication supersession lineage"
                            )
                        payload["replay_obligation_id"] = obligation.identity
                        payload["replay_obligation_origin_adjudication_id"] = (
                            obligation.historical_adjudication_id
                        )
                        payload["replay_obligation_authority"] = (
                            "reused_existing_lineage"
                        )
                        reused_replay_obligation_ids.append(obligation.identity)
                        try:
                            current_effective_priority = effective_replay_priority(
                                index, obligation
                            )
                        except ReplayProjectionError as exc:
                            raise RecoveryRequired(str(exc)) from exc
                        if item.replay_priority is current_effective_priority:
                            pass
                        elif (
                            obligation.replay_priority is ReplayPriority.P1
                            and current_effective_priority is ReplayPriority.P1
                            and item.replay_priority is ReplayPriority.P0
                        ):
                            if (
                                "accepted_replay_satisfaction_revocation_pending"
                                not in item.reason_codes
                                or obligation_head.status
                                != ReplayObligationStatus.SATISFIED.value
                                or obligation_head.kind
                                != "historical-replay-obligation-resolution"
                                or not obligation_head.record_id.startswith(
                                    "historical-replay-satisfaction:"
                                )
                                or obligation_head.payload.get("obligation_id")
                                != obligation.identity
                            ):
                                raise TransitionError(
                                    "replay priority escalation requires the exact "
                                    "accepted satisfaction pending revocation"
                                )
                            try:
                                invalidation = (
                                    current_completion_validity_invalidation(
                                        index,
                                        completion.record_id,
                                    )
                                )
                            except CompletionValidityProjectionError as exc:
                                raise RecoveryRequired(
                                    "replay priority escalation completion "
                                    "validity is malformed"
                                ) from exc
                            if invalidation is None:
                                raise TransitionError(
                                    "replay priority escalation requires the "
                                    "current completion invalidation"
                                )
                            try:
                                invalidation_plan = (
                                    build_satisfaction_invalidation_plan(
                                        index,
                                        mission_id=science["active_mission"],
                                        obligation_id=obligation.identity,
                                    )
                                )
                            except ReplayProjectionError as exc:
                                raise RecoveryRequired(str(exc)) from exc
                            except ReplayTransitionError as exc:
                                raise TransitionError(str(exc)) from exc
                            audit_manifest = invalidation_plan.get(
                                "audit_manifest"
                            )
                            if (
                                invalidation_plan.get("schema")
                                != "replay_satisfaction_invalidation_plan.v1"
                                or invalidation_plan.get("operation")
                                != "invalidate_historical_replay_satisfaction"
                                or not isinstance(audit_manifest, dict)
                                or audit_manifest.get("obligation_id")
                                != obligation.identity
                                or audit_manifest.get("satisfaction_record_id")
                                != obligation_head.record_id
                                or audit_manifest.get("governing_mission_id")
                                != science["active_mission"]
                            ):
                                raise RecoveryRequired(
                                    "replay priority escalation invalidation "
                                    "plan is not exact"
                                )
                            if index.event_head(
                                replay_priority_stream(obligation.identity)
                            ) is not None:
                                raise RecoveryRequired(
                                    "replay priority escalation already exists"
                                )
                            try:
                                escalation = ReplayPriorityEscalation(
                                    governing_mission_id=science["active_mission"],
                                    obligation_id=obligation.identity,
                                    superseding_historical_adjudication_id=(
                                        item.identity
                                    ),
                                    completion_validity_invalidation_id=(
                                        invalidation.invalidation_record_id
                                    ),
                                    accepted_satisfaction_record_id=(
                                        obligation_head.record_id
                                    ),
                                    audit_artifact_hash=audit_artifact_hash,
                                    reason_codes=item.reason_codes,
                                )
                            except ValueError as exc:
                                raise RecoveryRequired(
                                    "replay priority escalation derivation failed"
                                ) from exc
                            new_priority_escalation = escalation
                            priority_escalations.append(escalation)
                        else:
                            raise TransitionError(
                                "an immutable replay obligation priority cannot "
                                "be demoted or otherwise rewritten"
                            )
                    else:
                        if prior is not None and prior.status == "replay_required":
                            raise RecoveryRequired(
                                "prior replay adjudication lost its obligation"
                            )
                        try:
                            obligation = derive_historical_replay_obligation(
                                governing_mission_id=science["active_mission"],
                                historical_adjudication_id=item.identity,
                                adjudication_payload=item.to_identity_payload(),
                            )
                        except ValueError as exc:
                            raise RecoveryRequired(
                                "derived historical replay obligation is malformed"
                            ) from exc
                        if index.get(
                            "historical-replay-obligation", obligation.identity
                        ) is not None:
                            raise RecoveryRequired(
                                "historical replay obligation identity already exists"
                            )
                        payload["replay_obligation_id"] = obligation.identity
                        payload["replay_obligation_origin_adjudication_id"] = (
                            item.identity
                        )
                        payload["replay_obligation_authority"] = "derived_new"
                        new_obligation_record = initial_obligation_record(
                            obligation
                        )
                        new_replay_obligations.append(obligation)
                records.append(
                    _record(
                        kind="historical-scientific-adjudication",
                        record_id=item.identity,
                        subject=f"Study:{study_id}",
                        status=item.disposition.value,
                        fingerprint=item.identity.removeprefix(
                            "historical-adjudication:"
                        ),
                        payload=payload,
                        event_stream=stream,
                        event_sequence=sequence,
                    )
                )
                if new_obligation_record is not None:
                    records.append(new_obligation_record)
                if new_priority_escalation is not None:
                    records.append(
                        replay_priority_escalation_record(
                            new_priority_escalation
                        )
                    )
                derived.append(item)
            body = self._body(current)
            existing_pending = [
                obligation
                for obligation, head in obligation_heads
                if head.status == "pending"
            ]
            combined_pending = [*existing_pending, *new_replay_obligations]
            try:
                effective_priorities = {
                    obligation.identity: effective_replay_priority(
                        index, obligation
                    )
                    for obligation in existing_pending
                }
            except ReplayProjectionError as exc:
                raise RecoveryRequired(str(exc)) from exc
            effective_priorities.update(
                {
                    obligation.identity: obligation.replay_priority
                    for obligation in new_replay_obligations
                }
            )
            replay_constraints = constraints_for_pending(
                combined_pending,
                effective_priorities=effective_priorities,
            )
            if replay_constraints is not None:
                body["next_action"] = self._with_replay_scheduler_constraints(
                    body["next_action"],
                    replay_constraints,
                )
            return body, records, {
                "adjudication_record_ids": [item.identity for item in derived],
                "replay_obligation_ids": [
                    item.identity for item in new_replay_obligations
                ],
                "reused_replay_obligation_ids": sorted(
                    reused_replay_obligation_ids
                ),
                "replay_priority_escalation_ids": sorted(
                    item.identity for item in priority_escalations
                ),
                "audit_artifact_hash": audit_artifact_hash,
                "candidate_delta": 0,
                "holdout_delta": 0,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="historical_scientific_adjudications_recorded",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "audit_artifact_hash": audit_artifact_hash,
                "requests": request_manifest,
            },
            prepare=prepare,
        )

    def require_study_close_delivery_guard(self) -> None:
        """Public fail-closed preflight for coherent scientific mutations."""

        self._require_study_close_delivery_guard()

    def _require_study_close_delivery_guard(self) -> None:
        if self.engineering_fixture:
            return
        from axiom_rift.operations.study_close_git import (
            StudyCloseDeliveryError,
            require_all_study_close_deliveries,
            require_study_close_delivery_observation,
            require_study_close_guard_ready,
        )

        try:
            capability = getattr(self, "study_close_guard_capability", None)
            observation = getattr(
                self,
                "study_close_delivery_observation",
                None,
            )
            if observation is not None:
                require_study_close_delivery_observation(
                    self.root,
                    observation,
                )
            elif capability is None:
                require_study_close_guard_ready(self.root)
                require_all_study_close_deliveries(self.root)
            else:
                require_study_close_guard_ready(
                    self.root, capability=capability
                )
                require_all_study_close_deliveries(
                    self.root, capability=capability
                )
        except (OSError, RuntimeError, StudyCloseDeliveryError) as exc:
            raise TransitionError(
                "Scientific transition is blocked by the Study-close Git guard"
            ) from exc

    def record_negative_memory(
        self,
        *,
        memory: Any,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.research.trials import NegativeMemory

        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot create negative memory")
        if not isinstance(memory, NegativeMemory):
            raise TransitionError("memory must be a NegativeMemory")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("negative memory requires an active Mission")
            mission_id = current["scientific"]["active_mission"]
            trial = index.get("trial", memory.executable_identity)
            if trial is None:
                raise TransitionError("negative memory requires a counted Executable trial")
            trial_study_id = trial.payload.get("study_id")
            trial_study = (
                None
                if not isinstance(trial_study_id, str)
                else index.get("study-open", trial_study_id)
            )
            if (
                trial_study is None
                or trial.payload.get("portfolio_axis_identity")
                != trial_study.payload.get("portfolio_axis_identity")
                or trial.payload.get("portfolio_snapshot_id")
                != trial_study.payload.get("portfolio_snapshot_id")
            ):
                raise TransitionError("negative memory trial Portfolio lineage is incomplete")
            holdout_context_id: str | None = None
            executed_evidence_modes: set[str] = set()
            evidence_study_ids: set[str] = set()
            for reference in memory.evidence_references:
                evidence = index.get("job-completed", reference)
                failure = None if evidence is None else evidence.payload.get("failure")
                scientific = None if evidence is None else evidence.payload.get("scientific")
                effective_scope = (
                    None
                    if evidence is None or not isinstance(scientific, dict)
                    else _effective_completion_scope(index, evidence)
                )
                legacy_scientific_failure = (
                    evidence is not None
                    and evidence.status == "failed"
                    and isinstance(failure, dict)
                    and failure.get("failure_kind") == "scientific_falsification"
                )
                operationally_successful_falsification = (
                    evidence is not None
                    and evidence.status == "success"
                    and failure is None
                )
                if (
                    evidence is None
                    or not (
                        legacy_scientific_failure
                        or operationally_successful_falsification
                    )
                    or not isinstance(scientific, dict)
                    or scientific.get("verdict") != "failed"
                    or effective_scope is None
                    or effective_scope.scientific_eligible is not True
                    or effective_scope.candidate_eligible is not False
                    or scientific.get("executable_id") != memory.executable_identity
                ):
                    raise TransitionError("negative memory evidence reference is invalid")
                evidence_modes = list(effective_scope.evidence_modes)
                normalized_modes = _require_study_evidence_modes(
                    {"evidence_modes": evidence_modes}
                )
                if list(normalized_modes) != evidence_modes:
                    raise TransitionError(
                        "negative memory evidence modes are not canonical"
                    )
                executed_evidence_modes.update(normalized_modes)
                declaration = index.get("job-declared", evidence.payload["job_id"])
                active_holdout = current["scientific"].get(
                    "active_holdout_evaluation"
                )
                holdout_binding = (
                    None
                    if declaration is None
                    else declaration.payload["spec"].get("holdout_binding")
                )
                candidate = (
                    None
                    if not isinstance(active_holdout, dict)
                    else index.get(
                        "candidate", active_holdout.get("candidate_id", "")
                    )
                )
                evidence_study_id = (
                    None
                    if declaration is None
                    else declaration.payload.get("study_id")
                )
                evidence_study = (
                    None
                    if not isinstance(evidence_study_id, str)
                    else index.get("study-open", evidence_study_id)
                )
                same_study_context = (
                    declaration is not None
                    and evidence_study is not None
                    and evidence_study.payload.get("mission_id") == mission_id
                    and evidence_study.payload.get("material_identity")
                    == trial.payload.get("material_identity")
                    and evidence_study.payload.get("portfolio_axis_identity")
                    == trial.payload.get("portfolio_axis_identity")
                )
                holdout_context = (
                    declaration is not None
                    and isinstance(active_holdout, dict)
                    and declaration.payload.get("study_id") is None
                    and evidence.payload.get("job_id") == active_holdout.get("job_id")
                    and active_holdout.get("executable_id")
                    == memory.executable_identity
                    and holdout_binding
                    == {"holdout_id": active_holdout.get("holdout_id")}
                    and candidate is not None
                    and candidate.payload.get("mission_id") == mission_id
                    and candidate.subject
                    == f"Executable:{memory.executable_identity}"
                )
                if (
                    declaration is None
                    or declaration.payload["mission_id"] != mission_id
                    or not (same_study_context or holdout_context)
                    or declaration.payload["spec"]["evidence_subject"]
                    != {"kind": "Executable", "id": memory.executable_identity}
                ):
                    raise TransitionError("negative evidence is not Executable/Mission bound")
                if holdout_context:
                    holdout_context_id = active_holdout["holdout_id"]
                if same_study_context:
                    assert isinstance(evidence_study_id, str)
                    evidence_study_ids.add(evidence_study_id)
            if len(evidence_study_ids) > 1:
                raise TransitionError(
                    "negative memory evidence spans multiple Study contexts"
                )
            memory_study_id = (
                next(iter(evidence_study_ids))
                if evidence_study_ids
                else trial_study_id
            )
            memory_study = index.get("study-open", memory_study_id)
            if memory_study is None:
                raise TransitionError("negative memory Study context is unavailable")
            record = _record(
                kind="negative-memory",
                record_id=memory.identity,
                subject=f"Executable:{memory.executable_identity}",
                status="durable",
                fingerprint=memory.executable_identity,
                payload={
                    "scope": memory.scope,
                    "evidence_references": list(memory.evidence_references),
                    "executed_evidence_modes": sorted(executed_evidence_modes),
                    "reason": memory.reason,
                    "reopen_condition": memory.reopen_condition,
                    "mission_id": mission_id,
                    "portfolio_axis_id": memory_study.payload.get(
                        "portfolio_axis_id"
                    ),
                    "portfolio_axis_identity": memory_study.payload.get(
                        "portfolio_axis_identity"
                    ),
                    "portfolio_snapshot_id": memory_study.payload.get(
                        "portfolio_snapshot_id"
                    ),
                    "study_id": memory_study_id,
                    "holdout_id": holdout_context_id,
                },
            )
            return self._body(current), [record], {"negative_memory_id": memory.identity}

        return self._commit(
            event_kind="negative_memory_recorded",
            operation_id=operation_id,
            subject=f"Executable:{memory.executable_identity}",
            payload={"negative_memory_id": memory.identity},
            prepare=prepare,
        )

    def _validate_permit_locked(
        self,
        *,
        control: Mapping[str, Any],
        index: LocalIndex,
        permit: Permit,
        expected_kind: PermitKind,
        action: str,
        subject_kind: SubjectKind,
        subject_id: str,
        expected_input_hash: str | None = None,
        required_scope: tuple[str, ...] = (),
    ) -> None:
        if self.permit_authority is None:
            raise PermitError("permit authority is unavailable")
        current_subject = self._current_subject(control, subject_kind, subject_id)
        self.permit_authority.validate(
            permit,
            expected_kind=expected_kind,
            action=action,
            current_subject=current_subject,
            status=self._permit_status(index, permit.permit_id),
            now_utc=self.clock(),
            expected_input_hash=expected_input_hash,
            required_scope=required_scope,
        )

    def validate_runtime_entry(
        self,
        *,
        permit: Permit,
        executable_id: str,
        input_hash: str,
        action: str,
        depth: Any,
        operation_id: str,
    ) -> TransitionResult:
        """Revalidate and durably attest the exact runtime engine entry."""

        from axiom_rift.runtime.guards import (
            CandidateBinding,
            EvidenceDepth,
            RuntimeClaimGuard,
        )

        if not isinstance(depth, EvidenceDepth):
            raise TransitionError("runtime depth must be an EvidenceDepth")
        if depth not in {
            EvidenceDepth.EXECUTION_PROOF,
            EvidenceDepth.MATERIALIZATION,
        }:
            raise PermitError("RuntimePermit cannot authorize this evidence depth")
        _require_ascii("executable_id", executable_id)
        _require_digest("input_hash", input_hash)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science["active_executable"] != executable_id:
                raise TransitionError("runtime entry is not the active Executable")
            job = science["active_job"]
            if not isinstance(job, dict) or job.get("status") != "running":
                raise TransitionError("runtime entry requires the active running Job")
            if input_hash != job.get("hash"):
                raise PermitError("runtime entry input is not the active Job identity")
            if job.get("runtime_entry_record_id") is not None:
                raise TransitionError("runtime engine entry was already attested")
            declaration = index.get("job-declared", job["id"])
            start_record = index.get("job-started", job.get("start_record_id", ""))
            if declaration is None or start_record is None:
                raise TransitionError("runtime entry Job provenance is unavailable")
            runtime_binding = declaration.payload["spec"].get("runtime_binding")
            started_runtime = start_record.payload.get("runtime")
            if (
                not isinstance(runtime_binding, dict)
                or not isinstance(started_runtime, dict)
                or runtime_binding.get("action") != action
                or runtime_binding.get("evidence_depth") != depth.value
                or started_runtime.get("runtime_permit_id") != permit.permit_id
                or started_runtime.get("executable_id") != executable_id
                or started_runtime.get("mission_id") != science["active_mission"]
            ):
                raise PermitError("runtime entry differs from its started Job binding")
            candidate_head = index.event_head(f"candidate:{executable_id}")
            candidate_record = (
                None
                if candidate_head is None
                else index.get(candidate_head.record_kind, candidate_head.record_id)
            )
            allowed = {("candidate", "frozen")}
            if self.engineering_fixture:
                allowed.add(("engineering-executable-fixture", "bound_fixture"))
            if candidate_record is None or (
                candidate_record.kind,
                candidate_record.status,
            ) not in allowed:
                raise TransitionError("runtime entry has no durable candidate binding")
            source_contracts = tuple(
                candidate_record.payload["executable"].get("source_contracts", [])
            )
            try:
                current_source_snapshot = current_runtime_source_snapshot(
                    index=index,
                    source_contract_ids=source_contracts,
                    require_runtime_source=lambda source_index, source_id: (
                        self._require_runtime_source(
                            source_index,
                            source_id,
                            error_type=PermitError,
                        )
                    ),
                )
                expected_candidate_context = candidate_job_execution_context(
                    index=index,
                    candidate=candidate_record,
                    current=current_source_snapshot,
                    runtime_binding=runtime_binding,
                )
            except RuntimeSuccessAuthorityError as exc:
                raise PermitError(str(exc)) from exc
            if (
                candidate_record.record_id != started_runtime.get("candidate_id")
                or candidate_record.subject != f"Executable:{executable_id}"
                or candidate_record.payload.get("mission_id")
                != science["active_mission"]
                or declaration.payload.get("candidate_execution_context")
                != expected_candidate_context
                or {
                    name: started_runtime.get(name)
                    for name in current_source_snapshot.payload()
                }
                != current_source_snapshot.payload()
            ):
                raise PermitError(
                    "runtime entry candidate or source snapshot changed after Job start"
                )
            required_scope = (
                f"candidate:{candidate_record.record_id}",
                f"depth:{depth.value}",
                f"executable:{executable_id}",
                f"job:{job['id']}",
            ) + tuple(f"source:{source_id}" for source_id in source_contracts)
            self._validate_permit_locked(
                control=current,
                index=index,
                permit=permit,
                expected_kind=PermitKind.RUNTIME,
                action=action,
                subject_kind=SubjectKind.EXECUTABLE,
                subject_id=executable_id,
                expected_input_hash=input_hash,
                required_scope=required_scope,
            )
            candidate = CandidateBinding(
                candidate_id=candidate_record.record_id,
                executable_id=executable_id,
                frozen=True,
                source_bindings=source_contracts,
            )
            RuntimeClaimGuard.require_entry(depth=depth, candidate=candidate)
            executable_subject = self._current_subject(
                current, SubjectKind.EXECUTABLE, executable_id
            )
            entry_payload = {
                "action": action,
                "candidate_authorization_hash": executable_subject.authorization_hash,
                "candidate_id": candidate_record.record_id,
                "depth": depth.value,
                "engine_contract": candidate_record.payload["executable"]["engine_contract"],
                "executable_id": executable_id,
                "job_id": job["id"],
                "job_start_record_id": job["start_record_id"],
                "mission_id": science["active_mission"],
                "runtime_permit_id": permit.permit_id,
                **current_source_snapshot.payload(),
            }
            entry_id = canonical_digest(domain="runtime-engine-entry", payload=entry_payload)
            entry = _record(
                kind="runtime-engine-entry",
                record_id=entry_id,
                subject=f"Job:{job['id']}",
                status="validated",
                fingerprint=job["hash"],
                payload=entry_payload,
                event_stream=f"runtime-entry:{job['id']}",
                event_sequence=1,
            )
            job["runtime_entry_record_id"] = entry_id
            body["next_action"] = {"kind": "resume_job", "job_id": job["id"]}
            return body, [entry], {
                "runtime_entry_record_id": entry_id,
                "permit_id": permit.permit_id,
                "executable_id": executable_id,
                "depth": depth.value,
                "current_source_receipts": list(
                    current_source_snapshot.source_receipt_ids
                ),
                "current_source_state_records": list(
                    current_source_snapshot.source_state_record_ids
                ),
            }

        return self._commit(
            event_kind="runtime_engine_entered",
            operation_id=operation_id,
            subject=f"Executable:{executable_id}",
            payload={
                "permit_id": permit.permit_id,
                "input_hash": input_hash,
                "action": action,
                "depth": depth.value,
            },
            prepare=prepare,
        )

    @staticmethod
    def _permit_consumption_record(permit: Permit, operation_id: str) -> IndexRecord:
        record_id = canonical_digest(
            domain="permit-consumption",
            payload={"permit_id": permit.permit_id, "operation_id": operation_id},
        )
        return _record(
            kind="permit-consumed",
            record_id=record_id,
            subject=f"Permit:{permit.permit_id}",
            status="consumed",
            fingerprint=permit.permit_id,
            payload={"permit_id": permit.permit_id, "one_shot": permit.one_shot},
            event_stream=f"permit:{permit.permit_id}",
            event_sequence=2,
        )

    def start_job(
        self,
        *,
        permit: Permit,
        operation_id: str,
        runtime_permit: Permit | None = None,
    ) -> TransitionResult:
        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            job = body["scientific"]["active_job"]
            if not isinstance(job, dict) or job["status"] != "declared":
                raise TransitionError("no declared Job can start")
            self._validate_permit_locked(
                control=current,
                index=index,
                permit=permit,
                expected_kind=PermitKind.JOB,
                action="start_job",
                subject_kind=SubjectKind.JOB,
                subject_id=job["id"],
                expected_input_hash=job["hash"],
            )
            declaration = index.get("job-declared", job["id"])
            if declaration is None:
                raise TransitionError("Job declaration is unavailable at start")
            declared_spec = declaration.payload["spec"]
            if _job_requires_current_source_authority(
                engineering_fixture=self.engineering_fixture,
                evidence_subject_kind=declared_spec["evidence_subject"]["kind"],
            ):
                from axiom_rift.research.implementation_closure import (
                    ImplementationClosureError,
                    require_current_job_source_closure,
                    require_job_implementation_closure,
                )

                implementation_manifest = (
                    self._require_job_implementation_evidence(
                        declared_spec,
                        _index=index,
                    )
                )
                executable_manifest: dict[str, Any] | None = None
                try:
                    component_implementation_hashes: tuple[str, ...] = ()
                    if declared_spec["evidence_subject"]["kind"] == "Executable":
                        subject_trial = index.get(
                            "trial", declared_spec["evidence_subject"]["id"]
                        )
                        executable_manifest = (
                            None
                            if subject_trial is None
                            else subject_trial.payload.get("executable")
                        )
                        if not isinstance(executable_manifest, dict):
                            raise RecoveryRequired(
                                "Executable Job subject lost its exact trial manifest"
                            )
                        component_implementation_hashes = (
                            require_job_implementation_closure(
                                executable_manifest=executable_manifest,
                                job_artifact_hashes=implementation_manifest[
                                    "artifact_hashes"
                                ],
                                artifact_reader=self.evidence.read_verified,
                            )
                        )
                except ImplementationClosureError as exc:
                    raise TransitionError(str(exc)) from exc
                declared_component_hashes = declaration.payload.get(
                    "component_implementation_hashes"
                )
                if (
                    declared_component_hashes
                    != (
                        list(component_implementation_hashes)
                        if component_implementation_hashes
                        else None
                    )
                ):
                    raise RecoveryRequired(
                        "Job Component implementation closure drifted before start"
                    )
                source_closure_hashes = (
                    _job_implementation_source_closure_hashes(
                        implementation_manifest=implementation_manifest,
                        artifact_reader=self.evidence.read_verified,
                    )
                )
                declared_authority = declaration.payload.get(
                    "source_closure_authority"
                )
                if source_closure_hashes:
                    if not isinstance(declared_authority, Mapping):
                        raise RecoveryRequired(
                            "prospective Job lacks declared source-path authority"
                        )
                    try:
                        current_authority = (
                            require_current_job_source_closure(
                                callable_identity=declared_spec[
                                    "callable_identity"
                                ],
                                job_artifact_hashes=(
                                    implementation_manifest[
                                        "artifact_hashes"
                                    ]
                                ),
                                artifact_reader=self.evidence.read_verified,
                                source_root=self.foundation_root / "src",
                                verified_non_source_artifact_hashes=(
                                    component_implementation_hashes
                                ),
                            )
                        )
                    except ImplementationClosureError as exc:
                        raise TransitionError(str(exc)) from exc
                    if current_authority != declared_authority:
                        raise RecoveryRequired(
                            "Job source-path authority drifted before start"
                        )
                    try:
                        if executable_manifest is not None:
                            closure_payload = parse_canonical(
                                self.evidence.read_verified(
                                    source_closure_hashes[0]
                                )
                            )
                            if not isinstance(closure_payload, Mapping):
                                raise ExternalObservedDevelopmentJobBindingError(
                                    "Job source closure payload is malformed"
                                )
                            require_current_external_observed_development_job_binding(
                                executable_id=declared_spec[
                                    "evidence_subject"
                                ]["id"],
                                executable_manifest=executable_manifest,
                                job_spec=declared_spec,
                                source_closure_dependencies=closure_payload[
                                    "dependencies"
                                ],
                                durable_payload=declaration.payload.get(
                                    "external_observed_development_binding"
                                ),
                                repository_root=self.foundation_root,
                            )
                        elif declaration.payload.get(
                            "external_observed_development_binding"
                        ) is not None:
                            raise ExternalObservedDevelopmentJobBindingError(
                                "non-Executable Job has an external prefix binding"
                            )
                    except ExternalObservedDevelopmentJobBindingError as exc:
                        raise TransitionError(str(exc)) from exc
                else:
                    raise RecoveryRequired(
                        "production Job without a current recursive source closure "
                        "cannot start; historical evidence is read-only"
                    )
            batch_id = declaration.payload.get("batch_id")
            if isinstance(batch_id, str):
                active_batch = body["scientific"].get("active_batch")
                batch_record = index.get("batch-open", batch_id)
                if (
                    not isinstance(active_batch, dict)
                    or active_batch.get("id") != batch_id
                    or batch_record is None
                ):
                    raise RecoveryRequired(
                        "Job start lost its active frozen Batch declaration"
                    )
                _require_concurrent_family_registration(
                    index,
                    batch_record=batch_record,
                    evidence_subject=declared_spec["evidence_subject"],
                )
            runtime_binding = declared_spec.get("runtime_binding")
            for domain, binding_name in (
                ("scientific", "component_parity_binding"),
                ("external", "external_dependency_binding"),
                ("scientific", "scientific_binding"),
                ("source", "source_binding"),
                ("runtime", "runtime_binding"),
            ):
                binding = declared_spec.get(binding_name)
                if isinstance(binding, dict):
                    try:
                        self.validation_registry.preflight_binding(
                            validator_id=binding["validator_id"],
                            domain=domain,
                            binding=binding,
                        )
                    except EvidenceValidationError as exc:
                        raise TransitionError(str(exc)) from exc
            runtime_provenance: dict[str, Any] | None = None
            if runtime_binding is None:
                if runtime_permit is not None:
                    raise PermitError("a non-runtime Job cannot consume RuntimePermit authority")
            else:
                if runtime_permit is None:
                    raise PermitError("runtime-bound Job requires a RuntimePermit")
                science = body["scientific"]
                executable_id = science["active_executable"]
                if (
                    executable_id is None
                    or declaration.payload["spec"]["evidence_subject"]
                    != {"kind": "Executable", "id": executable_id}
                ):
                    raise TransitionError("runtime Job is not bound to the active Executable")
                candidate_head = index.event_head(f"candidate:{executable_id}")
                candidate = (
                    None
                    if candidate_head is None
                    else index.get(candidate_head.record_kind, candidate_head.record_id)
                )
                expected_kind = (
                    "engineering-executable-fixture"
                    if self.engineering_fixture
                    else "candidate"
                )
                expected_status = "bound_fixture" if self.engineering_fixture else "frozen"
                if (
                    candidate is None
                    or candidate.kind != expected_kind
                    or candidate.status != expected_status
                ):
                    raise TransitionError("runtime Job lacks the current candidate activation")
                source_contracts = tuple(
                    candidate.payload["executable"].get("source_contracts", [])
                )
                try:
                    source_snapshot = current_runtime_source_snapshot(
                        index=index,
                        source_contract_ids=source_contracts,
                        require_runtime_source=lambda source_index, source_id: (
                            self._require_runtime_source(
                                source_index,
                                source_id,
                                error_type=PermitError,
                            )
                        ),
                    )
                    expected_candidate_context = (
                        candidate_job_execution_context(
                            index=index,
                            candidate=candidate,
                            current=source_snapshot,
                            runtime_binding=runtime_binding,
                        )
                    )
                except RuntimeSuccessAuthorityError as exc:
                    raise PermitError(str(exc)) from exc
                if (
                    candidate.subject != f"Executable:{executable_id}"
                    or candidate.payload.get("mission_id")
                    != science["active_mission"]
                    or declaration.payload.get("candidate_execution_context")
                    != expected_candidate_context
                ):
                    raise PermitError(
                        "runtime Job candidate or source snapshot changed before start"
                    )
                required_scope = (
                    f"candidate:{candidate.record_id}",
                    f"depth:{runtime_binding['evidence_depth']}",
                    f"executable:{executable_id}",
                    f"job:{job['id']}",
                ) + tuple(f"source:{source_id}" for source_id in source_contracts)
                self._validate_permit_locked(
                    control=current,
                    index=index,
                    permit=runtime_permit,
                    expected_kind=PermitKind.RUNTIME,
                    action=runtime_binding["action"],
                    subject_kind=SubjectKind.EXECUTABLE,
                    subject_id=executable_id,
                    expected_input_hash=job["hash"],
                    required_scope=required_scope,
                )
                runtime_provenance = {
                    "action": runtime_binding["action"],
                    "candidate_id": candidate.record_id,
                    "evidence_depth": runtime_binding["evidence_depth"],
                    "executable_id": executable_id,
                    "mission_id": science["active_mission"],
                    "runtime_permit_id": runtime_permit.permit_id,
                    **source_snapshot.payload(),
                }
            start_id = canonical_digest(
                domain="job-start",
                payload={
                    "job_id": job["id"],
                    "job_permit": permit.permit_id,
                    "runtime_permit": (
                        None if runtime_permit is None else runtime_permit.permit_id
                    ),
                },
            )
            job["status"] = "running"
            job["start_record_id"] = start_id
            body["next_action"] = {"kind": "resume_job", "job_id": job["id"]}
            consumption = self._permit_consumption_record(permit, operation_id)
            record = _record(
                kind="job-started",
                record_id=start_id,
                subject=f"Job:{job['id']}",
                status="running",
                fingerprint=job["hash"],
                payload={
                    "job_permit_id": permit.permit_id,
                    "runtime": runtime_provenance,
                },
            )
            execution = RunningJobExecution(
                job_id=job["id"],
                job_hash=job["hash"],
                start_record_id=start_id,
                job_permit_id=permit.permit_id,
            )
            engine_records: list[IndexRecord] = []
            if runtime_binding is None:
                engine_entry_id = canonical_digest(
                    domain="job-engine-entry",
                    payload=execution.payload(),
                )
                job["engine_entry_record_id"] = engine_entry_id
                engine_records.append(
                    _record(
                        kind="job-engine-entry",
                        record_id=engine_entry_id,
                        subject=f"Job:{job['id']}",
                        status="validated",
                        fingerprint=job["hash"],
                        payload={
                            "execution": execution.payload(),
                            "permit_consumption_record_id": consumption.record_id,
                        },
                    )
                )
            return body, [consumption, record, *engine_records], {
                "execution": execution.payload(),
                "job_id": job["id"],
            }

        return self._commit(
            event_kind="job_started",
            operation_id=operation_id,
            subject=f"Job:{permit.subject.subject_id}",
            payload={
                "permit_id": permit.permit_id,
                "runtime_permit_id": (
                    None if runtime_permit is None else runtime_permit.permit_id
                ),
            },
            prepare=prepare,
        )

    def _run_registered_validator(
        self,
        *,
        domain: str,
        job_id: str,
        job_hash: str,
        mission_id: str,
        evidence_subject: Mapping[str, str],
        binding: Mapping[str, Any],
        result_manifest: Mapping[str, Any],
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
        result_name: str,
        artifact_output_names: frozenset[str] | None = None,
    ) -> tuple[Any, dict[str, Any]]:
        if artifact_output_names is not None and (
            not artifact_output_names
            or any(
                type(output_name) is not str or not output_name
                for output_name in artifact_output_names
            )
        ):
            raise TransitionError("validator artifact output scope is invalid")
        artifacts: list[ValidationArtifact] = []
        for output_name, output_hash in sorted(output_manifest.items()):
            if output_classes.get(output_name) != "durable_evidence":
                continue
            if (
                artifact_output_names is not None
                and output_name not in artifact_output_names
            ):
                continue
            artifacts.append(
                ValidationArtifact(
                    output_name=output_name,
                    sha256=output_hash,
                    _source=self.evidence.verified_path(output_hash),
                )
            )
        if not any(artifact.output_name == result_name for artifact in artifacts):
            raise TransitionError("result manifest is absent from validator artifacts")
        request = EvidenceValidationRequest(
            domain=domain,
            validator_id=binding["validator_id"],
            validation_plan_hash=binding["validation_plan_hash"],
            job_id=job_id,
            job_hash=job_hash,
            mission_id=mission_id,
            evidence_subject=evidence_subject,
            binding=binding,
            result_manifest=result_manifest,
            artifacts=tuple(artifacts),
            engineering_fixture=self.engineering_fixture,
        )
        try:
            validated, trace = self.validation_registry.validate(request)
        except EvidenceValidationError as exc:
            raise TransitionError(f"registered {domain} validation failed: {exc}") from exc
        return validated, {
            "validator_id": trace.validator_id,
            "declared_artifact_count": trace.declared_artifact_count,
            "opened_artifact_count": trace.opened_artifact_count,
        }

    def _scientific_validator_artifact_output_names(
        self,
        *,
        binding: Mapping[str, Any],
        result_name: str,
        measurement_hashes: set[str],
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
    ) -> frozenset[str] | None:
        """Route only v2 core and preregistered proof artifacts to science."""

        plan_hash = binding.get("validation_plan_hash")
        if type(plan_hash) is not str:
            raise TransitionError("scientific validation plan hash is absent")
        try:
            plan = parse_canonical(self.evidence.read_verified(plan_hash))
        except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
            raise TransitionError(
                "scientific validation plan is unavailable"
            ) from exc
        if (
            not isinstance(plan, Mapping)
            or plan.get("schema") != "scientific_validation_plan.v2"
        ):
            return None
        requirements = plan.get("proof_requirements")
        if not isinstance(requirements, list) or not requirements:
            raise TransitionError(
                "scientific v2 proof requirement routing is unavailable"
            )
        proof_names: set[str] = set()
        for requirement in requirements:
            output_name = (
                None
                if not isinstance(requirement, Mapping)
                else requirement.get("output_name")
            )
            if type(output_name) is not str or not output_name:
                raise TransitionError(
                    "scientific v2 proof output routing is malformed"
                )
            proof_names.add(output_name)
        plan_names = {
            output_name
            for output_name, output_hash in output_manifest.items()
            if output_hash == plan_hash
            and output_classes.get(output_name) == "durable_evidence"
        }
        measurement_names = {
            output_name
            for output_name, output_hash in output_manifest.items()
            if output_hash in measurement_hashes
            and output_classes.get(output_name) == "durable_evidence"
        }
        routed = {
            result_name,
            *plan_names,
            *measurement_names,
            *proof_names,
        }
        if (
            len(plan_names) != 1
            or not measurement_hashes
            or len(measurement_names) != len(measurement_hashes)
            or {
                output_manifest[output_name]
                for output_name in measurement_names
            }
            != measurement_hashes
            or len(routed)
            != 1 + len(plan_names) + len(measurement_names) + len(proof_names)
            or any(
                output_classes.get(output_name) != "durable_evidence"
                or output_name not in output_manifest
                for output_name in routed
            )
        ):
            raise TransitionError(
                "scientific v2 validator artifact routing is ambiguous"
            )
        return frozenset(routed)

    def _validated_scientific_multiplicity_registrations(
        self,
        *,
        binding: Mapping[str, Any],
        registrations: object,
        adjudication: object,
        batch_record: IndexRecord | None,
        expected_batch_id: str | None,
        executable_id: str,
        mission_id: str,
    ) -> tuple[
        list[dict[str, Any]] | None,
        dict[str, Any] | None,
    ]:
        try:
            return validate_scientific_multiplicity_registrations(
                binding=binding,
                registrations=registrations,
                adjudication=adjudication,
                batch_record=batch_record,
                expected_batch_id=expected_batch_id,
                executable_id=executable_id,
                mission_id=mission_id,
                artifact_reader=self.evidence.read_verified,
            )
        except ScientificMultiplicityIntegrityError as exc:
            raise RecoveryRequired(str(exc)) from exc
        except ScientificMultiplicityAuthorityError as exc:
            raise TransitionError(str(exc)) from exc

    def _derive_runtime_job_evidence(
        self,
        *,
        job_id: str,
        job_hash: str,
        binding: Mapping[str, Any],
        provenance: Mapping[str, Any],
        source_lifecycle_coverage: object,
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
    ) -> dict[str, Any]:
        """Parse a content-addressed runtime result packet and derive claims."""

        result_name = binding["result_manifest_output"]
        result_hash = output_manifest.get(result_name)
        if not isinstance(result_hash, str):
            raise TransitionError("runtime result manifest output is absent")
        try:
            value = parse_canonical(self.evidence.read_verified(result_hash))
        except ValueError as exc:
            raise TransitionError("runtime result manifest is not canonical") from exc
        required = {
            "action",
            "candidate_id",
            "evidence_depth",
            "executable_id",
            "job_hash",
            "job_id",
            "mission_id",
            "observations",
            "runtime_permit_id",
            "schema",
        }
        if not isinstance(value, dict) or set(value) != required:
            raise TransitionError("runtime result manifest schema is invalid")
        expected_values = {
            "action": binding["action"],
            "candidate_id": provenance["candidate_id"],
            "evidence_depth": binding["evidence_depth"],
            "executable_id": provenance["executable_id"],
            "job_hash": job_hash,
            "job_id": job_id,
            "mission_id": provenance["mission_id"],
            "runtime_permit_id": provenance["runtime_permit_id"],
            "schema": "runtime_job_evidence.v1",
        }
        if any(value.get(name) != expected for name, expected in expected_values.items()):
            raise TransitionError("runtime result manifest is bound to another execution")
        observations = value["observations"]
        if not isinstance(observations, list) or not observations:
            raise TransitionError("runtime result manifest has no observations")
        durable_hashes = {
            output_hash
            for output_name, output_hash in output_manifest.items()
            if output_classes.get(output_name) == "durable_evidence"
            and output_name != result_name
        }
        if not durable_hashes:
            raise TransitionError("runtime result has no measurement artifact")
        from axiom_rift.runtime.source_lifecycle_coverage import (
            SourceLifecycleCoverageError,
            require_source_lifecycle_coverage_ids,
        )

        coverage_rows = source_lifecycle_coverage
        if not isinstance(coverage_rows, list) or any(
            not isinstance(row, Mapping) for row in coverage_rows
        ):
            raise TransitionError(
                "runtime Job lacks Writer-derived source lifecycle coverage"
            )
        try:
            planned_coverage_ids = require_source_lifecycle_coverage_ids(
                binding["planned_source_lifecycle_coverage_ids"],
                allowed_rows=coverage_rows,
                planned_materialization_cases=binding[
                    "planned_materialization_cases"
                ],
            )
        except SourceLifecycleCoverageError as exc:
            raise TransitionError(str(exc)) from exc
        coverage_by_id = {
            row["coverage_id"]: row for row in coverage_rows
        }
        claims: set[str] = set()
        measurement_hashes: set[str] = set()
        observation_keys: set[tuple[str, str | None]] = set()
        observed_coverage_ids: set[str] = set()
        for observation in observations:
            if not isinstance(observation, dict) or set(observation) not in ({
                "claim_id",
                "measurement_artifact_hash",
                "status",
            }, {
                "claim_id",
                "measurement_artifact_hash",
                "source_lifecycle_coverage_id",
                "status",
            }):
                raise TransitionError("runtime observation schema is invalid")
            claim_id = observation["claim_id"]
            measurement_hash = observation["measurement_artifact_hash"]
            coverage_id = observation.get("source_lifecycle_coverage_id")
            observation_key = (claim_id, coverage_id)
            if (
                type(claim_id) is not str
                or observation_key in observation_keys
                or measurement_hash not in durable_hashes
            ):
                raise TransitionError("runtime observation is not artifact-bound")
            if coverage_id is not None:
                coverage_row = coverage_by_id.get(coverage_id)
                if (
                    coverage_id not in planned_coverage_ids
                    or coverage_row is None
                    or coverage_row.get("materialization_case") != claim_id
                ):
                    raise TransitionError(
                        "runtime source lifecycle observation exceeds its exact plan"
                    )
                observed_coverage_ids.add(coverage_id)
            elif coverage_rows and claim_id in {
                "source_interruption",
                "stale_or_missing_input",
            }:
                raise TransitionError(
                    "source-dependent lifecycle observation lacks its exact coverage row"
                )
            self.evidence.verify(measurement_hash)
            observation_keys.add(observation_key)
            claims.add(claim_id)
            measurement_hashes.add(measurement_hash)
        if observed_coverage_ids != set(planned_coverage_ids):
            raise TransitionError(
                "runtime source lifecycle observations do not cover the exact plan"
            )
        planned = (
            set(binding["planned_parity_surfaces"])
            if binding["evidence_depth"] == "execution_proof"
            else set(binding["planned_materialization_cases"])
        )
        if not claims.issubset(planned):
            raise TransitionError("runtime result exceeds preregistered claims")
        validated, validation_trace = self._run_registered_validator(
            domain="runtime",
            job_id=job_id,
            job_hash=job_hash,
            mission_id=provenance["mission_id"],
            evidence_subject={"kind": "Executable", "id": provenance["executable_id"]},
            binding=binding,
            result_manifest=value,
            output_manifest=output_manifest,
            output_classes=output_classes,
            result_name=result_name,
        )
        if validated.verdict != "passed" or set(validated.claims) != claims:
            raise TransitionError("runtime claims were not derived as passed by the validator")
        if set(validated.measurement_artifact_hashes) != measurement_hashes:
            raise TransitionError("runtime validator measurements differ from the Job packet")
        validated_coverage = validated.facts.get(
            "source_lifecycle_coverage_ids"
        )
        if planned_coverage_ids and (
            not isinstance(validated_coverage, (list, tuple))
            or tuple(validated_coverage) != planned_coverage_ids
        ):
            raise TransitionError(
                "runtime validator did not derive the exact source lifecycle coverage"
            )
        if not planned_coverage_ids and validated_coverage not in (None, (), []):
            raise TransitionError(
                "runtime validator invented source lifecycle coverage"
            )
        expected_roles = {
            role: output_manifest[output_name]
            for role, output_name in binding["artifact_roles"].items()
        }
        observed_roles = dict(validated.artifact_roles)
        if observed_roles != expected_roles:
            raise TransitionError("runtime validator artifact roles differ from declaration")
        if not self.engineering_fixture and (
            not validated.scientific_eligible or not validated.release_eligible
        ):
            raise TransitionError("runtime validator did not authorize Release-eligible evidence")
        return {
            **dict(provenance),
            "artifact_roles": dict(validated.artifact_roles),
            "materialization_cases": (
                sorted(claims)
                if binding["evidence_depth"] == "materialization"
                else []
            ),
            "measurement_artifact_hashes": sorted(measurement_hashes),
            "parity_surfaces": (
                sorted(claims)
                if binding["evidence_depth"] == "execution_proof"
                else []
            ),
            "result_manifest_hash": result_hash,
            "source_lifecycle_coverage_ids": list(
                planned_coverage_ids
            ),
            "scientific_eligible": validated.scientific_eligible,
            "release_eligible": validated.release_eligible,
            "validation_trace": validation_trace,
            "validator_id": binding["validator_id"],
            "validation_plan_hash": binding["validation_plan_hash"],
        }

    def _derive_source_job_evidence(
        self,
        *,
        job_id: str,
        job_hash: str,
        mission_id: str,
        evidence_subject: Mapping[str, str],
        binding: Mapping[str, Any],
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
    ) -> dict[str, Any]:
        result_name = binding["result_manifest_output"]
        result_hash = output_manifest.get(result_name)
        if not isinstance(result_hash, str):
            raise TransitionError("source result manifest output is absent")
        try:
            value = parse_canonical(self.evidence.read_verified(result_hash))
        except ValueError as exc:
            raise TransitionError("source result manifest is not canonical") from exc
        required = {
            "facts",
            "job_hash",
            "job_id",
            "measurement_artifact_hashes",
            "mission_id",
            "observed_at_utc",
            "schema",
            "source_contract_id",
            "transition_evidence",
        }
        if not isinstance(value, dict) or set(value) != required:
            raise TransitionError("source result manifest schema is invalid")
        if (
            value["schema"] != "source_eligibility_evidence.v1"
            or value["job_id"] != job_id
            or value["job_hash"] != job_hash
            or value["mission_id"] != mission_id
            or value["source_contract_id"] != binding["source_contract_id"]
            or value["transition_evidence"] != binding["transition_evidence"]
        ):
            raise TransitionError("source result manifest is bound to another Job")
        measurement_hashes = value["measurement_artifact_hashes"]
        if (
            not isinstance(measurement_hashes, list)
            or not measurement_hashes
            or len(set(measurement_hashes)) != len(measurement_hashes)
        ):
            raise TransitionError("source result measurements are invalid")
        durable_hashes = {
            output_hash
            for output_name, output_hash in output_manifest.items()
            if output_classes.get(output_name) == "durable_evidence"
            and output_name != result_name
        }
        if set(measurement_hashes) != durable_hashes:
            raise TransitionError("source measurements differ from durable Job outputs")
        for measurement_hash in measurement_hashes:
            self.evidence.verify(measurement_hash)
        if not isinstance(value["facts"], dict):
            raise TransitionError("source result facts are invalid")
        _require_ascii("source observed_at_utc", value["observed_at_utc"])
        validated, validation_trace = self._run_registered_validator(
            domain="source",
            job_id=job_id,
            job_hash=job_hash,
            mission_id=mission_id,
            evidence_subject=evidence_subject,
            binding=binding,
            result_manifest=value,
            output_manifest=output_manifest,
            output_classes=output_classes,
            result_name=result_name,
        )
        verified_facts = dict(validated.facts)
        observed_at_utc = verified_facts.pop("observed_at_utc", None)
        if (
            validated.verdict != "passed"
            or set(validated.measurement_artifact_hashes) != set(measurement_hashes)
            or verified_facts != value["facts"]
            or observed_at_utc != value["observed_at_utc"]
        ):
            raise TransitionError("source facts were not derived by the registered validator")
        return {
            "artifact_hashes": sorted(measurement_hashes),
            "facts": verified_facts,
            "observed_at_utc": observed_at_utc,
            "result_manifest_hash": result_hash,
            "source_contract_id": binding["source_contract_id"],
            "transition_evidence": binding["transition_evidence"],
            "validation_trace": validation_trace,
            "validator_id": binding["validator_id"],
            "validation_plan_hash": binding["validation_plan_hash"],
        }

    def _derive_scientific_job_evidence(
        self,
        *,
        job_id: str,
        job_hash: str,
        mission_id: str,
        executable_id: str,
        binding: Mapping[str, Any],
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
        batch_record: IndexRecord | None = None,
        expected_batch_id: str | None = None,
    ) -> dict[str, Any]:
        result_name = binding["result_manifest_output"]
        result_hash = output_manifest.get(result_name)
        if not isinstance(result_hash, str):
            raise TransitionError("scientific result manifest output is absent")
        try:
            value = parse_canonical(self.evidence.read_verified(result_hash))
        except ValueError as exc:
            raise TransitionError("scientific result manifest is not canonical") from exc
        required = {
            "evidence_depth",
            "executable_id",
            "job_hash",
            "job_id",
            "mission_id",
            "observations",
            "schema",
        }
        if not isinstance(value, dict) or set(value) != required:
            raise TransitionError("scientific result manifest schema is invalid")
        if (
            value["schema"] != "scientific_job_evidence.v1"
            or value["job_id"] != job_id
            or value["job_hash"] != job_hash
            or value["mission_id"] != mission_id
            or value["executable_id"] != executable_id
            or value["evidence_depth"] != binding["evidence_depth"]
        ):
            raise TransitionError("scientific result belongs to another Job")
        durable_hashes = {
            output_hash
            for output_name, output_hash in output_manifest.items()
            if output_classes.get(output_name) == "durable_evidence"
            and output_name != result_name
        }
        observations = value["observations"]
        if not isinstance(observations, list) or not observations:
            raise TransitionError("scientific result has no observations")
        claims: set[str] = set()
        measurement_hashes: set[str] = set()
        for observation in observations:
            if not isinstance(observation, dict) or set(observation) != {
                "claim_id",
                "measurement_artifact_hash",
            }:
                raise TransitionError("scientific observation schema is invalid")
            claim_id = observation["claim_id"]
            measurement_hash = observation["measurement_artifact_hash"]
            if (
                type(claim_id) is not str
                or claim_id in claims
                or measurement_hash not in durable_hashes
            ):
                raise TransitionError("scientific observation is not artifact-bound")
            claims.add(claim_id)
            measurement_hashes.add(measurement_hash)
        if claims != set(binding["planned_claims"]):
            raise TransitionError("scientific observations differ from preregistration")
        validator_artifact_outputs = (
            self._scientific_validator_artifact_output_names(
                binding=binding,
                result_name=result_name,
                measurement_hashes=measurement_hashes,
                output_manifest=output_manifest,
                output_classes=output_classes,
            )
        )
        validated, validation_trace = self._run_registered_validator(
            domain="scientific",
            job_id=job_id,
            job_hash=job_hash,
            mission_id=mission_id,
            evidence_subject={"kind": "Executable", "id": executable_id},
            binding=binding,
            result_manifest=value,
            output_manifest=output_manifest,
            output_classes=output_classes,
            result_name=result_name,
            artifact_output_names=validator_artifact_outputs,
        )
        validator_facts = dict(validated.facts)
        executed_modes = validator_facts.pop("executed_evidence_modes", None)
        adjudication = validator_facts.pop("scientific_adjudication", None)
        multiplicity_registrations = validator_facts.pop(
            "multiplicity_registrations", None
        )
        if (
            validated.verdict not in {"passed", "failed", "not_evaluable"}
            or set(validated.claims) != claims
            or set(validated.measurement_artifact_hashes) != measurement_hashes
            or executed_modes != list(binding["evidence_modes"])
            or validator_facts
            or not validated.scientific_eligible
        ):
            raise TransitionError(
                "scientific evidence was not derived as eligible by the validator"
            )
        if adjudication is not None:
            required_adjudication = {
                "candidate_eligible",
                "claims",
                "criteria",
                "evaluable",
                "evidence_depth",
                "invalid_metrics",
                "legacy_verdict",
                "multiplicity",
                "schema",
                "state",
            }
            projected_verdict = {
                "confirmed": "passed",
                "contradicted": "failed",
                "frontier": "passed",
                "not_evaluable": "not_evaluable",
                "partial_positive": "not_evaluable",
                "unresolved": "not_evaluable",
            }
            if (
                not isinstance(adjudication, dict)
                or set(adjudication) != required_adjudication
                or adjudication.get("schema") != "scientific_adjudication.v1"
                or adjudication.get("evidence_depth") != binding["evidence_depth"]
                or projected_verdict.get(adjudication.get("state"))
                != validated.verdict
                or adjudication.get("candidate_eligible")
                is not validated.candidate_eligible
                or not isinstance(adjudication.get("claims"), list)
                or {
                    item.get("claim_id")
                    for item in adjudication["claims"]
                    if isinstance(item, dict)
                }
                != claims
            ):
                raise TransitionError(
                    "scientific rich adjudication differs from the validator verdict"
                )
        (
            multiplicity_registrations,
            multiplicity_batch_binding,
        ) = (
            self._validated_scientific_multiplicity_registrations(
                binding=binding,
                registrations=multiplicity_registrations,
                adjudication=adjudication,
                batch_record=batch_record,
                expected_batch_id=expected_batch_id,
                executable_id=executable_id,
                mission_id=mission_id,
            )
        )
        scientific = {
            "candidate_eligible": validated.candidate_eligible,
            "claims": sorted(claims),
            "evidence_depth": binding["evidence_depth"],
            "executed_evidence_modes": list(binding["evidence_modes"]),
            "executable_id": executable_id,
            "measurement_artifact_hashes": sorted(measurement_hashes),
            "result_manifest_hash": result_hash,
            "scientific_eligible": True,
            "verdict": validated.verdict,
            "validation_trace": validation_trace,
            "validator_id": binding["validator_id"],
            "validation_plan_hash": binding["validation_plan_hash"],
        }
        if adjudication is not None:
            scientific["adjudication"] = adjudication
        if multiplicity_registrations is not None:
            scientific["multiplicity_registrations"] = (
                multiplicity_registrations
            )
        if multiplicity_batch_binding is not None:
            scientific["multiplicity_batch_binding"] = (
                multiplicity_batch_binding
            )
        return scientific

    def _derive_external_dependency_evidence(
        self,
        *,
        job_id: str,
        job_hash: str,
        mission_id: str,
        binding: Mapping[str, Any],
        outcome: str,
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
    ) -> dict[str, Any]:
        result_name = binding["result_manifest_output"]
        result_hash = output_manifest.get(result_name)
        if not isinstance(result_hash, str):
            raise TransitionError("external result manifest output is absent")
        try:
            value = parse_canonical(self.evidence.read_verified(result_hash))
        except ValueError as exc:
            raise TransitionError("external result manifest is not canonical") from exc
        required = {
            "contract_valid_next_action_found",
            "dependency_id",
            "indispensable_to_mission_terminal",
            "job_hash",
            "job_id",
            "measurement_artifact_hashes",
            "mission_id",
            "observed_external_state",
            "recovery_kind",
            "required_external_change",
            "safe_substitute_found",
            "schema",
        }
        if not isinstance(value, dict) or set(value) != required:
            raise TransitionError("external result manifest schema is invalid")
        if (
            value["schema"] != "external_dependency_evidence.v1"
            or value["job_id"] != job_id
            or value["job_hash"] != job_hash
            or value["mission_id"] != mission_id
            or value["dependency_id"] != binding["dependency_id"]
            or value["recovery_kind"] != binding["recovery_kind"]
            or value["required_external_change"]
            != binding["required_external_change"]
            or type(value["safe_substitute_found"]) is not bool
            or type(value["indispensable_to_mission_terminal"]) is not bool
            or type(value["contract_valid_next_action_found"]) is not bool
        ):
            raise TransitionError("external result is bound to another recovery Job")
        measurement_hashes = value["measurement_artifact_hashes"]
        durable_hashes = {
            output_hash
            for output_name, output_hash in output_manifest.items()
            if output_classes.get(output_name) == "durable_evidence"
            and output_name != result_name
        }
        if (
            not isinstance(measurement_hashes, list)
            or not measurement_hashes
            or set(measurement_hashes) != durable_hashes
            or len(set(measurement_hashes)) != len(measurement_hashes)
        ):
            raise TransitionError("external measurements differ from Job outputs")
        _require_ascii("observed_external_state", value["observed_external_state"])
        validated, validation_trace = self._run_registered_validator(
            domain="external",
            job_id=job_id,
            job_hash=job_hash,
            mission_id=mission_id,
            evidence_subject={"kind": "Mission", "id": mission_id},
            binding=binding,
            result_manifest=value,
            output_manifest=output_manifest,
            output_classes=output_classes,
            result_name=result_name,
        )
        expected_verdict = {
            "success": "passed",
            "failed": "failed",
            "not_evaluable": "not_evaluable",
        }[outcome]
        expected_facts = {
            "blocked_mission_capability": binding["blocked_mission_capability"],
            "contract_valid_next_action_found": value[
                "contract_valid_next_action_found"
            ],
            "dependency_id": value["dependency_id"],
            "indispensable_to_mission_terminal": value[
                "indispensable_to_mission_terminal"
            ],
            "observed_external_state": value["observed_external_state"],
            "recovery_kind": value["recovery_kind"],
            "required_external_change": value["required_external_change"],
            "safe_substitute_found": value["safe_substitute_found"],
        }
        if (
            validated.verdict != expected_verdict
            or validated.claims
            or validated.artifact_roles
            or validated.scientific_eligible
            or validated.candidate_eligible
            or validated.release_eligible
            or set(validated.measurement_artifact_hashes) != durable_hashes
            or dict(validated.facts) != expected_facts
        ):
            raise TransitionError(
                "external state was not derived by the registered validator"
            )
        return {
            **expected_facts,
            "measurement_artifact_hashes": sorted(durable_hashes),
            "result_manifest_hash": result_hash,
            "validation_trace": validation_trace,
            "validator_id": binding["validator_id"],
            "validation_plan_hash": binding["validation_plan_hash"],
            "verdict": validated.verdict,
        }

    def _derive_component_parity_job_evidence(
        self,
        *,
        job_id: str,
        job_hash: str,
        mission_id: str,
        evidence_subject: Mapping[str, str],
        binding: Mapping[str, Any],
        output_manifest: Mapping[str, Any],
        output_classes: Mapping[str, Any],
    ) -> dict[str, Any]:
        result_name = binding["result_manifest_output"]
        result_hash = output_manifest.get(result_name)
        if not isinstance(result_hash, str):
            raise TransitionError("component parity result manifest is absent")
        try:
            value = parse_canonical(self.evidence.read_verified(result_hash))
        except ValueError as exc:
            raise TransitionError(
                "component parity result manifest is not canonical"
            ) from exc
        required = {
            "architecture_chassis_identity",
            "artifact_hashes",
            "canonical_component_id",
            "dimensions",
            "equivalent_component_id",
            "job_hash",
            "job_id",
            "mission_id",
            "portfolio_axis_identity",
            "portfolio_decision_id",
            "portfolio_snapshot_id",
            "schema",
            "verdict",
        }
        if not isinstance(value, dict) or set(value) != required:
            raise TransitionError("component parity result schema is invalid")
        expected = {
            "architecture_chassis_identity": binding[
                "architecture_chassis_identity"
            ],
            "canonical_component_id": binding["canonical_component_id"],
            "dimensions": binding["dimensions"],
            "equivalent_component_id": binding["equivalent_component_id"],
            "job_hash": job_hash,
            "job_id": job_id,
            "mission_id": mission_id,
            "portfolio_axis_identity": binding["portfolio_axis_identity"],
            "portfolio_decision_id": binding["portfolio_decision_id"],
            "portfolio_snapshot_id": binding["portfolio_snapshot_id"],
            "schema": "component_parity_result.v2",
        }
        if any(value.get(name) != expected_value for name, expected_value in expected.items()):
            raise TransitionError(
                "component parity result differs from its Decision-bound Job"
            )
        if value["verdict"] not in {"equivalent", "not_equivalent"}:
            raise TransitionError("component parity verdict is not typed")
        measurement_hashes = {
            output_hash
            for output_name, output_hash in output_manifest.items()
            if output_classes.get(output_name) == "durable_evidence"
            and output_name != result_name
        }
        if (
            not measurement_hashes
            or value["artifact_hashes"] != sorted(measurement_hashes)
        ):
            raise TransitionError(
                "component parity result does not bind every measurement artifact"
            )
        validated, validation_trace = self._run_registered_validator(
            domain="scientific",
            job_id=job_id,
            job_hash=job_hash,
            mission_id=mission_id,
            evidence_subject=evidence_subject,
            binding=binding,
            result_manifest=value,
            output_manifest=output_manifest,
            output_classes=output_classes,
            result_name=result_name,
        )
        equivalent = value["verdict"] == "equivalent"
        expected_facts = {
            "canonical_component_id": binding["canonical_component_id"],
            "dimensions": binding["dimensions"],
            "equivalent": equivalent,
            "equivalent_component_id": binding["equivalent_component_id"],
        }
        expected_verdict = "passed" if equivalent else "failed"
        if (
            validated.verdict != expected_verdict
            or validated.claims
            or validated.scientific_eligible
            or validated.candidate_eligible
            or validated.release_eligible
            or set(validated.measurement_artifact_hashes) != measurement_hashes
            or dict(validated.facts) != expected_facts
        ):
            raise TransitionError(
                "component equivalence was not derived by the registered validator"
            )
        return {
            "canonical_component_id": binding["canonical_component_id"],
            "canonical_component_manifest": binding[
                "canonical_component_manifest"
            ],
            "dimensions": list(binding["dimensions"]),
            "equivalent": equivalent,
            "equivalent_component_id": binding["equivalent_component_id"],
            "equivalent_component_manifest": binding[
                "equivalent_component_manifest"
            ],
            "measurement_artifact_hashes": sorted(measurement_hashes),
            "result_manifest_hash": result_hash,
            "validation_plan_hash": binding["validation_plan_hash"],
            "validation_trace": validation_trace,
            "validator_id": binding["validator_id"],
            "verdict": validated.verdict,
        }

    def complete_job(
        self,
        *,
        outcome: str,
        output_manifest: Mapping[str, Any],
        failure: Mapping[str, Any] | None = None,
        operation_id: str,
        evidence_blobs: Sequence[bytes] = (),
        crash_after: str | None = None,
    ) -> TransitionResult:
        try:
            failure_manifest = normalize_job_failure_manifest(
                outcome=outcome,
                failure=failure,
                evidence_verifier=self.evidence.verify,
                engineering_cause_builder=self._engineering_failure_cause,
            )
        except JobContractError as exc:
            raise TransitionError(str(exc)) from exc

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            job = science["active_job"]
            if not isinstance(job, dict) or job["status"] != "running":
                raise TransitionError("no running Job can complete")
            job_id = job["id"]
            declaration = _index.get("job-declared", job_id)
            if declaration is None or declaration.fingerprint != job["hash"]:
                raise TransitionError("current Job declaration is unavailable")
            declared_spec = declaration.payload.get("spec")
            if not isinstance(declared_spec, dict):
                raise TransitionError("current Job spec is unavailable")
            engineering_disposition: dict[str, Any] | None = None
            required_engineering_disposition = job.get(
                "required_engineering_disposition_hash"
            )
            required_engineering_cause = job.get(
                "required_engineering_failure_cause_hash"
            )
            required_engineering_repair = job.get(
                "required_engineering_repair_id"
            )
            direction = body.get("next_action")
            if job.get("required_repair_resume_record_id") is not None:
                raise TransitionError(
                    "a repaired Job must re-enter its exact engine before completion"
                )
            if (
                failure_manifest is not None
                and failure_manifest["failure_kind"] == "engineering"
            ):
                disposition_hash = failure_manifest["repair_disposition_hash"]
                if (
                    "required_engineering_repair_id" not in job
                    or not isinstance(required_engineering_disposition, str)
                    or not isinstance(required_engineering_cause, str)
                    or failure_manifest["engineering_cause_hash"]
                    != required_engineering_cause
                    or not isinstance(direction, Mapping)
                    or set(direction)
                    != {"disposition_hash", "job_id", "kind"}
                    or direction.get("kind")
                    != "complete_engineering_failure"
                    or direction.get("job_id") != job_id
                    or direction.get("disposition_hash")
                    != disposition_hash
                    or required_engineering_disposition
                    != disposition_hash
                ):
                    raise TransitionError(
                        "engineering failure lacks its exact durable disposition"
                    )
                disposition = self._engineering_failure_disposition(
                    _index,
                    disposition_hash=disposition_hash,
                    job_id=job_id,
                    job_hash=job["hash"],
                    repair_id=required_engineering_repair,
                    cause_hash=required_engineering_cause,
                    reproduction_evidence_hashes=failure_manifest[
                        "minimum_reproduction_evidence"
                    ],
                )
                engineering_disposition = disposition.payload()
            elif (
                required_engineering_disposition is not None
                or required_engineering_cause is not None
                or "required_engineering_repair_id" in job
                or (
                    isinstance(direction, Mapping)
                    and direction.get("kind") == "complete_engineering_failure"
                )
            ):
                raise TransitionError(
                    "unrecovered Repair must complete as its typed engineering failure"
                )
            expected_outputs = declared_spec.get("expected_outputs")
            output_classes = declared_spec.get("output_classes")
            if not isinstance(expected_outputs, list) or not isinstance(output_classes, dict):
                raise TransitionError("current Job output declaration is invalid")
            _require_job_output_namespace(
                expected_outputs,
                output_classes=output_classes,
            )
            _require_job_output_namespace(
                tuple(output_manifest),
                output_classes=output_classes,
                name="Job completion outputs",
            )
            runtime_binding = declared_spec.get("runtime_binding")
            runtime_manifest: dict[str, Any] | None = None
            scientific_binding = declared_spec.get("scientific_binding")
            scientific_manifest: dict[str, Any] | None = None
            source_binding = declared_spec.get("source_binding")
            source_manifest: dict[str, Any] | None = None
            external_binding = declared_spec.get("external_dependency_binding")
            external_manifest: dict[str, Any] | None = None
            holdout_binding = declared_spec.get("holdout_binding")
            component_parity_binding = declared_spec.get(
                "component_parity_binding"
            )
            component_parity_manifest: dict[str, Any] | None = None
            if (
                failure_manifest is not None
                and failure_manifest["failure_kind"]
                == "runtime_source_ineligibility"
                and runtime_binding is None
            ):
                raise TransitionError(
                    "runtime source ineligibility requires a runtime-bound Job"
                )
            active_holdout = science.get("active_holdout_evaluation")
            pre_reveal_holdout_engineering_gap = False
            if holdout_binding is not None:
                holdout_id = (
                    holdout_binding.get("holdout_id")
                    if isinstance(holdout_binding, Mapping)
                    else None
                )
                reveal_head = (
                    None
                    if not isinstance(holdout_id, str)
                    else _index.event_head(f"holdout-reveal:{holdout_id}")
                )
                reveal = (
                    None
                    if reveal_head is None
                    else _index.get(
                        reveal_head.record_kind,
                        reveal_head.record_id,
                    )
                )
                exact_revealed_holdout = (
                    isinstance(active_holdout, dict)
                    and active_holdout.get("status")
                    == "revealed_pending_evaluation"
                    and active_holdout.get("job_id") == job_id
                    and active_holdout.get("holdout_id") == holdout_id
                    and active_holdout.get("executable_id")
                    == declared_spec.get("evidence_subject", {}).get("id")
                    and reveal_head is not None
                    and reveal_head.sequence == 1
                    and reveal is not None
                    and reveal.kind == "holdout-reveal"
                    and reveal.status == "revealed_once"
                    and reveal.payload.get("job_id") == job_id
                )
                pre_reveal_holdout_engineering_gap = (
                    engineering_disposition is not None
                    and active_holdout is None
                    and reveal_head is None
                )
                if not (
                    exact_revealed_holdout
                    or pre_reveal_holdout_engineering_gap
                ):
                    raise TransitionError(
                        "holdout-bound Job cannot complete before its exact reveal"
                    )
            start_record_id = job.get("start_record_id")
            start_record = (
                None
                if not isinstance(start_record_id, str)
                else _index.get("job-started", start_record_id)
            )
            if start_record is None:
                raise TransitionError("current Job start provenance is unavailable")
            job_permit_id = start_record.payload.get("job_permit_id")
            if not isinstance(job_permit_id, str):
                raise TransitionError("current Job start permit is unavailable")
            current_execution = RunningJobExecution(
                job_id=job_id,
                job_hash=job["hash"],
                start_record_id=start_record_id,
                job_permit_id=job_permit_id,
            )
            repair_resume_record_id = job.get(
                "last_repair_resume_record_id"
            )

            def completion_runtime_source(
                index: LocalIndex,
                source_id: str,
                *,
                freshness_required: bool = True,
            ) -> IndexRecord:
                try:
                    return self._require_runtime_source(
                        index,
                        source_id,
                        freshness_required=freshness_required,
                    )
                except TransitionError as exc:
                    raise JobCompletionEntryAuthorityError(str(exc)) from exc

            try:
                require_repair_resume_entry(
                    index=_index,
                    job=job,
                    job_id=job_id,
                    declared_spec=declared_spec,
                    current_execution=current_execution,
                    effective_implementation_resolver=(
                        self._effective_running_job_implementation
                    ),
                )
                provenance = require_completion_engine_entry(
                    control=body,
                    index=_index,
                    job=job,
                    job_id=job_id,
                    declaration=declaration,
                    start_record=start_record,
                    start_record_id=start_record_id,
                    job_permit_id=job_permit_id,
                    current_execution=current_execution,
                    runtime_binding=runtime_binding,
                    outcome=outcome,
                    failure_manifest=failure_manifest,
                    engineering_disposition=engineering_disposition,
                    direction=direction,
                    engineering_fixture=self.engineering_fixture,
                    runtime_source_resolver=completion_runtime_source,
                )
            except JobCompletionEntryIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except JobCompletionEntryAuthorityError as exc:
                raise TransitionError(str(exc)) from exc
            if outcome == "success" and set(output_manifest) != set(expected_outputs):
                raise TransitionError("successful Job output manifest differs from declaration")
            if outcome != "success" and not set(output_manifest).issubset(expected_outputs):
                raise TransitionError("failed Job returned an undeclared output")
            if set(output_classes) != set(expected_outputs):
                raise TransitionError("Job output classes differ from expected outputs")
            for output_name, output_hash in output_manifest.items():
                _require_ascii("output name", output_name)
                _require_digest("output hash", output_hash)
                if output_classes[output_name] == "durable_evidence":
                    self.evidence.verify(output_hash)
                else:
                    target = (self.root / output_name).resolve()
                    local_root = (self.root / "local").resolve()
                    if local_root not in target.parents:
                        raise TransitionError("Job local output escaped local/")
                    if outcome == "success" and not target.is_file():
                        raise TransitionError("successful Job local output is absent")
                    if target.is_file() and sha256(target.read_bytes()).hexdigest() != output_hash:
                        raise TransitionError("Job local output hash mismatch")
            if runtime_binding is not None and outcome == "success":
                runtime_manifest = self._derive_runtime_job_evidence(
                    job_id=job_id,
                    job_hash=job["hash"],
                    binding=runtime_binding,
                    provenance=provenance,
                    source_lifecycle_coverage=(
                        declaration.payload.get(
                            "candidate_execution_context", {}
                        ).get("source_lifecycle_coverage")
                        if isinstance(
                            declaration.payload.get(
                                "candidate_execution_context"
                            ), Mapping
                        )
                        else None
                    ),
                    output_manifest=output_manifest,
                    output_classes=output_classes,
                )
            if source_binding is not None and outcome == "success":
                source_manifest = self._derive_source_job_evidence(
                    job_id=job_id,
                    job_hash=job["hash"],
                    mission_id=declaration.payload["mission_id"],
                    evidence_subject=declared_spec["evidence_subject"],
                    binding=source_binding,
                    output_manifest=output_manifest,
                    output_classes=output_classes,
                )
            if scientific_binding is not None and outcome == "success":
                if set(output_manifest) != set(expected_outputs):
                    raise TransitionError(
                        "scientific evidence disposition requires every declared output"
                    )
                declared_batch_id = declaration.payload.get("batch_id")
                active_batch = science.get("active_batch")
                scientific_batch_record = (
                    None
                    if not isinstance(declared_batch_id, str)
                    else _index.get("batch-open", declared_batch_id)
                )
                if (
                    isinstance(declared_batch_id, str)
                    and (
                        not isinstance(active_batch, Mapping)
                        or active_batch.get("id") != declared_batch_id
                        or scientific_batch_record is None
                    )
                ):
                    raise TransitionError(
                        "scientific Job lost its exact active Batch before completion"
                    )
                scientific_manifest = self._derive_scientific_job_evidence(
                    job_id=job_id,
                    job_hash=job["hash"],
                    mission_id=declaration.payload["mission_id"],
                    executable_id=declared_spec["evidence_subject"]["id"],
                    binding=scientific_binding,
                    output_manifest=output_manifest,
                    output_classes=output_classes,
                    batch_record=scientific_batch_record,
                    expected_batch_id=(
                        declared_batch_id
                        if isinstance(declared_batch_id, str)
                        else None
                    ),
                )
            if component_parity_binding is not None and outcome == "success":
                if set(output_manifest) != set(expected_outputs):
                    raise TransitionError(
                        "component parity disposition requires every declared output"
                    )
                component_parity_manifest = (
                    self._derive_component_parity_job_evidence(
                        job_id=job_id,
                        job_hash=job["hash"],
                        mission_id=declaration.payload["mission_id"],
                        evidence_subject=declared_spec["evidence_subject"],
                        binding=component_parity_binding,
                        output_manifest=output_manifest,
                        output_classes=output_classes,
                    )
                )
            if isinstance(external_binding, dict) and (
                outcome == "success"
                or (
                    failure_manifest is not None
                    and failure_manifest["failure_kind"] == "external_dependency"
                )
            ):
                if set(output_manifest) != set(expected_outputs):
                    raise TransitionError(
                        "external dependency disposition requires every declared output"
                    )
                external_manifest = self._derive_external_dependency_evidence(
                    job_id=job_id,
                    job_hash=job["hash"],
                    mission_id=declaration.payload["mission_id"],
                    binding=external_binding,
                    outcome=outcome,
                    output_manifest=output_manifest,
                    output_classes=output_classes,
                )
            if (
                failure_manifest is not None
                and failure_manifest["resume_action"] != declared_spec["resume_action"]
            ):
                raise TransitionError("failure resume action differs from the Job declaration")
            if failure_manifest is not None and failure_manifest["failure_kind"] == "external_dependency":
                if (
                    not isinstance(external_binding, dict)
                    or failure_manifest.get("external_dependency_id")
                    != external_binding["dependency_id"]
                    or failure_manifest["resume_action"]
                    != external_binding["exact_resume_action"]
                ):
                    raise TransitionError(
                        "external failure differs from its preregistered dependency"
                    )
            if (
                isinstance(external_binding, Mapping)
                and isinstance(engineering_disposition, Mapping)
                and engineering_disposition.get("successor_scope")
                is not None
            ):
                raise TransitionError(
                    "external engineering failure cannot authorize scientific successor work"
                )
            completion_identity_payload = {
                "candidate_execution_context": declaration.payload.get(
                    "candidate_execution_context"
                ),
                "job_id": job_id,
                "outcome": outcome,
                "outputs": dict(output_manifest),
                "failure_signature": (
                    None
                    if failure_manifest is None
                    else failure_manifest["failure_signature"]
                ),
                "external": external_manifest,
                "runtime": runtime_manifest,
                "repair_resume_record_id": repair_resume_record_id,
                "scientific": scientific_manifest,
                "source": source_manifest,
            }
            if component_parity_manifest is not None:
                completion_identity_payload["component_parity"] = (
                    component_parity_manifest
                )
            record_id = canonical_digest(
                domain="job-completion",
                payload=completion_identity_payload,
            )
            completion_payload = {
                "candidate_execution_context": declaration.payload.get(
                    "candidate_execution_context"
                ),
                "job_id": job_id,
                "outputs": dict(output_manifest),
                "output_classes": dict(output_classes),
                "failure": failure_manifest,
                "engineering_disposition": engineering_disposition,
                "external": external_manifest,
                "start_record_id": start_record_id,
                "runtime": runtime_manifest,
                "repair_resume_record_id": repair_resume_record_id,
                "scientific": scientific_manifest,
                "source": source_manifest,
            }
            if component_parity_manifest is not None:
                completion_payload["component_parity"] = component_parity_manifest
            record = _record(
                kind="job-completed",
                record_id=record_id,
                subject=f"Job:{job_id}",
                status=outcome,
                fingerprint=job["hash"],
                payload=completion_payload,
                event_stream=f"job-attempt:{declaration.payload['work_fingerprint']}",
                event_sequence=(
                    _index.event_head(
                        f"job-attempt:{declaration.payload['work_fingerprint']}"
                    ).sequence
                    + 1
                ),
            )
            try:
                retry_family_completion = (
                    build_retry_family_completion_record(
                        index=_index,
                        declaration=declaration,
                        outcome=outcome,
                        completion_record_id=record_id,
                    )
                )
            except JobRetryAdmissionIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            science["active_job"] = None
            self._drop_authorization(body, SubjectKind.JOB, job_id)
            try:
                projection = project_job_completion(
                    index=_index,
                    declaration=declaration,
                    completion=record,
                    active_holdout=active_holdout,
                    pre_reveal_holdout_engineering_gap=(
                        pre_reveal_holdout_engineering_gap
                    ),
                    engineering_fixture=self.engineering_fixture,
                    record_builder=_record,
                )
            except JobCompletionProjectionIntegrityError as exc:
                raise RecoveryRequired(str(exc)) from exc
            except JobCompletionProjectionError as exc:
                raise TransitionError(str(exc)) from exc
            body["next_action"] = dict(projection.next_action)
            science["active_holdout_evaluation"] = (
                None
                if projection.active_holdout_evaluation is None
                else dict(projection.active_holdout_evaluation)
            )
            records = [
                record,
                *(
                    [retry_family_completion]
                    if retry_family_completion is not None
                    else []
                ),
                *projection.supplemental_records,
            ]
            return body, records, {
                "job_id": job_id,
                "outcome": outcome,
                "scientific_verdict": (
                    None
                    if scientific_manifest is None
                    else scientific_manifest["verdict"]
                ),
                "completion_record_id": record_id,
                "failure_signature": (
                    None
                    if failure_manifest is None
                    else failure_manifest.get("failure_signature")
                ),
                "output_classes": dict(output_classes),
            }

        result = self._commit(
            event_kind="job_completed",
            operation_id=operation_id,
            subject="Job:active",
            payload={
                "outcome": outcome,
                "output_manifest": dict(output_manifest),
                "failure": failure_manifest,
            },
            prepare=prepare,
            evidence_blobs=evidence_blobs,
            crash_after=crash_after,
        )
        transient_root = (self.root / "local" / "jobs").resolve()
        for output_name, output_class in result.result["output_classes"].items():
            if output_class != "transient":
                continue
            target = (self.root / output_name).resolve()
            if transient_root not in target.parents:
                raise TransitionError("transient cleanup escaped local/jobs")
            if target.is_file():
                target.unlink()
            elif target.exists():
                raise TransitionError("transient output path is not a file")
        return result

    def judge_job_evidence(
        self,
        *,
        completion_record_id: str,
        disposition: str,
        negative_memory_id: str | None = None,
        operation_id: str,
    ) -> TransitionResult:
        """Consume a completed Job judgement before more Batch work."""

        from axiom_rift.operations.architecture_review_direction import (
            ARCHITECTURE_CONTINUATION_ACTION_FIELDS,
            ArchitectureReviewDirectionError,
            constraint_from_action,
            require_review_binding,
        )

        _require_digest("completion_record_id", completion_record_id)
        if disposition not in {
            "accept_component_parity",
            "continue_batch",
            "reject_component_parity",
            "stop_batch",
        }:
            raise TransitionError("Job evidence disposition is not typed")
        if negative_memory_id is not None:
            if not negative_memory_id.startswith("negative-memory:"):
                raise TransitionError("negative_memory_id is invalid")
            _require_digest(
                "negative_memory_id",
                negative_memory_id.removeprefix("negative-memory:"),
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science["active_job"] is not None or science["active_repair"] is not None:
                raise TransitionError("Job judgement requires a stable completion")
            next_action = body.get("next_action")
            completion = index.get("job-completed", completion_record_id)
            if (
                completion is None
                or next_action
                != {
                    "completion_record_id": completion_record_id,
                    "job_id": completion.payload.get("job_id"),
                    "kind": "judge_job_evidence",
                }
            ):
                raise TransitionError("Job judgement is not the exact next action")
            job_id = completion.payload["job_id"]
            declaration = index.get("job-declared", job_id)
            if (
                declaration is None
                or declaration.payload.get("mission_id")
                != science["active_mission"]
            ):
                raise TransitionError("Job judgement lacks Mission provenance")
            scientific = completion.payload.get("scientific")
            component_parity = completion.payload.get("component_parity")
            needs_negative_memory = (
                isinstance(scientific, dict)
                and scientific.get("verdict") == "failed"
                and scientific.get("scientific_eligible") is True
            )
            if needs_negative_memory:
                memory = (
                    None
                    if negative_memory_id is None
                    else index.get("negative-memory", negative_memory_id)
                )
                if (
                    memory is None
                    or completion_record_id
                    not in memory.payload.get("evidence_references", [])
                    or memory.subject
                    != f"Executable:{scientific.get('executable_id')}"
                ):
                    raise TransitionError(
                        "scientific falsification requires its exact negative memory"
                    )
            elif negative_memory_id is not None:
                raise TransitionError("Job judgement carries unrelated negative memory")
            parity_binding = declaration.payload.get("spec", {}).get(
                "component_parity_binding"
            )
            parity_disposition = disposition in {
                "accept_component_parity",
                "reject_component_parity",
            }
            parity_member_records: list[IndexRecord] = []
            parity_trigger_records: list[IndexRecord] = []
            if parity_disposition:
                if not isinstance(parity_binding, dict):
                    raise TransitionError(
                        "component parity disposition requires its typed Job binding"
                    )
                if disposition == "accept_component_parity" and (
                    completion.status != "success"
                    or not isinstance(component_parity, dict)
                    or component_parity.get("equivalent") is not True
                    or component_parity.get("verdict") != "passed"
                ):
                    raise TransitionError(
                        "Writer cannot accept component parity without validator equivalence"
                    )
                decision = self._active_portfolio_decision(
                    index,
                    parity_binding["portfolio_decision_id"],
                )
                if decision is None:
                    raise TransitionError(
                        "component parity disposition lost its Portfolio Decision"
                    )
                options = {
                    option["option_id"]: option
                    for option in decision.payload.get("options", [])
                    if isinstance(option, dict)
                }
                chosen = options.get(decision.payload.get("chosen_option_id"))
                if not isinstance(chosen, dict):
                    raise TransitionError(
                        "component parity Portfolio Decision is malformed"
                    )
                decision_architecture = decision.payload.get(
                    "architecture_chassis"
                )
                if not isinstance(decision_architecture, dict):
                    raise TransitionError(
                        "component parity Decision lacks its architecture chassis"
                    )
                extra_equivalences: tuple[Mapping[str, Any], ...] = ()
                if disposition == "accept_component_parity":
                    assert isinstance(component_parity, dict)
                    extra_equivalences = (
                        {
                            "canonical_component_id": component_parity.get(
                                "canonical_component_id"
                            ),
                            "canonical_component_manifest": component_parity.get(
                                "canonical_component_manifest"
                            ),
                            "completion_record_id": completion_record_id,
                            "dimensions": component_parity.get("dimensions"),
                            "equivalent_component_id": component_parity.get(
                                "equivalent_component_id"
                            ),
                            "equivalent_component_manifest": component_parity.get(
                                "equivalent_component_manifest"
                            ),
                            "parity_manifest_hash": component_parity.get(
                                "result_manifest_hash"
                            ),
                            "schema": "component_parity_evidence.v1",
                        },
                    )
                    parity_member_records = self._component_parity_member_records(
                        equivalence=extra_equivalences[0],
                        mission_id=science["active_mission"],
                        portfolio_decision_id=decision.record_id,
                    )
                resolved_family = self._resolved_architecture_family(
                    index=index,
                    architecture_payload=decision_architecture,
                    extra_equivalences=extra_equivalences,
                )
                execute_action = {
                    "action": chosen["action"],
                    "architecture_chassis_identity": parity_binding[
                        "architecture_chassis_identity"
                    ],
                    "baseline_executable_id": decision.payload[
                        "baseline_executable_id"
                    ],
                    "decision_id": decision.record_id,
                    "kind": "execute_portfolio_decision",
                    "portfolio_snapshot_id": parity_binding[
                        "portfolio_snapshot_id"
                    ],
                    "resolved_architecture_family": resolved_family,
                    "target_axis_identity": parity_binding[
                        "portfolio_axis_identity"
                    ],
                    "target_id": chosen["target_id"],
                }
                reroute_action: dict[str, Any] | None = None
                if disposition == "accept_component_parity":
                    review_id = decision.payload.get("architecture_review_id")
                    review = (
                        None
                        if not isinstance(review_id, str)
                        else index.get("architecture-review", review_id)
                    )
                    if isinstance(review_id, str) and review is None:
                        raise RecoveryRequired(
                            "component parity lost its architecture review"
                        )
                    if review is not None and review.payload.get(
                        "conclusion"
                    ) == "bounded_same_architecture":
                        stored_constraints = decision.payload.get(
                            "scheduler_constraints"
                        )
                        if not isinstance(stored_constraints, dict):
                            raise RecoveryRequired(
                                "bounded parity Decision lost its scheduler constraints"
                            )
                        candidate_action = {
                            "kind": "portfolio_decision",
                            "portfolio_snapshot_id": parity_binding[
                                "portfolio_snapshot_id"
                            ],
                            **{
                                name: stored_constraints[name]
                                for name in (
                                    *ARCHITECTURE_CONTINUATION_ACTION_FIELDS,
                                    "pending_replay_obligation_ids",
                                    "required_replay_priority",
                                )
                                if name in stored_constraints
                            },
                        }
                        try:
                            continuation = constraint_from_action(candidate_action)
                        except ArchitectureReviewDirectionError as exc:
                            raise RecoveryRequired(str(exc)) from exc
                        trigger = (
                            None
                            if continuation is None
                            else index.get(
                                "architecture-review-trigger",
                                continuation.trigger_record_id,
                            )
                        )
                        if continuation is None or trigger is None:
                            raise RecoveryRequired(
                                "bounded parity Decision lost its review trigger"
                            )
                        try:
                            require_review_binding(
                                continuation,
                                review_record_id=review.record_id,
                                review_payload=review.payload,
                                trigger_payload=trigger.payload,
                            )
                        except ArchitectureReviewDirectionError as exc:
                            raise RecoveryRequired(str(exc)) from exc
                        reviewed_family = self._review_resolved_architecture_family(
                            index=index,
                            review=review,
                            extra_equivalences=extra_equivalences,
                        )
                        if (
                            resolved_family
                            != continuation.required_architecture_family
                            or reviewed_family
                            != continuation.required_architecture_family
                        ):
                            reroute_action = candidate_action
                    elif review is not None and review.payload.get(
                        "conclusion"
                    ) == "rotate_architecture":
                        reviewed_family = self._review_resolved_architecture_family(
                            index=index,
                            review=review,
                            extra_equivalences=extra_equivalences,
                        )
                        if resolved_family == reviewed_family:
                            reroute_action = {
                                "architecture_review_id": review.record_id,
                                "excluded_architecture_family": reviewed_family,
                                "kind": "portfolio_decision",
                                "portfolio_snapshot_id": parity_binding[
                                    "portfolio_snapshot_id"
                                ],
                            }
                    diagnosis_id = decision.payload.get("study_diagnosis_id")
                    diagnosis = (
                        None
                        if not isinstance(diagnosis_id, str)
                        else index.get("study-diagnosis", diagnosis_id)
                    )
                    if reroute_action is None and diagnosis is not None:
                        snapshot = index.get(
                            "portfolio-snapshot",
                            parity_binding["portfolio_snapshot_id"],
                        )
                        if snapshot is None:
                            raise RecoveryRequired(
                                "component parity lost its Portfolio snapshot"
                            )
                        axes = {
                            axis["axis_id"]: axis
                            for axis in snapshot.payload.get("axes", [])
                            if isinstance(axis, dict)
                            and isinstance(axis.get("axis_id"), str)
                        }
                        target_axis = axes.get(chosen["target_id"])
                        source_axis = axes.get(
                            diagnosis.payload.get("portfolio_axis_id")
                        )
                        if target_axis is None or source_axis is None:
                            raise RecoveryRequired(
                                "component parity diagnosis axes are unavailable"
                            )
                        allowed_actions = set(
                            diagnosis.payload.get("allowed_actions", [])
                        )
                        allowed_layers = set(
                            diagnosis.payload.get("allowed_research_layers", [])
                        )
                        chosen_action = chosen["action"]
                        branch_match = (
                            chosen_action not in {"preserve", "prune"}
                            and chosen_action in allowed_actions
                            and (
                                target_axis["primary_research_layer"]
                                in allowed_layers
                                or chosen_action == "new_mechanism"
                            )
                        )
                        source_study_id = diagnosis.payload.get("study_id")
                        source_study = (
                            None
                            if not isinstance(source_study_id, str)
                            else index.get("study-open", source_study_id)
                        )
                        if source_study is None:
                            raise RecoveryRequired(
                                "component parity diagnosis Study is unavailable"
                            )
                        controlled = source_study.payload.get(
                            "controlled_chassis"
                        )
                        source_architecture = (
                            None
                            if not isinstance(controlled, dict)
                            else controlled.get("architecture")
                        )
                        source_family = (
                            self._resolved_architecture_family(
                                index=index,
                                architecture_payload=source_architecture,
                                extra_equivalences=extra_equivalences,
                            )
                            if isinstance(source_architecture, dict)
                            else source_study.payload.get(
                                "system_architecture_family"
                            )
                        )
                        forest_diversion = (
                            chosen["target_id"]
                            != diagnosis.payload.get("portfolio_axis_id")
                            and chosen_action
                            in {
                                "complementary_sleeve",
                                "contrast",
                                "recombine",
                                "rotate",
                                "synthesize",
                            }
                            and (
                                target_axis["primary_research_layer"]
                                != source_axis["primary_research_layer"]
                                or resolved_family != source_family
                            )
                        )
                        if not (branch_match or forest_diversion):
                            reroute_action = {
                                "kind": "portfolio_decision",
                                "portfolio_snapshot_id": parity_binding[
                                    "portfolio_snapshot_id"
                                ],
                                "study_diagnosis_id": diagnosis.record_id,
                            }
                    trigger = self._pending_architecture_review_trigger(
                        index=index,
                        mission_id=science["active_mission"],
                        portfolio_snapshot_id=parity_binding[
                            "portfolio_snapshot_id"
                        ],
                        architecture_family=resolved_family,
                        extra_equivalences=extra_equivalences,
                    )
                    if trigger is not None:
                        parity_trigger_records = [trigger]
                        reroute_action = {
                            "kind": "review_architecture",
                            "trigger_record_id": trigger.record_id,
                        }
                body["next_action"] = (
                    execute_action if reroute_action is None else reroute_action
                )
            batch = science.get("active_batch")
            declared_batch_id = declaration.payload.get("batch_id")
            if not parity_disposition:
                if (
                    not isinstance(batch, dict)
                    or declared_batch_id != batch.get("id")
                ):
                    raise TransitionError("Job judgement is outside the active Batch")
                if disposition == "stop_batch" and not self.engineering_fixture:
                    study_id = science.get("active_study")
                    if not isinstance(study_id, str):
                        raise TransitionError(
                            "Real Batch stop requires its active Study"
                        )
                    self._study_kpi_from_completion(
                        index=index,
                        study_id=study_id,
                        completion_record_id=completion_record_id,
                        require_stop_decision=False,
                    )
                body["next_action"] = (
                    {"kind": "declare_job", "batch_id": batch["id"]}
                    if disposition == "continue_batch"
                    else {"kind": "dispose_batch", "batch_id": batch["id"]}
                )
            record_id = canonical_digest(
                domain="job-evidence-decision",
                payload={
                    "completion_record_id": completion_record_id,
                    "disposition": disposition,
                    "negative_memory_id": negative_memory_id,
                },
            )
            record = _record(
                kind="job-evidence-decision",
                record_id=record_id,
                subject=f"Job:{job_id}",
                status=disposition,
                fingerprint=completion.fingerprint,
                payload={
                    "completion_record_id": completion_record_id,
                    "negative_memory_id": negative_memory_id,
                },
            )
            return body, [
                record,
                *parity_member_records,
                *parity_trigger_records,
            ], {
                "disposition": disposition,
                "job_id": job_id,
            }

        return self._commit(
            event_kind="job_evidence_judged",
            operation_id=operation_id,
            subject="Job:completed",
            payload={
                "completion_record_id": completion_record_id,
                "disposition": disposition,
                "negative_memory_id": negative_memory_id,
            },
            prepare=prepare,
        )

    def judge_external_dependency_evidence(
        self,
        *,
        completion_record_id: str,
        operation_id: str,
    ) -> TransitionResult:
        """Consume one Mission-scoped external recovery result exactly once."""

        _require_digest("completion_record_id", completion_record_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science.get("active_job") is not None or science.get(
                "active_repair"
            ) is not None:
                raise TransitionError(
                    "external Job judgement requires a stable completion"
                )
            completion = index.get("job-completed", completion_record_id)
            next_action = body.get("next_action")
            if (
                completion is None
                or next_action
                != {
                    "completion_record_id": completion_record_id,
                    "job_id": completion.payload.get("job_id"),
                    "kind": "judge_external_dependency_evidence",
                }
            ):
                raise TransitionError(
                    "external Job judgement is not the exact next action"
                )
            job_id = completion.payload.get("job_id")
            declaration = (
                None
                if not isinstance(job_id, str)
                else index.get("job-declared", job_id)
            )
            binding = (
                None
                if declaration is None
                else declaration.payload.get("spec", {}).get(
                    "external_dependency_binding"
                )
            )
            if (
                declaration is None
                or declaration.payload.get("mission_id")
                != science.get("active_mission")
                or not isinstance(binding, dict)
            ):
                raise TransitionError(
                    "external Job judgement lacks exact Mission provenance"
                )
            try:
                plan = external_plan_from_binding(binding)
                path = plan.path(binding["recovery_path_id"])
            except ExternalDependencyContractError as exc:
                raise TransitionError(str(exc)) from exc
            plan_record = index.get("external-recovery-plan", plan.identity)
            if (
                plan_record is None
                or plan_record.status != "active"
                or plan_record.subject != f"Mission:{science['active_mission']}"
                or plan_record.payload != plan.to_identity_payload()
            ):
                raise RecoveryRequired(
                    "external Job judgement lost its frozen recovery plan"
                )
            attempt_id = canonical_digest(
                domain="external-dependency-attempt",
                payload={
                    "completion_record_id": completion_record_id,
                    "dependency_id": plan.condition.dependency_id,
                    "recovery_path_id": path.recovery_path_id,
                },
            )
            attempt = index.get("external-dependency-attempt", attempt_id)
            external = completion.payload.get("external")
            engineering = completion.payload.get("engineering_disposition")
            failure = completion.payload.get("failure")
            if (
                external is None
                and completion.status == "failed"
                and attempt is not None
                and attempt.status == "local_failure"
                and isinstance(engineering, Mapping)
                and engineering.get("schema")
                == "engineering_failure_disposition.v1"
                and isinstance(failure, Mapping)
                and failure.get("failure_kind") == "engineering"
            ):
                body["next_action"] = (
                    plan.condition.resume_action.to_next_action()
                )
                gap_payload = {
                    "completion_record_id": completion_record_id,
                    "disposition": "restore_local_engineering_failure",
                    "recovery_path_id": path.recovery_path_id,
                    "recovery_plan_id": plan.identity,
                    "scientific_failure_delta": 0,
                    "scientific_trial_delta": 0,
                }
                gap_id = canonical_digest(
                    domain="external-dependency-operational-gap",
                    payload=gap_payload,
                )
                gap_stream = (
                    f"external-operational-gap:{plan.identity}:"
                    f"{path.recovery_path_id}"
                )
                gap_head = index.event_head(gap_stream)
                gap = _record(
                    kind="external-dependency-operational-gap",
                    record_id=gap_id,
                    subject=f"Job:{job_id}",
                    status="engineering_gap",
                    fingerprint=completion.fingerprint,
                    payload=gap_payload,
                    event_stream=gap_stream,
                    event_sequence=(
                        1 if gap_head is None else gap_head.sequence + 1
                    ),
                )
                return body, [gap], {
                    "completion_record_id": completion_record_id,
                    "disposition": "restore_local_engineering_failure",
                    "recovery_plan_id": plan.identity,
                    "verdict": "engineering_gap",
                }
            if (
                attempt is None
                or attempt.payload.get("completion_record_id")
                != completion_record_id
                or not isinstance(external, dict)
            ):
                raise TransitionError(
                    "external Job judgement lacks its validator-derived attempt"
                )
            verdict = external.get("verdict")
            expected = {
                "failed": ("failed", "external_unavailable"),
                "not_evaluable": ("not_evaluable", "external_unresolved"),
                "passed": ("success", "available"),
            }
            if verdict not in expected or (
                completion.status,
                attempt.status,
            ) != expected[verdict]:
                raise TransitionError(
                    "external Job outcome differs from its validator verdict"
                )
            stream = f"external-recovery:{plan.identity}"
            decision_head = index.event_head(stream)
            decision_count = 0 if decision_head is None else decision_head.sequence
            if decision_count >= len(plan.paths) or plan.paths[decision_count] != path:
                raise TransitionError(
                    "external recovery result is outside the next frozen path"
                )
            prior_completion_ids: list[str] = []
            for sequence in range(1, decision_count + 1):
                prior = index.event_record(stream, sequence)
                if (
                    prior is None
                    or prior.kind != "external-dependency-judgement"
                    or prior.status != "failed"
                ):
                    raise RecoveryRequired(
                        "external recovery decision history is malformed"
                    )
                prior_completion = prior.payload.get("completion_record_id")
                if not isinstance(prior_completion, str):
                    raise RecoveryRequired(
                        "external recovery decision lost its completion"
                    )
                prior_completion_ids.append(prior_completion)
            all_completion_ids = [*prior_completion_ids, completion_record_id]
            blocker_credit = (
                verdict == "failed"
                and external.get("indispensable_to_mission_terminal") is True
                and external.get("contract_valid_next_action_found") is False
                and external.get("safe_substitute_found") is False
            )
            if verdict == "passed":
                body["next_action"] = plan.condition.resume_action.to_next_action()
                disposition = "resume_mission_action"
            elif verdict == "not_evaluable":
                body["next_action"] = plan.condition.resume_action.to_next_action()
                disposition = "restore_without_blocker_credit"
            elif not blocker_credit:
                body["next_action"] = plan.condition.resume_action.to_next_action()
                disposition = "restore_non_blocking_external_failure"
            elif decision_count + 1 < len(plan.paths):
                next_path = plan.paths[decision_count + 1]
                body["next_action"] = {
                    "kind": "declare_external_dependency_job",
                    "prior_completion_record_ids": all_completion_ids,
                    "recovery_path_id": next_path.recovery_path_id,
                    "recovery_plan_id": plan.identity,
                }
                disposition = "continue_external_recovery"
            else:
                body["next_action"] = {
                    "completion_record_ids": all_completion_ids,
                    "dependency_id": plan.condition.dependency_id,
                    "kind": "record_external_blocker",
                    "recovery_plan_id": plan.identity,
                }
                disposition = "record_external_blocker"
            decision_payload = {
                "blocker_credit": blocker_credit,
                "completion_record_id": completion_record_id,
                "disposition": disposition,
                "recovery_path_id": path.recovery_path_id,
                "recovery_plan_id": plan.identity,
                "verdict": verdict,
            }
            decision_id = canonical_digest(
                domain="external-dependency-judgement",
                payload=decision_payload,
            )
            record = _record(
                kind="external-dependency-judgement",
                record_id=decision_id,
                subject=f"Job:{job_id}",
                status=verdict,
                fingerprint=completion.fingerprint,
                payload=decision_payload,
                event_stream=stream,
                event_sequence=decision_count + 1,
            )
            return body, [record], {
                "completion_record_id": completion_record_id,
                "disposition": disposition,
                "recovery_plan_id": plan.identity,
                "verdict": verdict,
            }

        return self._commit(
            event_kind="external_dependency_evidence_judged",
            operation_id=operation_id,
            subject="Job:completed",
            payload={"completion_record_id": completion_record_id},
            prepare=prepare,
        )

    def _engineering_failure_cause(
        self,
        failure: Mapping[str, Any],
    ) -> tuple[dict[str, Any], str]:
        failure_manifest = _require_manifest(
            "repair failure",
            failure,
            required={
                "failure_kind",
                "minimum_reproduction_evidence",
                "root_cause",
                "interrupted_action",
            },
        )
        if set(failure_manifest) != {
            "failure_kind",
            "minimum_reproduction_evidence",
            "root_cause",
            "interrupted_action",
        } or failure_manifest.get("failure_kind") != "engineering":
            raise TransitionError(
                "Repair requires one exact engineering failure manifest"
            )
        for name in ("root_cause", "interrupted_action"):
            _require_ascii(name, failure_manifest[name])
        references = failure_manifest["minimum_reproduction_evidence"]
        if (
            not isinstance(references, list)
            or not references
            or references != sorted(set(references))
        ):
            raise TransitionError(
                "Repair requires sorted unique minimum reproduction evidence"
            )
        for reference in references:
            self.evidence.verify(reference)
        cause_hash = _digest(failure_manifest, domain="repair-cause")
        return failure_manifest, cause_hash

    def open_repair(
        self,
        *,
        permit: Permit,
        failure: Mapping[str, Any],
        operation_id: str,
    ) -> TransitionResult:
        failure_manifest, cause_hash = self._engineering_failure_cause(
            failure
        )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            job = science["active_job"]
            if not isinstance(job, dict) or job["status"] != "running":
                raise TransitionError("Repair requires a running Job")
            if science["active_repair"] is not None:
                raise TransitionError("another Repair is active")
            if job.get("required_repair_resume_record_id") is not None:
                raise TransitionError(
                    "a repaired Job must re-enter its engine before another Repair"
                )
            declaration = index.get("job-declared", job["id"])
            if declaration is None:
                raise TransitionError("interrupted Job declaration is absent")
            job_spec = declaration.payload["spec"]
            if failure_manifest["interrupted_action"] != job_spec["callable_identity"]:
                raise TransitionError("Repair interrupted action differs from the Job")
            resume_action = job_spec["resume_action"]
            self._validate_permit_locked(
                control=current,
                index=index,
                permit=permit,
                expected_kind=PermitKind.REPAIR,
                action="open_repair",
                subject_kind=SubjectKind.JOB,
                subject_id=job["id"],
                expected_input_hash=job["hash"],
            )
            repair_stream = f"job-repair:{job['id']}"
            predecessor_head = index.event_head(repair_stream)
            predecessor = (
                None
                if predecessor_head is None
                else index.get(
                    predecessor_head.record_kind,
                    predecessor_head.record_id,
                )
            )
            if predecessor_head is not None and (
                predecessor is None
                or predecessor.kind != "repair-close"
                or predecessor.status != "repaired"
                or predecessor.subject != f"Job:{job['id']}"
            ):
                raise RecoveryRequired(
                    "running Job Repair predecessor is invalid"
                )
            repair_episode = (
                1
                if predecessor_head is None
                else predecessor_head.sequence + 1
            )
            predecessor_id = (
                None if predecessor is None else predecessor.record_id
            )
            repair_id = (
                "repair:"
                + canonical_digest(
                    domain="repair",
                    payload={
                        "cause_hash": cause_hash,
                        "episode": repair_episode,
                        "job_id": job["id"],
                        "predecessor_repair_close_record_id": predecessor_id,
                    },
                )
            )
            job["status"] = "interrupted_repair"
            science["active_repair"] = {
                "id": repair_id,
                "job_id": job["id"],
                "cause_hash": cause_hash,
                "episode": repair_episode,
                "latest_attempt_record_id": None,
                "latest_basis_hash": cause_hash,
                "predecessor_repair_close_record_id": predecessor_id,
                "resume_action": resume_action,
            }
            body["next_action"] = {"kind": "execute_repair", "repair_id": repair_id}
            consumption = self._permit_consumption_record(permit, operation_id)
            record = _record(
                kind="repair-open",
                record_id=repair_id,
                subject=f"Job:{job['id']}",
                status="open",
                fingerprint=cause_hash,
                payload={
                    **failure_manifest,
                    "episode": repair_episode,
                    "predecessor_repair_close_record_id": predecessor_id,
                    "resume_action": resume_action,
                    "scientific_trial_delta": 0,
                },
            )
            return body, [consumption, record], {"repair_id": repair_id}

        return self._commit(
            event_kind="repair_opened",
            operation_id=operation_id,
            subject=f"Job:{permit.subject.subject_id}",
            payload={"cause_hash": cause_hash, "failure": failure_manifest},
            prepare=prepare,
        )

    def _repair_attempt_context(
        self,
        index: LocalIndex,
        *,
        repair: Mapping[str, Any],
        job: Mapping[str, Any],
    ) -> tuple[IndexRecord, IndexRecord | None, str | None, str, int]:
        repair_id = repair.get("id")
        if not isinstance(repair_id, str):
            raise TransitionError("active Repair identity is invalid")
        opened = index.get("repair-open", repair_id)
        if (
            opened is None
            or opened.status != "open"
            or opened.subject != f"Job:{job.get('id')}"
            or opened.fingerprint != repair.get("cause_hash")
            or opened.payload.get("episode") != repair.get("episode")
            or opened.payload.get("failure_kind") != "engineering"
            or opened.payload.get(
                "predecessor_repair_close_record_id"
            )
            != repair.get("predecessor_repair_close_record_id")
            or opened.payload.get("resume_action")
            != repair.get("resume_action")
        ):
            raise TransitionError("Repair cause record is absent")
        stream = f"repair-attempt:{repair_id}"
        head = index.event_head(stream)
        prior = (
            None
            if head is None
            else index.get(head.record_kind, head.record_id)
        )
        if prior is None:
            prior_record_id = None
            previous_basis = repair.get("cause_hash")
            sequence = 1
        else:
            if (
                prior.kind != "repair-attempt"
                or prior.status != "failed"
                or prior.subject != f"Repair:{repair_id}"
                or prior.payload.get("job_id") != job.get("id")
                or prior.payload.get("repair_id") != repair_id
            ):
                raise RecoveryRequired("Repair attempt head is invalid")
            prior_record_id = prior.record_id
            previous_basis = prior.payload.get("new_basis_hash")
            sequence = head.sequence + 1
        if not isinstance(previous_basis, str):
            raise RecoveryRequired("Repair attempt basis is unavailable")
        if (
            repair.get("latest_attempt_record_id") != prior_record_id
            or repair.get("latest_basis_hash") != previous_basis
        ):
            raise RecoveryRequired("active Repair trails its attempt stream")
        return opened, prior, prior_record_id, previous_basis, sequence

    def _parse_active_repair_attempt(
        self,
        *,
        proof_hash: str,
        expected_outcome: str,
        repair: Mapping[str, Any],
        job: Mapping[str, Any],
        opened: IndexRecord,
        prior_record_id: str | None,
        previous_basis: str,
    ) -> RepairAttemptProof:
        try:
            content = self.evidence.read_verified(proof_hash)
            return parse_repair_attempt_proof(
                content,
                expected_outcome=expected_outcome,
                repair_id=str(repair["id"]),
                job_id=str(job["id"]),
                job_hash=str(job["hash"]),
                cause_hash=str(repair["cause_hash"]),
                resume_action=str(repair["resume_action"]),
                reproduction_evidence_hashes=opened.payload[
                    "minimum_reproduction_evidence"
                ],
                prior_attempt_record_id=prior_record_id,
                previous_basis_hash=previous_basis,
                read_evidence=self.evidence.read_verified,
                verify_evidence=self.evidence.verify,
            )
        except (
            FileNotFoundError,
            OSError,
            RepairProtocolError,
            RuntimeError,
            TypeError,
            ValueError,
        ) as exc:
            raise TransitionError(str(exc)) from exc

    def record_failed_repair_attempt(
        self,
        *,
        attempt_proof_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Preserve one failed changed-basis attempt without abandoning Repair."""

        _require_digest("Repair attempt proof", attempt_proof_hash)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            repair = science.get("active_repair")
            job = science.get("active_job")
            if not isinstance(repair, dict) or not isinstance(job, dict):
                raise TransitionError("failed attempt requires an active Repair")
            if (
                job.get("status") != "interrupted_repair"
                or repair.get("job_id") != job.get("id")
            ):
                raise TransitionError("Repair and interrupted Job diverge")
            (
                opened,
                _prior,
                prior_record_id,
                previous_basis,
                sequence,
            ) = self._repair_attempt_context(index, repair=repair, job=job)
            proof = self._parse_active_repair_attempt(
                proof_hash=attempt_proof_hash,
                expected_outcome="failed",
                repair=repair,
                job=job,
                opened=opened,
                prior_record_id=prior_record_id,
                previous_basis=previous_basis,
            )
            record_id = canonical_digest(
                domain="repair-attempt",
                payload={
                    "attempt_proof_hash": attempt_proof_hash,
                    **proof.payload(),
                },
            )
            record = _record(
                kind="repair-attempt",
                record_id=record_id,
                subject=f"Repair:{repair['id']}",
                status="failed",
                fingerprint=attempt_proof_hash,
                payload={
                    "attempt_proof_hash": attempt_proof_hash,
                    **proof.payload(),
                    "scientific_failure_delta": 0,
                    "scientific_trial_delta": 0,
                },
                event_stream=f"repair-attempt:{repair['id']}",
                event_sequence=sequence,
            )
            repair["latest_attempt_record_id"] = record_id
            repair["latest_basis_hash"] = proof.new_basis_hash
            body["next_action"] = {
                "kind": "execute_repair",
                "repair_id": repair["id"],
                "prior_attempt_record_id": record_id,
                "required_previous_basis_hash": proof.new_basis_hash,
            }
            return body, [record], {
                "attempt_record_id": record_id,
                "job_id": job["id"],
                "repair_id": repair["id"],
            }

        return self._commit(
            event_kind="repair_attempt_failed",
            operation_id=operation_id,
            subject="Repair:active",
            payload={"attempt_proof_hash": attempt_proof_hash},
            prepare=prepare,
        )

    def _engineering_failure_disposition(
        self,
        index: LocalIndex,
        *,
        disposition_hash: str,
        job_id: str,
        job_hash: str,
        repair_id: str | None,
        cause_hash: str,
        reproduction_evidence_hashes: Sequence[str],
    ) -> EngineeringFailureDisposition:
        failed_records = (
            ()
            if repair_id is None
            else tuple(
                sorted(
                    (
                        record
                        for record in index.records_by_subject_status(
                            f"Repair:{repair_id}", "failed"
                        )
                        if record.kind == "repair-attempt"
                        and record.payload.get("repair_id") == repair_id
                    ),
                    key=lambda record: record.record_id,
                )
            )
        )
        repair_attempts = tuple(
            {
                "attempt_proof_hash": record.payload.get(
                    "attempt_proof_hash"
                ),
                "changed_dimension": record.payload.get(
                    "changed_dimension"
                ),
                "new_basis_hash": record.payload.get("new_basis_hash"),
                "repair_attempt_record_id": record.record_id,
                "verification_receipt_hashes": record.payload.get(
                    "verification_evidence_hashes"
                ),
            }
            for record in failed_records
        )
        try:
            disposition = parse_engineering_failure_disposition(
                self.evidence.read_verified(disposition_hash),
                job_id=job_id,
                job_hash=job_hash,
                repair_id=repair_id,
                cause_hash=cause_hash,
                reproduction_evidence_hashes=reproduction_evidence_hashes,
                repair_attempts=repair_attempts,
                read_evidence=self.evidence.read_verified,
                verify_evidence=self.evidence.verify,
            )
        except (
            FileNotFoundError,
            OSError,
            RepairProtocolError,
            RuntimeError,
            TypeError,
            ValueError,
        ) as exc:
            raise TransitionError(str(exc)) from exc
        failed_attempts = tuple(record.record_id for record in failed_records)
        if disposition.repair_attempt_record_ids != failed_attempts:
            raise TransitionError(
                "engineering disposition omits or invents failed Repair attempts"
            )
        if (
            disposition.disposition == "repair_exhausted_changed_causes"
            and (repair_id is None or len(failed_attempts) < 2)
        ):
            raise TransitionError(
                "one failed Repair attempt cannot establish changed-cause exhaustion"
            )
        return disposition

    def record_engineering_failure_disposition(
        self,
        *,
        failure: Mapping[str, Any],
        disposition_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Authorize direct Job failure only through a durable typed decision."""

        _require_digest("engineering disposition", disposition_hash)
        failure_manifest, cause_hash = self._engineering_failure_cause(
            failure
        )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            job = science.get("active_job")
            if (
                not isinstance(job, dict)
                or job.get("status") != "running"
                or science.get("active_repair") is not None
            ):
                raise TransitionError(
                    "engineering disposition requires one running unrepaired Job"
                )
            if job.get("required_repair_resume_record_id") is not None:
                raise TransitionError(
                    "a repaired Job must re-enter its engine before disposition"
                )
            declaration = index.get("job-declared", job["id"])
            spec = (
                None
                if declaration is None
                else declaration.payload.get("spec")
            )
            if (
                not isinstance(spec, Mapping)
                or failure_manifest["interrupted_action"]
                != spec.get("callable_identity")
            ):
                raise TransitionError(
                    "engineering disposition differs from the active Job"
                )
            disposition = self._engineering_failure_disposition(
                index,
                disposition_hash=disposition_hash,
                job_id=job["id"],
                job_hash=job["hash"],
                repair_id=None,
                cause_hash=cause_hash,
                reproduction_evidence_hashes=failure_manifest[
                    "minimum_reproduction_evidence"
                ],
            )
            record_id = canonical_digest(
                domain="engineering-failure-disposition",
                payload={
                    "cause_hash": cause_hash,
                    "disposition_hash": disposition_hash,
                    "job_id": job["id"],
                    "repair_id": None,
                },
            )
            record = _record(
                kind="engineering-failure-disposition",
                record_id=record_id,
                subject=f"Job:{job['id']}",
                status=disposition.disposition,
                fingerprint=disposition_hash,
                payload={
                    "cause": failure_manifest,
                    "cause_hash": cause_hash,
                    "disposition": disposition.payload(),
                    "disposition_hash": disposition_hash,
                    "job_id": job["id"],
                    "repair_id": None,
                    "scientific_failure_delta": 0,
                    "scientific_trial_delta": 0,
                },
            )
            job["required_engineering_disposition_hash"] = disposition_hash
            job["required_engineering_failure_cause_hash"] = cause_hash
            job["required_engineering_repair_id"] = None
            body["next_action"] = {
                "disposition_hash": disposition_hash,
                "job_id": job["id"],
                "kind": "complete_engineering_failure",
            }
            return body, [record], {
                "cause_hash": cause_hash,
                "disposition_hash": disposition_hash,
                "disposition_record_id": record_id,
                "job_id": job["id"],
                "repair_id": None,
            }

        return self._commit(
            event_kind="engineering_failure_disposition_recorded",
            operation_id=operation_id,
            subject="Job:active",
            payload={
                "cause_hash": cause_hash,
                "disposition_hash": disposition_hash,
                "failure": failure_manifest,
            },
            prepare=prepare,
        )

    def conclude_repair_unrecovered(
        self,
        *,
        disposition_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """End Repair only on a typed infeasibility, value, exhaustion, or scope basis."""

        _require_digest("engineering disposition", disposition_hash)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            repair = science.get("active_repair")
            job = science.get("active_job")
            if not isinstance(repair, dict) or not isinstance(job, dict):
                raise TransitionError("unrecovered conclusion requires active Repair")
            if (
                job.get("status") != "interrupted_repair"
                or repair.get("job_id") != job.get("id")
            ):
                raise TransitionError("Repair and interrupted Job diverge")
            opened, _prior, _prior_id, _basis, _sequence = (
                self._repair_attempt_context(index, repair=repair, job=job)
            )
            disposition = self._engineering_failure_disposition(
                index,
                disposition_hash=disposition_hash,
                job_id=job["id"],
                job_hash=job["hash"],
                repair_id=repair["id"],
                cause_hash=repair["cause_hash"],
                reproduction_evidence_hashes=opened.payload[
                    "minimum_reproduction_evidence"
                ],
            )
            stream = f"job-repair:{job['id']}"
            head = index.event_head(stream)
            record_id = canonical_digest(
                domain="repair-unrecovered",
                payload={
                    "disposition_hash": disposition_hash,
                    "repair_id": repair["id"],
                },
            )
            record = _record(
                kind="repair-close",
                record_id=record_id,
                subject=f"Job:{job['id']}",
                status="unrecovered",
                fingerprint=disposition_hash,
                payload={
                    "disposition": disposition.payload(),
                    "disposition_hash": disposition_hash,
                    "job_id": job["id"],
                    "repair_id": repair["id"],
                    "resume_action": repair["resume_action"],
                    "scientific_failure_delta": 0,
                    "scientific_trial_delta": 0,
                },
                event_stream=stream,
                event_sequence=(1 if head is None else head.sequence + 1),
            )
            science["active_repair"] = None
            job["status"] = "running"
            job["required_engineering_disposition_hash"] = disposition_hash
            job["required_engineering_failure_cause_hash"] = repair[
                "cause_hash"
            ]
            job["required_engineering_repair_id"] = repair["id"]
            body["next_action"] = {
                "disposition_hash": disposition_hash,
                "job_id": job["id"],
                "kind": "complete_engineering_failure",
            }
            return body, [record], {
                "disposition_hash": disposition_hash,
                "job_id": job["id"],
                "repair_id": repair["id"],
                "repair_close_record_id": record_id,
            }

        return self._commit(
            event_kind="repair_concluded_unrecovered",
            operation_id=operation_id,
            subject="Repair:active",
            payload={"disposition_hash": disposition_hash},
            prepare=prepare,
        )

    @staticmethod
    def _semantic_equivalence_repair_error(detail: object) -> TransitionError:
        return TransitionError(
            "in-place implementation Repair lacks fully passed registered "
            "semantic-equivalence; record a failed Repair attempt and preserve "
            "the requires_scientific_change disposition path: "
            f"{detail}"
        )

    def _implementation_repair_semantic_plan_locked(
        self,
        index: LocalIndex,
        *,
        repair: Mapping[str, Any],
        job: Mapping[str, Any],
        declaration: IndexRecord,
        spec: Mapping[str, Any],
        new_implementation_identity: str,
        validator_id: str,
    ) -> tuple[dict[str, Any], str]:
        """Rebuild the exact production Executable Repair plan from authority."""

        if validator_id == SEMANTIC_EQUIVALENCE_VALIDATOR_ID:
            validation_protocol = SEMANTIC_EQUIVALENCE_PROTOCOL
        else:
            fixed_validator_id = (
                _fixed_hold_authority_correction_validator_id()
            )
            if validator_id == fixed_validator_id:
                validation_protocol = FIXED_HOLD_AUTHORITY_CORRECTION_PROTOCOL
            else:
                raise self._semantic_equivalence_repair_error(
                    "validator does not implement the registered equivalence protocol"
                )
        try:
            self.validation_registry.require_registered_protocol(
                validator_id=validator_id,
                domain="scientific",
                protocol=validation_protocol,
            )
        except EvidenceValidationError as exc:
            raise self._semantic_equivalence_repair_error(exc) from exc
        subject = spec.get("evidence_subject")
        if (
            not isinstance(subject, Mapping)
            or subject.get("kind") != "Executable"
            or type(subject.get("id")) is not str
        ):
            raise self._semantic_equivalence_repair_error(
                "Repair is not bound to one exact Executable"
            )
        executable_id = str(subject["id"])
        trial = index.get("trial", executable_id)
        executable = None if trial is None else trial.payload.get("executable")
        if not isinstance(executable, Mapping):
            raise self._semantic_equivalence_repair_error(
                "Executable trial manifest is unavailable"
            )
        old_identity, _repair_record_id = (
            self._effective_running_job_implementation(
                index,
                job_id=str(job["id"]),
                declared_implementation_identity=str(
                    spec["implementation_identity"]
                ),
            )
        )
        old_manifest = self._require_job_implementation_evidence(
            {**dict(spec), "implementation_identity": old_identity},
            _index=index,
        )
        new_manifest = self._require_job_implementation_evidence(
            {
                **dict(spec),
                "implementation_identity": new_implementation_identity,
            },
            _index=index,
        )
        try:
            from axiom_rift.research.implementation_closure import (
                ImplementationClosureError,
                require_job_implementation_closure,
            )

            for manifest in (old_manifest, new_manifest):
                require_job_implementation_closure(
                    executable_manifest=executable,
                    job_artifact_hashes=manifest["artifact_hashes"],
                    artifact_reader=self.evidence.read_verified,
                )
            plan = build_semantic_equivalence_plan(
                validator_id=validator_id,
                validation_protocol=validation_protocol,
                repair_id=str(repair["id"]),
                job_id=str(job["id"]),
                job_hash=str(job["hash"]),
                executable_id=executable_id,
                job_spec=spec,
                executable_manifest=executable,
                old_implementation_identity=old_identity,
                old_implementation_manifest=old_manifest,
                new_implementation_identity=new_implementation_identity,
                new_implementation_manifest=new_manifest,
                artifact_reader=self.evidence.read_verified,
            )
        except (
            ImplementationClosureError,
            RepairSemanticEquivalenceError,
        ) as exc:
            raise self._semantic_equivalence_repair_error(exc) from exc
        return plan, old_identity

    def plan_implementation_repair_semantic_equivalence(
        self,
        *,
        new_implementation_identity: str,
        validator_id: str = SEMANTIC_EQUIVALENCE_VALIDATOR_ID,
    ) -> dict[str, Any]:
        """Return the exact read-only plan required for a production close."""

        _require_digest(
            "new implementation identity", new_implementation_identity
        )
        if self.engineering_fixture:
            raise TransitionError(
                "engineering fixtures do not acquire production semantic authority"
            )
        with WriterLock(self.lock_path):
            with self._open_authoritative_index() as index:
                current = self._require_stable_locked(index)
                assert current is not None
                science = current["scientific"]
                repair = science.get("active_repair")
                job = science.get("active_job")
                if not isinstance(repair, Mapping) or not isinstance(job, Mapping):
                    raise TransitionError(
                        "semantic-equivalence plan requires an active Repair"
                    )
                if (
                    job.get("status") != "interrupted_repair"
                    or repair.get("job_id") != job.get("id")
                ):
                    raise TransitionError("Repair and interrupted Job diverge")
                declaration = index.get("job-declared", str(job["id"]))
                spec = (
                    None
                    if declaration is None
                    else declaration.payload.get("spec")
                )
                if declaration is None or not isinstance(spec, Mapping):
                    raise TransitionError("Repair Job declaration is unavailable")
                plan, _old_identity = (
                    self._implementation_repair_semantic_plan_locked(
                        index,
                        repair=repair,
                        job=job,
                        declaration=declaration,
                        spec=spec,
                        new_implementation_identity=(
                            new_implementation_identity
                        ),
                        validator_id=validator_id,
                    )
                )
                return plan

    def plan_fixed_hold_authority_correction_repair(
        self,
        *,
        new_implementation_identity: str,
    ) -> dict[str, Any]:
        """Plan the exact protocol-specific fixed-hold in-place Repair."""

        return self.plan_implementation_repair_semantic_equivalence(
            new_implementation_identity=new_implementation_identity,
            validator_id=_fixed_hold_authority_correction_validator_id(),
        )

    def resolve_fixed_hold_authority_correction_verification(
        self,
        *,
        new_implementation_identity: str,
        evidence_hashes: tuple[str, ...],
    ) -> tuple[str, ...]:
        """Materialize or authenticate one recomputable engineering receipt."""

        from axiom_rift.operations.fixed_hold_repair_equivalence import (
            fixed_hold_authority_correction_verification_manifest,
            require_fixed_hold_authority_correction_verification,
        )
        fixed_validator_id = _fixed_hold_authority_correction_validator_id()

        _require_digest(
            "fixed-hold corrected implementation",
            new_implementation_identity,
        )
        self.validation_registry.require_registered_protocol(
            validator_id=fixed_validator_id,
            domain="scientific",
            protocol=FIXED_HOLD_AUTHORITY_CORRECTION_PROTOCOL,
        )
        if type(evidence_hashes) is not tuple:
            raise TransitionError(
                "fixed-hold correction verification hashes must be a tuple"
            )
        if evidence_hashes:
            if (
                len(evidence_hashes) != 1
                or evidence_hashes != tuple(sorted(set(evidence_hashes)))
            ):
                raise TransitionError(
                    "fixed-hold correction requires one exact verification"
                )
            evidence_hash = evidence_hashes[0]
            _require_digest(
                "fixed-hold correction verification",
                evidence_hash,
            )
            content = self.evidence.read_verified(evidence_hash)
        else:
            content = canonical_bytes(
                fixed_hold_authority_correction_verification_manifest(
                    new_implementation_identity=new_implementation_identity,
                )
            )
            evidence_hash = self.evidence.finalize(content).sha256
        try:
            require_fixed_hold_authority_correction_verification(
                content,
                new_implementation_identity=new_implementation_identity,
            )
        except EvidenceValidationError as exc:
            raise TransitionError(str(exc)) from exc
        return (evidence_hash,)

    def _run_implementation_repair_semantic_equivalence(
        self,
        *,
        plan: Mapping[str, Any],
        validation_plan_hash: str,
        result_manifest_hash: str,
        measurement_artifact_hashes: Sequence[str],
        mission_id: str,
        job_id: str,
        job_hash: str,
        executable_id: str,
    ) -> dict[str, Any]:
        """Dispatch exact Repair evidence through the immutable registry."""

        try:
            plan_artifact = parse_canonical(
                self.evidence.read_verified(validation_plan_hash)
            )
            if not isinstance(plan_artifact, Mapping) or dict(plan_artifact) != dict(
                plan
            ):
                raise RepairSemanticEquivalenceError(
                    "validation plan differs from Writer-derived authority"
                )
            result_manifest = parse_canonical(
                self.evidence.read_verified(result_manifest_hash)
            )
            if not isinstance(result_manifest, Mapping):
                raise RepairSemanticEquivalenceError(
                    "result manifest is not an object"
                )
            binding = build_semantic_equivalence_binding(
                plan=plan,
                validation_plan_hash=validation_plan_hash,
                result_manifest_hash=result_manifest_hash,
                measurement_artifact_hashes=measurement_artifact_hashes,
            )
            artifacts: list[ValidationArtifact] = []
            for ordinal, identity in enumerate(
                binding["declared_artifact_hashes"]
            ):
                artifacts.append(
                    ValidationArtifact(
                        output_name=f"repair-semantic-artifact-{ordinal:04d}",
                        sha256=identity,
                        _source=self.evidence.verified_path(identity),
                    )
                )
            request = EvidenceValidationRequest(
                domain="scientific",
                validator_id=str(binding["validator_id"]),
                validation_plan_hash=validation_plan_hash,
                job_id=job_id,
                job_hash=job_hash,
                mission_id=mission_id,
                evidence_subject={"kind": "Executable", "id": executable_id},
                binding=binding,
                result_manifest=result_manifest,
                artifacts=tuple(artifacts),
                engineering_fixture=False,
            )
            validated, trace = self.validation_registry.validate(request)
            facts = parse_canonical(canonical_bytes(dict(validated.facts)))
        except (
            EvidenceValidationError,
            FileNotFoundError,
            OSError,
            RepairSemanticEquivalenceError,
            RuntimeError,
            TypeError,
            ValueError,
        ) as exc:
            raise self._semantic_equivalence_repair_error(exc) from exc
        expected_claims = tuple(plan["claims"])
        expected_measurements = tuple(sorted(measurement_artifact_hashes))
        try:
            fixed_validator_id = (
                _fixed_hold_authority_correction_validator_id()
            )

            if (
                plan.get("validator_id") == SEMANTIC_EQUIVALENCE_VALIDATOR_ID
                and plan.get("protocol") == SEMANTIC_EQUIVALENCE_PROTOCOL
            ):
                require_passed_semantic_equivalence_facts(
                    binding=binding,
                    facts=facts,
                )
            elif (
                plan.get("validator_id")
                == fixed_validator_id
                and plan.get("protocol")
                == FIXED_HOLD_AUTHORITY_CORRECTION_PROTOCOL
            ):
                require_passed_fixed_hold_authority_correction_facts(
                    binding=binding,
                    facts=facts,
                )
            else:
                raise RepairSemanticEquivalenceError(
                    "implementation Repair validation protocol is unsupported"
                )
        except RepairSemanticEquivalenceError as exc:
            raise self._semantic_equivalence_repair_error(exc) from exc
        if (
            validated.verdict != "passed"
            or validated.claims != expected_claims
            or validated.measurement_artifact_hashes
            != expected_measurements
            or validated.scientific_eligible
            or validated.candidate_eligible
            or validated.release_eligible
            or trace.validator_id != plan["validator_id"]
            or trace.declared_artifact_count
            != len(binding["declared_artifact_hashes"])
            or trace.opened_artifact_count
            != trace.declared_artifact_count
        ):
            raise self._semantic_equivalence_repair_error(
                "validator verdict, coverage, claims, facts, or trace is partial"
            )
        return {
            "binding": binding,
            "claims": list(validated.claims),
            "facts": facts,
            "measurement_artifact_hashes": list(
                validated.measurement_artifact_hashes
            ),
            "registry_trace": {
                "declared_artifact_count": trace.declared_artifact_count,
                "opened_artifact_count": trace.opened_artifact_count,
                "validator_id": trace.validator_id,
            },
            "schema": (
                "implementation_repair_semantic_equivalence_validation.v1"
            ),
            "verdict": validated.verdict,
        }

    def close_repair(
        self,
        *,
        changed_cause_proof_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        _require_digest("changed_cause_proof_hash", changed_cause_proof_hash)

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            repair = science["active_repair"]
            job = science["active_job"]
            if not isinstance(repair, dict) or not isinstance(job, dict):
                raise TransitionError("no active Repair")
            if job["id"] != repair["job_id"] or job["status"] != "interrupted_repair":
                raise TransitionError("Repair and interrupted Job diverge")
            (
                opened,
                _prior,
                prior_attempt_record_id,
                previous_basis,
                attempt_sequence,
            ) = self._repair_attempt_context(
                _index,
                repair=repair,
                job=job,
            )
            proof = self._parse_active_repair_attempt(
                proof_hash=changed_cause_proof_hash,
                expected_outcome="repaired",
                repair=repair,
                job=job,
                opened=opened,
                prior_record_id=prior_attempt_record_id,
                previous_basis=previous_basis,
            )
            declaration = _index.get("job-declared", job["id"])
            spec = None if declaration is None else declaration.payload.get("spec")
            if not isinstance(spec, Mapping):
                raise TransitionError("Repair Job declaration is unavailable")
            prior_effective, _prior_repair_record_id = (
                self._effective_running_job_implementation(
                    _index,
                    job_id=job["id"],
                    declared_implementation_identity=spec[
                        "implementation_identity"
                    ],
                )
            )
            effective_implementation = prior_effective
            implementation_changed = False
            semantic_equivalence_validation: dict[str, Any] | None = None
            if proof.changed_dimension == "implementation":
                if proof.implementation_proof_hash is None:
                    raise TransitionError(
                        "implementation Repair omits its typed inner proof"
                    )
                try:
                    changed_manifest = parse_canonical(
                        self.evidence.read_verified(
                            proof.implementation_proof_hash
                        )
                    )
                except (OSError, TypeError, ValueError) as exc:
                    raise TransitionError(
                        "running Job implementation Repair proof is invalid"
                    ) from exc
                if not isinstance(changed_manifest, Mapping):
                    raise TransitionError(
                        "running Job implementation Repair proof is invalid"
                    )
                legacy_required = {
                    "changed_dimension",
                    "explanation",
                    "job_hash",
                    "job_id",
                    "new_evidence_hashes",
                    "new_implementation_identity",
                    "previous_implementation_identity",
                    "repair_id",
                    "reproduction_evidence_hashes",
                    "schema",
                }
                production_executable_repair = (
                    not self.engineering_fixture
                    and spec.get("evidence_subject", {}).get("kind")
                    == "Executable"
                )
                semantic_required = {
                    "semantic_equivalence_measurement_artifact_hashes",
                    "semantic_equivalence_result_manifest_hash",
                    "semantic_equivalence_validation_plan_hash",
                    "semantic_equivalence_validator_id",
                }
                required = (
                    legacy_required | semantic_required
                    if production_executable_repair
                    else legacy_required
                )
                new_evidence = changed_manifest.get("new_evidence_hashes")
                reproduction = changed_manifest.get(
                    "reproduction_evidence_hashes"
                )
                new_identity = changed_manifest.get(
                    "new_implementation_identity"
                )
                explanation = changed_manifest.get("explanation")
                if production_executable_repair and changed_manifest.get(
                    "schema"
                ) != IMPLEMENTATION_REPAIR_V2_SCHEMA:
                    raise self._semantic_equivalence_repair_error(
                        "production Executable implementation proof is not v2"
                    )
                if (
                    set(changed_manifest) != required
                    or (
                        not production_executable_repair
                        and changed_manifest.get("schema")
                        != "running_job_implementation_repair.v1"
                    )
                    or changed_manifest.get("changed_dimension")
                    != "implementation"
                    or changed_manifest.get("job_id") != job["id"]
                    or changed_manifest.get("job_hash") != job["hash"]
                    or changed_manifest.get("repair_id") != repair["id"]
                    or changed_manifest.get(
                        "previous_implementation_identity"
                    )
                    != prior_effective
                    or not isinstance(new_identity, str)
                    or new_identity == prior_effective
                    or type(explanation) is not str
                    or not explanation
                    or not explanation.isascii()
                    or not isinstance(new_evidence, list)
                    or not new_evidence
                    or new_evidence != sorted(set(new_evidence))
                    or not isinstance(reproduction, list)
                    or reproduction
                    != sorted(opened.payload["minimum_reproduction_evidence"])
                ):
                    raise TransitionError(
                        "running Job implementation Repair proof is invalid"
                    )
                _require_digest("repaired Job implementation", new_identity)
                if new_identity not in new_evidence:
                    raise TransitionError(
                        "running Job Repair omits its implementation manifest"
                    )
                if (
                    proof.new_basis_hash != new_identity
                    or list(proof.new_evidence_hashes)
                    != sorted(
                        {
                            proof.implementation_proof_hash,
                            *new_evidence,
                        }
                    )
                ):
                    raise TransitionError(
                        "implementation Repair attempt differs from its inner proof"
                    )
                for evidence_hash in new_evidence:
                    _require_digest("running Job Repair evidence", evidence_hash)
                    self.evidence.verify(evidence_hash)
                previous_manifest = self._require_job_implementation_evidence(
                    {
                        **dict(spec),
                        "implementation_identity": prior_effective,
                    },
                    _index=_index,
                )
                repaired_spec = {
                    **dict(spec),
                    "implementation_identity": new_identity,
                }
                repaired_manifest = self._require_job_implementation_evidence(
                    repaired_spec,
                    _index=_index,
                )
                if (
                    previous_manifest.get("protocol")
                    != repaired_manifest.get("protocol")
                    or any(
                        value not in new_evidence
                        for value in repaired_manifest["artifact_hashes"]
                    )
                ):
                    raise TransitionError(
                        "running Job Repair changes protocol or omits source bytes"
                    )
                if production_executable_repair:
                    from axiom_rift.research.implementation_closure import (
                        ImplementationClosureError,
                        require_job_implementation_closure,
                    )

                    subject = spec["evidence_subject"]["id"]
                    trial = _index.get("trial", subject)
                    executable = (
                        None
                        if trial is None
                        else trial.payload.get("executable")
                    )
                    if not isinstance(executable, dict):
                        raise TransitionError(
                            "running Job Repair lost its Executable trial"
                        )
                    try:
                        require_job_implementation_closure(
                            executable_manifest=executable,
                            job_artifact_hashes=repaired_manifest[
                                "artifact_hashes"
                            ],
                            artifact_reader=self.evidence.read_verified,
                        )
                    except ImplementationClosureError as exc:
                        raise TransitionError(str(exc)) from exc
                    validator_id = changed_manifest.get(
                        "semantic_equivalence_validator_id"
                    )
                    validation_plan_hash = changed_manifest.get(
                        "semantic_equivalence_validation_plan_hash"
                    )
                    result_manifest_hash = changed_manifest.get(
                        "semantic_equivalence_result_manifest_hash"
                    )
                    measurement_hashes = changed_manifest.get(
                        "semantic_equivalence_measurement_artifact_hashes"
                    )
                    try:
                        if type(validator_id) is not str:
                            raise RepairSemanticEquivalenceError(
                                "semantic-equivalence validator id is absent"
                            )
                        _require_digest(
                            "semantic-equivalence validation plan",
                            validation_plan_hash,
                        )
                        _require_digest(
                            "semantic-equivalence result manifest",
                            result_manifest_hash,
                        )
                        if (
                            not isinstance(measurement_hashes, list)
                            or measurement_hashes
                            != sorted(set(measurement_hashes))
                        ):
                            raise RepairSemanticEquivalenceError(
                                "semantic-equivalence measurement set is invalid"
                            )
                        for measurement_hash in measurement_hashes:
                            _require_digest(
                                "semantic-equivalence measurement",
                                measurement_hash,
                            )
                    except (
                        RepairSemanticEquivalenceError,
                        TransitionError,
                    ) as exc:
                        raise self._semantic_equivalence_repair_error(exc) from exc
                    expected_inner_evidence = sorted(
                        {
                            new_identity,
                            *repaired_manifest["artifact_hashes"],
                            validation_plan_hash,
                            result_manifest_hash,
                            *measurement_hashes,
                        }
                    )
                    if new_evidence != expected_inner_evidence:
                        raise self._semantic_equivalence_repair_error(
                            "implementation proof does not bind the exact plan, "
                            "result, measurement, manifest, and artifact set"
                        )
                    plan, planned_old_identity = (
                        self._implementation_repair_semantic_plan_locked(
                            _index,
                            repair=repair,
                            job=job,
                            declaration=declaration,
                            spec=spec,
                            new_implementation_identity=new_identity,
                            validator_id=validator_id,
                        )
                    )
                    if planned_old_identity != prior_effective:
                        raise self._semantic_equivalence_repair_error(
                            "old implementation identity changed during validation"
                        )
                    mission_id = declaration.payload.get("mission_id")
                    if type(mission_id) is not str:
                        raise self._semantic_equivalence_repair_error(
                            "Mission identity is unavailable"
                        )
                    semantic_equivalence_validation = (
                        self._run_implementation_repair_semantic_equivalence(
                            plan=plan,
                            validation_plan_hash=validation_plan_hash,
                            result_manifest_hash=result_manifest_hash,
                            measurement_artifact_hashes=measurement_hashes,
                            mission_id=mission_id,
                            job_id=job["id"],
                            job_hash=job["hash"],
                            executable_id=spec["evidence_subject"]["id"],
                        )
                    )
                effective_implementation = new_identity
                implementation_changed = True
            attempt_identity_payload = {
                "attempt_proof_hash": changed_cause_proof_hash,
                **proof.payload(),
            }
            if semantic_equivalence_validation is not None:
                attempt_identity_payload["semantic_equivalence_validation"] = (
                    semantic_equivalence_validation
                )
            attempt_record_id = canonical_digest(
                domain="repair-attempt",
                payload=attempt_identity_payload,
            )
            attempt_record = _record(
                kind="repair-attempt",
                record_id=attempt_record_id,
                subject=f"Repair:{repair['id']}",
                status="repaired",
                fingerprint=changed_cause_proof_hash,
                payload={
                    "attempt_proof_hash": changed_cause_proof_hash,
                    **proof.payload(),
                    **(
                        {
                            "semantic_equivalence_validation": (
                                semantic_equivalence_validation
                            )
                        }
                        if semantic_equivalence_validation is not None
                        else {}
                    ),
                    "scientific_failure_delta": 0,
                    "scientific_trial_delta": 0,
                },
                event_stream=f"repair-attempt:{repair['id']}",
                event_sequence=attempt_sequence,
            )
            science["active_repair"] = None
            job["status"] = "running"
            repair_stream = f"job-repair:{job['id']}"
            repair_head = _index.event_head(repair_stream)
            repair_close_identity_payload = {
                "repair_id": repair["id"],
                "proof": changed_cause_proof_hash,
            }
            if semantic_equivalence_validation is not None:
                repair_close_identity_payload[
                    "semantic_equivalence_validation"
                ] = semantic_equivalence_validation
            repair_close_id = canonical_digest(
                domain="repair-close",
                payload=repair_close_identity_payload,
            )
            job["required_repair_resume_record_id"] = repair_close_id
            body["next_action"] = {
                "job_id": job["id"],
                "kind": "resume_job",
                "repair_close_record_id": repair_close_id,
            }
            record = _record(
                kind="repair-close",
                record_id=repair_close_id,
                subject=f"Job:{job['id']}",
                status="repaired",
                fingerprint=changed_cause_proof_hash,
                payload={
                    "attempt_record_id": attempt_record_id,
                    "changed_dimension": proof.changed_dimension,
                    "resume_action": repair["resume_action"],
                    "changed_cause_proof_hash": changed_cause_proof_hash,
                    "effective_implementation_identity": (
                        effective_implementation
                    ),
                    "implementation_changed": implementation_changed,
                    "job_id": job["id"],
                    "previous_effective_implementation_identity": (
                        prior_effective
                    ),
                    "prior_attempt_record_id": prior_attempt_record_id,
                    "repair_id": repair["id"],
                    **(
                        {
                            "semantic_equivalence_validation": (
                                semantic_equivalence_validation
                            )
                        }
                        if semantic_equivalence_validation is not None
                        else {}
                    ),
                    "scientific_trial_delta": 0,
                    "scientific_failure_delta": 0,
                    "verification_evidence_hashes": list(
                        proof.verification_evidence_hashes
                    ),
                },
                event_stream=repair_stream,
                event_sequence=(
                    1 if repair_head is None else repair_head.sequence + 1
                ),
            )
            return body, [attempt_record, record], {
                "attempt_record_id": attempt_record_id,
                "effective_implementation_identity": (
                    effective_implementation
                ),
                "job_id": job["id"],
                "repair_id": repair["id"],
                "repair_close_record_id": repair_close_id,
                "resume_action": repair["resume_action"],
            }

        return self._commit(
            event_kind="repair_closed",
            operation_id=operation_id,
            subject="Repair:active",
            payload={"changed_cause_proof_hash": changed_cause_proof_hash},
            prepare=prepare,
        )

    def record_work_result(
        self,
        *,
        work: Mapping[str, Any],
        outcome: str,
        details: Mapping[str, Any],
        operation_id: str,
    ) -> TransitionResult:
        work_manifest = _require_manifest(
            "work",
            work,
            required={"callable_identity", "input_identity"},
        )
        work_fingerprint = _digest(work_manifest, domain="work-fingerprint")
        if outcome not in {"success", "failed"}:
            raise TransitionError("work outcome must be success or failed")
        if outcome == "failed" and (
            not isinstance(details, Mapping) or not isinstance(details.get("cause"), str)
        ):
            raise TransitionError("failed work requires a cause")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            if current["scientific"]["active_mission"] is None:
                raise TransitionError("work result requires an active Mission")
            existing = index.get("work-result", work_fingerprint)
            if existing is not None:
                if existing.status == "success":
                    return self._body(current), [], {"disposition": "reuse_success"}
                raise IdenticalFailedRetryError("identical failed work requires changed cause or input")
            record = _record(
                kind="work-result",
                record_id=work_fingerprint,
                subject="Work:fingerprint",
                status=outcome,
                fingerprint=work_fingerprint,
                payload=dict(details),
            )
            return self._body(current), [record], {"disposition": outcome}

        return self._commit(
            event_kind="work_result_recorded",
            operation_id=operation_id,
            subject="Work:fingerprint",
            payload={
                "work": work_manifest,
                "work_fingerprint": work_fingerprint,
                "outcome": outcome,
                "details": dict(details),
            },
            prepare=prepare,
        )

    def record_holdout_seal(
        self,
        *,
        manifest: Any,
        operation_id: str,
    ) -> TransitionResult:
        """Register sealed future data by semantic row/split identity without reading it."""

        from axiom_rift.runtime.guards import SealedHoldoutManifest

        if not isinstance(manifest, SealedHoldoutManifest):
            raise TransitionError("holdout seal requires SealedHoldoutManifest")
        artifact = self.evidence.verify(manifest.artifact_sha256)
        if artifact.size_bytes != manifest.size_bytes:
            raise TransitionError("holdout seal size differs from its artifact")
        starts_at = _parse_utc("holdout starts_at_utc", manifest.starts_at_utc)
        ends_at = _parse_utc("holdout ends_at_utc", manifest.ends_at_utc)
        if starts_at > ends_at:
            raise TransitionError("holdout time boundary is reversed")
        holdout_hash = manifest.identity.removeprefix("holdout:")
        _require_digest("holdout identity", holdout_hash)
        row_binding_id = canonical_digest(
            domain="holdout-row-binding", payload={"row_identity": manifest.row_identity}
        )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("Foundation is not initialized")
            if index.get("holdout-row-binding", row_binding_id) is not None:
                raise TransitionError(
                    "semantic holdout rows are already sealed under another operation"
                )
            chain_head = index.event_head("holdout-chain")
            chain_latest = (
                None
                if chain_head is None
                else index.get(chain_head.record_kind, chain_head.record_id)
            )
            if chain_head is None:
                if manifest.predecessor_holdout_id is not None:
                    raise TransitionError(
                        "first holdout cannot name a predecessor"
                    )
                try:
                    exposure = yaml.safe_load(
                        (self.foundation_root / "foundation" / "data_exposure.yaml").read_text(
                            encoding="ascii"
                        )
                    )
                    boundary_text = exposure["forward_holdout"]["starts_after"]
                    boundary = datetime.fromisoformat(boundary_text).replace(
                        tzinfo=timezone.utc
                    )
                except (OSError, UnicodeError, ValueError, TypeError, KeyError, yaml.YAMLError) as exc:
                    raise TransitionError(
                        "Foundation forward-holdout boundary is unavailable"
                    ) from exc
                if starts_at <= boundary:
                    raise TransitionError(
                        "first holdout is not strictly after the Foundation boundary"
                    )
            else:
                if (
                    chain_latest is None
                    or manifest.predecessor_holdout_id != chain_latest.record_id
                ):
                    raise TransitionError(
                        "new holdout must extend the single latest global chain"
                    )
                predecessor = index.get(
                    "holdout-seal", manifest.predecessor_holdout_id
                )
                if predecessor is None:
                    raise TransitionError("holdout predecessor seal is absent")
                reveal_head = index.event_head(
                    f"holdout-reveal:{manifest.predecessor_holdout_id}"
                )
                reveal_latest = (
                    None
                    if reveal_head is None
                    else index.get(reveal_head.record_kind, reveal_head.record_id)
                )
                if (
                    reveal_head is None
                    or reveal_head.sequence != 2
                    or reveal_latest is None
                    or reveal_latest.kind != "holdout-disposition"
                ):
                    raise TransitionError(
                        "new future holdout requires a disposed predecessor"
                    )
                predecessor_end = _parse_utc(
                    "predecessor ends_at_utc", predecessor.payload["ends_at_utc"]
                )
                if starts_at <= predecessor_end:
                    raise TransitionError(
                        "replacement holdout is not genuinely later future data"
                    )
            payload = {
                "artifact_sha256": manifest.artifact_sha256,
                "data_receipt_id": manifest.data_receipt_id,
                "ends_at_utc": manifest.ends_at_utc,
                "predecessor_holdout_id": manifest.predecessor_holdout_id,
                "row_identity": manifest.row_identity,
                "size_bytes": manifest.size_bytes,
                "split_identity": manifest.split_identity,
                "starts_at_utc": manifest.starts_at_utc,
                "value_exposed": False,
            }
            seal = _record(
                kind="holdout-seal",
                record_id=manifest.identity,
                subject=f"Data:{manifest.data_receipt_id}",
                status="sealed_unrevealed",
                fingerprint=holdout_hash,
                payload=payload,
                event_stream="holdout-chain",
                event_sequence=1 if chain_head is None else chain_head.sequence + 1,
            )
            row_binding = _record(
                kind="holdout-row-binding",
                record_id=row_binding_id,
                subject=f"Holdout:{manifest.identity}",
                status="sealed",
                fingerprint=holdout_hash,
                payload={"holdout_id": manifest.identity},
            )
            body = self._body(current)
            if body["next_action"].get("kind") == "await_new_future_holdout_data":
                if (
                    manifest.predecessor_holdout_id
                    != body["next_action"].get("predecessor_holdout_id")
                ):
                    raise TransitionError(
                        "replacement holdout differs from the required predecessor"
                    )
                body["scientific"]["required_future_holdout_id"] = manifest.identity
                body["next_action"] = {
                    "kind": "register_future_development_material",
                    "holdout_id": manifest.identity,
                    "mission_id": body["scientific"]["active_mission"],
                    "predecessor_holdout_id": manifest.predecessor_holdout_id,
                }
            return body, [seal, row_binding], {"holdout_id": manifest.identity}

        return self._commit(
            event_kind="holdout_sealed",
            operation_id=operation_id,
            subject=f"Holdout:{manifest.identity}",
            payload={"holdout_id": manifest.identity},
            prepare=prepare,
        )

    def register_future_development_material(
        self,
        *,
        material_receipt_hash: str,
        operation_id: str,
    ) -> TransitionResult:
        """Admit new post-reveal development without reading successor values."""

        if self.engineering_fixture:
            raise TransitionError(
                "engineering fixtures cannot register scientific development material"
            )
        _require_digest("material_receipt_hash", material_receipt_hash)
        try:
            receipt = parse_canonical(
                self.evidence.read_verified(material_receipt_hash)
            )
        except ValueError as exc:
            raise TransitionError(
                "future development material receipt is not canonical"
            ) from exc
        required_receipt_fields = {
            "development_ends_at_utc",
            "development_starts_at_utc",
            "material_content_sha256",
            "material_identity",
            "mission_id",
            "predecessor_holdout_id",
            "schema",
            "split_identity",
            "successor_holdout_id",
            "successor_values_exposed",
        }
        if (
            not isinstance(receipt, dict)
            or set(receipt) != required_receipt_fields
            or receipt.get("schema") != "post_holdout_development_material.v1"
            or receipt.get("successor_values_exposed") is not False
        ):
            raise TransitionError(
                "future development material receipt schema is invalid"
            )
        for name in (
            "mission_id",
            "predecessor_holdout_id",
            "successor_holdout_id",
        ):
            _require_ascii(name, receipt[name])
        material_content_sha256 = _require_digest(
            "material_content_sha256", receipt["material_content_sha256"]
        )
        self.evidence.verify(material_content_sha256)
        material_identity = _require_digest(
            "material_identity", receipt["material_identity"]
        )
        split_identity = _require_digest("split_identity", receipt["split_identity"])
        development_start = _parse_utc(
            "development_starts_at_utc", receipt["development_starts_at_utc"]
        )
        development_end = _parse_utc(
            "development_ends_at_utc", receipt["development_ends_at_utc"]
        )
        if development_start > development_end:
            raise TransitionError("future development time boundary is reversed")
        expected_material_identity = canonical_digest(
            domain="post-holdout-development-material",
            payload={
                "development_ends_at_utc": receipt["development_ends_at_utc"],
                "development_starts_at_utc": receipt[
                    "development_starts_at_utc"
                ],
                "material_content_sha256": material_content_sha256,
                "predecessor_holdout_id": receipt["predecessor_holdout_id"],
                "successor_holdout_id": receipt["successor_holdout_id"],
            },
        )
        expected_split_identity = canonical_digest(
            domain="post-holdout-development-split",
            payload={
                "development_ends_at_utc": receipt["development_ends_at_utc"],
                "development_starts_at_utc": receipt[
                    "development_starts_at_utc"
                ],
                "material_identity": expected_material_identity,
                "predecessor_holdout_id": receipt["predecessor_holdout_id"],
                "successor_holdout_id": receipt["successor_holdout_id"],
            },
        )
        if (
            material_identity != expected_material_identity
            or split_identity != expected_split_identity
        ):
            raise TransitionError(
                "future development receipt material identity is invalid"
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            mission_id = science["active_mission"]
            next_action = current["next_action"]
            successor_holdout_id = next_action.get("holdout_id")
            predecessor_holdout_id = next_action.get("predecessor_holdout_id")
            if (
                mission_id is None
                or next_action.get("kind")
                != "register_future_development_material"
                or next_action.get("mission_id") != mission_id
                or not isinstance(successor_holdout_id, str)
                or not isinstance(predecessor_holdout_id, str)
                or science.get("required_future_holdout_id")
                != successor_holdout_id
            ):
                raise TransitionError(
                    "future development registration is not the exact successor action"
                )
            if any(
                science[name] is not None
                for name in (
                    "active_study",
                    "active_batch",
                    "active_job",
                    "active_repair",
                    "active_executable",
                    "active_release",
                    "active_holdout_evaluation",
                )
            ):
                raise TransitionError(
                    "future development registration requires disposed active work"
                )
            if (
                receipt["mission_id"] != mission_id
                or receipt["successor_holdout_id"] != successor_holdout_id
                or receipt["predecessor_holdout_id"] != predecessor_holdout_id
            ):
                raise TransitionError(
                    "future development receipt belongs to another successor boundary"
                )
            successor = index.get("holdout-seal", successor_holdout_id)
            predecessor = index.get("holdout-seal", predecessor_holdout_id)
            predecessor_reveal = index.event_record(
                f"holdout-reveal:{predecessor_holdout_id}", 1
            )
            predecessor_disposition = index.event_record(
                f"holdout-reveal:{predecessor_holdout_id}", 2
            )
            if (
                successor is None
                or successor.status != "sealed_unrevealed"
                or successor.payload.get("predecessor_holdout_id")
                != predecessor_holdout_id
                or index.event_head(f"holdout-reveal:{successor_holdout_id}")
                is not None
                or predecessor is None
                or predecessor_reveal is None
                or predecessor_reveal.kind != "holdout-reveal"
                or predecessor_disposition is None
                or predecessor_disposition.kind != "holdout-disposition"
            ):
                raise TransitionError(
                    "future development registration lacks an untouched successor chain"
                )
            if not predecessor_reveal.subject.startswith("Executable:executable:"):
                raise TransitionError(
                    "predecessor holdout lacks its Executable binding"
                )
            predecessor_executable_id = predecessor_reveal.subject.removeprefix(
                "Executable:"
            )
            predecessor_end = _parse_utc(
                "predecessor ends_at_utc", predecessor.payload["ends_at_utc"]
            )
            successor_start = _parse_utc(
                "successor starts_at_utc", successor.payload["starts_at_utc"]
            )
            if (
                development_start <= predecessor_end
                or development_end >= successor_start
                or material_content_sha256
                in {
                    predecessor.payload["artifact_sha256"],
                    successor.payload["artifact_sha256"],
                }
            ):
                raise TransitionError(
                    "development material is not a distinct post-reveal pre-successor surface"
                )
            receipt_id = canonical_digest(
                domain="post-holdout-development",
                payload={
                    "holdout_id": successor_holdout_id,
                    "material_identity": material_identity,
                    "mission_id": mission_id,
                },
            )
            authority_payload = {
                "holdout_id": successor_holdout_id,
                "material_identity": material_identity,
                "material_content_sha256": material_content_sha256,
                "material_receipt_hash": material_receipt_hash,
                "mission_id": mission_id,
                "predecessor_executable_id": predecessor_executable_id,
                "predecessor_holdout_id": predecessor_holdout_id,
                "split_identity": split_identity,
            }
            authority = _record(
                kind="post-holdout-development",
                record_id=receipt_id,
                subject=f"Material:{material_identity}",
                status="accepted",
                fingerprint=material_receipt_hash,
                payload=authority_payload,
            )
            material = _record(
                kind="development-material",
                record_id=material_identity,
                subject=f"Mission:{mission_id}",
                status="accepted",
                fingerprint=material_receipt_hash,
                payload={
                    **authority_payload,
                    "development_ends_at_utc": receipt[
                        "development_ends_at_utc"
                    ],
                    "development_starts_at_utc": receipt[
                        "development_starts_at_utc"
                    ],
                    "post_holdout_development_id": receipt_id,
                },
            )
            if science["active_initiative"] is None:
                body["next_action"] = {
                    "kind": "open_initiative",
                    "mission_id": mission_id,
                }
            else:
                portfolio_head = index.event_head(f"portfolio:{mission_id}")
                snapshot = (
                    None
                    if portfolio_head is None
                    else index.get(
                        portfolio_head.record_kind, portfolio_head.record_id
                    )
                )
                if snapshot is None or snapshot.kind != "portfolio-snapshot":
                    raise TransitionError(
                        "active Initiative lacks its Portfolio reentry boundary"
                    )
                body["next_action"] = {
                    "kind": "portfolio_decision",
                    "portfolio_snapshot_id": snapshot.record_id,
                }
            return body, [authority, material], {
                "material_identity": material_identity,
                "post_holdout_development_id": receipt_id,
            }

        return self._commit(
            event_kind="future_development_registered",
            operation_id=operation_id,
            subject=f"Material:{material_identity}",
            payload={
                "material_receipt_hash": material_receipt_hash,
            },
            prepare=prepare,
        )

    def consume_holdout_permit(
        self,
        *,
        permit: Permit,
        executable_id: str,
        operation_id: str,
    ) -> TransitionResult:
        _require_ascii("executable_id", executable_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            if science["active_executable"] != executable_id:
                raise TransitionError("holdout permit is not candidate-executable bound")
            job = science.get("active_job")
            if not isinstance(job, dict) or job.get("status") != "running":
                raise TransitionError(
                    "holdout reveal requires its preregistered running evaluation Job"
                )
            declaration = index.get("job-declared", job["id"])
            holdout_id = f"holdout:{permit.input_hash}"
            if (
                declaration is None
                or declaration.payload["spec"].get("holdout_binding")
                != {"holdout_id": holdout_id}
                or declaration.payload["spec"].get("evidence_subject")
                != {"kind": "Executable", "id": executable_id}
            ):
                raise TransitionError("running Job is not bound to this holdout")
            self._validate_permit_locked(
                control=current,
                index=index,
                permit=permit,
                expected_kind=PermitKind.HOLDOUT,
                action="reveal_holdout",
                subject_kind=SubjectKind.EXECUTABLE,
                subject_id=executable_id,
                required_scope=(
                    holdout_id,
                    f"executable:{executable_id}",
                ),
            )
            seal = index.get("holdout-seal", holdout_id)
            if seal is None or seal.status != "sealed_unrevealed":
                raise TransitionError("holdout semantic seal is unavailable")
            self.evidence.verify(seal.payload["artifact_sha256"])
            if index.event_head(f"holdout-reveal:{holdout_id}") is not None:
                raise TransitionError("holdout semantic identity was already revealed")
            candidate_head = index.event_head(f"candidate:{executable_id}")
            candidate = (
                None
                if candidate_head is None
                else index.get(candidate_head.record_kind, candidate_head.record_id)
            )
            if candidate is None:
                raise TransitionError("holdout candidate activation is unavailable")
            science["holdout_reveals"] += 1
            science["active_holdout_evaluation"] = {
                "holdout_id": holdout_id,
                "candidate_id": candidate.record_id,
                "executable_id": executable_id,
                "job_id": job["id"],
                "status": "revealed_pending_evaluation",
            }
            body["next_action"] = {"kind": "evaluate_frozen_holdout", "executable_id": executable_id}
            consumption = self._permit_consumption_record(permit, operation_id)
            reveal_id = canonical_digest(
                domain="holdout-reveal",
                payload={
                    "candidate_id": candidate.record_id,
                    "holdout_id": holdout_id,
                    "job_id": job["id"],
                    "permit_id": permit.permit_id,
                },
            )
            reveal = _record(
                kind="holdout-reveal",
                record_id=reveal_id,
                subject=f"Executable:{executable_id}",
                status="revealed_once",
                fingerprint=seal.fingerprint,
                payload={
                    "artifact_sha256": seal.payload["artifact_sha256"],
                    "candidate_id": candidate.record_id,
                    "holdout_id": holdout_id,
                    "job_id": job["id"],
                    "reveal_delta": 1,
                    "retuning_allowed": False,
                },
                event_stream=f"holdout-reveal:{holdout_id}",
                event_sequence=1,
            )
            return body, [consumption, reveal], {
                "artifact_sha256": seal.payload["artifact_sha256"],
                "holdout_id": holdout_id,
                "reveal_count": science["holdout_reveals"],
                "reveal_record_id": reveal_id,
            }

        return self._commit(
            event_kind="holdout_revealed",
            operation_id=operation_id,
            subject=f"Executable:{executable_id}",
            payload={"permit_id": permit.permit_id, "executable_id": executable_id},
            prepare=prepare,
        )

    def reveal_holdout_values(
        self,
        *,
        permit: Permit,
        executable_id: str,
        operation_id: str,
    ) -> bytes:
        """Commit the one-time reveal before returning verified sealed values."""

        consumed = self.consume_holdout_permit(
            permit=permit,
            executable_id=executable_id,
            operation_id=operation_id,
        )
        if consumed.reused:
            raise PermitError("holdout reveal operation cannot return values twice")
        return self.evidence.read_verified(consumed.result["artifact_sha256"])

    def record_holdout_evaluation(
        self,
        *,
        completion_record_id: str,
        negative_memory_id: str | None,
        operation_id: str,
    ) -> TransitionResult:
        """Dispose the revealed final surface from validator-derived Job evidence."""

        _require_ascii("completion_record_id", completion_record_id)
        if negative_memory_id is not None:
            _require_ascii("negative_memory_id", negative_memory_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            active = science.get("active_holdout_evaluation")
            if not isinstance(active, dict):
                raise TransitionError("no revealed holdout awaits evaluation")
            if (
                active.get("status")
                != "evaluation_completed_pending_disposition"
                or active.get("completion_record_id")
                != completion_record_id
                or body.get("next_action")
                != {
                    "completion_record_id": completion_record_id,
                    "holdout_id": active.get("holdout_id"),
                    "job_id": active.get("job_id"),
                    "kind": "record_holdout_evaluation",
                }
            ):
                raise TransitionError(
                    "holdout evaluation is not its exact pending disposition"
                )
            completion = index.get("job-completed", completion_record_id)
            scientific = None if completion is None else completion.payload.get("scientific")
            effective_scope = (
                None
                if completion is None or not isinstance(scientific, dict)
                else _effective_completion_scope(index, completion)
            )
            if (
                completion is None
                or completion.payload.get("job_id") != active["job_id"]
                or not isinstance(scientific, dict)
                or scientific.get("executable_id") != active["executable_id"]
                or scientific.get("evidence_depth") != "confirmation"
                or effective_scope is None
                or effective_scope.scientific_eligible is not True
            ):
                raise TransitionError(
                    "holdout disposition lacks its validator-derived evaluation"
                )
            declaration = index.get("job-declared", active["job_id"])
            if (
                declaration is None
                or declaration.payload["spec"].get("holdout_binding")
                != {"holdout_id": active["holdout_id"]}
            ):
                raise TransitionError("holdout evaluation Job binding is unavailable")
            verdict = scientific.get("verdict")
            if verdict not in {"passed", "failed", "not_evaluable"}:
                raise TransitionError("holdout validator verdict is invalid")
            candidate_head = index.event_head(
                f"candidate:{active['executable_id']}"
            )
            candidate = (
                None
                if candidate_head is None
                else index.get(candidate_head.record_kind, candidate_head.record_id)
            )
            if candidate is None or candidate.record_id != active["candidate_id"]:
                raise TransitionError("holdout candidate activation changed")
            if verdict == "passed":
                if effective_scope.candidate_eligible is not True:
                    raise TransitionError(
                        "passed holdout did not authorize the frozen candidate"
                    )
                if negative_memory_id is not None:
                    raise TransitionError("passed holdout cannot carry negative memory")
                next_action = {
                    "kind": "plan_candidate_bound_evidence",
                    "executable_id": active["executable_id"],
                }
                science["required_future_holdout_id"] = None
            else:
                if verdict == "failed":
                    memory = (
                        None
                        if negative_memory_id is None
                        else index.get("negative-memory", negative_memory_id)
                    )
                    if (
                        memory is None
                        or memory.subject != f"Executable:{active['executable_id']}"
                        or completion_record_id
                        not in memory.payload.get("evidence_references", [])
                    ):
                        raise TransitionError(
                            "failed holdout requires its durable negative memory"
                        )
                elif negative_memory_id is not None:
                    raise TransitionError(
                        "not-evaluable holdout is not scientific negative memory"
                    )
                candidate_disposition_id = canonical_digest(
                    domain="candidate-disposition",
                    payload={
                        "candidate_id": active["candidate_id"],
                        "disposition": "invalidated",
                        "reason": "final_holdout_" + verdict,
                    },
                )
                candidate_disposition = _record(
                    kind="candidate-disposition",
                    record_id=candidate_disposition_id,
                    subject=f"Executable:{active['executable_id']}",
                    status="invalidated",
                    fingerprint=candidate.fingerprint,
                    payload={
                        "candidate_id": active["candidate_id"],
                        "executable_id": active["executable_id"],
                        "mission_id": science["active_mission"],
                        "reason": "final_holdout_" + verdict,
                    },
                    event_stream=f"candidate:{active['executable_id']}",
                    event_sequence=candidate_head.sequence + 1,
                )
                science["active_executable"] = None
                self._drop_authorization(
                    body, SubjectKind.EXECUTABLE, active["executable_id"]
                )
                next_action = {
                    "kind": "await_new_future_holdout_data",
                    "predecessor_holdout_id": active["holdout_id"],
                }
            disposition_id = canonical_digest(
                domain="holdout-disposition",
                payload={
                    "completion_record_id": completion_record_id,
                    "holdout_id": active["holdout_id"],
                    "verdict": verdict,
                },
            )
            disposition = _record(
                kind="holdout-disposition",
                record_id=disposition_id,
                subject=f"Holdout:{active['holdout_id']}",
                status=verdict,
                fingerprint=active["holdout_id"].removeprefix("holdout:"),
                payload={
                    "completion_record_id": completion_record_id,
                    "negative_memory_id": negative_memory_id,
                    "retuning_allowed": False,
                },
                event_stream=f"holdout-reveal:{active['holdout_id']}",
                event_sequence=2,
            )
            candidate_holdout = _record(
                kind="candidate-holdout",
                record_id=active["candidate_id"],
                subject=f"Candidate:{active['candidate_id']}",
                status=verdict,
                fingerprint=active["holdout_id"].removeprefix("holdout:"),
                payload={
                    "completion_record_id": completion_record_id,
                    "executable_id": active["executable_id"],
                    "holdout_id": active["holdout_id"],
                    "mission_id": science["active_mission"],
                },
            )
            records = [disposition, candidate_holdout]
            if verdict != "passed":
                records.append(candidate_disposition)
            science["active_holdout_evaluation"] = None
            body["next_action"] = next_action
            return body, records, {
                "holdout_id": active["holdout_id"],
                "verdict": verdict,
            }

        return self._commit(
            event_kind="holdout_evaluated",
            operation_id=operation_id,
            subject="Holdout:active",
            payload={
                "completion_record_id": completion_record_id,
                "negative_memory_id": negative_memory_id,
            },
            prepare=prepare,
        )

    def dispose_revealed_holdout_engineering_gap(
        self,
        *,
        completion_record_id: str,
        operation_id: str,
    ) -> TransitionResult:
        """Fail closed a revealed holdout after an unrecovered engineering gap."""

        _require_digest("holdout engineering completion", completion_record_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            active = science.get("active_holdout_evaluation")
            if not isinstance(active, dict):
                raise TransitionError("no revealed holdout engineering gap is active")
            if (
                active.get("status")
                != "engineering_gap_pending_disposition"
                or active.get("completion_record_id")
                != completion_record_id
                or body.get("next_action")
                != {
                    "completion_record_id": completion_record_id,
                    "holdout_id": active.get("holdout_id"),
                    "job_id": active.get("job_id"),
                    "kind": "dispose_revealed_holdout_engineering_gap",
                }
            ):
                raise TransitionError(
                    "holdout engineering gap is not the exact pending disposition"
                )
            completion = index.get("job-completed", completion_record_id)
            failure = (
                None if completion is None else completion.payload.get("failure")
            )
            engineering = (
                None
                if completion is None
                else completion.payload.get("engineering_disposition")
            )
            declaration = (
                None
                if completion is None
                else index.get(
                    "job-declared",
                    completion.payload.get("job_id", ""),
                )
            )
            holdout_id = active.get("holdout_id")
            reveal_head = (
                None
                if not isinstance(holdout_id, str)
                else index.event_head(f"holdout-reveal:{holdout_id}")
            )
            reveal = (
                None
                if reveal_head is None
                else index.get(reveal_head.record_kind, reveal_head.record_id)
            )
            if (
                completion is None
                or completion.status != "failed"
                or completion.payload.get("job_id") != active.get("job_id")
                or not isinstance(failure, Mapping)
                or failure.get("failure_kind") != "engineering"
                or not isinstance(engineering, Mapping)
                or engineering.get("schema")
                != "engineering_failure_disposition.v1"
                or completion.payload.get("scientific") is not None
                or completion.payload.get("source") is not None
                or completion.payload.get("external") is not None
                or declaration is None
                or declaration.payload.get("spec", {}).get("holdout_binding")
                != {"holdout_id": holdout_id}
                or declaration.payload.get("spec", {}).get(
                    "evidence_subject"
                )
                != {
                    "kind": "Executable",
                    "id": active.get("executable_id"),
                }
                or reveal_head is None
                or reveal_head.sequence != 1
                or reveal is None
                or reveal.kind != "holdout-reveal"
                or reveal.status != "revealed_once"
                or reveal.payload.get("job_id") != active.get("job_id")
            ):
                raise TransitionError(
                    "holdout engineering gap lacks exact typed provenance"
                )
            executable_id = active["executable_id"]
            candidate_head = index.event_head(f"candidate:{executable_id}")
            candidate = (
                None
                if candidate_head is None
                else index.get(
                    candidate_head.record_kind,
                    candidate_head.record_id,
                )
            )
            if (
                candidate is None
                or candidate.record_id != active.get("candidate_id")
                or candidate.status not in {"frozen", "bound_fixture"}
            ):
                raise TransitionError(
                    "holdout engineering gap lost its candidate activation"
                )
            disposition_payload = {
                "completion_record_id": completion_record_id,
                "engineering_disposition_hash": failure.get(
                    "repair_disposition_hash"
                ),
                "negative_memory_id": None,
                "retuning_allowed": False,
                "scientific_failure_delta": 0,
                "scientific_trial_delta": 0,
            }
            holdout_disposition_id = canonical_digest(
                domain="holdout-disposition",
                payload={
                    "completion_record_id": completion_record_id,
                    "holdout_id": holdout_id,
                    "verdict": "engineering_gap",
                },
            )
            holdout_disposition = _record(
                kind="holdout-disposition",
                record_id=holdout_disposition_id,
                subject=f"Holdout:{holdout_id}",
                status="engineering_gap",
                fingerprint=holdout_id.removeprefix("holdout:"),
                payload=disposition_payload,
                event_stream=f"holdout-reveal:{holdout_id}",
                event_sequence=2,
            )
            candidate_holdout = _record(
                kind="candidate-holdout",
                record_id=active["candidate_id"],
                subject=f"Candidate:{active['candidate_id']}",
                status="engineering_gap",
                fingerprint=holdout_id.removeprefix("holdout:"),
                payload={
                    "completion_record_id": completion_record_id,
                    "executable_id": executable_id,
                    "holdout_id": holdout_id,
                    "mission_id": science["active_mission"],
                    "scientific_failure_delta": 0,
                },
            )
            candidate_disposition_id = canonical_digest(
                domain="candidate-disposition",
                payload={
                    "candidate_id": active["candidate_id"],
                    "disposition": "invalidated",
                    "reason": "final_holdout_engineering_gap",
                },
            )
            candidate_disposition = _record(
                kind="candidate-disposition",
                record_id=candidate_disposition_id,
                subject=f"Executable:{executable_id}",
                status="invalidated",
                fingerprint=candidate.fingerprint,
                payload={
                    "candidate_id": active["candidate_id"],
                    "executable_id": executable_id,
                    "mission_id": science["active_mission"],
                    "reason": "final_holdout_engineering_gap",
                    "scientific_failure_delta": 0,
                },
                event_stream=f"candidate:{executable_id}",
                event_sequence=candidate_head.sequence + 1,
            )
            science["active_holdout_evaluation"] = None
            science["active_executable"] = None
            self._drop_authorization(
                body,
                SubjectKind.EXECUTABLE,
                executable_id,
            )
            body["next_action"] = {
                "kind": "await_new_future_holdout_data",
                "predecessor_holdout_id": holdout_id,
            }
            return body, [
                holdout_disposition,
                candidate_holdout,
                candidate_disposition,
            ], {
                "candidate_id": active["candidate_id"],
                "completion_record_id": completion_record_id,
                "holdout_id": holdout_id,
                "verdict": "engineering_gap",
            }

        return self._commit(
            event_kind="holdout_engineering_gap_disposed",
            operation_id=operation_id,
            subject="Holdout:active",
            payload={"completion_record_id": completion_record_id},
            prepare=prepare,
        )

    @staticmethod
    def _resolved_candidate_disposition_for_completion(
        index: LocalIndex,
        *,
        completion: IndexRecord,
        mission_id: str,
    ) -> str | None:
        """Return the exact terminal candidate-stream head for one positive.

        Candidate eligibility is authority to enter the candidate lifecycle,
        not a permanent ban on an honest axis disposition.  It is resolved only
        when the Writer-created candidate binds this exact completion and the
        latest executable stream head is its later typed disposition.
        """

        scientific = completion.payload.get("scientific")
        effective_scope = (
            None
            if not isinstance(scientific, dict)
            else _effective_completion_scope(index, completion)
        )
        executable_id = (
            None
            if not isinstance(scientific, dict)
            else scientific.get("executable_id")
        )
        if (
            completion.status != "success"
            or not isinstance(scientific, dict)
            or effective_scope is None
            or effective_scope.scientific_eligible is not True
            or effective_scope.candidate_eligible is not True
            or not isinstance(executable_id, str)
        ):
            return None
        head = index.event_head(f"candidate:{executable_id}")
        disposition = (
            None
            if head is None
            else index.get(head.record_kind, head.record_id)
        )
        candidate_id = (
            None
            if disposition is None
            else disposition.payload.get("candidate_id")
        )
        candidate = (
            None
            if not isinstance(candidate_id, str)
            else index.get("candidate", candidate_id)
        )
        evidence_refs = (
            None if candidate is None else candidate.payload.get("evidence_refs")
        )
        reason = (
            None if disposition is None else disposition.payload.get("reason")
        )
        expected_candidate_id = (
            None
            if not isinstance(evidence_refs, list)
            or any(not isinstance(item, str) for item in evidence_refs)
            else "candidate:"
            + canonical_digest(
                domain="mission-candidate",
                payload={
                    "evidence_refs": sorted(evidence_refs),
                    "executable_id": executable_id,
                    "mission_id": mission_id,
                },
            )
        )
        expected_disposition_id = (
            None
            if disposition is None
            or not isinstance(reason, str)
            or disposition.status
            not in {
                "invalidated",
                "rejected",
                "returned_to_library",
                "superseded",
            }
            else canonical_digest(
                domain="candidate-disposition",
                payload={
                    "candidate_id": candidate_id,
                    "disposition": disposition.status,
                    "reason": reason,
                },
            )
        )
        candidate_stream = f"candidate:{executable_id}"
        if (
            head is None
            or disposition is None
            or disposition.kind != "candidate-disposition"
            or disposition.event_stream != candidate_stream
            or disposition.event_sequence != head.sequence
            or disposition.record_id != expected_disposition_id
            or disposition.subject != f"Executable:{executable_id}"
            or disposition.payload.get("candidate_id") != candidate_id
            or disposition.payload.get("executable_id") != executable_id
            or disposition.payload.get("mission_id") != mission_id
            or candidate is None
            or candidate.record_id != expected_candidate_id
            or candidate.status != "frozen"
            or candidate.event_stream != candidate_stream
            or candidate.event_sequence is None
            or candidate.event_sequence + 1 != disposition.event_sequence
            or candidate.subject != f"Executable:{executable_id}"
            or candidate.fingerprint != executable_id.removeprefix("executable:")
            or disposition.fingerprint != candidate.fingerprint
            or candidate.payload.get("mission_id") != mission_id
            or not isinstance(evidence_refs, list)
            or len(set(evidence_refs)) != len(evidence_refs)
            or evidence_refs != sorted(evidence_refs)
            or completion.record_id not in evidence_refs
            or completion.authority_sequence is None
            or candidate.authority_sequence is None
            or disposition.authority_sequence is None
            or candidate.authority_sequence <= completion.authority_sequence
            or disposition.authority_sequence <= candidate.authority_sequence
        ):
            return None
        return disposition.record_id

    @classmethod
    def _candidate_authority_for_axis_bindings(
        cls,
        index: LocalIndex,
        *,
        references: Sequence[Any],
        bindings: Sequence[Any],
        mission_id: str,
    ) -> tuple[list[dict[str, str]], tuple[str, ...]]:
        resolved: list[dict[str, str]] = []
        unresolved: list[str] = []
        for reference, binding in zip(references, bindings, strict=True):
            if not binding.candidate_eligible:
                continue
            completion = (
                None
                if getattr(reference.kind, "value", None) != "job-completed"
                else index.get("job-completed", reference.record_id)
            )
            disposition_id = (
                None
                if completion is None
                else cls._resolved_candidate_disposition_for_completion(
                    index,
                    completion=completion,
                    mission_id=mission_id,
                )
            )
            if disposition_id is None:
                unresolved.append(reference.record_id)
            else:
                resolved.append(
                    {
                        "candidate_disposition_record_id": disposition_id,
                        "completion_record_id": reference.record_id,
                    }
                )
        return (
            sorted(
                resolved,
                key=lambda item: (
                    item["completion_record_id"],
                    item["candidate_disposition_record_id"],
                ),
            ),
            tuple(sorted(unresolved)),
        )

    def record_axis_dispositions(
        self,
        *,
        dispositions: Sequence[Any],
        operation_id: str,
    ) -> TransitionResult:
        """Record additive evidence-bound axis states without rewriting snapshots."""

        from axiom_rift.operations.axis_disposition import (
            AxisDispositionEvidenceError,
            aggregate_axis_evidence_state,
            derive_axis_evidence_binding,
            required_axes_scientific_references,
        )
        from axiom_rift.research.axis_disposition import (
            AxisDisposition,
            AxisDispositionAction,
            AxisEvidenceKind,
            AxisEvidenceState,
        )

        self._require_study_close_delivery_guard()
        normalized = tuple(dispositions)
        if (
            not normalized
            or any(not isinstance(item, AxisDisposition) for item in normalized)
            or len({item.axis_id for item in normalized}) != len(normalized)
            or len({item.axis_identity for item in normalized}) != len(normalized)
        ):
            raise TransitionError(
                "axis dispositions require unique typed Mission axes"
            )
        normalized = tuple(sorted(normalized, key=lambda item: item.axis_id))

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("axis disposition requires control")
            science = current["scientific"]
            mission_id = science.get("active_mission")
            if not isinstance(mission_id, str) or any(
                science.get(name) is not None
                for name in (
                    "active_batch",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_job",
                    "active_lineage",
                    "active_release",
                    "active_repair",
                    "active_study",
                )
            ):
                raise TransitionError(
                    "axis disposition requires a stable active Mission boundary"
                )
            next_action = current.get("next_action", {})
            active_initiative = science.get("active_initiative")
            stable_initiative_boundary = (
                isinstance(active_initiative, str)
                and next_action.get("kind") == "portfolio_decision"
            )
            stable_mission_boundary = (
                active_initiative is None
                and next_action
                == {
                    "kind": "choose_next_initiative_or_terminal",
                    "mission_id": mission_id,
                }
            )
            if not (stable_initiative_boundary or stable_mission_boundary):
                raise TransitionError(
                    "axis disposition cannot bypass pending research direction"
                )
            portfolio_head = index.event_head(f"portfolio:{mission_id}")
            snapshot = (
                None
                if portfolio_head is None
                else index.get(portfolio_head.record_kind, portfolio_head.record_id)
            )
            if snapshot is None or snapshot.kind != "portfolio-snapshot":
                raise TransitionError("axis disposition requires a current Portfolio")
            if (
                stable_initiative_boundary
                and next_action.get("portfolio_snapshot_id") != snapshot.record_id
            ):
                raise TransitionError(
                    "axis disposition Portfolio boundary is not current"
                )
            axes = {axis["axis_id"]: axis for axis in snapshot.payload["axes"]}
            axis_values = tuple(axes.values())
            axis_resolutions = {
                axis["axis_id"]: resolution
                for axis, resolution in zip(
                    axis_values,
                    self._effective_axis_resolutions(index, axis_values),
                    strict=True,
                )
            }
            for disposition in normalized:
                axis = axes.get(disposition.axis_id)
                resolution = axis_resolutions.get(disposition.axis_id)
                if (
                    disposition.mission_id != mission_id
                    or disposition.portfolio_snapshot_id != snapshot.record_id
                    or axis is None
                    or resolution is None
                    or axis.get("axis_identity") != disposition.axis_identity
                ):
                    raise TransitionError(
                        "axis disposition is stale or belongs to another Portfolio"
                    )
                if not resolution.terminal_eligible:
                    raise TransitionError(
                        "axis disposition cannot interpret replay- or scope-blocked authority"
                    )
            try:
                required_references_by_target = (
                    required_axes_scientific_references(
                        index,
                        targets=tuple(
                            (
                                mission_id,
                                disposition.axis_id,
                                disposition.axis_identity,
                            )
                            for disposition in normalized
                        ),
                    )
                )
            except AxisDispositionEvidenceError as exc:
                raise TransitionError(str(exc)) from exc
            records: list[IndexRecord] = []
            accepted_ids: list[str] = []
            for disposition in normalized:
                try:
                    required_references = required_references_by_target[
                        (
                            mission_id,
                            disposition.axis_id,
                            disposition.axis_identity,
                        )
                    ]
                    supplied_scientific_references = {
                        (reference.kind, reference.record_id)
                        for reference in disposition.evidence_references
                        if reference.kind is not AxisEvidenceKind.NEGATIVE_MEMORY
                    }
                    exact_required_references = {
                        (reference.kind, reference.record_id)
                        for reference in required_references
                    }
                    if supplied_scientific_references != exact_required_references:
                        raise AxisDispositionEvidenceError(
                            "axis disposition omits or supersedes scientific history"
                        )
                    bindings = tuple(
                        derive_axis_evidence_binding(
                            index,
                            reference=reference,
                            mission_id=mission_id,
                            axis_id=disposition.axis_id,
                            axis_identity=disposition.axis_identity,
                        )
                        for reference in disposition.evidence_references
                    )
                    effective_state = aggregate_axis_evidence_state(bindings)
                except AxisDispositionEvidenceError as exc:
                    raise TransitionError(str(exc)) from exc
                (
                    resolved_candidate_authority,
                    unresolved_candidate_completions,
                ) = self._candidate_authority_for_axis_bindings(
                    index,
                    references=disposition.evidence_references,
                    bindings=bindings,
                    mission_id=mission_id,
                )
                if unresolved_candidate_completions:
                    raise TransitionError(
                        "candidate-eligible evidence remains unresolved by its "
                        "candidate/disposition stream: "
                        + ", ".join(sorted(unresolved_candidate_completions))
                    )
                if effective_state is not disposition.evidence_state:
                    raise TransitionError(
                        "axis disposition differs from its Writer-derived evidence state"
                    )
                negative_memory_ids = sorted(
                    {
                        memory_id
                        for binding in bindings
                        for memory_id in binding.negative_memory_ids
                    }
                )
                scientifically_exhausted = bool(
                    effective_state is AxisEvidenceState.LOW_INFORMATION
                    and disposition.action
                    is AxisDispositionAction.RETIRE_WITH_REASON
                    and negative_memory_ids
                )
                if (
                    effective_state is AxisEvidenceState.LOW_INFORMATION
                    and disposition.action
                    is AxisDispositionAction.RETIRE_WITH_REASON
                    and not scientifically_exhausted
                ):
                    raise TransitionError(
                        "low-information retirement requires durable negative memory"
                    )
                stream = (
                    f"axis-disposition:{mission_id}:{disposition.axis_identity}"
                )
                head = index.event_head(stream)
                if head is not None and head.record_id == disposition.identity:
                    raise TransitionError("axis disposition is already current")
                sequence = 1 if head is None else head.sequence + 1
                payload = {
                    **disposition.to_identity_payload(),
                    "candidate_eligible": False,
                    "candidate_delta": 0,
                    "claim_delta": "none",
                    "derived_evidence_states": sorted(
                        {item.state.value for item in bindings}
                    ),
                    "holdout_delta": 0,
                    "negative_memory_ids": negative_memory_ids,
                    "resolved_candidate_authority": resolved_candidate_authority,
                    "scientifically_exhausted": scientifically_exhausted,
                    "supersedes_record_id": None if head is None else head.record_id,
                    "trial_delta": 0,
                }
                records.append(
                    _record(
                        kind="axis-disposition",
                        record_id=disposition.identity,
                        subject=f"Axis:{disposition.axis_identity}",
                        status=disposition.action.value,
                        fingerprint=disposition.identity.removeprefix(
                            "axis-disposition:"
                        ),
                        payload=payload,
                        event_stream=stream,
                        event_sequence=sequence,
                    )
                )
                accepted_ids.append(disposition.identity)
            return self._body(current), records, {
                "axis_disposition_record_ids": accepted_ids,
                "candidate_delta": 0,
                "claim_delta": "none",
                "holdout_delta": 0,
                "trial_delta": 0,
            }

        return self._commit(
            event_kind="axis_dispositions_recorded",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "dispositions": [
                    item.to_identity_payload() for item in normalized
                ]
            },
            prepare=prepare,
        )

    def accept_exhaustion_audit(
        self,
        *,
        frontiers: Mapping[str, Sequence[Mapping[str, str]]],
        diversity_basis: str,
        opportunity_cost_audit: str,
        operation_id: str,
    ) -> TransitionResult:
        from axiom_rift.operations.axis_disposition import (
            AxisDispositionEvidenceError,
            aggregate_axis_evidence_state,
            derive_axis_evidence_binding,
            required_axes_scientific_references,
        )
        from axiom_rift.research.axis_disposition import (
            AxisDispositionAction,
            AxisEvidenceKind,
            AxisEvidenceReference,
            AxisEvidenceState,
        )

        self._require_study_close_delivery_guard()
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot accept frontier exhaustion")
        _require_ascii("diversity_basis", diversity_basis)
        _require_ascii("opportunity_cost_audit", opportunity_cost_audit)
        if not frontiers:
            raise TransitionError("exhaustion audit requires a non-empty diverse frontier")
        normalized: dict[str, list[dict[str, str]]] = {}
        for frontier, references in frontiers.items():
            _require_ascii("frontier", frontier)
            if not references:
                raise TransitionError("every frontier requires bound evidence")
            normalized[frontier] = []
            for reference in references:
                if set(reference) != {"kind", "record_id"}:
                    raise TransitionError("exhaustion evidence reference is malformed")
                normalized[frontier].append(
                    {
                        "kind": _require_ascii("evidence kind", reference["kind"]),
                        "record_id": _require_ascii(
                            "evidence record id", reference["record_id"]
                        ),
                    }
                )
            normalized[frontier].sort(
                key=lambda value: (value["kind"], value["record_id"])
            )
        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("exhaustion audit requires an active Mission")
            science = current["scientific"]
            if current["next_action"] != {
                "kind": "choose_next_initiative_or_terminal",
                "mission_id": science["active_mission"],
            }:
                raise TransitionError(
                    "exhaustion audit requires the exact Mission terminal boundary"
                )
            if any(
                science[key] is not None
                for key in (
                    "active_initiative",
                    "active_study",
                    "active_batch",
                    "active_job",
                    "active_repair",
                    "active_executable",
                )
            ):
                raise TransitionError("exhaustion audit requires disposed active work")
            portfolio_head = index.event_head(
                f"portfolio:{science['active_mission']}"
            )
            latest = (
                None
                if portfolio_head is None
                else index.get(portfolio_head.record_kind, portfolio_head.record_id)
            )
            if latest is None:
                raise TransitionError("exhaustion requires a durable Portfolio")
            if latest.kind != "portfolio-snapshot":
                raise TransitionError("exhaustion requires a final Portfolio snapshot")
            snapshot_id = latest.record_id
            snapshot = (
                None
                if not isinstance(snapshot_id, str)
                else index.get("portfolio-snapshot", snapshot_id)
            )
            if snapshot is None or snapshot.subject != f"Mission:{science['active_mission']}":
                raise TransitionError("exhaustion Portfolio snapshot is unavailable")
            axes = {axis["axis_id"]: axis for axis in snapshot.payload["axes"]}
            axis_values = tuple(axes.values())
            axis_resolutions = {
                axis["axis_id"]: resolution
                for axis, resolution in zip(
                    axis_values,
                    self._effective_axis_resolutions(index, axis_values),
                    strict=True,
                )
            }
            blocked_axis_ids = sorted(
                axis_id
                for axis_id, resolution in axis_resolutions.items()
                if not resolution.terminal_eligible
            )
            mission_axis_blockers = self._mission_effective_axis_blockers(
                index,
                mission_id=science["active_mission"],
            )
            if blocked_axis_ids or mission_axis_blockers:
                raise TransitionError(
                    "exhaustion cannot bypass unresolved replay or source authority"
                )
            eligible_axes = {
                axis_id: axis
                for axis_id, axis in axes.items()
                if axis_resolutions[axis_id].terminal_eligible
            }
            families = {
                axis["mechanism_family"] for axis in eligible_axes.values()
            }
            research_layers = {
                axis.get("primary_research_layer")
                for axis in eligible_axes.values()
            }
            resolved_architectures = [
                self._axis_architecture_anchor(index, axis)
                for axis in eligible_axes.values()
            ]
            architecture_families = {
                (
                    self._resolved_architecture_family(
                        index=index,
                        architecture_payload=anchor["architecture_chassis"],
                    )
                    if isinstance(anchor.get("architecture_chassis"), dict)
                    else anchor["architecture_chassis_identity"]
                )
                for anchor in resolved_architectures
                if anchor is not None
            }
            standard = snapshot.payload.get("exhaustion_standard")
            if not isinstance(standard, dict):
                raise TransitionError(
                    "exhaustion Portfolio lacks its preregistered standard"
                )
            if (
                set(normalized) != set(eligible_axes)
                or len(eligible_axes) < standard["minimum_axes"]
                or len(families) < standard["minimum_mechanism_families"]
                or len(research_layers)
                < standard["minimum_primary_research_layers"]
                or len(architecture_families)
                < standard["minimum_system_architecture_families"]
                or any(anchor is None for anchor in resolved_architectures)
                or None in research_layers
            ):
                raise TransitionError(
                    "exhaustion does not cover its preregistered axes and families"
                )
            try:
                required_references_by_target = (
                    required_axes_scientific_references(
                        index,
                        targets=tuple(
                            (
                                science["active_mission"],
                                axis_id,
                                eligible_axes[axis_id]["axis_identity"],
                            )
                            for axis_id in sorted(eligible_axes)
                        ),
                    )
                )
            except AxisDispositionEvidenceError as exc:
                raise TransitionError(str(exc)) from exc
            family_executables: dict[str, set[str]] = {
                family: set() for family in families
            }
            axis_studies: dict[str, set[str]] = {
                axis_id: set() for axis_id in eligible_axes
            }
            axis_modes: dict[str, set[str]] = {
                axis_id: set() for axis_id in eligible_axes
            }
            global_executables: set[str] = set()
            scientifically_exhausted_axes: set[str] = set()
            carried_forward_axes: set[str] = set()
            retired_families: set[str] = set()
            disposition_summaries: dict[str, dict[str, Any]] = {}
            for axis_id, references in normalized.items():
                axis_identity = eligible_axes[axis_id]["axis_identity"]
                stream = (
                    f"axis-disposition:{science['active_mission']}:{axis_identity}"
                )
                head = index.event_head(stream)
                disposition = (
                    None
                    if head is None
                    else index.get(head.record_kind, head.record_id)
                )
                if (
                    disposition is None
                    or disposition.kind != "axis-disposition"
                    or disposition.payload.get("mission_id")
                    != science["active_mission"]
                    or disposition.payload.get("portfolio_snapshot_id")
                    != snapshot.record_id
                    or disposition.payload.get("axis_id") != axis_id
                    or disposition.payload.get("axis_identity") != axis_identity
                    or disposition.payload.get("candidate_eligible") is not False
                    or disposition.authority_sequence is None
                    or snapshot.authority_sequence is None
                    or disposition.authority_sequence
                    <= snapshot.authority_sequence
                ):
                    raise TransitionError(
                        "every axis requires its latest evidence-bound disposition"
                    )
                evidence_manifest = disposition.payload.get(
                    "evidence_references"
                )
                if not isinstance(evidence_manifest, list) or not evidence_manifest:
                    raise TransitionError(
                        "axis disposition evidence manifest is malformed"
                    )
                try:
                    typed_references = tuple(
                        AxisEvidenceReference(
                            kind=AxisEvidenceKind(reference["kind"]),
                            record_id=reference["record_id"],
                        )
                        for reference in evidence_manifest
                        if isinstance(reference, dict)
                        and set(reference) == {"kind", "record_id"}
                    )
                except (KeyError, TypeError, ValueError) as exc:
                    raise TransitionError(
                        "axis disposition evidence manifest is malformed"
                    ) from exc
                if len(typed_references) != len(evidence_manifest):
                    raise TransitionError(
                        "axis disposition evidence manifest is malformed"
                    )
                expected_references = {
                    ("axis-disposition", disposition.record_id),
                    *{
                        (reference.kind.value, reference.record_id)
                        for reference in typed_references
                    },
                }
                supplied_references = {
                    (reference["kind"], reference["record_id"])
                    for reference in references
                }
                if (
                    len(supplied_references) != len(references)
                    or supplied_references != expected_references
                ):
                    raise TransitionError(
                        "exhaustion frontier differs from its exact axis disposition"
                    )
                try:
                    required_references = required_references_by_target[
                        (
                            science["active_mission"],
                            axis_id,
                            axis_identity,
                        )
                    ]
                    supplied_scientific_references = {
                        (reference.kind, reference.record_id)
                        for reference in typed_references
                        if reference.kind is not AxisEvidenceKind.NEGATIVE_MEMORY
                    }
                    exact_required_references = {
                        (reference.kind, reference.record_id)
                        for reference in required_references
                    }
                    if supplied_scientific_references != exact_required_references:
                        raise AxisDispositionEvidenceError(
                            "axis disposition no longer covers scientific history"
                        )
                    bindings = tuple(
                        derive_axis_evidence_binding(
                            index,
                            reference=reference,
                            mission_id=science["active_mission"],
                            axis_id=axis_id,
                            axis_identity=axis_identity,
                        )
                        for reference in typed_references
                    )
                    effective_state = aggregate_axis_evidence_state(bindings)
                    action = AxisDispositionAction(disposition.status)
                except (AxisDispositionEvidenceError, ValueError) as exc:
                    raise TransitionError(str(exc)) from exc
                (
                    resolved_candidate_authority,
                    unresolved_candidate_completions,
                ) = self._candidate_authority_for_axis_bindings(
                    index,
                    references=typed_references,
                    bindings=bindings,
                    mission_id=science["active_mission"],
                )
                if (
                    unresolved_candidate_completions
                    or disposition.payload.get("resolved_candidate_authority")
                    != resolved_candidate_authority
                    or disposition.payload.get("evidence_state")
                    != effective_state.value
                    or disposition.payload.get("action") != action.value
                ):
                    raise TransitionError(
                        "axis disposition no longer matches its scientific evidence"
                    )
                evidence_records = [
                    index.get(reference.kind.value, reference.record_id)
                    for reference in typed_references
                ]
                if any(
                    record is None
                    or record.authority_sequence is None
                    or record.authority_sequence
                    >= disposition.authority_sequence
                    for record in evidence_records
                ):
                    raise TransitionError(
                        "axis disposition does not postdate its exact evidence"
                    )
                for binding in bindings:
                    axis_studies[axis_id].update(binding.study_ids)
                    axis_modes[axis_id].update(
                        _terminal_scientific_evidence_modes(
                            binding.evidence_modes
                        )
                    )
                negative_bindings = tuple(
                    binding for binding in bindings if binding.negative_memory_ids
                )
                scientifically_exhausted = bool(
                    effective_state is AxisEvidenceState.LOW_INFORMATION
                    and action is AxisDispositionAction.RETIRE_WITH_REASON
                    and negative_bindings
                )
                if (
                    disposition.payload.get("scientifically_exhausted")
                    is not scientifically_exhausted
                ):
                    raise TransitionError(
                        "axis scientific-exhaustion projection has drifted"
                    )
                if scientifically_exhausted:
                    family = eligible_axes[axis_id]["mechanism_family"]
                    retired_families.add(family)
                    scientifically_exhausted_axes.add(axis_id)
                    for binding in negative_bindings:
                        for executable_id in binding.executable_ids:
                            if executable_id in global_executables:
                                raise TransitionError(
                                    "negative Executable is reused across axis dispositions"
                                )
                            global_executables.add(executable_id)
                            family_executables[family].add(executable_id)
                else:
                    carried_forward_axes.add(axis_id)
                disposition_summaries[axis_id] = {
                    "action": action.value,
                    "axis_disposition_record_id": disposition.record_id,
                    "continuation_or_reopen_condition": disposition.payload.get(
                        "continuation_or_reopen_condition"
                    ),
                    "evidence_state": effective_state.value,
                    "scientifically_exhausted": scientifically_exhausted,
                }
            if not scientifically_exhausted_axes:
                raise TransitionError(
                    "exhaustion requires at least one genuinely scientifically "
                    "exhausted axis"
                )
            required_modes = set(standard["required_evidence_modes"])
            for axis_id in scientifically_exhausted_axes:
                if (
                    len(axis_studies[axis_id])
                    < standard["minimum_distinct_studies_per_axis"]
                    or not required_modes.issubset(axis_modes[axis_id])
                ):
                    raise TransitionError(
                        "scientifically exhausted axis lacks preregistered depth"
                    )
            if any(
                len(family_executables[family])
                < standard["minimum_negative_executables_per_family"]
                for family in retired_families
            ):
                raise TransitionError(
                    "retired negative family is below its preregistered depth"
                )
            unresolved_positive_axes: set[str] = set()
            for completion in index.records_by_kind("job-completed"):
                scientific = completion.payload.get("scientific")
                effective_scope = (
                    None
                    if not isinstance(scientific, dict)
                    else _effective_completion_scope(index, completion)
                )
                if (
                    completion.status != "success"
                    or not isinstance(scientific, dict)
                    or effective_scope is None
                    or effective_scope.candidate_eligible is not True
                ):
                    continue
                declaration = index.get(
                    "job-declared", completion.payload.get("job_id", "")
                )
                if (
                    declaration is None
                    or declaration.payload.get("mission_id")
                    != science["active_mission"]
                ):
                    continue
                declared_study_id = declaration.payload.get("study_id")
                if declared_study_id is None:
                    try:
                        holdout_lineage = holdout_completion_executable_lineage(
                            index, completion
                        )
                    except ExecutableAxisLineageError as exc:
                        raise TransitionError(
                            "Study-less positive evidence has malformed holdout lineage"
                        ) from exc
                    if holdout_lineage.mission_id != science["active_mission"]:
                        raise TransitionError(
                            "Study-less positive evidence changed Mission authority"
                        )
                    # Candidate authority is frozen from the originating Study
                    # evidence before holdout.  The Study-less holdout result is
                    # consumed by that candidate stream and must not manufacture
                    # a second axis completion or require a second disposition.
                    continue
                elif not isinstance(declared_study_id, str):
                    raise TransitionError(
                        "positive scientific evidence has malformed Study lineage"
                    )
                else:
                    try:
                        lineage = completion_executable_axis_lineage(
                            index, completion
                        )
                    except ExecutableAxisLineageError as exc:
                        raise TransitionError(
                            "positive scientific evidence has malformed Portfolio lineage"
                        ) from exc
                    axis_id = lineage.axis_id
                    axis_identity = lineage.axis_identity
                if (
                    axis_id not in axes
                    or axis_identity != axes[axis_id]["axis_identity"]
                ):
                    raise TransitionError(
                        "positive scientific evidence has stale Portfolio lineage"
                    )
                if self._resolved_candidate_disposition_for_completion(
                    index,
                    completion=completion,
                    mission_id=science["active_mission"],
                ) is None:
                    unresolved_positive_axes.add(axis_id)
            if unresolved_positive_axes:
                raise TransitionError(
                    "candidate-eligible positive evidence remains unresolved on: "
                    + ", ".join(sorted(unresolved_positive_axes))
                )
            audit_payload = {
                "axis_dispositions": disposition_summaries,
                "carried_forward_axis_ids": sorted(carried_forward_axes),
                "diversity_basis": diversity_basis,
                "frontiers": normalized,
                "mechanism_families": sorted(families),
                "primary_research_layers": sorted(research_layers),
                "system_architecture_families": sorted(architecture_families),
                "opportunity_cost_audit": opportunity_cost_audit,
                "portfolio_snapshot_id": snapshot.record_id,
                "preregistered_exhaustion_standard": standard,
                "scientifically_exhausted_axis_ids": sorted(
                    scientifically_exhausted_axes
                ),
                "unique_negative_executable_count": len(global_executables),
                "unresolved_candidate_eligible_axes": sorted(
                    unresolved_positive_axes
                ),
            }
            audit_id = canonical_digest(
                domain="exhaustion-audit", payload=audit_payload
            )
            body = self._body(current)
            body["next_action"] = {
                "kind": "close_mission",
                "outcome": "closed_no_candidate",
                "basis_record_id": audit_id,
            }
            record = _record(
                kind="exhaustion-audit",
                record_id=audit_id,
                subject=f"Mission:{science['active_mission']}",
                status="accepted",
                fingerprint=audit_id,
                payload=audit_payload,
            )
            return body, [record], {"basis_record_id": audit_id}

        return self._commit(
            event_kind="exhaustion_audit_accepted",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "diversity_basis": diversity_basis,
                "frontiers": normalized,
                "opportunity_cost_audit": opportunity_cost_audit,
            },
            prepare=prepare,
        )

    def record_external_blocker(
        self,
        *,
        dependency_id: str,
        completion_record_ids: tuple[str, ...],
        operation_id: str,
    ) -> TransitionResult:
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot create external blockers")
        _require_ascii("dependency_id", dependency_id)
        if (
            type(completion_record_ids) is not tuple
            or len(completion_record_ids) < 3
            or len(set(completion_record_ids)) != len(completion_record_ids)
        ):
            raise TransitionError(
                "external blocker requires at least three unique recovery completions"
            )
        for completion_id in completion_record_ids:
            _require_ascii("completion_record_id", completion_id)

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("external blocker requires an active Mission")
            science = current["scientific"]
            if any(
                science[key] is not None
                for key in (
                    "active_initiative",
                    "active_study",
                    "active_batch",
                    "active_job",
                    "active_repair",
                    "active_executable",
                    "active_holdout_evaluation",
                    "active_lineage",
                    "active_release",
                )
            ):
                raise TransitionError("external blocker requires preserved, disposed work")
            mission_id = science["active_mission"]
            next_action = current.get("next_action")
            if (
                not isinstance(next_action, dict)
                or next_action.get("kind") != "record_external_blocker"
                or next_action.get("dependency_id") != dependency_id
                or next_action.get("completion_record_ids")
                != list(completion_record_ids)
                or not isinstance(next_action.get("recovery_plan_id"), str)
            ):
                raise TransitionError(
                    "external blocker is not the exact judged recovery action"
                )
            plan_record = index.get(
                "external-recovery-plan", next_action["recovery_plan_id"]
            )
            try:
                recovery_plan = ExternalRecoveryPlan.from_identity_payload(
                    {} if plan_record is None else plan_record.payload
                )
            except ExternalDependencyContractError as exc:
                raise RecoveryRequired(
                    "external blocker recovery plan is unavailable"
                ) from exc
            if (
                plan_record is None
                or plan_record.record_id != recovery_plan.identity
                or plan_record.subject != f"Mission:{mission_id}"
                or recovery_plan.condition.dependency_id != dependency_id
                or len(completion_record_ids) != len(recovery_plan.paths)
            ):
                raise TransitionError(
                    "external blocker differs from its exact recovery plan"
                )
            attempts: list[IndexRecord] = []
            recovery_kinds: set[str] = set()
            recovery_paths: set[str] = set()
            required_changes: set[str] = set()
            resume_actions: set[str] = set()
            dependency_kinds: set[str] = set()
            blocked_capabilities: set[str] = set()
            reproduction_evidence: set[str] = set()
            completed_jobs: list[str] = []
            recovery_stream = f"external-recovery:{recovery_plan.identity}"
            for ordinal, completion_id in enumerate(completion_record_ids, start=1):
                completion = index.get("job-completed", completion_id)
                failure = None if completion is None else completion.payload.get("failure")
                external = None if completion is None else completion.payload.get("external")
                job_id = None if completion is None else completion.payload.get("job_id")
                declaration = (
                    None
                    if not isinstance(job_id, str)
                    else index.get("job-declared", job_id)
                )
                binding = (
                    None
                    if declaration is None
                    else declaration.payload["spec"].get(
                        "external_dependency_binding"
                    )
                )
                decision = index.event_record(recovery_stream, ordinal)
                try:
                    attempt_plan = (
                        None
                        if not isinstance(binding, dict)
                        else external_plan_from_binding(binding)
                    )
                except ExternalDependencyContractError as exc:
                    raise TransitionError(str(exc)) from exc
                if (
                    completion is None
                    or completion.status != "failed"
                    or not isinstance(failure, dict)
                    or failure.get("failure_kind") != "external_dependency"
                    or failure.get("external_dependency_id") != dependency_id
                    or not isinstance(external, dict)
                    or external.get("dependency_id") != dependency_id
                    or external.get("verdict") != "failed"
                    or external.get("indispensable_to_mission_terminal") is not True
                    or external.get("contract_valid_next_action_found") is not False
                    or external.get("safe_substitute_found") is not False
                    or external.get("observed_external_state")
                    != failure.get("observed_external_state")
                    or declaration is None
                    or declaration.payload.get("mission_id") != mission_id
                    or not isinstance(binding, dict)
                    or binding.get("dependency_id") != dependency_id
                    or attempt_plan != recovery_plan
                    or binding.get("recovery_path_id")
                    != recovery_plan.paths[ordinal - 1].recovery_path_id
                    or decision is None
                    or decision.kind != "external-dependency-judgement"
                    or decision.status != "failed"
                    or decision.payload.get("blocker_credit") is not True
                    or decision.payload.get("completion_record_id")
                    != completion_id
                ):
                    raise TransitionError(
                        "blocker completion is not typed external dependency evidence"
                    )
                attempt_id = canonical_digest(
                    domain="external-dependency-attempt",
                    payload={
                        "completion_record_id": completion_id,
                        "dependency_id": dependency_id,
                        "recovery_path_id": binding["recovery_path_id"],
                    },
                )
                attempt = index.get("external-dependency-attempt", attempt_id)
                if (
                    attempt is None
                    or attempt.status != "external_unavailable"
                    or attempt.subject != f"Mission:{mission_id}"
                    or attempt.payload.get("external") != external
                ):
                    raise TransitionError(
                        "external dependency attempt projection is unavailable"
                    )
                attempts.append(attempt)
                recovery_kinds.add(binding["recovery_kind"])
                blocked_capabilities.add(binding["blocked_mission_capability"])
                if binding["recovery_path_id"] in recovery_paths:
                    raise TransitionError("external recovery path was repeated")
                recovery_paths.add(binding["recovery_path_id"])
                required_changes.add(binding["required_external_change"])
                resume_actions.add(binding["exact_resume_action"])
                dependency_kinds.add(binding["dependency_kind"])
                reproduction_evidence.update(
                    failure["minimum_reproduction_evidence"]
                )
                completed_jobs.append(job_id)
            required_recovery_kinds = {
                "external_probe",
                "local_recovery",
                "safe_substitute_search",
            }
            if not required_recovery_kinds.issubset(recovery_kinds):
                raise TransitionError(
                    "external blocker has not exhausted probe, local recovery, and substitute search"
                )
            if (
                len(required_changes) != 1
                or len(resume_actions) != 1
                or len(dependency_kinds) != 1
                or len(blocked_capabilities) != 1
            ):
                raise TransitionError("external recovery attempts disagree on the dependency")
            dependency_head = index.event_head(f"external-dependency:{dependency_id}")
            dependency_latest = (
                None
                if dependency_head is None
                else index.get(
                    dependency_head.record_kind, dependency_head.record_id
                )
            )
            sequences = sorted(attempt.event_sequence for attempt in attempts)
            if (
                dependency_head is None
                or dependency_latest is None
                or dependency_latest.status != "external_unavailable"
                or sequences
                != list(
                    range(
                        dependency_head.sequence - len(attempts) + 1,
                        dependency_head.sequence + 1,
                    )
                )
            ):
                raise TransitionError(
                    "external blocker evidence is stale or not the latest consecutive state"
                )
            blocker_payload = {
                "candidate_delta": 0,
                "claim_delta": "none",
                "cause": {
                    "blocked_mission_capability": next(
                        iter(blocked_capabilities)
                    ),
                    "dependency_id": dependency_id,
                    "dependency_kind": next(iter(dependency_kinds)),
                },
                "completed_local_work": sorted(completed_jobs),
                "completion_record_ids": sorted(completion_record_ids),
                "exact_resume_action": next(iter(resume_actions)),
                "exhausted_recovery_kinds": sorted(recovery_kinds),
                "exhausted_recovery_paths": sorted(recovery_paths),
                "minimum_reproduction_evidence": sorted(reproduction_evidence),
                "holdout_delta": 0,
                "preserved_state": {
                    "control_revision": current["revision"],
                    "journal_event_id": current["heads"]["journal"]["event_id"],
                    "mission_id": mission_id,
                },
                "required_external_change": next(iter(required_changes)),
                "safe_substitute_absent": True,
                "scientific_credit": 0,
                "contract_valid_next_action_absent": True,
                "indispensable_to_mission_terminal": True,
                "mission_resume_next_action": (
                    recovery_plan.condition.resume_action.to_next_action()
                ),
                "recovery_plan": recovery_plan.to_identity_payload(),
                "recovery_plan_id": recovery_plan.identity,
                "resume_condition": (
                    recovery_plan.condition.to_identity_payload()
                ),
                "resume_condition_id": recovery_plan.condition.identity,
                "terminal_scientific_credit": 0,
                "trial_delta": 0,
            }
            blocker_id = canonical_digest(
                domain="external-blocker", payload=blocker_payload
            )
            body = self._body(current)
            body["next_action"] = {
                "kind": "close_mission",
                "outcome": "blocked_external",
                "basis_record_id": blocker_id,
            }
            record = _record(
                kind="external-blocker",
                record_id=blocker_id,
                subject=f"Mission:{science['active_mission']}",
                status="complete",
                fingerprint=blocker_id,
                payload=blocker_payload,
            )
            return body, [record], {"basis_record_id": blocker_id}

        return self._commit(
            event_kind="external_blocker_recorded",
            operation_id=operation_id,
            subject="Mission:active",
            payload={
                "completion_record_ids": list(completion_record_ids),
                "dependency_id": dependency_id,
            },
            prepare=prepare,
        )

    def close_mission(
        self,
        *,
        outcome: str,
        basis_record_id: str,
        operation_id: str,
    ) -> TransitionResult:
        self._require_study_close_delivery_guard()
        if self.engineering_fixture:
            raise TransitionError("engineering fixtures cannot create a Mission terminal")
        allowed = {"completed_pre_live_handoff", "closed_no_candidate", "blocked_external"}
        if outcome not in allowed:
            raise TransitionError("invalid Mission terminal")

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            mission_id = science["active_mission"]
            if mission_id is None:
                raise TransitionError("no active Mission")
            if body["next_action"] != {
                "kind": "close_mission",
                "outcome": outcome,
                "basis_record_id": basis_record_id,
            }:
                raise TransitionError("Mission terminal differs from the pending exact basis")
            if any(
                science[key] is not None
                for key in (
                    "active_initiative",
                    "active_study",
                    "active_batch",
                    "active_job",
                    "active_repair",
                    "active_lineage",
                )
            ):
                raise TransitionError("Mission terminal has active subordinate work")
            effective_axis_blockers = self._mission_effective_axis_blockers(
                index,
                mission_id=mission_id,
            )
            if effective_axis_blockers:
                raise TransitionError(
                    "Mission terminal cannot bypass replay- or scope-blocked axis authority"
                )
            portfolio_snapshots = [
                record
                for record in index.records_by_payload_text(
                    "portfolio-snapshot",
                    "mission_id",
                    mission_id,
                )
                if record.subject == f"Mission:{mission_id}"
                and record.authority_sequence is not None
            ]
            if not portfolio_snapshots and outcome != "blocked_external":
                raise TransitionError(
                    "Mission terminal requires a durable Portfolio snapshot"
                )
            terminal_snapshot = (
                None
                if not portfolio_snapshots
                else max(
                    portfolio_snapshots,
                    key=lambda record: record.authority_sequence,
                )
            )
            terminal_axes = (
                {}
                if terminal_snapshot is None
                else {
                    axis["axis_id"]: axis
                    for axis in terminal_snapshot.payload.get("axes", [])
                    if isinstance(axis, dict)
                    and isinstance(axis.get("axis_id"), str)
                }
            )
            if terminal_snapshot is not None and len(terminal_axes) != len(
                terminal_snapshot.payload.get("axes", [])
            ):
                raise RecoveryRequired(
                    "Mission terminal Portfolio axis inventory is malformed"
                )
            terminal_axis_values = tuple(terminal_axes.values())
            terminal_resolutions = {
                axis["axis_id"]: resolution
                for axis, resolution in zip(
                    terminal_axis_values,
                    self._effective_axis_resolutions(
                        index,
                        terminal_axis_values,
                    ),
                    strict=True,
                )
            }
            terminal_hard_blockers = sorted(
                axis_id
                for axis_id, resolution in terminal_resolutions.items()
                if not resolution.terminal_eligible
            )
            if terminal_hard_blockers:
                exact_source_replacement_wait = False
                if outcome == "blocked_external":
                    blocker_basis = index.get("external-blocker", basis_record_id)
                    try:
                        blocker_plan_probe = (
                            ExternalRecoveryPlan.from_identity_payload(
                                {}
                                if blocker_basis is None
                                else blocker_basis.payload.get(
                                    "recovery_plan", {}
                                )
                            )
                        )
                    except ExternalDependencyContractError:
                        blocker_plan_probe = None
                    if blocker_plan_probe is not None:
                        expected_capability = (
                            _exact_source_replacement_wait_capability(
                                mission_id=mission_id,
                                terminal_axes=terminal_axes,
                                terminal_resolutions=terminal_resolutions,
                                terminal_hard_blockers=terminal_hard_blockers,
                            )
                        )
                        exact_source_replacement_wait = (
                            expected_capability is not None
                            and blocker_plan_probe.condition.blocked_mission_capability
                            == expected_capability
                        )
                if not exact_source_replacement_wait:
                    raise TransitionError(
                        "Mission terminal cannot bypass unresolved Portfolio axis "
                        "authority; blocked_external requires the exact source-"
                        "replacement capability"
                    )
            if outcome == "completed_pre_live_handoff":
                basis = index.get("release", basis_record_id)
                active_release = science.get("active_release")
                if (
                    basis is None
                    or basis.status != "frozen"
                    or basis.payload.get("mission_id") != mission_id
                    or basis.payload.get("executable_id") != science["active_executable"]
                    or not isinstance(active_release, dict)
                    or active_release
                    != {
                        "id": basis_record_id,
                        "status": "frozen",
                        "candidate_id": basis.payload.get("candidate_id"),
                        "executable_id": basis.payload.get("executable_id"),
                    }
                ):
                    raise TransitionError("positive terminal requires a frozen Release")
                derived = self._derive_release_basis_locked(
                    index=index,
                    control=current,
                    executable_id=basis.payload["executable_id"],
                    candidate_id=basis.payload["candidate_id"],
                    completion_record_ids=tuple(basis.payload["completion_record_ids"]),
                )
                if any(basis.payload.get(name) != value for name, value in derived.items()):
                    raise TransitionError("frozen Release no longer matches current evidence")
                executable_id = science["active_executable"]
                science["active_executable"] = None
                science["active_release"] = None
                self._drop_authorization(body, SubjectKind.EXECUTABLE, executable_id)
            elif outcome == "closed_no_candidate":
                basis = index.get("exhaustion-audit", basis_record_id)
                if terminal_snapshot is None:
                    raise RecoveryRequired(
                        "negative terminal lost its Portfolio snapshot"
                    )
                if (
                    science["active_executable"] is not None
                    or science.get("active_release") is not None
                    or science.get("active_holdout_evaluation") is not None
                    or basis is None
                    or basis.status != "accepted"
                    or basis.subject != f"Mission:{mission_id}"
                ):
                    raise TransitionError("negative terminal requires an exhaustion audit")
                if (
                    basis.payload.get("portfolio_snapshot_id")
                    != terminal_snapshot.record_id
                ):
                    raise TransitionError(
                        "negative terminal authority changed after its exhaustion audit"
                    )
            else:
                basis = index.get("external-blocker", basis_record_id)
                try:
                    blocker_plan = ExternalRecoveryPlan.from_identity_payload(
                        {} if basis is None else basis.payload.get("recovery_plan", {})
                    )
                except ExternalDependencyContractError as exc:
                    raise TransitionError(
                        "blocked terminal lacks its typed resume condition"
                    ) from exc
                dependency_id = (
                    None
                    if basis is None
                    else basis.payload.get("cause", {}).get("dependency_id")
                )
                dependency_head = (
                    None
                    if not isinstance(dependency_id, str)
                    else index.event_head(f"external-dependency:{dependency_id}")
                )
                dependency_latest = (
                    None
                    if dependency_head is None
                    else index.get(
                        dependency_head.record_kind, dependency_head.record_id
                    )
                )
                if (
                    science["active_executable"] is not None
                    or science.get("active_release") is not None
                    or science.get("active_holdout_evaluation") is not None
                    or basis is None
                    or basis.status != "complete"
                    or basis.subject != f"Mission:{mission_id}"
                    or dependency_head is None
                    or dependency_latest is None
                    or dependency_latest.status != "external_unavailable"
                    or basis.payload.get("recovery_plan_id")
                    != blocker_plan.identity
                    or basis.payload.get("resume_condition_id")
                    != blocker_plan.condition.identity
                ):
                    raise TransitionError("blocked terminal requires a complete external blocker")
            expected_authorizations = {f"Mission:{mission_id}"}
            if set(body["authorizations"]) != expected_authorizations:
                raise TransitionError("Mission terminal has stale subject authorization")
            mission_open = index.get("mission-open", mission_id)
            if mission_open is None:
                raise TransitionError("Mission open record is absent")
            mission_ordinal = mission_open.payload.get("mission_ordinal", 1)
            if type(mission_ordinal) is not int or mission_ordinal < 1:
                raise TransitionError("Mission ordinal is invalid")
            project_goal_authority = mission_open.payload.get(
                "project_goal_authority",
                body["authority"]["operating_direction"],
            )
            project_goal_complete = outcome == "completed_pre_live_handoff"
            science["active_holdout_evaluation"] = None
            if project_goal_complete:
                science["required_future_holdout_id"] = None
            science["active_mission"] = None
            self._drop_authorization(body, SubjectKind.MISSION, mission_id)
            record_id = canonical_digest(
                domain="mission-close",
                payload={"mission_id": mission_id, "outcome": outcome, "basis": basis_record_id},
            )
            if outcome == "closed_no_candidate":
                body["next_action"] = {
                    "kind": "await_root_goal",
                    "predecessor_basis_record_id": basis_record_id,
                    "predecessor_mission_close_record_id": record_id,
                    "predecessor_mission_id": mission_id,
                    "predecessor_outcome": outcome,
                }
            elif outcome == "blocked_external":
                body["next_action"] = {
                    "basis_record_id": basis_record_id,
                    "kind": "await_external_change",
                    "mission_resume_next_action": basis.payload[
                        "mission_resume_next_action"
                    ],
                    "predecessor_mission_close_record_id": record_id,
                    "predecessor_mission_id": mission_id,
                    "required_external_change": basis.payload.get(
                        "required_external_change",
                        basis.payload.get("cause", {}).get(
                            "required_external_change"
                        ),
                    ),
                    "resume_condition_id": basis.payload["resume_condition_id"],
                }
            else:
                body["next_action"] = {
                    "kind": "project_goal_complete",
                    "mission_close_record_id": record_id,
                    "outcome": outcome,
                }
            project_stream = "project-goal:OPERATING_DIRECTION.md"
            project_head = index.event_head(project_stream)
            project_sequence = 1 if project_head is None else project_head.sequence + 1
            record = _record(
                kind="mission-close",
                record_id=record_id,
                subject=f"Mission:{mission_id}",
                status=outcome,
                fingerprint=record_id,
                payload={
                    "basis_record_id": basis_record_id,
                    "mission_ordinal": mission_ordinal,
                    "project_goal_authority": project_goal_authority,
                    "project_goal_complete": project_goal_complete,
                    **(
                        {
                            "terminal_scientific_credit": 0,
                            "unresolved_axis_ids": terminal_hard_blockers,
                        }
                        if outcome == "blocked_external"
                        else {}
                    ),
                },
                event_stream=project_stream,
                event_sequence=project_sequence,
            )
            return body, [record], {
                "mission_id": mission_id,
                "outcome": outcome,
                "project_goal_complete": project_goal_complete,
            }

        return self._commit(
            event_kind="mission_closed",
            operation_id=operation_id,
            subject="Mission:active",
            payload={"outcome": outcome, "basis_record_id": basis_record_id},
            prepare=prepare,
        )

    def resume_blocked_mission(
        self,
        *,
        basis_record_id: str,
        mission_close_record_id: str,
        evidence: ExternalChangeEvidence,
        operation_id: str,
    ) -> TransitionResult:
        """Reenter the same blocked Mission from exact validated availability."""

        self._require_study_close_delivery_guard()
        if self.engineering_fixture:
            raise TransitionError(
                "engineering fixtures cannot reenter blocked Missions"
            )
        _require_digest("external blocker basis", basis_record_id)
        _require_digest("blocked Mission close", mission_close_record_id)
        if not isinstance(evidence, ExternalChangeEvidence):
            raise TransitionError(
                "blocked Mission reentry requires typed external change evidence"
            )

        def prepare(current: dict[str, Any] | None, index: LocalIndex):
            if current is None:
                raise TransitionError("control is absent")
            body = self._body(current)
            science = body["scientific"]
            boundary = body.get("next_action")
            if (
                science.get("active_mission") is not None
                or any(
                    science.get(name) is not None
                    for name in (
                        "active_batch",
                        "active_executable",
                        "active_holdout_evaluation",
                        "active_initiative",
                        "active_job",
                        "active_lineage",
                        "active_release",
                        "active_repair",
                        "active_study",
                    )
                )
                or body.get("authorizations") != {}
                or not isinstance(boundary, dict)
                or boundary.get("kind") != "await_external_change"
                or boundary.get("basis_record_id") != basis_record_id
                or boundary.get("predecessor_mission_close_record_id")
                != mission_close_record_id
            ):
                raise TransitionError(
                    "blocked Mission reentry is not at its exact wait boundary"
                )
            mission_id = boundary.get("predecessor_mission_id")
            blocker = index.get("external-blocker", basis_record_id)
            close_record = index.get("mission-close", mission_close_record_id)
            mission_open = (
                None
                if not isinstance(mission_id, str)
                else index.get("mission-open", mission_id)
            )
            try:
                plan = ExternalRecoveryPlan.from_identity_payload(
                    {} if blocker is None else blocker.payload.get("recovery_plan", {})
                )
            except ExternalDependencyContractError as exc:
                raise RecoveryRequired(
                    "blocked Mission reentry lost its typed recovery plan"
                ) from exc
            condition = plan.condition
            if (
                blocker is None
                or blocker.status != "complete"
                or blocker.subject != f"Mission:{mission_id}"
                or blocker.payload.get("resume_condition_id")
                != condition.identity
                or blocker.payload.get("mission_resume_next_action")
                != condition.resume_action.to_next_action()
                or close_record is None
                or close_record.status != "blocked_external"
                or close_record.subject != f"Mission:{mission_id}"
                or close_record.payload.get("basis_record_id") != basis_record_id
                or mission_open is None
                or evidence.condition_id != condition.identity
                or boundary.get("resume_condition_id") != condition.identity
                or boundary.get("mission_resume_next_action")
                != condition.resume_action.to_next_action()
            ):
                raise TransitionError(
                    "blocked Mission reentry differs from its exact terminal"
                )
            try:
                self.evidence.verify(condition.validation_plan_hash)
            except (FileNotFoundError, OSError, RuntimeError, ValueError) as exc:
                raise RecoveryRequired(
                    "blocked Mission validation plan is absent or corrupt"
                ) from exc
            dependency_head = index.event_head(
                f"external-dependency:{condition.dependency_id}"
            )
            dependency_latest = (
                None
                if dependency_head is None
                else index.get(
                    dependency_head.record_kind, dependency_head.record_id
                )
            )
            if (
                dependency_head is None
                or dependency_latest is None
                or dependency_latest.status != "external_unavailable"
            ):
                raise TransitionError(
                    "blocked Mission dependency state is no longer the exact outage"
                )
            project_head = index.event_head("project-goal:OPERATING_DIRECTION.md")
            if project_head is None or project_head.record_id != mission_close_record_id:
                raise TransitionError(
                    "blocked Mission close is not the current Project Goal boundary"
                )
            output_manifest = dict(evidence.output_manifest)
            result_hash = output_manifest[evidence.result_manifest_output]
            try:
                result_manifest = parse_canonical(
                    self.evidence.read_verified(result_hash)
                )
            except ValueError as exc:
                raise TransitionError(
                    "external change result manifest is not canonical"
                ) from exc
            required_result = {
                "blocker_basis_record_id",
                "condition_id",
                "measurement_artifact_hashes",
                "mission_close_record_id",
                "mission_id",
                "schema",
            }
            measurement_hashes = sorted(
                artifact_hash
                for output_name, artifact_hash in evidence.output_manifest
                if output_name != evidence.result_manifest_output
            )
            if (
                not isinstance(result_manifest, dict)
                or set(result_manifest) != required_result
                or result_manifest.get("schema")
                != "external_change_evidence.v1"
                or result_manifest.get("blocker_basis_record_id")
                != basis_record_id
                or result_manifest.get("condition_id") != condition.identity
                or result_manifest.get("mission_close_record_id")
                != mission_close_record_id
                or result_manifest.get("mission_id") != mission_id
                or result_manifest.get("measurement_artifact_hashes")
                != measurement_hashes
            ):
                raise TransitionError(
                    "external change result differs from the blocked Mission"
                )
            artifacts: list[ValidationArtifact] = []
            for output_name, artifact_hash in evidence.output_manifest:
                artifacts.append(
                    ValidationArtifact(
                        output_name=output_name,
                        sha256=artifact_hash,
                        _source=self.evidence.verified_path(artifact_hash),
                    )
                )
            validation_binding = {
                "blocked_mission_capability": (
                    condition.blocked_mission_capability
                ),
                "dependency_id": condition.dependency_id,
                "result_manifest_output": evidence.result_manifest_output,
                "resume_condition_id": condition.identity,
            }
            request = ExternalChangeValidationRequest(
                validator_id=condition.validator_id,
                validation_plan_hash=condition.validation_plan_hash,
                boundary_id=mission_close_record_id,
                condition_id=condition.identity,
                mission_id=mission_id,
                evidence_subject={"kind": "Mission", "id": mission_id},
                binding=validation_binding,
                result_manifest=result_manifest,
                artifacts=tuple(artifacts),
                engineering_fixture=False,
            )
            try:
                validated, trace = self.validation_registry.validate(request)
            except EvidenceValidationError as exc:
                raise TransitionError(
                    f"registered external reentry validation failed: {exc}"
                ) from exc
            expected_facts = {
                "blocked_mission_capability": (
                    condition.blocked_mission_capability
                ),
                "dependency_id": condition.dependency_id,
                "external_change_satisfied": True,
                "resume_condition_id": condition.identity,
            }
            if (
                validated.verdict != "passed"
                or dict(validated.facts) != expected_facts
                or sorted(validated.measurement_artifact_hashes)
                != measurement_hashes
                or validated.claims
                or validated.artifact_roles
                or validated.scientific_eligible
                or validated.candidate_eligible
                or validated.release_eligible
            ):
                raise TransitionError(
                    "external change validator did not satisfy the exact condition"
                )
            validation_payload = {
                "blocker_basis_record_id": basis_record_id,
                "condition_id": condition.identity,
                "facts": expected_facts,
                "measurement_artifact_hashes": measurement_hashes,
                "mission_close_record_id": mission_close_record_id,
                "mission_id": mission_id,
                "result_manifest_hash": result_hash,
                "validation_plan_hash": condition.validation_plan_hash,
                "validation_trace": {
                    "declared_artifact_count": trace.declared_artifact_count,
                    "opened_artifact_count": trace.opened_artifact_count,
                    "validator_id": trace.validator_id,
                },
                "validator_id": condition.validator_id,
            }
            validation_id = canonical_digest(
                domain="external-change-validation",
                payload=validation_payload,
            )
            availability = _record(
                kind="external-change-validation",
                record_id=validation_id,
                subject=f"Mission:{mission_id}",
                status="available",
                fingerprint=condition.dependency_id,
                payload=validation_payload,
                event_stream=f"external-dependency:{condition.dependency_id}",
                event_sequence=dependency_head.sequence + 1,
            )
            authorization_head = index.event_head(
                f"mission-authorization:{mission_id}"
            )
            previous_authorization = (
                None
                if authorization_head is None
                else index.get(
                    authorization_head.record_kind,
                    authorization_head.record_id,
                )
            )
            if authorization_head is not None and (
                previous_authorization is None
                or previous_authorization.kind != "mission-authorization"
                or previous_authorization.subject != f"Mission:{mission_id}"
                or previous_authorization.payload.get("authorization_epoch")
                != authorization_head.sequence + 1
            ):
                raise RecoveryRequired(
                    "blocked Mission authorization history is malformed"
                )
            authorization_sequence = (
                1 if authorization_head is None else authorization_head.sequence + 1
            )
            authorization_epoch = authorization_sequence + 1
            activation_hash = canonical_digest(
                domain="mission-reentry-activation",
                payload={
                    "authorization_epoch": authorization_epoch,
                    "basis_record_id": basis_record_id,
                    "external_change_validation_id": validation_id,
                    "goal_hash": mission_open.payload.get("goal_hash"),
                    "mission_close_record_id": mission_close_record_id,
                    "mission_id": mission_id,
                },
            )
            authorization = self._authorization(
                kind=SubjectKind.MISSION,
                subject_id=mission_id,
                semantic_hash=activation_hash,
                epoch=authorization_epoch,
            )
            reentry_payload = {
                "authorization_epoch": authorization_epoch,
                "authorization_hash": authorization.authorization_hash,
                "basis_record_id": basis_record_id,
                "external_change_validation_id": validation_id,
                "mission_close_record_id": mission_close_record_id,
                "mission_id": mission_id,
                "mission_ordinal": mission_open.payload.get("mission_ordinal"),
                "project_goal_complete": False,
                "resume_next_action": condition.resume_action.to_next_action(),
                "trial_delta": 0,
                "claim_delta": 0,
                "holdout_delta": 0,
            }
            reentry_id = canonical_digest(
                domain="mission-reentry", payload=reentry_payload
            )
            reentry = _record(
                kind="mission-reentry",
                record_id=reentry_id,
                subject=f"Mission:{mission_id}",
                status="active",
                fingerprint=activation_hash,
                payload=reentry_payload,
                event_stream="project-goal:OPERATING_DIRECTION.md",
                event_sequence=project_head.sequence + 1,
            )
            authorization_record = _record(
                kind="mission-authorization",
                record_id=activation_hash,
                subject=f"Mission:{mission_id}",
                status="active",
                fingerprint=authorization.authorization_hash,
                payload={
                    **authorization.payload(),
                    "basis_record_id": basis_record_id,
                    "external_change_validation_id": validation_id,
                    "mission_close_record_id": mission_close_record_id,
                },
                event_stream=f"mission-authorization:{mission_id}",
                event_sequence=authorization_sequence,
            )
            science["active_mission"] = mission_id
            body["next_action"] = condition.resume_action.to_next_action()
            self._bind_authorization(body, authorization)
            return body, [availability, authorization_record, reentry], {
                "authorization_epoch": authorization_epoch,
                "external_change_validation_id": validation_id,
                "mission_id": mission_id,
                "mission_reentry_id": reentry_id,
                "project_goal_complete": False,
            }

        return self._commit(
            event_kind="blocked_mission_reentered",
            operation_id=operation_id,
            subject="ProjectGoal:OPERATING_DIRECTION.md",
            payload={
                "basis_record_id": basis_record_id,
                "evidence_id": evidence.identity,
                "mission_close_record_id": mission_close_record_id,
            },
            prepare=prepare,
            evidence_blobs=(),
        )

    def withdraw_terminal_basis(
        self,
        *,
        reason: str,
        operation_id: str,
    ) -> TransitionResult:
        """Withdraw a pending negative or blocker terminal when new evidence exists."""

        _require_ascii("reason", reason)

        def prepare(current: dict[str, Any] | None, _index: LocalIndex):
            if current is None or current["scientific"]["active_mission"] is None:
                raise TransitionError("terminal withdrawal requires an active Mission")
            pending = current["next_action"]
            if pending.get("kind") != "close_mission" or pending.get("outcome") not in {
                "closed_no_candidate",
                "blocked_external",
            }:
                raise TransitionError("there is no withdrawable terminal basis")
            body = self._body(current)
            body["next_action"] = {
                "kind": "choose_next_initiative_or_terminal",
                "mission_id": body["scientific"]["active_mission"],
            }
            record_id = canonical_digest(
                domain="terminal-basis-withdrawal",
                payload={"pending": pending, "reason": reason},
            )
            record = _record(
                kind="terminal-basis-withdrawal",
                record_id=record_id,
                subject=f"Mission:{body['scientific']['active_mission']}",
                status="withdrawn",
                fingerprint=record_id,
                payload={"pending": pending, "reason": reason},
            )
            return body, [record], {"withdrawn_basis_record_id": pending["basis_record_id"]}

        return self._commit(
            event_kind="terminal_basis_withdrawn",
            operation_id=operation_id,
            subject="Mission:active",
            payload={"reason": reason},
            prepare=prepare,
        )
